"use server";

import nodemailer from "nodemailer";
import { redis } from "@/lib/redis";
import { headers } from "next/headers";

interface ContactState {
    success?: boolean;
    error?: string;
}

export async function sendContactEmail(prevState: ContactState, formData: FormData): Promise<ContactState> {
    const rawFormData = {
        name: formData.get("name") as string,
        email: formData.get("email") as string,
        subject: formData.get("subject") as string,
        message: formData.get("message") as string,
        // Honeypot field - should be empty for humans
        website: formData.get("website") as string,
    };

    // 1. Honeypot Check (Anti-Bot)
    // If the hidden 'website' field is filled, it's likely a bot. 
    // Return fake success to confuse them.
    if (rawFormData.website) {
        console.warn("Honeypot triggered by submission", { name: rawFormData.name, website: rawFormData.website });
        return { success: true };
    }

    // Basic Validation
    if (!rawFormData.name || !rawFormData.email || !rawFormData.message) {
        return { success: false, error: "Please fill in all required fields." };
    }

    // 2. Rate Limiting (Redis)
    try {
        const headerStore = await headers();
        const ip = headerStore.get("x-forwarded-for") || "unknown";
        const rateLimitKey = `contact_rate_limit:${ip}`;

        // Allow 3 emails per hour per IP
        const currentCount = await redis.incr(rateLimitKey);

        if (currentCount === 1) {
            await redis.expire(rateLimitKey, 3600); // 1 hour TTL
        }

        if (currentCount > 3) {
            console.warn(`Rate limit exceeded for IP: ${ip}`);
            return {
                success: false,
                error: "You have sent too many messages recently. Please try again in an hour."
            };
        }
    } catch (redisError) {
        console.error("Rate limiting error (proceeding anyway):", redisError);
        // Fail open if Redis is down, don't block users
    }

    // SMTP Configuration
    // In production, these should be env variables
    const smtpHost = process.env.SMTP_HOST;
    const smtpPort = process.env.SMTP_PORT ? parseInt(process.env.SMTP_PORT) : 587;
    const smtpUser = process.env.SMTP_USER;
    const smtpPass = process.env.SMTP_PASS;
    const adminEmail = process.env.CONTACT_EMAIL || "admin@instanttea.com";

    if (!smtpHost || !smtpUser || !smtpPass) {
        console.error("Missing SMTP Configuration", { smtpHost, smtpUser });
        // Return simulated success in Dev/Demo mode if not configured, or error
        if (process.env.NODE_ENV === "development") {
            console.log("DEV MODE: Email would have been sent:", rawFormData);
            return { success: true };
        }
        const missing = [];
        if (!smtpHost) missing.push("SMTP_HOST");
        if (!smtpUser) missing.push("SMTP_USER");
        if (!smtpPass) missing.push("SMTP_PASS");
        return { success: false, error: `Email service not configured. Missing variables: ${missing.join(", ")}` };
    }

    try {
        const transporter = nodemailer.createTransport({
            host: smtpHost,
            port: smtpPort,
            secure: smtpPort === 465, // true for 465, false for other ports
            auth: {
                user: smtpUser,
                pass: smtpPass,
            },
        });

        await transporter.sendMail({
            from: `"${rawFormData.name}" <${process.env.SMTP_FROM || smtpUser}>`, // Sender address
            to: adminEmail, // List of receivers
            replyTo: rawFormData.email,
            subject: `[InstantTea Contact] ${rawFormData.subject || "New Message"}`, // Subject line
            text: `
Name: ${rawFormData.name}
Email: ${rawFormData.email}
Subject: ${rawFormData.subject}
IP: ${await (await headers()).get("x-forwarded-for") || "unknown"}

Message:
${rawFormData.message}
            `, // plain text body
            html: `
<div style="font-family: sans-serif; padding: 20px; color: #334155;">
  <h2>New Contact Form Submission</h2>
  <p><strong>Name:</strong> ${rawFormData.name}</p>
  <p><strong>Email:</strong> <a href="mailto:${rawFormData.email}">${rawFormData.email}</a></p>
  <p><strong>Subject:</strong> ${rawFormData.subject}</p>
  <hr style="border: 0; border-top: 1px solid #cbd5e1; margin: 20px 0;" />
  <div style="background: #f8fafc; padding: 20px; border-radius: 8px; border: 1px solid #e2e8f0;">
    <p style="white-space: pre-wrap; margin: 0;">${rawFormData.message}</p>
  </div>
</div>
            `, // html body
        });

        return { success: true };
    } catch (error) {
        console.error("Error sending email:", error);
        return { success: false, error: "Failed to send email. Please try again later." };
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { getAuthenticatedUserId } from '@/lib/auth-helper';
import { redis } from '@/lib/redis';

/**
 * Admin endpoint to clear all team data
 * DELETE /api/admin/clear-teams
 */
export async function DELETE(req: NextRequest) {
    try {
        const userId = await getAuthenticatedUserId(req);
        if (!userId) {
            return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
        }

        console.log('[Clear Teams] Starting cleanup...');

        // Find all team-related keys
        const patterns = [
            'team_*',
            'user:*:teams',
            'invitation:*'
        ];

        let totalDeleted = 0;

        for (const pattern of patterns) {
            console.log(`[Clear Teams] Scanning pattern: ${pattern}`);
            let cursor = '0';
            const keysToDelete: string[] = [];

            do {
                const [nextCursor, keys] = await redis.scan(cursor, 'MATCH', pattern, 'COUNT', 100);
                cursor = nextCursor;
                keysToDelete.push(...keys);
            } while (cursor !== '0');

            if (keysToDelete.length > 0) {
                console.log(`[Clear Teams] Deleting ${keysToDelete.length} keys for pattern ${pattern}`);
                await redis.del(...keysToDelete);
                totalDeleted += keysToDelete.length;
            }
        }

        console.log(`[Clear Teams] Done! Deleted ${totalDeleted} keys total`);

        return NextResponse.json({
            success: true,
            keysDeleted: totalDeleted,
            message: 'All team data cleared. Refresh your browser.'
        });
    } catch (error) {
        console.error('[Clear Teams] Error:', error);
        return NextResponse.json(
            { error: 'Failed to clear teams' },
            { status: 500 }
        );
    }
}

import { NextRequest, NextResponse } from 'next/server';
import OpenAI from 'openai';
import { getAuthenticatedUserId, isReadOnlyAccess } from '@/lib/auth-helper';

export const maxDuration = 300; // 5 minutes
export const dynamic = 'force-dynamic';

export async function POST(request: NextRequest) {
    const userId = await getAuthenticatedUserId(request);
    if (!userId) {
        return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    // Demo mode check
    if (await isReadOnlyAccess()) {
        return NextResponse.json({ error: "Analysis disabled in Demo Mode" }, { status: 403 });
    }

    const { policyText, technicalText } = await request.json();
    if (!policyText || !technicalText) {
        return NextResponse.json({ error: "Missing text content" }, { status: 400 });
    }

    const openai = new OpenAI({
        apiKey: process.env.OPENAI_API_KEY,
    });

    const encoder = new TextEncoder();

    const stream = new ReadableStream({
        async start(controller) {
            const sendEvent = (data: unknown) => {
                controller.enqueue(encoder.encode(`data: ${JSON.stringify(data)}\n\n`));
            };

            try {
                // 1. Planning Phase
                sendEvent({ type: 'status', message: 'Analyzing Policy Rhetoric and Technical Reality...' });

                // Parallel Extraction with clearer instructions
                const [rhetoric, reality] = await Promise.all([
                    extractRhetoric(openai, policyText),
                    extractReality(openai, technicalText)
                ]);

                sendEvent({ type: 'status', message: 'Tracing Assemblage Connections...' });

                // 2. Dimensional Tracing (Sequential or Batched for streaming progress)
                const dimensions = [
                    'doc_analysis', 'tech_analysis', 'implementation',
                    'outcome', 'enforcement', 'timeline'
                ];

                for (const dimId of dimensions) {
                    sendEvent({ type: 'status', message: `Analyzing Dimension: ${dimId}...` });

                    const result = await traceDimension(openai, dimId, rhetoric, reality);

                    sendEvent({
                        type: 'result',
                        data: result
                    });
                }

                sendEvent({ type: 'done' });
                controller.close();

            } catch (error) {
                console.error("Streaming analysis failed:", error);
                sendEvent({ type: 'error', message: 'Analysis failed.' });
                controller.close();
            }
        }
    });

    return new NextResponse(stream, {
        headers: {
            'Content-Type': 'text/event-stream',
            'Cache-Control': 'no-cache',
            'Connection': 'keep-alive',
        },
    });
}

async function extractRhetoric(openai: OpenAI, text: string) {
    console.log(`[DRIFT API] Extracting rhetoric from ${text.length} chars...`);
    try {
        const response = await openai.chat.completions.create({
            model: process.env.OPENAI_MODEL || "gpt-4o",
            messages: [
                { role: "system", content: "You are an expert policy analyst. Extract and summarize the core ethical promises, safety claims, and societal values asserted in this document. Focus on what it *claims* it will achieve. Return a clear text summary." },
                { role: "user", content: text.substring(0, 50000) }
            ],
            max_completion_tokens: 2000
        });
        const result = response.choices[0].message.content || "";
        if (result.length < 20) throw new Error("Extraction result too short"); // Loosened from 50

        console.log(`[DRIFT API] Rhetoric extracted (${result.length} chars)`);
        return result;
    } catch (err) {
        console.warn(`[DRIFT API] Rhetoric extraction failed. Using raw text fallback. Error: ${(err as Error).message}`);
        return "Raw Document Excerpt (Extraction Failed):\n" + text.substring(0, 4000); // Reduced to ensure fit
    }
}

async function extractReality(openai: OpenAI, text: string) {
    console.log(`[DRIFT API] Extracting reality from ${text.length} chars...`);
    try {
        const response = await openai.chat.completions.create({
            model: process.env.OPENAI_MODEL || "gpt-4o",
            messages: [
                { role: "system", content: "You are an expert technical auditor. Extract and summarize the actual technical implementation details, architectural decisions, and enforcement mechanisms described. Focus on *how* it works concretely. Return a clear text summary." },
                { role: "user", content: text.substring(0, 50000) }
            ],
            max_completion_tokens: 2000
        });
        const result = response.choices[0].message.content || "";
        if (result.length < 20) throw new Error("Extraction result too short");

        console.log(`[DRIFT API] Reality extracted (${result.length} chars)`);
        return result;
    } catch (err) {
        console.warn(`[DRIFT API] Reality extraction failed. Using raw text fallback. Error: ${(err as Error).message}`);
        return "Raw Document Excerpt (Extraction Failed):\n" + text.substring(0, 4000);
    }
}

async function traceDimension(openai: OpenAI, dimensionId: string, rhetoric: string, reality: string) {
    const dimensionPrompts: Record<string, string> = {
        doc_analysis: "Analyze the gap between the document's high-level ethical promises and its specific definitions/details.",
        tech_analysis: "Analyze the gap between the policy's requirements and the actual technical architecture/code implementation.",
        implementation: "Analyze how the system is deployed in practice vs how it was ideally described.",
        outcome: "Analyze the difference between intended positive impacts and observable real-world complications/harms.",
        enforcement: "Analyze the gap between promised accountability mechanisms and actual recourse/penalties.",
        timeline: "Analyze how the system's purpose or function has drifted or expanded over time (function creep)."
    };

    const prompt = dimensionPrompts[dimensionId] || "Analyze the gap.";
    console.log(`[DRIFT API] Tracing ${dimensionId}...`);

    try {
        const response = await openai.chat.completions.create({
            model: process.env.OPENAI_MODEL || "gpt-4o",
            messages: [
                {
                    role: "system", content: `You are an expert impartial auditor tracing the "drift" between valid Policy Rhetoric and Technical Reality.
      
      Task: ${prompt}
      
      Instructions:
      1. Compare the "Rhetoric" (claims) vs "Reality" (implementation).
      2. If "Raw Document Excerpt" is provided, do your best to analyze the raw text directly.
      3. Identify concrete contradictions or gaps.
      4. Assign a Drift Score (0.0 = aligned, 1.0 = total failure).
      
      Return JSON:
      {
        "driftScore": number,
        "summary": "Short qualitative description of the gap (max 2 sentences)",
        "evidence": {
           "rhetoric": "Quote or specific claim from the text",
           "reality": "Quote or specific mechanism from the text",
           "reasoning": "Why this represents a drift or gap"
        }
      }` },
                { role: "user", content: `Rhetoric Source:\n${rhetoric}\n\nReality Source:\n${reality}` }
            ],
            response_format: { type: "json_object" },
            max_completion_tokens: 1000
        });

        const rawContent = response.choices[0].message.content || "{}";
        console.log(`[DRIFT API] Response for ${dimensionId}:`, rawContent.substring(0, 100) + "...");

        const content = JSON.parse(rawContent);

        // Validate and sanitise
        return {
            dimensionId,
            driftScore: typeof content.driftScore === 'number' ? content.driftScore : parseFloat(content.driftScore) || 0,
            summary: content.summary || "No summary found.",
            evidence: {
                rhetoric: content.evidence?.rhetoric || "No rhetoric extracted.",
                reality: content.evidence?.reality || "No reality extracted.",
                reasoning: content.evidence?.reasoning || "No reasoning provided."
            }
        };
    } catch (e) {
        console.error(`[DRIFT API] Failed to parse/generate dimension ${dimensionId}:`, e);
        return {
            dimensionId,
            driftScore: 0,
            summary: "Analysis generation failed.",
            evidence: { rhetoric: "Error", reality: "Error", reasoning: "AI Error: " + (e as Error).message }
        };
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { getAuthenticatedUserId } from '@/lib/auth-helper';
import { validateWorkspaceAccess } from '@/lib/auth-middleware';
import { StorageService } from '@/lib/storage-service';
import { getSources } from '@/lib/store';
import { GhostNodeStore } from '@/lib/ghost-node-store';
import OpenAI from 'openai';
import { zodResponseFormat } from 'openai/helpers/zod';
import { PromptRegistry } from '@/lib/prompts/registry';
import { ControversyMappingSchema } from '@/lib/prompts/controversy-mapping';
import { compressLensesForControversyMapping, RawLensData } from '@/lib/controversy-compression';

const openai = new OpenAI({
    apiKey: process.env.OPENAI_API_KEY,
});

export const maxDuration = 60; // Allow maximum Vercel timeout for heavy synthesis

async function getEffectiveContext(req: NextRequest, userId: string) {
    const workspaceId = req.headers.get('x-workspace-id');
    const targetContext = workspaceId || userId;
    const access = await validateWorkspaceAccess(userId, targetContext);

    if (!access.allowed) {
        throw new Error('Access Denied to Workspace');
    }

    return { contextId: targetContext, role: access.role };
}

export async function POST(
    request: NextRequest,
) {
    try {
        const userId = await getAuthenticatedUserId(request);
        if (!userId) {
            return NextResponse.json({ success: false, error: 'Unauthorized' }, { status: 401 });
        }

        const { contextId } = await getEffectiveContext(request, userId);

        const body = await request.json();
        const { policyId, documentTitle, force } = body;

        if (!policyId) {
            return NextResponse.json({ success: false, error: 'Missing policyId' }, { status: 400 });
        }

        const titleToUse = documentTitle || policyId;

        // Check cache first if not forced
        if (!force) {
            const cachedMap = await StorageService.get(contextId, `controversy_mapping_${policyId}`);
            if (cachedMap) {
                return NextResponse.json({
                    success: true,
                    isPartial: (cachedMap as Record<string, unknown>).isPartial,
                    sourcesUsed: (cachedMap as Record<string, unknown>).sourcesUsed,
                    controversyMap: cachedMap
                });
            }
        }

        // 1. Fetch the Source object to get attached lenses
        const sources = await getSources(contextId);
        const source = sources.find(s => s.id === policyId);

        if (!source) {
            return NextResponse.json({ success: false, error: 'Source document not found' }, { status: 404 });
        }

        const cultural = source.cultural_framing;
        const institutional = source.institutional_logics;
        const abstractMachine = source.analysis?.abstract_machine;

        // 2. Fetch external strata from Redis / custom stores
        const [
            ghostNodes,
            actors,
            configurations,
            resistanceData,
            allComparisons
        ] = await Promise.all([
            GhostNodeStore.getGhostNodes(contextId, policyId),
            StorageService.get(contextId, `ecosystem_actors_${policyId}`),
            StorageService.get(contextId, `ecosystem_configurations_${policyId}`),
            StorageService.get(contextId, `resistance_synthesis_result_${policyId}`),
            StorageService.get<Record<string, any>>(contextId, `comparison_synthesis_results_v2`)
        ]);

        // Filter pairwise comparisons relevant to this policy
        const crossCaseExport = allComparisons
            ? Object.values(allComparisons).filter((comp: Record<string, unknown>) => typeof comp?.id === 'string' && comp.id.includes(policyId))
            : [];

        const rawData: RawLensData = {
            cultural,
            institutional,
            resistance: resistanceData as Record<string, unknown>,
            abstractMachine,
            actors: actors as unknown as Record<string, unknown>[],
            ghostNodes: ghostNodes as unknown as Record<string, unknown>[],
            configurations: configurations as unknown as Record<string, unknown>[],
            crossCaseExport: crossCaseExport.length > 0 ? crossCaseExport : null
        };

        // 2. Partial-Data Fallback Checks
        let availableCount = 0;
        const availableSources = [];
        for (const [key, val] of Object.entries(rawData)) {
            if (val !== null && val !== undefined && val !== "") {
                if (Array.isArray(val) && val.length === 0) continue;
                availableCount++;
                availableSources.push(key);
            }
        }

        if (availableCount < 3) {
            return NextResponse.json({
                success: false,
                isPartial: true,
                error: `Insufficient data points (${availableCount}). Please run at least 3 analysis lenses (e.g., Cultural Framing, Institutional Logics, Micro-Resistance) before attempting a Controversy Map. Found: ${availableSources.join(', ')}`,
                controversyMap: null
            }, { status: 400 });
        }

        // 3. Compress data aggressively to stay in context window limits
        const compressedJSON = compressLensesForControversyMapping(rawData);

        console.log(`[ControversyMapping] Extracted ${availableCount} lenses. Compressed token size approx: ${compressedJSON.length / 4} tokens.`);

        // 4. Run LLM
        const systemPrompt = await PromptRegistry.getEffectivePrompt(userId, 'controversy_mapping');
        const userPrompt = `Document: ${titleToUse}\n\nLenses Available: ${availableSources.join(', ')}\n\nCOMPRESSED LENS DATA:\n${compressedJSON}\n\nExecute Meta-Synthesis. Map the controversies and return structural JSON.`;

        const completion = await openai.chat.completions.create({
            model: process.env.OPENAI_MODEL || 'gpt-4o-2024-08-06',
            messages: [
                { role: 'system', content: systemPrompt },
                { role: 'user', content: userPrompt }
            ],
            response_format: zodResponseFormat(ControversyMappingSchema, 'controversyMap')
        });

        const content = completion.choices[0].message.content || '{}';

        let parsed;
        try {
            parsed = ControversyMappingSchema.parse(JSON.parse(content));
        } catch (parseError) {
            console.error("[ControversyMapping] LLM Output Parse Error. Raw content:", content);
            throw parseError;
        }

        // 5. Build final map with strict lineage metadata
        const controversyMap = {
            generatedAt: new Date().toISOString(),
            policyId,
            sourcesUsed: availableSources,
            isPartial: availableCount < 7, // If less than 7, inform the UI it's a partial map
            ...parsed
        };

        // Cache the result
        await StorageService.set(contextId, `controversy_mapping_${policyId}`, controversyMap);

        return NextResponse.json({
            success: true,
            isPartial: controversyMap.isPartial,
            sourcesUsed: availableSources,
            controversyMap
        });

    } catch (error: unknown) {
        console.error('[ControversyMappingRoute] Error:', error);
        return NextResponse.json({
            success: false,
            error: error instanceof Error ? error.message : 'Failed to generate controversy map'
        }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { ANTTraceService } from '@/lib/ant-trace-service';
import { AssemblageMechanismService } from '@/lib/assemblage-mechanism-service';
import { ProvisionalWrapper } from '@/lib/provisional-wrapper';
import { getAuthenticatedUserId } from '@/lib/auth-helper';
import { checkRateLimit } from '@/lib/ratelimit';
import { StorageService } from '@/lib/storage-service';

/**
 * POST /api/analyze/hybrid
 * Hybrid reflexive analysis endpoint
 * 
 * Combines ANT tracing with Assemblage ontology
 * Explicitly flags theoretical tensions
 */
export async function POST(request: NextRequest) {
    const userId = await getAuthenticatedUserId(request);

    if (!userId) {
        return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    // Rate limiting
    const rateLimit = await checkRateLimit(userId);
    if (!rateLimit.success) {
        return NextResponse.json(
            { error: `Rate limit exceeded. Try again in ${rateLimit.reset} seconds.` },
            { status: 429 }
        );
    }

    try {
        const { actors, links, configurations, text } = await request.json();

        // Generate cache key
        const cacheKey = `hybrid_analysis:${Buffer.from(text || '').toString('base64').substring(0, 50)}`;

        // Check cache
        const cached = await StorageService.getCache(userId, cacheKey);
        if (cached) {
            console.log('Returning cached hybrid analysis');
            return NextResponse.json(cached);
        }

        // Step 1: ANT Trace (Methodological)
        const tracedActors = ANTTraceService.hydrateWithProvenance(
            actors || [],
            "ai_inference"
        );

        const associations = ANTTraceService.traceAssociations(
            tracedActors,
            links || []
        );

        const antTrace = ANTTraceService.generateTraceResult(
            tracedActors,
            associations
        );

        // Step 2: Assemblage Analysis (Ontological)
        const mechanisms = AssemblageMechanismService.detectTerritorialization(
            tracedActors,
            associations,
            configurations || []
        );

        const capacities = AssemblageMechanismService.identifyCapacities(
            tracedActors,
            associations
        );

        const assemblageAnalysis = {
            mode: "assemblage_realist" as const,
            detected_mechanisms: mechanisms,
            identified_capacities: capacities,
            based_on_trace: {
                actor_count: tracedActors.length,
                association_count: associations.length
            }
        };

        // Step 3: Theoretical Tensions (Reflexive)
        const theoreticalTensions = [
            {
                description: "Instrumentalizing ANT for DeLandian purposes",
                latour_would_reject: "Latour explicitly rejects ontological mechanisms and capacities",
                delanda_requires: "DeLanda's realism requires explanatory mechanisms grounded in empirical traces",
                our_instrumentalization: "We use ANT as methodological foundation for Assemblage ontology, acknowledging this departs from Latour's anti-theoretical stance"
            }
        ];

        // Step 4: Wrap as Provisional Inscription
        const narrativeContent = `Hybrid analysis combining ANT tracing (${tracedActors.length} actors, ${associations.length} associations) with Assemblage mechanisms (${mechanisms.length} detected). This instrumentalizes ANT for DeLandian purposes.`;

        const provisionalStatus = ProvisionalWrapper.wrap(
            narrativeContent,
            "ai_generated",
            0.7
        );

        const result = {
            success: true,
            mode: "hybrid_reflexive",
            ant_trace: antTrace,
            assemblage_analysis: assemblageAnalysis,
            theoretical_tensions: theoreticalTensions,
            provisional_status: provisionalStatus,
            note: "This hybrid analysis explicitly acknowledges theoretical tensions between ANT (method) and Assemblage (ontology)"
        };

        // Cache result (24 hours)
        await StorageService.setCache(userId, cacheKey, result, 60 * 60 * 24);

        return NextResponse.json(result);

    } catch (error) {
        console.error('Hybrid analysis error:', error);
        return NextResponse.json(
            {
                success: false,
                error: 'Hybrid analysis failed',
                details: error instanceof Error ? error.message : 'Unknown error'
            },
            { status: 500 }
        );
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { AssemblageMechanismService } from '@/lib/assemblage-mechanism-service';
import { getAuthenticatedUserId } from '@/lib/auth-helper';
import { checkRateLimit } from '@/lib/ratelimit';
import { StorageService } from '@/lib/storage-service';
import { ProvisionalWrapper } from '@/lib/provisional-wrapper';

/**
 * POST /api/analyze/mechanisms
 * Assemblage Theory ontological analysis endpoint
 * 
 * This endpoint detects DeLandian mechanisms and capacities
 * REQUIRES ANT trace as input (layered approach)
 */
export async function POST(request: NextRequest) {
    const userId = await getAuthenticatedUserId(request);

    if (!userId) {
        return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    // Rate limiting
    const rateLimit = await checkRateLimit(userId);
    if (!rateLimit.success) {
        return NextResponse.json(
            { error: `Rate limit exceeded. Try again in ${rateLimit.reset} seconds.` },
            { status: 429 }
        );
    }

    try {
        const { traced_actors, associations, configurations } = await request.json();

        // Validate that ANT trace is provided
        if (!traced_actors || !associations) {
            return NextResponse.json(
                {
