      };

      if (!analysisToevaluate) {
        return NextResponse.json({ error: "Missing existingAnalysis" }, { status: 400 });
      }

      const escalationStatus = await runEscalationEvaluation(openai, analysisToevaluate, config);

      return NextResponse.json({
        success: true,
        analysis: { escalation_status: escalationStatus }
      });
    }



    // [Feature] Deep Structural Concern Analysis
    if (analysisMode === 'structural_concern') {
      if (!openai) {
        return NextResponse.json({ error: "OpenAI API Key required for Structural Concern Analysis" }, { status: 500 });
      }

      console.log('[ANALYSIS] Mode is STRUCTURAL_CONCERN.');
      const { StructuralConcernService } = await import('@/lib/structural-concern-service');

      if (!requestData.excerpts || !requestData.actorName || !requestData.title) {
        return NextResponse.json({ error: "Missing required fields (excerpts, actorName, title)" }, { status: 400 });
      }

      // 1. Generate Global Hash from Excerpts + Actor
      // This ensures all users on the survey page get the identical cached analysis for the same data
      const excerptNames = requestData.excerpts.map((e: Record<string, unknown>) => typeof e.id === 'string' ? e.id : '').sort().join(',');
      const signaturePayload = `${requestData.actorName}:${requestData.title}:${excerptNames}:${requestData.challengeMode ? 'challenge' : 'standard'}`;

      const encoder = new TextEncoder();
      const data = encoder.encode(signaturePayload);
      const hashBuffer = await crypto.subtle.digest('SHA-256', data);
      const hashArray = Array.from(new Uint8Array(hashBuffer));
      const payloadHash = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
      const globalCacheKey = `structural_concern:${payloadHash}`;

      if (!force) {
        console.log(`[STRUCTURAL_CONCERN] Checking global cache for ${globalCacheKey}...`);
        // We use 'global_analysis' as a shared context block in Redis
        const cachedAnalysis = await StorageService.getCache('global_analysis', globalCacheKey);

        if (cachedAnalysis) {
          console.log(`[CACHE HIT] Returning cached structural analysis.`);
          return NextResponse.json({
            success: true,
            analysis: { structural_concern: cachedAnalysis },
            cached: true
          });
        }
      }

      console.log(`[STRUCTURAL_CONCERN] Cache miss. Generating fresh analysis (challenge: ${!!requestData.challengeMode})...`);
      const result = await StructuralConcernService.analyzeStructuralConcern(
        openai,
        userId,
        requestData.actorName,
        requestData.title,
        requestData.excerpts,
        requestData.context,
        requestData.challengeMode ? 'anti_structural_concern' : 'structural_concern'
      );

      // Save to Global Cache (TTL: 30 days)
      await StorageService.setCache('global_analysis', globalCacheKey, result, 60 * 60 * 24 * 30);

      return NextResponse.json({
        success: true,
        analysis: { structural_concern: result },
        cached: false
      });
    }

    // [Feature] Comprehensive Scan
    if (analysisMode === 'comprehensive_scan') {
      if (!openai) {
        return NextResponse.json({ error: "OpenAI API Key required for Comprehensive Scan" }, { status: 500 });
      }

      // Check cache unless force=true
      if (!force) {
        console.log('[COMPREHENSIVE] Checking cache...');
        const cacheUserId = getCacheUserId(analysisMode, contextId); // Use ContextId
        const cachedAnalysis = await StorageService.getCache(cacheUserId, cacheKey);

        if (cachedAnalysis) {
          console.log(`[CACHE HIT] Returning cached comprehensive analysis for key: ${cacheKey}`);
          console.log(`[ANALYSIS] Completed(Cache Hit) in ${Date.now() - startTime} ms`);
          return NextResponse.json({
            success: true,
            analysis: cachedAnalysis,
            cached: true
          });
        }
        console.log('[COMPREHENSIVE] Cache miss, running fresh analysis.');
      } else {
        console.log('[COMPREHENSIVE] Force=true, skipping cache check.');
      }

      console.log('[ANALYSIS] Mode is COMPREHENSIVE. Running multi-stage workflow.');
      const result = await runComprehensiveAnalysis(openai, contextId, requestData); // Use ContextId

      // Cache the comprehensive result
      try {
        if (result.analysis && typeof result.analysis === 'object') {
          const cacheUserId = getCacheUserId(analysisMode, contextId); // Use ContextId
          await StorageService.setCache(cacheUserId, cacheKey, result.analysis, 86400); // 24 hours
          console.log(`[COMPREHENSIVE] Saved to cache: ${cacheKey}`);
        }
      } catch (saveError) {
        console.warn('[COMPREHENSIVE] Failed to save to cache:', saveError);
      }

      return NextResponse.json({
        success: true,
        analysis: result.analysis,
        usage: result.usage
      });
    }

    // --- PERFORM ANALYSIS VIA SERVICE ---
    if (!openai) {
      return NextResponse.json({ error: "OpenAI API Key required for Standard Analysis" }, { status: 500 });
    }
    const { analysis, usage } = await performAnalysis(openai, contextId, requestData); // Use ContextId

    // --- GHOST NODE DETECTION FOR BOTH MODES (Ontology & Ecosystem) ---
    const detectedNodes = analysis?.nodes || analysis?.assemblage_network?.nodes;
    if (detectedNodes && Array.isArray(detectedNodes)) {
      try {
        console.log(`[API] Starting ghost node detection based on ${detectedNodes.length} discovered entities...`);
        const { analyzeInstitutionalLogicsAndDetectGhostNodes } = await import('@/lib/ghost-nodes');

        // Pass the resolved nodes array so existing actors are considered for similarity checks
        const ghostNodesResult = await analyzeInstitutionalLogicsAndDetectGhostNodes(openai, text, { nodes: detectedNodes }, sourceType, requestData.expectedActors, contextId);

        console.log('[API] Ghost node detection completed:', {
          ghostNodeCount: ghostNodesResult.ghostNodes?.length || 0,
          hasInstitutionalLogics: !!ghostNodesResult.institutionalLogics
        });

        // Add ghost nodes to the analysis
        const nodesToAdd = Array.isArray(ghostNodesResult.ghostNodes) ? ghostNodesResult.ghostNodes : [];
        if (nodesToAdd.length > 0) {
          // Send to correct structure based on which mode we're using
          if (analysisMode === 'assemblage' && analysis.assemblage_network && analysis.assemblage_network.nodes) {
            analysis.assemblage_network.nodes = [...analysis.assemblage_network.nodes, ...nodesToAdd];
          }
          if (analysis.nodes) {
            analysis.nodes = [...analysis.nodes, ...nodesToAdd];
          }

          analysis.institutionalLogics = ghostNodesResult.institutionalLogics;
          analysis.ghostNodeCount = ghostNodesResult.ghostNodes.length;
          if (ghostNodesResult.methodologicalNotes) {
            analysis.methodologicalNotes = ghostNodesResult.methodologicalNotes;
          }
          if (ghostNodesResult.userActorsUsed?.length) {
            analysis.userActorsUsed = ghostNodesResult.userActorsUsed;
          }
          if (ghostNodesResult.dominantDiscourses) {
            analysis.dominantDiscourses = ghostNodesResult.dominantDiscourses;
          }
          console.log('[API] Added', ghostNodesResult.ghostNodes.length, 'ghost nodes to analysis');

          // Append to unified v2.0 catalog
          try {
            const { GhostNodeStore } = await import('@/lib/ghost-node-store');
            const policyId = requestData.documentId || "default_policy";
            for (const gn of ghostNodesResult.ghostNodes) {
              const ghostNodeData = gn as unknown as Record<string, unknown>;
              const ghostReason = typeof ghostNodeData.ghostReason === 'string' ? ghostNodeData.ghostReason : '';
              const absenceStrength = typeof ghostNodeData.absenceStrength === 'number' ? ghostNodeData.absenceStrength : (typeof gn.strength === 'number' ? gn.strength : 50);
              const evidence = Array.isArray(ghostNodeData.evidence)
                ? ghostNodeData.evidence as { rationale: string; quote?: string; context?: string }[]
                : [{ rationale: ghostReason }];

              const ghostData = gn as unknown as GhostNode & Record<string, unknown>;

              const fingerprint = GhostNodeStore.generateFingerprint(
                gn.label,
                policyId,
                gn.category ? [gn.category] : []
              );
              await GhostNodeStore.createGhostNode(contextId, {
                fingerprint,
                policyId,
                name: gn.label,
                description: gn.description || ghostReason,
                category: gn.category,
                confidence: absenceStrength,
                evidence: evidence,
                sourcePipelines: ['ontology_analysis'],
                aliases: [],
                relatedThemes: gn.category ? [gn.category] : [],
                // V2 Fields Passthrough
                evidenceQuotes: ghostData.evidenceQuotes,
                claim: ghostData.claim,
                discourseThreats: ghostData.discourseThreats,
                roster: ghostData.roster,
                missingSignals: ghostData.missingSignals,
                absenceType: ghostData.absenceType,
                exclusionType: ghostData.exclusionType,
                institutionalLogics: ghostData.institutionalLogics,
                potentialConnections: ghostData.potentialConnections
              });
            }
            console.log('[API] Appended ghost nodes to catalog');
          } catch (catalogErr) {
            console.error('[API] Failed to append ghost nodes to unified catalog:', catalogErr);
          }
        }
      } catch (error) {
        console.error('[API] Ghost node detection failed:', error);
        console.error('[API] Error stack:', error instanceof Error ? error.stack : 'No stack trace');
      }
    }

    // ---------------------
    // Cache the result
    try {
      if (analysis && typeof analysis === 'object' && !analysis.error) {
        const cacheUserId = getCacheUserId(analysisMode, contextId); // Use ContextId

        await StorageService.setCache(cacheUserId, cacheKey, analysis, 86400); // 24 hours
        console.log(`[ANALYSIS] Saved to cache: ${cacheKey}`);
      } else {
        console.warn(`[ANALYSIS] Skipping cache for failed/partial analysis. Key: ${cacheKey}`);
      }
    } catch (saveError) {
      console.warn('[ANALYSIS] Failed to save to cache:', saveError);
    }

    console.log(`[ANALYSIS] Request completed successfully in ${Date.now() - startTime} ms`);

    // [DEBUG] Log Node Count
    /* eslint-disable @typescript-eslint/no-explicit-any */
    const debugNodes = (analysis as Record<string, any>)?.assemblage_network?.nodes;
    if (Array.isArray(debugNodes)) {
      console.log(`[DEBUG_DENSITY] AI Generated Node Count: ${debugNodes.length}`);
    } else {
      console.log(`[DEBUG_DENSITY] No assemblage_network found or nodes is not an array.`);
    }

    // [FIX] Normalize topology keys (AI sometimes uses 'territorial' or 'territorial_scope' instead of 'scope')
    const topology = (analysis as Record<string, any>)?.topology_analysis;
    /* eslint-enable @typescript-eslint/no-explicit-any */
    if (topology) {
      const keys = Object.keys(topology);
      console.log(`[DEBUG_TOPOLOGY] Received topology keys: ${keys.join(', ')}`);

      if (!topology.scope) {
        console.warn('[DEBUG_TOPOLOGY] "scope" key missing! Attempting to find alias...');
        const alias = keys.find(k => k.includes('territorial') || k.includes('scope'));
        if (alias && topology[alias]) {
          console.log(`[DEBUG_TOPOLOGY] Found alias "${alias}", mapping to "scope"`);
          topology.scope = topology[alias];
        } else {
          console.warn('[DEBUG_TOPOLOGY] No alias found. Injecting default empty scope to prevent UI collapse.');
          // Inject default to prevent UI disappearing solely due to missing data
          topology.scope = {
            axis: "Territorial Scope",
            a_score: 5, b_score: 5,
            anchors: { low: "Domestic/Sovereign", high: "Extraterritorial/Market" },
            description: "Data for this axis was not generated by the AI model.",
            confidence: 0,
            evidence: { a_quotes: [], b_quotes: [] }
          };
        }
      }
    } else {
      console.warn('[DEBUG_TOPOLOGY] topology_analysis object is MISSING entirely.');
    }

    const { TransparencyService } = await import('@/services/transparency-service');
    const transparency = TransparencyService.generateTransparencyReport(analysis);

    return NextResponse.json({
      success: true,
      analysis,
      usage,
      transparency
    });

  } catch (error: unknown) {
    console.error(`[ANALYSIS ERROR] Failed after ${Date.now() - startTime} ms: `, error);
    const errorMessage = error instanceof Error ? error.message : 'Unknown error';
    return NextResponse.json(
      {
        error: 'Analysis failed',
        details: errorMessage
      },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { ANTTraceService } from '@/lib/ant-trace-service';
import { getAuthenticatedUserId } from '@/lib/auth-helper';
import { checkRateLimit } from '@/lib/ratelimit';
import { StorageService } from '@/lib/storage-service';

/**
 * POST /api/analyze/trace
 * Pure ANT methodological tracing endpoint
 * 
 * This endpoint performs ONLY empirical tracing - no ontological claims
 */
export async function POST(request: NextRequest) {
    const userId = await getAuthenticatedUserId(request);

    if (!userId) {
        return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    // Rate limiting
    const rateLimit = await checkRateLimit(userId);
    if (!rateLimit.success) {
        return NextResponse.json(
            { error: `Rate limit exceeded. Try again in ${rateLimit.reset} seconds.` },
            { status: 429 }
        );
    }

    try {
        const { actors, links, text } = await request.json();

        // Generate cache key
        const cacheKey = `ant_trace:${Buffer.from(text || '').toString('base64').substring(0, 50)}`;

        // Check cache
        const cached = await StorageService.getCache(userId, cacheKey);
        if (cached) {
            console.log('Returning cached ANT trace');
            return NextResponse.json(cached);
        }

        // Perform ANT tracing (pure methodological)
        const tracedActors = ANTTraceService.hydrateWithProvenance(
            actors || [],
            "ai_inference" // Would be determined by actual extraction method
        );

        const associations = ANTTraceService.traceAssociations(
            tracedActors,
            links || []
        );

        const result = ANTTraceService.generateTraceResult(
            tracedActors,
            associations,
            undefined // translation sequence would be generated here
        );

        // Cache result (24 hours)
        await StorageService.setCache(userId, cacheKey, result, 60 * 60 * 24);

        return NextResponse.json({
            success: true,
            ...result,
            note: "This is a methodological trace (ANT). For ontological explanation, use /api/analyze/mechanisms"
        });

    } catch (error) {
        console.error('ANT trace error:', error);
        return NextResponse.json(
            {
                success: false,
                error: 'Trace generation failed. Check input completeness.',
                details: error instanceof Error ? error.message : 'Unknown error'
            },
            { status: 500 }
        );
    }
}

import { NextResponse } from 'next/server';
import OpenAI from 'openai';
import { EcosystemActor } from '@/types/ecosystem';

// --- Type Definitions ---
interface DetectRequest {
    actors: EcosystemActor[];
    edges: { source: string; target: string; type: string }[];
}



interface AdjacencyList {
    [key: string]: {
        [target: string]: number;
    };
}

// --- Helper: Cosine Similarity ---
function cosineSimilarity(vecA: number[], vecB: number[]) {
    let dotProduct = 0;
    let normA = 0;
    let normB = 0;
    for (let i = 0; i < vecA.length; i++) {
        dotProduct += vecA[i] * vecB[i];
        normA += vecA[i] * vecA[i];
        normB += vecB[i] * vecB[i];
    }
    return dotProduct / (Math.sqrt(normA) * Math.sqrt(normB));
}

// --- Helper: Louvain Algorithm Implementation ---
// A simplified implementation of the Louvain method for modularity optimization
class Louvain {
    nodes: string[];
    adj: AdjacencyList;
    totalGraphWeight: number;
    nodeWeights: { [key: string]: number };
    communities: { [node: string]: number }; // node -> communityId
    communityWeights: { [comm: number]: number }; // tot (sum of weights of links incident to nodes in comm)
    internalWeights: { [comm: number]: number }; // in (sum of weights of links inside comm)

    constructor(nodes: string[], adj: AdjacencyList) {
        this.nodes = nodes;
        this.adj = adj;
        this.totalGraphWeight = 0;
        this.nodeWeights = {};
        this.communities = {};
        this.communityWeights = {};
        this.internalWeights = {};

        // Initialize
        nodes.forEach((node, i) => {
            this.communities[node] = i;
            this.internalWeights[i] = 0;

            // Calculate node weight (k_i)
            let w = 0;
            if (adj[node]) {
                Object.values(adj[node]).forEach(weight => {
                    w += weight;
                    // For the total graph weight, each undirected edge is counted twice here if the adj is symmetric
                    // We'll standardise that later.
                });
            }
            this.nodeWeights[node] = w;
            this.communityWeights[i] = w;
            this.totalGraphWeight += w;
        });

        this.totalGraphWeight /= 2; // m
    }

    // Helper to get weight between node and a community
    getWeightToCommunity(node: string, commId: number): number {
        let weight = 0;
        const neighbors = this.adj[node] || {};
        Object.entries(neighbors).forEach(([neighbor, w]) => {
            if (this.communities[neighbor] === commId) {
                weight += w;
            }
        });
        return weight;
    }

    run(maxPasses = 5) {
        let improvement = true;
        let passes = 0;

        while (improvement && passes < maxPasses) {
            improvement = false;
            passes++;

            // Randomize node order? (Optional, but good for stability)
            const shuffledNodes = [...this.nodes].sort(() => Math.random() - 0.5);

            shuffledNodes.forEach(node => {
                const currentComm = this.communities[node];
                const k_i = this.nodeWeights[node];
                const k_i_in_current = this.getWeightToCommunity(node, currentComm);

                // Remove node from current community
                this.communityWeights[currentComm] -= k_i;
                this.internalWeights[currentComm] -= (2 * k_i_in_current + (this.adj[node]?.[node] || 0)); // self loop handled?
                // Note: simple removal logic. 

                // Find best community
                let bestComm = currentComm;
                let bestGain = 0;

                // Check neighbors' communities
                const neighborComms = new Set<number>();
                const neighbors = this.adj[node] || {};
                Object.keys(neighbors).forEach(neighbor => neighborComms.add(this.communities[neighbor]));

                // Also always consider own isolated community? 
                // For simplicity in this phase 1 implementation, we move to neighbor communities.

                for (const commId of Array.from(neighborComms)) {
                    if (commId === currentComm) continue; // Skip if conceptually removed (logic above is slight approx)

                    const k_i_in = this.getWeightToCommunity(node, commId);
                    const tot = this.communityWeights[commId];

                    // Modularity Gain Formula (Simplified)
                    // Delta Q = [ (Sigma_in + k_i_in)/2m - ((Sigma_tot + k_i)/2m)^2 ] - [ Sigma_in/2m - (Sigma_tot/2m)^2 - (k_i/2m)^2 ]
                    // We just need to maximize: k_i_in - (tot * k_i) / m
                    const gain = k_i_in - (tot * k_i) / (2 * this.totalGraphWeight);

                    if (gain > bestGain) {
                        bestGain = gain;
                        bestComm = commId;
                    }
                }

                // If moving to bestComm is better than staying (which has 0 gain relative to removed state if optimal)
                // Actually we compared gains relative to *current* state.
                // Re-add to best comm
                this.communities[node] = bestComm;
                this.communityWeights[bestComm] += k_i;

                if (bestComm !== currentComm) {
                    improvement = true;
                }
            });
        }

        return this.communities;
    }
}

export async function POST(req: Request) {
    try {
        const { actors, edges } = await req.json() as DetectRequest;

        if (!actors || actors.length < 3) {
            return NextResponse.json({
                success: false,
                message: "Not enough actors for clustering."
            }, { status: 400 });
        }

        // 1. Initialize OpenAI
        const openai = new OpenAI({
            apiKey: process.env.OPENAI_API_KEY
        });

        // 2. Generate Embeddings (Batch)
        console.log(`Generating embeddings for ${actors.length} actors...`);
        const inputs = actors.map(a => `${a.name}: ${a.description || a.type}`);

        const embeddingResponse = await openai.embeddings.create({
            model: "text-embedding-3-small",
            input: inputs,
        });

        const embeddings = embeddingResponse.data.map(d => d.embedding);

        // 3. Build Hybrid Weighted Graph
        // Edge Weight = Structural (1.0 for existing link) + Semantic (Cosine Similarity)
        const adj: AdjacencyList = {};

        // Initialize Adj
        actors.forEach(a => adj[a.id] = {});

        // Add Semantic Edges (All-to-All) - Thresholded
        const SIMILARITY_THRESHOLD = 0.4; // Only connect if minimally relevant
        const SEMANTIC_WEIGHT_FACTOR = 0.8;

        for (let i = 0; i < actors.length; i++) {
            for (let j = i + 1; j < actors.length; j++) {
                const sim = cosineSimilarity(embeddings[i], embeddings[j]);
                if (sim > SIMILARITY_THRESHOLD) {
                    const weight = sim * SEMANTIC_WEIGHT_FACTOR;
                    adj[actors[i].id][actors[j].id] = (adj[actors[i].id][actors[j].id] || 0) + weight;
                    adj[actors[j].id][actors[i].id] = (adj[actors[j].id][actors[i].id] || 0) + weight;
                }
            }
        }

        // Add Structural Edges (Reinforce Semantic)
        const STRUCTURAL_WEIGHT = 2.0;
        edges.forEach(e => {
            if (adj[e.source] && adj[e.target]) { // Check existence
                adj[e.source][e.target] = (adj[e.source][e.target] || 0) + STRUCTURAL_WEIGHT;
                adj[e.target][e.source] = (adj[e.target][e.source] || 0) + STRUCTURAL_WEIGHT;
            }
        });

        // 4. Run Louvain
        const louvain = new Louvain(actors.map(a => a.id), adj);
        const communityMap = louvain.run();

        // 5. Group Results
        const communities: { [id: string]: string[] } = {};
        Object.entries(communityMap).forEach(([nodeId, commId]) => {
            if (!communities[commId]) communities[commId] = [];
            communities[commId].push(nodeId);
        });

        // Limit to top 3 largest to save tokens on naming
        const topCommunityKeys = Object.keys(communities)
            .sort((a, b) => communities[b].length - communities[a].length)
            .slice(0, 3);

        // 6. Generate Descriptive Names (Batch)
        const namingPrompts = topCommunityKeys.map(commId => {
            const members = communities[commId];
            const memberDetails = members.map(id => {
                const a = actors.find(act => act.id === id);
                return `${a?.name} (${a?.type})`;
            }).join(', ');
            return `Group ${commId}: ${memberDetails}`;
        }).join('\n');

        const nameResponse = await openai.chat.completions.create({
            model: "gpt-4o-mini",
            messages: [
                { role: "system", content: "You are a sociologist analyzing socio-technical assemblages. Given a list of actors in a group, provide a SHORT, TEMATIC title (max 4 words) that describes their collective function or domain (e.g., 'Algorithmic Surveillance Network', 'EU Compliance Layer'). Return ONLY a JSON object mapping 'Group ID' to 'Title'." },
                { role: "user", content: `Name these groups:\n${namingPrompts}` }
            ],
            response_format: { type: "json_object" }
        });

        const names = JSON.parse(nameResponse.choices[0].message.content || "{}");

        // Format as Configurations
        const suggestions = topCommunityKeys.map(commId => {
            const members = communities[commId];
            const commActors = actors.filter(a => members.includes(a.id));
            const types = commActors.map(a => a.type);
            const distinctTypes = Array.from(new Set(types));

            // Calculate Diversity
            const diversityScore = distinctTypes.length / Math.min(members.length, 5);

            // Calculate Metrics
            const humanTypes = ['Policymaker', 'Civil Society', 'Academic', 'User', 'Technologist'];
            const humanCount = commActors.filter(a => humanTypes.some(t => a.type.includes(t))).length;
            const nonHumanCount = members.length - humanCount;

            // Use AI Name or Fallback
            const name = names[`Group ${commId}`] || names[commId] || `Assemblage ${commId}`;

            return {
                id: `sugg-${crypto.randomUUID()}`,
                name,
                memberIds: members,
                nodes: members,
                description: `AI-detected community of ${members.length} actors.`,
                type: "detected",
                diversityScore: Math.min(1.0, diversityScore),
                metrics: {
                    size: members.length,
                    humanCount,
                    nonHumanCount
                }
            };
        });

        return NextResponse.json({
            success: true,
            suggestions
        });

    } catch (error) {
        console.error("Assemblage Detection Error:", error);
        return NextResponse.json({ success: false, message: "Detection failed" }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { getAuthenticatedUserId } from '@/lib/auth-helper';
import { CollaborationService } from '@/services/collaboration-service';
import { createErrorResponse, createUnauthorizedResponse } from '@/lib/api-helpers';

export async function POST(req: NextRequest) {
    try {
        const userId = await getAuthenticatedUserId(req);
        if (!userId) return createUnauthorizedResponse();

        const body = await req.json();
        let { token } = body;

        // URL-decode the token (colon gets encoded as %3A in URLs)
        token = decodeURIComponent(token);

        console.log('[Accept Invitation]', {
            userId,
            token,
            tokenLength: token?.length,
            hasColon: token?.includes(':'),
            timestamp: new Date().toISOString()
        });

        if (!token) {
            return NextResponse.json({ error: "Missing Invitation Token" }, { status: 400 });
        }

        const result = await CollaborationService.acceptInvitation(userId, token);

        if (!result.success) {
            return NextResponse.json({ error: result.error }, { status: 400 });
        }

        return NextResponse.json({ success: true, teamId: result.teamId });
    } catch (error) {
        return createErrorResponse(error);
    }
}

