        const content = completion.choices[0].message.content;
        if (!content) throw new Error('No content from AI');

        const simulationData = JSON.parse(content);

        // Add timestamp to cached data
        const dataToCache = {
            ...simulationData,
            timestamp: new Date().toISOString(),
        };

        // Store in cache with TTL
        try {
            await redis.setex(
                cacheKey,
                DETERRITORIALIZATION_CACHE_TTL, // 24 hours
                JSON.stringify(dataToCache)
            );
        } catch (cacheError) {
            console.warn('Cache write error:', cacheError);
            // Continue even if cache fails
        }

        return NextResponse.json({
            success: true,
            data: dataToCache,
            cached: false,
            cacheKey: actorHash
        });

    } catch (error: any) {
        console.error('Territorialization simulation error:', error);
        return NextResponse.json(
            { success: false, error: error.message },
            { status: 500 }
        );
    }
}

export async function GET(req: NextRequest) {
    try {
        const { userId } = await auth();
        if (!userId) {
            return NextResponse.json(
                { success: false, error: 'Unauthorized' },
                { status: 401 }
            );
        }

        const { searchParams } = new URL(req.url);
        const actorsJson = searchParams.get('actors');
        const context = searchParams.get('context') || undefined;

        if (!actorsJson) {
            return NextResponse.json(
                { success: false, error: 'Missing actors parameter' },
                { status: 400 }
            );
        }

        const actors = JSON.parse(actorsJson);
        const actorHash = generateActorHash(actors, context);
        const cacheKey = getTerritorizationCacheKey(userId, actorHash);

        const cached = await redis.get(cacheKey);
        if (cached) {
            const cachedData = JSON.parse(cached);
            return NextResponse.json({
                success: true,
                data: cachedData,
                cached: true,
                cacheKey: actorHash
            });
        }

        return NextResponse.json({
            success: true,
            data: null,
            cached: false
        });

    } catch (error: any) {
        console.error('Cache retrieval error:', error);
        return NextResponse.json(
            { success: false, error: error.message },
            { status: 500 }
        );
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { updateSource, deleteSource } from '@/lib/store';
import { getAuthenticatedUserId, isReadOnlyAccess } from '@/lib/auth-helper';

export async function PUT(
    request: NextRequest,
    { params }: { params: Promise<{ id: string }> }
) {
    if (await isReadOnlyAccess()) {
        return NextResponse.json({ error: "Updates disabled in Demo Mode" }, { status: 403 });
    }

    const userId = await getAuthenticatedUserId(request);

    if (!userId) {
        return new NextResponse("Unauthorized", { status: 401 });
    }

    // Use workspace ID if provided (for team workspaces), otherwise use user ID
    const workspaceId = request.headers.get('x-workspace-id') || userId;

    try {
        const { id } = await params;
        console.log(`[API] PUT /sources/${id} - Attempting update for Workspace: ${workspaceId} (User: ${userId})`);

        const body = await request.json();
        const updatedSource = await updateSource(workspaceId, id, body);

        if (!updatedSource) {
            console.error(`[API] Source not found for Workspace: ${workspaceId}, SourceID: ${id}`);
            // Verification: Log available source IDs for this workspace to see if it exists
            const { getSources } = await import('@/lib/store');
            const existing = await getSources(workspaceId);
            console.log(`[API] Workspace ${workspaceId} has ${existing.length} sources. IDs: ${existing.map((s: any) => s.id).join(', ')}`);

            return NextResponse.json({ error: 'Source not found' }, { status: 404 });
        }

        return NextResponse.json(updatedSource);
    } catch (error: unknown) {
        console.error('Update source error:', error);
        const errorMessage = error instanceof Error ? error.message : 'Unknown error';
        return NextResponse.json({ error: `Failed to update source: ${errorMessage}` }, { status: 500 });
    }
}

export async function DELETE(
    request: NextRequest,
    { params }: { params: Promise<{ id: string }> }
) {
    if (await isReadOnlyAccess()) {
        return NextResponse.json({ error: "Deletion disabled in Demo Mode" }, { status: 403 });
    }

    const userId = await getAuthenticatedUserId(request);

    if (!userId) {
        return new NextResponse("Unauthorized", { status: 401 });
    }

    // Use workspace ID if provided (for team workspaces), otherwise use user ID
    const workspaceId = request.headers.get('x-workspace-id') || userId;

    try {
        const { id } = await params;
        console.log(`[API] DELETE /sources/${id} - Attempting deletion for Workspace: ${workspaceId} (User: ${userId})`);

        await deleteSource(workspaceId, id);
        return new NextResponse(null, { status: 204 });
    } catch (error: unknown) {
        console.error('Delete source error:', error);
        const errorMessage = error instanceof Error ? error.message : 'Unknown error';
        return NextResponse.json({ error: `Failed to delete source: ${errorMessage}` }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { getSources } from '@/lib/store';
import { getAuthenticatedUserId } from '@/lib/auth-helper';
import { validateWorkspaceAccess } from '@/lib/auth-middleware';

// Helper to resolve effective context
async function getEffectiveContext(req: NextRequest, userId: string) {
    const workspaceId = req.headers.get('x-workspace-id');
    const targetContext = workspaceId || userId;
    const access = await validateWorkspaceAccess(userId, targetContext);

    if (!access.allowed) {
        throw new Error('Access Denied to Workspace');
    }

    return { contextId: targetContext, role: access.role };
}

export async function GET(request: NextRequest) {
    const userId = await getAuthenticatedUserId(request);
    if (!userId) return new NextResponse("Unauthorized", { status: 401 });

    try {
        const { contextId } = await getEffectiveContext(request, userId);
        const sources = await getSources(contextId);

        const searchParams = request.nextUrl.searchParams;
        const isListOnly = searchParams.get('list') === 'true';
        const idsParam = searchParams.get('ids');

        // Filter sources to only those that have an abstract machine extracted
        const sourcesWithMachines = sources.filter(s => s.analysis?.abstract_machine);

        if (idsParam) {
            const ids = idsParam.split(',').map(id => id.trim());
            // Return full abstract machines for requested IDs
            const requestedMachines = sourcesWithMachines
                .filter(s => ids.includes(s.id))
                .map(s => ({
                    id: s.id,
                    title: s.title,
                    abstract_machine: s.analysis!.abstract_machine
                }));
            return NextResponse.json(requestedMachines);
        }

        // Default or list=true: return lightweight list
        const lightweightList = sourcesWithMachines.map(s => ({
            id: s.id,
            title: s.title
        }));

        return NextResponse.json(lightweightList);

    } catch (e) {
        const msg = e instanceof Error ? e.message : 'Unknown Error';
        if (msg === 'Access Denied to Workspace') return new NextResponse("Forbidden", { status: 403 });
        return NextResponse.json({ error: 'Failed to fetch abstract machines' }, { status: 500 });
    }
}

import { headers } from 'next/headers';
import { NextRequest, NextResponse } from 'next/server';
import { stripe } from '@/lib/stripe';
import { addCredits } from '@/lib/redis-scripts';
import Stripe from 'stripe';

// This is required for webhooks to handle raw body
export const dynamic = 'force-dynamic';

export async function POST(req: NextRequest) {
    const body = await req.text();
    const signature = (await headers()).get('stripe-signature');

    let event: Stripe.Event;

    try {
        if (!signature || !process.env.STRIPE_WEBHOOK_SECRET) {
            console.error("[Stripe Webhook] Missing signature or secret");
            throw new Error('Missing signature or secret');
        }
        event = stripe.webhooks.constructEvent(
            body,
            signature,
            process.env.STRIPE_WEBHOOK_SECRET
        );
    } catch (err: any) {
        console.error(`[Stripe Webhook] Signature verification failed: ${err.message}`);
        return NextResponse.json({ error: 'Webhook Error' }, { status: 400 });
    }

    // Handle the event
    if (event.type === 'checkout.session.completed') {
        const session = event.data.object as Stripe.Checkout.Session;

        // Extract metadata
        const userId = session.client_reference_id;
        const amountPurchased = parseInt(session.metadata?.credits || '0', 10);

        // Fallback: If using a fixed price ID, you might map it to credits here
        // But passing it in metadata is safer/easier for dynamic implementation

        if (userId && amountPurchased > 0) {
            console.log(`[Stripe Webhook] Adding ${amountPurchased} credits to user ${userId}`);
            try {
                // Determine payment Ref
                const referenceId = session.payment_intent as string || session.id;

                await addCredits(userId, amountPurchased, 'STRIPE', referenceId, 'PURCHASE');
                console.log(`[Stripe Webhook] Successfully credited user ${userId}`);
            } catch (error) {
                console.error('[Stripe Webhook] Failed to add credits:', error);
                return NextResponse.json({ error: 'Failed to credit user' }, { status: 500 });
            }
        } else {
            console.warn('[Stripe Webhook] Missing userId or credits metadata', { userId, metadata: session.metadata });
        }
    }

    return NextResponse.json({ received: true });
}

