                                                        {doc.jurisdiction}
                                                    </Badge>
                                                )}
                                            </SelectItem>
                                        ))}
                                    </SelectContent>
                                </Select>
                            </div>
                        ))}
                    </div>
                </CardContent>
            </Card>

            {/* Analysis Type Tabs */}
            {selectedSources.length >= 2 && (
                <>
                    <div className="flex gap-2">
                        <Button
                            variant={activeTab === "cultural" ? "default" : "outline"}
                            onClick={() => setActiveTab("cultural")}
                            className="flex-1"
                        >
                            <Globe2 className="mr-2 h-4 w-4" />
                            Cultural Framing
                        </Button>
                        <Button
                            variant={activeTab === "logics" ? "default" : "outline"}
                            onClick={() => setActiveTab("logics")}
                            className="flex-1"
                        >
                            <Scale className="mr-2 h-4 w-4" />
                            Institutional Logics
                        </Button>
                        <Button
                            variant={activeTab === "legitimacy" ? "default" : "outline"}
                            onClick={() => setActiveTab("legitimacy")}
                            className="flex-1"
                        >
                            <Scale className="mr-2 h-4 w-4" />
                            Legitimacy
                        </Button>

                        <div className="flex-1 flex gap-2">
                            <Button
                                variant={activeTab === "synthesis" ? "default" : "outline"}
                                onClick={() => {
                                    if (currentResult) {
                                        // If results exist, just switch to the tab
                                        setActiveTab("synthesis");
                                    } else {
                                        // Otherwise, run synthesis
                                        handleSynthesize();
                                    }
                                }}
                                disabled={isSynthesizing || isReadOnly}
                                title={isReadOnly ? "Synthesis disabled in Demo Mode" : ""}
                                className="flex-1 bg-indigo-50 text-indigo-700 hover:bg-indigo-100 border-indigo-200">
                                {isSynthesizing ? (
                                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                ) : (
                                    <Sparkles className="mr-2 h-4 w-4" />
                                )}
                                {currentResult ? "View Synthesis" : "Synthesize"}
                            </Button>
                            {(currentResult || isSynthesizing) && (
                                <Button
                                    variant="outline"
                                    size="icon"
                                    onClick={() => handleSynthesize(true)}
                                    disabled={isReadOnly || isSynthesizing}
                                    title={isReadOnly ? "Cache clearing disabled in Demo Mode" : "Clear Cache & Re-run Synthesis"}
                                    className={`text-slate-400 hover:text-red-600 shrink-0 ${isSynthesizing ? 'animate-spin' : ''}`}
                                >
                                    <RefreshCw className="h-4 w-4" />
                                </Button>
                            )}
                        </div>
                    </div>

                    {synthesisError && (
                        <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-md flex items-center gap-2 text-sm">
                            <AlertTriangle className="h-4 w-4" />
                            {synthesisError}
                        </div>
                    )}

                    {activeTab === "cultural" && (
                        <div className="space-y-6">
                            <Card className="border-slate-200 shadow-sm">
                                <CardHeader className="pb-4">
                                    <div className="flex items-center justify-between">
                                        <div>
                                            <CardTitle>Cultural Framing Comparison</CardTitle>
                                            <CardDescription>
                                                Comparing the deep cultural assumptions across jurisdictions.
                                            </CardDescription>
                                        </div>
                                    </div>
                                </CardHeader>
                                <CardContent>
                                    <Tabs defaultValue="state_market_society" className="w-full">
                                        <div className="overflow-x-auto pb-2 mb-4">
                                            <TabsList className="bg-slate-100/50 p-1 w-full md:w-auto flex md:inline-flex justify-start">
                                                <TabsTrigger value="state_market_society">State-Market Relations</TabsTrigger>
                                                <TabsTrigger value="technology_role">Technology Role</TabsTrigger>
                                                <TabsTrigger value="rights_conception">Rights Conception</TabsTrigger>
                                                <TabsTrigger value="historical_context">Historical Context</TabsTrigger>
                                                <TabsTrigger value="epistemic_authority">Epistemic Authority</TabsTrigger>
                                            </TabsList>
                                        </div>

                                        {(["state_market_society", "technology_role", "rights_conception", "historical_context", "epistemic_authority"] as const).map((dimension) => (
                                            <TabsContent key={dimension} value={dimension} className="mt-0 focus-visible:ring-0">
                                                <CulturalFramingTable dimension={dimension} sources={selectedSources} />
                                            </TabsContent>
                                        ))}
                                    </Tabs>
                                </CardContent>
                            </Card>
                        </div>
                    )}

                    {/* Institutional Logics Comparison */}
                    {activeTab === "logics" && (
                        <div className="space-y-6">
                            <Card>
                                <CardHeader>
                                    <CardTitle>Institutional Logics Comparison</CardTitle>
                                    <CardDescription>
                                        Which institutional logics dominate in each jurisdiction?
                                    </CardDescription>
                                </CardHeader>
                                <CardContent>
                                    <InstitutionalLogicsTable sources={selectedSources} />
                                </CardContent>
                            </Card>
                        </div>
                    )}

                    {/* Legitimacy Analysis Comparison */}
                    {activeTab === "legitimacy" && (
                        <div className="space-y-6">
                            <Card>
                                <CardHeader>
                                    <CardTitle>Legitimacy & Justification Comparison</CardTitle>
                                    <CardDescription>
                                        Compare the moral arguments and orders of worth used in each jurisdiction.
                                    </CardDescription>
                                </CardHeader>
                                <CardContent>
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                        {selectedSources.map((source, idx) => (
                                            <div key={idx} className="space-y-4">
                                                <div className="flex items-center justify-between border-b pb-2">
                                                    <h3 className="font-semibold text-lg">{source.title}</h3>
                                                </div>
                                                {renderAnalysisButtonOrContent(source, 'legitimacy', (
                                                    source.legitimacy_analysis ? (
                                                        <LegitimacyAnalysisView analysis={source.legitimacy_analysis} />
                                                    ) : null
                                                ))}
                                            </div>
                                        ))}
                                    </div>
                                </CardContent>
                            </Card>
                        </div>
                    )}

                    {/* Comparative Synthesis Tab */}
                    {activeTab === "synthesis" && (
                        <div className="space-y-6">
                            <Card className="border-indigo-100 shadow-sm">
                                <CardHeader className="bg-indigo-50/50">
                                    <CardTitle className="text-indigo-900 flex items-center gap-2">
                                        <Sparkles className="h-5 w-5 text-indigo-600" />
                                        Comparative Synthesis
                                    </CardTitle>
                                    <CardDescription>
                                        AI-generated synthesis of cultural, institutional, and legitimacy dynamics across jurisdictions.
                                    </CardDescription>
                                </CardHeader>
                                <CardContent className="pt-6">
                                    {!currentResult && !isSynthesizing && (
                                        <div className="text-center py-12 text-slate-500">
                                            <Sparkles className="h-12 w-12 mx-auto mb-4 text-slate-300" />
                                            <p className="font-medium text-slate-700">No {activeLens} analysis generated yet</p>
                                            <p className="text-sm mt-2 max-w-sm mx-auto">
                                                Each interpretation lens requires a separate AI analysis. Click &quot;Synthesize&quot; to generate findings specifically for the <strong>{activeLens}</strong> perspective.
                                            </p>
                                        </div>
                                    )}

                                    {isSynthesizing && (
                                        <div className="text-center py-12 text-slate-500">
                                            <Loader2 className="h-12 w-12 mx-auto mb-4 animate-spin text-indigo-500" />
                                            <p>Synthesizing analysis across {selectedSources.length} documents...</p>
                                            <p className="text-xs text-slate-400 mt-2">This may take a minute.</p>
                                        </div>
                                    )}

                                    {currentResult && (
                                        <div className="space-y-8 animate-in fade-in duration-500">

                                            {/* [TRANSPARENCY] Transparency Dialog */}
                                            <PromptDialog
                                                open={showTransparency}
                                                onOpenChange={setShowTransparency}
                                                metadata={currentResult.metadata}
                                                provenance={undefined} // Provenance not yet tracked for synthesis
                                            />

                                            {/* [TRANSPARENCY] Banner */}
                                            {currentResult.metadata && (
                                                <div className="flex items-center gap-3 p-4 bg-gradient-to-r from-indigo-50 to-purple-50 border border-indigo-200 rounded-lg">
                                                    <div className="flex-1">
                                                        <h4 className="text-sm font-semibold text-indigo-900 mb-1">AI Transparency</h4>
                                                        <p className="text-xs text-indigo-700">View the exact prompt used for this synthesis</p>
                                                    </div>
                                                    <div className="flex items-center gap-2">
                                                        {currentResult.confidence && (
                                                            <ConfidenceBadge confidence={currentResult.confidence} />
                                                        )}
                                                        <Button
                                                            onClick={() => setShowTransparency(true)}
                                                            variant="outline"
                                                            size="sm"
                                                            className="bg-white hover:bg-indigo-50 border-indigo-300"
                                                        >
                                                            <Eye className="h-4 w-4 mr-2" />
                                                            Show Prompt
                                                        </Button>
                                                    </div>
                                                </div>
                                            )}
                                            {/* Top Bar: Lens Selector */}
                                            <div className="flex justify-between items-center bg-white p-3 rounded-lg border border-slate-200">
                                                <div className="text-sm font-medium text-slate-600">Active Interpretation Lens:</div>
                                                <LensSelector currentLens={activeLens} onLensChange={setActiveLens} />
                                            </div>

                                            {/* Executive Summary with Assemblage Tone */}
                                            <div className="bg-gradient-to-br from-indigo-50 to-white p-6 rounded-xl border border-indigo-100 shadow-sm">
                                                <h3 className="text-lg font-semibold text-indigo-900 mb-4 flex items-center gap-2">
                                                    <Sparkles className="h-5 w-5 text-indigo-600" />
                                                    Relational Summary
                                                </h3>
                                                <RebuttalPopover targetId="summary" initialRebuttal="" onSave={(id, txt) => console.log(id, txt)}>
                                                    <div className="prose prose-slate max-w-none text-slate-700 leading-relaxed cursor-pointer hover:bg-white/50 transition-colors rounded p-2 -ml-2">
                                                        <p className="whitespace-pre-wrap">{currentResult.synthesis_summary}</p>
                                                    </div>
                                                </RebuttalPopover>
                                            </div>

                                            {/* Network & Stabilization Row */}
                                            <div className="grid lg:grid-cols-3 gap-6 min-h-[400px]">
                                                <div className="lg:col-span-2 h-full">
                                                    <RhizomeNetwork network={currentResult.assemblage_network!} />
                                                </div>
                                                <div className="h-full">
                                                    {currentResult.stabilization_mechanisms && (
                                                        <StabilizationCard mechanisms={currentResult.stabilization_mechanisms} />
                                                    )}
                                                </div>
                                            </div>

                                            {/* Mutation Table */}
                                            {currentResult.concept_mutations && (
                                                <div className="mt-8">
                                                    <MutationTable mutations={currentResult.concept_mutations} />
                                                </div>
                                            )}

                                            {/* Friction & Desire */}
                                            {currentResult.desire_and_friction && (
                                                <div className="mt-8">
                                                    <h3 className="text-lg font-semibold text-slate-900 mb-4 flex items-center gap-2">
                                                        <AlertTriangle className="h-5 w-5 text-amber-500" />
                                                        Friction & Desire
                                                    </h3>
                                                    <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-4">
                                                        {currentResult.desire_and_friction.map((item, i) => (
                                                            <div key={i} className="flex flex-col p-5 bg-white border border-slate-200 rounded-xl shadow-sm hover:shadow-md transition-shadow relative overflow-hidden group">
                                                                <div className="absolute top-0 left-0 w-1 h-full bg-amber-400 group-hover:w-2 transition-all" />
                                                                <div className="text-[10px] font-bold uppercase tracking-wider text-amber-600 mb-2">{item.topic}</div>
                                                                <div className="font-semibold text-slate-900 mb-3 leading-snug">{item.friction_point}</div>
                                                                <div className="mt-auto pt-3 border-t border-slate-100">
                                                                    <span className="text-xs text-slate-400 uppercase font-semibold">Underlying Desire</span>
                                                                    <div className="text-sm font-medium text-indigo-700 mt-0.5">{item.underlying_desire}</div>
                                                                </div>
                                                            </div>
                                                        ))}
                                                    </div>
                                                </div>
                                            )}

                                            {/* Institutional Conflicts */}
                                            {currentResult.institutional_conflict && (
                                                <div className="mt-8">
                                                    <h3 className="text-lg font-semibold text-slate-900 mb-4 flex items-center gap-2">
                                                        <Building className="h-5 w-5 text-purple-600" />
                                                        Institutional Conflicts
                                                    </h3>
                                                    <div className="grid md:grid-cols-2 gap-4">
                                                        {currentResult.institutional_conflict?.map((conf, i) => (
                                                            <Card key={i} className="border-purple-100 bg-purple-50/30 hover:bg-purple-50/50 transition-colors">
                                                                <CardHeader className="pb-2">
                                                                    <CardTitle className="text-base font-bold text-purple-900">{conf.conflict_type}</CardTitle>
                                                                    <CardDescription className="text-slate-700">{conf.description}</CardDescription>
                                                                </CardHeader>
                                                                <CardContent className="space-y-3 text-sm">
                                                                    {conf.evidence?.map((ev, eIdx) => (
                                                                        <div key={eIdx} className="flex gap-2 items-start">
                                                                            <Badge variant="outline" className="shrink-0 text-[10px] px-1.5 py-0 h-5 mt-0.5 bg-white border-purple-200 text-purple-700">
                                                                                {ev.policy}
                                                                            </Badge>
                                                                            <span className="italic text-slate-600 leading-snug">&quot;{ev.text}&quot;</span>
                                                                        </div>
                                                                    ))}
                                                                </CardContent>
                                                            </Card>
                                                        ))}
                                                    </div>
                                                </div>
                                            )}

                                            {/* Legitimacy Tensions */}
                                            <div>
                                                <h3 className="text-lg font-semibold text-slate-900 mb-3 flex items-center gap-2">
                                                    <Scale className="h-5 w-5 text-emerald-600" />
                                                    Legitimacy Tensions
                                                </h3>
                                                <div className="grid gap-4">
                                                    {currentResult.legitimacy_tensions?.map((tens, i) => (
                                                        <Card key={i} className="border-emerald-100 bg-emerald-50/30">
                                                            <CardHeader className="pb-2">
                                                                <CardTitle className="text-base font-bold text-emerald-900">{tens.tension_type}</CardTitle>
                                                                <CardDescription className="text-slate-700">{tens.description}</CardDescription>
                                                            </CardHeader>
                                                            <CardContent className="space-y-3 text-sm">
                                                                {tens.evidence?.map((ev, eIdx) => (
                                                                    <div key={eIdx} className="flex gap-2 items-start">
                                                                        <Badge variant="outline" className="shrink-0 text-[10px] px-1.5 py-0 h-5 mt-0.5 bg-white border-emerald-200 text-emerald-700">
                                                                            {ev.policy}
                                                                        </Badge>
                                                                        <span className="italic text-slate-600 leading-snug">&quot;{ev.text}&quot;</span>
                                                                    </div>
                                                                ))}
                                                            </CardContent>
                                                        </Card>
                                                    ))}
                                                </div>
                                            </div>

                                            {/* Coloniality Assessment */}
                                            {currentResult.coloniality_assessment && (
                                                <div className="bg-amber-50 border border-amber-200 rounded-lg p-6">
                                                    <h3 className="text-lg font-bold text-amber-900 mb-2 flex items-center gap-2">
                                                        <AlertTriangle className="h-5 w-5" />
                                                        Coloniality Assessment
                                                    </h3>
                                                    <p className="text-amber-800 leading-relaxed">
                                                        {currentResult.coloniality_assessment}
                                                    </p>
                                                </div>
                                            )}
                                        </div>
                                    )}

                                    {selectedSources.length < 2 && (
                                        <Card className="bg-slate-50 border-dashed">
                                            <CardContent className="pt-6 text-center text-slate-500">
                                                <Globe2 className="h-12 w-12 mx-auto mb-4 text-slate-400" />
                                                <p>Select at least 2 documents above to begin comparing</p>
                                            </CardContent>
                                        </Card>
                                    )}
                                </CardContent>
                            </Card>
                        </div>
                    )}
                </>
            )
            }
        </div >
    );
}

"use client";

import { useState, useMemo, useEffect } from "react";
import { useServerStorage } from "@/hooks/useServerStorage";
import { useSources } from "@/hooks/useSources";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip";
import { Lightbulb, Sparkles, Loader2, BookOpen, HelpCircle, FileText } from "lucide-react";

import { useDemoMode } from "@/hooks/useDemoMode";
import { CulturalAnalysisResult } from "@/types/cultural";
import { MultiLensAnalysis } from "@/components/reflexivity/MultiLensAnalysis";
import { exportSummaryToCSV, exportDetailedMatrixToCSV } from "@/lib/export-utils";
import { ClusterNetworkGraph } from "@/components/cultural/ClusterNetworkGraph";

export default function CulturalAnalysisPage() {
    const { sources, isLoading, refresh } = useSources();
    const { isReadOnly } = useDemoMode();
    const [selectedSources, setSelectedSources] = useServerStorage<string[]>("cultural_selected_sources", []);
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    // [NEW] Dynamic persistence key based on selected sources
    const selectionKey = useMemo(() => {
        return selectedSources.length > 0 ? selectedSources.slice().sort().join('-') : 'empty';
    }, [selectedSources]);

    const [culturalAnalysis, setCulturalAnalysis] = useServerStorage<CulturalAnalysisResult | null>(`cultural_analysis_${selectionKey}`, null);
    const [selectedLensId] = useServerStorage<string>("cultural_lens_id", "default");
    const [forceRefresh, setForceRefresh] = useState(false);

    // Debug logging for key changes
    useEffect(() => {
        console.log('[CULTURAL] Selection key changed to:', selectionKey);
        console.log('[CULTURAL] Selected sources:', selectedSources);
    }, [selectionKey, selectedSources]);

    // Helper function to determine actual document type from both type field and title
    const getDocumentType = (source: typeof sources[0]): "Policy" | "Web" | "Trace" => {
        // Check title prefix first (more reliable for user-added sources)
        if (source.title.startsWith('[Web]')) return "Web";
        if (source.title.startsWith('[Trace]')) return "Trace";

        // Fall back to type field
        if (source.type === 'Web') return "Web";
        if (source.type === 'Trace') return "Trace";

        // Default to Policy for PDF, Text, Word types
        return "Policy";
    };

    // Filter sources that have text available for analysis, checking for Policy Documents specifically or excluding Traces/Web.
    // User request: "filter out trace and web and just list the policy documents"
    const analyzedSources = sources.filter(s => {
        if (!(s.analysis || s.extractedText)) return false;

        const docType = getDocumentType(s);
        return docType === "Policy"; // Only show Policy documents
    });

    // Cleanup effect: Remove selected sources that no longer exist in analyzedSources
    useEffect(() => {
        if (selectedSources.length > 0 && analyzedSources.length > 0) {
            const validSourceIds = analyzedSources.map(s => s.id);
            const cleanedSelection = selectedSources.filter(id => validSourceIds.includes(id));

            // Only update if there are invalid IDs to remove
            if (cleanedSelection.length !== selectedSources.length) {
                console.log('[CULTURAL] Cleaning up invalid source IDs. Before:', selectedSources, 'After:', cleanedSelection);
                setSelectedSources(cleanedSelection);
            }
        }
    }, [analyzedSources, selectedSources, setSelectedSources]);

    const toggleSource = (sourceId: string) => {
        setSelectedSources((prev) =>
            prev.includes(sourceId)
                ? prev.filter((id) => id !== sourceId)
                : [...prev, sourceId]
        );
    };

    const handleAnalyze = async () => {
        if (isReadOnly) {
            alert("Analysis disabled in Demo Mode");
            return;
        }

        if (selectedSources.length < 2) {
            alert("Please select at least 2 sources for cultural analysis.");
            return;
        }

        setIsAnalyzing(true);
        console.log('Starting cultural analysis...');

        try {
            const sourcesToAnalyze = analyzedSources.filter((s) =>
                selectedSources.includes(s.id)
            );

            console.log('Sources to analyze:', sourcesToAnalyze.map(s => ({ id: s.id, title: s.title, hasText: !!s.extractedText })));

            const requestBody = {
                sources: sourcesToAnalyze.map((s) => ({
                    id: s.id,
                    title: s.title,
                    text: s.extractedText?.substring(0, 4000) || '',
                })),
                lensId: selectedLensId,
                forceRefresh: forceRefresh
            };

            console.log('Sending request to /api/cultural-analysis...');

            const headers: HeadersInit = { 'Content-Type': 'application/json' };
            if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true' && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
            }
            console.log('Request headers:', headers);
            console.log('Demo mode:', process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE);
            console.log('Demo User ID:', process.env.NEXT_PUBLIC_DEMO_USER_ID);

            const response = await fetch('/api/cultural-analysis', {
                method: 'POST',
                headers: headers,
                body: JSON.stringify(requestBody),
            });

            console.log('Response status:', response.status);

            if (!response.ok) {
                const errorText = await response.text();
                console.error('Response error:', errorText);
                throw new Error(`API returned ${response.status}: ${errorText}`);
            }

            const data = await response.json();
            console.log('Response data:', data);

            if (data.success && data.analysis) {
                console.log('Analysis successful, setting results');
                console.log('[CULTURAL] About to save analysis with key:', `cultural_analysis_${selectionKey}`);
                console.log('[CULTURAL] Analysis data:', data.analysis);
                setCulturalAnalysis(data.analysis);
                console.log('[CULTURAL] setCulturalAnalysis called');


                // Log the methodological action
                try {
                    const logHeaders: HeadersInit = { 'Content-Type': 'application/json' };
                    if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true' && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                        logHeaders['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
                    }

                    await fetch('/api/logs', {
                        method: 'POST',
                        headers: logHeaders,
                        body: JSON.stringify({
                            action: "Cultural Analysis",
                            details: {
                                lens: selectedLensId,
                                sourceCount: sourcesToAnalyze.length,
                                clustersFound: data.analysis.clusters.length
                            }
                        })
                    });
                } catch (logError) {
                    console.error("Failed to log action:", logError);
                }
            } else {
                console.error('Analysis failed:', data.error);
                alert("Cultural analysis failed: " + (data.error || "Unknown error"));
            }
        } catch (error: unknown) {
            console.error("Cultural analysis error:", error);
            alert(`Failed to perform cultural analysis: ${(error as Error).message || String(error)}`);
        } finally {
            console.log('Analysis complete, resetting button');
            setIsAnalyzing(false);
        }
    };

    if (isLoading) {
        return (
            <div className="flex items-center justify-center h-64">
                <Loader2 className="h-8 w-8 animate-spin text-slate-400" />
            </div>
        );
    }

    const handleExportSummary = () => {
        if (!culturalAnalysis) return;
        exportSummaryToCSV(culturalAnalysis);
    };

    const handleExportDetailed = () => {
        if (!culturalAnalysis) return;
        exportDetailedMatrixToCSV(culturalAnalysis);
    };



    return (
        <div className="space-y-8">
            {/* Header */}
            <div>
                <h2 className="text-3xl font-bold tracking-tight text-slate-900">
                    Cultural Framing of Discursive Fields
                </h2>
                <p className="text-slate-500">
                    Identify gaps between discourse clusters within the algorithmic assemblage to discover innovation opportunities and legitimacy dynamics.
                </p>
            </div>

            <MultiLensAnalysis sources={sources} onRefresh={refresh} />



            {/* Source Selection */}
            <Card>
                <CardHeader>
                    <CardTitle>Select Sources for Analysis</CardTitle>
                    <CardDescription>
                        Choose at least 2 analyzed documents to detect cultural holes
                    </CardDescription>
                </CardHeader>
                <CardContent className="space-y-4">
                    {analyzedSources.length === 0 ? (
                        <div className="text-center py-8 text-slate-500">
                            <p>No analyzed sources available.</p>
                            <p className="text-sm mt-2">
                                Please upload and analyze documents on the Data page first.
                            </p>
                        </div>
                    ) : (
                        <>
                            <div className="grid gap-3">
                                {analyzedSources.map((source) => (
                                    <div
                                        key={source.id}
                                        className={`p-4 border-2 rounded-lg cursor-pointer transition-all ${selectedSources.includes(source.id)
                                            ? "border-amber-500 bg-amber-50"
                                            : "border-slate-200 hover:border-slate-300"
                                            }`}
                                        onClick={() => toggleSource(source.id)}
                                    >
                                        <div className="flex items-start justify-between">
                                            <div className="flex-1">
                                                <div className="flex items-center gap-2 mb-1">
                                                    <h4 className="font-semibold text-slate-900">
                                                        {source.title}
                                                    </h4>
                                                    <Badge
                                                        className={
                                                            getDocumentType(source) === "Policy"
                                                                ? "bg-blue-100 text-blue-700 border-blue-200"
                                                                : getDocumentType(source) === "Web"
                                                                    ? "bg-yellow-100 text-yellow-700 border-yellow-200"
                                                                    : "bg-green-100 text-green-700 border-green-200"
                                                        }
                                                        variant="outline"
                                                    >
                                                        {getDocumentType(source)}
                                                    </Badge>
                                                </div>
                                                <p className="text-sm text-slate-600 mt-1">
                                                    {source.description}
                                                </p>
                                            </div>
                                            {selectedSources.includes(source.id) && (
                                                <Badge className="bg-amber-500 text-white">
                                                    Selected
                                                </Badge>
                                            )}
                                        </div>
                                    </div>
                                ))}
                            </div>

                            <div className="flex items-center justify-between pt-4 border-t">
                                <div className="text-sm text-slate-600 flex items-center gap-4">
                                    <span>{[...new Set(selectedSources)].length} source{[...new Set(selectedSources)].length !== 1 ? 's' : ''} selected</span>
                                    <label className="flex items-center gap-2 cursor-pointer">
                                        <input
                                            type="checkbox"
                                            checked={forceRefresh}
                                            onChange={(e) => setForceRefresh(e.target.checked)}
                                            className="rounded border-slate-300 text-amber-600 focus:ring-amber-500"
                                        />
                                        <span className="text-sm text-slate-600">Force Refresh (Ignore Cache)</span>
                                    </label>
                                </div>
                                <Button
                                    className="bg-amber-600 text-white hover:bg-amber-700"
                                    onClick={handleAnalyze}
                                    disabled={selectedSources.length < 2 || isAnalyzing || isReadOnly} // [NEW]
                                >
                                    {isAnalyzing ? (
                                        <>
                                            <Sparkles className="mr-2 h-4 w-4 animate-spin" />
                                            Analyzing...
                                        </>
                                    ) : (
                                        <>
                                            <Lightbulb className="mr-2 h-4 w-4" />
                                            Detect Discourse Clusters
                                        </>
                                    )}
                                </Button>
                            </div>
                        </>
                    )}
                </CardContent>
            </Card>

            {/* Results */}
            {culturalAnalysis && (
                <div className="space-y-6">
                    {/* Analysis Summary */}
                    {culturalAnalysis.summary && (
                        <Card className="bg-slate-50 border-slate-200">
                            <CardHeader className="pb-2">
                                <div className="flex items-center justify-between">
                                    <div className="flex items-center gap-2">
                                        <Sparkles className="h-4 w-4 text-amber-600" />
                                        <CardTitle className="text-lg">Analysis Summary</CardTitle>
                                    </div>
                                    <Button variant="outline" size="sm" onClick={handleExportSummary}>
                                        Export Summary
                                    </Button>
                                    <Button variant="outline" size="sm" onClick={handleExportDetailed} className="gap-2">
                                        <FileText className="h-4 w-4" />
                                        Export Detailed Matrix
                                    </Button>
                                </div>
                            </CardHeader>
                            <CardContent>
                                <p className="text-sm text-slate-700 leading-relaxed">
                                    {culturalAnalysis.summary}
                                </p>
                            </CardContent>
                        </Card>
                    )}

                    {/* Discourse Landscape Metrics */}
                    <Card className="bg-gradient-to-br from-amber-50 to-blue-50 border-slate-200">
                        <CardHeader className="pb-2">
                            <CardTitle className="text-base text-slate-800">Discourse Landscape Overview</CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                                <div className="bg-white/60 p-3 rounded-lg border border-slate-200">
                                    <p className="text-xs font-medium text-slate-500 uppercase tracking-wide">Total Clusters</p>
                                    <p className="text-2xl font-bold text-slate-800">{culturalAnalysis.clusters.length}</p>
                                </div>
                                <div className="bg-white/60 p-3 rounded-lg border border-slate-200">
                                    <p className="text-xs font-medium text-slate-500 uppercase tracking-wide">Largest Field</p>
                                    <p className="text-lg font-bold text-blue-700 truncate" title={culturalAnalysis.clusters.reduce((max, c) => c.size > max.size ? c : max, culturalAnalysis.clusters[0]).name}>
                                        {culturalAnalysis.clusters.reduce((max, c) => c.size > max.size ? c : max, culturalAnalysis.clusters[0]).name}
                                    </p>
                                </div>
                                <div className="bg-white/60 p-3 rounded-lg border border-slate-200">
                                    <p className="text-xs font-medium text-slate-500 uppercase tracking-wide">Avg Themes</p>
                                    <p className="text-2xl font-bold text-slate-800">
                                        {Math.round(culturalAnalysis.clusters.reduce((acc, c) => acc + c.size, 0) / culturalAnalysis.clusters.length)}
                                    </p>
                                </div>
                                <div className="bg-white/60 p-3 rounded-lg border border-slate-200">
                                    <p className="text-xs font-medium text-slate-500 uppercase tracking-wide">Source Coverage</p>
                                    <p className="text-2xl font-bold text-emerald-700">
                                        {Math.round((new Set(culturalAnalysis.clusters.flatMap(c => c.sources)).size / selectedSources.length) * 100)}%
                                    </p>
                                </div>
                            </div>
                        </CardContent>
                    </Card>

                    {/* Methodology Explanation */}
                    <Card className="bg-blue-50 border-blue-200">
                        <CardHeader>
                            <div className="flex items-center gap-2">
                                <BookOpen className="h-5 w-5 text-blue-600" />
                                <CardTitle className="text-base">Methodology: Discourse Field Analysis</CardTitle>
                            </div>
                        </CardHeader>
                        <CardContent className="space-y-3 text-sm text-slate-700">
                            <div>
                                <p className="font-semibold text-blue-900 mb-1">What are Discourse Clusters?</p>
                                <p>Groups of related themes that use similar language and concepts. Each cluster represents a coherent &quot;discourse community&quot; or &quot;regime of truth&quot;.</p>
                            </div>
                            <div>
                                <p className="font-semibold text-blue-900 mb-1">Epistemic Framing</p>
                                <p>By analyzing how these clusters form, we can identify which knowledge systems are dominant (e.g., Technical Safety) and which are marginalized or fragmented.</p>
                            </div>
                        </CardContent>
                    </Card>

                    {/* Network Visualization */}
                    {culturalAnalysis.clusters.length >= 2 && (
                        <Card>
                            <CardHeader>
                                <CardTitle>Cluster Relationships</CardTitle>
                                <CardDescription>
                                    Visual map showing how discourse clusters relate through shared themes
                                </CardDescription>
                            </CardHeader>
                            <CardContent>
                                <ClusterNetworkGraph
                                    clusters={culturalAnalysis.clusters}
                                    onClusterClick={(clusterId) => {
                                        const element = document.getElementById(`cluster-${clusterId}`);
                                        element?.scrollIntoView({ behavior: 'smooth', block: 'center' });
                                    }}
                                />
                            </CardContent>
                        </Card>
                    )}


                    {/* Cluster Summary */}
                    <Card>
                        <CardHeader>
                            <CardTitle>Discourse Clusters</CardTitle>
                            <CardDescription>
                                {culturalAnalysis.clusters.length} clusters identified from {[...new Set(selectedSources)].length} sources (sorted by size)
                            </CardDescription>
                        </CardHeader>
                        <CardContent>
                            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3 auto-rows-fr">
                                {(() => {
                                    // Calculate max size for relative scaling
                                    const maxSize = Math.max(...culturalAnalysis.clusters.map(c => c.size), 1);

                                    return [...culturalAnalysis.clusters]
                                        .sort((a, b) => b.size - a.size)
                                        .map((cluster) => {
                                            // Determine visual weight
                                            const relativeSize = cluster.size / maxSize;
                                            const isDominant = relativeSize > 0.7;
                                            const isMajor = relativeSize > 0.4;

                                            return (
                                                <div
                                                    key={cluster.id}
                                                    id={`cluster-${cluster.id}`}
                                                    className={`
                                                        rounded-lg transition-all duration-200
                                                        ${isDominant
                                                            ? "md:col-span-2 lg:col-span-2 bg-gradient-to-br from-blue-50 to-indigo-50 border-2 border-blue-300 shadow-md p-6"
                                                            : isMajor
                                                                ? "bg-white border border-blue-200 shadow-sm p-5"
                                                                : "bg-slate-50 border border-slate-200 p-4 opacity-90 hover:opacity-100"
                                                        }
                                                    `}
                                                >
                                                    <div className="flex items-start justify-between mb-3">
                                                        <TooltipProvider delayDuration={0}>
                                                            <Tooltip>
                                                                <TooltipTrigger asChild>
                                                                    <div className="flex items-center gap-2 cursor-help group w-fit">
                                                                        <h4 className={`
                                                                            font-bold text-slate-900 underline decoration-dotted decoration-blue-300
                                                                            ${isDominant ? "text-xl" : isMajor ? "text-lg" : "text-base"}
                                                                        `}>
                                                                            {cluster.name}
                                                                        </h4>
                                                                        <HelpCircle className="h-4 w-4 text-slate-400 group-hover:text-blue-600 transition-colors" />
                                                                    </div>
                                                                </TooltipTrigger>
                                                                {cluster.description && (
                                                                    <TooltipContent className="max-w-xs bg-white shadow-xl border-blue-100 p-3">
                                                                        <p className="font-semibold text-xs text-blue-900 mb-1">Cluster Definition</p>
                                                                        <p className="text-xs text-slate-600 leading-snug">{cluster.description}</p>
                                                                    </TooltipContent>
                                                                )}
                                                            </Tooltip>
                                                        </TooltipProvider>

                                                        <Badge
                                                            className={`
                                                                ${isDominant ? "bg-blue-600 text-white hover:bg-blue-700" : isMajor ? "bg-blue-100 text-blue-800" : "bg-slate-100 text-slate-600"}
                                                                ml-2 shrink-0
                                                            `}
                                                        >
                                                            {cluster.size} themes
                                                        </Badge>
                                                    </div>

                                                    <div className="flex flex-wrap gap-1.5 mb-3">
                                                        {cluster.themes.filter(theme => theme !== cluster.name).map((theme, i) => (
                                                            <Badge
                                                                key={i}
                                                                variant="outline"
                                                                className={`
                                                                    text-xs 
                                                                    ${isDominant ? "bg-white border-blue-200" : "bg-transparent border-slate-200"}
                                                                `}
                                                            >
                                                                {theme}
                                                            </Badge>
                                                        ))}
                                                    </div>

                                                    <div className="flex items-center gap-2 text-xs text-slate-500 mb-3">
                                                        <BookOpen className="h-3 w-3" />
                                                        <span>Found in {cluster.sources.length} source{cluster.sources.length !== 1 ? 's' : ''}</span>
                                                    </div>

                                                    {
                                                        cluster.quotes && cluster.quotes.length > 0 && (
                                                            <div className={`mt-auto pt-3 border-t ${isDominant ? "border-blue-200" : "border-slate-100"}`}>
                                                                {/* Primary Quote - Always Visible */}
                                                                <div className="relative pl-3 border-l-2 border-blue-400 mb-2">
                                                                    <p className="text-xs text-slate-700 italic leading-relaxed">
                                                                        &quot;{cluster.quotes[0].text}&quot;
                                                                    </p>
                                                                    <p className="text-[10px] text-slate-500 mt-1 font-medium">
                                                                        — {cluster.quotes[0].source}
                                                                    </p>
                                                                </div>

                                                                {/* Secondary Quotes - Collapsible */}
                                                                {cluster.quotes.length > 1 && (
                                                                    <details className="group/details">
                                                                        <summary className="text-[10px] font-medium text-blue-600 cursor-pointer hover:text-blue-800 select-none flex items-center gap-1 transition-colors w-fit">
                                                                            <span className="group-open/details:hidden">
                                                                                + View {cluster.quotes.length - 1} more quote{cluster.quotes.length - 1 !== 1 ? 's' : ''}
                                                                            </span>
                                                                            <span className="hidden group-open/details:inline">
                                                                                Hide extra quotes
                                                                            </span>
                                                                        </summary>
                                                                        <div className="mt-2 space-y-3 pl-1">
                                                                            {cluster.quotes.slice(1).map((quote, i) => (
                                                                                <div key={i} className="relative pl-3 border-l-2 border-blue-200">
                                                                                    <p className="text-xs text-slate-600 italic leading-relaxed">
                                                                                        &quot;{quote.text}&quot;
                                                                                    </p>
                                                                                    <p className="text-[10px] text-slate-400 mt-1">
                                                                                        — {quote.source}
                                                                                    </p>
                                                                                </div>
                                                                            ))}
                                                                        </div>
                                                                    </details>
                                                                )}
                                                            </div>
                                                        )
                                                    }
                                                </div>
                                            );
                                        });
                                })()}
                            </div>
                        </CardContent>
                    </Card>


                </div>
            )
            }
        </div >
    );
}

"use client";
// Force cache refresh


import { useState, useRef, useEffect } from "react";
import { AiAbsenceAnalysis } from "@/types/ecosystem";
import { useSources } from "@/hooks/useSources";
import { useServerStorage } from "@/hooks/useServerStorage";
import { useDemoMode } from "@/hooks/useDemoMode";
import { useTeam } from "@/hooks/useTeam";
import { useSearchParams } from "next/navigation";
import { ReportData, LensType } from "@/types/report";
import {
    ResistanceSynthesisResult,
    EcosystemImpact,
    AnalysisResult,
    Source,
    LegitimacyAnalysis,
    ComparativeSynthesis,
    PositionalityData
} from "@/types";
import { EcosystemActor, EcosystemConfiguration } from "@/types/ecosystem";
import { CulturalAnalysisResult } from "@/types/cultural";
import { ComparisonResult as OntologyComparisonResult, OntologyData } from "@/types/ontology";
import { SynthesisComparisonResult } from "@/types/synthesis";
import { analyzeDocument, AnalysisMode } from "@/services/analysis";
import { extractTextFromPDF } from "@/utils/pdfExtractor";
import { DocumentCard } from "@/components/policy/DocumentCard";
import { AddDocumentDialog } from "@/components/policy/AddDocumentDialog";
import { ViewSourceDialog } from "@/components/policy/ViewSourceDialog";
import { EditSourceDialog } from "@/components/policy/EditSourceDialog";
import { DocumentToolbar } from "@/components/policy/DocumentToolbar";
import { PolicyComparisonView } from "@/components/policy/PolicyComparisonView";

import { PolicyFocusView } from "@/components/policy/PolicyFocusView";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Button } from "@/components/ui/button";
import { AddUrlDialog } from "@/components/policy/AddUrlDialog";
import { PositionalityDialog } from "@/components/reflexivity/PositionalityDialog";
import { Loader2, Upload, Plus, Search, Filter, Download, FileText, Database, Share2, Trash2, ExternalLink } from "lucide-react";
import { ExportReportDialog } from "@/components/policy/ExportReportDialog";
import { ReportSectionSelection } from "@/types/report";
import { ArtifactRepository } from "@/components/resistance/ArtifactRepository";
import { ResistanceArtifactView } from "@/components/resistance/ResistanceArtifactView";
import { ResistanceArtifact } from "@/types/resistance";
import { CreditTopUpDialog } from "@/components/CreditTopUpDialog";
import { useCredits } from "@/hooks/useCredits";
import { FileDropZone } from "@/components/ui/FileDropZone";
import { extractTextFromDOCX } from "@/utils/docxExtractor";
import { MethodLog } from "@/types/logs";

import { Suspense } from 'react';

function PolicyDocumentsPageContent() {
    // ----------------------------------------------------------------------
    // 1. Hooks & State
    // ----------------------------------------------------------------------
    const { sources, isLoading: isSourcesLoading, addSource, updateSource, deleteSource } = useSources();
    const { isReadOnly } = useDemoMode();
    const { hasCredits } = useCredits();
    const { currentUserRole } = useTeam();

    // Data for Full Report Aggregation
    const [resistanceSynthesis] = useServerStorage<ResistanceSynthesisResult | null>("resistance_synthesis_result", null);
    const [ecosystemActors, setEcosystemActors] = useServerStorage<EcosystemActor[]>("ecosystem_actors", []);
    const [ecosystemConfigs] = useServerStorage<EcosystemConfiguration[]>("ecosystem_configurations", []);

    const [absenceAnalysis] = useServerStorage<AiAbsenceAnalysis | null>("ecosystem_absence_analysis", null);
    const [synthesisComparison] = useServerStorage<SynthesisComparisonResult | null>("synthesis_comparison_result", null);
    const [comparativeSynthesisResults] = useServerStorage<Record<string, ComparativeSynthesis>>("comparison_synthesis_results_v2", {});
    const [culturalAnalysis] = useServerStorage<CulturalAnalysisResult | null>("cultural_analysis_result_v5", null);
    const [synthesisImpacts] = useServerStorage<EcosystemImpact[]>("synthesis_ecosystem_impacts", []);
    const [ontologyMaps] = useServerStorage<Record<string, OntologyData>>("ontology_maps", {});
    const [ontologyComparison] = useServerStorage<OntologyComparisonResult | null>("ontology_comparison_result", null);
    const [multiLensResults] = useServerStorage<Record<string, AnalysisResult | null>>("multi_lens_results", {
        dsf: null, cultural_framing: null, institutional_logics: null, legitimacy: null
    });
    const [multiLensText] = useServerStorage<string>("multi_lens_text", "");

    const [searchQuery, setSearchQuery] = useState("");
    const [isAddDialogOpen, setIsAddDialogOpen] = useState(false);
    const [isUrlDialogOpen, setIsUrlDialogOpen] = useState(false);
    const [isExportReportDialogOpen, setIsExportReportDialogOpen] = useState(false);
    const [analyzingId, setAnalyzingId] = useState<string | null>(null);
    const [searchingId, setSearchingId] = useState<string | null>(null);
    const [focusedSourceId, setFocusedSourceId] = useState<string | null>(null);

    const [isUploading, setIsUploading] = useState(false);
    const [isExporting, setIsExporting] = useState(false);
    const [isGeneratingTheory, setIsGeneratingTheory] = useState(false);
    const [viewingSource, setViewingSource] = useState<Source | null>(null);
    const [editingSource, setEditingSource] = useState<Source | null>(null);
    const [isPositionalityDialogOpen, setIsPositionalityDialogOpen] = useState(false);
    const [pendingAnalysis, setPendingAnalysis] = useState<{ sourceId: string, mode: AnalysisMode, force: boolean } | null>(null);
    const fileInputRef = useRef<HTMLInputElement | null>(null);

    const [selectedIds, setSelectedIds] = useState<string[]>([]);
    const [selectedArtifact, setSelectedArtifact] = useState<ResistanceArtifact | null>(null);
    const [showTopUp, setShowTopUp] = useState(false);

    // Deep Linking Support
    const searchParams = useSearchParams();
    const sourceIdParam = searchParams.get('sourceId');

    useEffect(() => {
        if (sourceIdParam && sources.length > 0) {
            const match = sources.find(s => s.id === sourceIdParam);
            if (match) {
                setFocusedSourceId(match.id);
            }
        }
    }, [sourceIdParam, sources]);

    // ----------------------------------------------------------------------
    // 2. Computed Values
    // ----------------------------------------------------------------------
    const filteredSources = sources.filter(source =>
        source.type !== 'Trace' &&
        (source.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
            source.description.toLowerCase().includes(searchQuery.toLowerCase()))
    );

    const selectedSources = sources.filter(s => selectedIds.includes(s.id));

    // ----------------------------------------------------------------------
    // 3. Handlers
    // ----------------------------------------------------------------------
    const toggleSelection = (id: string, selected: boolean) => {
        if (selected) {
            setSelectedIds(prev => [...prev, id]);
        } else {
            setSelectedIds(prev => prev.filter(sid => sid !== id));
        }
    };

    const handleSelectAll = () => {
        if (selectedIds.length === filteredSources.length) {
            setSelectedIds([]);
        } else {
            setSelectedIds(filteredSources.map(s => s.id));
        }
    };

    const handleFiles = async (files: File[]) => {
        if (isReadOnly) {
            alert('Document uploads are disabled in Demo Mode.');
            return;
        }
        if (currentUserRole === 'VOTER') {
            alert('Voter role is read-only for analysis. You cannot upload documents.');
            return;
        }

        setIsUploading(true);
        let successCount = 0;
        const errors: string[] = [];

        try {
            for (const file of files) {
                // Enforce 10MB Limit
                const MAX_SIZE_MB = 10;
                if (file.size > MAX_SIZE_MB * 1024 * 1024) {
                    errors.push(`${file.name}: File too large (Max ${MAX_SIZE_MB}MB)`);
                    continue;
                }

                try {
                    let text = "";
                    let type: "PDF" | "Word" = "PDF";
                    let iconClass = "text-purple-600";
                    let colorClass = "bg-purple-100";

                    const ext = file.name.split('.').pop()?.toLowerCase();

                    if (ext === 'pdf') {
                        const result = await extractTextFromPDF(file);
                        text = typeof result === 'string' ? result : result.text;
                        type = "PDF";
                        iconClass = "text-red-500";
                        colorClass = "bg-red-50";
                    } else if (ext === 'docx' || ext === 'doc') {
                        const result = await extractTextFromDOCX(file);
                        text = result.text;
                        type = "Word";
                        iconClass = "text-blue-600";
                        colorClass = "bg-blue-50";
                    } else {
                        throw new Error("Unsupported file type");
                    }

                    const newDoc: Source = {
                        id: Date.now().toString() + Math.random().toString(36).substring(2, 5),
                        title: file.name.replace(/\.[^/.]+$/, ""),
                        description: `Uploaded ${new Date().toLocaleDateString()} (${type}) `,
                        type: type, // "PDF" | "Word"
                        addedDate: new Date().toLocaleDateString(),
                        status: "Active Case",
                        colorClass,
                        iconClass,
                        extractedText: text
                    };
                    await addSource(newDoc);
                    successCount++;
                } catch (err: unknown) {
                    const errorMessage = err instanceof Error ? err.message : String(err);
                    console.error(`Error processing ${file.name}:`, err);
                    errors.push(`${file.name}: ${errorMessage}`);
                }
            }

            if (successCount > 0) {
                // alert(`Successfully uploaded ${successCount} document(s)!`);
            }
            if (errors.length > 0) {
                alert(`Some files failed:\n${errors.join('\n')}`);
            }

        } finally {
            setIsUploading(false);
            if (fileInputRef.current) fileInputRef.current.value = '';
        }
    };

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files.length > 0) {
            handleFiles(Array.from(e.target.files));
        }
    };

    const handleUrlAdd = async (url: string) => {
        if (isReadOnly) {
            alert('Adding content from URL is disabled in Demo Mode.');
            return;
        }
        if (currentUserRole === 'VOTER') {
            alert('Voter role is read-only for analysis. You cannot add content.');
            return;
        }

        const headers: HeadersInit = { 'Content-Type': 'application/json' };
        if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true' && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
            headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
        }

        const response = await fetch('/api/fetch-url', {
            method: 'POST',
            headers: headers,
            body: JSON.stringify({ url })
        });

        const data = await response.json();

        if (!response.ok) {
            throw new Error(data.error || 'Failed to fetch URL');
        }

        const newDoc: Source = {
            id: Date.now().toString(),
            title: data.title || url,
            description: `Fetched from ${new URL(url).hostname} `,
            type: "Web",
            addedDate: new Date().toLocaleDateString(),
            status: "Active Case",
            colorClass: "bg-emerald-100",
            iconClass: "text-emerald-600",
            extractedText: data.content,
            url: data.url
        };

        await addSource(newDoc);
        alert('Website content added successfully!');
    };

    const handleAddSource = async (title: string, description: string, pageCount: string, publicationDate: string, version: string) => {
        if (isReadOnly) {
            alert('Adding documents is disabled in Demo Mode.');
            return;
        }
        if (currentUserRole === 'VOTER') {
            alert('Voter role is read-only for analysis. You cannot add documents.');
            return;
        }
        const source: Source = {
            id: Date.now().toString(),
            title,
            description,
            type: "Text",
            pageCount: pageCount ? parseInt(pageCount) : undefined,
            publicationDate: publicationDate || undefined,
            version: version || undefined,
            addedDate: new Date().toLocaleDateString(),
            status: "Active Case",
            colorClass: "bg-blue-100",
            iconClass: "text-blue-600"
        };
        await addSource(source);
    };

    const handleEditSource = async (sourceId: string, updates: Partial<Source>) => {
        await updateSource(sourceId, updates);
    };

    const handleAnalyze = async (sourceId: string, mode: AnalysisMode) => {
        if (isReadOnly) {
            alert('Analysis is disabled in Demo Mode.');
            return;
        }
        if (currentUserRole === 'VOTER') {
            alert('Voter role is read-only for analysis. You cannot run new analysis.');
            return;
        }

        const source = sources.find(s => s.id === sourceId);
        if (!source || !source.extractedText) {
            alert('No text available to analyze. Please upload a PDF or add text first.');
            return;
        }

        let force = false;
        const hasAnalysis =
            (mode === 'dsf' && source.analysis) ||
            (mode === 'cultural_framing' && source.cultural_framing) ||
            (mode === 'institutional_logics' && source.institutional_logics) ||
            (mode === 'legitimacy' && source.legitimacy_analysis) ||
            (mode === 'stress_test' && source.analysis?.stress_test_report);

        if (hasAnalysis) {
            if (!confirm('Analysis already exists for this document. Click OK to FORCE a re-run (bypassing cache), or Cancel to abort.')) {
                return;
            }
            force = true;
        }

        setPendingAnalysis({ sourceId, mode, force });
        setIsPositionalityDialogOpen(true);
    };

    const proceedWithAnalysis = async (positionalityData: PositionalityData) => {
        if (!pendingAnalysis) return;
        if (isReadOnly) {
            alert('Analysis is disabled in Demo Mode.');
            setIsPositionalityDialogOpen(false);
            setPendingAnalysis(null);
            return;
        }
        const { sourceId, mode, force } = pendingAnalysis;
        const source = sources.find(s => s.id === sourceId);

        setIsPositionalityDialogOpen(false); // Close dialog immediately

        if (!source || !source.extractedText) return;

        setAnalyzingId(sourceId);
        try {
            const result = await analyzeDocument(
                source.extractedText.substring(0, 150000),
                mode,
                'Policy Document',
                force,
                sourceId,
                source.title,
                positionalityData,
                source.analysis // Pass existing analysis to avoid re-running it during stress test
            );

            const updates: Partial<Source> = {};
            if (mode === 'dsf') updates.analysis = result;
            if (mode === 'cultural_framing') updates.cultural_framing = result;
            if (mode === 'institutional_logics') updates.institutional_logics = result;
            if (mode === 'legitimacy') updates.legitimacy_analysis = result as unknown as LegitimacyAnalysis;
            if (mode === 'stress_test') {
                // The API returns a full analysis object including standard DSF fields AND stress_test_report
                updates.analysis = result;
            }

            await updateSource(sourceId, updates);

            if (mode === 'dsf' || mode === 'stress_test') {
                alert('Analysis complete! Scroll down to see results inside the document card.');
            } else {
                alert(`✅ ${mode === 'cultural_framing' ? 'Cultural framing' : mode === 'institutional_logics' ? 'Institutional logics' : 'Legitimacy'} analysis complete! Go to Comparison page to view results.`);
            }
        } catch (error: unknown) {
            const errorMessage = error instanceof Error ? error.message : 'Unknown error';

            // Check for Insufficient Credits (402)
            // Error usually comes as "Error: Insufficient Credits..."
            if (errorMessage.includes("Insufficient Credits") || errorMessage.includes("Payment Required") || errorMessage.includes("402")) {
                console.log("Triggering Top Up Dialog due to error:", errorMessage);
                setShowTopUp(true);
            } else {
                alert(`Analysis failed: ${errorMessage} `);
            }
        } finally {
            setAnalyzingId(null);
            setPendingAnalysis(null);
        }
    };

    const handleFindTraces = async (source: Source) => {
        if (isReadOnly) {
            alert('Trace search is disabled in Demo Mode.');
            return;
        }
        if (currentUserRole === 'VOTER') {
            alert('Voter role is read-only for analysis. You cannot search for traces.');
            return;
        }

        if (!source.extractedText) {
            alert('Please upload a PDF or add text first before finding traces.');
            return;
        }

        setSearchingId(source.id);
        try {
            // Generate search terms from the document text
            const headers: HeadersInit = { 'Content-Type': 'application/json' };
            if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true' && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
            }

            const response = await fetch('/api/search', {
                method: 'POST',
                headers: headers,
                body: JSON.stringify({
                    policyText: source.extractedText.substring(0, 3000),
                    maxResults: 10
                })
            });

            const result = await response.json();

            if (result.success && Array.isArray(result.results) && result.results.length > 0) {
                console.log("DEBUG: Data Page Search Results:", result.results);
                // Create trace sources from search results
                const newTraces: Source[] = result.results.map((item: { title: string; snippet: string; link: string; strategy?: string; explanation?: string }) => ({
                    id: Date.now().toString() + Math.random().toString(36).substr(2, 9),
                    title: `[Trace] ${item.title} `,
                    description: item.snippet || 'No description available',
                    type: "Trace" as const,
                    traceType: "provenance" as const, // Explicitly mark as provenance
                    extractedText: `${item.snippet} \n\nSource: ${item.link} \n\nFound via search for: "${result.searchQuery || 'policy analysis'}"\n\nInitial Classification: ${item.strategy || 'None'} `,
                    addedDate: new Date().toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" }),
                    status: "Active Case" as const,
                    colorClass: "bg-blue-100",
                    iconClass: "text-blue-600",
                    policyId: source.id, // Linked to the policy document
                    resistance_analysis: item.strategy ? {
                        strategy_detected: item.strategy,
                        evidence_quote: item.snippet,
                        interpretation: item.explanation || "⚠️ NO INTERPRETATION RECEIVED",
                        confidence: "Medium" // Start with medium confidence until verified
                    } : undefined
                }));

                // Add all traces to the store
                for (const trace of newTraces) {
                    await addSource(trace);
                }

                alert(`✅ Found ${newTraces.length} empirical traces! Added to sources.`);
            } else {
                alert(`No traces found.${result.error || 'Try analyzing the document first or check your Google Search API configuration.'} `);
            }
        } catch (error: unknown) {
            console.error('Search error:', error);
            const errorMessage = error instanceof Error ? error.message : 'Unknown error';
            alert(`Failed to search for traces: ${errorMessage} \n\nMake sure your Google Search API credentials are configured in .env.local`);
        } finally {
            setSearchingId(null);
        }
    };

    const handleDelete = async (sourceId: string) => {
        if (isReadOnly) {
            alert('Deleting documents is disabled in Demo Mode.');
            return;
        }
        if (currentUserRole === 'VOTER') {
            alert('Voter role is read-only for analysis. You cannot delete documents.');
            return;
        }
        if (confirm('Are you sure you want to delete this source?')) {
            await deleteSource(sourceId);
        }
    };

    // Helper to manually fetch storage data (since hooks can't be used inside the handler)
    const fetchServerStorage = async <T,>(key: string): Promise<T | null> => {
        try {
            const headers: HeadersInit = { 'Content-Type': 'application/json' };
            if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true' && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
            }
            const response = await fetch(`/api/storage?key=${encodeURIComponent(key)}`, { headers });
            if (response.ok) {
                const data = await response.json();
                return data.value as T;
            }
        } catch (error) {
            console.error(`Failed to fetch storage key "${key}":`, error);
        }
        return null;
    };

    const handleGenerateReport = async (selection: ReportSectionSelection) => {
        if (isReadOnly) {
            alert("Report generation is disabled in Demo Mode.");
            return;
        }

        // Check credits before starting
        if (!hasCredits) {
            setIsExportReportDialogOpen(false); // Close export dialog first
            alert("⚠️ You have no credits remaining.\n\nReport generation requires credits for AI analysis. Please add credits to continue.");
            setShowTopUp(true);
            return;
        }

        setIsExporting(true);
        try {
            // Use the shared snapshot function to gather all data
            const reportData = await getFullReportSnapshot();

            // Lazy Load the huge DOCX generator
            const { generateFullReportDOCX } = await import("@/utils/generateFullReportDOCX");

            // Generate the report
            await generateFullReportDOCX(reportData, selection);
            alert("✅ Report generated successfully! Check your Downloads folder.");
        } catch (error) {
            console.error("Export error:", error);
            alert(`❌ Failed to generate report.\n\nError: ${error instanceof Error ? error.message : String(error)}\n\nCheck the console for more details.`);
        } finally {
            setIsExporting(false);
        }
    };

    // ----------------------------------------------------------------------
    // 4. Render
    // ----------------------------------------------------------------------
    if (isSourcesLoading) {
        return (
            <div className="flex items-center justify-center h-64">
                <Loader2 className="h-8 w-8 animate-spin text-slate-400" />
            </div>
        );
    }

    // Shared helper to gather full report data
    const getFullReportSnapshot = async (): Promise<ReportData> => {
        // Determine Context for Ecosystem Data
        const contextId = selectedIds.length > 0 ? selectedIds[0] : (focusedSourceId || null);

        let finalActors = ecosystemActors;
        let finalConfigs = ecosystemConfigs;
        let finalAbsence = absenceAnalysis;

        if (contextId) {
            console.log(`Fetching Ecosystem Context for Policy ID: ${contextId}`);
            const [actorsData, configsData, absenceData] = await Promise.all([
                fetchServerStorage<EcosystemActor[]>(`ecosystem_actors_${contextId}`),
                fetchServerStorage<EcosystemConfiguration[]>(`ecosystem_configurations_${contextId}`),
                fetchServerStorage<AiAbsenceAnalysis>(`ecosystem_absence_analysis_${contextId}`)
            ]);

            if (actorsData) finalActors = actorsData;
            if (configsData) finalConfigs = configsData;
            if (absenceData) finalAbsence = absenceData;
        }

        // Fetch methodological logs & artifacts
        const methodLogs = await fetchServerStorage<MethodLog[]>('methodological_logs') || [];
        const resistanceArtifacts = await fetchServerStorage<ResistanceArtifact[]>('resistance_artifacts') || [];

        // Capture Charts if visible
        const images: Record<string, string> = {};

        try {
            const { default: html2canvas } = await import("html2canvas");
            const compassEl = document.getElementById('governance-compass-chart');
            if (compassEl) images.governanceCompass = (await html2canvas(compassEl, { scale: 2, useCORS: true, logging: false })).toDataURL('image/png');
        } catch (e) { console.warn("Compass capture failed", e); }

        try {
            const { default: html2canvas } = await import("html2canvas");
            const riskEl = document.getElementById('risk-heatmap-chart');
            if (riskEl) images.riskHeatmap = (await html2canvas(riskEl, { scale: 2, logging: false })).toDataURL('image/png');
        } catch (e) { console.warn("Risk heatmap capture failed", e); }

        try {
            const { default: html2canvas } = await import("html2canvas");
            const ecoEl = document.getElementById('ecosystem-map-canvas');
            if (ecoEl) images.ecosystemMap = (await html2canvas(ecoEl, { scale: 2, logging: false })).toDataURL('image/png');
        } catch (e) { console.warn("Ecosystem map capture failed", e); }

        return {
            sources: sources,
            resistance: resistanceSynthesis,
            ecosystem: {
                actors: finalActors,
                configurations: finalConfigs,
                absenceAnalysis: finalAbsence,
                assemblage: finalAbsence as unknown as undefined
            },
            synthesis: {
                comparison: (comparativeSynthesisResults['assemblage'] as unknown as SynthesisComparisonResult) || synthesisComparison,
                ecosystemImpacts: synthesisImpacts
            },
            ontology: {
                maps: ontologyMaps,
                comparison: ontologyComparison
            },
            multiLens: {
                results: multiLensResults as Record<LensType, AnalysisResult | null>,
                text: multiLensText
            },
            cultural: culturalAnalysis,
            resistanceArtifacts: resistanceArtifacts,
            images: images,
            logs: methodLogs
        };
    };
    const handleGenerateTheory = async () => {
        // Check credits before starting
        if (!hasCredits) {
            alert("⚠️ You have no credits remaining.\n\nTheoretical synthesis requires credits for AI analysis. Please add credits to continue.");
            setShowTopUp(true);
            return;
        }
        if (currentUserRole === 'VOTER') {
            alert('Voter role is read-only for analysis. You cannot generate theory.');
            return;
        }

        setIsGeneratingTheory(true);
        try {
            // 1. Gather FULL Report Data
            const reportData = await getFullReportSnapshot();

            // 2. Serialize for AI Context
            // [OPTIMIZATION] Aggressively summarize to avoid 128k token limit (currently ~360k)
            const contextForAI: any = {
                // Synthesis: Keep summary and themes, drop raw evidence lists
                synthesis: reportData.synthesis?.comparison ? {
                    synthesis_summary: (reportData.synthesis.comparison as any).synthesis_summary,
                    key_divergences: (reportData.synthesis.comparison as any).key_divergences?.map((d: any) => ({
                        theme: d.theme,
                        description: d.description
                    })),
                    stabilization_mechanisms: (reportData.synthesis.comparison as any).stabilization_mechanisms
                } : null,

                // Resistance: Drop evidence quotes, keep strategies and interpretations
                resistance: reportData.resistance ? {
                    executive_summary: reportData.resistance.executive_summary,
                    dominant_strategies: reportData.resistance.dominant_strategies?.map(s => ({
                        strategy: s.strategy,
                        description: s.description,
                        frequency: s.frequency
                    })),
                    lines_of_flight: reportData.resistance.lines_of_flight
                } : null,

                // Ecosystem: Keep high-level configs, drop absence details
                ecosystem_configs: reportData.ecosystem?.configurations?.map((c: any) => ({
                    name: c.name,
                    description: c.description,
                    dynamics: c.dynamics
                })),

                // Cultural: Keep high-level summary fields only
                cultural: reportData.cultural ? {
                    executive_summary: (reportData.cultural as any).executive_summary,
                    dominant_logic: (reportData.cultural as any).dominant_logic,
                    state_market_society: (reportData.cultural as any).state_market_society
                } : null,

                // Ontology: Keep high-level comparison
                ontology: reportData.ontology?.comparison ? {
                    distances: (reportData.ontology.comparison as any).distances,
                    implications: (reportData.ontology.comparison as any).implications
                } : null
            };

            let context = JSON.stringify(contextForAI);

            // [FIX] Fallback if no synthesis exists yet
            // If main structural analyses are empty, use individual summaries
            const hasStructuralData = contextForAI.synthesis || (contextForAI.resistance?.dominant_strategies?.length > 0);

            if (!hasStructuralData) {
                console.log("No synthesis found in full snapshot, falling back to individual summaries");
                // Need to filter sources from reportData
                const fallbackData = reportData.sources.filter(s => s.analysis).map(s => ({
                    title: s.title,
                    key_insight: s.analysis?.key_insight,
                    governance_style: s.analysis?.governance_scores
                }));

                context = JSON.stringify({
                    note: "No cross-case synthesis available. Using individual summaries.",
                    individual_summaries: fallbackData,
                    ...contextForAI // Include whatever fragments exist
                });
            }

            // 3. Call API
            let theoreticalSynthesis = null;
            const response = await fetch('/api/analyze', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    analysisMode: 'theoretical_synthesis',
                    reportContext: context
                })
            });

            if (response.ok) {
                const data = await response.json();
                console.log("Theoretical synthesis received:", data.analysis?.theoretical_synthesis?.substring(0, 50) + "...");
                theoreticalSynthesis = data.analysis?.theoretical_synthesis;
            } else {
                const errorText = await response.text();
                console.error("API Error Details:", response.status, errorText);
                throw new Error(`API failed (${response.status}): ${errorText.substring(0, 200)}`);
            }

            if (!theoreticalSynthesis) throw new Error("No synthesis returned");

            // 4. Generate Report (Only Theory)
            const theorySelection: ReportSectionSelection = {
                documentAnalysis: false,
                comparisonMatrix: false,
                synthesis: false,
                resistance: false,
                ecosystem: false,
                cultural: false,
                ontology: false,
                multiLens: false,
                scenarios: false,
                logs: false,
                configurations: false,
                resistanceArtifacts: false,
                theoreticalSynthesis: true
            };

            // Inject the new synthesis into the report data
            reportData.theoreticalSynthesis = theoreticalSynthesis;

            // Lazy Load the huge DOCX generator
            const { generateFullReportDOCX } = await import("@/utils/generateFullReportDOCX");

            await generateFullReportDOCX(reportData, theorySelection, `Theoretical_Analysis_${new Date().toISOString().split('T')[0]}.docx`);

        } catch (err) {
            console.error("Theory generation failed:", err);
            alert("Failed to generate theoretical translation.");
        } finally {
            setIsGeneratingTheory(false);
        }
    };

    return (
        <div className="container mx-auto p-6 max-w-7xl animate-in fade-in duration-500">
            {/* Header Area */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8">
                <div>
                    <h1 className="text-3xl font-black text-slate-900 tracking-tight">Data & Policy Analysis</h1>
                    <p className="text-slate-500 mt-1">Manage documents, run diagnostics, and compare frameworks.</p>
                </div>

                <div className="flex items-center gap-3 w-full md:w-auto">
                    <DocumentToolbar
                        searchQuery={searchQuery}
                        onSearchChange={setSearchQuery}
                        onUpload={handleFileUpload}
                        isUploading={isUploading}
                        fileInputRef={fileInputRef}
                        onAddClick={() => setIsAddDialogOpen(true)}
                        onAddUrlClick={() => setIsUrlDialogOpen(true)}
                        onExportReport={() => setIsExportReportDialogOpen(true)}
                        isExporting={isExporting}
                        onGenerateTheory={handleGenerateTheory}
                        isGeneratingTheory={isGeneratingTheory}
                        isReadOnly={isReadOnly}
                    />
                </div>
            </div>

            {/* Main Content Tabs */}
            <Tabs defaultValue="documents" className="w-full">
                <div className="flex items-center justify-between mb-6">
                    <TabsList className="bg-slate-100 p-1">
                        <TabsTrigger value="documents" className="uppercase text-xs font-bold px-4">My Documents</TabsTrigger>
                        <TabsTrigger value="resistance" className="uppercase text-xs font-bold px-4">Resistance</TabsTrigger>
                        <TabsTrigger value="compare" className="uppercase text-xs font-bold px-4">
                            Compare <span className="ml-2 bg-indigo-100 text-indigo-700 px-1.5 py-0.5 rounded-full text-[10px]">{selectedIds.length}</span>
                        </TabsTrigger>
                    </TabsList>
                </div>

                <TabsContent value="documents" className="space-y-4">
                    {filteredSources.length === 0 ? (
                        <div className="text-center py-20 bg-slate-50 rounded-2xl border border-dashed border-slate-200">
                            <div className="bg-white p-4 rounded-full w-16 h-16 mx-auto mb-4 shadow-sm flex items-center justify-center">
                                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-slate-300"><path d="M14.5 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V7.5L14.5 2z" /><polyline points="14 2 14 8 20 8" /></svg>
                            </div>
                            <h3 className="text-lg font-bold text-slate-700">No documents found</h3>
                            <p className="text-slate-500 text-sm mt-1">Upload a PDF or add a URL to get started.</p>
                        </div>
                    ) : (
                        <FileDropZone isReadOnly={isReadOnly} onFilesDropped={handleFiles}>
                            <div className={`grid grid-cols-1 md:grid-cols-2 gap-6 ${focusedSourceId ? 'hidden' : ''}`}>
                                {filteredSources.map((source) => (
                                    <DocumentCard
                                        key={source.id}
                                        source={source}
                                        isAnalyzing={analyzingId === source.id}
                                        isSearching={searchingId === source.id}
                                        isSelected={selectedIds.includes(source.id)}
                                        onSelect={(selected) => toggleSelection(source.id, selected)}
                                        onAnalyze={handleAnalyze}
                                        onDelete={handleDelete}
                                        onEdit={(s) => { setEditingSource(s); }}
                                        onFindTraces={handleFindTraces}
                                        onView={(s) => setViewingSource(s)}
                                        onUpdateSource={handleEditSource}
                                        isFocused={focusedSourceId === source.id}
                                        onToggleFocus={() => setFocusedSourceId(focusedSourceId === source.id ? null : source.id)}
                                        isReadOnly={isReadOnly}
                                    />
                                ))}
                            </div>
                        </FileDropZone>
                    )}
                </TabsContent>
            </Tabs>

            {/* Dialogs */}
            <AddDocumentDialog
                open={isAddDialogOpen}
                onOpenChange={setIsAddDialogOpen}
                onAdd={handleAddSource}
            />

            <AddUrlDialog
                open={isUrlDialogOpen}
                onOpenChange={setIsUrlDialogOpen}
                onAdd={handleUrlAdd}
            />

            <ViewSourceDialog
                source={viewingSource}
                onOpenChange={(open) => !open && setViewingSource(null)}
            />

            {/* Edit Source Dialog (if you have one, or remove if unused) */}
            <EditSourceDialog
                source={editingSource}
                open={!!editingSource}
                onOpenChange={(open: boolean) => !open && setEditingSource(null)}
                onSave={handleEditSource}
            />

            <PositionalityDialog
                isOpen={isPositionalityDialogOpen}
                onClose={() => setIsPositionalityDialogOpen(false)}
                onConfirm={proceedWithAnalysis}
            />

            <ExportReportDialog
                open={isExportReportDialogOpen}
                onOpenChange={setIsExportReportDialogOpen}
                onGenerate={handleGenerateReport}
                isGenerating={isExporting}
            />

            <CreditTopUpDialog
                open={showTopUp}
                onOpenChange={setShowTopUp}
                onSuccess={() => {
                    // Refresh is handled by Dashboard component or page reload if needed
                    // But let's alert user success
                    alert("Credits added! Please try running the analysis again.");
                }}
            />
        </div>
    );
}


export default function PolicyDocumentsPage() {
    return (
        <Suspense fallback={<div className="flex items-center justify-center h-screen"><Loader2 className="h-8 w-8 animate-spin text-slate-400" /></div>}>
            <PolicyDocumentsPageContent />
        </Suspense>
    );
}

"use client";

import { useState, useEffect, useMemo, Suspense } from "react";
import { useServerStorage } from "@/hooks/useServerStorage";
