            ))}
        </div >
    );
}

"use client";

import React, { useMemo } from 'react';
import Link from 'next/link';
import { useSources } from '@/hooks/useSources';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { ShieldCheck, Layers, BarChart3, AlertOctagon, Activity, Trash } from 'lucide-react';
import { GovernanceService } from '@/services/governance/governance-service';

import { GovernanceProposal } from '@/types/governance';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogFooter } from '@/components/ui/dialog';
import { Textarea } from '@/components/ui/textarea';

function VoteDialog({ proposal, voteType, onVote }: { proposal: GovernanceProposal, voteType: 'for' | 'against', onVote: (type: 'for' | 'against', rationale: string) => void }) {
    const [rationale, setRationale] = React.useState('');
    const [isOpen, setIsOpen] = React.useState(false);

    const handleVote = () => {
        onVote(voteType, rationale);
        setIsOpen(false);
        setRationale('');
    };

    const isNegation = proposal.type === 'epistemic_negation';
    const isFor = voteType === 'for';

    // Dynamic Text based on Vote Type & Proposal intent
    const actionText = isFor ? "Vote FOR" : "Vote AGAINST";

    let meaningTitle = "";
    let meaningDescription = "";
    let consequenceText = "";

    if (isNegation) {
        if (isFor) {
            meaningTitle = "Support Veto";
            meaningDescription = "You agree that this analysis is flawed, biased, or harmful.";
            consequenceText = "If this vote passes, the analysis will be formally REJECTED and removed from the consensus.";
        } else {
            meaningTitle = "Oppose Veto";
            meaningDescription = "You believe the analysis is valid and should remain.";
            consequenceText = "If this vote passes, the analysis will be RETAINED as valid.";
        }
    } else {
        if (isFor) {
            meaningTitle = "Support Proposal";
            meaningDescription = "You want this feature or change to be implemented.";
            consequenceText = "If passed, this will be queued for implementation.";
        } else {
            meaningTitle = "Oppose Proposal";
            meaningDescription = "You do not think this should be implemented right now.";
            consequenceText = "If passed, this proposal will be discarded.";
        }
    }

    const buttonColor = isFor
        ? "bg-emerald-600 hover:bg-emerald-700 text-white"
        : "bg-rose-600 hover:bg-rose-700 text-white";

    return (
        <Dialog open={isOpen} onOpenChange={setIsOpen}>
            <DialogTrigger asChild>
                <button
                    className={`flex items-center gap-1 cursor-pointer transition-colors p-1 rounded ${isFor
                        ? 'hover:text-emerald-600 hover:bg-emerald-50 text-slate-400'
                        : 'hover:text-rose-600 hover:bg-rose-50 text-slate-400'
                        }`}
                >
                    <span>{isFor ? '👍' : '👎'}</span>
                    {isFor ? proposal.votesFor : proposal.votesAgainst}
                </button>
            </DialogTrigger>
            <DialogContent>
                <DialogHeader>
                    <DialogTitle>{actionText}: {proposal.title}</DialogTitle>
                </DialogHeader>
                <div className="space-y-4 py-4">
                    <div className={`p-4 rounded-md border ${isFor ? 'bg-emerald-50 border-emerald-100' : 'bg-rose-50 border-rose-100'}`}>
                        <h4 className={`font-bold mb-1 ${isFor ? 'text-emerald-800' : 'text-rose-800'}`}>{meaningTitle}</h4>
                        <p className={`text-sm mb-2 ${isFor ? 'text-emerald-700' : 'text-rose-700'}`}>{meaningDescription}</p>
                        <div className={`text-xs uppercase font-bold tracking-wide mt-3 ${isFor ? 'text-emerald-600' : 'text-rose-600'}`}>Consequence:</div>
                        <p className={`text-xs ${isFor ? 'text-emerald-700' : 'text-rose-700'}`}>{consequenceText}</p>
                    </div>
                    <p className="text-sm text-slate-500">
                        Please provide a rationale for your vote.
                    </p>
                    <Textarea
                        placeholder={isFor ? "Why do you support this?" : "Why do you oppose this?"}
                        value={rationale}
                        onChange={(e) => setRationale(e.target.value)}
                        className="min-h-[100px]"
                    />
                </div>
                <DialogFooter className="flex gap-2 justify-end">
                    <Button variant="outline" onClick={() => setIsOpen(false)}>
                        Cancel
                    </Button>
                    <Button onClick={handleVote} className={buttonColor}>
                        Confirm {actionText}
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

export default function GovernanceOrchestrationPage() {
    const { sources, isLoading, refresh: refreshSources } = useSources();
    const [proposals, setProposals] = React.useState<GovernanceProposal[]>([]);

    // Load Proposals
    React.useEffect(() => {
        const loadProposals = async () => {
            const service = new GovernanceService();
            const data = await service.getProposals();
            setProposals(data);
        };
        loadProposals();
    }, []);

    // 1. Calculate Risk Classifications
    const riskStats = useMemo(() => {
        const stats = {
            total: sources.length,
            high: 0,
            medium: 0,
            low: 0,
            requiresAction: 0
        };

        sources.forEach(source => {
            const status = source.analysis?.escalation_status;
            if (status?.level === 'HARD') stats.high++;
            if (status?.level === 'MEDIUM') stats.medium++;
            if (status?.level === 'SOFT' || !status) stats.low++;

            if (status?.status === 'DETECTED' || status?.status === 'DEFERRED') {
                stats.requiresAction++;
            }
        });

        return stats;
    }, [sources]);

    // 2. Calculate Recurrence Patterns (Dominant Logics)
    const recurrencePatterns = useMemo(() => {
        const patterns: Record<string, { count: number, sources: string[] }> = {};

        sources.forEach(source => {
            const logic = source.analysis?.dominant_logic;
            if (logic) {
                if (!patterns[logic]) {
                    patterns[logic] = { count: 0, sources: [] };
                }
                patterns[logic].count++;
                patterns[logic].sources.push(source.title);
            }
        });

        // Filter for > 1 occurrence and sort
        return Object.entries(patterns)
            .filter(([_, data]) => data.count > 1)
            .sort((a, b) => b[1].count - a[1].count)
            .slice(0, 5); // Top 5
    }, [sources]);

    if (isLoading) {
        return <div className="p-12 text-center text-slate-400">Loading Orchestration Data...</div>;
    }

    return (
        <div className="min-h-screen bg-slate-50 p-8 space-y-8">
            {/* Header Section */}
            <div className="flex justify-between items-center max-w-6xl mx-auto">
                <div>
                    <h1 className="text-3xl font-light text-slate-900">Governance Orchestration</h1>
                    <p className="text-slate-500 mt-1">Resource-grounded insights and risk landscape analysis.</p>
                </div>
                <div className="flex gap-3">
                    <div className="flex gap-3">
                        {/* Meta-Governance Console Link Removed */}
                    </div>
                </div>
            </div>

            <div className="max-w-6xl mx-auto grid grid-cols-1 md:grid-cols-3 gap-6">

                {/* 1. Risk Landscape Card */}
                <Card className="md:col-span-2 border-slate-200 shadow-sm">
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <ShieldCheck className="w-5 h-5 text-indigo-600" />
                            Risk Landscape
                        </CardTitle>
                        <CardDescription>Escalation status across the ecosystem.</CardDescription>
                    </CardHeader>
                    <CardContent>
                        <div className="grid grid-cols-3 gap-4 mb-6">
                            <div className="bg-red-50 p-4 rounded-lg border border-red-100 flex flex-col items-center">
                                <span className="text-red-800 font-bold text-2xl">{riskStats.high}</span>
                                <span className="text-red-600 text-sm font-medium uppercase tracking-wide">High Risk</span>
                                <span className="text-red-400 text-xs mt-1">Blocking</span>
                            </div>
                            <div className="bg-amber-50 p-4 rounded-lg border border-amber-100 flex flex-col items-center">
                                <span className="text-amber-800 font-bold text-2xl">{riskStats.medium}</span>
                                <span className="text-amber-600 text-sm font-medium uppercase tracking-wide">Uncertainty</span>
                                <span className="text-amber-400 text-xs mt-1">Review Needed</span>
                            </div>
                            <div className="bg-emerald-50 p-4 rounded-lg border border-emerald-100 flex flex-col items-center">
                                <span className="text-emerald-800 font-bold text-2xl">{riskStats.low}</span>
                                <span className="text-emerald-600 text-sm font-medium uppercase tracking-wide">Stable</span>
                                <span className="text-emerald-400 text-xs mt-1">Clear</span>
                            </div>
                        </div>

                        {riskStats.requiresAction > 0 && (
                            <div className="bg-slate-50 border border-slate-200 rounded-md p-4 flex items-center justify-between">
                                <div className="flex items-center gap-3">
                                    <AlertOctagon className="w-5 h-5 text-amber-500" />
                                    <div className="text-sm">
                                        <span className="font-semibold text-slate-700">{riskStats.requiresAction} Sources</span> require mitigation or review.
                                    </div>
                                </div>
                                <Button size="sm" variant="secondary" asChild>
                                    <Link href="/synthesis">View in Synthesis</Link>
                                </Button>
                            </div>
                        )}
                    </CardContent>
                </Card>

                {/* 1.5 Active Governance Proposals */}
                <Card className="md:col-span-1 border-slate-200 shadow-sm flex flex-col">
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <Activity className="w-5 h-5 text-indigo-600" />
                            Active Proposals
                        </CardTitle>
                        <CardDescription>Ongoing community votes.</CardDescription>
                    </CardHeader>
                    <CardContent className="flex-1 overflow-y-auto max-h-[300px] space-y-4 custom-scrollbar pr-2">
                        {proposals.map(proposal => (
                            <div
                                key={proposal.id}
                                className={`p-3 rounded-lg border text-sm relative group transition-all ${proposal.type === 'epistemic_negation'
                                    ? 'bg-amber-50 border-amber-200 hover:border-amber-300'
                                    : 'bg-white border-slate-100 hover:border-slate-300'
                                    }`}
                            >
                                <button
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        if (confirm('Are you sure you want to delete this proposal?')) {
                                            const service = new GovernanceService();
                                            service.deleteProposal(proposal.id).then(success => {
                                                if (success) {
                                                    setProposals(prev => prev.filter(p => p.id !== proposal.id));
                                                    refreshSources(); // Sync stats
                                                } else {
                                                    alert('Failed to delete proposal. Check console for details.');
                                                }
                                            });
                                        }
                                    }}
                                    className="absolute top-2 right-2 p-1 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded opacity-0 group-hover:opacity-100 transition-all z-10"
                                    title="Delete Proposal (Owner)"
                                >
                                    <Trash className="w-4 h-4" />
                                </button>
                                <div className="flex justify-between items-start mb-1">
                                    <span className={`px-1.5 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider ${proposal.type === 'epistemic_negation' ? 'bg-red-100 text-red-700' : 'bg-slate-100 text-slate-600'
                                        }`}>
                                        {proposal.type === 'epistemic_negation' ? 'Veto Request' : 'Feature Proposal'}
                                    </span>
                                    <span className="text-xs text-slate-400 font-mono">
                                        {new Date(proposal.createdAt).toLocaleDateString()}
                                    </span>
                                </div>
                                <h4 className="font-medium text-slate-800 mb-1 leading-snug">
                                    {proposal.title.replace('Negation of:', 'Veto:')}
                                </h4>
                                {proposal.targetSourceTitle && (
                                    <div className="text-xs text-slate-500 mb-1">
                                        <span className="font-semibold text-slate-700">Target:</span>
                                        {proposal.targetSourceId ? (
                                            <Link
                                                href={`/data?sourceId=${proposal.targetSourceId}`}
                                                className="ml-1 text-indigo-600 hover:text-indigo-800 hover:underline cursor-pointer"
                                            >
                                                {proposal.targetSourceTitle}
                                            </Link>
                                        ) : (
                                            <span className="ml-1">{proposal.targetSourceTitle}</span>
                                        )}
                                    </div>
                                )}
                                <p className="text-slate-500 text-xs line-clamp-2 italic bg-slate-50 p-1 rounded border border-slate-100">
                                    "{proposal.description}"
                                </p>

                                <div className="mt-3 flex items-center gap-3 text-xs font-medium text-slate-400">
                                    <VoteDialog
                                        proposal={proposal}
                                        voteType="for"
                                        onVote={(type, rationale) => {
                                            const service = new GovernanceService();
                                            service.castVote(proposal.id, type, rationale).then(updated => {
                                                if (updated) {
                                                    setProposals(prev => prev.map(p => p.id === updated.id ? updated : p));
                                                }
                                            });
                                        }}
                                    />
                                    <VoteDialog
                                        proposal={proposal}
                                        voteType="against"
                                        onVote={(type, rationale) => {
                                            const service = new GovernanceService();
                                            service.castVote(proposal.id, type, rationale).then(updated => {
                                                if (updated) {
                                                    setProposals(prev => prev.map(p => p.id === updated.id ? updated : p));
                                                }
                                            });
                                        }}
                                    />

                                    {proposal.type === 'epistemic_negation' && (
                                        <div className="flex flex-col items-end gap-2 ml-auto">
                                            <div className="text-amber-600 font-bold text-[10px] uppercase">
                                                Veto Requested
                                            </div>
                                            {proposal.targetSourceId && (
                                                <Link href={`/analysis/${proposal.targetSourceId}`}>
                                                    <Button variant="ghost" size="sm" className="h-6 text-[10px] px-2 text-slate-500 hover:text-indigo-600">
                                                        View Analysis →
                                                    </Button>
                                                </Link>
                                            )}
                                        </div>
                                    )}
                                </div>
                                {proposal.voteHistory && proposal.voteHistory.length > 0 && (
                                    <div className="mt-3 pt-3 border-t border-slate-50 space-y-2">
                                        <div className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">Latest Comments</div>
                                        {proposal.voteHistory.slice(-3).reverse().map((v, i) => (
                                            <div key={i} className="text-xs text-slate-600 bg-slate-50 p-2 rounded relative">
                                                <span className="absolute top-2 right-2 text-[10px] text-slate-400">{v.vote.toUpperCase()}</span>
                                                <p className="italic">"{v.rationale || 'No comment'}"</p>
                                            </div>
                                        ))}
                                    </div>
                                )}
                            </div>
                        ))}
                    </CardContent>
                </Card>

                {/* 2. System Stats */}
                <Card className="border-slate-200 shadow-sm">
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <Layers className="w-5 h-5 text-blue-600" />
                            Orchestration Stats
                        </CardTitle>
                    </CardHeader>
                    <CardContent className="space-y-6">
                        <div className="flex justify-between items-center border-b border-slate-100 pb-4">
                            <span className="text-slate-500 text-sm">Active Sources</span>
                            <span className="font-mono font-bold text-lg">{riskStats.total}</span>
                        </div>
                        <div className="flex justify-between items-center border-b border-slate-100 pb-4">
                            <span className="text-slate-500 text-sm">Recurring Patterns</span>
                            <span className="font-mono font-bold text-lg">{recurrencePatterns.length}</span>
                        </div>
                        <div className="pt-2">
                            <p className="text-xs text-slate-400 leading-relaxed">
                                &quot;Governance is not just policy, but the orchestration of material assemblages.&quot;
                            </p>
                        </div>
                    </CardContent>
                </Card>

                {/* 3. Recurrence / Dominant Logics */}
                <Card className="md:col-span-3 border-slate-200 shadow-sm">
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <BarChart3 className="w-5 h-5 text-purple-600" />
                            Recurring Assemblage Patterns
                        </CardTitle>
                        <CardDescription>Dominant logics detected frequently across the corpus, indicating structural tendencies.</CardDescription>
                    </CardHeader>
                    <CardContent>
                        {recurrencePatterns.length === 0 ? (
                            <div className="p-8 text-center text-slate-400 bg-slate-50 rounded-lg border border-dashed border-slate-200">
                                No significant recurring patterns detected yet.
                            </div>
                        ) : (
                            <div className="space-y-4">
                                {recurrencePatterns.map(([logic, data]) => (
                                    <div key={logic} className="flex items-start gap-4 p-4 rounded-lg bg-white border border-slate-100 hover:border-purple-200 transition-colors">
                                        <div className="flex-shrink-0 w-10 h-10 rounded-full bg-purple-50 text-purple-700 font-bold flex items-center justify-center">
                                            {data.count}
                                        </div>
                                        <div className="flex-1">
                                            <h4 className="font-medium text-slate-800 text-lg">{logic}</h4>
                                            <p className="text-xs text-slate-500 mt-1">
                                                Present in: {data.sources.slice(0, 3).join(", ")}
                                                {data.sources.length > 3 && ` and ${data.sources.length - 3} others`}
                                            </p>
                                        </div>
                                        <div className="flex items-center">
                                            <div className="h-2 w-24 bg-slate-100 rounded-full overflow-hidden">
                                                <div
                                                    className="h-full bg-purple-500"
                                                    style={{ width: `${Math.min((data.count / sources.length) * 100, 100)}%` }}
                                                />
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </CardContent>
                </Card>
            </div>
        </div>
    );
}

"use client";

import { useState, useMemo } from 'react';
import { Source } from '@/types';
import { useSources } from '@/hooks/useSources';
import { useServerStorage } from '@/hooks/useServerStorage'; // [NEW] Persistence
import { FrameworkRadar } from '@/components/governance/FrameworkRadar';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { ShieldAlert, ShieldCheck, Info } from 'lucide-react';
import { Badge } from '@/components/ui/badge';

type ComparisonField = 'governance_power_accountability' | 'plurality_inclusion_embodiment' | 'agency_codesign_self_determination' | 'reflexivity_situated_praxis';

// --- Sub-components (extracted for optimization) ---

const ComparisonSection = ({
    field,
    leftSource,
    rightSource
}: {
    field: ComparisonField,
    leftSource?: Source | null,
    rightSource?: Source | null
}) => (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
        <Card className={`border-l-4 ${leftSource ? 'border-l-indigo-500' : 'border-slate-200'}`}>
            <CardHeader className="pb-2">
                <CardTitle className="text-sm font-medium text-slate-500 uppercase tracking-wide">
                    {leftSource?.title || "Select Source 1"}
                </CardTitle>
            </CardHeader>
            <CardContent>
                <div className="text-sm text-slate-700 leading-relaxed whitespace-pre-wrap">
                    {leftSource?.analysis?.[field] || <span className="text-slate-400 italic">No data available</span>}
                </div>
            </CardContent>
        </Card>

        <Card className={`border-l-4 ${rightSource ? 'border-l-emerald-500' : 'border-slate-200'}`}>
            <CardHeader className="pb-2">
                <CardTitle className="text-sm font-medium text-slate-500 uppercase tracking-wide">
                    {rightSource?.title || "Select Source 2"}
                </CardTitle>
            </CardHeader>
            <CardContent>
                <div className="text-sm text-slate-700 leading-relaxed whitespace-pre-wrap">
                    {rightSource?.analysis?.[field] || <span className="text-slate-400 italic">Select a second source to compare</span>}
                </div>
            </CardContent>
        </Card>
    </div>
);

const RiskBox = ({ source, colorLogic }: { source?: Source | null, colorLogic: (l?: string) => string }) => {
    const riskData = source?.analysis?.structural_pillars?.risk;
    const badge = riskData?.badge || "Unknown";

    return (
        <div className={`p-4 rounded-lg border flex flex-col gap-2 ${colorLogic(badge === "High Risk" ? "High" : "Low")}`}>
            <div className="flex justify-between items-start">
                <h4 className="font-bold text-sm">{riskData?.title || "Risk Classification"}</h4>
                <Badge variant="outline">{badge}</Badge>
            </div>
            <p className="text-xs mt-1">{riskData?.description || "No specific risk classification found."}</p>
            {riskData?.quote && (
                <div className="mt-2 text-xs italic border-l-2 border-inherit pl-2 opacity-80">
                    &quot;{riskData.quote}&quot;
                </div>
            )}
        </div>
    );
};

export default function ResourceOrchestrationPage() {
    const { sources, isLoading } = useSources();

    // [NEW] Persistent Selection
    const [leftSourceId, setLeftSourceId] = useServerStorage<string | null>("governance_left_source_v2", null);
    const [rightSourceId, setRightSourceId] = useServerStorage<string | null>("governance_right_source_v2", null);

    // [NEW] Filter for Policy Documents Only
    const policySources = useMemo(() => {
        return sources.filter(s => s.type === 'PDF' || s.type === 'Text');
    }, [sources]);

    // Initialize state with first available policy sources
    useMemo(() => {
        if (!isLoading && policySources.length > 0) {
            // Only auto-select if nothing is selected (persistence check)
            if (!leftSourceId) setLeftSourceId(policySources[0].id);
            if (!rightSourceId && policySources.length > 1) setRightSourceId(policySources[1].id);
        }
    }, [isLoading, policySources, leftSourceId, rightSourceId, setLeftSourceId, setRightSourceId]);

    const leftSource = useMemo(() => sources.find(s => s.id === leftSourceId), [sources, leftSourceId]);
    const rightSource = useMemo(() => sources.find(s => s.id === rightSourceId), [sources, rightSourceId]);

    // Prepare Radar Data
    const radarData = useMemo(() => {
        if (!leftSource) return [];

        const dimensions = [
            { key: 'centralization', label: 'Centralization' },
            { key: 'rights_focus', label: 'Rights Focus' },
            { key: 'flexibility', label: 'Flexibility' },
            { key: 'market_power', label: 'Market Power' },
            { key: 'procedurality', label: 'Procedural' },
        ];

        return dimensions.map(dim => ({
            dimension: dim.label,
            A: leftSource.analysis?.governance_scores?.[dim.key as keyof typeof leftSource.analysis.governance_scores] || 0,
            B: rightSource?.analysis?.governance_scores?.[dim.key as keyof typeof rightSource.analysis.governance_scores] || 0,
            fullMark: 100
        }));
    }, [leftSource, rightSource]);

    const getRiskColor = (level?: string) => {
        switch (level) {
            case 'High': return 'border-red-500 bg-red-50 text-red-900';
            case 'Medium': return 'border-amber-500 bg-amber-50 text-amber-900';
            case 'Low': return 'border-emerald-500 bg-emerald-50 text-emerald-900';
            default: return 'border-slate-200 bg-white text-slate-500';
        }
    };

    if (isLoading) return <div className="p-8">Loading...</div>;

    return (
        <div className="min-h-screen bg-slate-50 p-8 space-y-8">
            <div className="max-w-7xl mx-auto">
                <h1 className="text-3xl font-light text-slate-900 mb-2">Resource Orchestration</h1>
                <p className="text-slate-500 mb-8">Comparative analysis of governance mechanisms across AI frameworks.</p>

                {/* Controls */}
                <Card className="mb-8 border-slate-200">
                    <CardContent className="p-4 flex items-center justify-between">
                        <div className="flex items-center gap-4 w-full">
                            <span className="text-sm font-semibold text-slate-600 w-32 shrink-0">Framework Comparison</span>
                            <Select value={leftSourceId || ""} onValueChange={setLeftSourceId}>
                                <SelectTrigger className="w-[300px]">
                                    <SelectValue placeholder="Select Source 1" />
                                </SelectTrigger>
                                <SelectContent>
                                    {policySources.map(s => <SelectItem key={s.id} value={s.id}>{s.title}</SelectItem>)}
                                </SelectContent>
                            </Select>

                            <Select value={rightSourceId || ""} onValueChange={setRightSourceId}>
                                <SelectTrigger className="w-[300px]">
                                    <SelectValue placeholder="Select Source 2 (Optional)" />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="none">None</SelectItem>
                                    {policySources.map(s => <SelectItem key={s.id} value={s.id}>{s.title}</SelectItem>)}
                                </SelectContent>
                            </Select>
                        </div>
                    </CardContent>
                </Card>

                {/* Radar Chart */}
                <div className="mb-12 h-[400px] w-full bg-white rounded-xl border border-slate-100 shadow-sm p-4">
                    <FrameworkRadar
                        data={radarData}
                        labelA={leftSource?.title || "Source A"}
                        labelB={rightSource?.title || "Source B"}
                        selectedSourceB={rightSourceId || undefined}
                    />
                </div>

                {/* Grounded Insights Header */}
                <div className="flex items-center gap-2 mb-4">
                    <div className="p-1 rounded bg-purple-100 text-purple-600">
                        <Info className="w-4 h-4" />
                    </div>
                    <h2 className="text-xl font-semibold text-slate-800">Grounded Governance Insights</h2>
                    <Badge variant="secondary" className="text-xs">Original</Badge>
                </div>

                {/* Comparison Sections */}
                <div className="space-y-12">
                    {/* 1. Governance & Power */}
                    <div>
                        <h3 className="text-sm font-bold text-slate-400 uppercase mb-3 flex items-center gap-2">
                            Governance & Power
                        </h3>
                        <ComparisonSection field="governance_power_accountability" leftSource={leftSource} rightSource={rightSource} />
                    </div>

                    {/* 2. Plurality & Inclusion */}
                    <div>
                        <h3 className="text-sm font-bold text-slate-400 uppercase mb-3 flex items-center gap-2">
                            Plurality & Inclusion
                        </h3>
                        <ComparisonSection field="plurality_inclusion_embodiment" leftSource={leftSource} rightSource={rightSource} />
                    </div>

                    {/* 3. Agency & Co-Design */}
                    <div>
                        <h3 className="text-sm font-bold text-slate-400 uppercase mb-3 flex items-center gap-2">
                            Agency & Co-Design
                        </h3>
                        <ComparisonSection field="agency_codesign_self_determination" leftSource={leftSource} rightSource={rightSource} />
                    </div>

                    {/* 4. Reflexivity */}
                    <div>
                        <h3 className="text-sm font-bold text-slate-400 uppercase mb-3 flex items-center gap-2">
                            Reflexivity
                        </h3>
                        <ComparisonSection field="reflexivity_situated_praxis" leftSource={leftSource} rightSource={rightSource} />
                    </div>
                </div>

                {/* Risk Classification */}
                <div className="mt-12 mb-4 flex items-center gap-2">
                    <ShieldAlert className="w-5 h-5 text-slate-600" />
                    <h2 className="text-xl font-bold text-slate-800">Risk Classification</h2>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
                    <RiskBox source={leftSource} colorLogic={getRiskColor} />
                    <RiskBox source={rightSource} colorLogic={getRiskColor} />
                </div>

                {/* Enforcement Bodies */}
                <div className="mt-12 mb-4 flex items-center gap-2">
                    <ShieldCheck className="w-5 h-5 text-slate-600" />
                    <h2 className="text-xl font-bold text-slate-800">Enforcement Bodies</h2>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
                    {/* Left Enforcement */}
                    <Card className="border-slate-200">
                        <CardHeader className="pb-2">
                            <div className="flex justify-between">
                                <CardTitle className="text-xs uppercase text-slate-400">{leftSource?.title}</CardTitle>
                                {leftSource?.analysis?.structural_pillars?.enforcement?.badge && <Badge>{leftSource.analysis.structural_pillars.enforcement.badge}</Badge>}
                            </div>
                            <h4 className="font-bold text-sm mt-1">{leftSource?.analysis?.structural_pillars?.enforcement?.title || "Enforcement Bodies"}</h4>
                        </CardHeader>
                        <CardContent>
                            <p className="text-sm text-slate-600">{leftSource?.analysis?.structural_pillars?.enforcement?.description}</p>
                        </CardContent>
                    </Card>
                    {/* Right Enforcement */}
                    <Card className="border-slate-200">
                        <CardHeader className="pb-2">
                            <div className="flex justify-between">
                                <CardTitle className="text-xs uppercase text-slate-400">{rightSource?.title}</CardTitle>
                                {rightSource?.analysis?.structural_pillars?.enforcement?.badge && <Badge>{rightSource.analysis.structural_pillars.enforcement.badge}</Badge>}
                            </div>
                            <h4 className="font-bold text-sm mt-1">{rightSource?.analysis?.structural_pillars?.enforcement?.title || "Enforcement Bodies"}</h4>
                        </CardHeader>
                        <CardContent>
                            <p className="text-sm text-slate-600">{rightSource?.analysis?.structural_pillars?.enforcement?.description}</p>
                        </CardContent>
                    </Card>
                </div>


            </div>
        </div>
    );
}

'use client';

import React, { useEffect, useState, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '@clerk/nextjs';
import { useWorkspace } from '@/providers/WorkspaceProvider';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Users, CheckCircle, XCircle, Clock } from 'lucide-react';
import { toast } from 'sonner';

interface InviteDetails {
    teamName: string;
    inviterEmail: string;
    role: string;
}

interface PageProps {
    params: Promise<{ token: string }>;
}

export default function AcceptInvitePage({ params }: PageProps) {
    const router = useRouter();
    const { userId, isLoaded } = useAuth();
    const { switchWorkspace, refreshTeams } = useWorkspace();
    const [inviteDetails, setInviteDetails] = useState<InviteDetails | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [isAccepting, setIsAccepting] = useState(false);
    const [accepted, setAccepted] = useState(false);
    const [token, setToken] = useState<string | null>(null);

    // Unwrap params Promise
    useEffect(() => {
        params.then(p => setToken(p.token));
    }, [params]);

    const fetchInviteDetails = useCallback(async () => {
        if (!token) return;

        try {
            const res = await fetch(`/api/collaboration/invites/${token}`);
            const data = await res.json();

            if (!res.ok) {
                if (res.status === 410) {
                    setError('This invitation has expired or has already been used.');
                } else if (res.status === 409) {
                    setError('You are already a member of this team.');
                } else {
                    setError(data.error || 'Invalid invitation link');
                }
                setIsLoading(false);
                return;
            }

            setInviteDetails(data);
        } catch (err) {
            setError('Failed to load invitation details');
        } finally {
            setIsLoading(false);
        }
    }, [token]);

    useEffect(() => {
        if (!token) return;

        // Redirect to login if not authenticated
        if (isLoaded && !userId) {
            router.push(`/sign-in?redirect_url=/invite/${token}`);
            return;
        }

        if (isLoaded && userId) {
            fetchInviteDetails();
        }
    }, [isLoaded, userId, token, router, fetchInviteDetails]);

    const handleAcceptInvite = async () => {
        if (!token) return;

        setIsAccepting(true);

        try {
            const res = await fetch('/api/collaboration/invites/accept', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ token })
            });

            const data = await res.json();

            if (!res.ok) {
                toast.error(data.error || 'Failed to accept invitation');
                setIsAccepting(false);
                return;
            }

            setAccepted(true);
            toast.success(`Welcome to ${inviteDetails?.teamName}!`);

            // Refresh team list to show new team
            await refreshTeams();

            // Switch to team workspace immediately after refresh
            switchWorkspace(data.teamId);

            // Small delay before redirect to allow workspace switch to complete
            setTimeout(() => {
                router.push('/dashboard');
            }, 500);
        } catch (err) {
            toast.error('Network error accepting invitation');
            setIsAccepting(false);
        }
    };

    if (!isLoaded || isLoading) {
        return (
            <div className="min-h-screen flex items-center justify-center bg-zinc-950">
                <Card className="w-full max-w-md bg-zinc-900 border-zinc-800">
                    <CardContent className="pt-6">
                        <div className="text-center py-8">
                            <p className="text-zinc-400">Loading invitation...</p>
                        </div>
                    </CardContent>
                </Card>
            </div>
        );
    }

    if (error) {
        return (
            <div className="min-h-screen flex items-center justify-center bg-zinc-950 p-4">
                <Card className="w-full max-w-md bg-zinc-900 border-zinc-800">
                    <CardContent className="pt-6">
                        <div className="text-center py-8">
                            <XCircle className="w-16 h-16 mx-auto mb-4 text-red-400" />
                            <h2 className="text-xl font-semibold text-white mb-2">Invalid Invitation</h2>
                            <p className="text-zinc-400 mb-6">{error}</p>
                            <Button onClick={() => router.push('/dashboard')} variant="outline">
                                Go to Dashboard
                            </Button>
                        </div>
                    </CardContent>
                </Card>
            </div>
        );
    }

    if (accepted) {
        return (
            <div className="min-h-screen flex items-center justify-center bg-zinc-950 p-4">
                <Card className="w-full max-w-md bg-zinc-900 border-zinc-800">
                    <CardContent className="pt-6">
                        <div className="text-center py-8">
                            <CheckCircle className="w-16 h-16 mx-auto mb-4 text-green-400" />
                            <h2 className="text-xl font-semibold text-white mb-2">Welcome to the Team!</h2>
                            <p className="text-zinc-400">Redirecting to your team workspace...</p>
                        </div>
                    </CardContent>
                </Card>
            </div>
        );
    }

    return (
        <div className="min-h-screen flex items-center justify-center bg-zinc-950 p-4">
            <Card className="w-full max-w-md bg-zinc-900 border-zinc-800">
                <CardHeader className="text-center">
                    <div className="flex justify-center mb-4">
                        <div className="w-16 h-16 rounded-full bg-indigo-900/30 flex items-center justify-center border border-indigo-500/20">
                            <Users className="w-8 h-8 text-indigo-400" />
                        </div>
                    </div>
                    <CardTitle className="text-2xl text-white">Team Invitation</CardTitle>
                    <CardDescription>You've been invited to join a team</CardDescription>
                </CardHeader>
                <CardContent className="space-y-6">
                    <div className="bg-zinc-800 border border-zinc-700 rounded-lg p-4 space-y-3">
                        <div>
                            <p className="text-sm text-zinc-400">Team Name</p>
                            <p className="text-lg font-semibold text-white">{inviteDetails?.teamName}</p>
                        </div>
                        <div>
                            <p className="text-sm text-zinc-400">Invited by</p>
                            <p className="text-white">{inviteDetails?.inviterEmail}</p>
                        </div>
                        <div>
                            <p className="text-sm text-zinc-400">Role</p>
                            <p className="text-white font-medium">{inviteDetails?.role}</p>
                        </div>
                    </div>

                    <div className="flex items-center gap-2 text-sm text-zinc-400 bg-amber-950/20 border border-amber-900/30 rounded-lg p-3">
                        <Clock className="w-4 h-4 text-amber-400" />
                        <span>This invitation expires in 72 hours</span>
                    </div>

                    <div className="space-y-3">
                        <Button
                            onClick={handleAcceptInvite}
                            disabled={isAccepting}
                            className="w-full bg-indigo-600 hover:bg-indigo-700 text-white"
                            size="lg"
                        >
                            {isAccepting ? 'Joining Team...' : 'Accept & Join Team'}
                        </Button>
                        <Button
                            onClick={() => router.push('/dashboard')}
                            variant="outline"
                            className="w-full"
                        >
                            Decline
                        </Button>
                    </div>
                </CardContent>
            </Card>
        </div>
    );
}

"use client";

import { useState, useMemo, useEffect } from "react";
import { useServerStorage } from "@/hooks/useServerStorage";
import { useSources } from "@/hooks/useSources";
import { useDemoMode } from "@/hooks/useDemoMode"; // [NEW]
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Network, ArrowRightLeft, Sparkles, Loader2, PlayCircle, Trash2, Brain, ChevronDown } from "lucide-react";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue, SelectGroup, SelectLabel } from "@/components/ui/select";
import { Dialog, DialogContent, DialogTitle } from "@/components/ui/dialog";
import { OntologyData, OntologyNode, ComparisonResult } from "@/types/ontology";
import { getColorForCategory } from "@/lib/ontology-utils";
import { CreditTopUpDialog } from "@/components/CreditTopUpDialog"; // [NEW]
import { useCredits } from "@/hooks/useCredits"; // [NEW]



// Components
import { OntologyMap } from "@/components/ontology/OntologyMap";
import { ConceptList } from "@/components/ontology/ConceptList";
import { MapGallery } from "@/components/ontology/MapGallery";
import { ConceptDetailsModal } from "@/components/ontology/ConceptDetailsModal";
import { ComparisonView } from "@/components/ontology/ComparisonView";
import { generateCasesFromOntology } from "@/lib/study-utils";

// Static Data (Fallback) - Kept for initial state visualization


const STATIC_CONCEPTS = [
    {
        id: "0",
        label: "Coloniality of Power",
        description: "The living legacy of colonialism in contemporary power structures, defining who has the authority to classify and organize the world.",
        quote: "The coloniality of power is not just a historical event, but a continuous process of ordering the world.",
        category: "Core",
        color: "#fca5a5",
        x: 250, y: 50
    },
    {
        id: "1",
        label: "Algorithmic Rationality",
        description: "The logic by which algorithms order, sort, and prioritize information, often embedding specific cultural and epistemological values.",
        quote: "Algorithms are not neutral tools; they are crystallized forms of rationality.",
        category: "Mechanism",
        color: "#d8b4fe",
        x: 450, y: 150
    },
    {
        id: "2",
        label: "Global South State",
        description: "The political entity situated in the periphery of the world-system, navigating the imposition of external AI norms while asserting sovereignty.",
        quote: "The state in the Global South is not merely a regulator but a site of contestation.",
        category: "Actor",
        color: "#93c5fd",
        x: 50, y: 150
    },
    {
        id: "3",
        label: "Data Extractivism",
        description: "The process of extracting data from human life and turning it into a resource for capital accumulation.",
        quote: "Data is the new oil, but the extraction process leaves behind social pollution.",
        category: "Mechanism",
        color: "#d8b4fe",
        x: 400, y: 300
    },
    {
        id: "4",
        label: "Fundamental Rights",
        description: "The set of ethical and legal principles protected by frameworks like the EU AI Act, often framed as universal but historically situated.",
        quote: "Rights are the language through which power is negotiated and contested.",
        category: "Value",
        color: "#86efac",
        x: 100, y: 300
    },
    {
        id: "5",
        label: "Sociotechnical Assemblage",
        description: "Complex arrangements of humans, machines, norms, and resources that constitute AI systems as loosely coupled, emergently structured entities.",
        quote: "AI is not a thing, but an assemblage of social and technical relations that orchestrate value.",
        category: "Core",
        color: "#fca5a5",
        x: 250, y: 200
    },
] as OntologyNode[];

const STATIC_NETWORK_LINKS = [
    { source: "0", target: "1", relation: "informs" },
    { source: "0", target: "2", relation: "constrains" },
    { source: "0", target: "5", relation: "shapes" },
    { source: "1", target: "3", relation: "enables" },
    { source: "1", target: "5", relation: "structures" },
    { source: "2", target: "4", relation: "protects" },
    { source: "2", target: "5", relation: "regulates" },
    { source: "3", target: "5", relation: "feeds" },
    { source: "4", target: "5", relation: "embedded in" },
];

export default function OntologyPage() {
    const { sources } = useSources();
    const { isReadOnly } = useDemoMode(); // [NEW]
    const [selectedSourceId, setSelectedSourceId] = useServerStorage<string>("ontology_selected_source_id", "");
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [ontologyMaps, setOntologyMaps] = useServerStorage<Record<string, OntologyData>>("ontology_maps", {});



    // Comparison State
    const [isComparing, setIsComparing] = useServerStorage<boolean>("ontology_is_comparing", false);
    const [selectedForComparison, setSelectedForComparison] = useServerStorage<string[]>("ontology_selected_comparison_ids", []);
    const [comparisonResult, setComparisonResult, isComparisonResultLoading] = useServerStorage<ComparisonResult | null>("ontology_comparison_result", null);
    const [isComparingLoading, setIsComparingLoading] = useState(false);

    // Interactivity State
    // Interactivity State
    const [selectedNodeId, setSelectedNodeId] = useState<string | null>(null);
    const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
    type ViewMode = 'all' | 'ghost-network' | 'hide-ghosts';
    const [viewMode, setViewMode] = useState<ViewMode>('all');

    // Credit System
    const { hasCredits, refetch: refetchCredits, loading: creditsLoading } = useCredits();
    const [showTopUp, setShowTopUp] = useState(false);
    const [customExpectedActors, setCustomExpectedActors] = useState('');

    // [Fix] Hydration Mismatch for Radix UI
    const [isMounted, setIsMounted] = useState(false);
    useEffect(() => {
        setIsMounted(true);
    }, []);

    // Filter sources that have text available for analysis and exclude 'Web' and 'Trace' sources
    const analyzedSources = sources.filter(s => s.extractedText && s.type !== 'Web' && s.type !== 'Trace');

    // Group sources by type for the dropdown
    const groupedSources = useMemo(() => {
        return analyzedSources.reduce((acc, source) => {
            const type = source.type || 'Other';
            if (!acc[type]) acc[type] = [];
            acc[type].push(source);
            return acc;
        }, {} as Record<string, typeof analyzedSources>);
    }, [analyzedSources]);

    // Get the currently active map based on selectedSourceId
    const currentOntologyData = (selectedSourceId && ontologyMaps && ontologyMaps[selectedSourceId])
        ? ontologyMaps[selectedSourceId]
        : null;



    const handleGenerateOntology = async () => {
        if (selectedSourceId && analyzedSources.find(s => s.id === selectedSourceId) && ontologyMaps && ontologyMaps[selectedSourceId]) {
            // Allow viewing cached maps
        } else if (isAnalyzing) {
            return;
        }
        // NOTE: We don't strictly block generation if it's cached, but if new generation is required:
        if (isReadOnly) {
            alert("Ontology generation is disabled in Demo Mode.");
            return;
        }

        // Credit Check
        if (!creditsLoading && !hasCredits) {
            setShowTopUp(true);
            return;
        }

        const source = analyzedSources.find(s => s.id === selectedSourceId);
        if (!source || !source.extractedText) return;

        setIsAnalyzing(true);
        try {
            const headers: HeadersInit = { 'Content-Type': 'application/json' };
            if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true' && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
            }

            const response = await fetch('/api/analyze', {
                method: 'POST',
                headers: headers,
                body: JSON.stringify({
                    text: source.extractedText.substring(0, 100000), // Increase limit to 100k, let backend handle structural parsing
                    analysisMode: 'ontology',
                    force: true, // Force refresh to bypass cache
                    ...(customExpectedActors.trim() && { expectedActors: customExpectedActors }),
                })
            });

            const data = await response.json();
            if (data.success && data.analysis) {
                // Process nodes to add coordinates and colors
                const processedNodes = data.analysis.nodes.map((node: OntologyNode, index: number) => ({
                    ...node,
                    label: node.label || node.id,
                    x: 300 + 200 * Math.cos(2 * Math.PI * index / data.analysis.nodes.length),
                    y: 200 + 150 * Math.sin(2 * Math.PI * index / data.analysis.nodes.length),
                    color: getColorForCategory(node.category)
                }));

                const newMap: OntologyData = {
                    summary: data.analysis.summary,
                    nodes: processedNodes,
                    links: data.analysis.links,
                    ghostNodeCount: data.analysis.ghostNodeCount || 0,
                    ...(data.analysis.institutionalLogics && { institutionalLogics: data.analysis.institutionalLogics }),
                    ...(data.analysis.methodologicalNotes && { methodologicalNotes: data.analysis.methodologicalNotes }),
                    ...(data.analysis.userActorsUsed?.length && { userActorsUsed: data.analysis.userActorsUsed }),
                    ...(data.analysis.dominantDiscourses?.length && { dominantDiscourses: data.analysis.dominantDiscourses }),
                };

                // Update the maps record
                setOntologyMaps({
                    ...ontologyMaps,
                    [selectedSourceId]: newMap
                });
                refetchCredits();
            } else {
                alert("Analysis failed: " + (data.error || "Unknown error"));
            }
        } catch (error) {
            console.error("Ontology generation error:", error);
            alert("Failed to generate ontology.");
        } finally {
            setIsAnalyzing(false);
        }
    };

    const handleCompareOntologies = async () => {
        if (isReadOnly) {
            alert("Comparison is disabled in Demo Mode.");
            return;
        }

        // Credit Check
        if (!creditsLoading && !hasCredits) {
            setShowTopUp(true);
            return;
        }
        if (selectedForComparison.length < 2 || selectedForComparison.length > 3) return;
        if (isComparisonResultLoading) return; // Prevent run if still loading

        const sourceAId = selectedForComparison[0];
        const sourceBId = selectedForComparison[1];
        const sourceCId = selectedForComparison[2]; // Optional

        // Check for existing result
        if (comparisonResult) {
            // Check if the existing result matches the currently selected sources
            const currentIds = [...selectedForComparison].sort();
            const existingIds = [
                comparisonResult.sourceAId,
                comparisonResult.sourceBId,
                comparisonResult.sourceCId
            ].filter(Boolean) as string[];
            existingIds.sort();

            // Simple array equality check
            const isSameComparison = currentIds.length === existingIds.length &&
                currentIds.every((val, index) => val === existingIds[index]);

            if (isSameComparison) {
                // IDs match! Show the existing result without re-running or asking
                setIsComparing(true); // Ensure comparison view is active
                return;
            }

            // IDs differ, ask to overwrite
            const confirmRun = confirm("Existing comparison found for DIFFERENT maps. Do you want to run a new comparison? This will overwrite the current results.");
            if (!confirmRun) {
                return;
            }
        }

        const sourceA = sources.find(s => s.id === sourceAId);
        const sourceB = sources.find(s => s.id === sourceBId);
        const sourceC = sourceCId ? sources.find(s => s.id === sourceCId) : undefined;

        const mapA = ontologyMaps?.[sourceAId];
        const mapB = ontologyMaps?.[sourceBId];
        const mapC = sourceCId ? ontologyMaps?.[sourceCId] : undefined;

        if (!sourceA || !sourceB || !mapA || !mapB) return;
        if (sourceCId && (!sourceC || !mapC)) return; // If 3rd selected but missing data, abort

        setIsComparingLoading(true);
        // setComparisonResult(null); // Keep previous result for better UX during load

        try {
            const headers: HeadersInit = { 'Content-Type': 'application/json' };
            if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true' && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
            }

            const payload: Record<string, unknown> = {
                analysisMode: 'ontology_comparison',
                sourceA: { title: sourceA.title, data: mapA },
                sourceB: { title: sourceB.title, data: mapB },
                force: true
            };

            if (sourceC && mapC) {
                payload.sourceC = { title: sourceC.title, data: mapC };
            }

            const response = await fetch('/api/analyze', {
                method: 'POST',
                headers: headers,
                body: JSON.stringify(payload)
            });

            const data = await response.json();
            if (data.success && data.analysis) {
                // Attach the source IDs to the result so we can identify it later
                const analysisWithIds: ComparisonResult = {
                    ...data.analysis,
                    sourceAId: sourceAId,
                    sourceBId: sourceBId,
                    sourceCId: sourceCId
                };
                setComparisonResult(analysisWithIds);
            } else {
                alert("Comparison failed: " + (data.error || "Unknown error"));
            }
        } catch (error) {
            console.error("Comparison error:", error);
            alert("Failed to compare ontologies.");
        } finally {
            setIsComparingLoading(false);
        }
    };

    const toggleComparisonSelection = (sourceId: string) => {
        if (selectedForComparison.includes(sourceId)) {
            setSelectedForComparison(prev => prev.filter(id => id !== sourceId));
        } else {
            if (selectedForComparison.length < 3) { // Updated limit to 3
                setSelectedForComparison(prev => [...prev, sourceId]);
            }
        }
    };

    const handleNodeDrag = (nodeId: string, x: number, y: number) => {
        if (selectedSourceId && currentOntologyData) {
            const updatedNodes = currentOntologyData.nodes.map(node =>
                node.id === nodeId ? { ...node, x, y } : node
            );

            setOntologyMaps({
                ...ontologyMaps,
                [selectedSourceId]: {
                    ...currentOntologyData,
                    nodes: updatedNodes
                }
            });
        }
    };

    // Filtering Logic
    // Filter nodes based on category and view mode
    const displayNodes = currentOntologyData
        ? currentOntologyData.nodes.filter(n => {
            const categoryMatch = !selectedCategory || n.category === selectedCategory;

            // View mode filtering
            let viewMatch = true;
            if (viewMode === 'hide-ghosts') {
                viewMatch = !n.isGhost;
            } else if (viewMode === 'ghost-network') {
                // Show ghost nodes + actors they connect to
                if (n.isGhost) {
                    viewMatch = true;
                } else {
                    // Check if this real node is connected to any ghost node
                    const connectedToGhost = currentOntologyData.nodes.some(ghostNode => {
                        if (!ghostNode.isGhost) return false;
                        return ghostNode.potentialConnections?.some(pc =>
                            pc.targetActor === n.label || n.label.includes(pc.targetActor) || pc.targetActor.includes(n.label)
                        );
                    });
                    viewMatch = connectedToGhost;
                }
            }
            // viewMode === 'all' shows everything

            return categoryMatch && viewMatch;
        })
        : STATIC_CONCEPTS;

    const displayLinks = currentOntologyData
        ? currentOntologyData.links.filter(l => {
            const sourceNode = currentOntologyData.nodes.find(n => n.id === l.source);
            const targetNode = currentOntologyData.nodes.find(n => n.id === l.target);
            if (selectedCategory) {
                return sourceNode?.category === selectedCategory && targetNode?.category === selectedCategory;
            }
            return true;
        })
        : STATIC_NETWORK_LINKS;

    const selectedNode = currentOntologyData
        ? currentOntologyData.nodes.find(n => n.id === selectedNodeId)
        : STATIC_CONCEPTS.find(n => n.id === selectedNodeId);

    const effectiveSelectedNode = selectedNode;



    return (
        <div className="space-y-8 relative">
            <CreditTopUpDialog open={showTopUp} onOpenChange={setShowTopUp} onSuccess={() => refetchCredits()} />




            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h2 className="text-3xl font-bold text-slate-900 flex items-center gap-2">
                        <Network className="h-8 w-8 text-indigo-600" />
                        Concept Network
                    </h2>
                    <div className="text-slate-500 mt-2 flex flex-wrap items-center gap-2 text-sm">
                        Visualizing the assemblage:
                        <Badge variant="secondary" className="bg-red-100 text-red-700 hover:bg-red-200 border-red-200 cursor-default">Core</Badge>
                        <Badge variant="secondary" className="bg-purple-100 text-purple-700 hover:bg-purple-200 border-purple-200 cursor-default">Mechanism</Badge>
                        <Badge variant="secondary" className="bg-blue-100 text-blue-700 hover:bg-blue-200 border-blue-200 cursor-default">Actor</Badge>
                        <Badge variant="secondary" className="bg-green-100 text-green-700 hover:bg-green-200 border-green-200 cursor-default">Value</Badge>
                    </div>
                </div>
                <div className="flex items-center gap-3">
                    <Button
                        variant={isComparing ? "secondary" : "outline"}
                        onClick={() => {
                            setIsComparing(!isComparing);
                            setComparisonResult(null);
                            setSelectedForComparison([]);
                        }}
                        className="gap-2"
                    >
                        <ArrowRightLeft className="h-4 w-4" />
                        {isComparing ? "Exit Comparison" : "Compare Maps"}
                    </Button>



                    {!isComparing && (
                        <>
                            {isMounted ? (
                                <Select
                                    value={selectedSourceId || ""}
                                    onValueChange={(val) => {
                                        if (val !== selectedSourceId) {
                                            setSelectedSourceId(val);
                                        }
                                    }}
                                >
                                    <SelectTrigger className="w-[280px]">
                                        <SelectValue placeholder="Select a source to analyze" />
                                    </SelectTrigger>
                                    <SelectContent>
                                        {Object.entries(groupedSources).map(([type, groupSources]) => (
                                            <SelectGroup key={type}>
                                                <SelectLabel className="text-xs font-semibold text-slate-500 uppercase tracking-wider bg-slate-50/50 pl-2 py-1">
                                                    {type} Sources
                                                </SelectLabel>
                                                {groupSources.map((source) => {
                                                    const dotColor =
                                                        source.type === 'PDF' ? 'bg-red-500' :
                                                            source.type === 'Web' ? 'bg-sky-500' :
                                                                source.type === 'Word' ? 'bg-blue-600' :
                                                                    source.type === 'Trace' ? 'bg-amber-500' :
                                                                        'bg-slate-400';
                                                    return (
                                                        <SelectItem key={source.id} value={source.id}>
                                                            <div className="flex items-center gap-2">
                                                                <div className={`h-2 w-2 rounded-full ${dotColor}`} />
                                                                <span className="truncate max-w-[200px]" title={source.title}>{source.title}</span>
                                                            </div>
                                                        </SelectItem>
                                                    );
                                                })}
                                            </SelectGroup>
                                        ))}
                                    </SelectContent>
                                </Select>
                            ) : (
                                <div className="w-[280px] h-10 bg-slate-100 rounded-md animate-pulse" />
                            )}
                            <Button
                                onClick={handleGenerateOntology}
                                disabled={!selectedSourceId || isAnalyzing || (isReadOnly && analyzedSources.find(s => s.id === selectedSourceId) && !ontologyMaps?.[selectedSourceId])}
                                className="bg-indigo-600 hover:bg-indigo-700 text-white"
                                title={isReadOnly && (!ontologyMaps?.[selectedSourceId!]) ? "Generation disabled in Demo Mode" : ""}
                            >
                                {isAnalyzing ? (
                                    <>
                                        <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                        Analyzing...
                                    </>
                                ) : (
                                    <>
                                        <Sparkles className="mr-2 h-4 w-4" />
                                        Generate Map
                                    </>
                                )}
                            </Button>
                        </>
                    )}
                </div>
            </div>

            {/* Custom Expected Actors — collapsible textarea */}
            {!isComparing && (
                <details className="group">
                    <summary className="flex items-center gap-2 cursor-pointer text-sm font-medium text-slate-600 hover:text-slate-800 select-none">
                        <ChevronDown className="h-3.5 w-3.5 transition-transform group-open:rotate-180" />
                        Custom Expected Actors (optional)
                    </summary>
                    <div className="mt-2 max-w-lg">
                        <textarea
                            className="w-full h-24 text-sm border border-slate-200 rounded-lg p-3 resize-y focus:ring-2 focus:ring-indigo-200 focus:border-indigo-400 transition-colors"
                            placeholder={"One expected actor per line, e.g.:\nIndigenous communities\nGig economy workers\nEnvironmental justice organizations"}
                            value={customExpectedActors}
                            onChange={(e) => setCustomExpectedActors(e.target.value)}
                        />
                        {customExpectedActors.split('\n').filter(s => s.trim()).length > 15 && (
                            <p className="text-xs text-amber-600 mt-1">
                                ⚠️ More than 15 actors may reduce detection quality. Consider trimming.
                            </p>
                        )}
                    </div>
                </details>
            )}

            {/* Post-analysis confirmation of user actors */}
            {currentOntologyData?.userActorsUsed && currentOntologyData.userActorsUsed.length > 0 && (
                <div className="flex items-center gap-2 text-xs text-indigo-600 bg-indigo-50 border border-indigo-100 rounded-lg px-3 py-2">
                    <Sparkles className="h-3.5 w-3.5" />
                    <span>Analysis included your custom actors: {currentOntologyData.userActorsUsed.join(', ')}</span>
                </div>
            )}

            {/* Primary discourses display */}
            {currentOntologyData?.dominantDiscourses && currentOntologyData.dominantDiscourses.length > 0 && (
                <div className="flex flex-wrap gap-2 mt-2">
                    {currentOntologyData.dominantDiscourses.map((disc: string, idx: number) => (
                        <span key={idx} className="text-[10px] font-medium text-slate-500 bg-slate-100 px-2 py-0.5 rounded-full border border-slate-200">
                            {disc}
                        </span>
                    ))}
                </div>
            )}

            {/* Comparison Result View */}
            {
                isComparing && comparisonResult && (
                    <ComparisonView result={comparisonResult} sources={sources} />
                )
            }

            {/* Main Visualization */}
            {
                !isComparing && (
                    <>
                        {currentOntologyData?.summary && (
                            <Card className="bg-slate-50 border-indigo-100">
                                <CardContent className="pt-6">
                                    <p className="text-slate-700 leading-relaxed">
                                        <span className="font-semibold text-indigo-700">Analysis Summary: </span>
                                        {currentOntologyData.summary}
                                    </p>
                                </CardContent>
                            </Card>
                        )}

                        {/* Ghost Node Statistics */}
                        {currentOntologyData && currentOntologyData.ghostNodeCount && currentOntologyData.ghostNodeCount > 0 && (
                            <div className="grid grid-cols-3 gap-4">
                                <Card className="border-blue-200 bg-blue-50">
                                    <CardContent className="pt-6">
                                        <div className="text-3xl font-bold text-blue-700">
                                            {currentOntologyData.nodes.filter(n => !n.isGhost).length}
                                        </div>
                                        <div className="text-sm text-blue-600 mt-1">Visible Actors</div>
                                    </CardContent>
                                </Card>
                                <Card className="border-purple-200 bg-purple-50">
                                    <CardContent className="pt-6">
                                        <div className="text-3xl font-bold text-purple-700">
                                            {currentOntologyData.ghostNodeCount}
                                        </div>
                                        <div className="text-sm text-purple-600 mt-1">Ghost Nodes</div>
                                    </CardContent>
                                </Card>
                                <Card className="border-gray-200 bg-gray-50">
                                    <CardContent className="pt-6">
                                        <div className="text-3xl font-bold text-gray-700">
                                            {currentOntologyData.links.length}
                                        </div>
                                        <div className="text-sm text-gray-600 mt-1">Connections</div>
                                    </CardContent>
                                </Card>
                            </div>
                        )}

                        {/* AI Methodology Notes — transparency panel */}
                        {currentOntologyData && currentOntologyData.methodologicalNotes && (
                            <details className="group">
                                <summary className="flex items-center gap-2 cursor-pointer text-sm font-medium text-amber-700 bg-amber-50 border border-amber-200 rounded-lg px-4 py-2.5 hover:bg-amber-100 transition-colors select-none">
                                    <Brain className="h-4 w-4 text-amber-600" />
                                    <span>AI Methodology Notes</span>
                                    <ChevronDown className="h-3.5 w-3.5 ml-auto transition-transform group-open:rotate-180 text-amber-500" />
                                </summary>
                                <div className="mt-2 px-4 py-3 text-sm text-amber-800 bg-amber-50/60 border border-amber-100 rounded-lg leading-relaxed">
                                    {currentOntologyData.methodologicalNotes}
                                </div>
                            </details>
                        )}

                        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                            <div className="lg:col-span-2 space-y-4">
                                {/* Ghost Node Toggle */}
                                {currentOntologyData && currentOntologyData.ghostNodeCount && currentOntologyData.ghostNodeCount > 0 && (
                                    <div className="flex flex-col gap-2">
                                        <div className="text-sm font-medium text-slate-700">View Mode</div>
                                        <Select value={viewMode} onValueChange={(value) => setViewMode(value as ViewMode)}>
                                            <SelectTrigger className="w-[280px] bg-purple-50 border-purple-300">
                                                <SelectValue />
                                            </SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="all">
                                                    <div className="flex items-center gap-2">
                                                        <span>🌐</span>
                                                        <div>
                                                            <div className="font-medium">All Actors</div>
                                                            <div className="text-xs text-slate-500">Show complete network</div>
                                                        </div>
                                                    </div>
                                                </SelectItem>
                                                <SelectItem value="ghost-network">
                                                    <div className="flex items-center gap-2">
                                                        <span>👻</span>
                                                        <div>
                                                            <div className="font-medium">Ghost Network Only ({currentOntologyData.ghostNodeCount})</div>
                                                            <div className="text-xs text-slate-500">Absent actors + their connections</div>
                                                        </div>
                                                    </div>
                                                </SelectItem>
                                                <SelectItem value="hide-ghosts">
                                                    <div className="flex items-center gap-2">
                                                        <span>👤</span>
                                                        <div>
                                                            <div className="font-medium">Hide Ghost Nodes</div>
                                                            <div className="text-xs text-slate-500">Only present actors</div>
                                                        </div>
                                                    </div>
                                                </SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>
                                )}
                                <OntologyMap
                                    nodes={displayNodes}
                                    links={displayLinks}
                                    selectedCategory={selectedCategory}
                                    onSelectCategory={setSelectedCategory}
                                    selectedNodeId={selectedNodeId}
                                    onSelectNode={setSelectedNodeId}
                                    onNodeDrag={handleNodeDrag}
                                />
                            </div>

                            <ConceptList
                                nodes={displayNodes}
                                selectedNodeId={selectedNodeId}
                                onSelectNode={setSelectedNodeId}
                            />
                        </div>
                    </>
                )
            }

            <MapGallery
                ontologyMaps={ontologyMaps}
                sources={sources}
                selectedSourceId={selectedSourceId}
                onSelectSource={setSelectedSourceId}
                isComparing={isComparing}
                selectedForComparison={selectedForComparison}
                onToggleComparisonSelection={toggleComparisonSelection}
                onCompare={handleCompareOntologies}
                isComparingLoading={isComparingLoading}
                isComparisonResultLoading={isComparisonResultLoading}
            />

            <Dialog open={!!selectedNodeId} onOpenChange={(open) => !open && setSelectedNodeId(null)}>
                <DialogContent className="max-w-4xl p-0 border-none bg-transparent shadow-none max-h-[90vh] overflow-y-auto">
                    <DialogTitle className="sr-only">Concept Details</DialogTitle>
                    <ConceptDetailsModal
                        selectedNode={effectiveSelectedNode || null}
                        isActive={!!selectedNodeId}
                        onClose={() => setSelectedNodeId(null)}
                        isStatic={!currentOntologyData}
                        sourceId={selectedSourceId}
                        onNextCase={() => {
                            if (!currentOntologyData || !selectedNodeId) return;
                            const ghostNodes = currentOntologyData.nodes.filter(n => n.isGhost);
                            const currentIndex = ghostNodes.findIndex(n => n.id === selectedNodeId);
                            if (currentIndex >= 0 && currentIndex < ghostNodes.length - 1) {
                                setSelectedNodeId(ghostNodes[currentIndex + 1].id);
                            } else {
                                setSelectedNodeId(null); // Close if it's the last one
                            }
                        }}
                    />
                </DialogContent>
            </Dialog>
        </div >
    );
}

"use client";

import { useState, useEffect } from "react";
import { useServerStorage } from "@/hooks/useServerStorage";
import { useSources } from "@/hooks/useSources"; // Added hook
import { useDemoMode } from "@/hooks/useDemoMode";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { BookOpen, Save, UserCircle, History, FileText, Loader2 } from "lucide-react"; // Added icons
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"; // Added Select

import { LogEntry } from "@/components/reflexivity/LogEntry";
import { MethodLog } from "@/types/logs";

const GUIDING_QUESTIONS = [
    "How does my location in the Global North/South affect my reading of these texts?",
    "What assumptions am I making about 'universal' AI ethics?",
    "Whose voices are missing from the documents I am analyzing?",
    "How does my own disciplinary background shape my interpretation of 'risk' and 'harm'?",
];


export default function ReflexivityPage() {
    const { sources, isLoading } = useSources();
    const { isReadOnly } = useDemoMode();
    const [selectedPolicyId, setSelectedPolicyId] = useState<string | null>(null);

    // Identify Policy Documents
    const policyDocuments = sources.filter(s => s.type !== "Trace");

    // Dynamic Journal Entry Key based on Policy ID
    const journalKey = selectedPolicyId ? `research-journal-${selectedPolicyId}` : "research-journal-global";
    const [journalEntry, setJournalEntry] = useServerStorage(journalKey, "");

    // Reset journal entry when key changes (useServerStorage handles persistence, but we need to ensure UI updates)
    // Note: useServerStorage automatic syncing handles this, but explicit reset might be needed if switching fast.
    // Actually, useServerStorage hook usually handles the key change re-fetch internally.

    const [saveStatus, setSaveStatus] = useState<"saved" | "saving" | null>(null);
    const [logs, setLogs] = useState<MethodLog[]>([]);

    useEffect(() => {
        const fetchLogs = async () => {
            try {
                const headers: HeadersInit = { 'Content-Type': 'application/json' };
                if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true' && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                    headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
                }

                const res = await fetch('/api/logs', { headers });
                if (res.ok) {
                    const data = await res.json();
                    setLogs(data);
                }
            } catch (error) {
                console.error("Failed to fetch logs", error);
            }
        };

        fetchLogs();
    }, []);

    // Filter Logs by Selected Policy
    // We assume logs might have `details.policyId` or `details.sourceId`
    // If a log has NO policyId, we might hide it or show it in a "Global" view.
    // For this strict view, we show only matching logs.
    const filteredLogs = logs.filter(log => {
        if (!selectedPolicyId) return false;
        // Check various possible locations for the ID in the messy log structure
        const pId = log.details?.policyId || log.details?.sourceId || (log.details as any)?.documentId;
        return pId === selectedPolicyId;
    });

    const handleSave = () => {
        setSaveStatus("saving");
        // The data is already saved via useLocalStorage (useServerStorage), just show feedback
        setTimeout(() => {
            setSaveStatus("saved");
            setTimeout(() => setSaveStatus(null), 2000);
        }, 300);
    };

    if (isLoading) {
        return (
            <div className="flex items-center justify-center h-64">
                <Loader2 className="h-8 w-8 animate-spin text-slate-400" />
            </div>
        );
    }

    return (
        <div className="space-y-8 animate-in fade-in duration-500">
            <div>
                <h2 className="text-3xl font-bold tracking-tight text-slate-900">Critical Reflection</h2>
                <p className="text-slate-500">Documenting epistemic location and engaging with positionality.</p>
            </div>

            {/* Policy Selector Section */}
            <div className="p-6 bg-white rounded-xl border border-slate-200 shadow-sm">
                <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
                    <div className="flex items-center gap-4 w-full md:w-auto">
                        <div className="p-3 bg-purple-50 rounded-lg">
                            <FileText className="h-6 w-6 text-purple-600" />
                        </div>
                        <div>
                            <h3 className="font-semibold text-slate-900">Active Policy Document</h3>
                            <p className="text-sm text-slate-500">Select a document to view its specific reflexive journal and logs</p>
                        </div>
                    </div>
                    <div className="w-full md:w-[300px]">
                        <Select
                            value={selectedPolicyId || ""}
                            onValueChange={(val) => setSelectedPolicyId(val)}
                        >
                            <SelectTrigger>
                                <SelectValue placeholder="Select a policy document..." />
                            </SelectTrigger>
                            <SelectContent>
                                {policyDocuments.length === 0 ? (
                                    <div className="p-2 text-sm text-slate-500 text-center">No documents found</div>
                                ) : (
                                    policyDocuments.map(doc => (
                                        <SelectItem key={doc.id} value={doc.id}>
                                            {doc.title}
                                        </SelectItem>
                                    ))
                                )}
                            </SelectContent>
                        </Select>
                    </div>
                </div>
            </div>

            {selectedPolicyId ? (
                <div className="grid gap-6 md:grid-cols-2">
                    <div className="space-y-6">
                        <Card>
                            <CardHeader>
                                <div className="flex items-center space-x-2">
                                    <UserCircle className="h-5 w-5 text-slate-600" />
                                    <CardTitle className="text-lg">Guiding Questions</CardTitle>
                                </div>
                                <CardDescription>
                                    Prompts to consider during your analysis of {sources.find(s => s.id === selectedPolicyId)?.title}.
                                </CardDescription>
                            </CardHeader>
                            <CardContent>
                                <ul className="space-y-4">
                                    {GUIDING_QUESTIONS.map((question, index) => (
                                        <li key={index} className="flex items-start space-x-3 text-sm text-slate-700">
                                            <span className="flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-slate-100 text-xs font-medium text-slate-600">
                                                {index + 1}
                                            </span>
                                            <span className="pt-0.5">{question}</span>
                                        </li>
                                    ))}
                                </ul>
                            </CardContent>
                        </Card>

                        <Card>
                            <CardHeader>
                                <div className="flex items-center space-x-2">
                                    <History className="h-5 w-5 text-slate-600" />
                                    <CardTitle className="text-lg">Methodological Log</CardTitle>
                                </div>
                                <CardDescription>
                                    Automated log of actions performed on this policy.
                                </CardDescription>
                            </CardHeader>
                            <CardContent>
                                <div className="space-y-4 max-h-[400px] overflow-y-auto pr-2">
                                    {filteredLogs.length === 0 ? (
                                        <p className="text-sm text-slate-500 italic">No specific actions logged for this policy yet.</p>
                                    ) : (
                                        filteredLogs.map((log) => (
                                            <LogEntry key={log.id} log={log} />
                                        ))
                                    )}
                                </div>
                            </CardContent>
                        </Card>

                        <div className="bg-slate-50 p-4 rounded-lg border border-slate-200 text-sm text-slate-600 italic">
                            &quot;To think from the border is to think from the exteriority of modernity... it is a way of thinking that is not just &apos;critical&apos; but &apos;decolonial&apos;.&quot; — Walter Mignolo
                        </div>
                    </div>

                    <Card className="flex flex-col h-full">
                        <CardHeader>
                            <div className="flex items-center space-x-2">
                                <BookOpen className="h-5 w-5 text-slate-600" />
                                <CardTitle className="text-lg">Research Journal</CardTitle>
                            </div>
                            <CardDescription>
                                Record your thoughts, biases, and shifts in perspective for this specific document.
                            </CardDescription>
                        </CardHeader>
                        <CardContent className="flex-1 flex flex-col space-y-4">
                            <Textarea
                                placeholder="Start writing your specific reflections for this policy here..."
                                className="flex-1 min-h-[300px] resize-none p-4 leading-relaxed text-slate-900"
                                value={journalEntry}
                                onChange={(e) => setJournalEntry(e.target.value)}
                            />
                            <div className="flex justify-end">
                                <Button
                                    onClick={handleSave}
                                    className="bg-slate-900 text-white hover:bg-slate-800"
                                    disabled={saveStatus === "saving" || isReadOnly}
                                    title={isReadOnly ? "Saving disabled in Demo Mode" : ""}
                                >
                                    <Save className="mr-2 h-4 w-4" />
                                    {saveStatus === "saving" ? "Saving..." : saveStatus === "saved" ? "Saved!" : "Save Entry"}
                                </Button>
                            </div>
                        </CardContent>
                    </Card>
                </div>
            ) : (
                <div className="bg-slate-50 rounded-xl border border-dashed border-slate-200 p-12 text-center">
                    <div className="mx-auto w-16 h-16 bg-white rounded-full flex items-center justify-center shadow-sm mb-4">
                        <BookOpen className="h-8 w-8 text-slate-300" />
                    </div>
                    <h3 className="text-lg font-bold text-slate-700">No Policy Selected</h3>
                    <p className="text-slate-500 mt-2">Please select a policy document above to access its Reflexive Journal and Logs.</p>
                </div>
            )}
        </div>
    );
}

"use client";

import { useState } from "react";
import { toast } from "sonner";
import { useServerStorage } from "@/hooks/useServerStorage";
import { useSources } from "@/hooks/useSources";
import { useDemoMode } from "@/hooks/useDemoMode";
import { Source, ResistanceSynthesisResult } from "@/types";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { ResistanceVisualization } from "@/components/resistance/ResistanceVisualization";

import { Zap, EyeOff, Activity, Wrench, Users, Loader2, Search, Trash, FileText, ExternalLink, Play, Quote } from "lucide-react";

import { CreditTopUpDialog } from "@/components/CreditTopUpDialog";
import { useCredits } from "@/hooks/useCredits";

// Define Strategy Definitions with Icons for UI
const STRATEGY_DEFINITIONS = [
    { title: "Gambiarra", icon: Wrench, color: "text-orange-600", bg: "bg-orange-100" },
    { title: "Obfuscation", icon: EyeOff, color: "text-slate-600", bg: "bg-slate-100" },
    { title: "Solidarity", icon: Users, color: "text-green-600", bg: "bg-green-100" },
    { title: "Refusal", icon: Zap, color: "text-red-600", bg: "bg-red-100" },
];
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from "@/components/ui/dialog";



export default function ResistancePage() {
    const { sources, addSource, updateSource, deleteSource, isLoading } = useSources();
    const { isReadOnly } = useDemoMode();
    const [selectedTraceId, setSelectedTraceId] = useServerStorage<string | null>("resistance_selected_trace_id", null);
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [selectedPolicyId, setSelectedPolicyId] = useState<string | null>(null);

    // Credit System
    const { hasCredits, refetch: refetchCredits, loading: creditsLoading } = useCredits();
    const [showTopUp, setShowTopUp] = useState(false);

    // Identify Policy Documents (Not traces)
    const policyDocuments = sources.filter(s => s.type !== "Trace");

    // Filter traces based on selection
    const traces = sources.filter(s =>
        ((s.type === 'Trace' && s.traceType === 'resistance') || (s.type === 'Text' && s.extractedText)) &&
        s.policyId === selectedPolicyId
    );

    const [isFetching, setIsFetching] = useState(false);

    const handleDeepFetch = async (trace: Source) => {
        if (!trace.sourceUrl) return;
        if (isReadOnly) {
            toast.error("Deep fetch disabled in Demo Mode");
            return;
        }

        setIsFetching(true);
        toast.info("Fetching full content...", { description: "Retrieving original article text." });

        try {
            const headers: HeadersInit = { 'Content-Type': 'application/json' };
            if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true' && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
            }

            const response = await fetch('/api/fetch-url', {
                method: 'POST',
                headers: headers,
                body: JSON.stringify({ url: trace.sourceUrl })
            });

            const result = await response.json();
            if (result.success && result.text) {
                // Update source with full text
                const updatedTrace = {
                    ...trace,
                    extractedText: result.text.substring(0, 15000), // Cap size
                    description: `[Full Text Fetched] ${trace.description}`
                };

                await updateSource(trace.id, {
                    extractedText: updatedTrace.extractedText,
                    description: updatedTrace.description
                });

                toast.success("Content Fetched!", { description: "Now re-analyzing with full context..." });

                // Re-Analyze automatically
                await handleAnalyzeTrace(updatedTrace);
            } else {
                toast.error("Fetch failed", { description: result.error || "Could not extract content." });
            }
        } catch (error) {
            console.error("Fetch error:", error);
            toast.error("Network error during fetch.");
        } finally {
            setIsFetching(false);
        }
    };

    // Existing handleAnalyzeTrace...
    const handleAnalyzeTrace = async (trace: Source) => {
        if (!trace.extractedText) return;
        if (isReadOnly) {
            toast.error("Analysis disabled in Demo Mode");
            return;
        }

        // Credit Check
        if (!creditsLoading && !hasCredits) {
            setShowTopUp(true);
            return;
        }

        setIsAnalyzing(true);
        try {
            const headers: HeadersInit = { 'Content-Type': 'application/json' };
            if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true' && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
            }

            const response = await fetch('/api/analyze', {
                method: 'POST',
                headers: headers,
                body: JSON.stringify({
                    text: trace.extractedText.substring(0, 3000),
                    sourceType: 'Empirical Trace',
                    analysisMode: 'resistance'
                })
            });

            const result = await response.json();
            if (result.success) {
                await updateSource(trace.id, { resistance_analysis: result.analysis });
                refetchCredits(); // Refresh credits after successful analysis
                toast.success("Trace analyzed successfully!");
            } else {
                if (response.status === 429 || result.error === "Quota Exceeded") {
                    toast.error("Quota Exceeded", {
                        description: "You have reached your lifetime API limit. Please contact admin.",
                        duration: 5000,
                    });
                } else {
                    toast.error("Analysis failed", { description: result.error });
                }
            }
        } catch (error) {
            console.error("Analysis failed", error);
            toast.error("Failed to analyze trace.");
        } finally {
            setIsAnalyzing(false);
        }
    };

    const selectedTrace = traces.find(t => t.id === selectedTraceId);
    const currentAnalysis = selectedTrace?.resistance_analysis;

    const [isSearching, setIsSearching] = useState(false);
    const [isSearchDialogOpen, setIsSearchDialogOpen] = useState(false);
    const [searchSource, setSearchSource] = useState<Source | null>(null);
    const [customQuery, setCustomQuery] = useServerStorage<string>("resistance_custom_query", "");
    const [selectedPlatforms, setSelectedPlatforms] = useServerStorage<string[]>("resistance_selected_platforms", ["reddit", "hackernews", "forums"]);
    const [dynamicLexicon, setDynamicLexicon] = useState<string>("");
    const [showFrictionLog, setShowFrictionLog] = useState(false);

    // Persistent Strategy Tracking
    const [monitoredVectors, setMonitoredVectors] = useServerStorage<string[]>("monitored_vectors", []);

    const handleToggleMonitor = (id: string) => {
        setMonitoredVectors(prev => {
            const current = prev || [];
            if (current.includes(id)) {
                return current.filter(v => v !== id);
            } else {
                return [...current, id];
            }
        });
    };

    const handleSearchTraces = async () => {
        if (isReadOnly) {
            toast.error("Search disabled in Demo Mode");
            return;
        }

        // Credit Check
        if (!creditsLoading && !hasCredits) {
            setShowTopUp(true);
            return;
        }
        if (!selectedPolicyId) {
            alert("Please select a policy document first.");
            return;
        }

        // Need either a policy source or custom query
        // If searching with a specific source context, valid. Or just custom query.
        // But we MUST link result to selectedPolicyId.

        // Find the full source object for the selected policy to use as context if needed
        const activePolicy = sources.find(s => s.id === selectedPolicyId);

        if (!activePolicy?.extractedText && !customQuery.trim()) {
            alert("No text in selected policy and no custom query provided.");
            return;
        }

        setIsSearching(true);
        try {
            const headers: HeadersInit = { 'Content-Type': 'application/json' };
            if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true' && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
            }

            const response = await fetch('/api/search-traces', {
                method: 'POST',
                headers: headers,
                body: JSON.stringify({
                    policyText: activePolicy?.extractedText?.substring(0, 3000),
                    policyTitle: activePolicy?.title,
                    customQuery: customQuery.trim() || undefined,
                    dynamicLexicon: dynamicLexicon.trim() || undefined,
                    platforms: selectedPlatforms
                })
            });

            const result = await response.json();


            if (result.success && Array.isArray(result.traces)) {
                const newTraces = result.traces.map((trace: { title: string; description: string; query: string; content: string; sourceUrl: string; strategy?: string; explanation?: string }) => ({
                    id: Math.random().toString(36).substr(2, 9),
                    title: `[Web] ${trace.title}`,
                    description: `${trace.description} • Query: "${trace.query}"`,
                    type: "Trace",
                    traceType: "resistance" as const, // Explicitly mark as resistance reaction
                    extractedText: `${trace.content}\n\nSource: ${trace.sourceUrl}`,
                    sourceUrl: trace.sourceUrl, // Persist the URL!
                    addedDate: new Date().toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" }),
                    status: "Active Case",
                    colorClass: "bg-blue-100",
                    iconClass: "text-blue-600",
                    policyId: selectedPolicyId, // Link to selected policy
                    resistance_analysis: trace.strategy ? {
                        strategy_detected: trace.strategy,
                        evidence_quote: trace.content,
                        interpretation: trace.explanation || "⚠️ NO INTERPRETATION RECEIVED",
                        confidence: "Medium"
                    } : undefined
                }));

                // Add each new trace to the store
                for (const trace of newTraces) {
                    const addedSource = await addSource(trace);

                    // Auto-Analyze "Weak" classifications to get specific strategy
                    const weakStrategies = ["Potential Resistance", "Friction", "Unclassified"];
                    if (!trace.resistance_analysis?.strategy_detected || weakStrategies.includes(trace.resistance_analysis.strategy_detected)) {
                        handleAnalyzeTrace(addedSource);
                    }
                }

                toast.success(`Found ${newTraces.length} resistance traces from the web for ${activePolicy?.title}!`);
                setCustomQuery(""); // Reset query
            } else {
                if (response.status === 429 || result.error === "Quota Exceeded") {
                    toast.error("Quota Exceeded", {
                        description: "You have reached your lifetime API limit. Please contact admin.",
                        duration: 5000,
                    });
                } else {
                    toast.error("Search failed", { description: result.error || "Unknown error" });
                }
            }
        } catch (error) {
            console.error("Search error:", error);
            toast.error("Failed to search for traces", { description: "Make sure your Google Search API is configured." });
        } finally {
            setIsSearching(false);
            setIsSearchDialogOpen(false);
        }
    };

    const handleDeleteTrace = async (traceId: string) => {
        if (isReadOnly) {
            toast.error("Deletion disabled in Demo Mode");
            return;
        }
        if (confirm(`Are you sure you want to delete this trace?`)) {
            await deleteSource(traceId);
            if (selectedTraceId === traceId) {
                setSelectedTraceId(null);
            }
        }
    };

    const handleResetTraces = async () => {
        if (!selectedPolicyId) return;
        if (isReadOnly) {
            toast.error("Reset disabled in Demo Mode");
            return;
        }

        if (confirm("Are you sure? This will DELETE ALL traces for this policy and CLEAR the search cache. This action cannot be undone.")) {
            // 1. Delete all traces for this policy
            const policyTraces = sources.filter(s => s.type === 'Trace' && s.policyId === selectedPolicyId);
            let deletedCount = 0;

            for (const trace of policyTraces) {
                await deleteSource(trace.id);
                deletedCount++;
            }

            // 2. Clear Server Cache
            try {
                const headers: HeadersInit = { 'Content-Type': 'application/json' };
                if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true' && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                    headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
                }

                // We need to re-construct the same context to generate the key
                const activePolicy = sources.find(s => s.id === selectedPolicyId);
                const response = await fetch('/api/search-traces', {
                    method: 'DELETE',
                    headers: headers,
                    body: JSON.stringify({
                        policyText: activePolicy?.extractedText?.substring(0, 3000),
                        // customQuery: customQuery.trim() || undefined, // We might not know the exact query used, but usually cache is cleared by just clearing the "latest" one or all if possible.
                        // Actually, the API requires the exact params to generate the key.
                        // If the user changed the query, we can't clear the old one easily. 
                        // But usually users want to clear the *current* view.
                        customQuery: customQuery.trim() || undefined,
                        platforms: selectedPlatforms
                    })
                });

                if (response.ok) {
                    toast.success(`Reset Complete`, { description: `Deleted ${deletedCount} traces and cleared cache.` });
                } else {
                    toast.warning(`Traces deleted, but cache clear failed.`);
                }
            } catch (error) {
                console.error("Reset error:", error);
                toast.error("Network error during reset.");
            }

            setSelectedTraceId(null);
            setSynthesisResult(null);
        }
    };

    const [isSynthesizing, setIsSynthesizing] = useState(false);
    const [synthesisResult, setSynthesisResult] = useServerStorage<ResistanceSynthesisResult | null>(
        selectedPolicyId ? `resistance_synthesis_result_${selectedPolicyId}` : "resistance_synthesis_result_draft",
        null
    );

    const handleSynthesizeFindings = async () => {
        if (isReadOnly) {
            toast.error("Synthesis disabled in Demo Mode");
            return;
        }

        // Credit Check
        if (!creditsLoading && !hasCredits) {
            setShowTopUp(true);
            return;
        }
        const analyzedTraces = traces.filter(t => t.resistance_analysis);
        if (analyzedTraces.length < 2) {
            toast.error("Not enough data", { description: "Please analyze at least 2 traces before synthesizing." });
            return;
        }

        // Check if we already have results and ask for confirmation
        if (synthesisResult) {
            if (!confirm("Existing synthesis found. Do you want to re-run it? This will overwrite the current findings.")) {
                return;
            }
        }

        setIsSynthesizing(true);
        try {
            const headers: HeadersInit = { 'Content-Type': 'application/json' };
            if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true' && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
            }

            const response = await fetch('/api/analyze', {
                method: 'POST',
                headers: headers,
                body: JSON.stringify({
                    analysisMode: 'resistance_synthesis',
                    documents: analyzedTraces.map(t => ({
                        title: t.title,
                        content: t.extractedText,
                        analysis: t.resistance_analysis
                    })),
                    force: !!synthesisResult // Force refresh if we are overwriting existing results
                })
            });

            const result = await response.json();
            if (result.success) {
                setSynthesisResult(result.analysis);
                refetchCredits();
                toast.success("Synthesis complete!");
            } else {
                toast.error("Synthesis failed", { description: result.details || result.error || "Unknown error" });
            }
        } catch (error) {
            console.error("Synthesis error:", error);
            toast.error("Failed to synthesize findings.");
        } finally {
            setIsSynthesizing(false);
        }
    };

    if (isLoading) {
        return (
            <div className="flex items-center justify-center h-64">
                <Loader2 className="h-8 w-8 animate-spin text-slate-400" />
            </div>
        );
    }

    return (
        <div className="space-y-8 animate-in fade-in duration-500">
            <CreditTopUpDialog
                open={showTopUp}
                onOpenChange={setShowTopUp}
                onSuccess={() => refetchCredits()}
            />
            <div className="flex flex-col gap-6">
                <div>
                    <h2 className="text-3xl font-bold tracking-tight text-slate-900">Micro-Resistance: Empirical Traces</h2>
                    <p className="text-slate-500">Analyze empirical traces linked to specific policy documents.</p>
                </div>

                {/* Policy Selector Section */}
                <div className="p-6 bg-white rounded-xl border border-slate-200 shadow-sm">
                    <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
                        <div className="flex items-center gap-4 w-full md:w-auto">
                            <div className="p-3 bg-purple-50 rounded-lg">
                                <FileText className="h-6 w-6 text-purple-600" />
                            </div>
                            <div>
                                <h3 className="font-semibold text-slate-900">Active Policy Document</h3>
                                <p className="text-sm text-slate-500">Select a document to view resistance analysis</p>
                            </div>
                        </div>
                        <div className="w-full md:w-[300px]">
                            <Select
                                value={selectedPolicyId || ""}
                                onValueChange={(val) => setSelectedPolicyId(val)}
                            >
                                <SelectTrigger>
                                    <SelectValue placeholder="Select a policy document..." />
                                </SelectTrigger>
                                <SelectContent>
                                    {policyDocuments.length === 0 ? (
                                        <div className="p-2 text-sm text-slate-500 text-center">No documents found</div>
                                    ) : (
                                        policyDocuments.map(doc => (
                                            <SelectItem key={doc.id} value={doc.id}>
                                                {doc.title}
                                            </SelectItem>
                                        ))
                                    )}
                                </SelectContent>
                            </Select>
                        </div>
                    </div>
                </div>

                {selectedPolicyId ? (
                    <>
                        <div className="flex items-center justify-end gap-2">
                            <Button
                                variant="outline"
                                onClick={handleSynthesizeFindings}
                                disabled={isSynthesizing || traces.filter(t => t.resistance_analysis).length < 2 || isReadOnly}
                                className="border-purple-200 hover:bg-purple-50 text-purple-700"
                            >
                                {isSynthesizing ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Activity className="mr-2 h-4 w-4" />}
                                Synthesize Findings
                            </Button>
                            <Button
                                variant="outline"
                                onClick={handleResetTraces}
                                disabled={isReadOnly}
                                className="border-red-200 text-red-600 hover:bg-red-50 hover:border-red-300 mr-2"
                            >
                                <Trash className="mr-2 h-4 w-4" />
                                Reset & Clear
                            </Button>
                            <Button
                                variant={showFrictionLog ? "secondary" : "outline"}
                                onClick={() => setShowFrictionLog(!showFrictionLog)}
                                className={`mr-2 ${showFrictionLog ? "bg-orange-100 text-orange-800 border-orange-200" : "text-slate-600"}`}
                            >
                                <Activity className="mr-2 h-4 w-4" />
                                {showFrictionLog ? "View Cards" : "Friction Log"}
                            </Button>
                            <Dialog open={isSearchDialogOpen} onOpenChange={setIsSearchDialogOpen}>
                                <DialogTrigger asChild>
                                    <Button className="bg-blue-600 text-white hover:bg-blue-700">
                                        <Search className="mr-2 h-4 w-4" /> Search for Traces
                                    </Button>
                                </DialogTrigger>
                                <DialogContent className="sm:max-w-[600px]">
                                    <DialogHeader>
                                        <DialogTitle>Search Web for Resistance Traces</DialogTitle>
                                        <DialogDescription>
                                            Find real forum posts, Reddit threads, and discussions about resistance to {sources.find(s => s.id === selectedPolicyId)?.title}.
                                        </DialogDescription>
                                    </DialogHeader>
                                    <div className="space-y-4 py-4">
                                        <div>
                                            <label className="text-sm font-medium text-slate-700 mb-2 block">
                                                Custom Query (Optional)
                                            </label>
                                            <input
                                                type="text"
                                                className="w-full p-2 border rounded-md text-sm"
                                                placeholder="e.g. 'workarounds'"
                                                value={customQuery}
                                                onChange={(e) => setCustomQuery(e.target.value)}
                                            />
                                        </div>
                                        <div>
                                            <label className="text-sm font-medium text-slate-700 mb-2 block">
                                                Dynamic Lexicon (Slang/Jargon)
                                            </label>
                                            <input
                                                type="text"
                                                className="w-full p-2 border rounded-md text-sm"
                                                placeholder="e.g. 'quiet quitting', 'algo-speak'"
                                                value={dynamicLexicon}
                                                onChange={(e) => setDynamicLexicon(e.target.value)}
                                            />
                                            <p className="text-xs text-slate-500 mt-1">Inject community-specific terms to aid detection.</p>
                                        </div>

                                        <div className="grid grid-cols-2 gap-2 mt-4">
                                            {[
                                                { id: 'reddit', label: 'Reddit' },
                                                { id: 'hackernews', label: 'Hacker News' },
                                                { id: 'forums', label: 'Forums' },
                                                { id: 'twitter', label: 'Twitter/X' },
                                                { id: 'technews', label: 'Tech News' },
                                                { id: 'mastodon', label: 'Mastodon' }
                                            ].map(platform => (
                                                <label key={platform.id} className="flex items-center gap-2 cursor-pointer">
                                                    <input
                                                        type="checkbox"
                                                        checked={selectedPlatforms.includes(platform.id)}
                                                        onChange={(e) => {
                                                            if (e.target.checked) {
                                                                setSelectedPlatforms([...selectedPlatforms, platform.id]);
                                                            } else {
                                                                setSelectedPlatforms(selectedPlatforms.filter(p => p !== platform.id));
                                                            }
                                                        }}
                                                        className="rounded"
                                                    />
                                                    <span className="text-sm">{platform.label}</span>
                                                </label>
                                            ))}
                                        </div>
                                    </div>

                                    <DialogFooter>
                                        <Button
                                            onClick={handleSearchTraces}
                                            disabled={isSearching || isReadOnly}
                                            className="bg-blue-600 hover:bg-blue-700"
                                        >
                                            {isSearching ? (
                                                <>
                                                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                                    Searching Web...
                                                </>
                                            ) : (
                                                <>
                                                    <Search className="mr-2 h-4 w-4" />
                                                    Search
                                                </>
                                            )}
                                        </Button>
                                    </DialogFooter>
                                </DialogContent>
                            </Dialog>
                        </div>

                        {synthesisResult && (
                            <Card className="bg-purple-50 border-purple-200">
                                <CardHeader>
                                    <CardTitle className="text-purple-900 flex items-center justify-between">
                                        <div className="flex items-center">
                                            <Activity className="mr-2 h-5 w-5" /> Assemblage Analysis & Lines of Flight
                                        </div>
                                    </CardTitle>
                                </CardHeader>
                                <CardContent className="space-y-6">
                                    {/* Executive Summary */}
                                    <div>
                                        <h4 className="font-semibold text-purple-900 mb-1">Executive Summary</h4>
                                        <p className="text-purple-800 text-sm leading-relaxed">{synthesisResult.executive_summary}</p>
                                    </div>

                                    {/* Lines of Flight Dashboard */}
                                    <div className="bg-white p-4 rounded-lg border border-purple-100 shadow-sm">
                                        <h4 className="font-bold text-slate-900 mb-3 flex items-center">
                                            <Zap className="h-4 w-4 mr-2 text-orange-500" /> Lines of Flight Assessment
                                        </h4>

                                        <div className="mb-4">
                                            <div className="bg-slate-50 p-4 rounded-lg border border-slate-200">
                                                <p className="text-slate-700 leading-relaxed italic">
                                                    &quot;{synthesisResult.lines_of_flight?.narrative_aggregate || "No flight analysis available."}&quot;
                                                </p>
                                            </div>

                                            {/* Visualization Component */}
                                            <ResistanceVisualization
                                                result={synthesisResult}
                                                monitoredVectors={monitoredVectors}
                                                onToggleMonitor={handleToggleMonitor}
                                            />                          </div>

                                    </div>

                                    {/* Reflexive Audit */}
                                    <div className="bg-blue-50 p-4 rounded-lg border border-blue-100 text-sm">
                                        <h4 className="font-semibold text-blue-900 mb-2 flex items-center">
                                            <EyeOff className="h-4 w-4 mr-2" /> Reflexive Audit Trail
                                        </h4>
                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                            <div>
                                                <span className="font-medium text-blue-800">Analyst Positionality:</span>
                                                <p className="text-blue-700 mt-1">{synthesisResult.reflexive_audit?.analyst_positionality}</p>
                                            </div>
                                            <div>
                                                <span className="font-medium text-blue-800">Uncertainty Flags:</span>
                                                <p className="text-blue-700 mt-1">{synthesisResult.reflexive_audit?.uncertainty_flags}</p>
                                            </div>
                                        </div>
                                    </div>

                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                        {/* Dominant Strategies Section Removed (Now in Visualization) */}
                                        <div>
                                            <h4 className="font-semibold text-purple-900 mb-2">Implications for Legitimacy</h4>
                                            <p className="p-3 bg-white rounded border border-purple-100 text-sm text-purple-800">
                                                {synthesisResult.implications_for_legitimacy}
                                            </p>
                                        </div>
                                    </div>
                                </CardContent>
                            </Card>
                        )}

                        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                            {/* Left Column: Trace Selector or Friction Log */}
                            <div className={showFrictionLog ? "lg:col-span-3" : "space-y-4"}>
                                <div className="flex items-center justify-between mb-4">
                                    <h3 className="font-semibold text-slate-900 flex items-center">
                                        <Activity className="mr-2 h-4 w-4" /> {showFrictionLog ? "Friction Log (Raw Signals)" : "Available Traces"}
                                    </h3>
                                    {showFrictionLog && (
                                        <Badge variant="outline" className="bg-orange-50 text-orange-700 border-orange-200">
                                            Shadow Resistance Mode
                                        </Badge>
                                    )}
                                </div>

                                <div className={showFrictionLog ? "grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4" : "space-y-2"}>
                                    {traces.length === 0 && (
                                        <Card className="bg-slate-50 border-dashed col-span-full">
                                            <CardContent className="p-4 text-center text-sm text-slate-500">
                                                No traces found. Use &quot;Search for Traces&quot; to filter public comments and discussions for this policy.
                                            </CardContent>
                                        </Card>
                                    )}
                                    {traces.map(trace => (
                                        <Card
                                            key={trace.id}
                                            className={`transition-all hover:border-purple-400 ${selectedTraceId === trace.id ? 'border-purple-600 ring-1 ring-purple-600' : ''} ${showFrictionLog ? 'bg-orange-50/30' : ''}`}
                                        >
                                            <CardContent className="p-4">
                                                <div className="flex items-start justify-between gap-2">
                                                    <div
                                                        className="flex-1 min-w-0 pr-2 cursor-pointer"
                                                        onClick={() => setSelectedTraceId(trace.id)}
                                                    >
                                                        <div className="font-medium text-slate-900 break-words">{trace.title}</div>
                                                        <div className={`text-xs text-slate-500 mt-1 break-words ${showFrictionLog ? 'line-clamp-4' : ''}`}>
                                                            {trace.description}
                                                            {trace.sourceUrl && (
                                                                <span className="block mt-1 text-blue-400 truncate hover:underline">
                                                                    {new URL(trace.sourceUrl).hostname.replace('www.', '')}
                                                                </span>
                                                            )}
                                                        </div>

                                                        {showFrictionLog && trace.resistance_analysis?.evidence_quote && (
                                                            <div className="mt-2 text-xs italic text-slate-600 bg-white p-2 rounded border border-slate-100">
                                                                "{trace.resistance_analysis.evidence_quote.substring(0, 100)}..."
                                                            </div>
                                                        )}

                                                        {trace.resistance_analysis?.strategy_detected ? (() => {
                                                            const strategy = STRATEGY_DEFINITIONS.find(s => s.title === trace.resistance_analysis?.strategy_detected);
                                                            const badgeClass = strategy
                                                                ? `mt-2 ${strategy.bg} ${strategy.color} border-${strategy.color.split('-')[1]}-200`
                                                                : "mt-2 bg-purple-100 text-purple-700 border-purple-200";

                                                            return (
                                                                <Badge variant="secondary" className={badgeClass}>
                                                                    {strategy?.icon && <strategy.icon className="w-3 h-3 mr-1 inline" />}
                                                                    {trace.resistance_analysis.strategy_detected}
                                                                </Badge>
                                                            );
                                                        })() : trace.resistance_analysis && (
                                                            <Badge variant="secondary" className="mt-2 bg-green-100 text-green-700">
                                                                Analyzed
                                                            </Badge>
                                                        )}
                                                    </div>
                                                    <div className="flex flex-col gap-1 items-center shrink-0">
                                                        <Button
                                                            variant="ghost"
                                                            size="sm"
                                                            className="h-8 w-8 p-0 text-slate-400 hover:text-blue-600 hover:bg-blue-50"
                                                            onClick={(e) => {
                                                                e.stopPropagation();
                                                                let url = trace.sourceUrl;
                                                                // Fallback: Try to extract from text if missing (legacy fix)
                                                                if (!url && trace.extractedText) {
                                                                    const match = trace.extractedText.match(/Source: (https?:\/\/[^\s]+)/);
                                                                    if (match) url = match[1];
                                                                }

                                                                if (url) {
                                                                    window.open(url, '_blank');
                                                                } else {
                                                                    toast.error("No source URL available", { description: "The URL was not saved with this trace." });
                                                                }
                                                            }}
                                                            title={trace.sourceUrl || "View Source"}
                                                        >
                                                            <ExternalLink className="h-4 w-4" />
                                                        </Button>
                                                        <Button
                                                            variant="ghost"
                                                            size="sm"
                                                            className="h-8 w-8 p-0 text-slate-400 hover:bg-red-100 hover:text-red-600"
                                                            onClick={(e) => {
                                                                e.stopPropagation();
                                                                handleDeleteTrace(trace.id);
                                                            }}
                                                            title="Delete Trace"
                                                            disabled={isReadOnly}
                                                        >
                                                            <Trash className="h-4 w-4" />
                                                        </Button>
                                                    </div>
                                                </div>
                                            </CardContent>
                                        </Card>
                                    ))}
                                </div>
                            </div>

                            {/* Middle Column: Analysis Area - HIDE if Friction Log is ON */}
                            {!showFrictionLog && (
                                <div className="lg:col-span-2 space-y-6">
                                    {selectedTrace ? (
                                        <div className="space-y-6">
                                            <Card>
                                                <CardHeader>
                                                    <CardTitle className="flex justify-between items-center">
                                                        <span>Analysis: {selectedTrace.title}</span>
                                                        {!currentAnalysis && (
                                                            <Button
                                                                onClick={() => handleAnalyzeTrace(selectedTrace)}
                                                                disabled={isAnalyzing || isReadOnly}
                                                                className="bg-purple-600 hover:bg-purple-700"
                                                            >
                                                                {isAnalyzing ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Play className="mr-2 h-4 w-4" />}
                                                                Analyze Trace
                                                            </Button>
                                                        )}
                                                        {selectedTrace.sourceUrl && !selectedTrace.description.includes("[Full Text Fetched]") && (
                                                            <Button
                                                                variant="outline"
                                                                onClick={() => handleDeepFetch(selectedTrace)}
                                                                disabled={isFetching || isAnalyzing || isReadOnly}
                                                                className="ml-2 border-blue-200 text-blue-700 hover:bg-blue-50"
                                                            >
                                                                {isFetching ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <FileText className="mr-2 h-4 w-4" />}
                                                                Deep Fetch
                                                            </Button>
                                                        )}
                                                    </CardTitle>
                                                </CardHeader>
                                                <CardContent>
                                                    {currentAnalysis ? (
                                                        <div className="space-y-6">
                                                            <div className="flex items-center space-x-4">
                                                                <div className="p-3 bg-purple-100 rounded-full">
                                                                    <Zap className="h-6 w-6 text-purple-600" />
                                                                </div>
                                                                <div>
                                                                    <div className="text-sm text-slate-500 uppercase tracking-wider font-bold">Strategy Detected</div>
                                                                    <div className="text-2xl font-bold text-slate-900">{currentAnalysis.strategy_detected}</div>
                                                                </div>
                                                                <Badge className={currentAnalysis.confidence === 'High' ? 'bg-green-100 text-green-800' : 'bg-yellow-100 text-yellow-800'}>
                                                                    {currentAnalysis.confidence} Confidence
                                                                </Badge>
                                                            </div>

                                                            <div className="bg-slate-50 p-4 rounded-lg border border-slate-200 relative">
                                                                <Quote className="absolute top-2 left-2 h-8 w-8 text-slate-200 -z-0" />
                                                                <p className="text-slate-700 italic relative z-10 pl-6">
                                                                    &quot;{currentAnalysis.evidence_quote}&quot;
                                                                </p>
                                                            </div>

                                                            <div>
                                                                <h4 className="font-semibold text-slate-900 mb-2">Interpretation</h4>
                                                                <p className="text-slate-600 leading-relaxed">
                                                                    {currentAnalysis.interpretation}
                                                                </p>
                                                            </div>
                                                        </div>
                                                    ) : (
                                                        <div className="text-center py-12 text-slate-500">
                                                            <p>Select &quot;Analyze Trace&quot; to identify resistance strategies using the LLM.</p>
                                                        </div>
                                                    )}
                                                </CardContent>
                                            </Card>

                                            {/* Reference Definitions */}
                                            <div className="grid grid-cols-2 gap-4">
                                                {STRATEGY_DEFINITIONS.map(def => (
                                                    <div key={def.title} className="flex items-center space-x-3 p-3 bg-white rounded-lg border border-slate-100 shadow-sm">
                                                        <div className={`p-2 rounded-full ${def.bg}`}>
                                                            <def.icon className={`h-4 w-4 ${def.color}`} />
                                                        </div>
                                                        <span className="font-medium text-slate-700">{def.title}</span>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    ) : (
                                        <div className="flex flex-col items-center justify-center h-64 bg-slate-50 rounded-lg border-2 border-dashed border-slate-200">
                                            <Activity className="h-10 w-10 text-slate-300 mb-4" />
                                            <p className="text-slate-500">Select a trace from the left to begin analysis</p>
                                        </div>
                                    )}
                                </div>
                            )}
                        </div>
                    </>
                ) : (
                    <div className="bg-slate-50 rounded-xl border border-dashed border-slate-200 p-12 text-center">
                        <div className="mx-auto w-16 h-16 bg-white rounded-full flex items-center justify-center shadow-sm mb-4">
                            <FileText className="h-8 w-8 text-slate-300" />
                        </div>
                        <h3 className="text-lg font-bold text-slate-700">No Policy Selected</h3>
                        <p className="text-slate-500 mt-2">Please select a policy document above to view and manage its resistance traces.</p>
                    </div>
                )}
            </div>
        </div >
    );
}

"use client";

import React, { useState } from 'react';
import { useServerStorage } from "@/hooks/useServerStorage";
// import { CulturalHolesAnalysisResult } from "@/types/ecosystem";
// import { CulturalHolesAnalysis } from "@/components/ecosystem/CulturalHolesAnalysis";
import { Button } from "@/components/ui/button";
import { Sparkles, ArrowRight, RotateCcw } from "lucide-react";
import { AVAILABLE_PERSPECTIVES, DEFAULT_PERSPECTIVE_A, DEFAULT_PERSPECTIVE_B } from "@/lib/perspectives";

export default function ResultsPage() {
    // const [analysisResult, setAnalysisResult] = useState<CulturalHolesAnalysisResult | null>(null);
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [hasRun, setHasRun] = useState(false);

    // State for the "Manuscript" text - editable by the user
    const [paragraph1, setParagraph1] = useState("");
    const [paragraph2, setParagraph2] = useState("");
    const [isSimulating, setIsSimulating] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [perspA, setPerspA] = useState(DEFAULT_PERSPECTIVE_A.id);
    const [perspB, setPerspB] = useState(DEFAULT_PERSPECTIVE_B.id);

    const handleSimulate = async () => {
        setIsSimulating(true);
        setError(null);
        try {
            const headers: Record<string, string> = { 'Content-Type': 'application/json' };
            const demoUserId = process.env.NEXT_PUBLIC_DEMO_USER_ID;
            if (demoUserId) {
                headers['x-demo-user-id'] = demoUserId;
            }

            const response = await fetch('/api/simulate-perspectives', {
                method: 'POST',
                headers,
                body: JSON.stringify({
                    topic: "AI Safety Regulation",
                    perspectiveAId: perspA,
                    perspectiveBId: perspB
                })
            });
            const data = await response.json();
            if (data.success && data.perspectives) {
                setParagraph1(data.perspectives.perspectiveA);
                setParagraph2(data.perspectives.perspectiveB);
            } else {
                throw new Error(data.error || "Simulation failed");
            }
        } catch (error: any) {
            console.error("Simulation failed:", error);
            setError(error.message || "Failed to generate perspectives");
        } finally {
            setIsSimulating(false);
        }
    };

    const handleAnalyze = async (forceRefresh = false) => {
        setIsAnalyzing(true);
        setError(null);
        try {
            if (!paragraph1.trim() || !paragraph2.trim()) {
                throw new Error("Both perspectives must have text content.");
            }

            // we treat the two paragraphs as distinct "sources" to find the hole between them
            const sources = [
                {
                    id: "para-1-side-a",
                    title: "Perspective A",
                    text: paragraph1
                },
                {
                    id: "para-2-side-b",
                    title: "Perspective B",
                    text: paragraph2
                }
            ];

            const headers: Record<string, string> = { 'Content-Type': 'application/json' };
            const demoUserId = process.env.NEXT_PUBLIC_DEMO_USER_ID;
            if (demoUserId) {
                headers['x-demo-user-id'] = demoUserId;
            }

            const response = await fetch('/api/cultural-analysis', {
                method: 'POST',
                headers,
                body: JSON.stringify({
                    sources,
                    lensId: 'dsf_lens',
                    forceRefresh
                })
            });

            if (!response.ok) {
                const errorData = await response.json();
                throw new Error(errorData.error || `Analysis failed with status ${response.status}`);
            }

            const data = await response.json();
            if (data.success && data.analysis) {
                // setAnalysisResult(data.analysis);
                setHasRun(true);
            } else {
                throw new Error(data.error || "Analysis returned no data");
            }
        } catch (error: any) {
            console.error("Analysis failed:", error);
            setError(error.message || "An unexpected error occurred during analysis");
        } finally {
            setIsAnalyzing(false);
        }
    };

    return (
        <div className="max-w-4xl mx-auto py-12 px-6 font-serif">
            {error && (
                <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded mb-6 font-sans text-sm">
                    <strong>Error:</strong> {error}
                </div>
            )}
            <header className="mb-12 border-b pb-6">
                <div className="text-sm font-sans font-bold text-slate-500 uppercase tracking-widest mb-2">
                    Journal of Sociomaterial Governance • Vol. 12 • 2025
                </div>
                <h1 className="text-4xl font-bold text-slate-900 mb-4 font-sans">
                    Entangled Agencies: A Comparative Assemblage Analysis
                </h1>
                <div className="flex items-center gap-4 text-sm text-slate-600 font-sans">
                    <span>A. Nonymous</span>
                    <span>•</span>
                    <span>Methods: Algorithmic Ethnography</span>
                </div>
            </header>

            <article className="prose prose-lg prose-slate max-w-none">
                <h2 className="font-sans m-0 mb-4">3. Results: Analysis of Discursive Fractures</h2>
                <div className="flex flex-col gap-4 mb-8 bg-slate-50 p-4 rounded border border-slate-200">
                    <div className="flex items-center justify-between">
                        <h3 className="text-sm font-bold text-slate-700">Simulation Configuration</h3>
                        <Button
                            variant="default"
                            size="sm"
                            onClick={handleSimulate}
                            disabled={isSimulating}
                            className="text-xs"
                        >
                            {isSimulating ? "Generating..." : "Auto-Generate Perspectives"}
                            <Sparkles className="ml-1 h-3 w-3" />
                        </Button>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label className="text-xs font-semibold text-slate-500 mb-1 block">Perspective A</label>
                            <select
                                value={perspA}
                                onChange={(e) => setPerspA(e.target.value)}
                                className="w-full text-sm p-2 rounded border border-slate-300 bg-white"
                            >
                                {AVAILABLE_PERSPECTIVES.map(p => (
                                    <option key={p.id} value={p.id}>{p.name}</option>
                                ))}
                            </select>
                            <p className="text-[10px] text-slate-400 mt-1">
                                {AVAILABLE_PERSPECTIVES.find(p => p.id === perspA)?.description}
                            </p>
                        </div>
                        <div>
                            <label className="text-xs font-semibold text-slate-500 mb-1 block">Perspective B</label>
                            <select
                                value={perspB}
                                onChange={(e) => setPerspB(e.target.value)}
                                className="w-full text-sm p-2 rounded border border-slate-300 bg-white"
                            >
                                {AVAILABLE_PERSPECTIVES.map(p => (
                                    <option key={p.id} value={p.id}>{p.name}</option>
                                ))}
                            </select>
                            <p className="text-[10px] text-slate-400 mt-1">
                                {AVAILABLE_PERSPECTIVES.find(p => p.id === perspB)?.description}
                            </p>
                        </div>
                    </div>
                </div>

                <div className="relative group">
                    <div className="absolute -left-4 top-2 bottom-2 w-1 bg-indigo-200 opacity-0 group-hover:opacity-100 transition-opacity"></div>
                    <textarea
                        value={paragraph1}
                        onChange={(e) => setParagraph1(e.target.value)}
                        className="w-full bg-transparent border-none p-0 text-lg leading-relaxed text-slate-800 resize-none outline-none focus:ring-0 font-serif"
                        rows={6}
                        placeholder="[Perspective A text will appear here...]"
                    />
                </div>

                <div className="relative group mt-6">
                    <div className="absolute -left-4 top-2 bottom-2 w-1 bg-amber-200 opacity-0 group-hover:opacity-100 transition-opacity"></div>
                    <textarea
                        value={paragraph2}
                        onChange={(e) => setParagraph2(e.target.value)}
                        className="w-full bg-transparent border-none p-0 text-lg leading-relaxed text-slate-800 resize-none outline-none focus:ring-0 font-serif"
                        rows={6}
                        placeholder="[Perspective B text will appear here...]"
                    />
                </div>

                {/* THE ENTANGLED TOOL */}
                <div className="my-12 -mx-6 p-6 bg-slate-50 border-y border-slate-200 shadow-inner font-sans not-prose">
                    <div className="flex items-center justify-between mb-6">
                        <div>
                            <h3 className="text-lg font-bold text-indigo-900 flex items-center gap-2">
                                <Sparkles className="h-5 w-5 text-indigo-600" />
                                Interactive Instrument: Cultural Hole Detector
                            </h3>
                            <p className="text-sm text-slate-600 max-w-xl">
                                To operationalize the sociomaterial method, we embed the analytic instrument directly into the text.
                                Click below to perform a live structural hole analysis on the entered paragraphs.
                            </p>
                        </div>
                        {!hasRun && (
                            <Button
                                onClick={() => handleAnalyze(false)}
                                size="lg"
                                disabled={isAnalyzing || !paragraph1 || !paragraph2}
                                className="bg-indigo-600 hover:bg-indigo-700 text-white shadow-md transform transition-all hover:scale-105 disabled:opacity-50 disabled:cursor-not-allowed"
                            >
                                {isAnalyzing ? "Analyzing Text..." : "Run Detector"}
                                {!isAnalyzing && <ArrowRight className="ml-2 h-4 w-4" />}
                            </Button>
                        )}
                        {hasRun && (
                            <div className="flex gap-2">
                                <Button
                                    onClick={() => handleAnalyze(false)}
                                    variant="outline"
                                    size="sm"
                                    disabled={isAnalyzing}
                                >
                                    Rerun
                                </Button>
                                <Button
                                    onClick={() => handleAnalyze(true)}
                                    variant="destructive"
                                    size="sm"
                                    disabled={isAnalyzing}
                                    title="Force fresh analysis (ignores cache)"
                                >
                                    <RotateCcw className="mr-2 h-3 w-3" />
                                    Force Refresh
                                </Button>
                            </div>
                        )}
                    </div>

                    {/* Rendering the Analysis Component Inline */}
                    {/* {(hasRun || isAnalyzing) && (
                        <div className="animate-in fade-in slide-in-from-bottom-4 duration-700">
                            <CulturalHolesAnalysis
                                culturalHoles={analysisResult}
                                isAnalyzingHoles={isAnalyzing}
                                onAnalyze={handleAnalyze}
                            />
                            <div className="mt-4 text-xs text-center text-slate-400 font-mono">
                                Fig 3.1: Live generation of structural holes between the provided textual artifacts.
                            </div>
                        </div>
                    )} */}
                    <div className="p-8 text-center text-slate-500 border border-dashed border-slate-300 rounded-lg">
                        <p className="text-sm">Cultural Holes Analysis component temporarily disabled.</p>
                    </div>
                </div>
            </article>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Loader2, CreditCard, Coins, Check, History, LogIn } from "lucide-react";
import { useAuth, useClerk } from "@clerk/nextjs";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { DeleteAccountSection } from "@/components/settings/DeleteAccountSection";
import { DataExportSection } from "@/components/settings/DataExportSection";
import { TransactionHistory, Transaction } from "@/components/TransactionHistory";
import { CREDIT_PACKAGES } from "@/config/pricing";
import { cn } from "@/lib/utils";

export default function BillingPage() {
    const { userId, isLoaded, isSignedIn } = useAuth();
    const router = useRouter();
    const [credits, setCredits] = useState<number | null>(null);
    const [loading, setLoading] = useState(false);
    const [isLoadingCredits, setIsLoadingCredits] = useState(true);
    const [history, setHistory] = useState<Transaction[]>([]);

    const fetchCredits = async () => {
        try {
            const res = await fetch('/api/credits');
            const data = await res.json();
            setCredits(data.credits);
            if (data.history) setHistory(data.history);
        } catch (error) {
            console.error("Failed to fetch credits", error);
        } finally {
            setIsLoadingCredits(false);
        }
    };

    useEffect(() => {
        // Initial fetch
        fetchCredits();

        const query = new URLSearchParams(window.location.search);

        if (query.get('success')) {
            toastSuccess();
            // Poll for updates (Stripe webhooks can take a few seconds)
            const MAX_RETRIES = 10;
            let attempts = 0;

            const pollInterval = setInterval(async () => {
                attempts++;
                try {
                    const res = await fetch('/api/credits');
                    const data = await res.json();

                    // If credits increased (or just to be safe, update state)
                    if (data.credits !== null) {
                        setCredits(current => {
                            // If we have a new value that is different, we might stop polling? 
                            // Actually difficult to know "previous" state here without ref.
                            // But simply refreshing the UI 10 times over 20 seconds is fine.
                            return data.credits;
                        });
                        setHistory(data.history || []);
                    }
                } catch (e) {
                    console.error("Polling error", e);
                }

                if (attempts >= MAX_RETRIES) {
                    clearInterval(pollInterval);
                }
            }, 2000); // Check every 2 seconds

            // Clean URL
            window.history.replaceState({}, '', '/settings/billing');
        }

        if (query.get('canceled')) {
            alert("Payment canceled.");
            window.history.replaceState({}, '', '/settings/billing');
        }

        return () => {
            // Cleanup provided by scoping, standard useEffect cleanup handles component unmount
        }
    }, []);

    // Helper for toast (since we don't have a toast component in this file explicitly imported, use alert for now or assumed existing patterns)
    const toastSuccess = () => {
        // We will use a simple timeout to avoid blocking execution with alert immediately
        setTimeout(() => alert("Payment successful! Updating balance..."), 500);
    };

    const handlePurchase = async (packageId: string) => {
        if (!isSignedIn) {
            router.push('/sign-up');
            return;
        }

        setLoading(true);

        const publishableKey = process.env.NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY;
        if (!publishableKey) {
            console.error("Missing NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY");
            alert("Configuration Error: Missing Stripe Publishable Key. Please check your .env.local file and restart the server.");
            setLoading(false);
            return;
        }

        try {
            // Create Checkout Session
            const res = await fetch('/api/payments/checkout', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    packageId: packageId
                })
            });

            const data = await res.json();

            if (data.error) throw new Error(data.error);
            if (!data.url) throw new Error("No checkout URL returned");

            // Direct Redirect to Stripe URL
            window.location.href = data.url;

        } catch (error: unknown) {
            console.error("Purchase Flow Error:", error);
            alert(`Failed to initiate purchase: ${(error as Error).message}`);
            setLoading(false);
        }
        // Note: Loading state stays true until redirect or error
    };

    return (
        <div className="container mx-auto py-10 max-w-4xl">
            <div className="mb-8">
                <h1 className="text-3xl font-bold text-slate-900">Billing & Credits</h1>
                <p className="text-slate-500">Manage your credits and subscription plan.</p>
            </div>

            {/* Academic Banking Grant Offer */}
            <div className="bg-gradient-to-r from-indigo-50 to-blue-50 border border-indigo-100 rounded-xl p-6 mb-8 flex flex-col md:flex-row items-start md:items-center justify-between gap-4">
                <div>
                    <h3 className="text-lg font-bold text-indigo-900 flex items-center gap-2">
                        <span className="text-2xl">🎓</span> Student & Researcher Grant
                    </h3>
                    <p className="text-indigo-700 mt-1 max-w-xl">
                        Are you a student or academic researcher? We support open science!
                        Email us from your <strong>.edu</strong> or institutional address to receive <span className="font-bold underline">500 Free Credits</span> for your work.
                    </p>
                </div>
                <a href="mailto:support@instanttea.com?subject=Academic Grant Request" className="whitespace-nowrap bg-indigo-600 hover:bg-indigo-700 text-white font-medium px-4 py-2 rounded-lg transition-colors">
                    Claim Academic Grant
                </a>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {/* Current Balance Card */}
                <Card className="md:col-span-3 bg-gradient-to-r from-indigo-500 to-purple-600 text-white border-0">
                    <CardHeader>
                        <CardTitle className="text-indigo-100 font-medium">Current Balance</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="flex items-center gap-3">
                            <Coins className="h-10 w-10 text-indigo-200" />
                            <div className="text-5xl font-bold">
                                {isLoadingCredits ? "..." : credits}
                            </div>
                            <div className="text-indigo-200 self-end mb-2">credits available</div>
                        </div>
                    </CardContent>
                </Card>

                {/* Credit Value Explanation */}
                <Card className="md:col-span-3 bg-slate-50 border-slate-200">
                    <CardContent className="pt-6 flex items-center justify-between gap-4">
                        <div className="flex items-center gap-4">
                            <div className="bg-indigo-100 p-2 rounded-lg">
                                <span className="text-2xl">💡</span>
                            </div>
                            <div>
                                <h4 className="font-semibold text-slate-900">What is a Credit?</h4>
                                <p className="text-sm text-slate-600">
                                    <strong>1 Credit = 1 Document Analysis</strong>.
                                    Looking at a document through a single lens (e.g., &quot;Legitimacy&quot; or &quot;Cultural Framing&quot;) costs 1 credit.
                                    Complex synthesis tasks may cost more.
                                </p>
                                <Link href="/why-credits" className="mt-2 inline-block text-sm font-medium text-indigo-600 hover:text-indigo-800 hover:underline">
                                    Learn more about credits &rarr;
                                </Link>
                            </div>
                        </div>
                    </CardContent>
                </Card>

                {/* Purchase Options */}
                <div className="md:col-span-2 space-y-6">
                    <h2 className="text-xl font-semibold text-slate-900">Purchase Credits</h2>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {Object.values(CREDIT_PACKAGES).map((pack) => (
                            <Card key={pack.id} className={cn(
                                "border-2 relative overflow-hidden transition-all hover:border-indigo-300",
                                pack.popular ? "border-indigo-500 ring-4 ring-indigo-50/50" : "border-slate-200",
                                pack.id === 'institution' ? "bg-slate-50 border-slate-200" : "bg-white",
                                pack.id === 'starter' ? "opacity-75 bg-slate-50" : "" // Visual cue for unavailable
                            )}>
                                {pack.popular && (
                                    <div className="absolute top-0 right-0 bg-indigo-500 text-white text-xs font-bold px-3 py-1 rounded-bl-lg">
                                        POPULAR
                                    </div>
                                )}
                                <CardHeader>
                                    <CardTitle className="flex items-center gap-2">
                                        <CreditCard className="h-5 w-5 text-indigo-600" />
                                        {pack.name}
                                    </CardTitle>
                                    <CardDescription>
                                        {pack.description}
                                        {pack.promo?.badge && (
                                            <span className="ml-2 inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-amber-100 text-amber-800">
                                                {pack.promo.badge}
                                            </span>
                                        )}
                                    </CardDescription>
                                </CardHeader>
                                <CardContent>
                                    <div className="flex justify-between items-baseline mb-4">
                                        {pack.id === 'institution' ? (
                                            <span className="text-3xl font-bold text-slate-900">Contact Us</span>
                                        ) : pack.price === 0 ? (
                                            <span className="text-3xl font-bold text-slate-900">Free Trial</span>
                                        ) : (
                                            <span className="text-3xl font-bold text-slate-900">${pack.price}</span>
                                        )}

                                        {pack.id !== 'institution' && pack.id !== 'starter' && (
                                            <div className="text-right">
                                                <span className="text-slate-500 block text-xs">one-time payment</span>
                                                {pack.savings && (
                                                    <span className="text-green-600 text-xs font-bold">{pack.savings}</span>
                                                )}
                                            </div>
                                        )}
                                    </div>

                                    {pack.promo?.bannerText && (
                                        <div className="mb-4 text-xs text-amber-700 bg-amber-50 p-2 rounded border border-amber-200">
                                            {pack.promo.bannerText}
                                        </div>
                                    )}

                                    <ul className="space-y-2 text-sm text-slate-600 mb-6">
                                        {pack.features.map((feature, i) => (
                                            <li key={i} className="flex items-center gap-2">
                                                <Check className={cn(
                                                    "h-4 w-4",
                                                    pack.id === 'institution' ? "text-slate-500" : "text-green-500"
                                                )} />
                                                {feature}
                                            </li>
                                        ))}
                                    </ul>
                                </CardContent>
                                <CardFooter>
                                    {pack.id === 'institution' ? (
                                        <Button
                                            onClick={() => router.push('/contact')}
                                            className="w-full bg-slate-800 hover:bg-slate-700 text-white"
                                        >
                                            Contact Sales
                                        </Button>
                                    ) : isSignedIn ? (
                                        <Button
                                            onClick={() => handlePurchase(pack.id)}
                                            disabled={loading || pack.id === 'starter'}
                                            className={cn(
                                                "w-full",
                                                pack.popular ? "bg-indigo-600 hover:bg-indigo-700 text-white" : "bg-white border-2 border-indigo-600 text-indigo-600 hover:bg-indigo-50"
                                            )}
                                        >
                                            {loading ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : null}
                                            {pack.id === 'starter' ? "New Users Only" : `Buy ${pack.credits} Credits`}
                                        </Button>
                                    ) : (
                                        <Button
                                            onClick={() => router.push('/sign-up')}
                                            className="w-full bg-slate-900 hover:bg-slate-800 text-white"
                                        >
                                            <LogIn className="mr-2 h-4 w-4" />
                                            Sign Up to Purchase
                                        </Button>
                                    )}
                                </CardFooter>
                            </Card>
                        ))}
                    </div>



                    {/* Contributor Card */}
                    <Card className="border-emerald-500/20 bg-emerald-900/5">
                        <CardHeader>
                            <CardTitle className="text-emerald-700 dark:text-emerald-400 flex items-center gap-2">
                                <Coins className="h-5 w-5" />
                                Earn Credits
                            </CardTitle>
                            <CardDescription>
                                Contribute to the ecosystem relative to your expertise.
                            </CardDescription>
                        </CardHeader>
                        <CardContent>
                            <p className="text-sm text-slate-600 dark:text-slate-400 mb-4">
                                Research-grade contributions (critiques, bias reviews, or code) can earn you usage credits.
                            </p>
                            <Link href="/governance/contributor-credits">
                                <Button variant="outline" className="w-full border-emerald-200 text-emerald-700 hover:bg-emerald-50 hover:text-emerald-800 dark:border-emerald-800 dark:text-emerald-400 dark:hover:bg-emerald-900/50">
                                    View Contributor Policy
                                </Button>
                            </Link>
                        </CardContent>
                    </Card>

                    {isSignedIn && (
                        <>
                            <DeleteAccountSection />
                            <DataExportSection />
                        </>
                    )}
                </div>

                {/* Transaction History */}
                <div className="space-y-6">
                    <h2 className="text-xl font-semibold text-slate-900">History</h2>
                    <TransactionHistory transactions={history} />
                </div>
            </div>
        </div >
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Loader2, RotateCcw, Save, AlertCircle, Play, Sparkles, Search } from "lucide-react";
import Link from "next/link";
import { PromptDefinition } from "@/lib/prompts/registry";

interface PromptWithState extends PromptDefinition {
    currentValue: string;
    isModified: boolean;
    isEditable?: boolean;
    testInput: string;
    testOutput: string;
    isTesting: boolean;
}

const PromptEditor = ({ value, onChange }: { value: string, onChange: (val: string) => void }) => {
    const textareaRef = React.useRef<HTMLTextAreaElement>(null);
    const backdropRef = React.useRef<HTMLDivElement>(null);

    const handleScroll = () => {
        if (backdropRef.current && textareaRef.current) {
            backdropRef.current.scrollTop = textareaRef.current.scrollTop;
        }
    };

    // Simple parser to highlight "Output Format" section
    const renderHighlights = () => {
        // Regex to match "Output Format" section with various header styles (##, ###, ===, or just text)
        // Captures until next section (##, ===, ---) or end of string
        const regex = /((?:^|\n)(?:##+|={3,})?\s*Output\s*Format[\s\S]*?)(?=$|\n(?:##+|={3,}|---))/i;
        const match = value.match(regex);

        if (!match || match.index === undefined) {
            return <span>{value}</span>;
        }

        const start = match.index;
        const end = start + match[0].length;
        const before = value.substring(0, start);
        const danger = value.substring(start, end);
        const after = value.substring(end);

        return (
            <>
                <span>{before}</span>
                <span className="bg-red-50 text-red-600 font-bold decoration-red-200">{danger}</span>
                <span>{after}</span>
            </>
        );
    };

    return (
        <div className="relative text-sm font-mono leading-relaxed h-[400px] border rounded-md border-input focus-within:ring-2 focus-within:ring-ring focus-within:ring-offset-2">
            {/* Backdrop Layer */}
            <div
                ref={backdropRef}
                className="absolute inset-0 p-3 whitespace-pre-wrap break-words overflow-hidden pointer-events-none bg-white text-slate-900"
                aria-hidden="true"
            >
                {renderHighlights()}
                {/* Extra character to prevent jumpiness on trailing newlines */}
                {value.endsWith('\n') && <br />}
            </div>

            {/* Editable Layer */}
            <textarea
                ref={textareaRef}
                value={value}
                onChange={(e) => onChange(e.target.value)}
                onScroll={handleScroll}
                className="relative z-10 w-full h-full p-3 bg-transparent text-transparent caret-zinc-950 resize-none focus:outline-none rounded-md overflow-y-auto selection:bg-indigo-100 selection:text-transparent"
                spellCheck={false}
            />
        </div>
    )
};

export default function PromptSettingsPage() {
    const [prompts, setPrompts] = useState<PromptWithState[]>([]);
    const [searchQuery, setSearchQuery] = useState("");
    const [isLoading, setIsLoading] = useState(true);
    const [editingId, setEditingId] = useState<string | null>(null);
    const [editValue, setEditValue] = useState("");
    const [isSaving, setIsSaving] = useState(false);

    useEffect(() => {
        fetchPrompts();
    }, []);

    const fetchPrompts = async () => {
        setIsLoading(true);
        try {
            const headers: HeadersInit = {};
            if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true' && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
            }

            const res = await fetch('/api/prompts', { headers, cache: 'no-store' });
            const data = await res.json();
            if (data.prompts) {
                setPrompts(data.prompts.map((p: any) => ({
                    ...p,
                    testInput: "",
                    testOutput: "",
                    isTesting: false
                })));
            }
        } catch (error) {
            console.error("Failed to load prompts:", error);
        } finally {
            setIsLoading(false);
        }
    };

    const handleEdit = (prompt: PromptWithState) => {
        setEditingId(prompt.id);
        setEditValue(prompt.currentValue);
    };

    const handleCancel = () => {
        setEditingId(null);
        setEditValue("");
    };

    const handleSave = async (id: string) => {
        setIsSaving(true);
        try {
            const headers: HeadersInit = { 'Content-Type': 'application/json' };
            if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true' && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
            }

            await fetch('/api/prompts', {
                method: 'POST',
                headers,
                body: JSON.stringify({ id, value: editValue })
            });
            await fetchPrompts();
            setEditingId(null);
        } catch (error) {
            console.error("Failed to save prompt:", error);
            alert("Failed to save changes.");
        } finally {
            setIsSaving(false);
        }
    };

    const handleReset = async (id: string) => {
        if (!confirm("Reset this prompt to its system default?")) return;

        setIsSaving(true);
        try {
            const headers: HeadersInit = { 'Content-Type': 'application/json' };
            if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true' && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
            }

            await fetch('/api/prompts', {
                method: 'POST',
                headers,
                body: JSON.stringify({ id, action: 'reset' })
            });
            await fetchPrompts();
            if (editingId === id) {
                setEditingId(null);
            }
        } catch (error) {
            console.error("Failed to reset prompt:", error);
            alert("Failed to reset prompt.");
        } finally {
            setIsSaving(false);
        }
    };

    const updatePromptState = (id: string, updates: Partial<PromptWithState>) => {
        setPrompts(prev => prev.map(p => p.id === id ? { ...p, ...updates } : p));
    };

    const handleTest = async (prompt: PromptWithState) => {
        updatePromptState(prompt.id, { isTesting: true, testOutput: "" });

        try {
            const headers: HeadersInit = { 'Content-Type': 'application/json' };
            if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true' && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
            }

            // use editValue if we are currently editing this specific prompt, otherwise use the stored value
            const systemPromptToTest = (editingId === prompt.id) ? editValue : prompt.currentValue;

            const res = await fetch('/api/prompts/test', {
                method: 'POST',
                headers,
                body: JSON.stringify({
                    systemPrompt: systemPromptToTest,
                    userContent: prompt.testInput
                })
            });
            const data = await res.json();

            if (data.success) {
                let finalOutput = data.result;

                // VALIDATION LOGIC
                if (prompt.outputSchema?.format === 'json') {
                    try {
                        // 1. Check for valid JSON
                        // Sometimes models wrap JSON in markdown code blocks, strip them if present
                        const cleanJson = finalOutput.replace(/```json\n?|```/g, '').trim();
                        const parsed = JSON.parse(cleanJson);

                        // 2. Check for required keys
                        if (prompt.outputSchema.requiredKeys) {
                            const missingKeys = prompt.outputSchema.requiredKeys.filter(k => !(k in parsed));
                            if (missingKeys.length > 0) {
                                finalOutput = `⚠️ VALIDATION ERROR: Missing required JSON keys: ${missingKeys.join(', ')}\n\n` + finalOutput;
                            } else {
                                // Formatting for prettier display if valid
                                finalOutput = JSON.stringify(parsed, null, 2);
                            }
                        } else {
                            finalOutput = JSON.stringify(parsed, null, 2);
                        }
                    } catch (e) {
                        finalOutput = `❌ CRITICAL ERROR: Output is NOT valid JSON.\n\n${finalOutput}`;
                    }
                }

                updatePromptState(prompt.id, { testOutput: finalOutput });
            } else {
                updatePromptState(prompt.id, { testOutput: `Error: ${data.error}` });
            }
        } catch (error: any) {
            updatePromptState(prompt.id, { testOutput: `Error: ${error.message}` });
        } finally {
            updatePromptState(prompt.id, { isTesting: false });
        }
    };

    const filteredPrompts = prompts.filter(prompt => {
        if (!searchQuery.trim()) return true;
        const lowerQuery = searchQuery.toLowerCase();
        return prompt.name.toLowerCase().includes(lowerQuery) ||
            prompt.description?.toLowerCase().includes(lowerQuery) ||
            prompt.category?.toLowerCase().includes(lowerQuery);
    });

    const groupedPrompts = prompts.reduce((acc, prompt) => {
        const category = prompt.category || "Uncategorized";
        if (!acc[category]) acc[category] = [];
        acc[category].push(prompt);
        return acc;
    }, {} as Record<string, PromptWithState[]>);

    return (
        <div className="container mx-auto py-10 max-w-4xl">
            <div className="flex items-center justify-between mb-8">
                <div>
                    <h1 className="text-3xl font-bold text-slate-900">Lens Definitions</h1>
                    <p className="text-slate-500 text-sm mt-1">
                        <AlertCircle className="w-4 h-4 inline mr-1" />
                        Prompt customizations only available to administrators of forked git hub systems.
                    </p>
                </div>

            </div>

            <div className="mb-6 relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                <Input
                    placeholder="Search prompts by name, description, or category..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="pl-9 bg-white"
                />
            </div>

            {!isLoading && prompts.length > 0 && !searchQuery.trim() && (
                <div className="mb-10 p-6 bg-slate-50 border border-slate-200 rounded-xl shadow-sm">
                    <h2 className="text-xl font-semibold mb-6 flex items-center text-slate-800">
                        <Sparkles className="w-5 h-5 mr-2 text-indigo-500" />
                        Prompt Directory
                    </h2>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-x-8 gap-y-8">
                        {Object.entries(groupedPrompts)
                            .sort(([a], [b]) => a.localeCompare(b))
                            .map(([category, catPrompts]) => (
                                <div key={category}>
                                    <h3 className="font-medium text-slate-900 mb-3 border-b border-slate-200 pb-2 flex items-center justify-between">
                                        {category}
                                        <Badge variant="secondary" className="text-xs bg-slate-200/50 text-slate-600 font-normal">
                                            {catPrompts.length}
                                        </Badge>
                                    </h3>
                                    <ul className="space-y-3">
                                        {catPrompts.map(p => (
                                            <li key={p.id}>
                                                <a
                                                    href={`#prompt-${p.id}`}
                                                    className="text-sm font-medium text-indigo-600 hover:text-indigo-800 hover:underline transition-colors block mb-0.5"
                                                >
                                                    {p.name}
                                                </a>
                                                <p className="text-xs text-slate-500 line-clamp-2 leading-relaxed" title={p.description}>
                                                    {p.description}
                                                </p>
                                            </li>
                                        ))}
                                    </ul>
                                </div>
                            ))}
                    </div>
                </div>
            )}

            {isLoading ? (
                <div className="flex justify-center p-12">
                    <Loader2 className="h-8 w-8 animate-spin text-slate-400" />
                </div>
            ) : (
                <div className="grid gap-6">
                    {filteredPrompts.length === 0 ? (
                        <div className="text-center py-12 text-slate-500 border rounded-lg bg-slate-50/50">
                            No prompts found matching "{searchQuery}"
                        </div>
                    ) : (
                        filteredPrompts.map(prompt => (
                            <Card id={`prompt-${prompt.id}`} key={prompt.id} className={`scroll-mt-8 transition-all ${editingId === prompt.id ? 'ring-2 ring-indigo-500 border-indigo-500 shadow-md' : ''}`}>
                                <CardHeader className="pb-3">
                                    <div className="flex items-center justify-between">
                                        <div className="flex items-center gap-2">
                                            <CardTitle className="text-lg font-semibold">{prompt.name}</CardTitle>
                                            {prompt.isModified && (
                                                <Badge variant="secondary" className="bg-amber-100 text-amber-700 hover:bg-amber-100">
                                                    Customized
                                                </Badge>
                                            )}
                                            {/* DEBUG: Show Admin Status */}
                                            {prompt.isEditable && (
                                                <Badge variant="outline" className="border-indigo-200 text-indigo-700">
                                                    Admin
                                                </Badge>
                                            )}
                                        </div>
                                        <div className="flex gap-2">
                                            {editingId === prompt.id && prompt.isEditable ? (
                                                <>
                                                    <Button variant="ghost" size="sm" onClick={handleCancel} disabled={isSaving}>Cancel</Button>
                                                    <Button size="sm" onClick={() => handleSave(prompt.id)} disabled={isSaving}>
                                                        {isSaving ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <Save className="h-4 w-4 mr-2" />}
                                                        Save Changes
                                                    </Button>
                                                </>
                                            ) : (
                                                <>
                                                    {prompt.isEditable && prompt.isModified && (
                                                        <Button variant="outline" size="sm" onClick={() => handleReset(prompt.id)} title="Restore Default">
                                                            <RotateCcw className="h-4 w-4 mr-2" />
                                                            Reset
                                                        </Button>
                                                    )}
                                                    {prompt.isEditable && (
                                                        <Button variant="outline" size="sm" onClick={() => handleEdit(prompt)}>
                                                            Edit Prompt
                                                        </Button>
                                                    )}
                                                </>
                                            )}
                                        </div>

                                        {/* Test Playground */}
                                        {prompt.isEditable && (
                                            <div className="mt-6 pt-6 border-t border-slate-200">
                                                <h3 className="text-sm font-semibold text-slate-800 mb-3 flex items-center gap-2">
                                                    <Sparkles className="h-4 w-4 text-indigo-500" />
                                                    Test Playground
                                                </h3>
                                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                                    <div>
                                                        <label className="text-xs font-medium text-slate-500 mb-1 block">Sample Input</label>
                                                        <Textarea
                                                            placeholder="Paste a snippet of text to test..."
                                                            value={prompt.testInput}
                                                            onChange={(e) => updatePromptState(prompt.id, { testInput: e.target.value })}
                                                            className="h-40 font-mono text-xs"
                                                        />
                                                        <Button
                                                            onClick={() => handleTest(prompt)}
                                                            disabled={prompt.isTesting || !prompt.testInput?.trim()}
                                                            className="mt-2 w-full"
                                                            size="sm"
                                                            variant="secondary"
                                                        >
                                                            {prompt.isTesting ? <Loader2 className="h-3 w-3 animate-spin mr-2" /> : <Play className="h-3 w-3 mr-2" />}
                                                            Run Test
                                                        </Button>
                                                    </div>
                                                    <div>
                                                        <label className="text-xs font-medium text-slate-500 mb-1 block">AI Output</label>
                                                        <div className="h-40 bg-slate-50 rounded-md border p-3 overflow-y-auto text-xs font-mono whitespace-pre-wrap">
                                                            {prompt.testOutput || <span className="text-slate-400 italic">Output will appear here...</span>}
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                    <CardDescription>{prompt.description}</CardDescription>
                                </CardHeader>
                                <CardContent>
                                    {editingId === prompt.id ? (
                                        <div>
                                            <PromptEditor
                                                value={editValue}
                                                onChange={(val) => setEditValue(val)}
                                            />
                                            <div className="mt-2 text-xs text-slate-500 flex flex-col gap-1">
                                                <div className="flex items-center gap-1">
                                                    <AlertCircle className="h-3 w-3" />
                                                    Variables like <code>`{"${text}"}`</code> or <code>`{"${actors}"}`</code> must be preserved for the prompt to work.
                                                </div>
                                                {prompt.outputSchema && (
                                                    <div className="flex items-center gap-1 text-amber-600 font-medium">
                                                        <AlertCircle className="h-3 w-3" />
                                                        Warning: Do NOT change the JSON output keys or structure, or the visualization will break.
                                                    </div>
                                                )}
                                            </div>
                                        </div>
                                    ) : (
                                        <div className="bg-slate-50 p-4 rounded-md border text-sm font-mono text-slate-600 whitespace-pre-wrap max-h-[200px] overflow-y-auto hover:max-h-[500px] transition-all duration-300">
                                            {prompt.currentValue}
                                        </div>
                                    )}
                                </CardContent>
                            </Card>
                        ))
                    )}
                </div>
            )}
        </div>
    );
}

'use client';

import React, { useState } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '@clerk/nextjs';
import { useWorkspace } from '@/providers/WorkspaceProvider';
import { useTeam } from '@/hooks/useTeam';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Skeleton } from '@/components/ui/skeleton';
import { InviteMemberDialog } from '@/components/collaboration/InviteMemberDialog';
import { DeleteTeamDialog } from '@/components/collaboration/DeleteTeamDialog';
import { TeamMembers } from '@/components/collaboration/TeamMembers';
import { Users, UserPlus, ArrowLeft, Settings, AlertTriangle } from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';

export default function TeamSettingsPage() {
    const router = useRouter();
    const { userId } = useAuth();
    const { workspaceType, currentWorkspaceId } = useWorkspace();
    const { teamDetails, isLoading, error, isTeamWorkspace, removeMember } = useTeam();
    const [showInviteDialog, setShowInviteDialog] = useState(false);
    const [showDeleteDialog, setShowDeleteDialog] = useState(false);

    // Guard: Redirect if not in team workspace
    if (!isTeamWorkspace) {
        return (
            <div className="container max-w-4xl mx-auto py-12">
                <Card className="bg-zinc-700 border-zinc-500">
                    <CardContent className="pt-6">
                        <div className="text-center py-8">
                            <Users className="w-16 h-16 mx-auto mb-4 text-zinc-600" />
                            <h2 className="text-xl font-semibold text-zinc-300 mb-2">Not in a Team Workspace</h2>
                            <p className="text-zinc-400 mb-4">
                                Switch to a team workspace to manage team settings.
                            </p>
                            <Button onClick={() => router.push('/dashboard')} variant="outline">
                                <ArrowLeft className="w-4 h-4 mr-2" />
                                Back to Dashboard
                            </Button>
                        </div>
                    </CardContent>
                </Card>
            </div>
        );
    }

    // Loading state
    if (isLoading) {
        return (
            <div className="container max-w-4xl mx-auto py-12 space-y-6">
                <Skeleton className="h-32 bg-zinc-800" />
                <Skeleton className="h-64 bg-zinc-800" />
            </div>
        );
    }

    // Error state
    if (error || !teamDetails) {
        return (
            <div className="container max-w-4xl mx-auto py-12">
                <Card className="bg-zinc-700 border-zinc-500">
                    <CardContent className="pt-6">
                        <div className="text-center py-8">
                            <p className="text-red-400">{error || 'Failed to load team details'}</p>
                            <Button onClick={() => router.push('/dashboard')} variant="outline" className="mt-4">
                                Back to Dashboard
                            </Button>
                        </div>
                    </CardContent>
                </Card>
            </div>
        );
    }

    const currentUserMember = teamDetails.members.find(m => m.userId.toLowerCase() === userId?.toLowerCase());
    const currentUserRole = currentUserMember?.role;
    const isOwner = currentUserRole === 'OWNER';

    return (
        <div className="container max-w-4xl mx-auto py-12 space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-3xl font-bold text-white flex items-center gap-3">
                        <Settings className="w-8 h-8 text-indigo-400" />
                        Team Settings
                    </h1>
                    <p className="text-zinc-400 mt-1">Manage your team members and settings</p>
                </div>
                <Button onClick={() => router.push('/dashboard')} variant="outline">
                    <ArrowLeft className="w-4 h-4 mr-2" />
                    Back
                </Button>
            </div>

            {/* Team Info Card */}
            <Card className="bg-zinc-700 border-zinc-500">
                <CardHeader>
                    <CardTitle className="text-white">Team Information</CardTitle>
                    <CardDescription>Basic details about your team</CardDescription>
                </CardHeader>
                <CardContent className="space-y-3">
                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <p className="text-sm text-zinc-400">Team Name</p>
                            <p className="text-white font-medium">{teamDetails.name}</p>
                        </div>
                        <div>
                            <p className="text-sm text-zinc-400">Created</p>
                            <p className="text-white">
                                {formatDistanceToNow(teamDetails.createdAt, { addSuffix: true })}
                            </p>
                        </div>
                        <div>
                            <p className="text-sm text-zinc-400">Team ID</p>
                            <p className="text-white font-mono text-sm">{teamDetails.id}</p>
                        </div>
                        <div>
                            <p className="text-sm text-zinc-400">Total Members</p>
                            <p className="text-white">{teamDetails.members.length}</p>
                        </div>
                    </div>
                </CardContent>
            </Card>

            {/* Members Card */}
            <Card className="bg-zinc-700 border-zinc-500">
                <CardHeader>
                    <div className="flex items-center justify-between">
                        <div>
                            <CardTitle className="text-white flex items-center gap-2">
                                <Users className="w-5 h-5" />
                                Team Members
                            </CardTitle>
                            <CardDescription>
                                {isOwner
                                    ? 'Manage who has access to this team workspace'
                                    : 'View team members'}
                            </CardDescription>
                        </div>
                        {isOwner && (
                            <Button
                                onClick={() => setShowInviteDialog(true)}
                                className="bg-indigo-600 hover:bg-indigo-700"
                            >
                                <UserPlus className="w-4 h-4 mr-2" />
                                Invite Member
                            </Button>
                        )}
                    </div>
                </CardHeader>
                <CardContent>
                    <TeamMembers
                        members={teamDetails.members}
                        currentUserRole={currentUserRole}
                        onRemoveMember={removeMember}
                    />
                </CardContent>
            </Card>

            {/* Danger Zone - Owner Only */}
            {isOwner && (
                <Card className="bg-red-950/20 border-red-900/50">
                    <CardHeader>
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-red-900/30 rounded-lg">
                                <AlertTriangle className="w-5 h-5 text-red-400" />
                            </div>
                            <div>
                                <CardTitle className="text-white">Danger Zone</CardTitle>
                                <CardDescription className="text-red-300">
                                    Irreversible and destructive actions
                                </CardDescription>
                            </div>
                        </div>
                    </CardHeader>
                    <CardContent>
                        <div className="flex items-start justify-between gap-4 p-4 bg-red-950/30 border border-red-900/50 rounded-lg">
                            <div>
                                <h4 className="font-semibold text-white mb-1">Delete this team</h4>
                                <p className="text-sm text-red-200">
                                    Permanently delete this team, all documents, and remove all members. This action cannot be undone.
                                </p>
                            </div>
                            <Button
                                variant="destructive"
                                onClick={() => setShowDeleteDialog(true)}
                                className="shrink-0"
                            >
                                Delete Team
                            </Button>
                        </div>
                    </CardContent>
                </Card>
            )}

            {/* Dialogs */}
            <InviteMemberDialog open={showInviteDialog} onOpenChange={setShowInviteDialog} />
            {teamDetails && (
                <DeleteTeamDialog
                    open={showDeleteDialog}
                    onOpenChange={setShowDeleteDialog}
                    teamId={currentWorkspaceId!}
                    teamName={teamDetails.name}
                    memberCount={teamDetails.members.length}
                />
            )}
        </div>
    );
}

"use client";

import { useState } from "react";
import { useSources } from "@/hooks/useSources";
import { useServerStorage } from "@/hooks/useServerStorage";
import { Source, EcosystemImpact } from "@/types";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { GitMerge, GitPullRequest, AlertCircle, FileDown, CheckCircle2, Sparkles, Brain, Network, Loader2, RefreshCw, Radio } from "lucide-react";
import { AssemblageSankey } from "@/components/AssemblageSankey";
import { Radar, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, ResponsiveContainer, Legend, Tooltip, BarChart, Bar, XAxis, YAxis, CartesianGrid } from "recharts";
import { Info } from "lucide-react";
import { RelationalAxisMap } from "@/components/comparison/RelationalAxisMap";
import { ComparisonNetworkGraph } from "@/components/comparison/ComparisonNetworkGraph";
import { ResonanceNetworkGraph } from "@/components/comparison/ResonanceNetworkGraph";
import { AssemblageExport } from "@/types/bridge"; // [NEW] Import Data Contract
import { useRouter } from "next/navigation"; // [NEW] For Deep Linking

import { SynthesisComparisonResult as ComparisonResult } from "@/types/synthesis";
import { useDemoMode } from "@/hooks/useDemoMode";
import { CreditTopUpDialog } from "@/components/CreditTopUpDialog";
import { useCredits } from "@/hooks/useCredits";

const SYNTHESIS_FINDINGS = [
    {
        key: "risk",
        dimension: "Risk Classification",
        convergence: "Comparison of risk definitions and tiered obligations across frameworks.",
        divergence: "Analysis of how risk categories are adapted to local social and political contexts.",
        coloniality: "Examination of whether risk models reflect Global North assumptions or local realities.",
        resistance: "Identification of mechanisms that allow for local adaptation of risk frameworks.",
        icon: AlertCircle,
    },
    {
        key: "governance",
        dimension: "Governance Structure",
        convergence: "Comparison of institutional designs (e.g., centralized vs. networked authorities).",
        divergence: "Analysis of enforcement powers and coordination mechanisms.",
        coloniality: "Assessment of whether governance models assume state capacities that may not exist.",
        resistance: "Highlighting of innovative governance structures that leverage local expertise.",
        icon: GitMerge,
    },
    {
        key: "rights",
        dimension: "Rights Framework",
        convergence: "Comparison of individual rights (e.g., explanation, redress) and collective protections.",
        divergence: "Analysis of the balance between procedural compliance and substantive rights.",
        coloniality: "Examination of whether rights frameworks obscure underlying power asymmetries.",
        resistance: "Identification of rights-based approaches that empower affected communities.",
        icon: CheckCircle2,
    },
    {
        key: "scope",
        dimension: "Territorial Scope",
        convergence: "Comparison of jurisdictional reach and extraterritorial application.",
        divergence: "Analysis of data sovereignty claims and market power dynamics.",
        coloniality: "Assessment of the 'Brussels Effect' and the imposition of external legal norms.",
        resistance: "Highlighting of assertions of epistemic and legal autonomy.",
        icon: GitPullRequest,
    },
];

const EXCLUDED_KEYS = new Set([
    'verified_quotes',
    'system_critique',
    'assemblage_network',
    'resonances',
    'topology_analysis',
    'key_insight',
    'node_generation_step' // Internal AI brainstorming step, not for display
]);

// Type guard to check if a value is a valid synthesis section
const isSynthesisSection = (value: unknown): value is ComparisonResult["risk"] => {
    return value !== null &&
        typeof value === 'object' &&
        'convergence' in value &&
        'divergence' in value &&
        'coloniality' in value &&
        'resistance' in value;
};

export default function SynthesisPage() {
    const { sources, isLoading } = useSources();
    const { isReadOnly } = useDemoMode();
    const { hasCredits } = useCredits(); // [NEW] Credit Check
    const [showTopUp, setShowTopUp] = useState(false); // [NEW] Top Up Dialog State
    const [isExporting, setIsExporting] = useState(false);

    // Comparison State
    const [sourceA, setSourceA] = useState<Source | null>(null);
    const [sourceB, setSourceB] = useState<Source | null>(null);
    const [isComparing, setIsComparing] = useState(false);
    const [comparisonResult, setComparisonResult] = useServerStorage<ComparisonResult | null>("synthesis_comparison_result", null);

    // [NEW] Local Session Cache to restore results without re-fetching
    const [runCache, setRunCache] = useState<Record<string, ComparisonResult>>({});

    // Filter sources that have text available for analysis AND are Policy Documents (not Traces/Web)
    const analyzedSources = sources.filter(s =>
        (s.analysis || s.extractedText) &&
        (s.type === 'PDF' || s.type === 'Text')
    );

    // [NEW] Helper to update selection and check cache
    const updateSelection = async (newA: Source | null, newB: Source | null) => {
        setSourceA(newA);
        setSourceB(newB);
        setComparisonResult(null); // Reset while loading

        if (newA && newB) {
            const cacheKey = `synthesis:${newA.id}:${newB.id}`;
            const reverseKey = `synthesis:${newB.id}:${newA.id}`;

            setIsComparing(true);
            try {
                // 1. Try reading from Server Storage (Permanent)
                // We use the raw fetch here because useServerStorage hook is for component state, 
                // but we need to fetch *specific* keys based on selection.
                const headers: HeadersInit = { 'Content-Type': 'application/json' };
                if (isReadOnly && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                    headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
                } else if (localStorage.getItem('x-workspace-id')) {
                    headers['x-workspace-id'] = localStorage.getItem('x-workspace-id') || '';
                }

                // Try fetching direct forward key
                let response = await fetch(`/api/storage?key=${encodeURIComponent(cacheKey)}`, { headers });

                if (response.ok) {
                    const data = await response.json();
                    if (data && data.value) {
                        setComparisonResult(data.value);
                        setIsComparing(false);
                        return;
                    }
                }

                // Try fetching reverse key
                response = await fetch(`/api/storage?key=${encodeURIComponent(reverseKey)}`, { headers });
                if (response.ok) {
                    const data = await response.json();
                    if (data && data.value) {
                        setComparisonResult(data.value);
                        setIsComparing(false);
                        return;
                    }
                }

            } catch (err) {
                console.error("Failed to load persisted synthesis:", err);
            } finally {
                setIsComparing(false);
            }
        }
    };

    const handleExport = async () => {
        if (isReadOnly) {
            alert("Export disabled in Demo Mode");
            return;
        }

        // [NEW] Credit Check
        if (!hasCredits && !process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE) {
            setShowTopUp(true);
            return;
        }

        if (!comparisonResult) {
            alert("Please run a comparison first to generate a report.");
            return;
        }

        setIsExporting(true);
        try {
            // Lazy load the heavy PDF generation library only when the user explicitly clicks Export
            const { generateSynthesisPDF } = await import("@/utils/generateSynthesisPDF");

            await generateSynthesisPDF(
                comparisonResult,
                sourceA?.title || "Source A",
                sourceB?.title || "Source B"
            );
        } catch (error) {
            console.error("Error generating PDF:", error);
            alert("Failed to generate PDF. Please try again.");
        } finally {
            setIsExporting(false);
        }
    };

    const handleCompare = async (forceRefresh = false) => {
        if (!sourceA || !sourceB) return;

        // [NEW] Credit Check
        if (!hasCredits && !process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE && !isReadOnly) {
            setShowTopUp(true);
            return;
        }

        // [NEW] Soft Preflight: Check for AssemblageExport in SessionStorage
        const exportA = sessionStorage.getItem(`assemblage_export_${sourceA.id}`);
        const exportB = sessionStorage.getItem(`assemblage_export_${sourceB.id}`);

        let assemblageA: AssemblageExport | null = null;
        let assemblageB: AssemblageExport | null = null;

        try {
            if (exportA) assemblageA = JSON.parse(exportA);
            if (exportB) assemblageB = JSON.parse(exportB);
        } catch (e) {
            console.error("Failed to parse exports", e);
        }

        // Warning if missing (Rhizomatic Flexibility - warn but don't block, fallback to raw text)
        if (!assemblageA || !assemblageB) {
            console.warn("Missing Assemblage Exports. Comparison will rely on raw text regeneration, which lacks provenance.");
            // Optional: You could show a UI toast here
        }

        setIsComparing(true);
        // setComparisonResult(null); // Keep previous result while loading so button stays visible

        // Check for missing text
        if (!sourceA.extractedText || sourceA.extractedText.length < 50 || !sourceB.extractedText || sourceB.extractedText.length < 50) {
            alert("One or both selected documents appear to have no extracted text. Please check the Data Source Manager.");
            setIsComparing(false);
            return;
        }

        try {
            const headers: HeadersInit = { 'Content-Type': 'application/json' };
            if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true' && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
            }

            // Find associated traces for Source A
            const tracesA = sources.filter(s => s.type === 'Trace' && s.policyId === sourceA.id);
            // Find associated traces for Source B
            const tracesB = sources.filter(s => s.type === 'Trace' && s.policyId === sourceB.id);

            const controller = new AbortController();
            const timeoutId = setTimeout(() => controller.abort(), 300000); // 5m Client Timeout (Max safe limit)

            const response = await fetch('/api/analyze', {
                method: 'POST',
                headers: headers,
                body: JSON.stringify({
                    analysisMode: 'comparison',
                    sourceA: {
                        title: sourceA.title,
                        text: sourceA.extractedText?.substring(0, 15000) || '', // [MAX] Increased to 15k context
                        // [NEW] Inject Assemblage Narrative if available (Provenance)
                        assemblageNarrative: assemblageA?.impactNarrative?.summary?.substring(0, 2000), // Increased narrative
                        assemblageActors: assemblageA?.nodes?.slice(0, 10).map(n => ({ name: n.name, type: n.type, description: n.description })) || [], // Top 10
                        traces: tracesA.slice(0, 3).map(t => ({ // Top 3 traces
                            title: t.title,
                            description: t.description,
                            extractedText: t.extractedText?.substring(0, 1000)
                        }))
                    },
                    sourceB: {
                        title: sourceB.title,
                        text: sourceB.extractedText?.substring(0, 15000) || '', // [MAX] Increased to 15k context
                        // [NEW] Inject Assemblage Narrative if available (Provenance)
                        assemblageNarrative: assemblageB?.impactNarrative?.summary?.substring(0, 2000),
                        assemblageActors: assemblageB?.nodes?.slice(0, 10).map(n => ({ name: n.name, type: n.type, description: n.description })) || [],
                        traces: tracesB.slice(0, 3).map(t => ({
                            title: t.title,
                            description: t.description,
                            extractedText: t.extractedText?.substring(0, 1000)
                        }))
                    },
                    force: forceRefresh,
                    checkCacheOnly: isReadOnly // Demo users can only load cached analyses
                }),
                signal: controller.signal
            });

            clearTimeout(timeoutId);

            const data = await response.json();
            if (data.success && data.analysis) {
                setComparisonResult(data.analysis);

                // [NEW] Persist to Server Storage (Permanent)
                try {
                    const headers: HeadersInit = { 'Content-Type': 'application/json' };
                    if (isReadOnly && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                        headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
                    } else if (localStorage.getItem('x-workspace-id')) {
                        headers['x-workspace-id'] = localStorage.getItem('x-workspace-id') || '';
                    }

                    const cacheKey = `synthesis:${sourceA.id}:${sourceB.id}`;
                    await fetch('/api/storage', {
                        method: 'POST',
                        headers,
                        body: JSON.stringify({
                            key: cacheKey,
                            value: data.analysis
                        })
                    });
                } catch (err) {
                    console.error("Failed to persist synthesis results:", err);
                }

            } else {
                if (isReadOnly && !data.fromCache) {
                    alert("No cached analysis found for this comparison. Sign in to run new analyses.");
                } else {
                    alert("Comparison failed: " + (data.error || "Unknown error"));
                }
            }
        } catch (error: unknown) {
            console.error("Comparison error:", error);
            const err = error as Error;
            if (err.name === 'AbortError') {
                alert("Analysis timed out (60s limit). The documents may be too large or the AI service is busy. Please try again.");
            } else {
                alert("Failed to generate comparison. " + (err.message || ""));
            }
        } finally {
            setIsComparing(false);
        }
    };

    // [REMOVED] handleEcosystemMap logic - Moved to EcosystemPage (Separation of Concerns)

    if (isLoading) {
        return (
            <div className="flex items-center justify-center h-64">
                <Loader2 className="h-8 w-8 animate-spin text-slate-400" />
            </div>
        );
    }

    return (
        <div className="space-y-8">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-3xl font-bold tracking-tight text-slate-900">Cross-Case Analysis</h2>
                    <p className="text-slate-500">Comparative analysis of AI governance frameworks using the Decolonial Situatedness Framework.</p>
                </div>
                <Button
                    onClick={handleExport}
                    className="bg-slate-900 text-white hover:bg-slate-800"
                    disabled={isExporting || isReadOnly}
                    title={isReadOnly ? "Export disabled in Demo Mode" : ""}
                >
                    <FileDown className="mr-2 h-4 w-4" />
                    {isExporting ? "Generating PDF..." : "Export Report"}
                </Button>
            </div>

            <Card className="bg-gradient-to-br from-slate-50 to-blue-50 border-slate-200">
                <CardHeader>
                    <CardTitle>Executive Summary</CardTitle>
                    <CardDescription>Key insights from the comparative analysis</CardDescription>
                </CardHeader>
                <CardContent className="space-y-3 text-sm text-slate-700 leading-relaxed">
                    <p>
                        This synthesis compares governance frameworks to identify patterns of convergence, divergence, and coloniality. By applying the Decolonial Situatedness Framework, we analyze how different jurisdictions approach risk, governance, rights, and territorial scope.
                    </p>
                    <p>
                        <strong>Convergence:</strong> Identification of shared regulatory mechanisms, definitions, and risk classifications across frameworks.
                    </p>
                    <p>
                        <strong>Divergence:</strong> Analysis of distinct approaches to enforcement, rights protections, and institutional design that reflect local contexts.
                    </p>
                    <p>
                        <strong>Colonial Patterns:</strong> Examination of potential legal transplants, extraterritorial effects, and the imposition of Global North epistemologies.
                    </p>
                    <p>
                        <strong>Decolonial Potential:</strong> Highlighting opportunities for epistemic autonomy, local adaptation, and resistance to hegemonic norms.
                    </p>
                </CardContent>
            </Card>

            {/* AI-Powered Comparison */}
            {analyzedSources.length >= 2 && (
                <Card className="border-purple-200">
                    <CardHeader>
                        <div className="flex items-center gap-2">
                            <Brain className="h-5 w-5 text-purple-600" />
                            <CardTitle>AI-Powered Framework Comparison</CardTitle>
                        </div>
                        <CardDescription>
                            Compare two policy documents to identify convergence, divergence, and colonial patterns
                        </CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <label className="text-sm font-medium text-slate-700">Source A</label>
                                <select
                                    className="w-full p-2 border rounded-md text-sm"
                                    value={sourceA?.id || ""}
                                    onChange={(e) => {
                                        const source = analyzedSources.find(s => s.id === e.target.value);
                                        updateSelection(source || null, sourceB);
                                    }}
                                >
                                    <option value="">Select first document...</option>
                                    {analyzedSources.map(s => (
                                        <option key={s.id} value={s.id} disabled={s.id === sourceB?.id}>
                                            {s.title} {s.id === sourceB?.id ? "(Selected as Source B)" : ""}
                                        </option>
                                    ))}
                                </select>
                            </div>
                            <div className="space-y-2">
                                <label className="text-sm font-medium text-slate-700">Source B</label>
                                <select
                                    className="w-full p-2 border rounded-md text-sm"
                                    value={sourceB?.id || ""}
                                    onChange={(e) => {
                                        const source = analyzedSources.find(s => s.id === e.target.value);
                                        updateSelection(sourceA, source || null);
                                    }}
                                >
                                    <option value="">Select second document...</option>
                                    {analyzedSources.map(s => (
                                        <option key={s.id} value={s.id} disabled={s.id === sourceA?.id}>
                                            {s.title} {s.id === sourceA?.id ? "(Selected as Source A)" : ""}
                                        </option>
                                    ))}
                                </select>
                            </div>
                        </div>
                        <div className="flex gap-2">
                            <div className="flex flex-col gap-2 w-full">
                                <Button
                                    onClick={() => handleCompare(false)}
                                    disabled={!sourceA || !sourceB || isComparing}
                                    className="w-full bg-slate-900 text-white hover:bg-slate-800 disabled:opacity-50 disabled:cursor-not-allowed"
                                    title={isReadOnly ? "Load cached analysis (demo mode)" : (!sourceA || !sourceB) ? "Please select two documents to compare" : "Run comparison"}
                                >
                                    {isComparing ? (
                                        <>
                                            <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                            Analyzing...
                                        </>
                                    ) : (
                                        <>
                                            <Sparkles className="mr-2 h-4 w-4" />
                                            {isReadOnly ? "Load Cached Analysis" : "Compare Frameworks"}
                                        </>
                                    )}
                                </Button>
                                {(!sourceA || !sourceB) && (
                                    <p className="text-xs text-center text-slate-500">
                                        Select two documents above to enable comparison.
                                    </p>
                                )}
                            </div>
                            {comparisonResult && (
                                <Button
                                    onClick={() => handleCompare(true)}
                                    disabled={isComparing || isReadOnly}
                                    variant="outline"
                                    title={isReadOnly ? "Sign in to regenerate" : "Force Regenerate (Bypass Cache)"}
                                    className="shrink-0"
                                >
                                    <RefreshCw className={`mr-2 h-4 w-4 ${isComparing ? 'animate-spin' : ''}`} />
                                    Regenerate
                                </Button>

                            )}
                        </div>

                        {/* [NEW] Preflight Warning / Deep Link */}
                        {sourceA && !sessionStorage.getItem(`assemblage_export_${sourceA.id}`) && (
                            <div className="bg-amber-50 border border-amber-200 text-amber-800 px-3 py-2 rounded text-xs flex items-center justify-between">
                                <span>⚠️ Missing Assemblage Analysis for Source A ({sourceA.title}). Comparison will lack provenance.</span>
                                {!isReadOnly ? (
                                    <a
                                        href={`/ecosystem?returnTo=synthesis&mode=auto-generate&sourceId=${sourceA.id}`} // Deep Link
                                        className="font-bold underline hover:text-amber-900"
                                    >
                                        Analyze in Ecosystem
                                    </a>
                                ) : (
                                    <span className="font-bold text-slate-400 cursor-not-allowed" title="Analysis disabled in Demo Mode">Analyze in Ecosystem</span>
                                )}
                            </div>
                        )}
                        {sourceB && !sessionStorage.getItem(`assemblage_export_${sourceB.id}`) && (
                            <div className="bg-amber-50 border border-amber-200 text-amber-800 px-3 py-2 rounded text-xs flex items-center justify-between">
                                <span>⚠️ Missing Assemblage Analysis for Source B ({sourceB.title}). Comparison will lack provenance.</span>
                                {!isReadOnly ? (
                                    <a
                                        href={`/ecosystem?returnTo=synthesis&mode=auto-generate&sourceId=${sourceB.id}`} // Deep Link
                                        className="font-bold underline hover:text-amber-900"
                                    >
                                        Analyze in Ecosystem
                                    </a>
                                ) : (
                                    <span className="font-bold text-slate-400 cursor-not-allowed" title="Analysis disabled in Demo Mode">Analyze in Ecosystem</span>
                                )}
                            </div>
                        )}

                        {comparisonResult && (
                            <div className="mt-8 space-y-6 pt-4 border-t">
                                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 min-h-[800px] lg:min-h-[600px]">
                                    {/* PRIMARY: FORCE GRAPH */}
                                    {comparisonResult.assemblage_network && comparisonResult.assemblage_network.nodes.length > 0 ? (
                                        <div className="col-span-1 lg:col-span-1 h-full min-h-[400px]">
                                            <ComparisonNetworkGraph
                                                networkData={comparisonResult.assemblage_network}
                                                comparisonId={`${sourceA?.id}-${sourceB?.id}`}
                                            />
                                        </div>
                                    ) : (
                                        <div className="col-span-1 lg:col-span-1 h-full min-h-[400px] flex items-center justify-center border-2 border-dashed rounded-lg bg-slate-50">
                                            <p className="text-sm text-slate-500">No assemblage network data generated.</p>
                                        </div>
                                    )}

                                    {/* SECONDARY: RELATIONAL TOPOLOGY */}
                                    <div className="col-span-1 lg:col-span-1 h-full min-h-[400px]">
                                        <RelationalAxisMap
                                            key={`${sourceA?.id}-${sourceB?.id}-topology`}
                                            topology={comparisonResult.topology_analysis}
                                            sourceAName={sourceA?.title || "Source A"}
                                            sourceBName={sourceB?.title || "Source B"}
                                        />
                                    </div>
                                </div>
                            </div>
                        )}
                    </CardContent>
                </Card>
            )
            }

            {/* Synthesis Matrix */}
            <div>
                <h3 className="text-xl font-semibold text-slate-900 mb-4">Synthesis Framework</h3>

                {comparisonResult ? (
                    // Show AI-generated comparison results
                    <div className="grid gap-4">
                        {Object.entries(comparisonResult)
                            .filter(([key]) => !EXCLUDED_KEYS.has(key))
                            .filter(([_, value]) => isSynthesisSection(value))
                            .map(([key, value]) => {
                                const typedValue = value as ComparisonResult["risk"];
                                const finding = SYNTHESIS_FINDINGS.find(f => f.key === key);
                                const Icon = finding?.icon || AlertCircle;
                                return (
                                    <Card key={key}>
                                        <CardHeader>
                                            <div className="flex items-center gap-2">
                                                <Icon className="h-5 w-5 text-slate-600" />
                                                <CardTitle>{finding?.dimension || key}</CardTitle>
                                            </div>
                                        </CardHeader>
                                        <CardContent className="space-y-3">
                                            <div className="p-3 bg-green-50 rounded-lg border border-green-200">
                                                <p className="text-xs font-bold text-green-700 uppercase mb-1">Convergence</p>
                                                <p className="text-sm text-slate-700">{typedValue.convergence}</p>
                                            </div>
                                            <div className="p-3 bg-blue-50 rounded-lg border border-blue-200">
                                                <p className="text-xs font-bold text-blue-700 uppercase mb-1">Divergence</p>
                                                <p className="text-sm text-slate-700">{typedValue.divergence}</p>
                                            </div>
                                            <div className="p-3 bg-red-50 rounded-lg border border-red-200">
                                                <p className="text-xs font-bold text-red-700 uppercase mb-1">Coloniality</p>
                                                <p className="text-sm text-slate-700">{typedValue.coloniality}</p>
                                            </div>
                                            <div className="p-3 bg-purple-50 rounded-lg border border-purple-200">
                                                <p className="text-xs font-bold text-purple-700 uppercase mb-1">Resistance</p>
