import React from 'react';
import { BlindSpot } from '@/types';
import { LegacyBlindSpot } from './LegacyBlindSpot';
import { BasicBlindSpotCard } from './BasicBlindSpotCard';
import { EnhancedBlindSpotCard } from './EnhancedBlindSpotCard';
import { isBlindSpotString, isBlindSpotBasic, isBlindSpotEnhanced, isBlindSpotInteractive } from '@/utils/blindSpotHelpers';

interface BlindSpotRendererProps {
    spot: BlindSpot;
    index: number;
    onReAnalyze?: (spotId: string) => void;
    onMarkAddressed?: (spotId: string) => void;
}

/**
 * Smart renderer that detects blind spot tier and routes to appropriate component
 * Supports progressive enhancement from Tier 0 (string) to Tier 3 (interactive)
 */
export function BlindSpotRenderer({ spot, index, onReAnalyze, onMarkAddressed }: BlindSpotRendererProps) {
    // Tier 0: Legacy string
    if (isBlindSpotString(spot)) {
        return <LegacyBlindSpot text={spot} index={index} />;
    }

    // Tier 3: Interactive
    if (isBlindSpotInteractive(spot)) {
        return (
            <EnhancedBlindSpotCard
                spot={spot}
                onReAnalyze={onReAnalyze}
                onMarkAddressed={onMarkAddressed}
            />
        );
    }

    // Tier 2: Enhanced
    if (isBlindSpotEnhanced(spot)) {
        return <EnhancedBlindSpotCard spot={spot} />;
    }

    // Tier 1: Basic
    if (isBlindSpotBasic(spot)) {
        return <BasicBlindSpotCard spot={spot} />;
    }

    // Fallback to legacy for unknown types
    return <LegacyBlindSpot text={(spot as any).title || 'Unknown blind spot'} index={index} />;
}

"use client";

import React, { useEffect, useRef, useState, useCallback } from "react";
import * as d3 from "d3";
import { AbstractMachineAnalysis } from "@/types";
import { diffAbstractMachines } from "./abstractMachineDiff";
import { Focus, ZoomIn, ZoomOut, Maximize2, Minimize2 } from "lucide-react";

const CANVAS_W = 2000;
const CANVAS_H = 1200;

const ARCH_ORDER = ["STRATIFY", "BAN", "CAPTURE", "GATE", "GOVERN", "HUMANIZE", "EQUALIZE", "REMEDY", "ENFORCE", "UPDATE"];
const ARCH_X = Object.fromEntries(ARCH_ORDER.map((a, i) => [a, (i + 1) / (ARCH_ORDER.length + 1)]));

function archetypeForOperator(opName: string) {
    const n = (opName || "").toLowerCase();
    if (n.includes("classify")) return "STRATIFY";
    if (n.includes("ban") || n.includes("prohibit")) return "BAN";
    if (n.includes("inventory") || n.includes("register")) return "CAPTURE";
    if (n.includes("evaluation") || n.includes("gate")) return "GATE";
    if (n.includes("lifecycle") || n.includes("govern")) return "GOVERN";
    if (n.includes("human") || n.includes("supervision") || n.includes("explanation") || n.includes("contest")) return "HUMANIZE";
    if (n.includes("discrimination") || n.includes("bias") || n.includes("fairness")) return "EQUALIZE";
    if (n.includes("liability") || n.includes("compensation")) return "REMEDY";
    if (n.includes("sanction") || n.includes("supervise") || n.includes("enforce")) return "ENFORCE";
    if (n.includes("reclass") || n.includes("update")) return "UPDATE";
    return "GOVERN";
}

function normalizeMachine(model: AbstractMachineAnalysis | undefined) {
    if (!model) return { diagram: { operators: [], constraints: [], transformations: [] } };
    return {
        ...model,
        diagram: {
            ...model.diagram,
            operators: model.diagram?.operators || [],
            constraints: model.diagram?.constraints || [],
            transformations: model.diagram?.transformations || []
        }
    };
}

function buildMergedGraph(leftRaw: AbstractMachineAnalysis, rightRaw: AbstractMachineAnalysis) {
    const left = normalizeMachine(leftRaw);
    const right = normalizeMachine(rightRaw);

    // Use the existing fuzzy diff logic to categorize shared vs unique
    // diffAbstractMachines expects AbstractMachineStub, which matches our normalized shape
    const diffTokens = diffAbstractMachines(left as any, right as any);

    // D3 Arrays
    const nodes: any[] = [];
    const links: any[] = [];
    const byId = new Map<string, any>();

    const addNode = (id: string, kind: string, label: string, sourceMeta: { group: "shared" | "fuzzy_shared" | "left" | "right", fuzzyContext?: string }, meta = {}) => {
        const { group, fuzzyContext } = sourceMeta;
        if (byId.has(id)) {
            const n = byId.get(id);
            // If already added as left/right, and we see it in the other, upgrade it
            if (n.sourceGroup !== "shared" && n.sourceGroup !== group) {
                // If one is shared, it wins. If one is fuzzy_shared, it wins over left/right.
                if (group === "shared") {
                    n.sourceGroup = "shared";
                    delete n.fuzzyContext; // Clear fuzzy context if it becomes exact shared
                } else if (group === "fuzzy_shared" && n.sourceGroup !== "shared") {
                    n.sourceGroup = "fuzzy_shared";
                    if (fuzzyContext) n.fuzzyContext = fuzzyContext;
                }
            }
            return n;
        }
        const n = { id, kind, label, sourceGroup: group, fuzzyContext, ...meta };
        byId.set(id, n);
        nodes.push(n);
        return n;
    };

    const determineSource = (label: string, shardList: any[], defaultSrc: "left" | "right"): { group: "shared" | "fuzzy_shared" | "left" | "right", fuzzyContext?: string } => {
        if (!label) return { group: defaultSrc };
        const normalized = label.toLowerCase();

        for (const s of shardList) {
            const sNorm = s.toLowerCase();
            if (sNorm === normalized) {
                return { group: "shared" };
            }
            if (sNorm.includes("(≈")) {
                const parts = sNorm.split("(≈");
                const leftPart = parts[0].trim();
                const rightPart = parts[1].replace(")", "").trim();
                if (leftPart === normalized || rightPart === normalized || normalized.includes(leftPart) || leftPart.includes(normalized)) {
                    return { group: "fuzzy_shared", fuzzyContext: s };
                }
            } else if (normalized.includes(sNorm) || sNorm.includes(normalized)) {
                return { group: "fuzzy_shared", fuzzyContext: `Matched by '${s}'` };
            }
        }
        return { group: defaultSrc };
    };

    // 1. Operators
    const lOps = left.diagram.operators;
    const rOps = right.diagram.operators;

    const archCounts = new Map();
    [...lOps, ...rOps].forEach(op => {
        const arch = archetypeForOperator(op.name);
        archCounts.set(arch, (archCounts.get(arch) || 0) + 1);
    });

    const archIndex = new Map();

    const diffOps = diffAbstractMachines(left as any, right as any);

    const indexOp = (op: any, defaultGroup: "left" | "right") => {
        const arch = archetypeForOperator(op.name);
        const idx = archIndex.get(arch) || 0;
        archIndex.set(arch, idx + 1);
        const total = archCounts.get(arch) || 1;
        const baseX = ARCH_X[arch] ?? 0.5;
        const xOffset = total === 1 ? 0 : ((idx / (total - 1)) - 0.5) * 0.15;

        const srcMeta = determineSource(op.name, diffOps.sharedSpine, defaultGroup);
        const opId = srcMeta.group === "shared" || srcMeta.group === "fuzzy_shared" ? `op:${srcMeta.group}:${arch}-${idx}` : `op:${op.name}`;

        addNode(opId, "operator", op.name, srcMeta, {
            archetype: arch,
            xTargetFrac: Math.max(0.05, Math.min(0.95, baseX + xOffset)),
            definition: op.definition
        });

        // Connect tokens
        for (const t of (op.inputs || [])) {
            const tokId = `tok:${String(t).toLowerCase().replace(/\s+/g, '-')}`;
            addNode(tokId, "token", String(t), srcMeta, { xTargetFrac: 0.2 });
            links.push({ source: tokId, target: opId, kind: "input", sourceGroup: srcMeta.group, label: String(t) });
        }
        for (const t of (op.outputs || [])) {
            const tokId = `tok:${String(t).toLowerCase().replace(/\s+/g, '-')}`;
            addNode(tokId, "token", String(t), srcMeta, { xTargetFrac: 0.8 });
            links.push({ source: opId, target: tokId, kind: "output", sourceGroup: srcMeta.group, label: String(t) });
        }
    };

    lOps.forEach(op => indexOp(op, "left"));
    rOps.forEach(op => indexOp(op, "right"));

    // 2. Constraints
    const indexCon = (c: any, defaultGroup: "left" | "right") => {
        const ruleName = String(c.rule || c);
        const srcMeta = determineSource(ruleName, diffOps.sharedSpine, defaultGroup);
        const cId = srcMeta.group === "shared" || srcMeta.group === "fuzzy_shared" ? `cons:${srcMeta.group}:${ruleName.slice(0, 10)}` : `cons:${ruleName}`;

        addNode(cId, "constraint", ruleName, srcMeta, { xTargetFrac: 0.5 });

        const targetOps = defaultGroup === "left" ? lOps : rOps;
        for (const op of targetOps) {
            const matchingOpNode = nodes.find(n => n.kind === "operator" && (n.label === op.name || (n.sourceGroup.includes("shared") && (n.label.includes(op.name) || op.name.includes(n.label)))));
            if (matchingOpNode) {
                links.push({ source: cId, target: matchingOpNode.id, kind: "constraint", sourceGroup: srcMeta.group, label: ruleName });
            }
        }
    };

    left.diagram.constraints.forEach(c => indexCon(c, "left"));
    right.diagram.constraints.forEach(c => indexCon(c, "right"));

    return { nodes, links };
}

function renderMergedGraphSvg(
    svgEl: SVGSVGElement,
    leftMachine: AbstractMachineAnalysis,
    rightMachine: AbstractMachineAnalysis,
    W: number,
    H: number,
    tooltipEl: HTMLDivElement | null,
    filters: { shared: boolean, fuzzy_shared: boolean, left: boolean, right: boolean }
) {
    const svg = d3.select(svgEl);
    svg.selectAll("*").remove();
    svg.attr("viewBox", `0 0 ${W} ${H}`);

    const raw = buildMergedGraph(leftMachine, rightMachine);

    // Filter out disabled node categories BEFORE pushing to force sim
    const nodes = raw.nodes.filter(n => (filters as any)[n.sourceGroup]);
    const allowedNodeIds = new Set(nodes.map(n => n.id));

    // Filter links - ensure sourceGroup is enabled AND both endpoints still exist
    const links = raw.links.filter(l => (filters as any)[l.sourceGroup] && allowedNodeIds.has(l.source) && allowedNodeIds.has(l.target));

    const isDarkMode = document.documentElement.classList.contains('dark');
    const labelColor = isDarkMode ? '#cbd5e1' : '#475569';
    const strokeColor = isDarkMode ? '#475569' : '#94a3b8';

    const defs = svg.append("defs");
    const zoomGroup = svg.append("g").attr("class", "d3-zoom-group");

    const zoomBehavior = d3.zoom()
        .scaleExtent([0.1, 4])
        .on("zoom", (e) => {
            zoomGroup.attr("transform", e.transform);
        });
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    svg.call(zoomBehavior as any);
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    svg.call((zoomBehavior as any).transform, d3.zoomIdentity.translate(50, 50).scale(0.8));

    const filter = defs.append("filter")
        .attr("id", "drop-shadow-merged")
        .attr("width", "150%")
        .attr("height", "150%");
    filter.append("feDropShadow")
        .attr("dx", "0")
        .attr("dy", "3")
        .attr("stdDeviation", "4")
        .attr("flood-opacity", isDarkMode ? "0.4" : "0.15");

    const arrowGroups = ["shared", "fuzzy_shared", "left", "right"];
    const arrowColors = {
        shared: isDarkMode ? "#0f766e" : "#0d9488", // Teal
        fuzzy_shared: isDarkMode ? "#8b5cf6" : "#7c3aed", // Violet for fuzzy matches
        left: isDarkMode ? "#1e3a8a" : "#2563eb",   // Blue
        right: isDarkMode ? "#9a3412" : "#ea580c"   // Orange
    };

    defs.selectAll("marker")
        .data(arrowGroups)
        .join("marker")
        .attr("id", d => `merged-arrow-${d}`)
        .attr("viewBox", "0 -5 10 10")
        .attr("refX", 18)
        .attr("refY", 0)
        .attr("markerWidth", 6)
        .attr("markerHeight", 6)
        .attr("orient", "auto")
        .append("path")
        .attr("d", "M0,-5L10,0L0,5")
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        .attr("fill", (d: any) => (arrowColors as any)[d] || strokeColor);

    function laneY(d: any) {
        if (d.kind === "constraint") return H * 0.15;
        if (d.kind === "operator") return H * 0.50;
        return H * 0.85;
    }

    svg.append("text").attr("class", "text-xs font-bold").attr("fill", labelColor).attr("x", 14).attr("y", H * 0.12).text("Global Constraints");
    svg.append("text").attr("class", "text-xs font-bold").attr("fill", labelColor).attr("x", 14).attr("y", H * 0.42).text("Operators (Shared Spine = Teal)");
    svg.append("text").attr("class", "text-xs font-bold").attr("fill", labelColor).attr("x", 14).attr("y", H * 0.72).text("Tokens (Inputs/Outputs)");

    const link = zoomGroup.append("g")
        .selectAll("path")
        .data(links)
        .join("path")
        .attr("fill", "none")
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        .attr("stroke", (d: any) => (arrowColors as any)[d.sourceGroup] || strokeColor)
        .attr("stroke-width", 2)
        .attr("stroke-opacity", 0.7)
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        .attr("stroke-dasharray", (d: any) => d.kind === "constraint" ? "5,5" : null)
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        .attr("marker-end", (d: any) => `url(#merged-arrow-${d.sourceGroup})`);

    const g = zoomGroup.append("g").selectAll("g")
        .data(nodes)
        .join("g")
        .attr("class", "cursor-pointer transition-opacity duration-200");

    const categoryColors = {
        shared: { fill: isDarkMode ? '#ccfbf1' : '#b0f6ef', stroke: isDarkMode ? '#0f766e' : '#0d9488', text: isDarkMode ? '#134e4a' : '#115e59' }, // Teal
        fuzzy_shared: { fill: isDarkMode ? '#ede9fe' : '#ddd6fe', stroke: isDarkMode ? '#8b5cf6' : '#7c3aed', text: isDarkMode ? '#4c1d95' : '#4c1d95' }, // Violet
        left: { fill: isDarkMode ? '#dbeafe' : '#bfdbfe', stroke: isDarkMode ? '#1e3a8a' : '#2563eb', text: isDarkMode ? '#1e3a8a' : '#1d4ed8' }, // Blue
        right: { fill: isDarkMode ? '#ffedd5' : '#fed7aa', stroke: isDarkMode ? '#9a3412' : '#ea580c', text: isDarkMode ? '#7c2d12' : '#9a3412' } // Orange
    };

    g.each(function (d) {
        const sel = d3.select(this);
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const groupC = (categoryColors as any)[(d as any).sourceGroup] || categoryColors.shared;

        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        if ((d as any).kind === "operator") {
            sel.append("rect").attr("rx", 6).attr("ry", 6).attr("x", -70).attr("y", -18).attr("width", 140).attr("height", 36)
                .attr("stroke", groupC.stroke).attr("stroke-width", 2).attr("fill", groupC.fill).attr("filter", "url(#drop-shadow-merged)");
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
        } else if ((d as any).kind === "constraint") {
            const r = 22;
            const pts = d3.range(6).map(i => {
                const MathPI = Math.PI;
                const a = (MathPI / 3) * i - MathPI / 6;
                return [r * Math.cos(a), r * Math.sin(a)];
            });
            sel.append("polygon").attr("points", pts.map(p => p.join(",")).join(" "))
                .attr("stroke", groupC.stroke).attr("stroke-width", 2).attr("fill", groupC.fill).attr("filter", "url(#drop-shadow-merged)");
        } else {
            sel.append("circle").attr("r", 14).attr("stroke", groupC.stroke).attr("stroke-width", 2).attr("fill", groupC.fill).attr("stroke-dasharray", (d as any).sourceGroup === "fuzzy_shared" ? "4,2" : null);
        }

        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const isExternalLabel = ((d as any).kind === "constraint" || (d as any).kind === "token");

        sel.append("text")
            .attr("text-anchor", "middle")
            .attr("dy", isExternalLabel ? "2.6em" : "0.35em")
            .attr("font-size", isExternalLabel ? 9 : 10)
            .attr("fill", isExternalLabel ? labelColor : groupC.text)
            .style("pointer-events", "none")
            .style("font-weight", isExternalLabel ? "400" : "600")
            .text(() => {
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                const safeD = d as any;
                let s = "";
                if (safeD.kind === "operator") {
                    s = safeD.label + "()";
                    s = s.length > 22 ? s.slice(0, 22) + "…" : s;
                } else {
                    s = safeD.label || "";
                    s = s.length > 28 ? s.slice(0, 28) + "…" : s;
                }
                return safeD.sourceGroup === "fuzzy_shared" ? `⚠️ ${s}` : s;
            });
    });

    const sim = d3.forceSimulation(nodes)
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        .force("link", d3.forceLink(links).id((d: any) => d.id)
            .distance(120)
            .strength(0.3)
        )
        .force("charge", d3.forceManyBody().strength(-300))
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        .force("collide", d3.forceCollide().radius((d: any) => {
            if (d.kind === "operator") return 80;
            if (d.kind === "constraint") return 45;
            return 35;
        }).iterations(3))
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        .force("x", d3.forceX(d => ((d as any).xTargetFrac ?? 0.5) * W).strength(0.3))

        .force("y", d3.forceY(d => laneY(d)).strength(0.6))
        .alphaDecay(0.02);

    const drag = d3.drag<any, any>()
        .on("start", (event, d) => {
            if (!event.active) sim.alphaTarget(0.3).restart();
            d.fx = d.x;
            d.fy = d.y;
        })
        .on("drag", (event, d) => {
            d.fx = event.x;
            d.fy = event.y;
        })
        .on("end", (event, d) => {
            if (!event.active) sim.alphaTarget(0);
            d.fx = null;
            d.fy = null;
        });

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    g.call(drag as any);

    const dfMap = new Map();
    links.forEach(l => {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const sId = typeof l.source === "string" ? l.source : (l.source as any).id;
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const tId = typeof l.target === "string" ? l.target : (l.target as any).id;
        if (!dfMap.has(sId)) dfMap.set(sId, new Set());
        if (!dfMap.has(tId)) dfMap.set(tId, new Set());
        dfMap.get(sId).add(tId);
        dfMap.get(tId).add(sId);
    });

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    g.on("mouseenter", (event, d: any) => {
        const related = dfMap.get(d.id) || new Set();
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        g.style("opacity", (n: any) => n.id === d.id || related.has(n.id) ? 1 : 0.15);
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        link.style("opacity", (l: any) => {
            const ls = typeof l.source === "string" ? l.source : l.source.id;
            const lt = typeof l.target === "string" ? l.target : l.target.id;
            return (ls === d.id || related.has(ls)) && (lt === d.id || related.has(lt)) ? 1 : 0.15;
        });
        if (tooltipEl) {
            tooltipEl.style.opacity = "1";
            const isFuzzy = d.sourceGroup === "fuzzy_shared";
            let html = `<div class="font-bold mb-1 dark:text-slate-100 ${isFuzzy ? 'text-violet-600 dark:text-violet-400 flex items-center gap-1' : ''}">${isFuzzy ? '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="m21.73 18-8-14a2 2 0 0 0-3.48 0l-8 14A2 2 0 0 0 4 21h16a2 2 0 0 0 1.73-3Z"/><path d="M12 9v4"/><path d="M12 17h.01"/></svg>' : ''} ${d.label}</div>`;
            if (d.kind === "operator") {
                html += `<div class="text-slate-600 dark:text-slate-400 mb-1 leading-tight">${d.definition || ""}</div>`;
            }
            if (isFuzzy && d.fuzzyContext) {
                html += `<div class="text-violet-700 bg-violet-50 dark:bg-violet-900/30 p-2 rounded text-[10px] my-2 leading-relaxed italic border border-violet-100 dark:border-violet-800">Possible match: ${d.fuzzyContext}</div>`;
            }
            let prettyGroup = d.sourceGroup;
            if (prettyGroup === "fuzzy_shared") prettyGroup = "fuzzy match";
            html += `<div class="text-xs text-slate-500 uppercase tracking-widest mt-1">${d.kind} · <span style="color: ${(categoryColors as any)[d.sourceGroup].stroke}">${prettyGroup}</span></div>`;
            tooltipEl.innerHTML = html;
        }
    })
        .on("mousemove", (event) => {
            if (tooltipEl) {
                let left = event.clientX + 15;
                const top = event.clientY + 15;
                if (left + 300 > window.innerWidth) left = window.innerWidth - 320;
                tooltipEl.style.left = left + "px";
                tooltipEl.style.top = top + "px";
            }
        })
        .on("mouseleave", () => {
            g.style("opacity", 1);
            link.style("opacity", 1);
            if (tooltipEl) tooltipEl.style.opacity = "0";
        });

    sim.on("tick", () => {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        link.attr("d", (d: any) => {
            const ls = d.source as any, lt = d.target as any;
            const dx = lt.x - ls.x, dy = lt.y - ls.y;
            const dr = Math.sqrt(dx * dx + dy * dy) * 1.15;
            return `M${ls.x},${ls.y}A${dr},${dr} 0 0,1 ${lt.x},${lt.y}`;
        });
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        g.attr("transform", (d: any) => `translate(${d.x},${d.y})`);
    });

    return { sim, zoom: zoomBehavior };
}

export function ComparativeAssemblageD3({ leftMachine, rightMachine }: { leftMachine: AbstractMachineAnalysis, rightMachine: AbstractMachineAnalysis }) {
    const svgRef = useRef<SVGSVGElement>(null);
    const tooltipRef = useRef<HTMLDivElement>(null);
    const zoomFnRef = useRef<d3.ZoomBehavior<Element, unknown> | null>(null);

    const [filters, setFilters] = useState({
        shared: true,
        fuzzy_shared: true,
        left: true,
        right: true
    });

    useEffect(() => {
        const svgElement = svgRef.current;
        let sim: d3.Simulation<d3.SimulationNodeDatum, undefined> | null = null;
        if (svgElement && leftMachine && rightMachine) {
            const out = renderMergedGraphSvg(svgElement, leftMachine, rightMachine, CANVAS_W, CANVAS_H, tooltipRef.current, filters);
            sim = out.sim;
            zoomFnRef.current = out.zoom;
        }
        return () => {
            if (sim) sim.stop();
            if (svgElement) d3.select(svgElement).selectAll("*").remove();
        };
    }, [leftMachine, rightMachine, filters]);

    return (
        <div className="flex flex-col h-full w-full relative bg-slate-50 dark:bg-slate-950 overflow-hidden rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm">
            <div
                ref={tooltipRef}
                className="pointer-events-none fixed opacity-0 p-3 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl shadow-xl max-w-[420px] text-xs leading-relaxed z-[9999] transition-opacity duration-150"
            />

            <div className="absolute top-4 left-4 z-10 bg-white/90 dark:bg-slate-900/90 backdrop-blur-sm p-3 rounded-lg border border-slate-200 dark:border-slate-800 shadow-sm transition-all">
                <div className="text-sm font-bold text-slate-800 dark:text-slate-100 mb-2">Comparative Assemblage</div>
                <div className="flex flex-col gap-1.5 text-xs">
                    <button onClick={() => setFilters(f => ({ ...f, shared: !f.shared }))} className={`flex items-center gap-2 hover:bg-slate-100 dark:hover:bg-slate-800 p-1 -ml-1 rounded transition-opacity ${!filters.shared ? 'opacity-40 grayscale selection-none hover:bg-transparent' : ''}`}>
                        <div className="w-3 h-3 rounded-full bg-teal-100 border border-teal-600 shrink-0"></div><span className="text-slate-600 dark:text-slate-300 pointer-events-none">Shared Spine (OPPs)</span>
                    </button>
                    <button onClick={() => setFilters(f => ({ ...f, fuzzy_shared: !f.fuzzy_shared }))} className={`flex items-center gap-2 hover:bg-slate-100 dark:hover:bg-slate-800 p-1 -ml-1 rounded transition-opacity ${!filters.fuzzy_shared ? 'opacity-40 grayscale selection-none hover:bg-transparent' : ''}`}>
                        <div className="w-3 h-3 rounded-full bg-violet-100 border border-violet-600 shrink-0"></div><span className="text-slate-600 dark:text-slate-300 pointer-events-none">Possible Match</span>
                    </button>
                    <button onClick={() => setFilters(f => ({ ...f, left: !f.left }))} className={`flex items-center gap-2 hover:bg-slate-100 dark:hover:bg-slate-800 p-1 -ml-1 rounded transition-opacity ${!filters.left ? 'opacity-40 grayscale selection-none hover:bg-transparent' : ''}`}>
                        <div className="w-3 h-3 rounded-full bg-blue-100 border border-blue-600 shrink-0"></div><span className="text-slate-600 dark:text-slate-300 pointer-events-none">Left Machine Only</span>
                    </button>
                    <button onClick={() => setFilters(f => ({ ...f, right: !f.right }))} className={`flex items-center gap-2 hover:bg-slate-100 dark:hover:bg-slate-800 p-1 -ml-1 rounded transition-opacity ${!filters.right ? 'opacity-40 grayscale selection-none hover:bg-transparent' : ''}`}>
                        <div className="w-3 h-3 rounded-full bg-orange-100 border border-orange-600 shrink-0"></div><span className="text-slate-600 dark:text-slate-300 pointer-events-none">Right Machine Only</span>
                    </button>
                </div>
            </div>

            <div className="absolute top-4 right-4 z-10 flex gap-1 bg-white/90 dark:bg-slate-900/90 backdrop-blur-sm p-1 rounded-lg border border-slate-200 dark:border-slate-800 shadow-sm">
                <button
                    onClick={() => {
                        if (svgRef.current && zoomFnRef.current) {
                            const transform = d3.zoomIdentity.translate(50, 50).scale(0.8);
                            // eslint-disable-next-line @typescript-eslint/no-explicit-any
                            zoomFnRef.current.transform(d3.select(svgRef.current).transition().duration(500) as any, transform);
                        }
                    }}
                    className="p-1.5 text-slate-500 hover:text-slate-800 hover:bg-slate-100 rounded-md transition-colors"
                ><Focus className="w-4 h-4" /></button>
            </div>

            <div className="relative flex-1 bg-slate-50/50 dark:bg-slate-900/20 overflow-hidden cursor-grab active:cursor-grabbing">
                <svg ref={svgRef} className="block w-full h-full" />
            </div>
        </div>
    );
}

"use client";

import { useWorkspace } from "@/providers/WorkspaceProvider";
import React, { useEffect, useState, useCallback } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { AbstractMachineCompareD3 } from "./AbstractMachineCompareD3";
import { AbstractMachineAnalysis } from "@/types";
import { AlertCircle, ArrowLeftRight, ChevronRight, Layers, Network, Sparkles, Loader2 } from "lucide-react";
import Link from "next/link";
import { z } from "zod";
import { normalizeAbstractMachine } from "./abstractMachineNormalize";
import { diffAbstractMachines } from "./abstractMachineDiff";
import type { AICompareAbstractMachinesResponse } from "@/lib/prompts/compare-machines";
import { ComparisonDashboard } from "./ComparisonDashboard";

interface LightweightSource {
    id: string;
    title: string;
}

const urlSchema = z.object({
    left: z.string().optional(),
    right: z.string().optional(),
    view: z.enum(["dashboard", "machine", "strata", "state", "diff", "ai"]).catch("machine"),
});

export function CompareMachinesClient() {
    const router = useRouter();
    const searchParams = useSearchParams();
    const { currentWorkspaceId } = useWorkspace();

    // Parse URL Params safely
    const parsedParams = urlSchema.safeParse({
        left: searchParams.get("left") || undefined,
        right: searchParams.get("right") || undefined,
        view: searchParams.get("view") || "machine",
    });

    const leftId = parsedParams.success ? parsedParams.data.left : undefined;
    const rightId = parsedParams.success ? parsedParams.data.right : undefined;
    const viewMode = parsedParams.success ? parsedParams.data.view : "machine";

    const [sourcesList, setSourcesList] = useState<LightweightSource[]>([]);
    const [fullMachines, setFullMachines] = useState<Record<string, AbstractMachineAnalysis>>({});
    const [status, setStatus] = useState<"loading" | "error" | "ready" | "empty">("loading");

    // AI Analysis State
    const [aiReport, setAiReport] = useState<{ timestamp: number, comparison: AICompareAbstractMachinesResponse, model_name: string, schema_version?: number } | null>(null);
    const [isGeneratingAi, setIsGeneratingAi] = useState(false);
    const [aiError, setAiError] = useState<string | null>(null);
    const [analyzedIds, setAnalyzedIds] = useState<{ left?: string, right?: string }>({ left: leftId, right: rightId });

    // Sync AI Report state when the selected documents change
    if (analyzedIds.left !== leftId || analyzedIds.right !== rightId) {
        setAiReport(null);
        setAiError(null);
        setAnalyzedIds({ left: leftId, right: rightId });
    }

    const getHeaders = useCallback((base: HeadersInit = {}) => {
        const headers = { ...base } as Record<string, string>;
        if (currentWorkspaceId) {
            headers['x-workspace-id'] = currentWorkspaceId;
        }
        if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true') {
            headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID || 'demo-user';
        }
        return headers;
    }, [currentWorkspaceId]);

    // Fetch the lightweight list when workspace is ready
    useEffect(() => {
        // Wait until Workspace is initialized (handles both auth and demo states)
        if (!currentWorkspaceId && process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE !== 'true') return;

        let mounted = true;

        async function fetchList() {
            try {
                const res = await fetch("/api/sources/abstract-machines?list=true", {
                    headers: getHeaders()
                });
                if (!res.ok) throw new Error("Failed to fetch abstract machines list");

                const data: LightweightSource[] = await res.json();

                if (mounted) {
                    if (data.length === 0) {
                        setStatus("empty");
                    } else {
                        setSourcesList(data);
                        setStatus("ready");

                        // Auto-select latest two if URL params are empty
                        if (!leftId && !rightId && data.length >= 1) {
                            const newLeft = data[0].id;
                            const newRight = data.length > 1 ? data[1].id : undefined;

                            const params = new URLSearchParams(searchParams.toString());
                            params.set("left", newLeft);
                            if (newRight) params.set("right", newRight);

                            // Prevent full re-fetch spam by waiting a tick
                            requestAnimationFrame(() => {
                                router.replace(`?${params.toString()}`, { scroll: false });
                            });
                        }
                    }
                }
            } catch (err) {
                console.error("Error fetching machines list:", err);
                if (mounted) setStatus("error");
            }
        }

        fetchList();

        return () => { mounted = false; };
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [currentWorkspaceId, getHeaders]); // React to workspace ID changes

    // Fetch actual machine payloads when selection changes
    useEffect(() => {
        const idsToFetch = [leftId, rightId].filter(Boolean) as string[];
        const missingIds = idsToFetch.filter(id => fullMachines[id] === undefined);

        if (missingIds.length === 0) return; // Already have them cached

        let mounted = true;

        async function fetchMachines() {
            try {
                const res = await fetch(`/api/sources/abstract-machines?ids=${missingIds.join(',')}`, {
                    headers: getHeaders()
                });
                if (!res.ok) throw new Error("Failed to fetch full machines");

                const data: { id: string, abstract_machine: AbstractMachineAnalysis }[] = await res.json();

                if (mounted) {
                    setFullMachines(prev => {
                        const next = { ...prev };
                        missingIds.forEach(id => {
                            const found = data.find(item => item.id === id);
                            next[id] = found ? found.abstract_machine : (null as any);
                        });
                        return next;
                    });
                }
            } catch (err) {
                console.error("Error fetching full machine data:", err);
            }
        }

        fetchMachines();

        return () => { mounted = false; };
    }, [leftId, rightId, fullMachines, getHeaders]);

    // Optional: Auto-fetch AI report if we mount/switch to AI view and have both IDs
    const fetchAiAnalysis = React.useCallback(async (force = false) => {
        if (!leftId || !rightId) return;
        setIsGeneratingAi(true);
        setAiError(null);
        try {
            const isForce = force === true; // Enforce strict boolean so Zod doesn't fail on React Event objects
            const res = await fetch(`/api/analyze/compare-machines`, {
                method: "POST",
                headers: { ...getHeaders(), "Content-Type": "application/json" },
                body: JSON.stringify({ leftId, rightId, force: isForce })
            });
            if (!res.ok) {
                const errData = await res.json();
                throw new Error(errData.error || "Failed to generate AI analysis");
            }
            const data = await res.json();
            setAiReport(data);
        } catch (err: unknown) {
            setAiError(err instanceof Error ? err.message : String(err));
        } finally {
            setIsGeneratingAi(false);
        }
    }, [leftId, rightId, getHeaders]);

    // Refetch AI Analysis if we explicitly switch to the View and haven't fetched it yet
    React.useEffect(() => {
        let mounted = true;

        if ((viewMode === "ai" || viewMode === "dashboard") && leftId && rightId && !aiReport && !isGeneratingAi && !aiError) {
            // Prevent duplicate triggers by eagerly setting the loading state
            setIsGeneratingAi(true);

            fetchAiAnalysis().finally(() => {
                if (mounted) {
                    setIsGeneratingAi(false);
                }
            });
        }

        return () => { mounted = false; };
        // We INTENTIONALLY exclude `isGeneratingAi`, `aiReport`, `aiError` and `fetchAiAnalysis` from this hook's dependency array.
        // Including them causes React to infinitely cycle as the state resolves and triggers re-evaluations.
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [viewMode, leftId, rightId]);

    const handleParamChange = (key: "left" | "right" | "view", value: string) => {
        const params = new URLSearchParams(searchParams.toString());
        if (value) params.set(key, value);
        else params.delete(key);
        router.push(`?${params.toString()}`, { scroll: false });
    };

    // Prepare data directly for the renderer (Moved above conditional returns to satisfy Hooks rules)
    const leftMachine = leftId ? fullMachines[leftId] || null : null;
    const rightMachine = rightId ? fullMachines[rightId] || null : null;

    const leftTitle = sourcesList.find(s => s.id === leftId)?.title || "Unknown Document";
    const rightTitle = sourcesList.find(s => s.id === rightId)?.title || "Unknown Document";

    // Normalize and compute diff before conditionally returning
    const leftNorm = React.useMemo(() => (leftMachine ? normalizeAbstractMachine(leftMachine) : null), [leftMachine]);
    const rightNorm = React.useMemo(() => (rightMachine ? normalizeAbstractMachine(rightMachine) : null), [rightMachine]);

    const computedDiff = React.useMemo(() => {
        if (!leftNorm?.normalized || !rightNorm?.normalized) return null;
        return diffAbstractMachines(leftNorm.normalized, rightNorm.normalized);
    }, [leftNorm, rightNorm]);

    const canRender = Boolean(leftNorm?.normalized && rightNorm?.normalized);

    if (status === "loading") {
        return (
            <div className="flex flex-col items-center justify-center p-12 text-slate-500 animate-pulse">
                <Network className="w-8 h-8 mb-4 opacity-50 text-blue-500" />
                <p>Loading abstract machines workspace...</p>
            </div>
        );
    }

    if (status === "empty") {
        return (
            <div className="flex justify-center p-6 sm:p-12 md:p-24 pl-8">
                <div className="flex flex-col items-center justify-center max-w-md text-center bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl p-8 shadow-sm">
                    <div className="w-16 h-16 bg-blue-100 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 rounded-full flex items-center justify-center mb-6">
                        <Layers className="w-8 h-8" />
                    </div>
                    <h2 className="text-xl font-bold text-slate-900 dark:text-slate-100 mb-2">No Machines Extracted</h2>
                    <p className="text-slate-600 dark:text-slate-400 mb-8 leading-relaxed">
                        To compare abstract machines, you first need to extract them from your ingested policy documents.
                    </p>
                    <Link
                        href="/data"
                        className="inline-flex items-center justify-center px-6 py-3 border border-transparent text-base font-medium rounded-full text-white bg-blue-600 hover:bg-blue-700 shadow-sm transition-colors"
                    >
                        Go to Data & Sources
                        <ChevronRight className="ml-2 w-4 h-4" />
                    </Link>
                </div>
            </div>
        );
    }

    if (status === "error") {
        return (
            <div className="flex flex-col items-center justify-center p-12 text-red-500">
                <AlertCircle className="w-8 h-8 mb-4 opacity-50" />
                <p>Failed to load abstract machines. Please try refreshing.</p>
            </div>
        );
    }

    return (
        <div className="flex flex-col h-full bg-slate-50 dark:bg-slate-950">
            {/* Header Controls */}
            <header className="flex flex-wrap items-center gap-4 p-4 border-b border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 sticky top-0 z-10 shrink-0">
                <div className="flex items-center gap-2 mr-4 hidden md:flex">
                    <div className="w-8 h-8 bg-blue-100 dark:bg-blue-900/40 text-blue-600 dark:text-blue-400 rounded flex items-center justify-center">
                        <ArrowLeftRight className="w-4 h-4" />
                    </div>
                    <div>
                        <h1 className="text-sm font-bold text-slate-900 dark:text-slate-100 leading-tight">Compare Abstract Machines</h1>
                        <p className="text-[10px] text-slate-500 uppercase tracking-wider">Side-by-side Layout</p>
                    </div>
                </div>

                <div className="flex flex-wrap flex-1 gap-4 items-center min-w-0">
                    {/* View Switcher */}
                    <div className="flex items-center border border-slate-200 dark:border-slate-700 rounded-lg overflow-x-auto shrink-0 max-w-full">
                        {([
                            ["dashboard", "Visualizations"],
                            ["machine", "Machine"],
                            ["strata", "Strata"],
                            ["state", "State Capture"],
                            ["diff", "Computed Diff"],
                            ["ai", "AI Analysis"]
                        ] as const).map(([val, label]) => (
                            <button
                                key={val}
                                onClick={() => handleParamChange("view", val)}
                                className={`px-4 py-2 text-xs font-medium transition-colors whitespace-nowrap flex-shrink-0 ${viewMode === val
                                    ? "bg-slate-100 dark:bg-slate-800 text-blue-600 dark:text-blue-400"
                                    : "bg-white dark:bg-slate-900 text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800/50"
                                    }`}
                            >
                                {label}
                            </button>
                        ))}
                    </div>

                    {/* Source Selectors */}
                    <div className="flex items-center gap-2 flex-1 min-w-[300px]">
                        <div className="flex items-center flex-1 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg overflow-hidden min-w-[150px]">
                            <select
                                value={leftId || ""}
                                onChange={e => handleParamChange("left", e.target.value)}
                                className="w-full text-sm p-2 bg-transparent text-slate-900 dark:text-slate-100 outline-none truncate"
                            >
                                <option value="" disabled>Select Left Document...</option>
                                {sourcesList.map(s => (
                                    <option key={s.id} value={s.id}>{s.title}</option>
                                ))}
                            </select>
                        </div>

                        <ArrowLeftRight className="w-4 h-4 text-slate-400 shrink-0" />

                        <div className="flex items-center flex-1 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg overflow-hidden min-w-[200px]">
                            <select
                                value={rightId || ""}
                                onChange={e => handleParamChange("right", e.target.value)}
                                className="w-full text-sm p-2 bg-transparent text-slate-900 dark:text-slate-100 outline-none truncate"
                            >
                                <option value="" disabled>Select Right Document...</option>
                                {sourcesList.map(s => (
                                    <option key={s.id} value={s.id}>{s.title}</option>
                                ))}
                            </select>
                        </div>
                    </div>
                </div>
            </header>

            {/* Legend Panel */}
            <div className="flex flex-wrap text-sm gap-2 sm:gap-6 px-6 py-2 border-b border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-900/50 whitespace-nowrap overflow-x-auto">
                <div className="text-slate-500 font-mono text-[10px] uppercase tracking-widest flex items-center mr-2">
                    Visual Legend
                </div>
                {viewMode === "machine" && (
                    <>
                        <div className="flex items-center gap-2 text-slate-600 dark:text-slate-400">
                            <div className="w-4 h-3 bg-blue-50 dark:bg-blue-900 border border-blue-600 dark:border-blue-500 rounded-sm"></div>
                            <span>Operator</span>
                        </div>
                        <div className="flex items-center gap-2 text-slate-600 dark:text-slate-400">
                            <div className="w-3 h-3 bg-green-50 dark:bg-green-900 border border-green-600 dark:border-green-500 rounded-full"></div>
                            <span>Token</span>
                        </div>
                        <div className="flex items-center gap-2 text-slate-600 dark:text-slate-400">
                            <div className="w-3 h-3 bg-amber-50 dark:bg-amber-900 border border-amber-600 dark:border-amber-500" style={{ clipPath: "polygon(50% 0%, 100% 25%, 100% 75%, 50% 100%, 0% 75%, 0% 25%)" }}></div>
                            <span>Global Constraint (dashed line)</span>
                        </div>
                    </>
                )}
                {viewMode === "strata" && (
                    <>
                        <div className="flex items-center gap-2 text-slate-600 dark:text-slate-400">
                            <div className="w-4 h-3 bg-purple-50 dark:bg-purple-900 border border-purple-600 dark:border-purple-500 rounded-sm"></div>
                            <span>Content</span>
                        </div>
                        <div className="flex items-center gap-2 text-slate-600 dark:text-slate-400">
                            <div className="w-4 h-3 bg-pink-50 dark:bg-pink-900 border border-pink-600 dark:border-pink-500 rounded-sm"></div>
                            <span>Expression</span>
                        </div>
                        <div className="flex items-center gap-2 text-slate-600 dark:text-slate-400 ml-2">
                            <div className="w-6 h-px bg-slate-400"></div>
                            <span>Resonance</span>
                        </div>
                        <div className="flex items-center gap-2 text-slate-600 dark:text-slate-400">
                            <div className="w-6 h-px border-b border-dashed border-slate-400"></div>
                            <span>Clash</span>
                        </div>
                    </>
                )}
                {viewMode === "state" && (
                    <>
                        <div className="flex items-center gap-2 text-slate-600 dark:text-slate-400">
                            <div className="w-4 h-3 bg-teal-50 dark:bg-teal-900 border border-teal-600 dark:border-teal-500 rounded-sm"></div>
                            <span>State Node</span>
                        </div>
                        <div className="flex items-center gap-2 text-slate-600 dark:text-slate-400 ml-2">
                            <div className="w-10 h-px bg-slate-400 relative">
                                <svg className="w-3 h-3 absolute right-0 -translate-y-[5px]" viewBox="0 -5 10 10" preserveAspectRatio="none"><path d="M0,-5L10,0L0,5" fill="currentColor" /></svg>
                            </div>
                            <span>Transformation trigger</span>
                        </div>
                    </>
                )}
            </div>

            {/* Same Document Warning */}
            {leftId && leftId === rightId && (
                <div className="mx-6 mt-4 p-3 bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-900 text-amber-800 dark:text-amber-400 text-sm rounded-xl flex items-center justify-center">
                    <AlertCircle className="w-4 h-4 mr-2" />
                    You have selected the same document on both sides. This will show a mirrored view.
                </div>
            )}

            {/* Main Content Area */}
            <div className="flex-1 w-full min-h-0 relative overflow-y-auto">
                {viewMode === "diff" ? (
                    <div className="p-6 max-w-7xl mx-auto space-y-8">
                        <div>
                            <h2 className="text-xl font-bold text-slate-900 dark:text-slate-100 mb-2">Computed Structural Diff</h2>
                            <p className="text-slate-600 dark:text-slate-400 text-sm mb-6">
                                A deterministic set-based comparison of operators, constraints, and transformations between the two abstract machines.
                            </p>
                        </div>

                        {!canRender && (
                            <div className="text-sm text-slate-500 italic p-8 border border-dashed border-slate-300 rounded-xl text-center">
                                Please select both a Left and Right document to compute the diff.
                            </div>
                        )}

                        {canRender && computedDiff && (
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                <section className="p-5 bg-white dark:bg-slate-900 border border-emerald-200 dark:border-emerald-900/50 rounded-xl shadow-sm">
                                    <div className="font-bold text-emerald-800 dark:text-emerald-400 mb-3 flex items-center gap-2 border-b border-emerald-100 dark:border-emerald-900/30 pb-2">
                                        <div className="w-3 h-3 rounded-full bg-emerald-500"></div>
                                        Shared Spine
                                    </div>
                                    <ul className="space-y-2 text-sm text-slate-700 dark:text-slate-300">
                                        {computedDiff.textRepresentation.sharedSpine.length === 0 ? <li className="text-slate-400 italic text-xs">No shared elements found.</li> : null}
                                        {computedDiff.textRepresentation.sharedSpine.map((x: string) => (
                                            <li key={x} className="flex gap-2"><span className="text-emerald-500">•</span> <span>{x}</span></li>
                                        ))}
                                    </ul>
                                </section>

                                <section className="p-5 bg-white dark:bg-slate-900 border border-blue-200 dark:border-blue-900/50 rounded-xl shadow-sm">
                                    <div className="font-bold text-blue-800 dark:text-blue-400 mb-3 flex items-center gap-2 border-b border-blue-100 dark:border-blue-900/30 pb-2">
                                        <div className="w-3 h-3 rounded-full bg-blue-500"></div>
                                        Only in Left ({leftTitle})
                                    </div>
                                    <ul className="space-y-2 text-sm text-slate-700 dark:text-slate-300">
                                        {computedDiff.textRepresentation.onlyInLeft.length === 0 ? <li className="text-slate-400 italic text-xs">No unique elements on left.</li> : null}
                                        {computedDiff.textRepresentation.onlyInLeft.map((x: string) => (
                                            <li key={x} className="flex gap-2"><span className="text-blue-500">•</span> <span>{x}</span></li>
                                        ))}
                                    </ul>
                                </section>

                                <section className="p-5 bg-white dark:bg-slate-900 border border-purple-200 dark:border-purple-900/50 rounded-xl shadow-sm">
                                    <div className="font-bold text-purple-800 dark:text-purple-400 mb-3 flex items-center gap-2 border-b border-purple-100 dark:border-purple-900/30 pb-2">
                                        <div className="w-3 h-3 rounded-full bg-purple-500"></div>
                                        Only in Right ({rightTitle})
                                    </div>
                                    <ul className="space-y-2 text-sm text-slate-700 dark:text-slate-300">
                                        {computedDiff.textRepresentation.onlyInRight.length === 0 ? <li className="text-slate-400 italic text-xs">No unique elements on right.</li> : null}
                                        {computedDiff.textRepresentation.onlyInRight.map((x: string) => (
                                            <li key={x} className="flex gap-2"><span className="text-purple-500">•</span> <span>{x}</span></li>
                                        ))}
                                    </ul>
                                </section>
                            </div>
                        )}
                    </div>
                ) : viewMode === "dashboard" ? (
                    <div className="flex-1 w-full p-4 h-full bg-slate-100 dark:bg-black/20">
                        <ComparisonDashboard
                            leftMachine={(leftNorm?.normalized as AbstractMachineAnalysis) || null}
                            rightMachine={(rightNorm?.normalized as AbstractMachineAnalysis) || null}
                            leftSource={sourcesList.find(s => s.id === leftId) as any}
                            rightSource={sourcesList.find(s => s.id === rightId) as any}
                            aiReport={aiReport as any}
                            onRegenerate={() => fetchAiAnalysis(true)}
                            isRegenerating={isGeneratingAi}
                        />
                    </div>
                ) : viewMode === "ai" ? (
                    <div className="p-6 max-w-4xl mx-auto space-y-8 pb-32">
                        <div className="flex items-center gap-4 justify-between border-b border-slate-200 dark:border-slate-800 pb-4">
                            <div>
                                <h2 className="text-xl font-bold text-slate-900 dark:text-slate-100 mb-1 flex items-center gap-2">
                                    <Sparkles className="w-5 h-5 text-indigo-500" />
                                    AI Structural Analysis
                                </h2>
                                <p className="text-slate-600 dark:text-slate-400 text-sm">
                                    Deleuzian Assemblage comparison generated by {aiReport?.model_name || "AI"}.
                                </p>
                            </div>
                            <button
                                onClick={() => fetchAiAnalysis(true)}
                                disabled={isGeneratingAi || !canRender}
                                className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white shadow-sm rounded-lg text-sm font-medium transition-colors"
                            >
                                {isGeneratingAi ? "Analyzing..." : aiReport ? "Regenerate" : "Generate Report"}
                            </button>
                        </div>

                        {!canRender && (
                            <div className="text-sm text-slate-500 italic p-8 border border-dashed border-slate-300 rounded-xl text-center">
                                Please select both a Left and Right document to generate an AI analysis.
                            </div>
                        )}

                        {isGeneratingAi && (
                            <div className="flex flex-col items-center justify-center p-12 text-indigo-600 dark:text-indigo-400">
                                <Loader2 className="w-8 h-8 animate-spin mb-4" />
                                <p className="text-sm font-medium">Extracting theoretical comparisons...</p>
                            </div>
                        )}

                        {aiError && !isGeneratingAi && (
                            <div className="p-4 bg-red-50 dark:bg-red-900/20 text-red-700 dark:text-red-400 rounded-lg text-sm border border-red-200 dark:border-red-900">
                                <AlertCircle className="w-4 h-4 inline mr-2" />
                                {aiError}
                            </div>
                        )}

                        {aiReport && !isGeneratingAi && (
                            <div className="space-y-10">
                                {/* Shared Spine */}
                                <section>
                                    <h3 className="text-lg font-bold text-slate-800 dark:text-slate-200 mb-3 border-l-4 border-emerald-500 pl-3">
                                        Shared Spine (Obligatory Passage Points)
                                    </h3>
                                    <p className="text-slate-700 dark:text-slate-300 mb-4 leading-relaxed">{aiReport.comparison.shared_spine.explanation}</p>
                                    <ul className="space-y-3 pl-4">
                                        {aiReport.comparison.shared_spine.items.map((item, i) => (
                                            <li key={i} className="text-sm bg-white dark:bg-slate-900 p-3 rounded shadow-sm border border-slate-100 dark:border-slate-800">
                                                <span className="font-bold text-emerald-700 dark:text-emerald-400">{item.element_name}</span>: {item.significance}
                                            </li>
                                        ))}
                                    </ul>
                                </section>

                                {/* Differences */}
                                <section>
                                    <h3 className="text-lg font-bold text-slate-800 dark:text-slate-200 mb-3 border-l-4 border-amber-500 pl-3">
                                        Fundamental Divergences
                                    </h3>
                                    <p className="text-slate-700 dark:text-slate-300 mb-4 leading-relaxed">{aiReport.comparison.differences.explanation}</p>
                                    <ul className="space-y-3 pl-4">
                                        {aiReport.comparison.differences.items.map((item, i) => (
                                            <li key={i} className="text-sm bg-white dark:bg-slate-900 p-3 rounded shadow-sm border border-slate-100 dark:border-slate-800">
                                                <span className="font-bold text-amber-700 dark:text-amber-400">{item.element_name}</span>: {item.description}
                                            </li>
                                        ))}
                                    </ul>
                                </section>

                                {/* Double Articulation */}
                                <section>
                                    <h3 className="text-lg font-bold text-slate-800 dark:text-slate-200 mb-3 border-l-4 border-blue-500 pl-3">
                                        Double Articulation
                                    </h3>
                                    <p className="text-slate-700 dark:text-slate-300 leading-relaxed mb-4">{aiReport.comparison.double_articulation.explanation}</p>
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                        <div className="bg-slate-50 dark:bg-slate-800/50 p-4 rounded-lg border border-slate-200 dark:border-slate-700">
                                            <div className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">{leftTitle}</div>
                                            {aiReport.schema_version === 2 ? (
                                                <div className="text-sm text-slate-800 dark:text-slate-300">
                                                    <div className="font-semibold mb-1">Content:</div>
                                                    <ul className="list-disc pl-4 mb-3">{aiReport.comparison.double_articulation.left_content_items?.map((x: string, i: number) => <li key={i}>{x}</li>)}</ul>
                                                    <div className="font-semibold mb-1">Expression:</div>
                                                    <ul className="list-disc pl-4">{aiReport.comparison.double_articulation.left_expression_items?.map((x: string, i: number) => <li key={i}>{x}</li>)}</ul>
                                                </div>
                                            ) : (
                                                <p className="text-sm text-slate-800 dark:text-slate-300">{(aiReport.comparison.double_articulation as any).left_tension}</p>
                                            )}
                                        </div>
                                        <div className="bg-slate-50 dark:bg-slate-800/50 p-4 rounded-lg border border-slate-200 dark:border-slate-700">
                                            <div className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">{rightTitle}</div>
                                            {aiReport.schema_version === 2 ? (
                                                <div className="text-sm text-slate-800 dark:text-slate-300">
                                                    <div className="font-semibold mb-1">Content:</div>
                                                    <ul className="list-disc pl-4 mb-3">{aiReport.comparison.double_articulation.right_content_items?.map((x: string, i: number) => <li key={i}>{x}</li>)}</ul>
                                                    <div className="font-semibold mb-1">Expression:</div>
                                                    <ul className="list-disc pl-4">{aiReport.comparison.double_articulation.right_expression_items?.map((x: string, i: number) => <li key={i}>{x}</li>)}</ul>
                                                </div>
                                            ) : (
                                                <p className="text-sm text-slate-800 dark:text-slate-300">{(aiReport.comparison.double_articulation as any).right_tension}</p>
                                            )}
                                        </div>
                                    </div>
                                </section>

                                {/* Conclusion */}
                                <section className="bg-indigo-50 dark:bg-indigo-900/10 p-6 rounded-xl border border-indigo-100 dark:border-indigo-900/50">
                                    <h3 className="text-lg font-bold text-indigo-900 dark:text-indigo-300 mb-3">
                                        Synthesis
                                    </h3>
                                    <p className="text-indigo-950 dark:text-indigo-100 leading-relaxed italic">
                                        &quot;{aiReport.comparison.conclusion}&quot;
                                    </p>
                                    <div className="mt-4 text-[10px] text-indigo-400 uppercase tracking-wider text-right">
                                        Generated by {aiReport.model_name}
                                    </div>
                                </section>
                            </div>
                        )}
                    </div>
                ) : (
                    <AbstractMachineCompareD3
                        leftMachine={(leftNorm?.normalized as AbstractMachineAnalysis) || null}
                        rightMachine={(rightNorm?.normalized as AbstractMachineAnalysis) || null}
                        leftTitle={leftTitle}
                        rightTitle={rightTitle}
                        viewMode={viewMode as "machine" | "strata" | "state"}
                    />
                )}
            </div>
        </div>
    );
}

"use client";

import React, { useMemo } from "react";
import { AbstractMachineAnalysis } from "@/types";
import { AICompareAbstractMachinesResponse } from "@/lib/prompts/compare-machines";
import { ComparativeAssemblageD3 } from "./ComparativeAssemblageD3";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip as RechartsTooltip, Legend, ResponsiveContainer, Cell } from "recharts";
import { AlertCircle, RefreshCw } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";

interface DocumentSource {
    id: string;
    title: string;
}

interface ComparisonDashboardProps {
    leftMachine?: AbstractMachineAnalysis;
    rightMachine?: AbstractMachineAnalysis;
    leftSource?: DocumentSource;
    rightSource?: DocumentSource;
    aiReport?: {
        model_name: string;
        schema_version?: number;
        timestamp: number;
        comparison: AICompareAbstractMachinesResponse;
    };
    onRegenerate: () => void;
    isRegenerating: boolean;
}

export function ComparisonDashboard({ leftMachine, rightMachine, leftSource, rightSource, aiReport, onRegenerate, isRegenerating }: ComparisonDashboardProps) {

    // 0. Process Data (Rules of Hooks require this before early returns)
    const capacitiesData = useMemo(() => {
        return aiReport?.comparison?.affective_capacities?.scores?.map((item: any) => ({
            name: item.stakeholder,
            Left: item.left_score,
            Right: item.right_score,
            confidence: item.confidence,
            rationale: item.rationale
        })) || [];
    }, [aiReport?.comparison?.affective_capacities]);

    const monteCarloData = useMemo(() => {
        return (aiReport?.comparison as any)?.scenario_assessments?.simulations?.map((item: any) => ({
            name: item.scenario,
            Left: item.left_likelihood,
            Right: item.right_likelihood,
            confidence: item.confidence,
            rationale: item.rationale
        })) || [];
    }, [aiReport?.comparison]);

    // 1. Loading State
    if (!aiReport && isRegenerating) {
        return (
            <div className="w-full h-full flex flex-col gap-6 p-4">
                <div className="h-16 w-full"><Skeleton className="w-full h-full rounded-xl" /></div>
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 flex-1 min-h-[500px]">
                    <Skeleton className="w-full h-full rounded-xl" />
                    <Skeleton className="w-full h-full rounded-xl" />
                </div>
            </div>
        );
    }

    // 2. Empty State
    if (!aiReport || !leftMachine || !rightMachine) {
        return (
            <div className="flex flex-col items-center justify-center p-12 text-center h-full text-slate-500">
                <AlertCircle className="w-12 h-12 mb-4 text-slate-300 dark:text-slate-700" />
                <h3 className="text-lg font-medium text-slate-900 dark:text-slate-100 mb-2">No AI Analysis Found</h3>
                <p className="max-w-md mb-6">Generate an AI structural comparison to view the interactive dashboard.</p>
                <Button onClick={onRegenerate} disabled={isRegenerating}>
                    <RefreshCw className="w-4 h-4 mr-2" />
                    Generate Dashboard
                </Button>
            </div>
        );
    }

    // 3. Fallback Version State (V1/V2 Cache)
    if (aiReport.schema_version !== 2.1) {
        return (
            <div className="flex flex-col items-center justify-center p-12 text-center h-full text-slate-500">
                <AlertCircle className="w-12 h-12 mb-4 text-amber-500" />
                <h3 className="text-lg font-medium text-slate-900 dark:text-slate-100 mb-2">Dashboard Data Missing</h3>
                <p className="max-w-lg mb-6 text-sm">Your previously generated comparison uses an older schema that does not have the numeric probabilities required to plot the charts. Please regenerate the analysis to view the dashboard.</p>
                <Button onClick={onRegenerate} disabled={isRegenerating}>
                    {isRegenerating ? <RefreshCw className="w-4 h-4 mr-2 animate-spin" /> : <RefreshCw className="w-4 h-4 mr-2" />}
                    Regenerate Analysis
                </Button>
            </div>
        );
    }

    // 4. Dashboard View



    const da = aiReport.comparison.double_articulation;

    // Left Blue, Right Orange styling
    const LEFT_COLOR = "#b2d1eb"; // Soft Blue matching original screenshot for bars
    const RIGHT_COLOR = "#f1b373"; // Soft Orange matching screenshot for bars
    const LEFT_DARK = "#1d4ed8";
    const RIGHT_DARK = "#c2410c";

    const isDarkMode = document.documentElement.classList.contains('dark');
    const L_BAR = isDarkMode ? LEFT_DARK : LEFT_COLOR;
    const R_BAR = isDarkMode ? RIGHT_DARK : RIGHT_COLOR;

    const renderCustomBarLabel = (props: any) => {
        const { x, y, width, value } = props;
        return (
            <text x={x + width / 2} y={y - 6} fill="#64748b" textAnchor="middle" fontSize={10} fontWeight={500}>
                {Number(value).toFixed(2)}
            </text>
        );
    };

    const renderCustomTooltip = ({ active, payload, label }: any) => {
        if (active && payload && payload.length) {
            const data = payload[0].payload;
            return (
                <div
                    className={`p-3 rounded-lg border shadow-lg text-xs max-w-md max-h-[350px] overflow-y-auto custom-scrollbar ${isDarkMode ? 'border-slate-700 text-slate-300' : 'border-slate-200 text-slate-700'}`}
                    style={{ backgroundColor: isDarkMode ? '#0f172a' : '#ffffff', zIndex: 1000, position: 'relative' }}
                >
                    <div className="font-bold mb-2 break-words text-[13px]">{label}</div>
                    <div className="flex justify-between mb-1">
                        <div className="flex items-center gap-1.5"><div className="w-2.5 h-2.5 rounded-sm" style={{ backgroundColor: L_BAR }}></div>{payload[0]?.name}:</div>
                        <span className="font-medium">{payload[0]?.value?.toFixed(2)}</span>
                    </div>
                    <div className="flex justify-between mb-3 border-b pb-3 border-slate-200 dark:border-slate-800">
                        <div className="flex items-center gap-1.5"><div className="w-2.5 h-2.5 rounded-sm" style={{ backgroundColor: R_BAR }}></div>{payload[1]?.name}:</div>
                        <span className="font-medium">{payload[1]?.value?.toFixed(2)}</span>
                    </div>
                    <div className="mb-1 text-[10px] uppercase tracking-wider text-slate-500 font-bold flex justify-between">
                        <span>LLM Rationale</span>
                        <span className="text-indigo-500">Conf: {data.confidence?.toFixed(2)}</span>
                    </div>
                    <div className="text-[11px] leading-relaxed italic text-slate-600 dark:text-slate-400">
                        "{data.rationale}"
                    </div>
                </div>
            );
        }
        return null;
    };

    return (
        <div className="flex flex-col h-full overflow-y-auto space-y-6 pb-[400px]">

            <div className="bg-slate-50 border border-slate-200 dark:bg-slate-900/50 dark:border-slate-800 shrink-0 p-4 rounded-xl flex gap-3">
                <AlertCircle className="h-5 w-5 text-slate-500 mt-0.5 shrink-0" />
                <div className="flex flex-col gap-1">
                    <h5 className="text-slate-700 dark:text-slate-300 text-xs uppercase tracking-wide font-bold">Illustrative Simulation</h5>
                    <p className="text-slate-600 dark:text-slate-400 text-xs leading-relaxed">
                        Numeric values and simulations shown in the charts below are illustrative interpretations deterministically generated via <code>{aiReport.model_name}</code>. They represent structural leverage potentials derived from the text, not empirical real-world enforcement statistics.
                    </p>
                </div>
            </div>

            {/* Figure 1: Network graph (Full Width) */}
            <div className="w-full h-[600px] shrink-0 flex flex-col items-center">
                <h3 className="text-sm font-medium text-slate-800 dark:text-slate-200 mb-1">Figure 1: Comparative Algorithmic Assemblages</h3>
                <h4 className="text-xs text-slate-500 mb-4 tracking-wide font-medium">Shared OPP Spine + Divergent Territorializations</h4>
                <ComparativeAssemblageD3 leftMachine={leftMachine} rightMachine={rightMachine} />
            </div>

            {/* Figures Stack */}
            <div className="flex flex-col gap-8 shrink-0">

                {/* Figure 2: Double Articulation Strata */}
                <div className="flex flex-col w-full h-[500px] bg-white dark:bg-slate-950 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm p-4 overflow-hidden">
                    <div className="text-center mb-6">
                        <h3 className="text-sm font-medium text-slate-800 dark:text-slate-200 mb-1">Figure 2: Double Articulation (Content / Expression Strata)</h3>
                    </div>

                    <div className="flex-1 grid grid-cols-2 gap-4 h-full relative">
                        {/* Headers */}
                        <div className="absolute top-0 left-0 w-[49%] text-center text-xs font-bold text-slate-600 dark:text-slate-400">{leftSource?.title || "Left Document"}</div>
                        <div className="absolute top-0 right-0 w-[49%] text-center text-xs font-bold text-slate-600 dark:text-slate-400">{rightSource?.title || "Right Document"}</div>

                        <div className="col-span-1 flex flex-col gap-4 mt-6 overflow-y-auto pr-2 custom-scrollbar">
                            <div className="bg-slate-50 dark:bg-slate-900/40 border border-slate-100 dark:border-slate-800/60 p-4 rounded-lg flex-1">
                                <div className="text-center font-bold text-xs uppercase tracking-widest text-slate-700 dark:text-slate-300 mb-1">Content Stratum</div>
                                <div className="text-center text-[10px] text-slate-500 mb-4">(machinic assemblage of bodies)</div>
                                <ul className="space-y-2 text-xs text-slate-700 dark:text-slate-300">
                                    {da?.left_content_items?.map((it: string, i: number) => <li key={i} className="flex gap-2 leading-relaxed"><span className="text-blue-500 shrink-0">•</span> {it}</li>)}
                                </ul>
                            </div>
                            <div className="bg-slate-50 dark:bg-slate-900/40 border border-slate-100 dark:border-slate-800/60 p-4 rounded-lg flex-1">
                                <div className="text-center font-bold text-xs uppercase tracking-widest text-slate-700 dark:text-slate-300 mb-1">Expression Stratum</div>
                                <div className="text-center text-[10px] text-slate-500 mb-4">(collective assemblage of enunciation)</div>
                                <ul className="space-y-2 text-xs text-slate-700 dark:text-slate-300">
                                    {da?.left_expression_items?.map((it: string, i: number) => <li key={i} className="flex gap-2 leading-relaxed"><span className="text-blue-500 shrink-0">•</span> {it}</li>)}
                                </ul>
                            </div>
                        </div>

                        <div className="col-span-1 flex flex-col gap-4 mt-6 overflow-y-auto pr-2 custom-scrollbar">
                            <div className="bg-slate-50 dark:bg-slate-900/40 border border-slate-100 dark:border-slate-800/60 p-4 rounded-lg flex-1">
                                <div className="text-center font-bold text-xs uppercase tracking-widest text-slate-700 dark:text-slate-300 mb-1">Content Stratum</div>
                                <div className="text-center text-[10px] text-slate-500 mb-4">(machinic assemblage of bodies)</div>
                                <ul className="space-y-2 text-xs text-slate-700 dark:text-slate-300">
                                    {da?.right_content_items?.map((it: string, i: number) => <li key={i} className="flex gap-2 leading-relaxed"><span className="text-orange-500 shrink-0">•</span> {it}</li>)}
                                </ul>
                            </div>
                            <div className="bg-slate-50 dark:bg-slate-900/40 border border-slate-100 dark:border-slate-800/60 p-4 rounded-lg flex-1">
                                <div className="text-center font-bold text-xs uppercase tracking-widest text-slate-700 dark:text-slate-300 mb-1">Expression Stratum</div>
                                <div className="text-center text-[10px] text-slate-500 mb-4">(collective assemblage of enunciation)</div>
                                <ul className="space-y-2 text-xs text-slate-700 dark:text-slate-300">
                                    {da?.right_expression_items?.map((it: string, i: number) => <li key={i} className="flex gap-2 leading-relaxed"><span className="text-orange-500 shrink-0">•</span> {it}</li>)}
                                </ul>
                            </div>
                        </div>

                    </div>
                </div>

                {/* Figure 3: Affective Capacities */}
                <div className="w-full h-[500px] bg-white dark:bg-slate-950 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm p-4 flex flex-col">
                    <div className="text-center mb-1">
                        <h3 className="text-sm font-medium text-slate-800 dark:text-slate-200">Figure 3: Affective Capacities – Who Gains Leverage?</h3>
                        <div className="text-[10px] text-slate-500 uppercase tracking-widest font-bold">Interpretive (LLM)</div>
                    </div>
                    <div className="flex-1 min-h-0 w-full mt-4">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart data={capacitiesData} margin={{ top: 20, right: 10, left: -20, bottom: 0 }}>
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? "#334155" : "#e2e8f0"} />
                                <XAxis dataKey="name" tick={{ fontSize: 10, fill: isDarkMode ? "#94a3b8" : "#64748b" }} axisLine={false} tickLine={false} />
                                <YAxis domain={[0, 1]} tick={{ fontSize: 10, fill: isDarkMode ? "#94a3b8" : "#64748b" }} axisLine={false} tickLine={false} />
                                <RechartsTooltip position={{ y: 0 }} content={renderCustomTooltip} cursor={{ fill: isDarkMode ? '#1e293b' : '#f1f5f9' }} wrapperStyle={{ zIndex: 1000, pointerEvents: "auto" }} />
                                <Legend wrapperStyle={{ fontSize: '11px', color: isDarkMode ? '#cbd5e1' : '#475569' }} />
                                <Bar dataKey="Left" name={leftSource?.title?.slice(0, 15) || "Left"} fill={L_BAR} radius={[2, 2, 0, 0]} label={renderCustomBarLabel} maxBarSize={100} isAnimationActive={false} />
                                <Bar dataKey="Right" name={rightSource?.title?.slice(0, 15) || "Right"} fill={R_BAR} radius={[2, 2, 0, 0]} label={renderCustomBarLabel} maxBarSize={100} isAnimationActive={false} />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* Figure 4: Scenario Assessments */}
                <div className="w-full h-[600px] bg-white dark:bg-slate-950 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm p-4 flex flex-col">
                    <div className="text-center mb-1">
                        <h3 className="text-sm font-medium text-slate-800 dark:text-slate-200">Figure 4: Scenario Assessments</h3>
                        <div className="flex justify-center gap-2 items-center text-[10px] text-slate-500 uppercase tracking-widest mt-1">
                            <span className="font-bold">Interpretive (LLM)</span>
                            <span>•</span>
                            <span>Based on Structural Restrictiveness</span>
                        </div>
                    </div>
                    <div className="flex-1 min-h-0 w-full mt-2">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart data={monteCarloData} margin={{ top: 20, right: 10, left: -20, bottom: 60 }}>
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? "#334155" : "#e2e8f0"} />
                                <XAxis
                                    dataKey="name"
                                    angle={-30}
                                    textAnchor="end"
                                    height={100}
                                    tick={{ fontSize: 10, fill: isDarkMode ? "#94a3b8" : "#64748b" }}
                                    axisLine={false}
                                    tickLine={false}
                                    tickFormatter={(v: string) => v.length > 25 ? v.slice(0, 25) + '...' : v}
                                />
                                <YAxis domain={[0, 1]} tick={{ fontSize: 10, fill: isDarkMode ? "#94a3b8" : "#64748b" }} axisLine={false} tickLine={false} />
                                <RechartsTooltip position={{ y: 0 }} content={renderCustomTooltip} cursor={{ fill: isDarkMode ? '#1e293b' : '#f1f5f9' }} wrapperStyle={{ zIndex: 1000, pointerEvents: "auto" }} />
                                <Bar dataKey="Left" name={leftSource?.title?.slice(0, 15) || "Left"} fill={L_BAR} radius={[2, 2, 0, 0]} label={renderCustomBarLabel} maxBarSize={80} isAnimationActive={false} />
                                <Bar dataKey="Right" name={rightSource?.title?.slice(0, 15) || "Right"} fill={R_BAR} radius={[2, 2, 0, 0]} label={renderCustomBarLabel} maxBarSize={80} isAnimationActive={false} />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>

            </div>
        </div>
    );
}

"use client";

import { useWorkspace } from "@/providers/WorkspaceProvider";
import React, { useEffect, useState, useCallback } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { Activity, AlertTriangle, Layers, Loader2, Sparkles, FileText, CheckCircle2 } from "lucide-react";
import { FrictionGraph } from "./FrictionGraph";

interface Source {
    id: string;
    title: string;
    text: string;
    type: "PDF" | "Web" | "Text" | "Trace" | "Word";
}

export function ControversyDashboard() {
    const router = useRouter();
    const searchParams = useSearchParams();
    const { currentWorkspaceId } = useWorkspace();

    const selectedDocId = searchParams.get("doc") || undefined;

    const [sourcesList, setSourcesList] = useState<Source[]>([]);
    const [status, setStatus] = useState<"loading" | "error" | "ready" | "empty">("loading");

    const [mapData, setMapData] = useState<any>(null);
    const [isGenerating, setIsGenerating] = useState(false);
    const [mapError, setMapError] = useState<string | null>(null);

    const getHeaders = useCallback((base: HeadersInit = {}) => {
        const headers = { ...base } as Record<string, string>;
        if (currentWorkspaceId) {
            headers['x-workspace-id'] = currentWorkspaceId;
        }
        if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true') {
            headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID || 'demo-user';
        }
        return headers;
    }, [currentWorkspaceId]);

    // Fetch documents list
    useEffect(() => {
        if (!currentWorkspaceId && process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE !== 'true') return;

        let mounted = true;
        async function fetchList() {
            try {
                // Fetch all documents. (Assuming /api/sources exists)
                const res = await fetch("/api/sources", { headers: getHeaders() });
                if (!res.ok) throw new Error("Failed to fetch sources");
                const data = await res.json();

                if (mounted) {
                    if (data.length === 0) setStatus("empty");
                    else {
                        // Filter out secondary evidence (Web) and micro-resistance findings (Trace)
                        const policyDocs = data.filter((s: Source) => s.type !== 'Web' && s.type !== 'Trace');

                        if (policyDocs.length === 0) {
                            setStatus("empty");
                        } else {
                            setSourcesList(policyDocs);
                            setStatus("ready");
                            if (!selectedDocId) {
                                router.replace(`?doc=${policyDocs[0].id}`, { scroll: false });
                            }
                        }
                    }
                }
            } catch (err) {
                if (mounted) setStatus("error");
            }
        }
        fetchList();
        return () => { mounted = false; };
    }, [currentWorkspaceId, getHeaders, selectedDocId, router]);

    const activeDoc = sourcesList.find(s => s.id === selectedDocId);

    // Fetch existing map on doc selection
    useEffect(() => {
        if (!selectedDocId || status !== "ready") return;

        const mounted = true;
        async function fetchMap() {
            setIsGenerating(true);
            setMapError(null);
            try {
                // Actually the route is a POST that can act as a GET if we tell it we just want to check cache?
                // For now, we'll just POST but use checkCacheOnly: false if we explicitly clicekd generate,
                // Wait, if we want to just check the cache, how does our endpoint handle it?
                // Our endpoint currently has no GET logic, so we must POST to it. 
                // There is no query cache. Wait, the endpoint uses `force: false`. So POSTing is fine, it will return cache if available.
                // But it's better to add a simple GET or check cache if necessary.
                // Let's just avoid auto-fetch unless they click generate to save API hits, or let's try a POST with `checkCacheOnly` which the main logic doesn't fully support yet for Controversy route.

                // Let's try doing the POST with force: false
                // But wait, it will run the LLM if cache misses! That's bad for auto-load.
                // We'll skip auto-loading and require explicit generation click, UNLESS we know it exists.
                // Let's keep it manual generation for now: "Run Meta-Synthesis"
                setIsGenerating(false);
            } catch (e) {
                if (mounted) setIsGenerating(false);
            }
        }
        setMapData(null);
        // fetchMap();
    }, [selectedDocId, status]);

    const handleGenerate = async (force = false) => {
        if (!selectedDocId || !activeDoc) return;
        setIsGenerating(true);
        setMapError(null);

        try {
            const res = await fetch("/api/analyze/controversy-mapping", {
                method: "POST",
                headers: {
                    ...getHeaders(),
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    policyId: selectedDocId,
                    documentTitle: activeDoc.title,
                    force
                })
            });

            const data = await res.json();
            if (!data.success) throw new Error(data.error || "Failed to generate map");

            setMapData(data.controversyMap);
        } catch (e: any) {
            setMapError(e.message);
        } finally {
            setIsGenerating(false);
        }
    };

    if (status === "loading") {
        return (
            <div className="flex flex-col h-full w-full items-center justify-center p-12 text-slate-500 animate-pulse">
                <Activity className="w-8 h-8 mb-4 opacity-50" />
                <p className="text-sm font-medium">Loading workspace...</p>
            </div>
        );
    }

    if (status === "empty") {
        return (
            <div className="flex flex-col h-full items-center justify-center p-8 text-slate-500 max-w-md mx-auto text-center space-y-4">
                <FileText className="w-12 h-12 text-slate-300" />
                <h3 className="text-lg font-semibold text-slate-700">No Documents Found</h3>
                <p className="text-sm text-slate-500">Upload a policy document to trace controversies.</p>
            </div>
        );
    }

    return (
        <div className="flex h-full w-full overflow-hidden">
            {/* Sidebar List */}
            <div className="w-80 border-r border-slate-200 bg-white flex flex-col z-10 shrink-0">
                <div className="p-4 border-b border-slate-100 bg-slate-50/50 space-y-2 shrink-0">
                    <h2 className="text-sm font-bold text-slate-800 flex items-center gap-2">
                        <Activity className="h-4 w-4 text-indigo-600" />
                        Trace Documents
                    </h2>
                </div>
                <div className="flex-1 overflow-y-auto w-full">
                    {sourcesList.map((doc) => {
                        const isSelected = selectedDocId === doc.id;
                        return (
                            <button
                                key={doc.id}
                                onClick={() => router.push(`?doc=${doc.id}`)}
                                className={`w-full text-left p-4 border-b border-slate-100 transition-colors hover:bg-slate-50 ${isSelected ? 'bg-indigo-50/50 border-l-4 border-l-indigo-600' : 'border-l-4 border-l-transparent'}`}
                            >
                                <div className="text-sm font-medium text-slate-800 truncate mb-1" title={doc.title}>
                                    {doc.title}
                                </div>
                                <div className="text-[10px] text-slate-500 font-medium">DOC ID: {doc.id.substring(0, 8)}</div>
                            </button>
                        );
                    })}
                </div>
            </div>

            {/* Main Area */}
            <div className="flex-1 overflow-y-auto bg-slate-50 dark:bg-slate-900 flex flex-col relative">
                {/* Epistemic Transparency Banner */}
                <div className="w-full bg-indigo-50 border-b border-indigo-100 px-4 py-2 flex items-start gap-3 shrink-0">
                    <AlertTriangle className="h-4 w-4 text-indigo-600 shrink-0 mt-0.5" />
                    <p className="text-xs text-indigo-800">
                        <strong>Generative meta-synthesis by LLM.</strong> All detected frictions and contradictions are proposed
                        connections — always verify against primary lens outputs.
                    </p>
                </div>

                <div className="flex-1 p-6 flex flex-col max-w-7xl mx-auto w-full">
                    <div className="flex items-center justify-between mb-8">
                        <div>
                            <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-3">
                                Controversy Map
                                <span className="bg-indigo-100 text-indigo-700 text-xs px-2 py-0.5 rounded-full font-medium">Meta-Synthesis</span>
                            </h1>
                            <p className="text-slate-500 mt-1">Synthesizing consensus and frictions across all 7 ontological strata.</p>
                        </div>

                        <button
                            onClick={() => handleGenerate(!!mapData)}
                            disabled={isGenerating}
                            className={`flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-md text-sm font-medium hover:bg-indigo-700 transition-colors ${isGenerating ? 'opacity-70 cursor-not-allowed' : 'shadow-md shadow-indigo-200'}`}
                        >
                            {isGenerating ? <Loader2 className="h-4 w-4 animate-spin" /> : <Sparkles className="h-4 w-4" />}
                            {isGenerating ? "Synthesizing Strata..." : mapData ? "Regenerate Map" : "Run Meta-Synthesis"}
                        </button>
                    </div>

                    {mapError && (
                        <div className="mb-6 bg-red-50 border border-red-200 text-red-700 p-4 rounded-lg flex gap-3 text-sm">
                            <AlertTriangle className="h-5 w-5 shrink-0" />
                            <div>
                                <strong>Synthesis Failed</strong>
                                <p>{mapError}</p>
                            </div>
                        </div>
                    )}

                    {!mapData && !isGenerating && !mapError && (
                        <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-slate-200 rounded-xl bg-white/50 space-y-4">
                            <Layers className="h-12 w-12 text-slate-300" />
                            <div className="text-center">
                                <h3 className="font-semibold text-slate-700">Structure Ready</h3>
                                <p className="text-sm text-slate-500 max-w-sm">
                                    Click "Run Meta-Synthesis" to aggregate Cultural Framing, Micro-Resistance, Abstract Machines, and other lenses into a single map.
                                </p>
                            </div>
                        </div>
                    )}

                    {isGenerating && (
                        <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-indigo-200 rounded-xl bg-indigo-50/30 space-y-6">
                            <div className="relative">
                                <Activity className="h-10 w-10 text-indigo-400 animate-pulse" />
                                <div className="absolute inset-0 bg-indigo-500 blur-xl opacity-20 rounded-full animate-pulse" />
                            </div>
                            <div className="text-center space-y-2">
                                <p className="text-indigo-800 font-medium animate-pulse">Running Pre-LLM Compression (7 strata)...</p>
                                <p className="text-xs text-indigo-500 max-w-sm">
                                    Aggregating Context &gt; Packing JSON &gt; Structuring Frictions
                                </p>
                            </div>
                        </div>
                    )}

                    {mapData && !isGenerating && (
                        <div className="flex flex-col gap-6 animate-in fade-in slide-in-from-bottom-4 duration-700">

                            {mapData.isPartial && (
                                <div className="bg-amber-50 border border-amber-200 text-amber-800 p-3 rounded-lg flex items-start gap-2 text-xs">
                                    <AlertTriangle className="h-4 w-4 shrink-0 mt-0.5" />
                                    <div>
                                        <strong>Partial Map Generated.</strong> Analysis lacks full cross-strata representation.
                                        Sources used: {mapData.sourcesUsed?.join(", ")}.
                                    </div>
                                </div>
                            )}

                            {/* Render Heatmap / Network Graph via D3 */}
                            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-1 flex flex-col h-[500px]">
                                <FrictionGraph data={mapData} />
                            </div>

                            {/* Textural summary beneath graph */}
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-200 space-y-4">
                                    <h3 className="font-semibold text-slate-800 flex items-center gap-2">
                                        <CheckCircle2 className="h-4 w-4 text-emerald-500" />
                                        Consensus Zones
                                    </h3>
                                    <div className="space-y-4 max-h-80 overflow-y-auto pr-2">
                                        {mapData.consensus_zones?.map((z: any, i: number) => (
                                            <div key={i} className="text-sm p-3 bg-slate-50 border border-slate-100 rounded-md">
                                                <div className="font-medium text-slate-700 mb-1">{z.topic}</div>
                                                <div className="text-slate-600 text-xs mb-2">{z.description}</div>
                                                <div className="flex justify-between items-center mt-2">
                                                    <span className="text-[10px] bg-emerald-100 text-emerald-700 px-2 py-0.5 rounded-full font-medium">Strength: {z.strength}/10</span>
