                                        <AlertTriangle className="h-4 w-4 text-rose-500" />
                                        Structural Contradictions
                                    </h3>
                                    <div className="space-y-4 max-h-80 overflow-y-auto pr-2">
                                        {mapData.structural_contradictions?.map((c: any, i: number) => (
