                                aria-label={`Re-analyze with focus on: ${spot.title}`}
                            >
                                Re-Analyze with Focus
                            </Button>
                            <Button
                                size="sm"
                                variant="ghost"
                                onClick={() => onMarkAddressed?.(spot.id)}
                                className="text-xs"
                                aria-label={`Mark blind spot as addressed: ${spot.title}`}
