    const [activeLens, setActiveLens] = useState<string>('default');

    // [STATE] Simulation (Perspectives)
    const [perspectiveResults, setPerspectiveResults] = useState<Record<string, string> | null>(analysis.perspectives || null);
    const [isSimulating, setIsSimulating] = useState(false);

    // [STATE] Credits
    const { hasCredits, refetch: refetchCredits, loading: creditsLoading } = useCredits();
    const { isReadOnly } = useDemoMode();
    const [showTopUp, setShowTopUp] = useState(false);

    const hasGovernanceScores = !!(
        analysis.governance_scores &&
        typeof analysis.governance_scores.rights_focus === 'number' &&
        typeof analysis.governance_scores.procedurality === 'number'
    );

    const hasUserImpression = !!(userImpression && userImpression.trim().length > 0);
    const accountabilityData = analysis.accountability_map || {
        signatory: "",
        liability_holder: "",
        appeals_mechanism: "",
        human_in_the_loop: undefined
    };

    // --- HANDLERS ---

    const handleGeneratePerspectives = async () => {
        if (isReadOnly) {
            alert('Simulation is disabled in Demo Mode.');
            return;
        }

        // Credit Check
        if (!creditsLoading && !hasCredits) {
            setShowTopUp(true);
            return;
        }
        setIsSimulating(true);
        try {
            const headers: HeadersInit = { 'Content-Type': 'application/json' };
            if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true' && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
            }

            const response = await fetch('/api/simulate-perspectives', {
                method: 'POST',
                headers,
                body: JSON.stringify({
                    topic: sourceTitle,
                    perspectiveAId: DEFAULT_PERSPECTIVE_A.id,
                    perspectiveBId: DEFAULT_PERSPECTIVE_B.id
                })
            });

            const data = await response.json();
            if (data.success && data.perspectives) {
                const newPerspectives = {
                    [DEFAULT_PERSPECTIVE_A.id]: data.perspectives.perspectiveA,
                    [DEFAULT_PERSPECTIVE_B.id]: data.perspectives.perspectiveB
                };

                setPerspectiveResults(newPerspectives);
                refetchCredits();

                // Save to DB
                if (onUpdate) {
                    await onUpdate({ perspectives: newPerspectives });
                }
            }
        } catch (error) {
            console.error("Simulation failed:", error);
            alert("Failed to generate perspective simulation.");
        } finally {
            setIsSimulating(false);
        }
    };

    // Determine current display content based on lens
    const getCurrentContent = () => {
        if (activeLens === 'default') {
            return {
                title: "Key Insight",
                text: analysis.key_insight || "No key insight available.",
                colorClass: "bg-purple-100 text-purple-600",
                bgGradient: "from-purple-50 to-indigo-50",
                borderClass: "border-purple-100"
            };
        }

        // Use local state if recently generated, otherwise fall back to analysis props
        const results = perspectiveResults || analysis.perspectives;
        const resultText = results?.[activeLens];

        if (!resultText) return null;

        const isLensA = activeLens === DEFAULT_PERSPECTIVE_A.id;

        return {
            title: isLensA ? DEFAULT_PERSPECTIVE_A.name : DEFAULT_PERSPECTIVE_B.name,
            text: resultText,
            colorClass: isLensA ? "bg-indigo-100 text-indigo-700" : "bg-rose-100 text-rose-700",
            bgGradient: isLensA ? "from-indigo-50 to-blue-50" : "from-rose-50 to-orange-50",
            borderClass: isLensA ? "border-indigo-100" : "border-rose-100"
        };
    };

    const currentDisplay = getCurrentContent();

    return (
        <div className="space-y-6 animate-in fade-in duration-500">
            <CreditTopUpDialog open={showTopUp} onOpenChange={setShowTopUp} onSuccess={() => refetchCredits()} />

            {/* 1. Header Area: Lens Selector */}
            <div className="space-y-4">

                {/* Interpretation Lens Selector */}
                <InterpretationLensSelector
                    currentLens={activeLens}
                    onLensChange={setActiveLens}
                    onGenerate={handleGeneratePerspectives}
                    isGenerating={isSimulating}
                    hasResults={!!(perspectiveResults || analysis.perspectives)}
                />

                {/* Hero Card: Key Insight (Dynamic based on Lens) */}
                {currentDisplay && (
                    <div className={`relative overflow-hidden rounded-xl bg-gradient-to-br ${currentDisplay.bgGradient} border ${currentDisplay.borderClass} p-6 shadow-sm transition-all duration-500`}>
                        <div className={`absolute top-0 right-0 -mt-4 -mr-4 h-32 w-32 rounded-full blur-3xl opacity-50 ${currentDisplay.colorClass}`}></div>

                        <div className="relative flex items-start gap-4">
                            <div className={`p-3 bg-white rounded-xl shadow-sm shrink-0`}>
                                <Sparkles className={`h-6 w-6 ${currentDisplay.colorClass.split(' ')[1]}`} />
                            </div>
                            <div>
                                <h4 className={`text-xs font-bold uppercase tracking-widest mb-2 ${currentDisplay.colorClass.split(' ')[1]}`}>
                                    {currentDisplay.title} {activeLens !== 'default' && <span className="opacity-70">(Simulated)</span>}
                                </h4>
                                <p className="text-lg font-medium text-slate-900 leading-relaxed italic">
                                    &quot;{currentDisplay.text}&quot;
                                </p>
                            </div>
                        </div>
                    </div>
                )}
            </div>

            {/* 2. Secondary Info Grid */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {/* User Context Card */}
                {hasUserImpression && (
                    <div className="md:col-span-3 p-6 rounded-xl bg-white border border-slate-200 shadow-sm flex flex-col justify-center">
                        <h5 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3">Your Initial Anchor</h5>
                        <p className="text-sm text-slate-700 italic border-l-2 border-slate-300 pl-3">
                            &quot;{userImpression}&quot;
                        </p>
                        {analysis.anchor_bias_choice && (
                            <div className="mt-4 pt-4 border-t border-slate-100">
                                <span className={`text-[10px] font-bold px-2 py-1 rounded-full uppercase ${analysis.anchor_bias_choice === 'extractive_asymmetrical' ? 'bg-red-50 text-red-700' : 'bg-emerald-50 text-emerald-700'}`}>
                                    {analysis.anchor_bias_choice.replace('_', ' ')}
                                </span>
                            </div>
                        )}
                    </div>
                )}
            </div>

            {/* 3. Visual Diagnostics & Accountability */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 items-start">

                {/* Governance Compass */}
                {hasGovernanceScores && analysis.governance_scores && (
                    <div className="bg-white rounded-xl border border-slate-200 p-1 shadow-sm h-full min-h-[400px]">
                        <GovernanceCompass
                            rhetoricScore={analysis.governance_scores.rights_focus}
                            realityScore={analysis.governance_scores.procedurality}
                            driftExplanation={analysis.verification_gap?.gap_explanation}
                            scoreExplanations={analysis.governance_score_explanations}
                        />
                    </div>
                )}

                {/* Accountability Map */}
                <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm h-full">
                    <h3 className="text-sm font-bold text-slate-800 uppercase tracking-wide mb-4 flex items-center gap-2">
                        <span className="w-2 h-2 rounded-full bg-slate-800" />
                        Decision Ownership
                    </h3>
                    <AccountabilitySection
                        accountability={accountabilityData}
                        onMaterialize={(entity) => onMaterialize && onMaterialize({
                            name: entity.name,
                            detail: entity.detail,
                            context: "accountability"
                        })}
                        existingActors={[]} // TODO: Pass real actors
                        onViewActor={onViewActor}
                    />
                </div>
            </div>

            {/* Algorithmic Transparency - Phase 2 (Global Section) */}
            <AIAuditPanel
                analysis={analysis}
                sourceId={sourceId}
                sourceTitle={sourceTitle}
            />
        </div>
    );
}

import React, { useState } from 'react';
import { PromptDefinition } from '@/lib/prompts/registry';

interface PromptForkDialogProps {
    isOpen: boolean;
    onClose: () => void;
    currentPromptId: string;
    currentPromptVersion: string;
    defaultValue: string;
    onSaveFork: (newContent: string) => Promise<void>;
}

export function PromptForkDialog({
    isOpen,
    onClose,
    currentPromptId,
    currentPromptVersion,
    defaultValue,
    onSaveFork
}: PromptForkDialogProps) {
    const [forkContent, setForkContent] = useState(defaultValue);
    const [isSaving, setIsSaving] = useState(false);

    if (!isOpen) return null;

    const handleSave = async () => {
        setIsSaving(true);
        try {
            await onSaveFork(forkContent);
            onClose();
        } catch (error) {
            console.error("Failed to save fork:", error);
            // TODO: Add toast error
        } finally {
            setIsSaving(false);
        }
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
            <div className="bg-slate-900 border border-slate-700 rounded-lg shadow-xl w-full max-w-4xl flex flex-col max-h-[90vh]">
                <div className="p-4 border-b border-slate-700 flex justify-between items-center bg-slate-800/50 rounded-t-lg">
                    <div>
                        <h2 className="text-lg font-semibold text-slate-100 flex items-center gap-2">
                            <span className="text-amber-400">⚡</span>
                            Fork Prompt: {currentPromptId}
                        </h2>
                        <p className="text-xs text-slate-400">
                            Create a personalized branch from version <span className="font-mono text-slate-300">{currentPromptVersion}</span>
                        </p>
                    </div>
                    <button onClick={onClose} className="text-slate-400 hover:text-slate-200">
                        ✕
                    </button>
                </div>

                <div className="flex-1 overflow-hidden p-6 gap-6 flex flex-col">
                    <div className="bg-amber-900/20 border-l-4 border-amber-600 p-4 text-sm text-amber-200">
                        <strong>Existential Notice:</strong> You are about to negate the given configuration of this system.
                        By forking this prompt, you assume authorship and responsibility for the resulting analysis.
                    </div>

                    <div className="flex-1 flex flex-col gap-2 min-h-0">
                        <label className="text-sm font-medium text-slate-300">Prompt Definition</label>
                        <textarea
                            value={forkContent}
                            onChange={(e) => setForkContent(e.target.value)}
                            className="flex-1 w-full bg-slate-950 border border-slate-700 rounded-md p-4 text-sm font-mono text-slate-300 focus:outline-none focus:ring-2 focus:ring-amber-500/50 resize-none leading-relaxed"
                            spellCheck={false}
                        />
                    </div>
                </div>

                <div className="p-4 border-t border-slate-700 bg-slate-800/50 rounded-b-lg flex justify-end gap-3">
                    <button
                        onClick={onClose}
                        className="px-4 py-2 text-sm text-slate-400 hover:text-slate-200 transition-colors"
                    >
                        Cancel
                    </button>
                    <button
                        onClick={handleSave}
                        disabled={isSaving}
                        className="px-4 py-2 text-sm bg-amber-600 hover:bg-amber-500 text-white font-medium rounded-md shadow-lg shadow-amber-900/20 transition-all flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        {isSaving ? 'Forging...' : 'Save as Personal Override'}
                    </button>
                </div>
            </div>
        </div>
    );
}

import React from 'react';
import {
    Radar, RadarChart, PolarGrid, PolarAngleAxis,
    PolarRadiusAxis, ResponsiveContainer, Tooltip
} from 'recharts';
import { HelpCircle } from "lucide-react";
import { HelpTooltip } from "@/components/help/HelpTooltip";

interface StructuralRadarProps {
    scores?: {
        centralization: number;
        rights_focus: number;
        flexibility: number;
        market_power: number;
        procedurality: number;
        coloniality?: number;
    };
}

export function StructuralRadar({ scores }: StructuralRadarProps) {
    // Default scores if not provided
    const defaultScores = {
        centralization: 50,
        rights_focus: 50,
        flexibility: 50,
        market_power: 50,
        procedurality: 50,
        coloniality: 50
    };

    const s = scores || defaultScores;

    const data = [
        { subject: 'Centralization', A: s.centralization, fullMark: 100 },
        { subject: 'Rights Focus', A: s.rights_focus, fullMark: 100 },
        { subject: 'Flexibility', A: s.flexibility, fullMark: 100 },
        { subject: 'Market Power', A: s.market_power, fullMark: 100 },
        { subject: 'Procedurality', A: s.procedurality, fullMark: 100 },
        { subject: 'Coloniality', A: s.coloniality || 0, fullMark: 100 },
    ];

    return (
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
            <div className="flex items-center justify-between mb-6">
                <div>
                    <h4 className="text-sm font-bold text-slate-900 uppercase tracking-wide">Governance Profile</h4>
                    <p className="text-[10px] text-slate-500 mt-1 italic">Structural distribution across six dimensions</p>
                </div>
                <div className="flex items-center gap-1.5 px-2 py-1 bg-indigo-50 rounded text-[10px] font-bold text-indigo-600">
                    <div className="w-2 h-2 rounded-full bg-indigo-600 animate-pulse" />
                    LIVE ANALYSIS
                </div>
            </div>

            <div className="h-[300px] w-full">
                <ResponsiveContainer width="100%" height="100%">
                    <RadarChart cx="50%" cy="50%" outerRadius="80%" data={data}>
                        <PolarGrid stroke="#e2e8f0" />
                        <PolarAngleAxis
                            dataKey="subject"
                            tick={{ fill: '#64748b', fontSize: 10, fontWeight: 600 }}
                        />
                        <PolarRadiusAxis
                            angle={30}
                            domain={[0, 100]}
                            tick={false}
                            axisLine={false}
                        />
                        <Tooltip
                            content={({ active, payload }) => {
                                if (active && payload && payload.length) {
                                    return (
                                        <div className="bg-white p-3 border border-slate-200 shadow-xl rounded-lg text-xs">
                                            <p className="font-bold text-slate-900 mb-1">{payload[0].payload.subject}</p>
                                            <div className="flex items-center gap-2">
                                                <div className="h-1.5 flex-1 bg-slate-100 rounded-full overflow-hidden">
                                                    <div
                                                        className="h-full bg-indigo-500 rounded-full"
                                                        style={{ width: `${payload[0].value}%` }}
                                                    />
                                                </div>
                                                <span className="font-mono font-bold text-indigo-600">{payload[0].value}</span>
                                            </div>
                                        </div>
                                    );
                                }
                                return null;
                            }}
                        />
                        <Radar
                            name="Governance"
                            dataKey="A"
                            stroke="#4f46e5"
                            strokeWidth={2}
                            fill="#4f46e5"
                            fillOpacity={0.4}
                        />
                    </RadarChart>
                </ResponsiveContainer>
            </div>

            <div className="mt-4 grid grid-cols-2 gap-4">
                <div className="space-y-2">
                    <MetricLabel label="High Centralization" value={s.centralization > 70} />
                    <MetricLabel label="Rights-Preserving" value={s.rights_focus > 70} />
                    <MetricLabel label="Agile/Flexible" value={s.flexibility > 70} />
                </div>
                <div className="space-y-2">
                    <MetricLabel label="Market Dominant" value={s.market_power > 70} />
                    <MetricLabel label="Bureaucratic" value={s.procedurality > 70} />
                    <MetricLabel label="Center-Heavy" value={(s.coloniality || 0) > 70} />
                </div>
            </div>
        </div>
    );
}

function MetricLabel({ label, value }: { label: string, value: boolean }) {
    return (
        <div className="flex items-center gap-2">
            <div className={`w-1.5 h-1.5 rounded-full ${value ? 'bg-emerald-500' : 'bg-slate-200'}`} />
            <span className={`text-[10px] font-medium ${value ? 'text-slate-900' : 'text-slate-400'}`}>{label}</span>
        </div>
    );
}

import React, { useState } from 'react';
import { ChevronDown, ChevronUp, Info, AlertCircle, BookOpen, Code } from 'lucide-react';
import { Card } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { TransparencyMetadata } from '@/services/transparency-service';
import {
    Tooltip,
    TooltipContent,
    TooltipProvider,
    TooltipTrigger,
} from "@/components/ui/tooltip";

interface TransparencyPanelProps {
    metadata: TransparencyMetadata;
    score?: number;
}

export function TransparencyPanel({ metadata, score }: TransparencyPanelProps) {
    const [isExpanded, setIsExpanded] = useState(false);

    const confidenceColors = {
        high: 'bg-emerald-950/50 text-emerald-400 border-emerald-500/30',
        medium: 'bg-amber-950/50 text-amber-400 border-amber-500/30',
        low: 'bg-rose-950/50 text-rose-400 border-rose-500/30'
    };

    const getScoreInterpretation = (s: number, metric: string) => {
        if (s >= 90) return "Very High: Maximum structural intensity and analytical certainty.";
        if (s >= 70) {
            if (metric.includes("Asymmetry")) return "High Imbalance: Significant epistemic exclusion detected.";
            if (metric.includes("Power")) return "Significant Concentration: Power is held by a few key actors.";
            return "High Intensity: This pattern is prominent and analytically significant.";
        }
        if (s >= 50) return "Moderate: Notable pattern presence with balanced counter-forces.";
        if (s >= 30) return "Low: Minor presence; mostly distributed or ambiguous.";
        return "Minimal: This dynamic is not a primary driver in this analysis.";
    };

    return (
        <TooltipProvider>
            <Card className="bg-zinc-900 border-zinc-700 shadow-xl overflow-hidden group transition-all duration-300 hover:border-zinc-500">
                {/* Header - Always Visible */}
