                        <div className="pt-6">
                            <div className="flex items-center gap-2 mb-3">
                                <Code className="w-4 h-4 text-purple-400" />
                                <h4 className="font-bold text-zinc-100 uppercase text-xs tracking-wider">The Formula</h4>
