                                </div>
                            </div>
                        </div>

                        {/* Footer Info */}
                        <div className="flex items-center justify-between pt-4 border-t border-zinc-800 text-[10px] uppercase font-bold tracking-[0.2em]">
                            <span className="text-zinc-600">Metric Kernel v{metadata.version}</span>
                            <span className="text-zinc-600">Updated: {metadata.last_updated}</span>
                        </div>
                    </div>
                )}
            </Card>
        </TooltipProvider>
    );
}

type AbstractMachineStub = {
    diagram?: {
        operators?: unknown[];
        constraints?: unknown[];
        transformations?: unknown[];
    };
    [key: string]: unknown;
};

function namesFrom(arr: unknown[], fallbackPrefix: string): string[] {
    return (arr ?? []).map((x, i) => String((x as Record<string, unknown>)?.name ?? (x as Record<string, unknown>)?.id ?? `${fallbackPrefix}-${i}`));
}

function getBigrams(s: string): Set<string> {
    const b = new Set<string>();
    const str = s.toLowerCase();
    for (let i = 0; i < str.length - 1; i++) {
        b.add(str.slice(i, i + 2));
    }
    return b;
}

function stringSimilarity(a: string, b: string): number {
    if (a === b) return 1;
    const tA = getBigrams(a);
    const tB = getBigrams(b);
    if (tA.size === 0 && tB.size === 0) return 1;
    if (tA.size === 0 || tB.size === 0) return 0;
    let intersection = 0;
    for (const t of tA) if (tB.has(t)) intersection++;
    return intersection / (tA.size + tB.size - intersection);
}

const SIMILARITY_THRESHOLD = 0.45;

function fuzzyPartitions(a: Set<string>, b: Set<string>) {
    const shared: string[] = [];
    const onlyA: string[] = [];
    const onlyB: string[] = [];
    const matchedB = new Set<string>();
    const arrayA = Array.from(a);
    const arrayB = Array.from(b);
    const aMatched = new Set<string>();

    // Pass 1: Exact matches (case-insensitive)
    for (const x of arrayA) {
        const xNorm = x.toLowerCase().trim();
        for (const y of arrayB) {
            if (matchedB.has(y)) continue;
            if (xNorm === y.toLowerCase().trim()) {
                shared.push(x);
                matchedB.add(y);
                aMatched.add(x);
                break;
            }
        }
    }

    // Pass 2: Fuzzy matches
    for (const x of arrayA) {
        if (aMatched.has(x)) continue;
        let bestMatch = null;
        let bestScore = 0;
        for (const y of arrayB) {
            if (matchedB.has(y)) continue;
            const score = stringSimilarity(x, y);
            if (score > bestScore) {
                bestScore = score;
                bestMatch = y;
            }
        }
        if (bestMatch && bestScore >= SIMILARITY_THRESHOLD) {
            matchedB.add(bestMatch);
            aMatched.add(x);
            shared.push(`${x} (≈ ${bestMatch})`);
        } else {
            onlyA.push(x);
            aMatched.add(x);
        }
    }
    for (const y of b) {
        if (!matchedB.has(y)) onlyB.push(y);
    }
    return { shared: shared.sort(), onlyA: onlyA.sort(), onlyB: onlyB.sort() };
}

export function diffAbstractMachines(left: AbstractMachineStub, right: AbstractMachineStub) {
    const lOps = new Set<string>(namesFrom(left.diagram?.operators ?? [], "op"));
    const rOps = new Set<string>(namesFrom(right.diagram?.operators ?? [], "op"));

    const lCons = new Set<string>((left.diagram?.constraints as unknown[] ?? []).map((x: unknown) => String((x as Record<string, unknown>).rule || x)));
    const rCons = new Set<string>((right.diagram?.constraints as unknown[] ?? []).map((x: unknown) => String((x as Record<string, unknown>).rule || x)));

    const formatTransformation = (t: unknown, i: number) => {
        const tr = t as Record<string, unknown>;
        if (tr?.name) return String(tr.name);
        if (tr?.from && tr?.to) {
            const triggerText = tr.trigger ? ` via [${tr.trigger}]` : "";
            return `${tr.from} → ${tr.to}${triggerText}`;
        }
        return `tx-${i}`;
    };

    const lTrans = new Set<string>((left.diagram?.transformations ?? []).map(formatTransformation));
    const rTrans = new Set<string>((right.diagram?.transformations ?? []).map(formatTransformation));

    const opsDiff = fuzzyPartitions(lOps, rOps);
    const consDiff = fuzzyPartitions(lCons, rCons);
    const transDiff = fuzzyPartitions(lTrans, rTrans);

    const leftTokens = new Set<string>();
    const rightTokens = new Set<string>();
    const addTokens = (ops: any[], set: Set<string>) => {
        ops.forEach(op => {
            (op.inputs || []).forEach((t: any) => set.add(String(t)));
            (op.outputs || []).forEach((t: any) => set.add(String(t)));
        });
    };
    addTokens(left.diagram?.operators ?? [], leftTokens);
    addTokens(right.diagram?.operators ?? [], rightTokens);
    const tokensDiff = fuzzyPartitions(leftTokens, rightTokens);

    const sharedSpine = [
        ...opsDiff.shared.map((x) => `Operator: ${x}`),
        ...consDiff.shared.map((x) => `Constraint: ${x}`),
        ...transDiff.shared.map((x) => `Transformation: ${x}`),
        ...tokensDiff.shared.map((x) => `Token: ${x}`),
    ];

    const onlyInLeft = [
        ...opsDiff.onlyA.map((x) => `Operator: ${x}`),
        ...consDiff.onlyA.map((x) => `Constraint: ${x}`),
        ...transDiff.onlyA.map((x) => `Transformation: ${x}`),
        ...tokensDiff.onlyA.map((x) => `Token: ${x}`),
    ];

    const onlyInRight = [
        ...opsDiff.onlyB.map((x) => `Operator: ${x}`),
        ...consDiff.onlyB.map((x) => `Constraint: ${x}`),
        ...transDiff.onlyB.map((x) => `Transformation: ${x}`),
        ...tokensDiff.onlyB.map((x) => `Token: ${x}`),
    ];

    return {
        sharedSpine: opsDiff.shared,
        leftOnlyOps: opsDiff.onlyA,
        rightOnlyOps: opsDiff.onlyB,
        sharedCons: consDiff.shared,
        leftOnlyCons: consDiff.onlyA,
        rightOnlyCons: consDiff.onlyB,
        sharedTokens: tokensDiff.shared,
        leftOnlyTokens: tokensDiff.onlyA,
        rightOnlyTokens: tokensDiff.onlyB,
        textRepresentation: {
            sharedSpine,
            onlyInLeft,
            onlyInRight
        }
    };
}

export type Compat = "ok" | "coerced" | "incompatible";

type AnyObj = Record<string, any>;

export function normalizeAbstractMachine(input: unknown): { normalized: AnyObj | null; compat: Compat } {
    if (!input || typeof input !== "object") return { normalized: null, compat: "incompatible" };

    const am = input as AnyObj;
    let coerced = false;

    // Ensure top-level structure exists
    if (!am.diagram || typeof am.diagram !== "object") {
        am.diagram = {};
        coerced = true;
    }

    const ensureArray = (obj: AnyObj, key: string) => {
        if (!Array.isArray(obj[key])) {
            obj[key] = [];
            coerced = true;
        }
    };

    ensureArray(am.diagram, "operators");
    ensureArray(am.diagram, "constraints");
    ensureArray(am.diagram, "transformations");

    // Optional fields; keep stable
    if (!am.version) {
        am.version = "unknown";
        coerced = true;
    }

    return { normalized: am, compat: coerced ? "coerced" : "ok" };
}

'use client';

import React, { useState } from 'react';
import { useTeam } from '@/hooks/useTeam';
import { Button } from '@/components/ui/button';
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import { Copy, Check, Mail, UserPlus } from 'lucide-react';
import { toast } from 'sonner';

interface InviteMemberDialogProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
}

export const InviteMemberDialog: React.FC<InviteMemberDialogProps> = ({ open, onOpenChange }) => {
    const { inviteMember } = useTeam();
    const [email, setEmail] = useState('');
    const [role, setRole] = useState<'OWNER' | 'EDITOR' | 'VOTER'>('EDITOR');
    const [isCreating, setIsCreating] = useState(false);
    const [inviteLink, setInviteLink] = useState<string | null>(null);
    const [copied, setCopied] = useState(false);

    const validateEmail = (email: string) => {
        return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
    };

    const handleCreateInvite = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!validateEmail(email)) {
            toast.error('Please enter a valid email address');
            return;
        }

        setIsCreating(true);
        const result = await inviteMember(email, role);
        setIsCreating(false);

        if (result.success && result.token) {
            const link = `${window.location.origin}/invite/${result.token}`;
            setInviteLink(link);
        }
    };

    const handleCopyLink = async () => {
        if (!inviteLink) return;

        try {
            await navigator.clipboard.writeText(inviteLink);
            setCopied(true);
            toast.success('Invitation link copied to clipboard');
            setTimeout(() => setCopied(false), 2000);
        } catch (err) {
            toast.error('Failed to copy link');
        }
    };

    const handleClose = () => {
        setEmail('');
        setRole('EDITOR');
        setInviteLink(null);
        setCopied(false);
        onOpenChange(false);
    };

    return (
        <Dialog open={open} onOpenChange={handleClose}>
            <DialogContent className="sm:max-w-[500px] bg-zinc-600 border-zinc-400 shadow-2xl text-white">
                <DialogHeader>
                    <DialogTitle className="flex items-center gap-2">
                        <UserPlus className="w-5 h-5 text-indigo-400" />
                        Invite Team Member
                    </DialogTitle>
                    <DialogDescription className="text-zinc-300">
                        Send an invitation link to add a new member to your team. The link expires in 72 hours.
                    </DialogDescription>
                </DialogHeader>

                {!inviteLink ? (
                    <form onSubmit={handleCreateInvite} className="grid gap-4 py-4">
                        <div className="grid gap-2">
                            <Label htmlFor="email" className="text-zinc-200">
                                Email Address
                            </Label>
                            <div className="relative">
                                <Mail className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-400" />
                                <Input
                                    id="email"
                                    type="email"
                                    value={email}
                                    onChange={(e) => setEmail(e.target.value)}
                                    placeholder="colleague@example.com"
                                    className="pl-10 bg-zinc-800 border-zinc-600 text-white placeholder:text-zinc-500"
                                    autoFocus
                                    required
                                />
                            </div>
                        </div>

                        <div className="grid gap-2">
                            <Label htmlFor="role" className="text-zinc-200">
                                Role
                            </Label>
                            <Select value={role} onValueChange={(v) => setRole(v as 'OWNER' | 'EDITOR' | 'VOTER')}>
                                <SelectTrigger className="bg-zinc-800 border-zinc-600 text-white">
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent className="bg-zinc-800 border-zinc-600">
                                    <SelectItem value="VOTER">Voter - Can view and vote</SelectItem>
                                    <SelectItem value="EDITOR">Editor - Can view and edit</SelectItem>
                                    <SelectItem value="OWNER">Owner - Full admin access</SelectItem>
                                </SelectContent>
                            </Select>
                            <p className="text-xs text-zinc-400">
                                {role === 'OWNER' && 'Owners can invite members, manage settings, and delete the team.'}
                                {role === 'EDITOR' && 'Editors can view and edit team content but cannot manage members.'}
                                {role === 'VOTER' && 'Voters can view content and participate in governance voting.'}
                            </p>
                        </div>

                        <DialogFooter>
                            <Button
                                type="button"
                                variant="outline"
                                onClick={handleClose}
                                className="bg-zinc-800 border-zinc-600 hover:bg-zinc-700"
                            >
                                Cancel
                            </Button>
                            <Button
                                type="submit"
                                disabled={isCreating || !email}
                                className="bg-indigo-600 hover:bg-indigo-700 text-white"
                            >
                                {isCreating ? 'Creating...' : 'Create Invitation'}
                            </Button>
                        </DialogFooter>
                    </form>
                ) : (
                    <div className="grid gap-4 py-4">
                        <div className="bg-zinc-800 border border-zinc-600 rounded-lg p-4">
                            <p className="text-sm text-zinc-300 mb-2">Invitation Link</p>
                            <div className="flex items-center gap-2">
                                <code className="flex-1 text-xs bg-zinc-900 px-3 py-2 rounded border border-zinc-700 text-indigo-300 break-all">
                                    {inviteLink}
                                </code>
                                <Button
                                    size="sm"
                                    onClick={handleCopyLink}
                                    className="bg-indigo-600 hover:bg-indigo-700 shrink-0"
                                >
                                    {copied ? <Check className="w-4 h-4" /> : <Copy className="w-4 h-4" />}
                                </Button>
                            </div>
                            <p className="text-xs text-zinc-400 mt-2">
                                ⏱️ Expires in 72 hours • One-time use only
                            </p>
                        </div>

                        <DialogFooter>
                            <Button
                                onClick={handleClose}
                                className="bg-zinc-800 hover:bg-zinc-700 text-white w-full"
                            >
                                Done
                            </Button>
                        </DialogFooter>
                    </div>
                )}
            </DialogContent>
        </Dialog>
    );
};

'use client';

import React, { useState } from 'react';
import { useAuth } from '@clerk/nextjs';
import { TeamMember } from '@/hooks/useTeam';
import { Button } from '@/components/ui/button';
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from '@/components/ui/alert-dialog';
import { Badge } from '@/components/ui/badge';
import { Users, Crown, UserMinus, User } from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';

interface TeamMembersProps {
    members: TeamMember[];
    currentUserRole?: 'OWNER' | 'EDITOR' | 'VOTER';
    onRemoveMember: (userId: string) => Promise<{ success: boolean; error?: string }>;
}

export const TeamMembers: React.FC<TeamMembersProps> = ({ members, currentUserRole, onRemoveMember }) => {
    const { userId: currentUserId } = useAuth();
    const [removingUserId, setRemovingUserId] = useState<string | null>(null);
    const [showConfirmDialog, setShowConfirmDialog] = useState(false);
    const [isRemoving, setIsRemoving] = useState(false);

    // Sort: owners first, then by join date
    const sortedMembers = [...members].sort((a, b) => {
        if (a.role === 'OWNER' && b.role !== 'OWNER') return -1;
        if (a.role !== 'OWNER' && b.role === 'OWNER') return 1;
        return a.joinedAt - b.joinedAt;
    });

    const handleRemoveClick = (userId: string) => {
        setRemovingUserId(userId);
        setShowConfirmDialog(true);
    };

    const handleConfirmRemove = async () => {
        if (!removingUserId) return;

        setIsRemoving(true);
        await onRemoveMember(removingUserId);
        setIsRemoving(false);
        setShowConfirmDialog(false);
        setRemovingUserId(null);
    };

    const getInitials = (email: string, name?: string) => {
        if (name) {
            return name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2);
        }
        return email.slice(0, 2).toUpperCase();
    };

    const memberToRemove = members.find(m => m.userId === removingUserId);

    return (
        <>
            <div className="space-y-3">
                {sortedMembers.length === 0 ? (
                    <div className="text-center py-8 text-zinc-400">
                        <Users className="w-12 h-12 mx-auto mb-3 opacity-50" />
                        <p>No members yet</p>
                    </div>
                ) : (
                    sortedMembers.map((member) => {
                        const isCurrentUser = member.userId === currentUserId;
                        const canRemove = currentUserRole === 'OWNER' && !isCurrentUser;

                        return (
                            <div
                                key={member.userId}
                                className="flex items-center justify-between p-4 bg-zinc-800 border border-zinc-700 rounded-lg hover:border-zinc-600 transition-colors"
                            >
                                <div className="flex items-center gap-3">
                                    {/* Avatar */}
                                    <div className="flex items-center justify-center w-10 h-10 rounded-full bg-indigo-900/30 text-indigo-300 font-semibold border border-indigo-500/20">
                                        {getInitials(member.email, member.name)}
                                    </div>

                                    {/* Info */}
                                    <div>
                                        <div className="flex items-center gap-2">
                                            <span className="font-medium text-white">
                                                {member.name || member.email}
                                            </span>
                                            {isCurrentUser && (
                                                <Badge variant="outline" className="text-xs border-indigo-500/30 text-indigo-300">
                                                    You
                                                </Badge>
                                            )}
                                            {member.role === 'OWNER' && (
                                                <Crown className="w-4 h-4 text-amber-400" aria-label="Owner" />
                                            )}
                                        </div>
                                        <div className="flex items-center gap-2 text-sm text-zinc-400">
                                            <span>{member.email}</span>
                                            <span>•</span>
                                            <span>Joined {formatDistanceToNow(member.joinedAt, { addSuffix: true })}</span>
                                        </div>
                                    </div>
                                </div>

                                {/* Actions */}
                                <div className="flex items-center gap-2">
                                    <Badge variant={member.role === 'OWNER' ? 'default' : 'secondary'}>
                                        {member.role}
                                    </Badge>
                                    {canRemove && (
                                        <Button
                                            size="sm"
                                            variant="ghost"
                                            onClick={() => handleRemoveClick(member.userId)}
                                            className="text-red-400 hover:text-red-300 hover:bg-red-950/20"
                                            aria-label={`Remove ${member.email}`}
                                        >
                                            <UserMinus className="w-4 h-4" />
                                        </Button>
                                    )}
                                </div>
                            </div>
                        );
                    })
                )}
            </div>

            {/* Confirmation Dialog */}
            <AlertDialog open={showConfirmDialog} onOpenChange={setShowConfirmDialog}>
                <AlertDialogContent className="bg-zinc-800 border-zinc-700 text-white">
                    <AlertDialogHeader>
                        <AlertDialogTitle>Remove Team Member?</AlertDialogTitle>
                        <AlertDialogDescription className="text-zinc-300">
                            Are you sure you want to remove <strong>{memberToRemove?.email}</strong> from the team?
                            They will lose access to all team data and analyses.
                        </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter>
                        <AlertDialogCancel className="bg-zinc-700 border-zinc-600 hover:bg-zinc-600">
                            Cancel
                        </AlertDialogCancel>
                        <AlertDialogAction
                            onClick={handleConfirmRemove}
                            disabled={isRemoving}
                            className="bg-red-600 hover:bg-red-700 text-white"
                        >
                            {isRemoving ? 'Removing...' : 'Remove Member'}
                        </AlertDialogAction>
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>
        </>
    );
};

