                        </DropdownMenuItem>
                    </DropdownMenuGroup>

                    <DropdownMenuSeparator className="bg-zinc-800" />

                    {/* Teams List */}
                    <DropdownMenuGroup>
                        {availableTeams.length > 0 && (
                            <DropdownMenuLabel className="text-xs text-zinc-500 font-mono uppercase tracking-wider">
                                Teams
