"use client";

import { Send, Loader2, CheckCircle2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { useActionState, useEffect, useState } from "react";
import { sendContactEmail } from "@/app/actions/contact";
import { toast } from "sonner";

const initialState = {
    success: false,
    error: ""
};

export function ContactForm() {
    const [state, formAction, isPending] = useActionState(sendContactEmail, initialState);
    const [isSuccess, setIsSuccess] = useState(false);

    useEffect(() => {
        if (state.success) {
            toast.success("Message sent successfully!");
            // eslint-disable-next-line react-hooks/set-state-in-effect
            setIsSuccess(true);
        } else if (state.error) {
            toast.error(state.error);
        }
    }, [state]);

    if (isSuccess) {
        return (
            <div className="h-full flex flex-col items-center justify-center text-center animate-in fade-in zoom-in duration-500">
                <div className="w-16 h-16 bg-emerald-100 rounded-full flex items-center justify-center mb-6">
                    <CheckCircle2 className="h-8 w-8 text-emerald-600" />
                </div>
                <h2 className="text-2xl font-bold text-slate-900 mb-2">Message Sent!</h2>
                <p className="text-slate-500 mb-8 max-w-xs">
                    Thank you for reaching out. We've received your message and will get back to you shortly.
                </p>
                <Button
                    onClick={() => setIsSuccess(false)}
                    variant="outline"
                    className="border-slate-200"
                >
                    Send Another Message
                </Button>
            </div>
        );
    }

    return (
        <form action={formAction} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                    <Label htmlFor="name">Name</Label>
                    <Input id="name" name="name" placeholder="Dr. Jane Doe" required className="bg-slate-50 border-slate-200" />
                </div>
                <div className="space-y-2">
                    <Label htmlFor="email">Email</Label>
                    <Input id="email" name="email" type="email" placeholder="jane@university.edu" required className="bg-slate-50 border-slate-200" />
                </div>
            </div>

            <div className="space-y-2">
                <Label htmlFor="subject">Subject</Label>
                <Input id="subject" name="subject" placeholder="Question about Academic Grants..." required className="bg-slate-50 border-slate-200" />
            </div>

            <div className="space-y-2">
                <Label htmlFor="message">Message</Label>
                <Textarea
                    id="message"
                    name="message"
                    placeholder="Tell us how we can help..."
                    required
                    className="min-h-[150px] bg-slate-50 border-slate-200 resize-none"
                />
            </div>

            <div className="pt-2">
                <Button
                    type="submit"
                    className="w-full bg-slate-900 hover:bg-slate-800 text-white"
                    disabled={isPending}
                >
                    {isPending ? (
                        <>
                            <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                            Sending...
                        </>
                    ) : (
                        <>
                            Send Message
                            <Send className="ml-2 h-4 w-4" />
                        </>
                    )}
                </Button>
                {/* Honeypot Field - Hidden from humans */}
                <input type="text" name="website" className="hidden" tabIndex={-1} autoComplete="off" />
                {!process.env.NEXT_PUBLIC_SMTP_CONFIGURED && (
                    <p className="text-[10px] text-slate-400 text-center mt-3">
                        (Note: In Demo Mode, messages are simulated)
                    </p>
                )}
            </div>
        </form>
    );
}

import React, { useMemo, useState } from 'react';
import Link from 'next/link';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { AlertCircle, Clock, ShieldAlert, Users, BrainCircuit, Sparkles, Loader2, ArrowRight, Plus, Ghost } from 'lucide-react';
import { EcosystemActor } from '@/types/ecosystem';

interface AbsencePanelProps {
    actors: EcosystemActor[];
    analyzedText?: string;
    onSimulate?: (query: string, source?: "default" | "simulation" | "absence_fill") => Promise<void>;
    topic?: string;
}

export interface AiAbsenceAnalysis {
    narrative: string;
    missing_voices: { name: string; reason: string; category: string }[];
    structural_voids: string[];
    blindspot_intensity: "Low" | "Medium" | "High";
}

interface AbsencePanelProps {
    actors: EcosystemActor[];
    analyzedText?: string;
    onSimulate?: (query: string, source?: "default" | "simulation" | "absence_fill") => Promise<void>;
    topic?: string;
    savedAnalysis?: AiAbsenceAnalysis | null;
    onSaveAnalysis?: (analysis: AiAbsenceAnalysis) => void;
}

export function AbsencePanel({ actors, analyzedText = "", onSimulate, topic, savedAnalysis, onSaveAnalysis }: AbsencePanelProps) {
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    // Use savedAnalysis if available, otherwise local state (though local state basically ignored if saved provided)
    const [localAiAnalysis, setLocalAiAnalysis] = useState<AiAbsenceAnalysis | null>(null);
    const aiAnalysis = savedAnalysis !== undefined ? savedAnalysis : localAiAnalysis;
    const [simulatingIndex, setSimulatingIndex] = useState<number | null>(null);

    const handleDeepScan = async () => {
        setIsAnalyzing(true);
        try {
            const headers: HeadersInit = { 'Content-Type': 'application/json' };
            if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true' && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
            }

            const response = await fetch('/api/ecosystem/absence', {
                method: 'POST',
                headers: headers,
                body: JSON.stringify({ actors, text: analyzedText })
            });
            const data = await response.json();
            console.log("Deep Scan Data Received:", data); // DEBUG LOG
            if (data.success) {
                if (onSaveAnalysis) {
                    onSaveAnalysis(data.analysis);
                } else {
                    setLocalAiAnalysis(data.analysis);
                }
            } else {
                console.error("Deep Scan returned success:false", data);
            }
        } catch (error) {
            console.error("Deep Scan failed", error);
        } finally {
            setIsAnalyzing(false);
        }
    };

    const analysis = useMemo(() => {
        const results = {
            missingStakeholders: [] as string[],
            deferredStandards: [] as string[],
            enforcementDependencies: [] as string[]
        };

        // 1. Missing Stakeholders (Heuristic: Check for common missing groups)
        const commonStakeholders = [
            "Civil Society",
            "Labor Unions",
            "Environmental Groups",
            "Marginalized Communities",
            "Local Government",
            "Auditors"
        ];

        const presentTypes = new Set(actors.map(a => a.type));
        const presentNames = new Set(actors.map(a => a.name.toLowerCase()));

        commonStakeholders.forEach(stakeholder => {
            // Check if type matches or name fuzzy matches
            const isPresent = Array.from(presentTypes).some(t => t.toLowerCase() === stakeholder.toLowerCase()) ||
                Array.from(presentNames).some(n => n.includes(stakeholder.toLowerCase()));

            if (!isPresent) {
                results.missingStakeholders.push(stakeholder);
            }
        });

        // 2. Deferred Standards (Heuristic: Keywords in text)
        if (analyzedText) {
            const deferredKeywords = [
                "to be defined",
                "future rulemaking",
                "voluntary standard",
                "industry best practice",
                "as appropriate",
                "subject to available resources"
            ];

            // Simple sentence extraction
            const sentences = analyzedText.split(/[.!?]+/);
            deferredKeywords.forEach(keyword => {
                sentences.forEach(sentence => {
                    if (sentence.toLowerCase().includes(keyword)) {
                        results.deferredStandards.push(sentence.trim());
                    }
                });
            });

            // 3. Enforcement Dependencies
            const enforcementKeywords = [
                "upon establishment of",
                "contingent on",
                "subject to funding",
                "capacity building",
                "member state discretion"
            ];

            enforcementKeywords.forEach(keyword => {
                sentences.forEach(sentence => {
                    if (sentence.toLowerCase().includes(keyword)) {
                        results.enforcementDependencies.push(sentence.trim());
                    }
                });
            });
        }

        return results;
    }, [actors, analyzedText]);

    return (
        <Card className="h-full border-l-4 border-l-slate-400 bg-slate-50/50 flex flex-col">
            <CardHeader className="pb-2">
                <CardTitle className="text-lg font-semibold flex items-center justify-between text-slate-700">


                    <div className="flex items-center gap-2">
                        <Ghost className="h-5 w-5 text-indigo-600" />
                        Voices Silenced & Voids
                    </div>
                </CardTitle>
                <CardDescription>
                    Tracking who is excluded, what is deferred, and whose knowledge is silenced.
                </CardDescription>

                {/* AI Trigger */}
                <div className="pt-2">
                    <Button
                        size="sm"
                        onClick={handleDeepScan}
                        disabled={isAnalyzing}
                        className={`w-full text-xs font-medium gap-2 transition-all ${aiAnalysis ? "bg-indigo-100 text-indigo-700 hover:bg-indigo-200 border-indigo-200" : "bg-slate-900 text-white hover:bg-slate-800"}`}
                    >
                        {isAnalyzing ? (
                            <>
                                <Loader2 className="h-3 w-3 animate-spin" />
                                Listening for Silences...
                            </>
                        ) : aiAnalysis ? (
                            <>
                                <BrainCircuit className="h-3 w-3" />
                                Re-Analyze Silences
                            </>
                        ) : (
                            <>
                                <Sparkles className="h-3 w-3" />
                                Reveal Silenced Voices
                            </>
                        )}
                    </Button>
                </div>
            </CardHeader>
            <CardContent className="space-y-6 overflow-y-auto flex-1 p-4">

                {/* AI Results Section */}
                {aiAnalysis && (
                    <div className="space-y-4 border-2 border-indigo-100 rounded-lg p-2 bg-white">
                        <div className="bg-indigo-50 p-3 rounded-lg border border-indigo-100 shadow-sm">
                            <h4 className="text-xs font-bold text-indigo-800 uppercase tracking-wide mb-1 flex items-center justify-between gap-1">
                                <span className="flex items-center gap-1">
                                    <BrainCircuit className="h-3 w-3" />
                                    Assemblage Critique
                                </span>
                                {aiAnalysis.blindspot_intensity && (
                                    <span className={`text-[10px] px-1.5 py-0.5 rounded-full border ${aiAnalysis.blindspot_intensity === "High" ? "bg-red-100 text-red-700 border-red-200" :
                                        aiAnalysis.blindspot_intensity === "Medium" ? "bg-amber-100 text-amber-700 border-amber-200" :
                                            "bg-emerald-100 text-emerald-700 border-emerald-200"
                                        }`}>
                                        Intensity: {aiAnalysis.blindspot_intensity}
                                    </span>
                                )}
                            </h4>
                            <p className="text-xs text-indigo-900 leading-relaxed italic">
                                "{aiAnalysis.narrative}"
                            </p>
                        </div>

                        {/* Structural Voids */}
                        <div>
                            <h4 className="text-xs font-bold text-slate-500 uppercase flex items-center gap-1 mb-2">
                                <AlertCircle className="h-3 w-3" />
                                Functional Voids
                            </h4>
                            <ul className="space-y-1">
                                {aiAnalysis.structural_voids.map((voidDesc, i) => (
                                    <li key={i} className="text-xs text-slate-700 pl-2 border-l-2 border-slate-300">
                                        {voidDesc}
                                    </li>
                                ))}
                            </ul>
                        </div>

                        {/* Missing Voices */}
                        <div>
                            <h4 className="text-xs font-bold text-slate-500 uppercase flex items-center gap-1 mb-2">
                                <Users className="h-3 w-3" />
                                Excluded Actors
                            </h4>
                            <div className="grid gap-2">
                                {aiAnalysis.missing_voices.map((mv, i) => (
                                    <div key={i} className="bg-white p-2 rounded border border-slate-200 shadow-sm group hover:border-indigo-300 transition-colors">
                                        <div className="flex justify-between items-start mb-1 gap-2">
                                            <div className="flex-1">
                                                <span className="font-semibold text-xs text-slate-900 block">{mv.name}</span>
                                                <span className="text-[10px] uppercase bg-slate-100 px-1 rounded text-slate-500">{mv.category}</span>
                                            </div>
                                            {onSimulate && (
                                                <Button
                                                    variant="ghost"
                                                    size="icon"
                                                    className="h-6 w-6 text-indigo-600 hover:bg-indigo-50 hover:text-indigo-800 -mt-1 -mr-1"
                                                    title={`Simulate ${mv.name}`}
                                                    disabled={simulatingIndex === i}
                                                    onClick={async () => {
                                                        setSimulatingIndex(i);
                                                        const context = topic ? `within the broader assemblage of "${topic}"` : "relevant to this ecosystem";
                                                        try {
                                                            await onSimulate(
                                                                `Generate detailed ecosystem actors representing "${mv.name}" (${mv.category}) ${context}. Key context: ${mv.reason}`,
                                                                "absence_fill"
                                                            );
                                                        } finally {
                                                            setSimulatingIndex(null);
                                                        }
                                                    }}
                                                >
                                                    {simulatingIndex === i ? (
                                                        <Loader2 className="h-3 w-3 animate-spin" />
                                                    ) : (
                                                        <Plus className="h-4 w-4" />
                                                    )}
                                                </Button>
                                            )}
                                        </div>
                                        <p className="text-[10px] text-slate-500 leading-tight">{mv.reason}</p>
                                    </div>
                                ))}
                            </div>
                        </div>

                        <div className="h-px bg-slate-200 my-4" />
                    </div>
                )}

                {/* Standard Heuristics (Always Visible as Baseline) */}
                <div className="opacity-80 hover:opacity-100 transition-opacity">
                    {!aiAnalysis && <h3 className="text-xs font-bold text-slate-400 uppercase mb-3 text-center">- Initial Heuristic Scan -</h3>}

                    {/* Missing Stakeholders */}
                    <div className="mb-4">
                        <h4 className="text-sm font-bold text-slate-800 flex items-center gap-2 mb-2">
                            <Users className="h-4 w-4 text-slate-400" />
                            Standard Gaps
                        </h4>
                        {analysis.missingStakeholders.length > 0 ? (
                            <div className="flex flex-wrap gap-2">
                                {analysis.missingStakeholders.map(s => (
                                    <span key={s} className="px-2 py-1 bg-slate-100 text-slate-600 text-xs rounded-full border border-slate-200">
                                        {s}
                                    </span>
                                ))}
                            </div>
                        ) : (
                            <p className="text-xs text-slate-500 italic">No standard missing types detected.</p>
                        )}
                    </div>

                    {/* Deferred Standards */}
                    <div className="mb-4">
                        <h4 className="text-sm font-bold text-slate-800 flex items-center gap-2 mb-2">
                            <Clock className="h-4 w-4 text-slate-400" />
                            Deferred Mechanisms
                        </h4>
                        {analysis.deferredStandards.length > 0 ? (
                            <ul className="space-y-2">
                                {analysis.deferredStandards.slice(0, 3).map((s, i) => (
                                    <li key={i} className="text-xs text-slate-600 bg-slate-50 p-2 rounded border border-slate-100">
                                        "{s}..."
                                    </li>
                                ))}
                            </ul>
                        ) : (
                            <p className="text-xs text-slate-500 italic">
                                {analyzedText ? "No deferred mechanisms found in text." : "Scan text to detect deferred standards."}
                            </p>
                        )}
                    </div>
                </div>

            </CardContent>
        </Card>
    );
}

import React from 'react';
import { EcosystemActor, EcosystemConfiguration } from '@/types/ecosystem';
import { getBiasIntensity } from '@/lib/ecosystem-utils';
import { ProvisionalBadge } from '@/components/ui/provisional-badge';
import { Badge } from '@/components/ui/badge';
import { Checkbox } from '@/components/ui/checkbox';
import { ExternalLink, Layers, FileText, AlertTriangle } from 'lucide-react';

import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '@/components/ui/tooltip';
import { cn } from '@/lib/utils';

const ABSENCE_DESCRIPTIONS: Record<string, string> = {
    'textual-absence': "Simply not mentioned in the text.",
    'structural-exclusion': "Lack of formal roles or institutions for the actor in this context.",
    'discursive-marginalization': "The document's logic or framing excludes the actor's primary concerns.",
    'constitutive-silence': "An absence that is fundamental to the document's logic or world-view.",
    'Textual': "Simply not mentioned in the text.",
    'Structural': "Lack of formal roles or institutions for the actor.",
    'Discursive': "The document's framing excludes the actor's concerns.",
    'Constitutive': "An absence fundamental to the document's logic."
};

const EXCLUSION_DESCRIPTIONS: Record<string, string> = {
    'silenced': "Active omission or censorship of the actor's perspective.",
    'marginalized': "Actor is mentioned but their influence or agency is minimized.",
    'structurally-excluded': "The framework inherently prevents the actor's participation.",
    'displaced': "Actor's roles have been reassigned to other entities."
};

interface ActorCardProps {
    actor: EcosystemActor;
    isSelected: boolean;
    isGroupSelected: boolean;
    onSelect: () => void;
    onToggleGroupSelection: () => void;


    configurations?: EcosystemConfiguration[];
    // [NEW] ANT Workbench Props
    isTraced?: boolean;
    onTrace?: () => void;
}

export function ActorCard({
    actor,
    isSelected,
    isGroupSelected,
    onSelect,
    onToggleGroupSelection,
    configurations = [],
    isTraced,
    onTrace
}: ActorCardProps) {
    return (
        <TooltipProvider>
            <div
                aria-label={('isGhost' in actor && (actor as any).isGhost) ? `Ghost Node: ${actor.name}` : `Actor: ${actor.name}`}
                className={`p-3 rounded-md border cursor-pointer transition-colors relative flex gap-3 
                    ${isTraced ? 'bg-rose-50/80 border-rose-400 ring-2 ring-rose-200 shadow-sm' :
                        isSelected ? 'bg-indigo-50 border-indigo-200' :
                            isGroupSelected ? 'bg-indigo-50/50 border-indigo-300 ring-1 ring-indigo-300/20' :
                                actor.source === 'absence_fill' ? 'bg-amber-50/50 border-amber-200 hover:bg-amber-50' : 'bg-white hover:bg-slate-50'}`}
                onClick={onSelect}
            >
                {/* Checkbox Column */}
                <div className="flex flex-col items-center pt-1" onClick={(e) => e.stopPropagation()}>
                    <Checkbox
                        checked={isGroupSelected}
                        onCheckedChange={onToggleGroupSelection}
                        className="border-slate-300 data-[state=checked]:bg-indigo-600 data-[state=checked]:border-indigo-600 h-4 w-4"
                    />
                </div>

                {/* Main Content Column */}
                <div className="flex-1 min-w-0 flex flex-col gap-2">
                    {actor.source === 'absence_fill' && (
                        <div className="absolute -top-1.5 -right-1.5">
                            <span className="flex h-3 w-3 relative">
                                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-amber-400 opacity-75"></span>
                                <span className="relative inline-flex rounded-full h-3 w-3 bg-amber-500"></span>
                            </span>
                        </div>
                    )}

                    {/* Header: Name + Badges */}
                    <div className="flex items-start justify-between gap-2">
                        <div className="flex flex-wrap items-center gap-1.5">
                            <span className={`font-semibold text-sm ${actor.source === 'absence_fill' ? 'text-amber-900 group-hover:text-amber-700' : 'text-slate-900'}`}>
                                {actor.name}
                            </span>
                            {(!actor.source || actor.source === 'default') && !('isGhost' in actor && (actor as any).isGhost) && (
                                <ProvisionalBadge
                                    className="h-4 px-1 text-[9px] border-indigo-200 bg-indigo-50 text-indigo-600"
                                    fragility={{ value: 0.4, interpretation: "provisional", factors: { input_completeness: 0.5, model_uncertainty: 0.3, theoretical_tension: 0.4, empirical_grounding: 0.8 } }}
                                />
                            )}
                            {/* [NEW] Ghost/Absence Specific Badges */}
                            {('isGhost' in actor && (actor as any).isGhost) && (
                                <>
                                    {(actor as any).absenceType && (
                                        <Tooltip>
                                            <TooltipTrigger asChild>
                                                <Badge className="h-4 px-1 text-[9px] bg-amber-100 text-amber-800 border-amber-200 cursor-help">
                                                    {(actor as any).absenceType.includes('constitutive') ? 'Constitutive' :
                                                        (actor as any).absenceType.includes('discursive') ? 'Discursive' :
                                                            (actor as any).absenceType.includes('structural') ? 'Structural' :
                                                                (actor as any).absenceType.includes('textual') ? 'Textual' :
                                                                    ((actor as any).absenceType.split('-')[0])}
                                                </Badge>
                                            </TooltipTrigger>
                                            <TooltipContent className="max-w-[200px]">
                                                <p>{ABSENCE_DESCRIPTIONS[(actor as any).absenceType] || ABSENCE_DESCRIPTIONS[(actor as any).absenceType.split('-')[0].charAt(0).toUpperCase() + (actor as any).absenceType.split('-')[0].slice(1)] || "Mechanism of absence in the document."}</p>
                                            </TooltipContent>
                                        </Tooltip>
                                    )}
                                    {(actor as any).exclusionType && (
                                        <Tooltip>
                                            <TooltipTrigger asChild>
                                                <Badge className="h-4 px-1 text-[9px] bg-slate-100 text-slate-600 border-slate-200 lowercase cursor-help">
                                                    {(actor as any).exclusionType}
                                                </Badge>
                                            </TooltipTrigger>
                                            <TooltipContent className="max-w-[200px]">
                                                <p>{EXCLUSION_DESCRIPTIONS[(actor as any).exclusionType] || "Type of exclusion detected."}</p>
                                            </TooltipContent>
                                        </Tooltip>
                                    )}
                                </>
                            )}
                        </div>

                        {/* Top Right Badges */}
                        <div className="flex gap-1 shrink-0 flex-wrap justify-end">
                            {actor.source === 'absence_fill' && (
                                <Tooltip>
                                    <TooltipTrigger asChild>
                                        <Badge variant="outline" className="text-[9px] px-1 py-0 h-5 border-amber-300 text-amber-600 bg-amber-100 cursor-help">
                                            Recovered
                                        </Badge>
                                    </TooltipTrigger>
                                    <TooltipContent>
                                        <p>Actor identified as potentially missing and restored from absence analysis.</p>
                                    </TooltipContent>
                                </Tooltip>
                            )}
                            <Badge variant="outline" className="text-[10px] px-1 py-0 h-5 font-normal">
                                {actor.type}
                            </Badge>
                            {actor.role_type && (
                                <Badge variant="secondary" className="text-[10px] px-1 py-0 h-5 bg-slate-100 text-slate-600 border border-slate-200 font-normal">
                                    {actor.role_type}
                                </Badge>
                            )}
                        </div>
                    </div>

                    {/* Description */}
                    <p className="text-xs text-slate-500 line-clamp-2 leading-relaxed">
                        {actor.description}
                    </p>

                    {/* Assemblage Memberships (Middle Section) */}
                    {configurations.some(c => c.memberIds.includes(actor.id)) && (
                        <div className="mt-1 bg-amber-50 rounded-md p-2 border border-amber-100">
                            <p className="text-[10px] font-semibold text-amber-800 mb-1 flex items-center gap-1 uppercase tracking-wider">
                                <Layers className="h-3 w-3" /> Assemblage Memberships
                            </p>
                            <ul className="space-y-1">
                                {configurations.filter(c => c.memberIds.includes(actor.id)).map(c => (
                                    <li key={c.id} className="text-xs flex items-center justify-between group/item">
                                        <span className="font-medium text-slate-700 truncate mr-2">{c.name}</span>
                                        {c.properties?.stability && (
                                            <Tooltip>
                                                <TooltipTrigger asChild>
                                                    <Badge variant="outline" className="text-[9px] h-4 px-1 py-0 bg-white border-slate-200 text-slate-400 shrink-0 cursor-help">
                                                        {c.properties.stability}
                                                    </Badge>
                                                </TooltipTrigger>
                                                <TooltipContent>
                                                    <p>Assemblage Stability: {c.properties.stability}. Indicates how established this group is in the document.</p>
                                                </TooltipContent>
                                            </Tooltip>
                                        )}
                                    </li>
                                ))}
                            </ul>
                        </div>
                    )}

                    {/* Trace Evidence */}
                    {actor.quotes && actor.quotes.length > 0 && (
                        <div className="mt-1 bg-slate-50 p-2 rounded border border-slate-100">
                            <p className="text-[10px] font-semibold text-slate-400 mb-1 flex items-center gap-1 uppercase tracking-wider">
                                <FileText className="h-3 w-3" /> Empirical Traces
                            </p>
                            <ul className="space-y-1">
                                {actor.quotes.map((quote, idx) => (
                                    <li key={idx} className="text-[10px] text-slate-600 italic border-l-2 border-indigo-200 pl-2 line-clamp-2">
                                        &quot;{quote}&quot;
                                    </li>
                                ))}
                            </ul>
                        </div>
                    )}

                    {/* [NEW] Bias Hot Spot Warning */}
                    {getBiasIntensity(actor) > 0.5 && (
                        <div className="mt-1 bg-red-50 p-2 rounded border border-red-100">
                            <p className="text-[10px] font-semibold text-red-700 mb-1 flex items-center gap-1 uppercase tracking-wider">
                                <AlertTriangle className="h-3 w-3" /> Structural Friction (Hot Spot)
                            </p>
                            <p className="text-[10px] text-red-600 leading-snug">
                                High structural resistance detected. This actor may be a site of algorithmic bias, extraction, or ethical friction.
                            </p>
                        </div>
                    )}

                    {/* Footer: Actions */}
                    <div className="flex items-center justify-between mt-1 pt-2 border-t border-slate-100/50">
                        {/* Trace Action */}
                        <div>
                            {onTrace && (
                                <button
                                    className={`flex items-center gap-1.5 px-2 py-1 rounded-md text-[10px] font-medium transition-colors border ${isTraced
                                        ? "bg-rose-50 text-rose-600 border-rose-200"
                                        : "bg-white text-slate-500 border-slate-200 hover:border-rose-200 hover:text-rose-600 hover:bg-rose-50/50"
                                        }`}
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        onTrace();
                                    }}
                                >
                                    <Layers className="h-3 w-3" />
                                    {isTraced ? "Stop Tracing" : "Trace Actor"}
                                </button>
                            )}
                        </div>

                        {/* Links */}
                        {actor.url && (
                            <a
                                href={actor.url}
                                target="_blank"
                                rel="noopener noreferrer"
                                className="text-[10px] text-indigo-600 hover:text-indigo-800 flex items-center gap-1 hover:underline ml-auto"
                                onClick={(e) => e.stopPropagation()}
                            >
                                Visit Website
                                <ExternalLink className="h-3 w-3" />
                            </a>
                        )}
                    </div>
                </div>
            </div>
        </TooltipProvider>
    );
}

import React from 'react';
import { TheoreticalTensionsDialog } from './TheoreticalTensionsDialog';
import { EcosystemActor, EcosystemConfiguration } from '@/types/ecosystem';
import { ProvisionalBadge } from '@/components/ui/provisional-badge';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Textarea } from '@/components/ui/textarea';
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from '@/components/ui/alert-dialog';
import { Loader2, Trash2, ExternalLink, Maximize2, Minimize2, X, FileText, Search, Globe, Layers, Info } from 'lucide-react';
import { useDemoMode } from '@/hooks/useDemoMode';
import { AssemblageExtractionDialog } from './AssemblageExtractionDialog';
import { Checkbox } from '@/components/ui/checkbox';
import { ActorCard } from './ActorCard';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '@/components/ui/tooltip';

interface ActorListProps {
    actors: EcosystemActor[];
    selectedActorId: string | null;
    onSelectActor: (id: string) => void;
    onClearAll: () => void;

    // Expansion Props
    isExpanded?: boolean;
    onToggleExpand?: () => void;

    // Extraction Props
    isExtracting: boolean;
    extractionText: string;
    setExtractionText: (text: string) => void;
    onExtract: () => void;
    isExtractionDialogOpen: boolean;
    setIsExtractionDialogOpen: (open: boolean) => void;

    onClose?: () => void;
    // New Props for Discovery


    // Link Enrichment
    onEnrichLinks?: () => void;
    isEnriching?: boolean;
    enrichProgress?: number;

    // Selection Props [NEW]
    selectedForGrouping: string[];
    onToggleSelection: (id: string) => void;
    onCreateConfiguration: () => void;
    configurations?: EcosystemConfiguration[]; // [NEW] For membership display
    // [NEW] ANT Workbench Props
    tracedActorId?: string | null;
    onTraceActor?: (id: string | null) => void;
}

export function ActorList({
    actors,
    selectedActorId,
    onSelectActor,
    onClearAll,
    isExpanded = false,
    onToggleExpand,
    isExtracting,
    extractionText,
    setExtractionText,
    onExtract,
    isExtractionDialogOpen,
    setIsExtractionDialogOpen,
    onClose,
    onEnrichLinks,
    isEnriching = false,
    enrichProgress = 0,
    selectedForGrouping,
    onToggleSelection,
    onCreateConfiguration,
    configurations = [],
    tracedActorId,
    onTraceActor
}: ActorListProps) {
    const { isReadOnly } = useDemoMode();

    const [searchQuery, setSearchQuery] = React.useState("");

    const filteredActors = React.useMemo(() => {
        let result = actors;
        if (searchQuery.trim()) {
            const lowerQuery = searchQuery.toLowerCase();
            result = actors.filter(actor =>
                actor.name.toLowerCase().includes(lowerQuery) ||
                actor.description?.toLowerCase().includes(lowerQuery) ||
                actor.type.toLowerCase().includes(lowerQuery)
            );
        }

        // [NEW] Pin traced actor to top
        if (tracedActorId) {
            result = [...result].sort((a, b) => {
                if (a.id === tracedActorId) return -1;
                if (b.id === tracedActorId) return 1;
                return 0;
            });
        }

        return result;
    }, [actors, searchQuery, tracedActorId]);

    return (
        <Card className="h-[500px] lg:h-full flex flex-col">
            <CardHeader className="pb-2">
                <div className="flex items-center justify-between">
                    <CardTitle className="text-lg">Trace Provenance ({filteredActors.length})</CardTitle>
                    <div className="flex gap-1">
                        {onToggleExpand && (
                            <Button size="icon" variant="ghost" className="h-8 w-8 text-slate-400 hover:text-slate-600" onClick={onToggleExpand} title={isExpanded ? "Collapse" : "Expand"}>
                                {isExpanded ? <Minimize2 className="h-4 w-4" /> : <Maximize2 className="h-4 w-4" />}
                            </Button>
                        )}
                        {onClose && (
                            <Button size="icon" variant="ghost" className="h-8 w-8 bg-slate-100 text-slate-500 hover:bg-slate-200" onClick={onClose} title="Close Panel">
                                <X className="h-4 w-4" />
                            </Button>
                        )}
                        {/* Extraction Dialog */}
                        <Dialog open={isExtractionDialogOpen} onOpenChange={setIsExtractionDialogOpen}>
                            <DialogTrigger asChild>
                                <Button
                                    size="icon"
                                    variant="ghost"
                                    className="h-8 w-8"
                                    title={isReadOnly ? "Sign in to extract actors" : "Extract from Text"}
                                    disabled={isReadOnly}
                                >
                                    <FileText className={`h-4 w-4 ${isReadOnly ? 'text-slate-300' : 'text-emerald-600'}`} />
                                </Button>
                            </DialogTrigger>
                        </Dialog>

                        <AssemblageExtractionDialog
                            open={isExtractionDialogOpen}
                            onOpenChange={setIsExtractionDialogOpen}
                            isExtracting={isExtracting}
                            extractionText={extractionText}
                            setExtractionText={setExtractionText}
                            onExtract={onExtract}
                        />

                        {/* Link Enrichment Button */}
                        {onEnrichLinks && (
                            <Button
                                size="icon"
                                variant="ghost"
                                className="h-8 w-8 text-indigo-500 hover:text-indigo-700 hover:bg-indigo-50"
                                onClick={onEnrichLinks}
                                disabled={isEnriching}
                                title="Find Actor Links"
                            >
                                {isEnriching ? <Loader2 className="h-4 w-4 animate-spin" /> : <Globe className="h-4 w-4" />}
                            </Button>
                        )}
                        <AlertDialog>
                            <AlertDialogTrigger asChild>
                                <Button size="icon" variant="ghost" className="h-8 w-8" title="Clear All Actors">
                                    <Trash2 className="h-4 w-4 text-red-600" />
                                </Button>
                            </AlertDialogTrigger>
                            <AlertDialogContent>
                                <AlertDialogHeader>
                                    <AlertDialogTitle>Clear All Actors?</AlertDialogTitle>
                                    <AlertDialogDescription>
                                        This will remove all actors. You&apos;ll start with an empty ecosystem. This action cannot be undone.
                                    </AlertDialogDescription>
                                </AlertDialogHeader>
                                <AlertDialogFooter>
                                    <AlertDialogCancel>Cancel</AlertDialogCancel>
                                    <AlertDialogAction onClick={onClearAll} className="bg-red-600 hover:bg-red-700">
                                        Clear All
                                    </AlertDialogAction>
                                </AlertDialogFooter>
                            </AlertDialogContent>
                        </AlertDialog>
                    </div>
                </div>

                {/* Enrichment Progress Bar if active */}
                {isEnriching && (
                    <div className="mt-2 text-[10px] text-indigo-600 flex items-center gap-2 bg-indigo-50 p-1 rounded px-2">
                        <Loader2 className="h-3 w-3 animate-spin" />
                        Finding Links... {enrichProgress}%
                    </div>
                )}
                <div className="relative mt-2">
                    <Search className="absolute left-2 top-2.5 h-4 w-4 text-slate-400" />
                    <input
                        placeholder="Search actors..."
                        className="w-full pl-8 pr-4 py-2 text-sm border rounded-md bg-slate-50 text-slate-900"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                    />
                </div>

                {/* Create Configuration Action [NEW] */}
                {selectedForGrouping.length >= 2 && (
                    <div className="mt-3 animate-in slide-in-from-top-2">
                        <Button
                            onClick={onCreateConfiguration}
                            className="w-full bg-indigo-600 hover:bg-indigo-700 text-white shadow-md flex items-center justify-center gap-2 h-9 text-sm font-semibold"
                        >
                            <Layers className="h-4 w-4" />
                            Define Macro Assemblage ({selectedForGrouping.length})
                        </Button>
                    </div>
                )}
            </CardHeader >
            <CardContent className="flex-1 overflow-y-auto space-y-2 pt-0 flex flex-col">
                {/* Empty State with Extraction Button - Always visible for adding more actors */}
                {actors.length === 0 && (
                    <div className="text-center p-6 text-slate-500 text-sm border-2 border-dashed border-slate-200 rounded-lg m-2 bg-slate-50/50">
                        <div className="flex justify-center mb-3">
                            <div className="relative">
                                <Globe className="h-10 w-10 text-slate-300" />
                                <div className="absolute -bottom-1 -right-1 bg-white rounded-full p-0.5 border border-slate-200">
                                    <X className="h-4 w-4 text-slate-400" />
                                </div>
                            </div>
                        </div>
                        <div className="flex items-center justify-center gap-2 mb-1">
                            <h3 className="font-semibold text-slate-700">Strategic Subtraction Active</h3>
                            <TooltipProvider>
                                <Tooltip>
                                    <TooltipTrigger>
                                        <Info className="h-4 w-4 text-slate-400 cursor-help" />
                                    </TooltipTrigger>
                                    <TooltipContent className="max-w-xs text-xs p-3 space-y-2 bg-slate-900 border border-slate-700 shadow-xl z-50 text-slate-100">
                                        <p className="font-semibold text-indigo-300">Why are features disabled?</p>
                                        <p>
                                            <span className="font-medium text-slate-200">Anti-Hallucination:</span> Automated web crawling is disabled to prevent the inclusion of irrelevant or &quot;invented&quot; data.
                                        </p>
                                        <p>
                                            <span className="font-medium text-slate-200">Empirical Traceability:</span> In qualitative research (ANT), you must &quot;trace&quot; connections in the text. By only analyzing documents you upload, we guarantee every insight has a provenance.
                                        </p>
                                        <p>
                                            <span className="font-medium text-slate-200">You are the Filter:</span> The AI refuses to &quot;fill in the blanks&quot; from the internet, ensuring all claims are grounded in your specific corpus.
                                        </p>
                                    </TooltipContent>
                                </Tooltip>
                            </TooltipProvider>
                        </div>
                        <p className="text-xs text-slate-500 max-w-[280px] mx-auto mb-4 leading-relaxed">
                            Automated web scraping and predictive modeling are excluded to preserve empirical traceability.
                            You must adhere researcher-curated text to trace mediations.
                        </p>
                    </div>
                )}

                {/* Extraction Button - Always visible */}
                <div className="px-2 pb-2">
                    <Button
                        variant="outline"
                        size="sm"
                        onClick={() => setIsExtractionDialogOpen(true)}
                        className="w-full bg-white hover:bg-slate-50 text-xs gap-2"
                    >
                        <FileText className="h-3 w-3 text-emerald-600" />
                        {actors.length === 0 ? 'Adhere Empirical Source' : 'Add More Actors'}
                    </Button>
                </div>

                <div className="flex-1 space-y-2">
                    {filteredActors.map(actor => (
                        <ActorCard
                            key={actor.id}
                            actor={actor}
                            isSelected={selectedActorId === actor.id}
                            isGroupSelected={selectedForGrouping.includes(actor.id)}
                            onSelect={() => onSelectActor(actor.id)}
                            onToggleGroupSelection={() => onToggleSelection(actor.id)}
                            configurations={configurations}
                            // [NEW]
                            isTraced={tracedActorId === actor.id}
                            onTrace={() => onTraceActor && onTraceActor(tracedActorId === actor.id ? null : actor.id)}
                        />
                    ))}
                </div>

                <div className="p-2 pt-4 border-t mt-auto">
                    <div className="flex justify-center">
