import React, { useState } from 'react';
import { Button } from '@/components/ui/button';
import { Textarea } from '@/components/ui/textarea';
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Loader2, FileText, Globe, Search, UploadCloud } from 'lucide-react';
import { toast } from 'sonner';

interface AssemblageExtractionDialogProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;

    // State
    isExtracting: boolean;
    extractionText: string;
    setExtractionText: (text: string) => void;

    // Actions
    onExtract: () => void;
}

export function AssemblageExtractionDialog({
    open,
    onOpenChange,
    isExtracting,
    extractionText,
    setExtractionText,
    onExtract
}: AssemblageExtractionDialogProps) {
    const [isFileUploading, setIsFileUploading] = useState(false);

    const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        setIsFileUploading(true);
        try {
            const formData = new FormData();
            formData.append('file', file);

            const response = await fetch('/api/extract-file', {
                method: 'POST',
                body: formData,
            });

            const data = await response.json();

            if (!response.ok) {
                throw new Error(data.error || 'Failed to analyze document');
            }

            if (data.text) {
                setExtractionText(data.text);
                toast.success(`Extracted content from ${file.name}`);
            }
        } catch (error) {
            console.error('File upload failed:', error);
            toast.error('Failed to extract text from file.');
        } finally {
            setIsFileUploading(false);
            // Reset input
            e.target.value = '';
        }
    };

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="sm:max-w-md max-h-[85vh] flex flex-col p-6">
                <DialogHeader className="shrink-0">
                    <DialogTitle>Extract & Trace Assemblage</DialogTitle>
                    <DialogDescription>
                        Identify actors, agencies, and relationships to populate the ecosystem.
                    </DialogDescription>
                </DialogHeader>

                <div className="flex-1 overflow-y-auto py-2">
                    <div className="space-y-4">
                        <div className="flex flex-col gap-2">
                            <div className="flex items-center justify-between">
                                <label className="text-sm font-medium text-slate-700">Source Text</label>
                                <div className="relative">
                                    <input
                                        type="file"
                                        id="file-upload"
                                        className="hidden"
                                        accept=".pdf,.docx,.txt"
                                        onChange={handleFileUpload}
                                    />
                                    <Button
                                        variant="outline"
                                        size="sm"
                                        className="h-7 text-xs gap-2"
                                        onClick={() => document.getElementById('file-upload')?.click()}
                                        disabled={isFileUploading}
                                    >
                                        {isFileUploading ? <Loader2 className="h-3 w-3 animate-spin" /> : <UploadCloud className="h-3 w-3" />}
                                        {isFileUploading ? 'Extracting...' : 'Upload Doc'}
                                    </Button>
                                </div>
                            </div>
                            <p className="text-xs text-slate-500 mb-1">
                                Paste research text or upload a document (PDF, DOCX, TXT).
                            </p>
                        </div>
                        <Textarea
                            placeholder="Paste text here or upload a document..."
                            value={extractionText}
                            onChange={(e) => setExtractionText(e.target.value)}
                            className="min-h-[200px] max-h-[400px] resize-none"
                        />
                    </div>
                </div>

                <DialogFooter className="shrink-0 pt-4 bg-white dark:bg-slate-950 z-20 relative">
                    <Button onClick={onExtract} disabled={isExtracting || !extractionText} className="bg-slate-900 text-white hover:bg-slate-800 w-full sm:w-auto">
                        {isExtracting ? (
                            <>
                                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                Tracing Text...
                            </>
                        ) : (
                            <>
                                <FileText className="mr-2 h-4 w-4" />
                                Trace Actors
                            </>
                        )}
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

import React from 'react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { cn } from '@/lib/utils';
import { Loader2, CheckCircle2, Circle, TrendingUp, ShieldCheck, Activity, Users, Layers, MessageSquare } from 'lucide-react';

export type PipelineStepStatus = 'pending' | 'analyzing' | 'done' | 'error';

export interface AssemblageMethodologyGraphProps {
    status: {
        actants: PipelineStepStatus;
        relations: PipelineStepStatus;
        mechanisms: PipelineStepStatus;
        trajectory: PipelineStepStatus;
        critique: PipelineStepStatus;
        stress_test: PipelineStepStatus;
    };
    currentStepMessage?: string;
}

const NODES = [
    { id: 'actants', label: 'Actants & Agency', x: 200, y: 50, color: '#3b82f6', icon: Users }, // Blue
    { id: 'relations', label: 'Network Relations', x: 400, y: 50, color: '#8b5cf6', icon: Layers }, // Violet
    { id: 'mechanisms', label: 'Mechanisms (T/C)', x: 150, y: 150, color: '#10b981', icon: ShieldCheck }, // Emerald
    { id: 'trajectory', label: 'Trajectory Forecast', x: 450, y: 150, color: '#f59e0b', icon: TrendingUp }, // Amber
    { id: 'critique', label: 'Adversarial Critique', x: 300, y: 250, color: '#ef4444', icon: MessageSquare }, // Red
    { id: 'stress_test', label: 'Stress Test Capable', x: 300, y: 350, color: '#ec4899', icon: Activity }, // Pink
];

const LINKS = [
    { from: 'actants', to: 'relations' },
    { from: 'actants', to: 'mechanisms' },
    { from: 'relations', to: 'mechanisms' },
    { from: 'mechanisms', to: 'trajectory' },
    { from: 'mechanisms', to: 'critique' },
    { from: 'trajectory', to: 'critique' },
    { from: 'critique', to: 'stress_test' }
];

export function AssemblageMethodologyGraph({ status, currentStepMessage }: AssemblageMethodologyGraphProps) {

    const getNodeStatus = (id: string) => {
        return status[id as keyof typeof status] || 'pending';
    };

    return (
        <Card className="w-full bg-slate-50/50 dark:bg-slate-900/50 border-slate-200 dark:border-slate-800 mb-6">
            <CardHeader className="pb-2">
                <CardTitle className="text-sm font-bold uppercase tracking-wider text-slate-600 flex items-center justify-between">
                    <span>Methodological Entanglement</span>
                    {Object.values(status).some(s => s === 'analyzing') && (
                        <Badge variant="outline" className="animate-pulse bg-indigo-50 text-indigo-700 border-indigo-200 text-[10px]">
                            Processing...
                        </Badge>
                    )}
                </CardTitle>
            </CardHeader>
            <CardContent>
                <div className="relative w-full h-[400px] flex items-center justify-center select-none">
                    <svg width="100%" height="100%" viewBox="0 0 600 400" className="overflow-visible">
                        {/* Links */}
                        {LINKS.map((link, i) => {
                            const source = NODES.find(n => n.id === link.from)!;
                            const target = NODES.find(n => n.id === link.to)!;
                            const isSourceDone = getNodeStatus(link.from) === 'done';
                            const isTargetActive = getNodeStatus(link.to) !== 'pending';

                            const isActive = isSourceDone && isTargetActive;

                            return (
                                <line
                                    key={i}
                                    x1={source.x} y1={source.y}
                                    x2={target.x} y2={target.y}
                                    stroke={isActive ? "#94a3b8" : "#e2e8f0"}
                                    strokeWidth={isActive ? 2 : 1}
                                    strokeDasharray={isActive ? "none" : "5,5"}
                                    className="transition-all duration-500"
                                />
                            );
                        })}

                        {/* Nodes */}
                        {NODES.map((node) => {
                            const nodeStatus = getNodeStatus(node.id);
                            const isActive = nodeStatus === 'analyzing';
                            const isDone = nodeStatus === 'done';
                            const Icon = node.icon;

                            return (
                                <g key={node.id} transform={`translate(${node.x}, ${node.y})`}>
                                    {/* Pulsing effect */}
                                    {isActive && (
                                        <circle r={35} fill={node.color} opacity={0.3} className="animate-ping" />
                                    )}

                                    {/* Main Circle */}
                                    <circle
                                        r={24}
                                        fill={isDone ? node.color : "white"}
                                        stroke={node.color}
                                        strokeWidth={isActive ? 2 : 1.5}
                                        className="transition-all duration-300 shadow-sm"
                                    />

                                    {/* Icon */}
                                    <foreignObject x={-12} y={-12} width={24} height={24} className="pointer-events-none">
                                        <div className="flex items-center justify-center w-full h-full text-white">
                                            {isActive ? (
                                                <Loader2 className={cn("w-5 h-5 animate-spin", isDone ? "text-white" : "text-slate-400")} style={{ color: isDone ? 'white' : node.color }} />
                                            ) : isDone ? (
                                                <Icon className="w-4 h-4 text-white" />
                                            ) : (
                                                <Circle className="w-4 h-4 text-slate-200" />
                                            )}
                                        </div>
                                    </foreignObject>

                                    {/* Label */}
                                    <foreignObject x={-75} y={32} width={150} height={40}>
                                        <div className={cn(
                                            "text-center text-[10px] font-bold uppercase tracking-tight transition-colors duration-300",
                                            isActive || isDone ? "text-slate-700 dark:text-slate-200" : "text-slate-300"
                                        )}>
                                            {node.label}
                                        </div>
                                    </foreignObject>
                                </g>
                            );
                        })}
                    </svg>
                </div>

                {currentStepMessage && (
                    <div className="mt-2 text-center">
                        <p className="text-xs text-slate-500 animate-pulse font-mono">
                            {currentStepMessage}
                        </p>
                    </div>
                )}
            </CardContent>
        </Card>
    );
}

"use client";

import React, { useState, useEffect } from 'react';
import { Card, CardHeader, CardTitle, CardDescription, CardContent } from '@/components/ui/card';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Button } from '@/components/ui/button';
import { Loader2, Layers, Maximize2, Minimize2, X, ChevronDown, ChevronUp, GripVertical, Trash2, Lock, Wind, Scale, Activity } from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '@/components/ui/tooltip';
import { EcosystemActor, AssemblageAnalysis, EcosystemConfiguration } from '@/types/ecosystem';
import { ProvisionalBadge } from '@/components/ui/provisional-badge';
import { AssemblageAnalysisView } from './AssemblageAnalysisView';
import { AssemblageMethodologyGraph, PipelineStepStatus } from './AssemblageMethodologyGraph';
import { CreditTopUpDialog } from "@/components/CreditTopUpDialog";
import { useCredits } from "@/hooks/useCredits";
import { calculateAssemblageMetrics } from "@/lib/ecosystem-utils";
import { analyzeMediatorScoresBatch } from "@/services/mediatorAnalysis";
import { generateEdges } from "@/lib/graph-utils";
import { getMediatorClassification } from "@/types/relationship"; // [FIX] Import function

interface AssemblagePanelProps {
    actors: EcosystemActor[];
    analyzedText?: string;
    savedAnalysis?: AssemblageAnalysis | null;
    onSaveAnalysis?: (analysis: AssemblageAnalysis) => void;
    // Expansion Props
    isExpanded?: boolean;
    onToggleExpand?: () => void;
    // Unification Props
    selectedConfigs?: EcosystemConfiguration[];
    onUpdateConfig?: (config: EcosystemConfiguration) => void;
    onClose?: () => void;
    onUpdateActors?: (actors: EcosystemActor[]) => void;
    // [NEW] Management Props
    allConfigurations?: EcosystemConfiguration[];
    onReorderConfigs?: (configs: EcosystemConfiguration[]) => void;
    onSelectConfig?: (id: string, multi: boolean) => void;
    onDeleteConfig?: (id: string) => void;
    // [NEW] ANT Workbench Props
    collapsedIds?: Set<string>;
    onToggleCollapse?: (id: string) => void;
}

export function AssemblagePanel({
    actors,
    analyzedText = "",
    savedAnalysis,
    onSaveAnalysis,
    isExpanded = false,
    onToggleExpand,
    selectedConfigs = [],
    onUpdateConfig,
    onClose,
    onUpdateActors,
    allConfigurations = [],
    onReorderConfigs,
    onSelectConfig,
    onDeleteConfig,
    collapsedIds,
    onToggleCollapse
}: AssemblagePanelProps) {
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [analysisType, setAnalysisType] = useState('comprehensive_scan');

    // Credit System
    const { hasCredits, refetch: refetchCredits, loading: creditsLoading } = useCredits();
    const [showTopUp, setShowTopUp] = useState(false);
    const [forceRefresh, setForceRefresh] = useState(false);
    const [showGraph, setShowGraph] = useState(false);

    // [NEW] View Mode: 'analysis' | 'manage'
    const [viewMode, setViewMode] = useState<'analysis' | 'manage'>('analysis');

    // Auto-switch to analysis when analyzing starts
    useEffect(() => {
        if (isAnalyzing) setViewMode('analysis');
    }, [isAnalyzing]);
    const [pipelineStatus, setPipelineStatus] = useState<{
        actants: PipelineStepStatus;
        relations: PipelineStepStatus;
        mechanisms: PipelineStepStatus;
        trajectory: PipelineStepStatus;
        critique: PipelineStepStatus;
        stress_test: PipelineStepStatus;
    }>({
        actants: 'pending',
        relations: 'pending',
        mechanisms: 'pending',
        trajectory: 'pending',
        critique: 'pending',
        stress_test: 'pending'
    });
    const [pipelineMessage, setPipelineMessage] = useState<string>('');

    // [NEW] Robust Assemblage Prep for Stress Test
    // Ensures we never pass an empty/stale configuration to the simulator
    const dashboardAssemblage = React.useMemo(() => {
        const currentActorIds = actors.map(a => a.id);

        // 1. Helper: Check if IDs are valid (must match at least one current actor)
        const hasValidMembers = (ids: string[]) => ids && ids.length > 0 && ids.some(id => currentActorIds.includes(id));

        // 2. Prefer selected config (has explicit members)
        if (selectedConfigs.length === 1) {
            const config = selectedConfigs[0];
            // [CRITICAL FIX] If selected config has no members (or invalid), 
            // we MUST polyfill it, otherwise Stress Test shows 0.
            if (hasValidMembers(config.memberIds)) {
                console.log('[StressTestDebug] Using Selected Config', { id: config.id, members: config.memberIds.length });
                return config;
            }
            console.log('[StressTestDebug] Selected Config has empty/stale members. Polyfilling with all actors.');
            return {
                ...config,
                memberIds: currentActorIds
            };
        }

        // 3. Fallback to analysis assemblage
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const analysisAssemblage = (savedAnalysis as any)?.assemblage;

        // 4. Smart Polyfill
        if (analysisAssemblage) {
            const existingIds = analysisAssemblage.memberIds || [];

            // Usage: If existing members are valid, keep them. If not (stale/empty), use ALL.
            // This fixes "0.0" metrics from stale/mismatched IDs.
            if (hasValidMembers(existingIds)) {
                console.log('[StressTestDebug] Using Existing Analysis Assemblage', { count: existingIds.length });
                return {
                    ...analysisAssemblage,
                    memberIds: existingIds
                };
            }

            console.log('[StressTestDebug] Polyfilling Analysis Assemblage (stale/empty)', { existing: existingIds.length, current: currentActorIds.length });
            // Otherwise overwrite with all actors (Comprehensive Scan assumption)
            return {
                ...analysisAssemblage,
                memberIds: currentActorIds
            };
        }

        console.log('[StressTestDebug] Synthesizing Full Assemblage (no analysis)', { current: currentActorIds.length });
        // 5. Last resort: Synthesize a wrapper for the stress test
        return {
            id: "synthesized-root",
            name: "Analyzed Context",
            memberIds: currentActorIds,
            properties: {}
        };
    }, [selectedConfigs, savedAnalysis, actors]);

    // [FIX] Dynamic Metric Calculation 
    // Uses dashboardAssemblage (which is robust) to ensure metrics are never 0 unless truly empty
    const dynamicMetrics = React.useMemo(() => {
        // We act on the dashboardAssemblage, which is guaranteed to be a valid config-like object
        return calculateAssemblageMetrics(actors, dashboardAssemblage as EcosystemConfiguration);
    }, [actors, dashboardAssemblage]);

    const handleRatify = () => {
        const selectedConfig = selectedConfigs.length === 1 ? selectedConfigs[0] : null;
        const currentData = savedAnalysis || selectedConfig?.analysisData;
        if (!currentData?.provisional_status) return;

        const currentStatus = currentData.provisional_status;
        const updatedProvisional = {
            ...currentStatus,
            source: "user_validated" as const,
            fragility_score: {
                ...currentStatus.fragility_score,
                value: 0.1, // Significant reduction in fragility
                interpretation: "stable" as const,
                factors: {
                    input_completeness: 0.1,
                    model_uncertainty: 0.1,
                    theoretical_tension: 0.1,
                    empirical_grounding: 0.1
                }
            },
            authority_conditions: [" ratified by human expert"] // Mark as ratified
        };

        const updatedAnalysis = {
            ...currentData,
            provisional_status: updatedProvisional
        };

        if (selectedConfig && onUpdateConfig) {
            const updatedConfig = {
                ...selectedConfig,
                analysisData: updatedAnalysis
            };
            onUpdateConfig(updatedConfig);
        }

        if (onSaveAnalysis) onSaveAnalysis(updatedAnalysis);
    };

    const handleContest = (interpretation: string, basis: string) => {
        const selectedConfig = selectedConfigs.length === 1 ? selectedConfigs[0] : null;
        const currentData = savedAnalysis || selectedConfig?.analysisData;
        if (!currentData?.provisional_status) return;

        const currentStatus = currentData.provisional_status;
        const updatedProvisional = {
            ...currentStatus,
            alternative_interpretations: [
                ...(currentStatus.alternative_interpretations || []),
                {
                    interpretation,
                    theoretical_basis: basis,
                    plausibility: 0.5
                }
            ],
            last_contested_at: new Date().toISOString()
        };

        const updatedAnalysis = {
            ...currentData,
            provisional_status: updatedProvisional
        };

        if (selectedConfig && onUpdateConfig) {
            const updatedConfig = {
                ...selectedConfig,
                analysisData: updatedAnalysis
            };
            onUpdateConfig(updatedConfig);
        }

        if (onSaveAnalysis) onSaveAnalysis(updatedAnalysis);
    };

    const handleAddLog = (entry: import('@/types/ecosystem').ReflexiveLogEntry) => {
        const selectedConfig = selectedConfigs.length === 1 ? selectedConfigs[0] : null;
        if (!selectedConfig || !onUpdateConfig) return;

        const updatedConfig = {
            ...selectedConfig,
            reflexive_log: [...(selectedConfig.reflexive_log || []), entry]
        };
        onUpdateConfig(updatedConfig);
    };

    const handleDeleteLog = (entryId: string) => {
        const selectedConfig = selectedConfigs.length === 1 ? selectedConfigs[0] : null;
        if (!selectedConfig || !onUpdateConfig) return;

        const updatedConfig = {
            ...selectedConfig,
            reflexive_log: (selectedConfig.reflexive_log || []).filter(l => l.id !== entryId)
        };
        onUpdateConfig(updatedConfig);
    };

    const handleDeepScan = async () => {
        if (actors.length === 0 && !analyzedText) {
            alert("Please add actors or text source before analyzing.");
            return;
        }

        // Credit Check
        if (!creditsLoading && !hasCredits) {
            setShowTopUp(true);
            return;
        }

        setIsAnalyzing(true);
        setShowGraph(true); // Auto-open graph on start
        // Reset pipeline
        setPipelineStatus({
            actants: 'analyzing',
            relations: 'analyzing',
            mechanisms: 'pending',
            trajectory: 'pending',
            critique: 'pending',
            stress_test: 'pending'
        });
        setPipelineMessage("Tracing actants and relations...");

        try {
            const headers: HeadersInit = { 'Content-Type': 'application/json' };
            // Always try to send demo ID if available (handles client/server env mismatch)
            if (process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
            }

            // [FIX] Filter actors if a specific assemblage is selected
            const targetActors = selectedConfigs.length > 0
                ? actors.filter(a => selectedConfigs.some(c => c.memberIds.includes(a.id)))
                : actors;

            // [FIX] Changed from /api/ecosystem/absence to /api/analyze to use the full Deleuzian prompt
            const response = await fetch('/api/analyze', {
                method: 'POST',
                headers: headers,
                body: JSON.stringify({
                    text: analyzedText || targetActors.map(a => `${a.name}: ${a.description}`).join("\n"),
                    analysisMode: analysisType, // Use selected mode
                    sourceType: 'Trace',
                    force: forceRefresh, // Use toggle state for cache control
                    assemblageId: selectedConfigs.map(c => c.id).join(','), // [NEW] Pass IDs for precise caching
                    // [FIX] Pass existing analysis for Critique and Realist modes
                    existingAnalysis: savedAnalysis || (selectedConfigs.length === 1 ? selectedConfigs[0].analysisData : null),
                    // [FIX] Pass structured data for Realist/Explanation modes
                    traced_actors: targetActors,
                    detected_mechanisms: (savedAnalysis as any)?.stabilization_mechanisms || (savedAnalysis as any)?.assemblage?.stabilization_mechanisms || [],
                    identified_capacities: (savedAnalysis as any)?.capacities || []
                })
            });

            if (!response.ok) {
                console.error("Assemblage Analysis failed:", response.status, response.statusText);
                alert(`Analysis failed: Server returned ${response.status}`);
                return;
            }

            const data = await response.json();

            // 1. Update Analysis Data
            if (data.analysis && onSaveAnalysis) {
                const effectiveAnalysis = (selectedConfigs.length === 1 ? selectedConfigs[0].analysisData : null) || savedAnalysis || {};

                // [CRITICAL] Derive member IDs from returned actors if missing in assemblage object
                // The AI returns `analysis.actors` but might return an assemblage object without `memberIds`.
                let derivedMemberIds: string[] | undefined = data.analysis.assemblage?.memberIds;

                if ((!derivedMemberIds || derivedMemberIds.length === 0) && data.analysis.actors) {
                    // Match returned actors to current actors by name to find IDs
                    derivedMemberIds = actors
                        .filter(current => data.analysis.actors.some((analyzed: any) => analyzed.name.toLowerCase() === current.name.toLowerCase()))
                        .map(a => a.id);
                }

                // [CRITICAL] Extract/Sync Properties
                // Sync properties from analysis to config level
                const analysisProps = data.analysis.assemblage?.properties || {};
                const computedMetrics = data.analysis.computed_metrics || {};

                // Normalize keys (handle variations like territorialization_score vs territoriality)
                const stabilityScore = analysisProps.stability || 'Medium';
                const territorializationScore = computedMetrics.territorialization_score ?? analysisProps.territorialization_score ?? 5;
                const codingIntensityScore = computedMetrics.coding_intensity_score ?? analysisProps.coding_intensity_score ?? 5;


                const mergedAnalysis = {
                    ...effectiveAnalysis,
                    ...data.analysis,
                    // Preserve the core assemblage identity if not provided by new analysis
                    assemblage: {
                        ...(effectiveAnalysis.assemblage || data.analysis.assemblage),
                        memberIds: derivedMemberIds || effectiveAnalysis.assemblage?.memberIds
                    },
                    // [FIX] Force Reset Provisional Status on new analysis
                    provisional_status: {
                        source: "ai_generated",
                        fragility_score: {
                            value: 0.55,
                            interpretation: "provisional",
                            factors: {
                                input_completeness: 0.6,
                                model_uncertainty: 0.5,
                                theoretical_tension: 0.4,
                                empirical_grounding: 0.3
                            }
                        },
                        authority_conditions: ["pending ratification"]
                    }
                };
                onSaveAnalysis(mergedAnalysis);

                // [FIX] Update Structural Data (memberIds & properties) on Config
                if (selectedConfigs.length === 1 && onUpdateConfig) {
                    const updatedConfig = {
                        ...selectedConfigs[0],
                        memberIds: derivedMemberIds && derivedMemberIds.length > 0 ? derivedMemberIds : selectedConfigs[0].memberIds, // Keep old if derivation failed
                        properties: {
                            ...selectedConfigs[0].properties,
                            sensitivity: stabilityScore, // Map specific props ? or keep general properties
                            stability: stabilityScore,
                            territorialization_score: territorializationScore,
                            coding_intensity_score: codingIntensityScore
                        },
                        analysisData: mergedAnalysis
                    };
                    onUpdateConfig(updatedConfig);
                }

                refetchCredits();
            }

            // 2. [NEW] Update Actor Metrics (Territorialization/Deterritorialization)
            if (data.analysis?.actors && Array.isArray(data.analysis.actors) && onUpdateActors) {
                console.log("Trace Complete: Updating Actor Metrics", data.analysis.actors);

                const updatedActors = actors.map(existingActor => {
                    // Fuzzy match by name
                    // eslint-disable-next-line @typescript-eslint/no-explicit-any
                    const match = data.analysis.actors.find((a: any) => a.name.toLowerCase() === existingActor.name.toLowerCase());

                    if (match && match.metrics) {
                        return {
                            ...existingActor,
                            metrics: {
                                ...existingActor.metrics,
                                territorialization: match.metrics.territorialization ?? match.metrics.territoriality ?? match.metrics.territorial ?? match.metrics.influence ?? 5,
                                deterritorialization: match.metrics.deterritorialization ?? match.metrics.resistance ?? match.metrics.escape ?? Math.max(match.metrics.counter_conduct || 0, match.metrics.discursive_opposition || 0) ?? 5,
                                coding: match.metrics.coding ?? 5,
                                rationale: match.metrics.rationale
                            }
                        };
                    }
                    return existingActor;
                });

                onUpdateActors(updatedActors);
            }

        } catch (error) {
            console.error("Assemblage Analysis failed", error);
            alert("Failed to analyze assemblage. Please check your connection.");
            setPipelineStatus(prev => ({ ...prev, actants: 'error', relations: 'error' }));
        } finally {
            setIsAnalyzing(false);
            // Simulate completion sequence for visual feedback (since API is monolithic)
            // Realistically this should be driven by server events, but for now we simulate the flow
            // assuming the server did its job if no error was thrown.

            // Step 1: Trace Complete
            setPipelineStatus(prev => ({ ...prev, actants: 'done', relations: 'done', mechanisms: 'analyzing', trajectory: 'analyzing', critique: 'analyzing' }));
            setPipelineMessage("Running parallel tracks: Interpretation & Critique...");

            setTimeout(() => {
                // Step 2 & 3: Parallel Tracks Complete
                setPipelineStatus(prev => ({ ...prev, mechanisms: 'done', trajectory: 'done', critique: 'done', stress_test: 'done' }));
                setPipelineMessage("Analysis Complete. Stress Test Ready.");

                // Clear message after delay
                setTimeout(() => setPipelineMessage(''), 3000);
            }, 2500); // Slightly longer single delay to represent the parallel block
        }
    };

    const [isEnriching, setIsEnriching] = useState(false);
    const [enrichProgress, setEnrichProgress] = useState(0);

    const [isAnalyzingRelationships, setIsAnalyzingRelationships] = useState(false);

    const handleAnalyzeRelationships = async () => {
        if (!actors || actors.length === 0) return;

        // Credit Check
        if (!creditsLoading && !hasCredits) {
            setShowTopUp(true);
            return;
        }

        setIsAnalyzingRelationships(true);

        try {
            // 1. Identify Edges
            const targetActors = selectedConfigs.length > 0
                ? actors.filter(a => selectedConfigs.some(c => c.memberIds.includes(a.id)))
                : actors;

            let edges = generateEdges(targetActors);
            if (edges.length === 0) {
                alert("No relationships found between these actors.");
                setIsAnalyzingRelationships(false);
                return;
            }

            // [SMART SORT] Prioritize "Healthier" / More Powerful links
            // Sort by combined dynamic power of actors
            edges = edges.sort((a, b) => {
                const getPower = (actor: EcosystemActor) => (actor.metrics?.dynamic_power || 0);
                const scoreA = getPower(a.source) + getPower(a.target);
                const scoreB = getPower(b.source) + getPower(b.target);
                return scoreB - scoreA; // Descending
            });

            // 2. Prepare Inputs
            // TODO: Get real context from a "context" prop or similar if available, otherwise generic.
            const context = analyzedText || "Policy Ecosystem Analysis";

            const inputs = edges.map(edge => ({
                sourceActor: edge.source.name,
                targetActor: edge.target.name,
                relationshipType: edge.label,
                empiricalTraces: [edge.description], // Use existing description as trace for now
                documentContext: context
            }));


            // [SPEED] Full Processing with gpt-4o-mini (Limited to 50 per user request)
            const inputsToProcess = inputs.slice(0, 50);

            const results = await analyzeMediatorScoresBatch(inputsToProcess);

            // 4. Map Results to Relationship Objects
            const relationships: import('@/types/relationship').Relationship[] = results.map((res, i) => {
                const edge = edges[i];
                return {
                    id: `${edge.source.id}-${edge.target.id}`,
                    source: edge.source.id,
                    target: edge.target.id,
                    type: edge.label,
                    mediatorScore: res.mediatorScore,
                    classification: getMediatorClassification(res.mediatorScore),
                    dimensions: res.dimensions,
                    empiricalTraces: [res.interpretation], // User interpretation as the trace
                    metadata: {
                        analyzedAt: new Date().toISOString(),
                        aiModel: 'gpt-4o',
                        confidence: 'medium'
                    }
                };
            });

            // 5. Save Results
            const effectiveAnalysis = (selectedConfigs.length === 1 ? selectedConfigs[0].analysisData : null) || savedAnalysis || {};

            // Merge with existing relationships if any
            const existingRelationships = effectiveAnalysis.relationships || [];
            // Create map for easy merge
            const mergedMap = new Map(existingRelationships.map((r: any) => [r.id, r]));
            relationships.forEach(r => mergedMap.set(r.id, r));

            const finalRelationships = Array.from(mergedMap.values());

            const updatedAnalysis = {
                ...effectiveAnalysis,
                relationships: finalRelationships
            };

            if (onSaveAnalysis) onSaveAnalysis(updatedAnalysis);

            if (selectedConfigs.length === 1 && onUpdateConfig) {
                onUpdateConfig({
                    ...selectedConfigs[0],
                    analysisData: updatedAnalysis
                });
            }

            alert(`Analysis Complete: ${relationships.length} relationships classified.`);

        } catch (error) {
            console.error("Link analysis failed", error);
            alert("Failed to analyze relationships.");
        } finally {
            setIsAnalyzingRelationships(false);
        }
    };

    const handleEnrichLinks = async () => {
        if (!actors || actors.length === 0) return;
        if (!onUpdateActors) return;

        // Credit Check
        if (!creditsLoading && !hasCredits) {
            setShowTopUp(true);
            return;
        }

        setIsEnriching(true);
        setEnrichProgress(0);

        const actorsToEnrich = actors.filter(a => !a.url);
        const total = actorsToEnrich.length;
        let processed = 0;
        const updatedActors = [...actors];

        // Process in batches of 3 to avoid rate limits
        const BATCH_SIZE = 3;

        try {
            for (let i = 0; i < total; i += BATCH_SIZE) {
                const batch = actorsToEnrich.slice(i, i + BATCH_SIZE);

                await Promise.all(batch.map(async (actor) => {
                    try {
                        const response = await fetch('/api/enrich-actor', {
                            method: 'POST',
                            headers: { 'Content-Type': 'application/json' },
                            body: JSON.stringify({
                                actorName: actor.name,
                                context: actor.type === 'Policymaker' ? 'government ministry' : 'official website'
                            })
                        });

                        if (response.ok) {
                            const data = await response.json();
                            if (data.success && data.url) {
                                const index = updatedActors.findIndex(a => a.id === actor.id);
                                if (index !== -1) {
                                    updatedActors[index] = { ...updatedActors[index], url: data.url };
                                }
                                refetchCredits();
                            }
                        }
                    } catch (err) {
                        console.warn(`Failed to enrich ${actor.name}`, err);
                    }
                }));

                processed += batch.length;
                setEnrichProgress(Math.round((processed / total) * 100));

                // Update text as we go (optional, or update at end)
                onUpdateActors([...updatedActors]);
            }
        } catch (error) {
            console.error("Enrichment failed", error);
            alert("Failed to complete link enrichment.");
        } finally {
            setIsEnriching(false);
            setEnrichProgress(0);
        }
    };

    // [NEW] Drag and Drop Logic
    const [draggingIndex, setDraggingIndex] = useState<number | null>(null);

    const onDragStart = (e: React.DragEvent, index: number) => {
        setDraggingIndex(index);
        e.dataTransfer.effectAllowed = "move";
        // Ghost image usually automatic
    };

    const onDragOver = (e: React.DragEvent, index: number) => {
        e.preventDefault(); // Necesssary to allow dropping
        // Optional: Implement instant swap animation here if desired, 
        // but for safety/simplicity we'll do it on drop or use a library-like swap.
        // For standard HTML5, waiting for drop is safer to avoid jitter without libraries.
    };

    const onDrop = (e: React.DragEvent, dropIndex: number) => {
        e.preventDefault();
        if (draggingIndex === null || draggingIndex === dropIndex) return;

        if (onReorderConfigs && allConfigurations) {
            const newConfigs = [...allConfigurations];
            const [movedItem] = newConfigs.splice(draggingIndex, 1);
            newConfigs.splice(dropIndex, 0, movedItem);
            onReorderConfigs(newConfigs);
        }
        setDraggingIndex(null);
    };

    return (
        <Card className="h-full border-l-4 border-l-slate-400 bg-slate-50/50 flex flex-col">
            <CardHeader className="pb-2">
                <CardTitle className="text-lg font-semibold flex items-center justify-between text-slate-700">
                    <div className="flex items-center gap-2">
                        <Layers className="h-5 w-5 text-indigo-600" />
                        Interpretive Workspace
                    </div>
                    <div className="flex items-center gap-1">
                        {onToggleExpand && (
                            <Button size="icon" variant="ghost" className="h-8 w-8 text-slate-400 hover:text-slate-600" onClick={onToggleExpand} title={isExpanded ? "Collapse" : "Expand"}>
                                {isExpanded ? <Minimize2 className="h-4 w-4" /> : <Maximize2 className="h-4 w-4" />}
                            </Button>
                        )}
                        {onClose && (
                            <Button size="icon" variant="ghost" className="h-8 w-8 bg-red-100 text-red-600 hover:bg-red-200" onClick={onClose} title="Close Panel">
                                <X className="h-4 w-4" />
                            </Button>
                        )}
                    </div>
                </CardTitle>
                <CardDescription>
                    Tracing components, mobilities, and silences in the policy assemblage.
                    {/* Provisional Badge in Header if available */}
                    {(savedAnalysis?.provisional_status || (selectedConfigs.length === 1 ? (selectedConfigs[0].analysisData as AssemblageAnalysis)?.provisional_status : undefined)) && (
                        <div className="mt-2">
                            <ProvisionalBadge
                                fragility={(savedAnalysis?.provisional_status || (selectedConfigs.length === 1 ? (selectedConfigs[0].analysisData as AssemblageAnalysis)?.provisional_status : undefined))?.fragility_score}
                            />
                        </div>
                    )}
                </CardDescription>


                {/* Methodology Graph Toggle */}
                <div className="mt-2 flex items-center justify-between px-1">
                    <Button
                        variant="ghost"
                        size="sm"
                        className="text-xs text-slate-500 h-6 gap-1 hover:text-indigo-600"
                        onClick={() => setShowGraph(!showGraph)}
                    >
                        {showGraph ? <ChevronUp className="h-3 w-3" /> : <ChevronDown className="h-3 w-3" />}
                        {showGraph ? "Hide Methodology Pipeline" : "Show Methodology Pipeline"}
                    </Button>
                </div>

                {/* Methodology Graph */}
                {showGraph && (
                    <div className="mt-2 px-2 border-b border-slate-100 pb-4">
                        <AssemblageMethodologyGraph
                            status={pipelineStatus}
                            currentStepMessage={pipelineMessage}
                        />
                    </div>
                )}

                <div className="pt-2">
                    <div className="flex flex-col gap-2">
                        {/* View Switcher */}
                        <div className="bg-slate-100 p-0.5 rounded-lg flex mb-2">
                            <button
                                onClick={() => setViewMode('analysis')}
                                className={`flex-1 text-xs font-medium py-1.5 rounded-md transition-all ${viewMode === 'analysis' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                            >
                                Analysis & Report
                            </button>
                            <button
                                onClick={() => setViewMode('manage')}
                                className={`flex-1 text-xs font-medium py-1.5 rounded-md transition-all ${viewMode === 'manage' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                            >
                                Manage Assemblages
                            </button>
                        </div>

                        <div className="flex items-center justify-between px-1">
                            <label className="flex items-center gap-2 cursor-pointer hover:bg-slate-50 p-1 rounded transition-colors">
                                <span className="text-[10px] text-slate-400 font-medium">Force Fresh</span>
                                <input
                                    type="checkbox"
                                    checked={forceRefresh}
                                    onChange={(e) => setForceRefresh(e.target.checked)}
                                    className="rounded border-slate-300 text-indigo-600 focus:ring-indigo-500 h-3 w-3"
                                />
                            </label>

                            {/* Comprehensive Component Analysis */}
                            <div className="flex gap-1 w-full">
                                <Button
                                    size="sm"
                                    onClick={handleDeepScan}
                                    disabled={isAnalyzing}
                                    className={`flex-1 text-xs font-medium gap-2 transition-all ${savedAnalysis ? "bg-indigo-600 hover:bg-indigo-700 text-white" : "bg-slate-900 hover:bg-slate-800 text-white"}`}
                                >
                                    {isAnalyzing ? (
                                        <>
                                            <Loader2 className="h-3 w-3 animate-spin" />
                                            Analyzing...
                                        </>
                                    ) : (
                                        <>
                                            <Layers className="h-3 w-3" />
                                            Deep Scan
                                        </>
                                    )}
                                </Button>
                                <TooltipProvider>
                                    <Tooltip>
                                        <TooltipTrigger asChild>
                                            <Button
                                                size="sm"
                                                variant="outline"
                                                onClick={handleAnalyzeRelationships}
                                                disabled={isAnalyzingRelationships}
                                                className="px-3 border-slate-200 text-slate-600 hover:text-indigo-600 hover:border-indigo-200 flex items-center gap-2"
                                            >
                                                {isAnalyzingRelationships ? <Loader2 className="h-3 w-3 animate-spin" /> : <Activity className="h-3 w-3" />}
                                                Analyze Links
                                            </Button>
                                        </TooltipTrigger>
                                        <TooltipContent>Analyze Mediator/Intermediary Roles</TooltipContent>
                                    </Tooltip>
                                </TooltipProvider>
                            </div>
                        </div>
                    </div>
                </div>
            </CardHeader>
            <CardContent className="space-y-6 overflow-y-auto flex-1 p-4">
                {viewMode === 'manage' || (allConfigurations && allConfigurations.length > 0 && !selectedConfigs.length && !savedAnalysis) ? (
                    <div className="space-y-4">
                        <div className="flex items-center justify-between">
                            <h3 className="text-sm font-semibold text-slate-700">All Macro Assemblages ({allConfigurations?.length || 0})</h3>
                        </div>
                        <div className="space-y-2">
                            {allConfigurations?.map((config, index) => (
                                <div
                                    key={config.id}
                                    draggable
                                    onDragStart={(e) => onDragStart(e, index)}
                                    onDragOver={(e) => onDragOver(e, index)}
                                    onDrop={(e) => onDrop(e, index)}
                                    onClick={() => onSelectConfig?.(config.id, false)}
                                    className={`
                                        bg-white border rounded-lg p-3 flex items-center gap-3 cursor-pointer group transition-all
                                        ${draggingIndex === index ? 'opacity-50 border-dashed border-indigo-400' : 'hover:border-indigo-300 hover:shadow-sm'}
                                    `}
                                    style={{ borderLeftColor: config.color, borderLeftWidth: '4px' }}
                                >
                                    <div className="cursor-grab text-slate-300 hover:text-slate-500 active:cursor-grabbing" onClick={(e) => e.stopPropagation()}>
                                        <GripVertical className="h-4 w-4" />
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <div className="flex items-center justify-between">
                                            <h4 className="font-medium text-slate-900 text-sm truncate">{config.name}</h4>
                                            {onDeleteConfig && (
                                                <button
                                                    className="opacity-0 group-hover:opacity-100 p-1 hover:bg-red-50 text-slate-400 hover:text-red-500 rounded"
                                                    onClick={(e) => {
                                                        e.stopPropagation();
                                                        if (confirm("Delete this assemblage?")) onDeleteConfig(config.id);
                                                    }}
                                                >
                                                    <Trash2 className="h-3.5 w-3.5" />
                                                </button>
                                            )}
                                            {onToggleCollapse && (
                                                <button
                                                    className={`p-1 rounded hover:bg-indigo-50 ${collapsedIds?.has(config.id) ? "text-indigo-600 bg-indigo-50 ring-1 ring-indigo-200" : "text-slate-400 hover:text-indigo-500"}`}
                                                    onClick={(e) => {
                                                        e.stopPropagation();
                                                        onToggleCollapse(config.id);
                                                    }}
                                                    title={collapsedIds?.has(config.id) ? "Expand Assemblage" : "Black Box (Collapse)"}
                                                >
                                                    {collapsedIds?.has(config.id) ? (
                                                        <Minimize2 className="h-3.5 w-3.5 fill-current" />
                                                    ) : (
                                                        <Minimize2 className="h-3.5 w-3.5" />
                                                    )}
                                                </button>
                                            )}
                                        </div>
                                        <div className="flex items-center gap-2 mt-1">
                                            <Badge variant="outline" className="text-[10px] h-4 px-1">{config.memberIds.length} members</Badge>
                                            <span className="text-[10px] text-slate-400">
                                                Stab: {typeof config.properties.calculated_stability === 'number' ? config.properties.calculated_stability.toFixed(2) : config.properties.stability}
                                            </span>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                        <p className="text-[10px] text-slate-400 text-center italic">Drag to reorder priority. Click to analyze.</p>
                    </div>
                ) : selectedConfigs.length > 0 ? (
                    <div className="space-y-6">
                        {selectedConfigs.length === 1 ? (
                            <div className="bg-indigo-50 border border-indigo-100 p-4 rounded-lg">
                                <div className="flex justify-between items-start">
                                    <h3 className="font-bold text-indigo-900 text-lg mb-1">{selectedConfigs[0].name}</h3>
                                    {onToggleCollapse && (
                                        <button
                                            className={`p-1.5 rounded-md transition-colors ${collapsedIds?.has(selectedConfigs[0].id) ? "text-indigo-600 bg-indigo-100 ring-1 ring-indigo-300" : "text-indigo-400 hover:text-indigo-700 hover:bg-indigo-100"}`}
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                onToggleCollapse(selectedConfigs[0].id);
                                            }}
                                            title={collapsedIds?.has(selectedConfigs[0].id) ? "Expand Assemblage" : "Black Box (Collapse)"}
                                        >
                                            {collapsedIds?.has(selectedConfigs[0].id) ? (
                                                <Minimize2 className="h-4 w-4 fill-current" />
                                            ) : (
                                                <Minimize2 className="h-4 w-4" />
                                            )}
                                        </button>
                                    )}
                                </div>
                                <p className="text-sm text-indigo-700 mb-3">{selectedConfigs[0].description}</p>
                                {(() => {
                                    /* ... existing single config metric display ... */
                                    // [FIX] Hybrid Logic: Prefer AI Score if Graph is "Closed" (1.0), and normalize units.
                                    const rawStability = dynamicMetrics.stability;
                                    const aiScoreT = Number(selectedConfigs[0].properties?.territorialization_score) || 0;
                                    const aiScoreTNorm = aiScoreT > 1 ? aiScoreT / 10 : aiScoreT; // Normalize 0-10 to 0-1

                                    const territorialization = (rawStability > 0.95 && aiScoreTNorm < 0.9 && aiScoreTNorm > 0)
                                        ? aiScoreTNorm
                                        : rawStability;

                                    const rawCoding = dynamicMetrics.coding_intensity;
                                    const aiScoreC = Number(selectedConfigs[0].properties?.coding_intensity_score) || 0;
                                    const aiScoreCNorm = aiScoreC > 1 ? aiScoreC / 10 : aiScoreC;

                                    const codingIntensity = (rawCoding > 0.95 && aiScoreCNorm < 0.9 && aiScoreCNorm > 0)
                                        ? aiScoreCNorm
                                        : rawCoding;

                                    const selectedConfig = selectedConfigs[0];

                                    return (
                                        <div className="grid grid-cols-2 gap-4">
                                            {/* ... Tooltips relying on selectedConfig loop ... */}
                                            <TooltipProvider>
                                                <Tooltip>
                                                    <TooltipTrigger asChild>
                                                        <div className="bg-white p-2 rounded border border-indigo-100 cursor-help hover:bg-slate-50 transition-colors">
                                                            <span className="text-[10px] uppercase font-bold text-slate-500 block mb-1">Territorialization</span>
                                                            <div className="flex items-center gap-2">
                                                                <span className="text-base font-bold text-slate-900">
                                                                    {territorialization > 0.7 ? "High Intensity" : territorialization > 0.4 ? "Medium Intensity" : "Low Intensity"}
                                                                </span>
                                                                <span className="text-xs text-slate-400">({(territorialization * 10).toFixed(1)})</span>
                                                            </div>
                                                        </div>
                                                    </TooltipTrigger>
                                                    <TooltipContent className="max-w-xs bg-slate-900 text-white border-slate-800">
                                                        <p className="font-bold border-b border-slate-700 pb-1 mb-1">Dynamic Metric:</p>
                                                        <p className="text-xs mb-2">Based on {dynamicMetrics.internal} internal / {dynamicMetrics.external} external associations.</p>

                                                        <p className="font-bold border-b border-slate-700 pb-1 mb-1">Audit Trail:</p>
                                                        <ul className="text-xs list-disc list-inside space-y-1">
                                                            {(selectedConfig.analysisData as AssemblageAnalysis)?.computed_metrics?.territorialization_audit && (selectedConfig.analysisData as AssemblageAnalysis).computed_metrics!.territorialization_audit!.length > 0
                                                                ? (selectedConfig.analysisData as AssemblageAnalysis).computed_metrics!.territorialization_audit!.map((t: string, i: number) => <li key={i}>{t}</li>)
                                                                : <li className="text-slate-400">No traces found</li>}
                                                        </ul>
                                                    </TooltipContent>
                                                </Tooltip>

                                                <Tooltip>
                                                    <TooltipTrigger asChild>
                                                        <div className="bg-white p-2 rounded border border-indigo-100 cursor-help hover:bg-slate-50 transition-colors">
                                                            <span className="text-[10px] uppercase font-bold text-slate-500 block mb-1">Coding Intensity</span>
                                                            <div className="flex items-center gap-2">
                                                                <span className="text-base font-bold text-slate-900">
                                                                    {codingIntensity > 0.7 ? (
                                                                        <span className="flex items-center gap-1.5"><Lock className="w-4 h-4 text-slate-500" /> Over-Coded</span>
                                                                    ) : codingIntensity > 0.4 ? (
                                                                        <span className="flex items-center gap-1.5"><Scale className="w-4 h-4 text-slate-500" /> Mixed Coding</span>
                                                                    ) : (
                                                                        <span className="flex items-center gap-1.5"><Wind className="w-4 h-4 text-slate-500" /> Decoded</span>
                                                                    )}
                                                                </span>
                                                                <span className="text-xs text-slate-400">({(codingIntensity * 10).toFixed(1)})</span>
                                                            </div>
                                                        </div>
                                                    </TooltipTrigger>
                                                    <TooltipContent className="max-w-xs bg-slate-900 text-white border-slate-800">
                                                        <p className="font-bold border-b border-slate-700 pb-1 mb-1">Dynamic Metric:</p>
                                                        <p className="text-xs mb-2">Inverse of Porosity ({(dynamicMetrics.porosity).toFixed(2)}).</p>

                                                        <p className="font-bold border-b border-slate-700 pb-1 mb-1">Audit Trail:</p>
                                                        <ul className="text-xs list-disc list-inside space-y-1">
                                                            {(selectedConfig.analysisData as AssemblageAnalysis)?.computed_metrics?.coding_audit && (selectedConfig.analysisData as AssemblageAnalysis).computed_metrics!.coding_audit!.length > 0
                                                                ? (selectedConfig.analysisData as AssemblageAnalysis).computed_metrics!.coding_audit!.map((t: string, i: number) => <li key={i}>{t}</li>)
                                                                : <li className="text-slate-400">No traces found</li>}
                                                        </ul>
                                                    </TooltipContent>
                                                </Tooltip>
                                            </TooltipProvider>
                                        </div>
                                    );
                                })()}
                            </div>
                        ) : (
                            <div className="bg-indigo-50 border border-indigo-100 p-4 rounded-lg">
                                <h3 className="font-bold text-indigo-900 text-lg mb-1">Combined Analysis</h3>
                                <p className="text-sm text-indigo-700 mb-3">{selectedConfigs.length} Assemblages Selected: {selectedConfigs.map(c => c.name).join(', ')}</p>
                                <div className="p-2 bg-white/50 rounded text-xs text-indigo-800 italic">
                                    Metrics and specific audits are disabled for multi-assemblage analysis. The analysis below reflects the combined socio-technical territory.
                                </div>
                            </div>
                        )}

                        {(selectedConfigs.length === 1 ? selectedConfigs[0].analysisData : savedAnalysis) ? (
                            <AssemblageAnalysisView
                                analysis={{
                                    ...((selectedConfigs.length === 1 ? selectedConfigs[0].analysisData : savedAnalysis) as AssemblageAnalysis),
                                    assemblage: dashboardAssemblage
                                }}
                                actors={actors}
                                reflexiveLogs={selectedConfigs.length === 1 ? selectedConfigs[0].reflexive_log : undefined}
                                onAddLog={handleAddLog}
                                onDeleteLog={handleDeleteLog}
                                onRatify={handleRatify}
                                onContest={handleContest}
                                onEnrichLinks={handleEnrichLinks}
                                isEnriching={isEnriching}
                                enrichProgress={enrichProgress}
                            />
                        ) : (
                            <div className="p-4 border border-dashed border-slate-300 rounded-lg text-center text-slate-500">
                                <p className="text-sm">No analysis data available. Click "Run Comprehensive Analysis".</p>
                            </div>
                        )}
                    </div>
                ) : savedAnalysis ? (
                    <AssemblageAnalysisView
                        analysis={savedAnalysis}
                        actors={actors}
                        onEnrichLinks={handleEnrichLinks}
                        isEnriching={isEnriching}
                        enrichProgress={enrichProgress}
                        onRatify={handleRatify}
                        onContest={handleContest}
                    // Logs only exist in Config mode so far, but we could add them to global analysis too if needed.
                    // Currently ReflexiveLog is only connected to `selectedConfig` in logic above.
                    />
                ) : (
                    // Default Fallback
                    <div className="flex flex-col items-center justify-center h-48 text-center text-slate-400">
                        <Layers className="h-8 w-8 mb-2 opacity-50" />
                        <p className="text-sm">Run analysis to map the assemblage.</p>
                    </div>
                )}
            </CardContent >
            <div className="p-2 border-t border-slate-200 bg-slate-50 text-[10px] text-slate-400 text-center italic">
                Methodological constrained artifact. Outputs are provisional inscriptions.
            </div>
            <CreditTopUpDialog open={showTopUp} onOpenChange={setShowTopUp} onSuccess={() => refetchCredits()} />
        </Card >
    );
}

import React, { useState, useEffect } from 'react';
import { Button } from '@/components/ui/button';
import {
    Popover,
    PopoverContent,
    PopoverTrigger,
} from '@/components/ui/popover';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Sparkles, Network, RefreshCw, Layers } from 'lucide-react';
import { EcosystemActor, EcosystemEdge, EcosystemConfiguration } from '@/types/ecosystem';
import { Badge } from '@/components/ui/badge';
import { Progress } from '@/components/ui/progress';

interface AssemblageSuggesterProps {
    actors: EcosystemActor[];
    edges: EcosystemEdge[];
    configurations: EcosystemConfiguration[];
    onCreateAssemblage: (name: string, actorIds: string[]) => void;
}

interface Suggestion {
    id: number;
    nodes: string[];
    diversityScore: number;
    metrics: {
        humanCount: number;
        nonHumanCount: number;
        size: number;
    };
    name: string;
}

export const AssemblageSuggester = React.memo(function AssemblageSuggester({ actors, edges, configurations, onCreateAssemblage }: AssemblageSuggesterProps) {
    const [suggestions, setSuggestions] = useState<Suggestion[]>([]);
    const [isOpen, setIsOpen] = useState(false);
    const [isCalculating, setIsCalculating] = useState(false);

    const handleSuggest = React.useCallback(async () => {
        setIsCalculating(true);
        try {
            // [AI-ENHANCED] Call Server-Side Detection
            const response = await fetch('/api/assemblages/detect', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    actors,
                    edges: edges.map(e => ({
                        source: typeof e.source === 'object' && 'id' in e.source ? (e.source as EcosystemActor).id : String(e.source),
                        target: typeof e.target === 'object' && 'id' in e.target ? (e.target as EcosystemActor).id : String(e.target),
                        type: e.type
                    })),
                    config: {
                        alpha: 1.0, // Balance Semantic/Structural
                        similarityThreshold: 0.75
                    }
                })
            });

            if (!response.ok) {
                const errorText = await response.text();
                throw new Error(`Detection failed: ${response.status} ${errorText}`);
            }

            const data = await response.json();

            if (data.suggestions) {
                // Filter out suggestions that match existing configurations
                const filteredSuggestions = data.suggestions.filter((suggestion: Suggestion) => {
                    // Check if an assemblage with this name already exists
                    const nameExists = configurations.some(config =>
                        config.name.toLowerCase() === suggestion.name.toLowerCase()
                    );
                    if (nameExists) return false;

                    // Check if this exact set of nodes already exists in a configuration
                    const suggestionNodeSet = new Set(suggestion.nodes);
                    return !configurations.some(config => {
                        const configNodeSet = new Set(config.memberIds);
                        // Check if sets are equal (same size and all elements match)
                        if (suggestionNodeSet.size !== configNodeSet.size) return false;
                        return Array.from(suggestionNodeSet).every(node => configNodeSet.has(node));
                    });
                });
                setSuggestions(filteredSuggestions);
            }

        } catch (error) {
            console.error("Failed to suggest assemblages:", error);
            setSuggestions([]);
        } finally {
            setIsCalculating(false);
        }, [actors, edges, configurations]);

    useEffect(() => {
        if (isOpen) {
            handleSuggest();
        }
    }, [isOpen, handleSuggest]);
    return (
        <Popover open={isOpen} onOpenChange={setIsOpen}>
            <PopoverTrigger asChild>
                <Button variant="outline" size="sm" className="h-8 gap-2 border-dashed">
                    <Sparkles className="h-3.5 w-3.5 text-amber-500" />
                    Suggest Assemblages
                </Button>
            </PopoverTrigger>
            <PopoverContent className="w-80 p-0 bg-white" align="start">
                <div className="p-3 border-b bg-slate-50 flex items-center justify-between">
                    <h4 className="font-semibold text-sm flex items-center gap-2">
                        <Network className="h-4 w-4 text-slate-500" />
                        Assemblage Scout
                    </h4>
                    <Button variant="ghost" size="icon" className="h-6 w-6" onClick={handleSuggest} disabled={isCalculating}>
                        <RefreshCw className={`h-3.5 w-3.5 ${isCalculating ? 'animate-spin' : ''}`} />
                    </Button>
                </div>

                <ScrollArea className="h-[300px] p-3">
                    {isCalculating ? (
                        <div className="flex flex-col items-center justify-center h-full text-slate-500 gap-2">
                            <RefreshCw className="h-6 w-6 animate-spin opacity-20" />
                            <span className="text-xs">Analyzing network topology...</span>
                        </div>
                    ) : suggestions.length === 0 ? (
                        <div className="text-center py-8 text-slate-400 text-xs">
                            No strong assemblages detected.<br />Try adding more connections.
                        </div>
                    ) : (
                        <div className="space-y-3">
                            {suggestions.map((s, idx) => (
                                <div key={idx} className="border rounded-md p-3 hover:bg-slate-50 transition-colors group relative">
                                    <div className="flex justify-between items-start mb-2">
                                        <div>
                                            <div className="font-medium text-sm text-slate-800">{s.name}</div>
                                            <div className="text-[10px] text-slate-500 flex items-center gap-1">
                                                <span>{s.metrics.size} Actors</span>
                                                <span>&bull;</span>
                                                <span>{s.metrics.humanCount} Human</span>
                                                <span>/</span>
                                                <span>{s.metrics.nonHumanCount} Non-Human</span>
                                            </div>
                                        </div>
                                        <Badge variant={s.diversityScore > 0.7 ? "default" : "secondary"} className="text-[10px] h-5">
                                            Div: {(s.diversityScore * 100).toFixed(0)}%
                                        </Badge>
                                    </div>

                                    <div className="space-y-1 mb-3">
                                        <div className="flex justify-between text-[10px] text-slate-400">
                                            <span>Socio-Technical Heterogeneity</span>
                                        </div>
                                        <Progress value={s.diversityScore * 100} className="h-1" />
                                    </div>

                                    {/* Display actor names in this assemblage */}
                                    <div className="mb-3 p-2 bg-slate-50 rounded border border-slate-100">
                                        <div className="text-[10px] font-medium text-slate-600 mb-1">Actors:</div>
                                        <div className="flex flex-wrap gap-1">
                                            {s.nodes.map((nodeId) => {
                                                const actor = actors.find(a => a.id === nodeId);
                                                return actor ? (
                                                    <Badge
                                                        key={nodeId}
                                                        variant="outline"
                                                        className="text-[9px] px-1.5 py-0 h-4 bg-white"
                                                    >
                                                        {actor.name}
                                                    </Badge>
                                                ) : null;
                                            })}
                                        </div>
                                    </div>

                                    <Button
                                        size="sm"
                                        className="w-full text-xs h-7 gap-1"
                                        onClick={() => {
                                            onCreateAssemblage(s.name, s.nodes);
                                            setIsOpen(false);
                                        }}
                                    >
                                        <Layers className="h-3 w-3" />
                                        Form Assemblage
                                    </Button>
                                </div>
                            ))}
                        </div>
                    )}
                </ScrollArea>
                <div className="p-2 border-t bg-slate-50 text-[10px] text-slate-400 text-center">
                    Powered by AI-Enhanced Louvain (Semantically Aware)
                </div>
            </PopoverContent>
        </Popover>
    );
});

import React, { useState, useMemo } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Button } from '@/components/ui/button';
import { Search, X, Activity, Filter, ArrowRight } from 'lucide-react';
import { EcosystemActor } from '@/types/ecosystem';

interface AssociationDirectoryProps {
    links: any[]; // The processed links array from EcosystemMap
    actors: EcosystemActor[]; // The merged/hydrated actors
    onSelectLink: (link: any) => void;
    onClose: () => void;
}

export function AssociationDirectory({ links, actors, onSelectLink, onClose }: AssociationDirectoryProps) {
    const [searchQuery, setSearchQuery] = useState('');
    const [filterType, setFilterType] = useState<string>('all');
    const [filterClassification, setFilterClassification] = useState<string>('all');

    // Create a quick lookup for actor names if needed (though links often have IDs or Node objects)
    const actorMap = useMemo(() => {
        const map = new Map<string, string>();
        actors.forEach(a => map.set(a.id, a.name));
        return map;
    }, [actors]);

    const getActorName = (actorOrId: any) => {
        if (!actorOrId) return 'Unknown';
        if (typeof actorOrId === 'string') return actorMap.get(actorOrId) || actorOrId;
        if (typeof actorOrId === 'object' && actorOrId.name) return actorOrId.name;
        if (typeof actorOrId === 'object' && actorOrId.id) return actorMap.get(actorOrId.id) || actorOrId.id;
        return 'Unknown';
    };

    // Extract unique interaction types for the filter dropdown
    const availableTypes = useMemo(() => {
        const types = new Set<string>();
        links.forEach(l => {
            if (l.type) types.add(l.type);
        });
        return Array.from(types).sort();
    }, [links]);

    // Extract unique classifications for the filter dropdown
    const availableClassifications = useMemo(() => {
        const classes = new Set<string>();
        links.forEach(l => {
            if (l.analysis?.classification) classes.add(l.analysis.classification);
        });
        return Array.from(classes).sort();
    }, [links]);

    const filteredLinks = useMemo(() => {
        return links.filter(link => {
            const sourceName = getActorName(link.source).toLowerCase();
            const targetName = getActorName(link.target).toLowerCase();
            const linkType = (link.type || '').toLowerCase();
            const linkDesc = (link.description || '').toLowerCase();
            const query = searchQuery.toLowerCase();

            const matchesSearch = !query ||
                sourceName.includes(query) ||
                targetName.includes(query) ||
                linkType.includes(query) ||
                linkDesc.includes(query);

            const matchesType = filterType === 'all' || link.type === filterType;
            const matchesClass = filterClassification === 'all' || link.analysis?.classification === filterClassification;

            return matchesSearch && matchesType && matchesClass;
        }).sort((a, b) => {
            // Sort by mediator score if available, otherwise by type
            const scoreA = a.analysis?.mediatorScore || 0;
            const scoreB = b.analysis?.mediatorScore || 0;
            if (scoreA !== scoreB) return scoreB - scoreA;
            return (a.type || '').localeCompare(b.type || '');
        });
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [links, searchQuery, filterType, filterClassification, actorMap]);

    return (
        <Card className="flex flex-col h-full w-[350px] shadow-xl border-l border-slate-200 bg-white/95 backdrop-blur-sm rounded-none absolute right-0 top-0 z-50 animate-in slide-in-from-right-full duration-300">
            <CardHeader className="p-4 border-b border-slate-100 flex flex-row items-center justify-between shrink-0 bg-white">
                <CardTitle className="text-sm font-semibold flex items-center gap-2 text-indigo-900 tracking-tight">
                    <Activity className="h-4 w-4 text-indigo-500" />
                    Association Directory
                </CardTitle>
                <Button variant="ghost" size="icon" className="h-6 w-6 rounded-full hover:bg-slate-100" onClick={onClose}>
                    <X className="h-4 w-4 text-slate-500" />
                </Button>
            </CardHeader>
            <div className="p-3 border-b border-slate-100 bg-slate-50/50 shrink-0 space-y-3">
                <div className="relative">
                    <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-slate-400" />
                    <Input
                        placeholder="Search actors, types, or descriptions..."
                        className="pl-9 h-9 text-xs bg-white border-slate-200 focus-visible:ring-indigo-500"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                    />
                </div>
                <div className="flex items-center gap-2">
                    <Filter className="h-3.5 w-3.5 text-slate-400 shrink-0" />
                    <select
                        className="flex-1 text-xs border border-slate-200 rounded-md h-8 px-2 bg-white outline-none focus:border-indigo-500 text-slate-700 w-1/2"
                        value={filterType}
                        onChange={(e) => setFilterType(e.target.value)}
                    >
                        <option value="all">All Types</option>
                        {availableTypes.map(t => (
                            <option key={t} value={t}>{t}</option>
                        ))}
                    </select>
                    <select
                        className="flex-1 text-xs border border-slate-200 rounded-md h-8 px-2 bg-white outline-none focus:border-indigo-500 text-slate-700 w-1/2"
                        value={filterClassification}
                        onChange={(e) => setFilterClassification(e.target.value)}
                    >
                        <option value="all">All Profiles</option>
                        {availableClassifications.map(c => (
                            <option key={c} value={c}>{c.replace(/_/g, ' ')}</option>
                        ))}
                    </select>
                </div>
            </div>

            <CardContent className="p-0 flex-1 overflow-hidden bg-slate-50/30">
                <ScrollArea className="h-full">
                    {filteredLinks.length === 0 ? (
                        <div className="p-8 text-center text-sm text-slate-400 flex flex-col items-center gap-2">
                            <Activity className="h-8 w-8 text-slate-200 block" />
                            <p>No associations found matching criteria.</p>
                        </div>
                    ) : (
                        <div className="divide-y divide-slate-100">
                            {filteredLinks.map((link, idx) => (
                                <button
                                    key={idx}
                                    onClick={() => onSelectLink(link)}
                                    className="w-full text-left p-3 hover:bg-indigo-50 transition-colors group relative"
                                >
                                    <div className="flex justify-between items-start mb-1.5">
                                        <div className="flex items-center gap-1.5 flex-wrap flex-1 pr-2">
                                            <span className="text-[11px] font-bold text-slate-700 truncate max-w-[120px]" title={getActorName(link.source)}>
                                                {getActorName(link.source)}
                                            </span>
                                            <ArrowRight className="h-3 w-3 text-slate-300 shrink-0" />
                                            <span className="text-[11px] font-bold text-slate-700 truncate max-w-[120px]" title={getActorName(link.target)}>
                                                {getActorName(link.target)}
                                            </span>
                                        </div>
                                    </div>
                                    <div className="flex flex-wrap items-center gap-1.5 mt-1">
                                        <span className="text-[10px] uppercase font-semibold text-indigo-600 bg-indigo-50 px-1.5 py-0.5 rounded border border-indigo-100 flex-shrink-0">
                                            {link.type}
                                        </span>
                                        {link.flow_type && (
                                            <span className="text-[9px] uppercase font-semibold text-slate-500 bg-slate-100 px-1.5 py-0.5 rounded border border-slate-200 flex-shrink-0">
                                                {link.flow_type} flow
                                            </span>
                                        )}
                                        {link.analysis?.classification && (
                                            <span className="text-[9px] uppercase font-semibold text-amber-700 bg-amber-50 px-1.5 py-0.5 rounded border border-amber-200 flex-shrink-0">
                                                {link.analysis.classification.replace(/_/g, ' ')}
                                            </span>
                                        )}
                                        {link.analysis?.mediatorScore !== undefined && (
                                            <span className="text-[9px] font-mono text-slate-500 bg-white px-1.5 py-0.5 rounded border border-slate-200 flex-shrink-0">
                                                score: {link.analysis.mediatorScore.toFixed(2)}
                                            </span>
                                        )}
                                    </div>
                                    {link.description && (
                                        <p className="text-[10px] text-slate-500 mt-1.5 line-clamp-1 italic">
                                            {link.description}
                                        </p>
                                    )}
                                </button>
                            ))}
                        </div>
                    )}
                </ScrollArea>
            </CardContent>
            <div className="p-2 border-t border-slate-100 bg-white shrink-0">
                <p className="text-[10px] text-center text-slate-400 font-medium">
                    Showing {filteredLinks.length} of {links.length} total associations
                </p>
            </div>
        </Card>
    );
}

import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import { HelpTooltip } from "@/components/help/HelpTooltip";
import { SimulationNode } from '@/hooks/useForceGraph';
import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Badge } from "@/components/ui/badge";

import { Play, Pause, RotateCcw, BookOpen } from "lucide-react";
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle } from "@/components/ui/dialog";

interface Props {
    isExpanded: boolean;
    nodes: SimulationNode[];
}

interface ProcessedItem {
    id: string;
    originalName: string;
    translationCode: string;
    type: "social" | "economic" | "technical" | "resistance";
    timestamp: number;
}

export function CodingView({ isExpanded, nodes }: Props) {
    const svgRef = useRef<SVGSVGElement>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const [processedLog, setProcessedLog] = useState<ProcessedItem[]>([]);
    const processedIdsRef = useRef<Set<string>>(new Set());


    // Pause Control
    const [isPaused, setIsPaused] = useState(false);
    const isPausedRef = useRef(false);

    // Theory Dialog
    const [showTheory, setShowTheory] = useState(false);
    const [dimensions, setDimensions] = useState({ width: 0, height: 0 });

    // Handle container resizing
    useEffect(() => {
        if (!containerRef.current) return;

        const observer = new ResizeObserver((entries) => {
            if (!entries[0]) return;
            const { width, height } = entries[0].contentRect;
            setDimensions({ width, height });
        });

        observer.observe(containerRef.current);
        return () => observer.disconnect();
    }, []);

    // Sync Ref for D3 Timer
    useEffect(() => {
        isPausedRef.current = isPaused;
    }, [isPaused]);

    useEffect(() => {
        if (!containerRef.current || !svgRef.current || dimensions.width === 0) return;
        const { width, height } = dimensions;

        const svg = d3.select(svgRef.current)
            .attr("width", width)
            .attr("height", height)
            .attr("viewBox", `0 0 ${width} ${height}`)
            .attr("preserveAspectRatio", "xMidYMid meet")
            .html("");

        // --- Visual Setup ---
        const filterX = width / 2;

        // Background Zones
        svg.append("rect").attr("x", 0).attr("width", filterX).attr("y", 0).attr("height", height).attr("fill", "#f8fafc");
        svg.append("rect").attr("x", filterX).attr("width", width / 2).attr("y", 0).attr("height", height).attr("fill", "#ecfdf5");

        // The Filter Barrier
        svg.append("line")
            .attr("x1", filterX)
            .attr("y1", 20)
            .attr("x2", filterX)
            .attr("y2", height - 20)
            .attr("stroke", "#334155")
            .attr("stroke-width", 4)
            .attr("stroke-dasharray", "8 4");

        svg.append("text").attr("x", width * 0.25).attr("y", 30).attr("text-anchor", "middle").attr("class", "text-xs font-bold text-slate-400 uppercase").text("Raw Social Reality");
        svg.append("text").attr("x", width * 0.75).attr("y", 30).attr("text-anchor", "middle").attr("class", "text-xs font-bold text-emerald-600 uppercase").text("coded metrics");

        interface Particle {
            id: string;
            name: string;
            x: number;
            y: number;
            vx: number; // Add velocity X
            vy: number; // Add velocity Y
            type: "social" | "economic" | "technical"; // Add technical
            baseR: number;
            nodeType: string;
            isResisting?: boolean; // Track resistance state
        }

        // --- Particles (Mapped from Nodes) ---
        const validNodes = nodes.filter(n => !n.isHidden);

        const getCategory = (type: string) => {
            const t = type.toLowerCase();
            if (
                t.includes('market') || t.includes('capital') || t.includes('infra') ||
                t.includes('economic') || t.includes('finance') || t.includes('industry') ||
                t.includes('commercial') || t.includes('investment') || t.includes('bank') ||
                t.includes('business') || t.includes('utility') || t.includes('governance')
            ) return 'economic';

            if (
                t.includes('tech') || t.includes('artifact') || t.includes('resource') ||
                t.includes('data') || t.includes('algorithm') || t.includes('software') ||
                t.includes('hardware') || t.includes('machine') || t.includes('digital') ||
                t.includes('automated') || t.includes('tool') || t.includes('platform')
            ) return 'technical';

            return 'social';
        };

        const particles: Particle[] = validNodes.map((n, i) => ({
            id: n.id,
            name: n.name,
            x: -20 - (Math.random() * width),
            y: 50 + Math.random() * (height - 100),
            type: getCategory(n.type) as "social" | "economic" | "technical",
            baseR: n.radius ? n.radius / 3 : 5,
            vx: 1 + Math.random() * 1.5, // Init velocity X
            vy: (Math.random() - 0.5) * 0.5, // Slight random jitter Y
            nodeType: n.type
        }));

        // Fallback
        if (particles.length === 0) {
            for (let i = 0; i < 30; i++) {
                particles.push({
                    id: `Actor-${i}`,
                    name: `Actor ${i}`,
                    x: -Math.random() * width,
                    y: 50 + Math.random() * (height - 100),
                    type: Math.random() > 0.6 ? 'social' : Math.random() > 0.3 ? 'technical' : 'economic',
                    baseR: 5 + Math.random() * 5,
                    vx: 1 + Math.random() * 2,
                    vy: 0,
                    nodeType: 'Generated'
                });
            }
        }

        const timer = d3.timer(() => {
            if (isPausedRef.current) return;

            // Update
            const newItems: ProcessedItem[] = [];

            particles.forEach(p => {
                p.x += p.vx;
                p.y += p.vy;

                // Resistance Logic (The Fragility of the Network)
                if (p.x > filterX - 5 && p.x < filterX + 5 && !p.isResisting && !processedIdsRef.current.has(p.id)) {
                    // Small chance to resist translation (bounce off)
                    // Social actors resist more (15%), Technical (5%), Economic (1%)
                    const resistanceChance = p.type === 'social' ? 0.15 : p.type === 'technical' ? 0.05 : 0.01;

                    if (Math.random() < resistanceChance) {
                        p.isResisting = true;
                        p.vx = -Math.abs(p.vx * 3);
                        p.vy = (Math.random() - 0.5) * 4;

                        // Log Resistance (Instability Node)
                        if (!processedIdsRef.current.has(p.id)) {
                            processedIdsRef.current.add(p.id);
                            newItems.push({
                                id: p.id,
                                originalName: p.name,
                                translationCode: `LINE_OF_FLIGHT_${Math.floor(Math.random() * 100)}`,
                                type: 'resistance' as any, // Cast to any to bypass strict type for now or add to interface
                                timestamp: Date.now()
                            });
                        }
                    }
                }

                // Detection Logic (Successful Translation)
                if (p.x > filterX && !processedIdsRef.current.has(p.id) && !p.isResisting) {
                    processedIdsRef.current.add(p.id);

                    // Add to log
                    newItems.push({
                        id: p.id,
                        originalName: p.name,
                        translationCode: p.type === 'social' ? `ERR_REDUCT_${Math.floor(Math.random() * 1000)}` :
                            p.type === 'technical' ? `ARTIFACT_${Math.floor(Math.random() * 1000)}` :
                                `METRIC_${Math.floor(Math.random() * 1000)}`,
                        type: p.type === 'technical' ? 'economic' : p.type, // Group technical with economic for simplicity in log color, or keep separate?
                        timestamp: Date.now()
                    });
                }

                // Loop around or reset resistant particles
                if (p.x > width + 50 || p.x < -100 || p.y < -50 || p.y > height + 50) {
                    p.x = -50;
                    p.y = 50 + Math.random() * (height - 100);
                    p.vx = 1 + Math.random() * 1.5; // Reset speed
                    p.vy = 0;
                    p.isResisting = false;
                    processedIdsRef.current.delete(p.id);
                }
            });

            if (newItems.length > 0) {
                setProcessedLog(prev => [...newItems, ...prev].slice(0, 50));
            }

            // Draw
            const selection = svg.selectAll<SVGGElement, Particle>(".particle")
                .data(particles, (d: Particle) => d.id);

            const enter = selection.enter().append("g").attr("class", "particle");

            enter.filter((d: Particle) => d.type === 'social').append("circle").attr("r", (d: Particle) => d.baseR);
            enter.filter((d: Particle) => d.type === 'economic').append("rect")
                .attr("width", (d: Particle) => d.baseR * 2)
                .attr("height", (d: Particle) => d.baseR * 2)
                .attr("x", (d: Particle) => -d.baseR)
                .attr("y", (d: Particle) => -d.baseR);
            // Non-Human / Technical Actors (Triangles)
            enter.filter((d: Particle) => d.type === 'technical').append("path")
                .attr("d", d3.symbol().type(d3.symbolTriangle).size(100))
                .attr("fill", "#eab308"); // Yellow-500

            // Update Transforms & Styles
            selection.attr("transform", d => {
                let scale = 1;
                const rotate = 0;
                let tx = d.x;
                let ty = d.y;

                if (d.isResisting) {
                    scale = 1.2; // Slight swell
                    tx += (Math.random() - 0.5) * 2; // Jitter X
                    ty += (Math.random() - 0.5) * 2; // Jitter Y
                } else if (d.x > filterX) {
                    if (d.type === 'social') scale = 0.4; // Slightly larger reduction for visibility
                    else scale = 0.9; // Less reduction for economic/technical
                }

                return `translate(${tx},${ty}) scale(${scale})`;
            });

            selection.select("circle")
                .attr("fill", (d: Particle) => d.isResisting ? "#fb923c" : d.x > filterX ? "#cbd5e1" : "#f43f5e") // Orange if resisting
                .attr("opacity", (d: Particle) => d.x > filterX ? 0.4 : 0.8);

            selection.select("rect")
                .attr("rx", (d: any) => d.x > filterX ? 2 : 0)
                .attr("fill", (d: Particle) => d.isResisting ? "#fb923c" : d.x > filterX ? "#10b981" : "#3b82f6");

            selection.select("path")
                .attr("fill", (d: Particle) => d.isResisting ? "#fb923c" : d.x > filterX ? "#a3e635" : "#eab308") // Yellow -> Lime
                .attr("opacity", (d: Particle) => d.x > filterX ? 0.6 : 1);

            selection.exit().remove();
        });

        return () => timer.stop();

    }, [isExpanded, nodes, dimensions]);

    return (
        <div className="flex h-full w-full gap-4">
            {/* Main Viz */}
            <div className="flex-1 flex flex-col gap-4">
                <div className="bg-white p-4 rounded-lg border border-slate-200 shadow-sm flex items-center justify-between shrink-0">
                    <div className="space-y-1">
                        <h3 className="font-semibold text-slate-800 flex items-center gap-2">
                            Translation Filter (Coding)
                            <HelpTooltip>
                                Social Actors (Red Circles) are complex, messy, and human. The System (The Coding Filter) cannot understand them.
                                So it flags them as an ERROR (ERR_REDUCT) because it has to "reduce" them to make them fit.
                            </HelpTooltip>
                        </h3>
                        <p className="text-xs text-slate-500 max-w-lg">
                            Visualizing the epistemic violence of translation: to make something legible to the system, you must often mutilate it.
                        </p>
                    </div>
                    <div className="flex items-center gap-1">
                        <Button variant="outline" size="icon" onClick={() => setShowTheory(true)} title="Explain Theory">
                            <BookOpen className="h-4 w-4 text-indigo-600" />
                        </Button>
                        <Button variant="outline" size="icon" onClick={() => setIsPaused(!isPaused)} title={isPaused ? "Resume" : "Pause"}>
                            {isPaused ? <Play className="h-4 w-4 fill-current" /> : <Pause className="h-4 w-4 fill-current" />}
                        </Button>
                    </div>
                </div>

                {/* Theory Dialog */}
                <Dialog open={showTheory} onOpenChange={setShowTheory}>
                    <DialogContent className="max-w-2xl bg-white">
                        <DialogHeader>
                            <DialogTitle className="text-xl font-bold text-slate-800 flex items-center gap-2">
                                <BookOpen className="h-6 w-6 text-indigo-600" />
                                Assemblage Theory: The Coding Filter
                            </DialogTitle>
                            <DialogDescription>
                                Understanding the "epistemic violence" of translation in Actor-Network Theory.
                            </DialogDescription>
                        </DialogHeader>
                        <ScrollArea className="max-h-[60vh] pr-4">
                            <div className="space-y-6 py-4">
                                <div className="space-y-2">
                                    <h4 className="font-semibold text-rose-600 flex items-center gap-2">
                                        1. Translation as "Betrayal"
                                    </h4>
                                    <p className="text-sm text-slate-600 leading-relaxed">
                                        In ANT, to "translate" an actor is to displace them and make them speak the language of the network.
                                        There is a famous saying: <em>"Traduttore, traditore"</em> (Translator, traitor).
                                        <br /><br />
                                        <strong>The Viz:</strong> You see complex "Social Actors" (Red) hitting the barrier.
                                        <br />
                                        <strong>The Theory:</strong> The system cannot handle their full, messy complexity. To bring them into the network, it must <strong>betray</strong> their nature—stripping away nuance and turning them into a simple data point (or "Error") just to process them.
                                    </p>
                                </div>

                                <div className="space-y-2">
                                    <h4 className="font-semibold text-slate-800 flex items-center gap-2">
                                        2. Obligatory Passage Points (The Filter)
                                    </h4>
                                    <p className="text-sm text-slate-600 leading-relaxed">
                                        The central barrier represents an mechanism that forces all actors to pass through a specific channel to be recognized.
                                        <br /><br />
                                        <strong>The Viz:</strong> The vertical line that all particles must hit.
                                        <br />
                                        <strong>The Theory:</strong> If an actor (like a "Civil Society Group") wants to be relevant, they <em>must</em> pass through this filter. They cannot just "be themselves"; they must become "System-Compatible."
                                    </p>
                                </div>

                                <div className="space-y-2">
                                    <h4 className="font-semibold text-emerald-600 flex items-center gap-2">
                                        3. Codification & Legibility
                                    </h4>
                                    <p className="text-sm text-slate-600 leading-relaxed">
                                        Assemblages work by making things "legible" (readable) to the center of power. Different actors have different levels of friction:
                                        <br /><br />
                                        <strong>Economic Actors (Blue Squares):</strong> Represent abstract market flows. They readily pass through to become <strong>Green Metrics</strong> because they are already "legible" to the system—their value is easily counted.
                                        <br /><br />
                                        <strong>Technical Actors (Yellow Triangles):</strong> Represent non-human tools, data, and infrastructure. They are translated into <strong>Lime Artifacts</strong>—the "black boxes" that the network relies on to function.
                                        <br /><br />
                                        <strong>Social Actors (Red Circles):</strong> These face the most friction. Because they are messy and human, they are often reduced to <strong>Grey Errors</strong> (ERR_REDUCT) to make them processable.
                                    </p>
                                </div>

                                <div className="space-y-2">
                                    <h4 className="font-semibold text-amber-600 flex items-center gap-2">
                                        4. Symmetry & Fragility
                                    </h4>
                                    <p className="text-sm text-slate-600 leading-relaxed">
                                        <strong>Generalized Symmetry:</strong> It's not just humans who get translated. Non-human actors (like soil samples or instruments) also have to be standardized to fit the network.
                                        <br /><br />
                                        <strong>Resistance:</strong> Translation is never guaranteed. Sometimes actors "bounce off," resist enrollment, or form counter-networks. The filter implies control, but the network is always precarious.
                                    </p>
                                </div>
                            </div>
                        </ScrollArea>
                    </DialogContent>
                </Dialog>
                <div ref={containerRef} className="flex-1 bg-slate-50 rounded-lg overflow-hidden border border-slate-200 relative min-h-0">
                    <svg ref={svgRef} className="w-full h-full block" />
                </div>
            </div>

            {/* Live Log Sidebar */}
            <div className="w-96 bg-white border border-slate-200 rounded-lg shadow-sm flex flex-col transition-all duration-500 ease-in-out">
                <div className="p-3 border-b border-slate-100 bg-slate-50/50 space-y-2">
                    <h4 className="text-xs font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                        <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
                        Encoding Log
                    </h4>
                    <div className="grid grid-cols-2 gap-2 text-[10px] text-slate-500 font-mono bg-white p-1.5 rounded border border-slate-100">
                        <div className="flex items-center gap-1.5">
                            <span className="w-1.5 h-1.5 rounded-full bg-rose-500"></span>
                            <span>ERR_REDUCT = Social</span>
                        </div>
                        <div className="flex items-center gap-1.5">
                            <span className="w-1.5 h-1.5 rounded-sm bg-emerald-500"></span>
                            <span>METRIC = Economic</span>
                        </div>
                        <div className="flex items-center gap-1.5">
                            <div className="w-0 h-0 border-l-[4px] border-l-transparent border-r-[4px] border-r-transparent border-b-[6px] border-b-lime-500"></div>
                            <span>ARTIFACT = Technical</span>
                        </div>
                        <div className="flex items-center gap-1.5 opacity-60">
                            <span className="w-1.5 h-1.5 rounded-full bg-amber-500 animate-pulse"></span>
                            <span className="italic">FLIGHT = Resistance</span>
                        </div>
                    </div>
                </div>
                <div className="px-3 py-2 bg-rose-50 border-b border-rose-100 text-[10px] text-rose-700 leading-relaxed">
                    <strong>Why "Error"?</strong> The system struggles to quantify complex social actors, so it flags them as <span className="font-mono bg-white px-1 border border-rose-200 rounded text-rose-600">ERR_REDUCT</span> (Reduction Error) and assigns a random ID.
                </div>
                <ScrollArea className="flex-1 p-0">
                    <div className="flex flex-col">
                        {processedLog.length === 0 && (
