"use client";

import React, { useRef, useMemo, useEffect, useState } from 'react';
import { EcosystemActor, EcosystemConfiguration } from '@/types/ecosystem';
import dynamic from 'next/dynamic';
import * as THREE from 'three';
// @ts-ignore
import { UnrealBloomPass } from 'three/examples/jsm/postprocessing/UnrealBloomPass';
import { computeNodeViz, computeLinkViz, NodeViz, LinkViz } from '@/lib/viz-contract';
import { OverlayDetails } from './OverlayDetails';
import { generateEdges } from '@/lib/graph-utils';
import { createLinkGeometry, updateLinkPosition, createNodeObject, GraphNode, GraphLink, NodeUserData, animateLinkParticles } from './GraphVisuals';
import { RelationshipDetail } from './RelationshipDetail';
import { Relationship } from '@/types/relationship';

// Dynamically import ForceGraph3D because it uses window/WEBGL which is client-side only
const ForceGraph3D = dynamic(() => import('react-force-graph-3d'), {
    ssr: false,
    loading: () => <div className="flex items-center justify-center h-full text-slate-400">Loading 3D Engine...</div>
});


interface EcosystemMap3DProps {
    actors: EcosystemActor[];
    links?: GraphLink[]; // [NEW] Typed Links
    configurations: EcosystemConfiguration[];
    selectedForGrouping: string[];
    onToggleSelection: (actorId: string) => void;
    focusedNodeId: string | null;
    width: number;
    height: number;
    isStratumMode: boolean;
    reduceMotion?: boolean;
    onToggleCollapse?: (id: string) => void;
    tracedId?: string | null;
    isPresentationMode?: boolean; // [NEW] Presentation Mode Toggle
    selectedActorId?: string | null; // [NEW] Synced Selection
    showUnverifiedLinks?: boolean;
    linkClassFilter?: 'all' | 'mediator' | 'intermediary';
}




export const EcosystemMap3D = ({
    actors,
    links: externalLinks,
    configurations,
    selectedForGrouping,
    onToggleSelection,
    onToggleCollapse,
    width,
    height,
    isStratumMode,
    reduceMotion = false,
    tracedId,
    isPresentationMode = false,
    selectedActorId,
    showUnverifiedLinks = false,
    linkClassFilter = 'all'
}: EcosystemMap3DProps) => {
    const fgRef = useRef<any>(null);
    const lastClickRef = useRef<{ id: string, time: number } | null>(null);
    const [graphData, setGraphData] = useState<{ nodes: GraphNode[], links: GraphLink[] }>({ nodes: [], links: [] });
    const [selectedLink, setSelectedLink] = useState<Relationship | null>(null);
    const [selectedNode, setSelectedNode] = useState<GraphNode | null>(null);
    const [isOverlayPinned, setIsOverlayPinned] = useState(false);
    const [performanceMode, setPerformanceMode] = useState(false);
    const frameTimes = useRef<number[]>([]);
    const lastFrameTime = useRef<number>(Date.now());

    // 1. Unified Links Memo
    const links = useMemo(() => {
        // [FIX] Always enrich, even if links are passed from parent
        const baseEdges = externalLinks || generateEdges(actors);

        // [NEW] Enrich with Analysis Data from Configurations
        const analysisMap = new Map<string, any>();

        configurations.forEach(config => {
            if (config.analysisData && config.analysisData.relationships) {
                config.analysisData.relationships.forEach((rel: any) => {
                    // Store strict and reverse keys to ensure matching
                    analysisMap.set(`${rel.source}-${rel.target}`, rel);
                    analysisMap.set(`${rel.target}-${rel.source}`, rel);
                });
            }
        });

        // [FILTER] If analysis exists, ONLY show analyzed links (Mediators/Intermediaries)
        // If no analysis (size 0), show all theoretical links (Logic)
        const hasAnalysis = analysisMap.size > 0;

        const output = baseEdges
            .map(edge => {
                const sId = typeof edge.source === 'object' ? (edge.source as any).id : edge.source;
                const tId = typeof edge.target === 'object' ? (edge.target as any).id : edge.target;
                const analysis = analysisMap.get(`${sId}-${tId}`);

                if (analysis) {
                    return { ...edge, analysis };
                }
                return edge;
            })
            .filter(edge => {
                const edgeAnalysis = (edge as any).analysis;
                const isAnalyzed = !!edgeAnalysis;

                // 1. Explicit Classification Filter (High Priority)
                if (linkClassFilter !== 'all') {
                    if (!isAnalyzed) return false; // Hide unanalyzed when filtering specific types
                    const score = edgeAnalysis.mediatorScore;
                    if (linkClassFilter === 'mediator') return score >= 0.5;
                    if (linkClassFilter === 'intermediary') return score < 0.5;
                }

                // 2. Default View ("All Types")
                // If no analysis exists contextually (neither global nor local), show logical links.
                if (!hasAnalysis && !isAnalyzed) return true;

                // 3. Unverified Visibility (in presence of analysis)
                if (!isAnalyzed) {
                    return showUnverifiedLinks;
                }

                return true;
            });


        return output;
    }, [actors, externalLinks, configurations, showUnverifiedLinks, linkClassFilter]);

    // 2. Neighbors Memo
    // 2. Neighbors Memo
    const nodeNeighbors = useMemo(() => {
        if (!selectedNode) return [];
        return graphData.links
            .filter(link => {
                const l = link as GraphLink;
                const sId = typeof l.source === 'object' ? (l.source as GraphNode).id : l.source as string;
                const tId = typeof l.target === 'object' ? (l.target as GraphNode).id : l.target as string;
                return sId === selectedNode.id || tId === selectedNode.id;
            })
            .map(link => {
                const l = link as GraphLink;
                const sId = typeof l.source === 'object' ? (l.source as GraphNode).id : l.source as string;
                const isSource = sId === selectedNode.id;
                const other = isSource ? l.target : l.source;
                const otherNode = typeof other === 'object' ? other as GraphNode : graphData.nodes.find(n => n.id === other);
                return {
                    name: otherNode ? otherNode.name : 'Unknown',
                    type: otherNode ? otherNode.type : 'Unknown',
                    relation: l.type
                };
            })
            .slice(0, 5);
    }, [selectedNode, graphData]);

    // 3. Sync Selections
    useEffect(() => {
        if (selectedActorId) {
            const node = graphData.nodes.find(n => n.id === selectedActorId);
            if (node) {
                setSelectedNode(node);
                setIsOverlayPinned(true);
            }
        } else {
            if (!isOverlayPinned) setSelectedNode(null);
        }
    }, [selectedActorId, graphData.nodes, isOverlayPinned]);

    // 4. Data Mapping Effect
    useEffect(() => {

        const getZLevel = (type: string) => {
            const t = type.toLowerCase();
            if (t.includes('legal') || t.includes('law')) return 150;
            if (t.includes('policy') || t.includes('government')) return 80;
            if (t.includes('civil') || t.includes('academic')) return 20;
            if (t.includes('startup') || t.includes('private')) return -40;
            if (t.includes('algorithm') || t.includes('agent')) return -80;
            return 0;
        };

        const nodes: GraphNode[] = actors.map(actor => {
            const viz = computeNodeViz(actor);
            const baseNode: GraphNode = {
                id: actor.id,
                name: actor.name,
                type: actor.type,
                val: selectedForGrouping.includes(actor.id) ? 20 : 10,
                color: viz.color,
                isConfiguration: false,
                actor: actor,
                viz: viz
            };

            if (isStratumMode) {
                // Remove 'as any' since interface now supports fz/z
                baseNode.fz = getZLevel(actor.type);
                baseNode.z = getZLevel(actor.type);
            }

            return baseNode;
        });

        const gLinks: GraphLink[] = links.map(link => {
            const l = link as GraphLink; // Safe cast as we normalize it below
            const sourceId = typeof l.source === 'string' ? l.source : (l.source as GraphNode).id;
            const targetId = typeof l.target === 'string' ? l.target : (l.target as GraphNode).id;

            const viz = l.viz || computeLinkViz({
                source: sourceId,
                target: targetId,
                type: l.type || "Association",
                weight: 1.0,
                flow_type: (l as any).flow_type || 'logic', // Use actual flow type or default
                confidence: 1.0
            });

            return {
                source: sourceId,
                target: targetId,
                type: l.type,
                flow_type: (l as any).flow_type || 'logic',
                viz,
                analysis: l.analysis
            };
        });

        setGraphData({ nodes, links: gLinks });
    }, [actors, links, selectedForGrouping, isStratumMode]);

    // 5. Node Object Factory
    // Delegated to GraphVisuals for cleaner code
    const nodeObjectCallback = (node: any): THREE.Object3D => {
        return createNodeObject(node as GraphNode);
    };

    // 6. Animation Hook
    useEffect(() => {
        let animationFrameId: number;
        let bloomPass: any = null;
        const fgInstance = fgRef.current;

        if (isPresentationMode && !performanceMode && fgInstance) {
            const fg = fgInstance;
            const scene = fg.scene();
            scene.fog = new THREE.FogExp2(0x0F172A, 0.002);

            if (fg.postProcessingComposer) {
                const composer = fg.postProcessingComposer();
                // @ts-ignore
                bloomPass = new UnrealBloomPass(undefined, 1.2, 0.5, 0.5);
                composer.addPass(bloomPass);
            }
        }

        const animate = () => {
            const now = Date.now();
            const delta = now - lastFrameTime.current;
            lastFrameTime.current = now;

            if (delta > 0) {
                const fps = 1000 / delta;
                frameTimes.current.push(fps);
                if (frameTimes.current.length > 60) frameTimes.current.shift();
                if (frameTimes.current.length === 60 && animationFrameId % 60 === 0) {
                    const avgFps = frameTimes.current.reduce((a, b) => a + b) / 60;
                    if (avgFps < 30 && !performanceMode) setPerformanceMode(true);
                    else if (avgFps > 55 && performanceMode) setPerformanceMode(false);
                }
            }

            if (fgRef.current) {
                const fg = fgRef.current;
                const scene = fg.scene ? fg.scene() : null;
                if (scene && !reduceMotion && !performanceMode) {
                    // [NEW] Animate Particles
                    animateLinkParticles(scene, now);

                    scene.traverse((object: THREE.Object3D) => {
                        const userData = object.userData as NodeUserData;
                        if (userData && userData.isJitterTarget) {
                            const magnitude = (userData.jitterMagnitude || 0) * 0.5;
                            const heat = userData.heat || 0;
                            const freq = 0.002 + (heat * 0.01);
                            const scaledMagnitude = magnitude + (heat * 0.1);
                            const phase = object.id * 0.1;

                            object.position.x = Math.sin(now * freq + phase) * scaledMagnitude;
                            object.position.y = Math.cos(now * freq + phase) * scaledMagnitude;
                            object.position.z = Math.sin(now * freq * 0.8 + phase) * scaledMagnitude;

                            if (object instanceof THREE.Mesh && object.material instanceof THREE.MeshStandardMaterial) {
                                const mat = object.material;
                                if (heat > 0.4) {
                                    const pulse = (Math.sin(now * freq + phase) + 1) * 0.5;
                                    mat.emissiveIntensity = heat * pulse * 2;
                                    mat.emissive = new THREE.Color(heat > 0.8 ? 0xff3300 : 0xff9900);
                                }
                            }
                        }
                    });
                }
            }
            animationFrameId = requestAnimationFrame(animate);
        };

        animate();
        return () => {
            if (animationFrameId) cancelAnimationFrame(animationFrameId);
            if (bloomPass && fgInstance) {
                const fg = fgInstance;
                if (fg.postProcessingComposer) fg.postProcessingComposer().removePass(bloomPass);
            }
        };
    }, [reduceMotion, performanceMode, isPresentationMode]);

    // 7. Focus Effect
    useEffect(() => {
        if (!tracedId || !fgRef.current) return;
        const node = graphData.nodes.find(n => n.id === tracedId);
        if (node && typeof node.x === 'number' && typeof node.y === 'number' && typeof node.z === 'number') {
            const distance = 80;
            const distRatio = 1 + distance / Math.hypot(node.x, node.y, node.z);
            fgRef.current.cameraPosition(
                { x: node.x * distRatio, y: node.y * distRatio, z: node.z * distRatio },
                { x: node.x, y: node.y, z: node.z },
                2000
            );
        }
    }, [tracedId, graphData.nodes]);

    return (
        <div style={{ width: '100%', height: '100%', overflow: 'hidden', position: 'relative' }}>
            <div className="absolute top-2 right-2 flex flex-col items-end gap-2 z-50 pointer-events-none">
                {performanceMode && (
                    <div className="px-2 py-1 bg-yellow-900/80 text-yellow-200 text-xs rounded border border-yellow-700">
                        ⚡ Low Power Mode
                    </div>
                )}
            </div>

            <ForceGraph3D
                ref={fgRef}
                width={width}
                height={height}
                graphData={graphData}
                nodeLabel="name"
                nodeColor="color"
                backgroundColor="#0F172A"
                linkThreeObject={(link) => createLinkGeometry(link as any)}
                linkPositionUpdate={(obj, { start, end }, link) => {
                    // [FIX] Valid coordinates check
                    if (start && end && typeof start.x === 'number' && typeof end.x === 'number') {
                        // [FIX] Pass to updater
                        updateLinkPosition(obj, start, end, link as unknown as GraphLink);

                        // [FIX] Create Link Geometry builds geometry in WORLD coordinates (start/end).
                        // If we let ForceGraph apply default transforms (translate/rotate/scale), 
                        // it will apply them to the Group, causing double-transformation 
                        // (e.g. Group moved to midpoint + Geometry drawn from 0 to world coord).
                        // Returning true tells ForceGraph we handled positioning, keeping the Group at identity.
                        return true;
                    }
                    return false;
                }}
                linkWidth={0}
                linkDirectionalParticles={0}
                linkCurvature={isPresentationMode ? 0.25 : 0}
                nodeThreeObject={nodeObjectCallback}
                onNodeClick={(node) => {
                    const n = node as GraphNode;
                    const now = Date.now();
                    const isDouble = lastClickRef.current && lastClickRef.current.id === n.id && (now - lastClickRef.current.time < 300);
                    lastClickRef.current = { id: n.id, time: now };

                    if (isDouble && onToggleCollapse) {
                        if (n.actor && n.actor.isBlackBox) {
                            onToggleCollapse(n.id.replace('blackbox-', ''));
                            return;
                        }
                        if (n.isConfiguration) {
                            onToggleCollapse(n.id.replace('config-', ''));
                            return;
                        }
                    }

                    if (n.isConfiguration) return;

                    const distance = 60;
                    const distRatio = 1 + distance / Math.hypot(n.x!, n.y!, n.z!);
                    fgRef.current?.cameraPosition(
                        { x: n.x! * distRatio, y: n.y! * distRatio, z: n.z! * distRatio },
                        n,
                        2000
                    );

                    setSelectedNode(n);
                    setSelectedLink(null);
                    if (!isOverlayPinned) setIsOverlayPinned(true);
                    onToggleSelection(n.id);
                }}
                onLinkClick={(link) => {
                    const l = link as GraphLink;
                    if (l.analysis) {
                        setSelectedLink(l.analysis);
                        setSelectedNode(null);
                    }
                }}
                onBackgroundClick={() => {
                    if (!isOverlayPinned) {
                        setSelectedNode(null);
                        setSelectedLink(null);
                    }
                }}
            />

            {selectedNode && selectedNode.actor && selectedNode.viz && (
                <OverlayDetails
                    node={selectedNode.actor}
                    viz={selectedNode.viz}
                    onClose={() => {
                        setIsOverlayPinned(false);
                        setSelectedNode(null);
                        if (selectedActorId === selectedNode.id) onToggleSelection(selectedNode.id);
                    }}
                    onPin={() => setIsOverlayPinned(!isOverlayPinned)}
                    isPinned={isOverlayPinned}
                    neighbors={nodeNeighbors}
                />
            )}

            {selectedLink && (
                <RelationshipDetail
                    relationship={selectedLink}
                    onClose={() => setSelectedLink(null)}
                />
            )}

            {!selectedNode && !selectedLink && (
                <div className="absolute bottom-4 left-4 text-xs text-slate-500 pointer-events-none">
                    Click a node or link to inspect Assemblage Metrics.
                </div>
            )}
        </div>
    );
};

import React from 'react';
import { EcosystemActor } from '@/types/ecosystem';
import { Table, TableBody, TableCaption, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '@/components/ui/tooltip';
import { ExternalLink, ArrowUpDown, Check, Minus, Gavel, Coins, Code2, Megaphone } from 'lucide-react';

interface EcosystemTableProps {
    actors: EcosystemActor[];
    onSelectActor: (id: string) => void;
    selectedActorId: string | null;
}

export function EcosystemTable({ actors, onSelectActor, selectedActorId }: EcosystemTableProps) {
    const [sortConfig, setSortConfig] = React.useState<{ key: keyof EcosystemActor | 'metrics.territorialization' | 'metrics.deterritorialization'; direction: 'asc' | 'desc' } | null>(null);

    const getMetricRank = (val: string | number | undefined): number => {
        if (!val) return 0;
        if (typeof val === 'number') return val;
        // Map qualitative to rank
        const map: Record<string, number> = {
            "Strong": 3, "High": 3,
            "Moderate": 2, "Medium": 2,
            "Weak": 1, "Low": 1,
            "Latent": 0
        };
        return map[val] || 0;
    };

    const sortedActors = React.useMemo(() => {
        const sortableActors = [...actors];
        if (sortConfig !== null) {
            sortableActors.sort((a, b) => {
                let aValue: any = a[sortConfig.key as keyof EcosystemActor];
                let bValue: any = b[sortConfig.key as keyof EcosystemActor];

                // Handle nested metrics with rank conversion
                if (sortConfig.key === 'metrics.deterritorialization') {
                    aValue = getMetricRank(a.metrics?.deterritorialization);
                    bValue = getMetricRank(b.metrics?.deterritorialization);
                } else if (sortConfig.key === 'metrics.territorialization') {
                    aValue = getMetricRank(a.metrics?.territorialization);
                    bValue = getMetricRank(b.metrics?.territorialization);
                }

                if (aValue < bValue) {
                    return sortConfig.direction === 'asc' ? -1 : 1;
                }
                if (aValue > bValue) {
                    return sortConfig.direction === 'asc' ? 1 : -1;
                }
                return 0;
            });
        }
        return sortableActors;
    }, [actors, sortConfig]);

    const requestSort = (key: keyof EcosystemActor | 'metrics.territorialization' | 'metrics.deterritorialization') => {
        let direction: 'asc' | 'desc' = 'asc';
        if (sortConfig && sortConfig.key === key && sortConfig.direction === 'asc') {
            direction = 'desc';
        }
        setSortConfig({ key, direction });
    };

    // Helper to determine functional aptitude
    const getFunctionalAptitude = (type: string) => {
        const t = type.toLowerCase();
        return {
            regulatory: ['policy', 'law', 'regulation', 'government', 'court', 'legislator', 'regulator'].some(k => t.includes(k)),
            fund: ['fund', 'capital', 'investor', 'market', 'corporation', 'private', 'bank'].some(k => t.includes(k)),
            implement: ['startup', 'technologist', 'infrastructure', 'algorithm', 'standard', 'cloud', 'developer', 'lab'].some(k => t.includes(k)),
            contest: ['civilsociety', 'ngo', 'academic', 'activist', 'public', 'union', 'advocate'].some(k => t.includes(k)),
        };
    };

    const renderCheck = (active: boolean) => active ? (
        <Check className="h-4 w-4 text-emerald-600 mx-auto" />
    ) : (
        <Minus className="h-3 w-3 text-slate-200 mx-auto" />
    );

    // Helper to standardize display (Number -> String)
    const formatMetric = (val: string | number | undefined): string => {
        if (val === undefined || val === null) return '-';
        if (typeof val === 'string') return val;
        if (val >= 8) return 'High';
        if (val >= 4) return 'Medium';
        return 'Low';
    };

    return (
        <TooltipProvider>
            <div className="rounded-md border bg-white overflow-y-auto max-h-[600px] shadow-sm">
                <Table>
                    <TableCaption>Actor-Function Matrix: Capabilities of Ecosystem Participants</TableCaption>
                    <TableHeader className="bg-slate-50 sticky top-0 z-10">
                        <TableRow>
                            <TableHead className="w-[180px] cursor-pointer hover:bg-slate-100" onClick={() => requestSort('name')}>
                                Name <ArrowUpDown className="ml-2 h-3.5 w-3.5 inline-block text-slate-400" />
                            </TableHead>
                            <TableHead className="w-[100px] cursor-pointer hover:bg-slate-100" onClick={() => requestSort('type')}>
                                Type
                            </TableHead>

                            {/* Functional Matrix Columns */}
                            <TableHead className="text-center w-[60px]" title="Regulatory Capability">
                                <Gavel className="h-4 w-4 mx-auto text-slate-500" />
                            </TableHead>
                            <TableHead className="text-center w-[60px]" title="Financial/Funding Capability">
                                <Coins className="h-4 w-4 mx-auto text-slate-500" />
                            </TableHead>
                            <TableHead className="text-center w-[60px]" title="Technical Implementation">
                                <Code2 className="h-4 w-4 mx-auto text-slate-500" />
                            </TableHead>
                            <TableHead className="text-center w-[60px]" title="Contestation/Advocacy">
                                <Megaphone className="h-4 w-4 mx-auto text-slate-500" />
                            </TableHead>

                            <TableHead className="text-right cursor-pointer hover:bg-slate-100" onClick={() => requestSort('metrics.territorialization')}>
                                Terr. <ArrowUpDown className="ml-1 h-3 w-3 inline-block text-slate-400" />
                            </TableHead>
                            <TableHead className="text-right cursor-pointer hover:bg-slate-100" onClick={() => requestSort('metrics.deterritorialization')}>
                                Deterr. <ArrowUpDown className="ml-1 h-3 w-3 inline-block text-slate-400" />
                            </TableHead>
                            <TableHead className="text-right">Link</TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {sortedActors.map((actor) => {
                            const aptitude = getFunctionalAptitude(actor.type);
                            return (
                                <TableRow
                                    key={actor.id}
                                    className={`cursor-pointer transition-colors ${selectedActorId === actor.id ? 'bg-indigo-50 hover:bg-indigo-100' : 'hover:bg-slate-50'} ${actor.source === 'absence_fill' ? 'bg-amber-50/30' : ''}`}
                                    onClick={() => onSelectActor(actor.id)}
                                >
                                    <TableCell className="font-medium py-2">
                                        <div className="flex flex-col">
                                            <span className="truncate max-w-[150px] text-xs font-semibold text-slate-700">{actor.name}</span>
                                            {actor.source === 'absence_fill' && (
                                                <span className="text-[9px] text-amber-600 font-medium">Recovered Check</span>
                                            )}
                                        </div>
                                    </TableCell>
                                    <TableCell className="py-2">
                                        <Badge variant="secondary" className="font-normal text-[10px] px-1.5 h-5">{actor.type}</Badge>
                                    </TableCell>

                                    {/* Functional Matrix Cells */}
                                    <TableCell className="text-center py-2 bg-slate-50/50 border-x border-slate-50">{renderCheck(aptitude.regulatory)}</TableCell>
                                    <TableCell className="text-center py-2 bg-slate-50/50 border-x border-slate-50">{renderCheck(aptitude.fund)}</TableCell>
                                    <TableCell className="text-center py-2 bg-slate-50/50 border-x border-slate-50">{renderCheck(aptitude.implement)}</TableCell>
                                    <TableCell className="text-center py-2 bg-slate-50/50 border-x border-slate-50">{renderCheck(aptitude.contest)}</TableCell>

                                    <TableCell className="text-right py-2">
                                        <Tooltip>
                                            <TooltipTrigger asChild>
                                                <span className="cursor-help decoration-slate-300 underline underline-offset-2 decoration-dotted text-xs text-slate-500 font-mono">
                                                    {formatMetric(actor.metrics?.territorialization)}
                                                </span>
                                            </TooltipTrigger>
                                            <TooltipContent className="max-w-[300px] p-3 text-xs">
                                                <p className="font-semibold mb-2">Territorialization (Stability): {String(actor.metrics?.territorialization)}</p>
                                                {/* Dimensional Breakdown */}
                                                {actor.metrics?.coding !== undefined && (
                                                    <div className="grid grid-cols-2 gap-x-4 gap-y-1 mb-2 text-[10px] text-slate-500">
                                                        <span>Coding:</span><span className="font-mono text-slate-900">{String(actor.metrics.coding)}</span>
                                                        {actor.metrics.centrality !== undefined && (
                                                            <><span>Centrality:</span><span className="font-mono text-slate-900">{String(actor.metrics.centrality)}</span></>
                                                        )}
                                                    </div>
                                                )}
                                            </TooltipContent>
                                        </Tooltip>
                                    </TableCell>
                                    <TableCell className="text-right py-2">
                                        <Tooltip>
                                            <TooltipTrigger asChild>
                                                <span className={`cursor-help decoration-slate-300 underline underline-offset-2 decoration-dotted text-xs font-mono font-bold ${(actor.metrics?.deterritorialization === 'Strong' || (typeof actor.metrics?.deterritorialization === 'number' && actor.metrics.deterritorialization > 6)) ? 'text-red-500' : 'text-slate-400'
                                                    }`}>
                                                    {formatMetric(actor.metrics?.deterritorialization)}
                                                </span>
                                            </TooltipTrigger>
                                            <TooltipContent className="max-w-[300px] p-3 text-xs">
                                                <p className="font-semibold mb-2">Deterritorialization (Change): {actor.metrics?.deterritorialization}</p>
                                                {/* Dimensional Breakdown */}
                                                {actor.metrics?.counter_conduct !== undefined && (
                                                    <div className="grid grid-cols-2 gap-x-4 gap-y-1 mb-2 text-[10px] text-slate-500">
                                                        <span>Counter-Conduct:</span><span className="font-mono text-slate-900">{actor.metrics.counter_conduct}</span>
                                                        <span>Opposition:</span><span className="font-mono text-slate-900">{actor.metrics.discursive_opposition}</span>
                                                    </div>
                                                )}
                                            </TooltipContent>
                                        </Tooltip>
                                    </TableCell>

                                    <TableCell className="text-right py-2">
                                        {actor.url && (
                                            <a href={actor.url} target="_blank" rel="noopener noreferrer" className="inline-flex items-center justify-center h-6 w-6 rounded-full hover:bg-slate-100 text-slate-400 hover:text-indigo-600" onClick={(e) => e.stopPropagation()}>
                                                <ExternalLink className="h-3 w-3" />
                                            </a>
                                        )}
                                    </TableCell>
                                </TableRow>
                            );
                        })}
                    </TableBody>
                </Table>
            </div>
        </TooltipProvider>
    );
}

import React, { memo } from 'react';
import { Button } from '@/components/ui/button';
import { Network, Layers, ZoomIn, Maximize, Minimize, MessageSquare, EyeOff } from 'lucide-react';
import { AssemblageSuggester } from './AssemblageSuggester';
import { VisualGuideDialog } from './VisualGuideDialog';
import { EcosystemActor, EcosystemConfiguration } from '@/types/ecosystem';

interface EcosystemToolbarProps {
    extraToolbarContent?: React.ReactNode;
    is3DMode: boolean;
    setIs3DMode: () => void;
    setIsStratumMode: () => void;
    isStratumMode: boolean;
    reduceMotion: boolean;
    setReduceMotion: () => void;
    isMetricMode: boolean;
    setLayoutMode: () => void;
    isReadOnly: boolean;
    isExplaining: boolean;
    handleExplainMap: () => void;
    explanation: any; // We can refine this type if needed
    isFullScreen: boolean;
    toggleFullScreen: () => void;
    tracedActorId: string | null;
    setTracedActorId: (id: string | null) => void;
    isPresentationMode: boolean;
    setIsPresentationMode: () => void;
    actors: EcosystemActor[];
    links: any[]; // Using any[] to match usage, ideally strict type
    configurations: EcosystemConfiguration[];
    onCreateAssemblage: (name: string, members: string[]) => void;
    resetZoom: () => void;
    // [NEW] Visual Filters
    showUnverifiedLinks?: boolean;
    onToggleUnverified?: () => void;
    linkClassFilter?: 'all' | 'mediator' | 'intermediary';
    onCycleClassFilter?: () => void;
    // [NEW] Directory View
    isAssociationDirectoryOpen?: boolean;
    onToggleAssociationDirectory?: () => void;
}

export const EcosystemToolbar = memo(function EcosystemToolbar({
    extraToolbarContent,
    is3DMode,
    setIs3DMode,
    setIsStratumMode,
    isStratumMode,
    reduceMotion,
    setReduceMotion,
    isMetricMode,
    setLayoutMode,
    isReadOnly,
    isExplaining,
    handleExplainMap,
    explanation,
    isFullScreen,
    toggleFullScreen,
    tracedActorId,
    setTracedActorId,
    isPresentationMode,
    setIsPresentationMode,
    actors,
    links,
    configurations,
    onCreateAssemblage,
    resetZoom,
    showUnverifiedLinks,
    onToggleUnverified,
    linkClassFilter = 'all',
    onCycleClassFilter,
    isAssociationDirectoryOpen = false,
    onToggleAssociationDirectory
}: EcosystemToolbarProps) {
    return (
        <div className="flex items-center gap-1.5 bg-slate-50 p-1 rounded-md border border-slate-200 overflow-x-auto max-w-full pb-1">
            {extraToolbarContent}
            {extraToolbarContent && <div className="w-px h-3 bg-slate-300 mx-0.5 shrink-0" />}

            <Button
                variant="ghost" size="sm"
                onClick={setIs3DMode}
                className={`h-7 px-2.5 text-xs font-medium shrink-0 ${is3DMode ? "bg-indigo-600 text-white hover:bg-indigo-700 shadow-sm" : "text-slate-500 hover:text-slate-900"}`}
            >
                <Network className="h-3 w-3 mr-1" /> {is3DMode ? "Toggle 2D View" : "Toggle 3D View"}
            </Button>

            {/* Accessibility / Perf Toggle (Reduce Motion) */}
            {is3DMode && (
                <>
                    <div className="w-px h-3 bg-slate-300 mx-0.5 shrink-0" />
                    <Button
                        variant="ghost" size="sm"
                        onClick={setReduceMotion}
                        className={`h-7 px-2.5 text-xs font-medium shrink-0 ${reduceMotion ? "bg-indigo-50 text-indigo-700 border border-indigo-200" : "text-slate-500 hover:text-slate-900"}`}
                        title="Disable intense animations (Jitter, Particles)"
                    >
                        {reduceMotion ? "Motion Reduced" : "Reduce Motion"}
                    </Button>
                </>
            )}

            {!is3DMode && (
                <>
                    <div className="w-px h-3 bg-slate-300 mx-0.5 shrink-0" />
                    <Button
                        variant="ghost" size="sm"
                        className={`h-7 px-2.5 text-xs font-medium shrink-0 ${isMetricMode ? "bg-indigo-50 text-indigo-700 border border-indigo-200" : "text-slate-500 hover:text-slate-900"}`}
                        onClick={setLayoutMode}
                    >
                        <Layers className="h-3 w-3 mr-1" /> {isMetricMode ? "Switch to Nested" : "Assemblage Compass"}
                    </Button>
                    <div className="w-px h-3 bg-slate-300 mx-0.5 shrink-0" />

                    {!isReadOnly && (
                        <AssemblageSuggester
                            actors={actors}
                            edges={links}
                            configurations={configurations}
                            onCreateAssemblage={onCreateAssemblage}
                        />
                    )}
                    <div className="w-px h-3 bg-slate-300 mx-0.5 shrink-0" />
                    <Button
                        variant="ghost" size="sm"
                        className="h-7 px-2.5 text-xs font-medium text-slate-500 hover:text-slate-900 shrink-0"
                        onClick={resetZoom}
                    >
                        <ZoomIn className="h-3 w-3 mr-1" /> Reset View
                    </Button>
                </>
            )}

            <div className="w-px h-3 bg-slate-300 mx-0.5 shrink-0" />

            {/* [NEW] Association Directory Toggle */}
            {onToggleAssociationDirectory && (
                <>
                    <Button
                        variant="ghost" size="sm"
                        onClick={onToggleAssociationDirectory}
                        className={`h-7 px-2.5 text-xs font-medium shrink-0 ${isAssociationDirectoryOpen ? "bg-indigo-50 text-indigo-700 border border-indigo-200" : "text-slate-500 hover:text-slate-900"}`}
                        title="Open Association Directory"
                    >
                        <Network className="h-3 w-3 mr-1" /> {isAssociationDirectoryOpen ? "Close Directory" : "Directory"}
                    </Button>
                    <div className="w-px h-3 bg-slate-300 mx-0.5 shrink-0" />
                </>
            )}

            {/* ANT Workbench Controls */}
            {tracedActorId && (
                <Button
                    variant="destructive" size="sm"
                    className="h-7 px-2.5 text-xs font-medium shrink-0 animate-in fade-in"
                    onClick={() => setTracedActorId(null)}
                >
                    <EyeOff className="h-3 w-3 mr-1" /> Exit Trace
                </Button>
            )}

            {is3DMode && (
                <>
                    <div className="w-px h-3 bg-slate-300 mx-0.5 shrink-0" />
                    <Button
                        variant="ghost" size="sm"
                        onClick={setIsStratumMode}
                        className={`h-7 px-2.5 text-xs font-medium shrink-0 ${isStratumMode ? "bg-indigo-50 text-indigo-700 border border-indigo-200" : "text-slate-500 hover:text-slate-900"}`}
                        title="Visualize Law as a Stratum over the Meshwork"
                    >
                        <Layers className="h-3 w-3 mr-1" /> {isStratumMode ? "Stratum Active" : "Legal Stratum"}
                    </Button>
                    <div className="w-px h-3 bg-slate-300 mx-0.5 shrink-0" />
                    <Button
                        variant="ghost" size="sm"
                        onClick={setIsPresentationMode}
                        className={`h-7 px-2.5 text-xs font-medium shrink-0 ${isPresentationMode ? "bg-purple-50 text-purple-700 border border-purple-200 shadow-sm" : "text-slate-500 hover:text-slate-900"}`}
                        title="Toggle Presentation Mode: Bloom, Fog, Curved Links"
                    >
                        {isPresentationMode ? "✨ Presentation Mode" : "🔬 Research Mode"}
                    </Button>
                    {/* Class Filter Cycle */}
                    {onCycleClassFilter && (
                        <>
                            <div className="w-px h-3 bg-slate-300 mx-0.5 shrink-0" />
                            <Button
                                variant="ghost" size="sm"
                                onClick={onCycleClassFilter}
                                className={`h-7 px-2.5 text-xs font-medium shrink-0 ${linkClassFilter !== 'all' ? "bg-blue-50 text-blue-700 border border-blue-200" : "text-slate-600 hover:bg-slate-100 border border-transparent"}`}
                                title="Filter analyzed links by classification"
                            >
                                {linkClassFilter === 'all' ? "All Types" :
                                    linkClassFilter === 'mediator' ? "Mediators" :
                                        "Intermediaries"}
                            </Button>
                        </>
                    )}
                    <div className="w-px h-3 bg-slate-300 mx-0.5 shrink-0" />
                    <Button
                        variant="ghost" size="sm"
                        onClick={onToggleUnverified}
                        className={`h-7 px-2.5 text-xs font-medium shrink-0 ${showUnverifiedLinks ? "bg-amber-50 text-amber-700 border border-amber-200" : "text-slate-500 hover:text-slate-900"}`}
                        title="Show/Hide unanalyzed relationships"
                    >
                        {showUnverifiedLinks ? "Show All Links" : "Filtered View"}
                    </Button>
                </>
            )}

            <div className="w-px h-3 bg-slate-300 mx-0.5 shrink-0" />

            <Button
                variant="ghost"
                size="sm"
                className={`h-7 px-2.5 text-xs font-medium shrink-0 ${isExplaining || explanation ? "bg-indigo-50 text-indigo-700" : "text-slate-500 hover:text-slate-900"}`}
                onClick={handleExplainMap}
                disabled={isReadOnly}
                title={isReadOnly ? "Trace analysis disabled in Demo Mode" : "Generate AI Analysis of current view"}
            >
                <MessageSquare className="h-3 w-3 mr-1.5" />
                {isExplaining ? "Tracing..." : "Open Trace"}
            </Button>

            <div className="w-px h-3 bg-slate-300 mx-0.5 shrink-0" />

            <Button
                variant="ghost" size="sm"
                className={`h-7 px-2.5 text-xs font-medium shrink-0 ${isFullScreen ? "bg-red-50 text-red-600" : "text-slate-500 hover:text-slate-900"}`}
                onClick={toggleFullScreen}
            >
                {isFullScreen ? (
                    <><Minimize className="h-3 w-3 mr-1" /> Exit Full Screen</>
                ) : (
                    <><Maximize className="h-3 w-3 mr-1" /> Full Screen</>
                )}
            </Button>
            <VisualGuideDialog />
        </div>
    );
});

import * as THREE from 'three';
import { Relationship, getMediatorClassification } from '@/types/relationship';

import { EcosystemActor } from '@/types/ecosystem';
import { NodeViz, LinkViz } from '@/lib/viz-contract';

// --- VISUAL CONSTANTS (User Defined) ---
const PALETTE = {
    strong_intermediary: 0x64748B, // Slate-500
    weak_intermediary: 0x94A3B8,   // Slate-400
    weak_mediator: 0xFB923C,       // Orange-400
    strong_mediator: 0xEF4444      // Red-500
};

const THICKNESS = {
    strong_intermediary: 1,
    weak_intermediary: 2,
    weak_mediator: 3,
    strong_mediator: 5 // Thick
};

const CURVATURE = {
    strong_intermediary: 0,
    weak_intermediary: 0.2,
    weak_mediator: 0.5,
    strong_mediator: 0.8 // High wobble
};

// --- Shared Types ---
export interface GraphNode {
    id: string;
    name: string;
    type: string;
    val: number;
    color: string;
    isConfiguration: boolean;
    x?: number;
    y?: number;
    z?: number;
    fz?: number; // Stratum Z target
    actor?: EcosystemActor;
    viz?: NodeViz;
}

export interface GraphLink {
    source: string | GraphNode;
    target: string | GraphNode;
    type: string;
    viz?: LinkViz;
    analysis?: Relationship;
}

export interface NodeUserData {
    isJitterTarget?: boolean;
    jitterMagnitude?: number;
    heat?: number;
    baseColor?: string;
}

// --- FACTORY FUNCTIONS ---

export function createTextSprite(text: string, color: string, fontSize: number = 24) {
    if (typeof document === 'undefined') return new THREE.Mesh();

    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d');
    if (!context) return new THREE.Mesh();

    const font = `Bold ${fontSize}px Inter, sans-serif`;
    context.font = font;
    const metrics = context.measureText(text);
    const textWidth = metrics.width;

    canvas.width = textWidth + 20;
    canvas.height = fontSize + 20;

    context.font = font;
    context.globalAlpha = 0.65;
    context.fillStyle = color;
    context.beginPath();
    context.roundRect(0, 0, canvas.width, canvas.height, 10);
    context.fill();
    context.globalAlpha = 1.0;

    context.fillStyle = 'white';
    context.textAlign = 'center';
    context.textBaseline = 'middle';
    context.fillText(text, canvas.width / 2, canvas.height / 2);

    const texture = new THREE.CanvasTexture(canvas);
    const material = new THREE.SpriteMaterial({ map: texture, transparent: true });
    const sprite = new THREE.Sprite(material);

    sprite.scale.set(textWidth / 4, (fontSize + 10) / 4, 1);
    return sprite;
}

export function createNodeObject(node: GraphNode): THREE.Object3D {
    if (node.isConfiguration) return createTextSprite(node.name, node.color);

    if (!node.viz) return new THREE.Mesh(new THREE.SphereGeometry(2), new THREE.MeshBasicMaterial({ color: '#ccc' }));

    const viz = node.viz;
    let geometry: THREE.BufferGeometry;
    if (viz.roleType === 'Material') {
        geometry = new THREE.BoxGeometry(node.val, node.val, node.val);
    } else if (viz.roleType === 'Expressive') {
        geometry = new THREE.IcosahedronGeometry(node.val / 1.5, 0);
    } else {
        geometry = new THREE.SphereGeometry(node.val / 2, 16, 16);
    }

    const roughness = 1 - (viz.territorialization * 0.8);
    const materialParams: THREE.MeshStandardMaterialParameters = {
        color: node.color,
        roughness: roughness,
        metalness: 0.2,
        emissive: viz.ethicalRisk > 0.4 ? 0xff0000 : 0x000000,
        emissiveIntensity: viz.ethicalRisk > 0.4 ? (viz.ethicalRisk * 5) : 0,
        transparent: true,
        opacity: Math.max(0.3, viz.confidence),
        wireframe: viz.isGhost
    };

    if (viz.hasMissingMetrics) {
        if (typeof document !== 'undefined') {
            const canvas = document.createElement('canvas');
            canvas.width = 64; canvas.height = 64;
            const ctx = canvas.getContext('2d');
            if (ctx) {
                ctx.fillStyle = '#ffffff'; ctx.fillRect(0, 0, 64, 64);
                ctx.fillStyle = '#000000'; ctx.globalAlpha = 0.3;
                for (let i = -64; i < 128; i += 16) {
                    ctx.beginPath(); ctx.moveTo(i, 0); ctx.lineTo(i + 64, 64); ctx.lineWidth = 4; ctx.stroke();
                }
            }
            const texture = new THREE.CanvasTexture(canvas);
            materialParams.map = texture;
            materialParams.bumpMap = texture;
            materialParams.bumpScale = 0.5;
            materialParams.color = new THREE.Color(node.color).offsetHSL(0, 0, 0.1);
        }
    }

    const material = new THREE.MeshStandardMaterial(materialParams);
    const mesh = new THREE.Mesh(geometry, material);
    mesh.userData = {
        isJitterTarget: true,
        jitterMagnitude: viz.deterritorialization,
        heat: viz.heat,
        baseColor: node.color
    };

    const group = new THREE.Group();
    group.add(mesh);

    if (viz.isProvisional && !viz.isGhost) {
        const wiregeo = new THREE.WireframeGeometry(geometry);
        const wiremat = new THREE.LineBasicMaterial({ color: 0xffffff, transparent: true, opacity: 0.3 });
        const wireframe = new THREE.LineSegments(wiregeo, wiremat);
        group.add(wireframe);
    }

    return group;
}

export function createLinkGeometry(link: GraphLink) {
    // Group to hold Tube/Line + (Optional) Particles
    const group = new THREE.Group();

    // Determine Pattern Type & Base Colors
    const flowType = link.viz?.flowType || (link as any).flow_type || (link.type === 'ghost' ? 'ghost' : 'logic');

    // Evaluate if we should override with Mediator Score (Only for thickness/particles, colors stay fixed to Flow Legend)
    let classification = 'weak_intermediary';
    let opacity = 0.5;
    let thicknessMultiplier = 1;

    if (link.analysis) {
        classification = link.analysis.classification || getMediatorClassification(link.analysis.mediatorScore);
        thicknessMultiplier = (THICKNESS[classification as keyof typeof THICKNESS] || 2) * 0.5;
        // Intermediaries (0-0.5 score) are subtle, Mediators (0.5-1.0) are bold
        opacity = classification.includes('intermediary') ? 0.4 : 0.8;
    }

    // 1. Core Geometry & Material Selection based on Flow Type
    let mesh: THREE.Mesh | THREE.Line;
    const curvature = CURVATURE[classification as keyof typeof CURVATURE] || 0.2;

    if (flowType === 'power') {
        // [SOLID RED TUBE] - Power Flow
        const tubeColor = 0xEF4444; // Red-500
        const tubeGeo = new THREE.TubeGeometry(
            new THREE.CatmullRomCurve3([new THREE.Vector3(0, 0, 0), new THREE.Vector3(1, 1, 1)]),
            20,
            thicknessMultiplier * 0.5,
            8,
            false
        );
        const material = new THREE.MeshStandardMaterial({
            color: tubeColor,
            transparent: true,
            opacity: Math.max(opacity, 0.6),
            emissive: tubeColor,
            emissiveIntensity: 0.4
        });
        mesh = new THREE.Mesh(tubeGeo, material);
        mesh.userData = { isLinkMesh: true, curvature, flowType: 'power', baseColor: tubeColor };
        group.add(mesh);

        // Always attach a particle to Power forces to indicate Direction
        const particleGeo = new THREE.BufferGeometry();
        particleGeo.setAttribute('position', new THREE.BufferAttribute(new Float32Array([0, 0, 0]), 3));
        particleGeo.setAttribute('offset', new THREE.BufferAttribute(new Float32Array([Math.random()]), 1));
        const particleMat = new THREE.PointsMaterial({ color: 0xffaaaa, size: Math.max(2, thicknessMultiplier * 1.5), sizeAttenuation: true });
        const particles = new THREE.Points(particleGeo, particleMat);
        particles.userData = { isParticleSystem: true, speed: 0.6, isDirected: true };
        group.add(particles);

    } else if (flowType === 'ghost') {
        // [TRANSLUCENT INDIGO TUBE] - Absent/Ghost Flow
        // Switched from THREE.Line to THREE.TubeGeometry for guaranteed hardware visibility
        const tubeColor = 0x6366F1; // Indigo-500
        const tubeGeo = new THREE.TubeGeometry(
            new THREE.CatmullRomCurve3([new THREE.Vector3(0, 0, 0), new THREE.Vector3(1, 1, 1)]),
            20,
            Math.max(0.3, thicknessMultiplier * 0.4), // Thinner than power
            8,
            false
        );
        const ghostMaterial = new THREE.MeshStandardMaterial({
            color: tubeColor,
            transparent: true,
            opacity: Math.max(opacity, 0.4),
            emissive: tubeColor,
            emissiveIntensity: 0.6,
            wireframe: true // Gives a 'virtual' dotted appearance securely
        });
        mesh = new THREE.Mesh(tubeGeo, ghostMaterial);
        mesh.userData = { isLinkMesh: true, curvature: 0.1, flowType: 'ghost', baseColor: tubeColor };
        group.add(mesh);
    } else {
        // [DASHED AMBER LINE] - Logic Flow (Default)
        const lineColor = 0xF59E0B; // Amber-500
        const points = [new THREE.Vector3(0, 0, 0), new THREE.Vector3(1, 1, 1)];
        const lineGeo = new THREE.BufferGeometry().setFromPoints(points);
        const logicMaterial = new THREE.LineDashedMaterial({
            color: lineColor,
            linewidth: Math.max(1, thicknessMultiplier),
            transparent: true,
            opacity: Math.max(opacity, 0.5),
            dashSize: 4, // Long dash
            gapSize: 4   // Standard gap = Dashed
        });
        mesh = new THREE.Line(lineGeo, logicMaterial);
        mesh.userData = { isLinkLine: true, curvature, flowType: 'logic', baseColor: lineColor };
        group.add(mesh);
    }

    // 2. Extra Mediator Particles (Only for strong structural Logic/Ghost links, since Power already gets a directional dot)
    if (classification.includes('mediator') && flowType !== 'power') {
        const particleCount = classification === 'strong_mediator' ? 8 : 3;
        const particleGeo = new THREE.BufferGeometry();
        const positions = new Float32Array(particleCount * 3);
        const offsets = new Float32Array(particleCount);

        for (let i = 0; i < particleCount; i++) {
            offsets[i] = Math.random();
            positions[i * 3] = 0;
            positions[i * 3 + 1] = 0;
            positions[i * 3 + 2] = 0;
        }

        particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
        particleGeo.setAttribute('offset', new THREE.BufferAttribute(offsets, 1));

        const particleMat = new THREE.PointsMaterial({
            color: classification === 'strong_mediator' ? 0xffea00 : 0xffffff,
            size: classification === 'strong_mediator' ? 2 : 1.5,
            sizeAttenuation: true
        });

        const particles = new THREE.Points(particleGeo, particleMat);
        particles.userData = {
            isParticleSystem: true,
            speed: classification === 'strong_mediator' ? 0.8 : 0.4,
            turbulence: classification === 'strong_mediator'
        };
        group.add(particles);
    }

    return group;
}

export function updateLinkPosition(
    object: THREE.Object3D,
    start: { x: number, y: number, z: number },
    end: { x: number, y: number, z: number },
    link?: GraphLink
) {
    if (!start || !end) return;

    const group = object as THREE.Group;
    const mainGeometryChild = group.children.find(c => c.userData.isLinkMesh || c.userData.isLinkLine) as THREE.Mesh | THREE.Line;

    // Safety check
    if (!mainGeometryChild) return;

    // [NEW] Dynamic Visual Update
    if (link && link.analysis && mainGeometryChild.userData.baseColor) {
        const rel = link.analysis;
        const classification = rel.classification || getMediatorClassification(rel.mediatorScore);

        // Ensure flow_type colors (Power/Logic/Ghost) are strictly maintained when overridden by updates
        const targetColor = new THREE.Color(mainGeometryChild.userData.baseColor);

        // Check if we need to update material properties
        const mat = mainGeometryChild.material as THREE.Material & { color?: THREE.Color; emissive?: THREE.Color; opacity: number };
        const targetOpacity = Math.max(classification.includes('intermediary') ? 0.9 : 0.7, 0.6);

        if (mat.color && (!mat.color.equals(targetColor) || mat.opacity !== targetOpacity)) {
            mat.color.copy(targetColor);
            if (mat.emissive) mat.emissive.copy(targetColor);
            mat.opacity = targetOpacity;

            // Update curvature property based on relation strength
            const targetCurvature = CURVATURE[classification as keyof typeof CURVATURE] || 0.2;
            if (mainGeometryChild.userData.curvature !== targetCurvature && mainGeometryChild.userData.flowType !== 'ghost') {
                mainGeometryChild.userData.curvature = targetCurvature;
            }
        }
    }

    const startV = new THREE.Vector3(start.x, start.y, start.z);
    const endV = new THREE.Vector3(end.x, end.y, end.z);
    const midV = new THREE.Vector3().addVectors(startV, endV).multiplyScalar(0.5);

    // Apply Curvature (Perpendicular offset)
    if (mainGeometryChild.userData.curvature > 0) {
        const dist = startV.distanceTo(endV);
        const dir = new THREE.Vector3().subVectors(endV, startV).normalize();

        // Arbitrary perpendicular vector
        const up = new THREE.Vector3(0, 1, 0);
        let perp = new THREE.Vector3().crossVectors(dir, up);
        if (perp.lengthSq() < 0.001) {
            perp = new THREE.Vector3().crossVectors(dir, new THREE.Vector3(1, 0, 0));
        }
        perp.normalize();

        // Wobble for Strong Mediators
        let wobble = 0;
        if (mainGeometryChild.userData.curvature > 0.6) {
            const time = Date.now() * 0.002;
            wobble = Math.sin(time) * 2; // subtle wave
        }

        midV.add(perp.multiplyScalar(dist * mainGeometryChild.userData.curvature * 0.2 + wobble));
    }

    const curve = new THREE.CatmullRomCurve3([startV, midV, endV]);

    // Store curve in group for particle animation systems
    group.userData.curve = curve;

    // Use dynamic radius based on analysis if available (for Tube)
    let targetRadius = 0.5;
    if (link && link.analysis) {
        const classification = link.analysis.classification || getMediatorClassification(link.analysis.mediatorScore);
        targetRadius = (THICKNESS[classification as keyof typeof THICKNESS] || 2) * 0.5;
    }

    // Update the geometry based on the type of WebGL object (Tube vs DashedLine)
    if (mainGeometryChild.userData.isLinkMesh && mainGeometryChild instanceof THREE.Mesh) {
        // [SOLID POWER FLOW] Re-generate Tube
        const newGeo = new THREE.TubeGeometry(curve, 20, targetRadius, 8, false);
        mainGeometryChild.geometry.dispose();
        mainGeometryChild.geometry = newGeo;
    } else if (mainGeometryChild.userData.isLinkLine && mainGeometryChild instanceof THREE.Line) {
        // [DASHED LOGIC/GHOST FLOW] Sample curve points and generate Line
        const points = curve.getPoints(20);
        mainGeometryChild.geometry.dispose();

        const newGeo = new THREE.BufferGeometry().setFromPoints(points);
        mainGeometryChild.geometry = newGeo;

        // Crucial for Dashed/Dotted Materials to render gap intervals natively on GPU
        mainGeometryChild.computeLineDistances();
    }
}

// [NEW] Animation Loop Helper
export function animateLinkParticles(scene: THREE.Scene, time: number) {
    scene.traverse((object) => {
        if (object.userData && object.userData.isParticleSystem) {
            const particles = object as THREE.Points;
            const group = particles.parent;
            if (group && group.userData.curve) {
                const curve = group.userData.curve as THREE.Curve<THREE.Vector3>;
                const speed = (particles.userData.speed || 0.4) * 0.5; // Adjusted speed

                const positions = particles.geometry.attributes.position.array as Float32Array;
                const offsets = particles.geometry.attributes.offset.array as Float32Array;
                const count = offsets.length;

                const t = time * 0.001 * speed;
                const point = new THREE.Vector3();

                for (let i = 0; i < count; i++) {
                    const progress = (offsets[i] + t) % 1;
                    curve.getPoint(progress, point);
                    positions[i * 3] = point.x;
                    positions[i * 3 + 1] = point.y;
                    positions[i * 3 + 2] = point.z;
                }

                particles.geometry.attributes.position.needsUpdate = true;
            }
        }
    });
}

import React, { useState } from 'react';
import { EcosystemActor } from '@/types/ecosystem';
import { NodeViz } from '@/lib/viz-contract';
import { X, Pin, FileText, Activity, History, Share2, ExternalLink } from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import { getBiasIntensity } from '@/lib/ecosystem-utils';

interface OverlayDetailsProps {
    node: EcosystemActor;
    viz: NodeViz;
    onClose: () => void;
    onPin: () => void;
    isPinned: boolean;
    neighbors?: { name: string; type: string; relation: string }[]; // Simplified neighbor data
}

type Tab = 'summary' | 'evidence' | 'history' | 'network';

export function OverlayDetails({ node, viz, onClose, onPin, isPinned, neighbors = [] }: OverlayDetailsProps) {
    const [activeTab, setActiveTab] = useState<Tab>('summary');

    // Metrics for display
    const metrics = [
        { label: 'Stability (Territorialization)', value: viz.territorialization, color: 'bg-emerald-500' },
        { label: 'Mutation (Deterritorialization)', value: viz.deterritorialization, color: 'bg-amber-500' },
        { label: 'Rigidity (Coding)', value: viz.coding, color: 'bg-blue-500' },
    ];

    return (
        <div className="absolute top-8 right-8 w-80 bg-white/98 backdrop-blur-xl shadow-2xl border border-slate-200 rounded-2xl overflow-hidden flex flex-col max-h-[720px] animate-in slide-in-from-right-10 duration-500 z-[200]">
            {/* Header */}
            <div className="p-4 border-b border-slate-100 bg-slate-50/50 flex justify-between items-start">
                <div>
                    <div className="flex items-center gap-2 mb-1">
                        <h2 className="font-bold text-slate-900 leading-tight">{node.name}</h2>
                        {viz.isProvisional && (
                            <Badge variant="outline" className="text-[10px] h-4 px-1 border-dashed border-slate-400 text-slate-500">
                                Provisional
                            </Badge>
                        )}
                    </div>
                    <div className="flex gap-2">
                        <Badge variant="secondary" className="text-[10px] h-5 bg-slate-100 text-slate-600 font-normal">
                            {node.type}
                        </Badge>
                        <Badge variant="outline" className="text-[10px] h-5 border-slate-200 text-slate-500 font-normal">
                            {viz.roleType}
                        </Badge>
                    </div>
                </div>
                <div className="flex gap-1">
                    <button onClick={onPin} className={`p-1.5 rounded-md transition-colors ${isPinned ? 'bg-indigo-100 text-indigo-600' : 'text-slate-400 hover:text-slate-600 hover:bg-slate-100'}`}>
                        <Pin className="h-4 w-4" />
                    </button>
                    <button onClick={onClose} className="p-1.5 rounded-md text-slate-400 hover:text-slate-600 hover:bg-slate-100 transition-colors">
                        <X className="h-4 w-4" />
                    </button>
                </div>
            </div>

            {/* Tabs */}
            <div className="flex border-b border-slate-200">
                <TabButton active={activeTab === 'summary'} onClick={() => setActiveTab('summary')} icon={Activity} label="Summary" />
                <TabButton active={activeTab === 'evidence'} onClick={() => setActiveTab('evidence')} icon={FileText} label="Evidence" />
                <TabButton active={activeTab === 'history'} onClick={() => setActiveTab('history')} icon={History} label="History" />
                <TabButton active={activeTab === 'network'} onClick={() => setActiveTab('network')} icon={Share2} label="Network" />
            </div>

            {/* Content Body */}
            <div className="p-4 overflow-y-auto min-h-[200px] flex-1">
                {activeTab === 'summary' && (
                    <div className="space-y-4">
                        {/* Bias Warning */}
                        {viz.ethicalRisk > 0.6 && (
                            <div className="p-3 bg-red-50 border border-red-100 rounded-md">
                                <h4 className="text-xs font-bold text-red-700 mb-1 flex items-center gap-1">
                                    <Activity className="h-3 w-3" /> High Bias Risk Detected
                                </h4>
                                <p className="text-[10px] text-red-600 leading-snug">
                                    High structural resistance combined with low legitimacy. Monitor for exclusionary effects.
                                </p>
                            </div>
                        )}

                        {/* Metric Bars */}
                        <div className="space-y-3">
                            {metrics.map((m) => (
                                <div key={m.label}>
                                    <div className="flex justify-between mb-1">
                                        <span className="text-[10px] font-medium text-slate-500 uppercase tracking-wide">{m.label}</span>
                                        <span className="text-[10px] font-bold text-slate-700">{Math.round(m.value * 100)}%</span>
                                    </div>
                                    <div className="h-1.5 bg-slate-100 rounded-full overflow-hidden">
                                        <div className={`h-full ${m.color}`} style={{ width: `${m.value * 100}%` }} />
                                    </div>
                                </div>
                            ))}
                        </div>

                        {/* Source Links */}
                        {node.url && (
                            <div className="pt-2 border-t border-slate-100 mt-2">
                                <a href={node.url} target="_blank" rel="noopener noreferrer" className="flex items-center text-xs text-indigo-600 hover:underline gap-1">
                                    Visit Official Source <ExternalLink className="h-3 w-3" />
                                </a>
                            </div>
                        )}
                    </div>
                )}

                {activeTab === 'evidence' && (
                    <div className="space-y-3">
                        {node.quotes && node.quotes.length > 0 ? (
                            node.quotes.map((quote, i) => (
                                <blockquote key={i} className="text-xs italic text-slate-600 border-l-2 border-indigo-200 pl-3 py-1">
                                    &quot;{quote}&quot;
                                </blockquote>
                            ))
                        ) : (
                            <div className="text-center py-8 text-slate-400 text-xs">
                                No direct quotes captured. Evidence inferred from network structure.
                            </div>
                        )}

                        {node.trace_metadata && (
                            <div className="mt-4 pt-3 border-t border-slate-100">
                                <h4 className="text-[10px] font-bold text-slate-400 uppercase mb-2">Provenance</h4>
                                <div className="text-xs text-slate-600 space-y-2">
                                    {node.trace_metadata.evidence && (
                                        <div className="bg-amber-50/50 p-2 rounded border border-amber-100/50 mb-2">
                                            <p className="text-[10px] text-amber-800 font-semibold uppercase mb-1">Analytical Evidence</p>
                                            <p>{node.trace_metadata.evidence}</p>
                                        </div>
                                    )}
                                    <p>Method: <span className="font-medium capitalize">{node.trace_metadata.source.replace('_', ' ')}</span></p>
                                    <p>Reliability: <span className="font-medium">{Math.round(node.trace_metadata.confidence * 100)}%</span></p>
                                </div>
                            </div>
                        )}
                    </div>
                )}

                {activeTab === 'history' && (
                    <div className="space-y-4">
                        {node.reflexive_log && node.reflexive_log.length > 0 ? (
                            <div className="relative border-l border-slate-200 ml-2 space-y-6">
                                {node.reflexive_log.map((log) => (
                                    <div key={log.id} className="relative pl-4">
                                        <div className="absolute -left-1.5 top-1.5 h-3 w-3 rounded-full border-2 border-white bg-indigo-500 shadow-sm" />
                                        <div className="text-[10px] text-slate-400 mb-0.5">
                                            {new Date(log.timestamp).toLocaleDateString()}
                                        </div>
                                        <div className="text-xs font-medium text-slate-800">
                                            {log.action_type.replace(/_/g, " ")}
                                        </div>
                                        <div className="text-[11px] text-slate-600 mt-1 italic">
                                            "{log.rationale}"
                                        </div>
                                    </div>
                                ))}
                            </div>
                        ) : (
                            <div className="text-center py-8 text-slate-400 text-xs">
                                No reflexive modifications recorded for this actor.
                            </div>
                        )}
                    </div>
                )}

                {activeTab === 'network' && (
                    <div className="space-y-2">
                        <h4 className="text-[10px] font-bold text-slate-400 uppercase mb-2">Connected Actors</h4>
                        {neighbors.length > 0 ? (
                            <ul className="space-y-1">
                                {neighbors.map((n, i) => (
                                    <li key={i} className="flex items-center justify-between text-xs p-2 bg-slate-50 rounded border border-slate-100">
                                        <span className="font-medium text-slate-700">{n.name}</span>
                                        <span className="text-[10px] text-slate-400">{n.relation}</span>
                                    </li>
                                ))}
                            </ul>
                        ) : (
                            <p className="text-xs text-slate-500">No active connections in current view.</p>
                        )}
                    </div>
                )}
            </div>

            {/* Footer hint */}
            <div className="p-2 border-t border-slate-100 bg-slate-50 text-[10px] text-center text-slate-400">
                {isPinned ? "Pinned: Click unpin to close" : "Click Pin icon to keep open"}
            </div>
        </div>
    );
}

function TabButton({ active, onClick, icon: Icon, label }: { active: boolean, onClick: () => void, icon: any, label: string }) {
    return (
        <button
            onClick={onClick}
            className={`flex-1 flex items-center justify-center gap-1.5 py-2.5 text-[10px] font-medium transition-colors border-b-2 ${active
                ? 'border-indigo-600 text-indigo-600 bg-indigo-50/10'
                : 'border-transparent text-slate-500 hover:text-slate-800 hover:bg-slate-50'
                }`}
        >
            <Icon className="h-3 w-3" />
            {label}
        </button>
    );
}

import React, { useState } from 'react';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Textarea } from '@/components/ui/textarea';
import { ProvisionalInscription } from '@/types/provisional';
import { FragilityIndicator } from '@/components/ui/provisional-badge';
import { CheckCircle2, AlertTriangle, MessageSquarePlus, ShieldAlert } from 'lucide-react';

interface RatificationControlsProps {
    inscription: ProvisionalInscription;
    onRatify: () => void;
    onContest: (interpretation: string, basis: string) => void;
}

export function RatificationControls({ inscription, onRatify, onContest }: RatificationControlsProps) {
    const [isContesting, setIsContesting] = useState(false);
    const [altInterpretation, setAltInterpretation] = useState("");
    const [theoreticalBasis, setTheoreticalBasis] = useState("");

    const isRatified = inscription.source === "user_validated";

    const handleContestSubmit = () => {
        if (!altInterpretation.trim()) return;
        onContest(altInterpretation, theoreticalBasis);
        setIsContesting(false);
        setAltInterpretation("");
        setTheoreticalBasis("");
    };

    return (
        <Card className="border-l-4 border-l-yellow-400 bg-yellow-50/30">
            <CardHeader className="pb-2">
                <CardTitle className="text-sm font-bold flex items-center justify-between text-slate-800">
                    <div className="flex items-center gap-2">
                        <ShieldAlert className="h-4 w-4 text-yellow-600" />
                        Epistemic Status: {inscription.fragility_score.interpretation.toUpperCase()}
                    </div>
                    {isRatified && (
                        <Badge variant="outline" className="bg-green-100 text-green-700 border-green-200 gap-1">
                            <CheckCircle2 className="h-3 w-3" /> Ratified
                        </Badge>
                    )}
                </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
                <div className="flex items-center gap-4">
                    <FragilityIndicator score={inscription.fragility_score} className="flex-1" />
                    {!isRatified && (
                        <Button size="sm" onClick={onRatify} className="bg-green-600 hover:bg-green-700 text-white h-7 text-xs">
                            <CheckCircle2 className="h-3 w-3 mr-1" />
                            Ratify Findings
                        </Button>
                    )}
                </div>

                <div className="text-xs text-slate-600 space-y-2">
                    <p className="font-semibold text-slate-700">Authority Conditions (Requirements for Stability):</p>
                    <ul className="list-disc list-inside space-y-1 pl-1">
                        {inscription.authority_conditions.map((cond, i) => (
                            <li key={i}>{cond}</li>
                        ))}
                    </ul>
                </div>

                {!isContesting ? (
                    <Button
                        variant="outline"
                        size="sm"
                        onClick={() => setIsContesting(true)}
                        className="w-full text-xs border-amber-200 text-amber-700 hover:bg-amber-50 hover:text-amber-800 hover:border-amber-300"
                    >
                        <AlertTriangle className="h-3 w-3 mr-1" />
                        Contest / Add Alternative Interpretation
                    </Button>
                ) : (
                    <div className="space-y-3 bg-white p-3 rounded-md border border-slate-200 animate-in fade-in slide-in-from-top-1">
                        <h4 className="text-xs font-bold flex items-center gap-1">
                            <AlertTriangle className="h-3 w-3 text-amber-500" />
                            Contest this Inscription
                        </h4>
                        <div>
                            <label className="text-[10px] font-bold text-slate-500 uppercase">Alternative Reading</label>
                            <Textarea
                                value={altInterpretation}
                                onChange={(e) => setAltInterpretation(e.target.value)}
                                placeholder="How else could this be interpreted?"
                                className="text-xs min-h-[60px]"
                            />
                        </div>
                        <div>
                            <label className="text-[10px] font-bold text-slate-500 uppercase">Theoretical Basis</label>
                            <Textarea
                                value={theoreticalBasis}
                                onChange={(e) => setTheoreticalBasis(e.target.value)}
                                placeholder="e.g., Latour's 'Reassembling the Social', Post-structuralism..."
                                className="text-xs min-h-[40px]"
                            />
                        </div>
                        <div className="flex justify-end gap-2">
                            <Button size="sm" variant="ghost" onClick={() => setIsContesting(false)} className="h-7 text-xs">Cancel</Button>
                            <Button size="sm" onClick={handleContestSubmit} className="h-7 text-xs bg-amber-600 hover:bg-amber-700 text-white">
                                Submit Contest
                            </Button>
                        </div>
                    </div>
                )}

                {inscription.alternative_interpretations && inscription.alternative_interpretations.length > 0 && (
                    <div className="space-y-2 pt-2 border-t border-slate-200/50">
                        <p className="text-[10px] font-bold text-slate-400 uppercase">Recorded Contests</p>
                        {inscription.alternative_interpretations.map((alt, i) => (
                            <div key={i} className="bg-white p-2 text-xs border border-slate-100 rounded shadow-sm">
                                <p className="font-medium text-slate-800">"{alt.interpretation}"</p>
                                <p className="text-[10px] text-slate-500 mt-1 italic">Basis: {alt.theoretical_basis}</p>
                            </div>
                        ))}
                    </div>
                )}
            </CardContent>
        </Card>
    );
}

import React, { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
