interface TranslationChainProps {
    actors?: EcosystemActor[];
    onHoverStage?: (stageId: string | null) => void;
}

export const TranslationChain = React.memo(function TranslationChain({ actors = [], onHoverStage }: TranslationChainProps) {

    // Draggable Logic
    // ... (unchanged) ...
    const [position, setPosition] = React.useState({ x: 0, y: 0 });
    const [isDraggingUI, setIsDraggingUI] = React.useState(false);
    const isDragging = React.useRef(false);
    const dragStart = React.useRef({ x: 0, y: 0 });
    const startPos = React.useRef({ x: 0, y: 0 });

    React.useEffect(() => {
        const handleMouseMove = (e: MouseEvent) => {
            if (!isDragging.current) return;
            const dx = e.clientX - dragStart.current.x;
            const dy = e.clientY - dragStart.current.y;
            setPosition({
                x: startPos.current.x + dx,
                y: startPos.current.y + dy
            });
        };
        const handleMouseUp = () => {
            isDragging.current = false;
            setIsDraggingUI(false);
        };

        window.addEventListener('mousemove', handleMouseMove);
        window.addEventListener('mouseup', handleMouseUp);
        return () => {
            window.removeEventListener('mousemove', handleMouseMove);
            window.removeEventListener('mouseup', handleMouseUp);
        };
    }, []);

    const handleMouseDown = (e: React.MouseEvent) => {
        e.preventDefault();
        e.stopPropagation();
        isDragging.current = true;
        setIsDraggingUI(true);
        dragStart.current = { x: e.clientX, y: e.clientY };
        startPos.current = { ...position };
    };

    // Calculate Presence Live
    const hydratedStages = React.useMemo(() => {
        const { isActorRelevantToStage } = require('@/lib/ecosystem-utils');
        return STAGES_TEMPLATE.map(stage => {
            // Only count actors that are NOT hidden
            const count = actors.filter(a => !a.isHidden && isActorRelevantToStage(a, stage.id)).length;
            return {
                ...stage,
                active_actor_count: count,
                fidelity_score: undefined,
                betrayal_type: undefined
            };
        });
    }, [actors]);

    return (
        <TooltipProvider>
            <Card
                className="absolute bottom-4 left-4 w-[320px] bg-white/95 backdrop-blur-sm shadow-xl border-slate-200 z-20 overflow-hidden"
                style={{
                    transform: `translate(${position.x}px, ${position.y}px)`,
                    transition: isDraggingUI ? 'none' : 'transform 0.1s ease-out',
                    cursor: 'default'
                }}
            >
                <div
                    className="bg-slate-50 px-3 py-2 border-b border-slate-100 flex justify-between items-center cursor-move select-none"
                    onMouseDown={handleMouseDown}
                >
                    <span className="text-[10px] uppercase tracking-wider font-bold text-slate-600">Translation Chain</span>
                    <span className="text-[9px] text-slate-400">Trace Coverage</span>
                </div>
                <div className="p-3 flex flex-col gap-2">
                    {hydratedStages.map((stage, i) => {
                        const count = stage.active_actor_count || 0;
                        const isActive = count > 0;

                        return (
                            <Tooltip key={stage.id} delayDuration={0}>
                                <TooltipTrigger asChild>
                                    <div
                                        className="relative group cursor-pointer"
                                        onMouseEnter={() => onHoverStage?.(stage.id)}
                                        onMouseLeave={() => onHoverStage?.(null)}
                                    >
                                        {/* Connecting Line */}
                                        {i < hydratedStages.length - 1 && (
                                            <div
                                                className={`absolute left-[11px] top-6 bottom-[-8px] w-[2px] z-0 transition-colors ${isActive ? 'bg-slate-300' : 'bg-slate-100'}`}
                                            ></div>
                                        )}

                                        <div className="flex items-start gap-2 relative z-10 text-xs transition-transform group-hover:translate-x-1">
                                            {/* Icon/Dot */}
                                            <div className={`
                                                w-6 h-6 rounded-full flex items-center justify-center shrink-0 border transition-all
                                                ${stage.ontology === 'social' ? 'bg-amber-50 border-amber-200 text-amber-600' : ''}
                                                ${stage.ontology === 'regulatory' ? 'bg-blue-50 border-blue-200 text-blue-600' : ''}
                                                ${stage.ontology === 'technical' ? 'bg-emerald-50 border-emerald-200 text-emerald-600' : ''}
                                                ${stage.ontology === 'market' ? 'bg-purple-50 border-purple-200 text-purple-600' : ''}
                                                ${!isActive ? 'opacity-50 grayscale' : ''}
                                            `}>
                                                <span className="font-mono text-[9px] font-bold">{i + 1}</span>
                                            </div>

                                            {/* Content */}
                                            <div className="flex-1 min-w-0">
                                                <div className="flex justify-between items-start">
                                                    <div className="flex flex-col">
                                                        <span className={`font-semibold leading-tight group-hover:text-indigo-700 ${isActive ? 'text-slate-800' : 'text-slate-400'}`}>{stage.label}</span>
                                                        <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-widest opacity-80">{stage.ant_label}</span>
                                                    </div>
                                                    <div className="flex gap-1">
                                                        {count > 0 && (
                                                            <span className="bg-slate-100 text-slate-600 text-[9px] px-1.5 rounded-full font-mono border border-slate-200">
                                                                {count}
                                                            </span>
                                                        )}
                                                    </div>
                                                </div>
                                                <p className="text-[10px] text-slate-500 leading-tight mt-0.5">{stage.description}</p>
                                            </div>
                                        </div>
                                    </div>
                                </TooltipTrigger>
                                <TooltipContent
                                    side="left"
                                    sideOffset={10}
                                    className="max-w-[260px] bg-slate-900 border-slate-800 text-slate-100 shadow-xl animate-in fade-in slide-in-from-right-8 duration-300"
                                >
                                    <p className="font-semibold mb-1 text-indigo-300">{stage.label}</p>
                                    <p className="text-xs text-slate-300 leading-relaxed">{stage.tooltip}</p>
                                </TooltipContent>
                            </Tooltip>
                        );
                    })}
                </div>
            </Card>
        </TooltipProvider>
    );
});

import React from 'react';
import { RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar, Legend, ResponsiveContainer } from 'recharts';

interface FrameworkRadarProps {
    data: any[];
    labelA: string;
    labelB?: string;
    labelC?: string;
    selectedSourceB?: string;
    selectedSourceC?: string;
}

export function FrameworkRadar({ data, labelA, labelB, labelC, selectedSourceB, selectedSourceC }: FrameworkRadarProps) {
    return (
        <ResponsiveContainer width="100%" height="100%">
            <RadarChart cx="50%" cy="50%" outerRadius="80%" data={data}>
                <PolarGrid />
                <PolarAngleAxis dataKey="dimension" />
                <PolarRadiusAxis angle={30} domain={[0, 100]} />
                <Radar name={labelA} dataKey="A" stroke="#8884d8" fill="#8884d8" fillOpacity={0.6} />
                {selectedSourceB && <Radar name={labelB} dataKey="B" stroke="#82ca9d" fill="#82ca9d" fillOpacity={0.6} />}
                {selectedSourceC && <Radar name={labelC} dataKey="C" stroke="#ffc658" fill="#ffc658" fillOpacity={0.6} />}
                <Legend />
            </RadarChart>
        </ResponsiveContainer>
    );
}

"use client";

import React from 'react';
import { ScatterChart, Scatter, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, ReferenceLine, Label, Cell, LabelList } from 'recharts';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { DriftVector } from '@/lib/governance';

interface GovernanceCompassProps {
    analysis: DriftVector | null;
}

export function GovernanceCompass({ analysis }: GovernanceCompassProps) {
    if (!analysis) {
        return (
            <Card className="h-[500px] flex items-center justify-center bg-slate-50 border-dashed">
                <p className="text-slate-400">Run analysis to generate Governance Compass</p>
            </Card>
        );
    }

    const data = [
        { x: analysis.rhetoric.x, y: analysis.rhetoric.y, name: 'Rhetoric', fill: '#3b82f6' }, // Blue
        { x: analysis.reality.x, y: analysis.reality.y, name: 'Reality', fill: '#0f172a' },   // Black
    ];

    return (
        <Card className="w-full">
            <CardHeader>
                <CardTitle>Governance Drift Compass</CardTitle>
                <CardDescription>
                    Visualizing the gap between ethical rhetoric and technical reality.
                    <br />
                    <span className="text-xs text-slate-500">
                        Drift Magnitude: {analysis.magnitude.toFixed(2)} |
                        X-Shift: {analysis.driftX.toFixed(2)} |
                        Y-Shift: {analysis.driftY.toFixed(2)}
                    </span>
                </CardDescription>
            </CardHeader>
            <CardContent>
                <div className="h-[500px] w-full relative">
                    {/* Background Quadrant Labels */}
                    <div className="absolute top-4 right-4 text-xs font-bold text-emerald-600 bg-emerald-50 px-2 py-1 rounded opacity-80">
                        REGENERATIVE / PARTICIPATORY
                    </div>
                    <div className="absolute bottom-4 left-4 text-xs font-bold text-red-600 bg-red-50 px-2 py-1 rounded opacity-80">
                        EXTRACTIVE / ASYMMETRICAL
                    </div>

                    <ResponsiveContainer width="100%" height="100%">
                        <ScatterChart margin={{ top: 20, right: 20, bottom: 40, left: 80 }}>
                            <CartesianGrid strokeDasharray="3 3" />
                            <XAxis
                                type="number"
                                dataKey="x"
                                name="Power"
                                domain={[-1.2, 1.2]}
                                label={{ value: 'Power: Asymmetrical (-) vs Participatory (+)', position: 'bottom', offset: 0 }}
                            />
                            <YAxis
                                type="number"
                                dataKey="y"
                                name="Value"
                                domain={[-1.2, 1.2]}
                                label={{ value: 'Value: Extractive (-) vs Regenerative (+)', angle: -90, position: 'insideLeft', offset: 10, style: { textAnchor: 'middle' } }}
                            />
                            <ReferenceLine x={0} stroke="#64748b" />
                            <ReferenceLine y={0} stroke="#64748b" />

                            <Tooltip cursor={{ strokeDasharray: '3 3' }} />

                            <Scatter name="Points" data={data} fill="#8884d8">
                                {data.map((entry, index) => (
                                    <Cell key={`cell-${index}`} fill={entry.fill} />
                                ))}
                                <LabelList dataKey="name" position="top" offset={10} style={{ fill: '#64748b', fontSize: '12px', fontWeight: 'bold' }} />
                            </Scatter>
                        </ScatterChart>
                    </ResponsiveContainer>

                    {/* SVG Overlay for the Arrow (Drift Vector) */}
                    {/* Note: Precise overlay requires mapping coordinates to pixels, which is hard with ResponsiveContainer. 
                        For this MVP, we rely on the scatter points. A more advanced version would use a custom SVG layer. */}
                </div>
            </CardContent>
        </Card>
    );
}

