import React, { useState, useRef, useCallback, useEffect } from 'react';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { ChevronRight, ChevronLeft, MapPin, GripHorizontal, Network } from 'lucide-react';
import { StudyCase, StudyState } from '@/lib/study-config';

interface StudyNavigatorProps {
    currentCase: StudyCase | undefined;
    studyState: StudyState;
    onNext: () => void;
    onPrev: () => void;
    onLocateNode: () => void;
    onSave: () => void;
    canAdvance: boolean;
}

export function StudyNavigator({
    currentCase,
    studyState,
    onNext,
    onPrev,
    onLocateNode,
    onSave,
    canAdvance,
}: StudyNavigatorProps) {
    // Drag functionality state
    const [position, setPosition] = useState({ x: 0, y: 0 });
    const dragStartPos = useRef({ x: 0, y: 0 });
    const startElemPos = useRef({ x: 0, y: 0 });

    const handleMouseMove = useCallback((e: MouseEvent) => {
        const dx = e.clientX - dragStartPos.current.x;
        const dy = e.clientY - dragStartPos.current.y;
        setPosition({
            x: startElemPos.current.x + dx,
            y: startElemPos.current.y + dy
        });
    }, []);

    const handleMouseUp = useCallback(() => {
        document.removeEventListener('mousemove', handleMouseMove);
        document.removeEventListener('mouseup', handleMouseUp);
        document.body.style.cursor = 'default';
    }, [handleMouseMove]);

    const handleMouseDown = (e: React.MouseEvent) => {
        if (e.button !== 0) return; // Only left click
        e.preventDefault();

        dragStartPos.current = { x: e.clientX, y: e.clientY };
        startElemPos.current = { ...position };

        document.addEventListener('mousemove', handleMouseMove);
        document.addEventListener('mouseup', handleMouseUp);
        document.body.style.cursor = 'grabbing';
    };

    // Cleanup on unmount
    useEffect(() => {
        return () => {
            document.removeEventListener('mousemove', handleMouseMove);
            document.removeEventListener('mouseup', handleMouseUp);
            document.body.style.cursor = 'default';
        };
    }, [handleMouseMove, handleMouseUp]);


    if (!currentCase) return null;

    const totalCases = studyState.playlist.length;
    const currentCaseNumber = studyState.currentCaseIndex + 1;
    const progressPercent = (currentCaseNumber / totalCases) * 100;

    // Calculate estimated time remaining
    const casesRemaining = totalCases - currentCaseNumber;
    const estTimeRemaining = casesRemaining * 8;

    return (
        <Card
            className="fixed bottom-6 right-6 w-[350px] bg-white shadow-2xl border-t-4 border-t-purple-600 z-50 animate-in slide-in-from-bottom-10 fade-in transition-shadow will-change-transform"
            style={{
                transform: `translate(${position.x}px, ${position.y}px)`,
                // Disable transition during drag for smoothness if needed, but 'transform' is usually fast enough. 
                // However, the initial animation might conflict. 
                // Let's rely on standard transform.
            }}
        >
            <CardContent className="p-4 space-y-4">
                {/* Drag Handle */}
                <div
                    className="flex justify-center -mt-2 -mx-4 py-1 cursor-grab active:cursor-grabbing hover:bg-slate-50 transition-colors group"
                    onMouseDown={handleMouseDown}
                    title="Drag to move"
                >
                    <GripHorizontal className="text-slate-200 group-hover:text-slate-400 h-4 w-4 transition-colors" />
                </div>

                {/* Header / Progress */}
                <div className="space-y-2">
                    <div className="flex justify-between items-center text-sm font-medium text-muted-foreground">
                        <span>Case {currentCaseNumber} of {totalCases}</span>
                        <div className="flex items-center gap-2">
                            <span>Est. Remaining: {estTimeRemaining}m</span>
                            <Button
                                variant="outline"
                                size="sm"
                                className="h-7 px-3 text-xs gap-1.5 border-purple-200 text-purple-700 hover:bg-purple-50"
                                onClick={onSave}
                                title="Save progress to file"
                            >
                                <Network className="h-3 w-3" /> {/* Using Network icon as placeholder, preferably Download/Save if imported */}
                                Save & Resume
                            </Button>
                        </div>
                    </div>
                    {/* Custom Progress Bar since component missing */}
                    <div className="h-2 w-full bg-secondary rounded-full overflow-hidden">
                        <div
                            className="h-full bg-purple-600 transition-all duration-500 ease-in-out"
                            style={{ width: `${progressPercent}%` }}
                        />
                    </div>
                </div>

                {/* Current Case Title */}
                <div>
                    <h3 className="font-bold text-lg leading-tight text-foreground">
                        {currentCase.title}
                    </h3>
                    {currentCase.isCalibration && (
                        <span className="inline-block mt-1 px-2 py-0.5 bg-yellow-100 text-yellow-800 text-xs font-semibold rounded-full">
                            Calibration
                        </span>
                    )}
                </div>

                {/* Controls */}
                <div className="flex items-center gap-2 pt-2">
                    <Button
                        variant="outline"
                        size="icon"
                        onClick={onPrev}
                        disabled={studyState.currentCaseIndex === 0}
                        title="Review Previous Case"
                    >
                        <ChevronLeft className="h-4 w-4" />
                    </Button>

                    <Button
                        variant="default"
                        className="flex-1 bg-purple-600 hover:bg-purple-700 text-white shadow-sm"
                        onClick={onLocateNode}
                        title="Evaluate this case"
                    >
                        <Network className="mr-2 h-4 w-4" />
                        Evaluate Case
                    </Button>

                    <Button
                        onClick={onNext}
                        disabled={!canAdvance}
                        className={!canAdvance ? "opacity-50" : ""}
                        title={canAdvance ? "Go to next case" : "Complete assessment to continue"}
                    >
                        Next
                        <ChevronRight className="ml-2 h-4 w-4" />
                    </Button>
                </div>
            </CardContent>
        </Card>
    );
}

"use client";

import React, { createContext, useContext, useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { StudyCase } from '@/lib/study-config';
import { resolveTargets } from '@/lib/survey/targeting';

export interface FocusModeConfig {
    fieldId: string;
    required: boolean;
    // Follow up prompt for V3 bounds
    requiresBoundedDefinition?: boolean;
}

export interface EvaluationContextValue {
    // Current field pointer
    activeFieldId: string | null;
    setActiveFieldId: (id: string | null) => void;

    // Derived targets
    resolvedTargets: string[];
    isLoadingTargets: boolean;
    targetHint: string | null;
    targetError: string | null;

    // Focus Mode constraints
    focusMode: FocusModeConfig | null;
    setFocusMode: (config: FocusModeConfig | null) => void;

    // Scroller refs
    registerEvidenceRef: (evidenceId: string, element: HTMLElement | null) => void;
    jumpToTarget: (direction?: 'next' | 'first') => void;
}

const EvaluationContext = createContext<EvaluationContextValue | undefined>(undefined);

export function EvaluationProvider({
    children,
    caseData
}: {
    children: React.ReactNode;
    caseData: StudyCase | null;
}) {
    const [activeFieldId, setActiveFieldId] = useState<string | null>(null);
    const [focusMode, setFocusMode] = useState<FocusModeConfig | null>(null);

    // Reset active field and focus mode when case changes
    useEffect(() => {
        setActiveFieldId(null);
        setFocusMode(null);
    }, [caseData?.id]);

    // Derived target state
    const [resolvedTargets, setResolvedTargets] = useState<string[]>([]);
    const [isLoadingTargets, setIsLoadingTargets] = useState(false);
    const [targetHint, setTargetHint] = useState<string | null>(null);
    const [targetError, setTargetError] = useState<string | null>(null);

    const evidenceRefs = useRef<Map<string, HTMLElement>>(new Map());
    const [currentTargetIndex, setCurrentTargetIndex] = useState(0);

    // Resolve targets implicitly when activeField or caseData changes
    useEffect(() => {
        let isMounted = true;
        setCurrentTargetIndex(0); // Reset cycle index on field change

        async function loadTargets() {
            if (!activeFieldId || !caseData) {
                setResolvedTargets([]);
                setTargetHint(null);
                setTargetError(null);
                return;
            }

            setIsLoadingTargets(true);
            setTargetError(null);
            try {
                const { targets, hintText, error } = await resolveTargets(activeFieldId, caseData);
                if (isMounted) {
                    setResolvedTargets(targets || []);
                    setTargetHint(hintText || null);
                    setTargetError(error || null);
                }
            } catch (err) {
                if (isMounted) {
                    setTargetError("Failed to compute evidence boundaries.");
                    setResolvedTargets([]);
                }
            } finally {
                if (isMounted) setIsLoadingTargets(false);
            }
        }

        loadTargets();

        return () => { isMounted = false; };
    }, [activeFieldId, caseData]);

    // Handle reliable scroll tracking
    const registerEvidenceRef = useCallback((evidenceId: string, element: HTMLElement | null) => {
        if (element) {
            evidenceRefs.current.set(evidenceId, element);
        } else {
            evidenceRefs.current.delete(evidenceId);
        }
    }, []);

    const jumpToTarget = useCallback((direction: 'next' | 'first' = 'first') => {
        if (!resolvedTargets.length) return;

        let indexToJump = 0;
        if (direction === 'next' && resolvedTargets.length > 1) {
            indexToJump = (currentTargetIndex + 1) % resolvedTargets.length;
            setCurrentTargetIndex(indexToJump);
        } else {
            setCurrentTargetIndex(0);
        }

        const targetId = resolvedTargets[indexToJump];
        const element = evidenceRefs.current.get(targetId);

        if (element) {
            // Scroll safely within potentially scrollable offset containers
            element.scrollIntoView({ behavior: 'smooth', block: 'center' });

            // Apply a fleeting flash animation for accessibility/attention
            element.animate([
                { backgroundColor: 'rgba(168, 85, 247, 0.4)' }, // purple-500 fading out
                { backgroundColor: 'transparent' }
            ], { duration: 1200, easing: 'ease-out' });
        }
    }, [resolvedTargets, currentTargetIndex]);

    const value = useMemo(() => ({
        activeFieldId,
        setActiveFieldId,
        resolvedTargets,
        isLoadingTargets,
        targetHint,
        targetError,
        focusMode,
        setFocusMode,
        registerEvidenceRef,
        jumpToTarget
    }), [
        activeFieldId,
        resolvedTargets,
        isLoadingTargets,
        targetHint,
        targetError,
        focusMode,
        registerEvidenceRef,
        jumpToTarget
    ]);

    return (
        <EvaluationContext.Provider value={value}>
            {children}
        </EvaluationContext.Provider>
    );
}

export function useEvaluationContext() {
    const context = useContext(EvaluationContext);
    if (context === undefined) {
        throw new Error('useEvaluationContext must be used within an EvaluationProvider');
    }
    return context;
}

import React, { useState } from 'react';
import { GhostNodeSurveyResponse, EvaluationConfig, PerceivedGapSchema, EnforcementEscalationSchema, AnalyticalChallengeSchema, MechanismStepSchema, ImpactCategorySchema } from '@/lib/study-config';
import { setImmutablePath } from '@/lib/survey/path-update';
import { Card, CardContent } from '@/components/ui/card';
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group';
import { Label } from '@/components/ui/label';
import { Slider } from '@/components/ui/slider';
import { Checkbox } from '@/components/ui/checkbox';
import { Button } from '@/components/ui/button';
import { ChevronLeft, ChevronRight, Crosshair, Target, EyeOff, CheckSquare, AlertCircle, Circle, CircleDashed, CheckCircle2, Info } from 'lucide-react';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '@/components/ui/tooltip';
import { useEvaluationContext } from './EvaluationContext';

interface GhostNodeEvaluationFormProps {
    config?: EvaluationConfig;
    initialData?: GhostNodeSurveyResponse;
    surveyTitle?: string;
    onChange: (data: Partial<GhostNodeSurveyResponse>) => void;
}

export function GhostNodeEvaluationForm({ config, initialData, surveyTitle, onChange }: GhostNodeEvaluationFormProps) {
    const title = surveyTitle || "EU AI Act";

    // Default values if no config provided yet
    const safeConfig = config || {
        presenceGateQuestion: "Does the text assign any governance role to Citizens/Public?",
        presenceGateOptions: ["yes", "no", "unsure"],
        disambiguationPrompts: [
            { id: "d1", question: "Consumers vs Public?", options: ["Yes", "No", "Unsure"] }
        ],
        strengthAbsence: { min: 0, max: 100, anchors: [{ value: 0, label: "Not absent" }, { value: 100, label: "Very strong" }] },
        feasibility: { min: 0, max: 100, anchors: [{ value: 0, label: "Not feasible" }, { value: 100, label: "Highly feasible" }], mechanismGateThreshold: 40, mechanismOptions: ["Public Hearings", "Citizen Suit"] }
    };

    let contextVals;
    try {
        contextVals = useEvaluationContext();
    } catch (e) {
        contextVals = null;
    }

    const activeFieldId = contextVals?.activeFieldId || 'presenceGate';
    const setActiveFieldId = contextVals?.setActiveFieldId || (() => { });
    const resolvedTargets = contextVals?.resolvedTargets || [];
    const jumpToTarget = contextVals?.jumpToTarget || (() => { });
    const focusMode = contextVals?.focusMode || null;
    const setFocusMode = contextVals?.setFocusMode || (() => { });
    const isLoadingTargets = contextVals?.isLoadingTargets || false;

    const [expandedMech, setExpandedMech] = useState<string | null>(null);
    const [expandedImpact, setExpandedImpact] = useState<string | null>(null);

    React.useEffect(() => {
        if (!contextVals?.activeFieldId) {
            setActiveFieldId('presenceGate');
        }
    }, [contextVals, setActiveFieldId]);

    const handleAnswer = (field: keyof GhostNodeSurveyResponse, value: unknown) => {
        onChange({ [field]: value });

        // Auto-advance logic for simple radio buttons
        if (field === 'absenceGate' && value !== 'unsure') {
            if (safeConfig.disambiguationPrompts && safeConfig.disambiguationPrompts.length > 0) {
                // If yes/no and there's disambiguation, go there and maybe trigger focus mode
                setActiveFieldId('disambiguation');
                // Optional: trigger focus mode for V3 Quote Extraction on "Yes"
                if (value === 'yes') {
                    setFocusMode({ fieldId: 'v3_exclusionBounding', required: true, requiresBoundedDefinition: true });
                }
            } else {
                setActiveFieldId('strength');
            }
        }
    };

    const handleDisambiguation = (id: string, value: string) => {
        const currentAns = initialData?.disambiguationAnswers || {};
        onChange({ disambiguationAnswers: { ...currentAns, [id]: value } });
    };

    const handlePathAnswer = (path: string, value: any) => {
        const updated = setImmutablePath(initialData || {} as any, path, value);
        // Force version V3 flag on deep update to ensure schema validation aligns
        updated.surveyVersion = 'v3';
        onChange(updated as Partial<GhostNodeSurveyResponse>);
    };

    const v3Data = (initialData || {}) as any; // Cast temporarily to allow flex reading

    const steps = (() => {
        const out = [
            {
                id: 'presenceGate', label: 'Presence',
                completed: (v3Data.absenceGate ? 1 : 0) + (v3Data.absenceGate === 'yes' && v3Data.selectedQuoteId ? 1 : 0),
                total: v3Data.absenceGate === 'yes' ? 2 : 1
            },
            ...(safeConfig.disambiguationPrompts && safeConfig.disambiguationPrompts.length > 0 ? [{
                id: 'disambiguation', label: 'Details',
                completed: Object.keys(v3Data.disambiguationAnswers || {}).length,
                total: safeConfig.disambiguationPrompts.length
            }] : []),
            {
                id: 'strength', label: 'Strength',
                completed: v3Data.strength !== undefined ? 1 : 0,
                total: 1
            },
            {
                id: 'groundingGate', label: 'Grounding',
                completed: v3Data.groundingGate ? 1 : 0,
                total: 1
            },
            {
                id: 'section3', label: `1. ${title}`,
                completed: v3Data.euAiActOmissionAgreement ? 1 : 0,
                total: 1
            },
            {
                id: 'section4', label: '2. Responses',
                completed: v3Data.counterfactualFeasibility ? 1 : 0,
                total: 1
            },
            {
                id: 'section5', label: '3. Impacts',
                completed: v3Data.scenarioConfidence ? 1 : 0,
                total: 1
            },
            {
                id: 'section6', label: '4. Synthesis',
                completed: (v3Data.innovativeIdeas ? 1 : 0) + (v3Data.crossDisciplinaryInsights ? 1 : 0),
                total: 2
            }
        ];
        return out;
    })();

    const currentStepIndex = steps.findIndex(s => s.id === activeFieldId);
    if (currentStepIndex === -1 && steps.length > 0) setActiveFieldId(steps[0].id);

    const goToNext = () => {
        if (currentStepIndex < steps.length - 1) setActiveFieldId(steps[currentStepIndex + 1].id);
    };

    const goToPrev = () => {
        if (currentStepIndex > 0) setActiveFieldId(steps[currentStepIndex - 1].id);
    };

    const JumpControls = () => {
        if (isLoadingTargets) return <span className="text-xs text-purple-600 animate-pulse ml-2 font-medium">Resolving evidence...</span>;
        if (!resolvedTargets.length) return null;

        return (
            <div className="flex items-center gap-2 ml-auto">
                <Button
                    variant="outline"
                    size="sm"
                    className="h-7 text-[11px] gap-1 px-2 border-indigo-200 text-indigo-700 hover:bg-indigo-50"
                    onClick={() => jumpToTarget('first')}
                >
                    <Target className="h-3 w-3" /> Jump to Evidence
