}

import React from 'react';
import { EvidenceQuote } from '@/lib/study-config';
import { Card, CardContent, CardHeader, CardTitle, CardFooter } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Maximize2, ExternalLink } from 'lucide-react';
import { useSources } from '@/hooks/useSources';

import { useRouter } from 'next/navigation';
import { useEvaluationContext } from './EvaluationContext';

interface QuoteCardListProps {
    quotes?: EvidenceQuote[];
    onContextRequest?: (quote: EvidenceQuote) => void;
    onFullDocRequest?: () => void;
    documentLabel?: string;
    highlightedExcerptIds?: string[];
    // Pass the Case ID so we can stably hash targets
    caseId?: string;
    onQuoteSelected?: (quote: EvidenceQuote) => void;
}

export function QuoteCardList({ quotes, onContextRequest, onFullDocRequest, documentLabel, highlightedExcerptIds = [], caseId, onQuoteSelected }: QuoteCardListProps) {
    const { sources } = useSources();

    // Attempt to grab context safely (fallback if rendered outside Provider)
    let contextVals;
    try {
        // eslint-disable-next-line react-hooks/rules-of-hooks
        contextVals = useEvaluationContext();
    } catch (e) {
        contextVals = null;
    }
    const resolvedTargets = contextVals?.resolvedTargets || [];
    const registerEvidenceRef = contextVals?.registerEvidenceRef;
    const focusMode = contextVals?.focusMode;

    if (!quotes || quotes.length === 0) {
        return (
            <div className="p-8 text-center border-2 border-dashed border-slate-300 rounded-lg text-slate-600 bg-slate-50/50">
                <div className="mb-3 text-slate-400 flex justify-center">
                    <Maximize2 className="h-8 w-8 opacity-50" />
                </div>
                <h4 className="font-semibold text-slate-800 mb-2">No quotes extracted for this case</h4>
                <p className="text-sm mb-5 text-slate-500 max-w-md mx-auto leading-relaxed">
                    This may indicate: (a) true absence in excerpts, (b) extraction failure, or (c) excerpt set too narrow.
                </p>
                <div className="flex justify-center gap-3">
                    <Button variant="outline" size="sm" onClick={onFullDocRequest}>
                        <ExternalLink className="h-4 w-4 mr-2 text-slate-400" />
                        Search Full Document
                    </Button>
                    <Button variant="outline" size="sm" className="bg-amber-50 text-amber-700 border-amber-200 hover:bg-amber-100 hover:text-amber-800">
                        Mark Insufficient Evidence
                    </Button>
                </div>
            </div>
        );
    }

    const getSourceName = (id: string, fallback?: string) => {
        const source = sources.find(s => s.id === id);
        return source ? source.title : (fallback || id);
    };

    return (
        <div className="space-y-4">
            <div className="mb-4">
                <h3 className="text-lg font-semibold text-slate-900">Key Quotes (verbatim)</h3>
                <p className="text-sm text-slate-500">These excerpts are exact text from the policy. Use &quot;Open in context&quot; to view surrounding paragraphs.</p>
            </div>
            {quotes.map((quote, i) => {
                const legacyHighlight = highlightedExcerptIds.includes(quote.id);
                // The rigorous target ID defined in our Target Registry
                const targetId = `quote-${caseId}-${i}`;
                const isTargeted = resolvedTargets.includes(targetId);
                const isFocused = focusMode?.required && isTargeted;

                const borderClass = isFocused
                    ? 'border-l-fuchsia-600 ring-4 ring-fuchsia-500/30'
                    : isTargeted
                        ? 'border-l-indigo-600 ring-2 ring-indigo-500/50 transform scale-[1.01]'
                        : legacyHighlight
                            ? 'border-l-indigo-400'
                            : 'border-l-blue-500';

                return (
                    <Card
                        key={quote.id || i}
                        id={targetId}
                        ref={(el) => {
                            if (registerEvidenceRef) registerEvidenceRef(targetId, el);
                        }}
                        className={`border-l-4 shadow-sm overflow-hidden transition-all duration-300 ${borderClass} ${isFocused ? 'bg-fuchsia-50/20' : isTargeted ? 'bg-indigo-50/30' : ''} ${(focusMode && !isTargeted) ? 'opacity-40 grayscale-[50%]' : ''}`}
                    >
                        <CardHeader className={`border-b py-3 px-4 ${(isTargeted || isFocused) ? 'bg-indigo-100/50' : 'bg-slate-50'}`}>
                            <CardTitle className="text-sm font-semibold text-slate-800">
                                {quote.heading || "Excerpt"}
                                {legacyHighlight && <Badge variant="secondary" className="ml-2 bg-indigo-200 text-indigo-800 text-[10px]">Grounded Claim Reference</Badge>}
                            </CardTitle>
                        </CardHeader>
                        <CardContent className={`p-4 ${legacyHighlight ? 'bg-transparent' : 'bg-white'}`}>
                            <blockquote className="font-mono text-sm text-slate-700 whitespace-pre-wrap border-l-2 border-slate-200 pl-3">
                                {quote.text}
                            </blockquote>
                        </CardContent>
                        <CardFooter className="bg-slate-50 border-t py-3 px-4 flex flex-col items-start gap-3 sm:flex-row sm:items-center sm:justify-between">
                            <div className="flex flex-col gap-2">
                                <div className="text-xs font-medium text-slate-500">
                                    Source: {getSourceName(quote.sourceRef.docId, documentLabel)} {quote.sourceRef.section ? `• ${quote.sourceRef.section}` : ''} {quote.sourceRef.paragraph ? `• ${quote.sourceRef.paragraph}` : ''}
                                </div>
                                <div className="flex flex-wrap gap-1">
                                    {quote.actorTags.map(tag => (
                                        <Badge key={`actor-${tag}`} variant="outline" className="bg-indigo-50 text-indigo-700 border-indigo-200 text-[10px] uppercase">
                                            {tag}
                                        </Badge>
                                    ))}
                                    {quote.mechanismTags.map(tag => (
                                        <Badge key={`mech-${tag}`} variant="outline" className="bg-emerald-50 text-emerald-700 border-emerald-200 text-[10px] uppercase">
                                            {tag}
                                        </Badge>
                                    ))}
                                </div>
                            </div>
                            <div className="flex flex-col sm:flex-row items-center gap-2 w-full sm:w-auto mt-2 sm:mt-0">
                                {isFocused && onQuoteSelected && (
                                    <Button
                                        variant="default"
                                        size="sm"
                                        className="w-full sm:w-auto h-8 text-xs gap-1 bg-fuchsia-600 hover:bg-fuchsia-700 animate-pulse"
                                        onClick={() => onQuoteSelected(quote)}
                                    >
                                        Select as Evidence
                                    </Button>
                                )}
                                <Button
                                    variant="outline"
                                    size="sm"
                                    className="w-full sm:w-auto h-8 text-xs gap-1"
                                    onClick={() => onContextRequest && onContextRequest(quote)}
                                >
                                    <Maximize2 className="h-3 w-3" /> Context
                                </Button>
                                <Button
                                    variant="outline"
                                    size="sm"
                                    className="w-full sm:w-auto h-8 text-xs gap-1"
                                    onClick={() => onFullDocRequest && onFullDocRequest()}
                                >
                                    <ExternalLink className="h-3 w-3" /> Full Doc
                                </Button>
                            </div>
                        </CardFooter>
                    </Card>
                );
            })}
        </div>
    );
}

import React from 'react';
import { Sheet, SheetContent, SheetHeader, SheetTitle, SheetDescription } from '@/components/ui/sheet';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Search, Loader2 } from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import { useSources } from '@/hooks/useSources';


interface SearchDrawerProps {
    isOpen: boolean;
    onClose: () => void;
    searchChips?: string[];
    initialQuery?: string;
    documentId: string;
}

export function SearchDrawer({ isOpen, onClose, searchChips, initialQuery, documentId }: SearchDrawerProps) {
    const [query, setQuery] = React.useState(initialQuery || '');
    const [isSearching, setIsSearching] = React.useState(false);
    const [hasSearched, setHasSearched] = React.useState(false);

    const { sources } = useSources();
    const source = sources.find(s => s.id === documentId);
    const documentText = source?.extractedText || '';

    React.useEffect(() => {
        if (isOpen) {
            setQuery(initialQuery || '');
            setHasSearched(!!initialQuery);
        }
    }, [isOpen, initialQuery]);

    const handleSearch = (e: React.FormEvent) => {
        e.preventDefault();
        setIsSearching(true);
        setTimeout(() => {
            setIsSearching(false);
            setHasSearched(true);
        }, 300);
    };

    // Simple text search, split by paragraphs
    const paragraphs = documentText.split(/\n\s*\n/).filter(p => p.trim());

    const searchResults = React.useMemo(() => {
        if (!query.trim()) return paragraphs; // return all paragraphs if no query

        const lowerQuery = query.toLowerCase();
        return paragraphs.filter(p => p.toLowerCase().includes(lowerQuery));
    }, [query, paragraphs]);

    return (
        <Sheet open={isOpen} onOpenChange={onClose}>
            <SheetContent side="right" className="sm:max-w-md w-[400px] flex flex-col h-full bg-white p-6 shadow-2xl border-l border-slate-200">
                <SheetHeader className="mb-6 shrink-0">
                    <SheetTitle>Search Document</SheetTitle>
                    <SheetDescription>
                        Search the full policy document to verify contextual absences.
                    </SheetDescription>
                </SheetHeader>

                <form onSubmit={handleSearch} className="flex gap-2 mb-6 shrink-0 z-10 relative">
                    <Input
                        placeholder="Search for terms... (leave empty for full text)"
                        value={query}
                        onChange={(e) => setQuery(e.target.value)}
                        className="flex-1"
                    />
                    <Button type="submit" disabled={isSearching}>
                        {isSearching ? <Loader2 className="h-4 w-4 animate-spin" /> : <Search className="h-4 w-4" />}
                    </Button>
                </form>

                {searchChips && searchChips.length > 0 && (
                    <div className="mb-8">
                        <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-3">Suggested Terms</h4>
                        <div className="flex flex-wrap gap-2">
                            {searchChips.map(chip => (
                                <Badge
                                    key={chip}
                                    variant="secondary"
                                    className="cursor-pointer hover:bg-slate-200 transition-colors"
                                    onClick={() => {
                                        setQuery(chip);
                                        // Auto trigger search
                                        setIsSearching(true);
                                        setTimeout(() => {
                                            setIsSearching(false);
                                            setHasSearched(true);
                                        }, 400);
                                    }}
                                >
                                    {chip}
                                </Badge>
                            ))}
                        </div>
                    </div>
                )}

                {(hasSearched || !query) && !isSearching && (
                    <div className="flex-1 overflow-hidden flex flex-col min-h-0 bg-slate-50/50 rounded-lg border border-slate-200 p-2 gap-2 mt-4 shadow-inner">
                        <div className="p-3 bg-white rounded flex justify-between items-center shrink-0 shadow-sm border border-slate-100">
                            <p className="text-sm text-slate-600 font-medium">
                                {query.trim() ? `Found ${searchResults.length} occurrences in text` : `Full Document View`}
                            </p>
                            {!query.trim() && (
                                <p className="text-xs text-slate-400">{paragraphs.length} paragraphs</p>
                            )}
                        </div>

                        <div className="flex-1 overflow-y-auto rounded bg-white shadow-sm border border-slate-100 p-4 relative isolate custom-scrollbar">
                            {searchResults.length > 0 ? (
                                <div className="space-y-6 pb-6 pr-2">
                                    {searchResults.map((p, idx) => {
                                        // Highlight query if exists
                                        if (query.trim()) {
                                            const parts = p.split(new RegExp(`(${query})`, 'gi'));
                                            return (
                                                <p key={idx} className="text-sm text-slate-700 leading-relaxed pb-4 border-b border-slate-50 last:border-0">
                                                    {parts.map((part, i) =>
                                                        part.toLowerCase() === query.toLowerCase() ?
                                                            <mark key={i} className="bg-yellow-200 text-slate-900 font-medium py-0.5 px-1 rounded-sm">{part}</mark> : part
                                                    )}
                                                </p>
                                            );
                                        }
                                        return (
                                            <p key={idx} className="text-sm text-slate-700 leading-relaxed pb-4 border-b border-slate-50 last:border-0">
                                                {p}
                                            </p>
                                        );
                                    })}
                                </div>
                            ) : (
                                <div className="text-center py-10 text-slate-400 text-sm">
                                    No textual evidence found matching "{query}"
                                </div>
                            )}
                        </div>
                    </div>
                )}
            </SheetContent>
        </Sheet>
    );
}

import React, { useState } from 'react';
import { Card, CardHeader, CardTitle, CardContent, CardFooter } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Loader2, ShieldAlert, CheckCircle2, AlertTriangle, BookOpen, Brain, Info } from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import type { StructuralConcernResult } from '@/lib/structural-concern-service';

interface StructuralAnalysisCardProps {
    actorName: string;
    excerptCount: number;
    result: StructuralConcernResult | null;
    challengedResult?: StructuralConcernResult | null;
    escalation?: any;
    onHighlightExcerpts?: (excerptIds: string[]) => void;
    onGenerate?: () => void;
    isGenerating?: boolean;
}

export function StructuralAnalysisCard({
    actorName,
    excerptCount,
    result,
    challengedResult,
    escalation,
    onHighlightExcerpts,
    onGenerate,
    isGenerating
}: StructuralAnalysisCardProps) {
    const [hoveredClaimIdx, setHoveredClaimIdx] = useState<number | null>(null);

    const handleMouseEnter = (claimIdx: number, excerptIds: string[]) => {
        setHoveredClaimIdx(claimIdx);
        if (onHighlightExcerpts) onHighlightExcerpts(excerptIds);
    };

    const handleMouseLeave = () => {
        setHoveredClaimIdx(null);
        if (onHighlightExcerpts) onHighlightExcerpts([]);
    };

    if (!result) {
        if (onGenerate) {
            return (
                <Card className="border border-slate-200 shadow-sm mt-6 overflow-hidden bg-white">
                    <CardHeader className="pb-4 border-b bg-slate-50/80">
                        <div className="flex items-center justify-between">
                            <CardTitle className="text-base font-semibold text-slate-900 flex items-center gap-2">
                                <BookOpen className="h-4 w-4 text-indigo-600" />
                                Structural Concern Mapping
                            </CardTitle>
                        </div>
                    </CardHeader>
                    <CardContent className="p-8 flex flex-col items-center justify-center text-center">
                        <Brain className="h-8 w-8 text-slate-300 mb-3" />
                        <h4 className="text-sm font-semibold text-slate-700 mb-1">No Structural Analysis Available</h4>
                        <p className="text-xs text-slate-500 mb-4 max-w-xs">
                            Generate an AI analysis to see if this actor's absence is a structural concern based on the provided excerpts.
                        </p>
                        <Button
                            variant="outline"
                            size="sm"
                            className="text-xs bg-indigo-50 border-indigo-200 text-indigo-700 hover:bg-indigo-100"
                            onClick={onGenerate}
                            disabled={isGenerating}
                        >
                            {isGenerating ? (
                                <><Loader2 className="h-3 w-3 mr-2 animate-spin" /> Analyzing Excerpts...</>
                            ) : (
                                <><Brain className="h-3 w-3 mr-2" /> Run Structural Analysis</>
                            )}
                        </Button>
                    </CardContent>
                </Card>
            );
        }
        return null;
    }

    // Signal-name to human-readable label mapping
    const signalLabels: Record<string, string> = {
        noGovernanceMechanism: 'Governance Mechanism',
        noParticipationRule: 'Participation Rule',
        noBoundedForum: 'Bounded Forum',
        noOPPAccessInfo: 'OPP Access Info',
        noExclusionLanguage: 'Exclusion Language',
        noActorBoundaryLanguage: 'Actor Boundary Language'
    };

    // Scoped diagnostic messaging based on evidenceScope
    if (result?.evidenceScope === 'impact_only' || (result?.insufficientEvidence && !result?.evidenceScope)) {
        const isImpactOnly = result?.evidenceScope === 'impact_only';
        const missing = (result as any)?.missingSignals as string[] || [];
        const present = (result as any)?.signalsPresent as string[] || [];

        return (
            <Card className={`border shadow-sm mt-6 ${isImpactOnly ? 'border-slate-200 bg-slate-50/50' : 'border-amber-200 bg-amber-50'}`}>
                <CardHeader className={`pb-3 border-b ${isImpactOnly ? 'border-slate-100 bg-white/50' : 'border-amber-100 bg-white/50'}`}>
                    <CardTitle className={`text-sm font-semibold flex items-center gap-2 ${isImpactOnly ? 'text-slate-700' : 'text-amber-900'}`}>
                        {isImpactOnly ? (
                            <BookOpen className="h-4 w-4 text-slate-500" />
                        ) : (
                            <AlertTriangle className="h-4 w-4 text-amber-600" />
                        )}
                        {isImpactOnly
                            ? 'Mentioned as Affected — Governance Standing Unproven'
                            : 'Insufficient Excerpt Signal'}
                    </CardTitle>
                </CardHeader>
                <CardContent className={`p-5 text-sm leading-relaxed ${isImpactOnly ? 'text-slate-600' : 'text-amber-800'}`}>
                    {result.thesis && <p className="mb-3">{result.thesis}</p>}
                    {isImpactOnly ? (
                        <p className="text-xs text-slate-500">No governance roles, OPPs, or participation rules appear in the provided excerpts.</p>
                    ) : (
                        <p className="text-xs text-slate-500">Try expanding the excerpt window or adding governance sections (roles, committees, enforcement).</p>
                    )}
                    {/* Diagnostic pills for missing signals */}
                    {missing.length > 0 && (
                        <div className="mt-3 pt-3 border-t border-slate-200/60">
                            <p className="text-[10px] uppercase tracking-wider text-slate-400 font-semibold mb-1.5">Missing</p>
                            <div className="flex flex-wrap gap-1.5">
                                {missing.map(s => (
                                    <Badge key={s} variant="outline" className="text-[10px] border-slate-200 text-slate-500 bg-white">
                                        {signalLabels[s] || s.replace(/^no/, '').replace(/([A-Z])/g, ' $1').trim()}
                                    </Badge>
                                ))}
                            </div>
                        </div>
                    )}
                    {/* Show what WAS found */}
                    {present.length > 0 && (
                        <div className="mt-2">
                            <p className="text-[10px] uppercase tracking-wider text-slate-400 font-semibold mb-1.5">Found</p>
                            <div className="flex flex-wrap gap-1.5">
                                {present.map(s => (
                                    <Badge key={s} variant="outline" className="text-[10px] border-emerald-200 text-emerald-600 bg-emerald-50/50">
                                        {s.replace(/([A-Z])/g, ' $1').trim()}
                                    </Badge>
                                ))}
                            </div>
                        </div>
                    )}
                    {/* UI label explaining why anti-structural challenge is skipped */}
                    {isImpactOnly && (
                        <div className="mt-4 flex items-start gap-2 bg-slate-50/80 p-3 rounded-md border border-slate-200 shadow-sm">
                            <Info className="h-4 w-4 text-slate-400 shrink-0 mt-0.5" />
                            <p className="text-[11px] text-slate-500 leading-snug">
                                <strong className="text-slate-600 block mb-0.5 text-xs">Anti-Structural Challenge Skipped</strong>
                                Since there are no governance signals to establish a base structural exclusion, the pipeline skips the opposing challenge phase.
                            </p>
                        </div>
                    )}
                </CardContent>
            </Card>
        );
    }

    const validClaims = result?.claims || [];

    const getLogicColor = (logic: string) => {
        switch (logic) {
            case 'role-allocation': return 'bg-emerald-100 text-emerald-800 border-emerald-200';
            case 'categorical boundary': return 'bg-violet-100 text-violet-800 border-violet-200';
            case 'procedural participation': return 'bg-sky-100 text-sky-800 border-sky-200';
            case 'silencing / omission': return 'bg-rose-100 text-rose-800 border-rose-200';
            case 'external reference-only': return 'bg-amber-100 text-amber-800 border-amber-200';
            default: return 'bg-slate-100 text-slate-800 border-slate-200';
        }
    };

    const highlightQuotes = (text: string) => {
        if (!text) return text;
        const parts = text.split(/(["“”''].*?["“”''])/g);
        return parts.map((part, i) => {
            if (/^["“”''].*["“”'']$/.test(part)) {
                return (
                    <span key={i} className="bg-indigo-50 text-indigo-700 px-1 rounded-sm font-medium">
                        {part}
                    </span>
                );
            }
            return <span key={i}>{part}</span>;
        });
    };

    const cleanEscalationText = (text: string) => {
        if (!text) return text;
        // Strip raw excerpt IDs (like q-ghost-[hash], [uuid], etc.) that the LLM might have outputted.
        // Matches (q-ghost-abcd...), (ghost-abcd...), q-abcd..., or just abcd... if it's a long UUID/hash.
        return text
            .replace(/\(?(?:q-)?(?:ghost-)?[a-fA-F0-9\-]{30,}\)?/g, '[Excerpt]')
            .replace(/\[Excerpt\](?:,\s*\[Excerpt\])+/g, '[Excerpts]');
    };

    return (
        <Card className="border border-slate-200 shadow-sm mt-6 overflow-hidden bg-white">
            <CardHeader className="pb-4 border-b bg-slate-50/80">
                <div className="flex items-center justify-between">
                    <div>
                        <CardTitle className="text-base font-semibold text-slate-900 flex items-center gap-2">
                            <BookOpen className="h-4 w-4 text-indigo-600" />
                            Structural Concern Mapping
                        </CardTitle>
                        <p className="text-xs text-slate-500 mt-1">
                            Analyzed strictly from <strong>{excerptCount} excerpts</strong> for {actorName}
                        </p>
                    </div>
                </div>
            </CardHeader>
            <CardContent className="p-0">
                {/* Thesis Statement */}
                {result?.thesis && (
                    <div className="p-5 bg-indigo-50/50 border-b border-indigo-100">
                        <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-wider mb-2 flex items-center gap-1.5">
                            <CheckCircle2 className="h-3.5 w-3.5" />
                            Net Effect / Thesis
                        </h4>
                        <p className="text-sm text-indigo-950 font-medium leading-relaxed">
                            {highlightQuotes(result.thesis)}
                        </p>
                    </div>
                )}

                {/* Claims List */}
                <div className="divide-y divide-slate-100">
                    {validClaims.map((claim, idx) => (
                        <div
                            key={idx}
                            className={`p-5 transition-colors ${hoveredClaimIdx === idx ? 'bg-slate-50' : 'bg-white'}`}
                            onMouseEnter={() => handleMouseEnter(idx, claim.supportedBy)}
                            onMouseLeave={handleMouseLeave}
                        >
                            <div className="flex items-start justify-between gap-4 mb-3">
                                <h4 className="text-sm font-semibold text-slate-800">
                                    {idx + 1}. {claim.sectionTitle}
                                </h4>
                                <Badge variant="outline" className={`text-[10px] whitespace-nowrap ${getLogicColor(claim.logicType)}`}>
                                    {claim.logicType.replace(/-/g, ' ')}
                                </Badge>
                            </div>
                            <p className="text-sm text-slate-600 leading-relaxed mb-4">
                                {highlightQuotes(claim.claimText)}
                            </p>

                            {/* Grounding Context */}
                            <div className="flex items-center gap-2">
                                <Badge variant="secondary" className="bg-slate-100 text-slate-500 text-[10px] uppercase font-semibold">
                                    Grounded In
                                </Badge>
                                <span className="text-xs text-slate-500 font-mono">
                                    {claim.supportedBy.length} Excerpt{claim.supportedBy.length === 1 ? '' : 's'}
                                </span>
                            </div>
                        </div>
                    ))}
                </div>

                {/* Challenged Results Section */}
                {challengedResult && (
                    <div className="border-t-2 border-dashed border-indigo-200 bg-purple-50/30">
                        <div className="p-4 bg-purple-100/50 border-b border-purple-100 flex items-center gap-2">
                            <ShieldAlert className="h-4 w-4 text-purple-700" />
                            <h3 className="font-semibold text-purple-900 text-sm">Anti-Structural Concern Findings</h3>
                        </div>
                        {challengedResult.thesis && (
                            <div className="p-5 border-b border-purple-100/50">
                                <h4 className="text-xs font-bold text-purple-600 uppercase tracking-wider mb-2 flex items-center gap-1.5">
                                    <CheckCircle2 className="h-3.5 w-3.5" />
                                    Net Effect / Challenge Thesis
                                </h4>
                                <p className="text-sm text-purple-950 font-medium leading-relaxed">
                                    {highlightQuotes(challengedResult.thesis)}
                                </p>
                            </div>
                        )}
                        <div className="divide-y divide-purple-100/50">
                            {challengedResult.claims?.map((claim, idx) => (
                                <div
                                    key={`challenge-${idx}`}
                                    className="p-5 bg-transparent"
                                >
                                    <div className="flex items-start justify-between gap-4 mb-3">
                                        <h4 className="text-sm font-semibold text-slate-800">
                                            {idx + 1}. {claim.sectionTitle}
                                        </h4>
                                        <Badge variant="outline" className={`text-[10px] whitespace-nowrap border-purple-200 text-purple-700 bg-purple-50/50`}>
                                            {claim.logicType.replace(/-/g, ' ')}
                                        </Badge>
                                    </div>
                                    <p className="text-sm text-slate-600 leading-relaxed mb-4">
                                        {highlightQuotes(claim.claimText)}
                                    </p>
                                </div>
                            ))}
                        </div>
                    </div>
                )}
                {escalation && (
                    <div className="border-t-2 border-indigo-300 bg-slate-50">
                        <div className="p-4 bg-slate-100 border-b flex items-center gap-2">
                            <Brain className="h-4 w-4 text-slate-700" />
                            <h3 className="font-semibold text-slate-900 text-sm">AI Evidence Synthesis</h3>
                        </div>
                        <div className="p-5 space-y-4">
                            <div>
                                <h4 className="text-xs font-bold text-slate-600 uppercase tracking-wider mb-2">AI Takeaway</h4>
                                <Badge variant={escalation.verdict === 'pro_stronger' ? 'destructive' : escalation.verdict === 'anti_stronger' ? 'default' : 'secondary'}>
                                    {escalation.verdict === 'pro_stronger' ? 'Seems to lean toward exclusion' : escalation.verdict === 'anti_stronger' ? 'Seems to lean toward inclusion' : 'Hard to say for sure'}
                                </Badge>
                            </div>
                            <div>
                                <h4 className="text-xs font-bold text-slate-600 uppercase tracking-wider mb-2">Reasoning & Context</h4>
                                <p className="text-sm text-slate-800 leading-relaxed italic">{cleanEscalationText(escalation.methodologicalCritique.notes)}</p>
                            </div>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mt-4 pt-4 border-t border-slate-200">
                                <div>
                                    <h4 className="text-xs font-bold text-emerald-700 uppercase tracking-wider mb-2 flex items-center gap-1.5"><CheckCircle2 className="h-3.5 w-3.5" /> Tier 1: Proven</h4>
                                    <p className="text-sm text-slate-700">{cleanEscalationText(escalation.tier1Proven.text)}</p>
                                </div>
                                <div>
                                    <h4 className="text-xs font-bold text-amber-700 uppercase tracking-wider mb-2 flex items-center gap-1.5">
                                        <AlertTriangle className="h-3.5 w-3.5" />
                                        {result?.evidenceScope === 'impact_only' ? 'Tier 2: Affected — Standing Unproven' : 'Tier 2: Mentioned — Standing Unproven'}
                                    </h4>
                                    <p className="text-sm text-slate-700">{cleanEscalationText(escalation.tier2Unproven.text)}</p>
                                </div>
                            </div>
                        </div>
                    </div>
                )}
            </CardContent>
            <CardFooter className="bg-slate-50 border-t py-3 px-5 flex flex-col gap-2">
                <div className="w-full text-xs text-slate-400 flex items-center justify-between">
                    <span>AI-generated formal mapping based solely on provided quote text.</span>
                    <span>{validClaims.length} structural points proved.</span>
                </div>
                {/* Gaps disclosure for successful analyses */}
                {(result as any)?.missingSignals?.length > 0 && (
                    <div className="w-full flex items-center gap-2 text-[10px]">
                        <span className="text-slate-400 uppercase tracking-wider font-semibold shrink-0">Gaps</span>
                        <div className="flex flex-wrap gap-1">
                            {((result as any).missingSignals as string[]).map(s => (
                                <Badge key={s} variant="outline" className="text-[9px] border-slate-200 text-slate-400 bg-white py-0 px-1.5">
                                    {signalLabels[s] || s.replace(/^no/, '').replace(/([A-Z])/g, ' $1').trim()}
                                </Badge>
                            ))}
                        </div>
                    </div>
                )}
            </CardFooter>
        </Card >
    );
}

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from "@/components/ui/dialog";
import { Plus } from "lucide-react";

interface AddDocumentDialogProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    onAdd: (title: string, description: string, pageCount: string, publicationDate: string, version: string) => void;
}

export function AddDocumentDialog({ open, onOpenChange, onAdd }: AddDocumentDialogProps) {
    const [newSource, setNewSource] = useState({
        title: "",
        description: "",
        pageCount: "",
        publicationDate: "",
        version: ""
    });

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onAdd(newSource.title, newSource.description, newSource.pageCount, newSource.publicationDate, newSource.version);
        setNewSource({ title: "", description: "", pageCount: "", publicationDate: "", version: "" });
        onOpenChange(false);
    };

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>

            <DialogContent className="sm:max-w-[500px]">
                <DialogHeader>
                    <DialogTitle>Add New Policy Document</DialogTitle>
                    <DialogDescription>
                        Add a policy document manually or upload a PDF.
                    </DialogDescription>
                </DialogHeader>
                <form onSubmit={handleSubmit}>
                    <div className="grid gap-4 py-4">
                        <div className="grid grid-cols-4 items-center gap-4">
                            <Label htmlFor="title" className="text-right">
                                Title
                            </Label>
                            <Input
                                id="title"
                                value={newSource.title}
                                onChange={(e) => setNewSource({ ...newSource, title: e.target.value })}
                                className="col-span-3"
                                required
                                placeholder="e.g., EU AI Act"
                            />
                        </div>
                        <div className="grid grid-cols-4 items-center gap-4">
                            <Label htmlFor="description" className="text-right">
                                Description
                            </Label>
                            <Input
                                id="description"
                                value={newSource.description}
                                onChange={(e) => setNewSource({ ...newSource, description: e.target.value })}
                                className="col-span-3"
                                required
                                placeholder="e.g., Official Journal Version"
                            />
                        </div>
                        <div className="grid grid-cols-4 items-center gap-4">
                            <Label htmlFor="pages" className="text-right">
                                Pages
                            </Label>
                            <Input
                                id="pages"
                                type="number"
                                value={newSource.pageCount}
                                onChange={(e) => setNewSource({ ...newSource, pageCount: e.target.value })}
                                className="col-span-3"
                            />
                        </div>
                        <div className="grid grid-cols-4 items-center gap-4">
                            <Label htmlFor="date" className="text-right">
                                Date
                            </Label>
                            <Input
                                id="date"
                                type="date"
                                value={newSource.publicationDate}
                                onChange={(e) => setNewSource({ ...newSource, publicationDate: e.target.value })}
                                className="col-span-3"
                            />
                        </div>
                        <div className="grid grid-cols-4 items-center gap-4">
                            <Label htmlFor="version" className="text-right">
                                Version
                            </Label>
                            <Input
                                id="version"
                                value={newSource.version}
                                onChange={(e) => setNewSource({ ...newSource, version: e.target.value })}
                                className="col-span-3"
                                placeholder="e.g., 1.0, Draft"
                            />
                        </div>
                    </div>
                    <DialogFooter>
                        <Button type="submit">Save Document</Button>
                    </DialogFooter>
                </form>
            </DialogContent>
        </Dialog>
    );
}

