interface InstitutionalLogicsTableProps {
    sources: Source[];
}

const LOGIC_TYPES = ["market", "state", "professional", "community"] as const;

// Helper to normalize conflict names (e.g. "state vs market" -> "market-state")
function normalizeConflictName(name: string): string {
    return name.toLowerCase()
        .replace(" and ", " vs ")
        .replace(" & ", " vs ")
        .split(" vs ")
        .map(s => s.trim())
        .sort()
        .join(" vs ");
}

export function InstitutionalLogicsTable({ sources }: InstitutionalLogicsTableProps) {
    // 1. Prepare Conflicts Data
    // we need to collect ALL unique conflict pairs from all sources
    const allConflictPairs = new Set<string>();
    sources.forEach(source => {
        source.institutional_logics?.logic_conflicts?.forEach(conflict => {
            if (conflict.between) {
                allConflictPairs.add(normalizeConflictName(conflict.between));
            }
        });
    });
    const sortedConflicts = Array.from(allConflictPairs).sort();

    return (
        <div className="space-y-8">
            <Tabs defaultValue="logics" className="w-full">
                <div className="flex justify-center mb-6">
                    <TabsList className="bg-slate-100 p-1">
                        <TabsTrigger value="logics" className="px-6">Core Logics</TabsTrigger>
                        <TabsTrigger value="conflicts" className="px-6">Key Conflicts</TabsTrigger>
                    </TabsList>
                </div>

                {/* --- LOGICS VIEW --- */}
                <TabsContent value="logics" className="mt-0">
                    <LogicsVisualizer sources={sources} />
                    <div className="border border-slate-200 rounded-lg overflow-hidden shadow-sm bg-white">
                        <div className="overflow-x-auto">
                            <table className="w-full text-left text-sm">
                                <thead>
                                    <tr className="bg-slate-50 border-b border-slate-200">
                                        <th className="p-3 font-semibold text-slate-500 w-32 min-w-[120px]">Logic</th>
                                        {sources.map((source, i) => (
                                            <th key={i} className="p-3 font-semibold text-slate-900 min-w-[280px]">
                                                <div className="flex items-center gap-2">
                                                    <div className={`w-2 h-2 rounded-full ${source.colorClass ? source.colorClass.replace('bg-', 'bg-').replace('border-', 'bg-') : 'bg-slate-400'}`} />
                                                    {source.title}
                                                </div>
                                            </th>
                                        ))}
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100">
                                    {LOGIC_TYPES.map((logicType) => (
                                        <tr key={logicType} className="hover:bg-slate-50/50 transition-colors group">
                                            <td className="p-3 font-medium text-slate-700 capitalize align-top bg-slate-50/30 group-hover:bg-slate-50 border-r border-slate-100">
                                                {logicType}
                                            </td>
                                            {sources.map((source, idx) => {
                                                // Access the specific logic object
                                                // Need to cast or access safely as key signature might differ slightly in types
                                                const logicData = source.institutional_logics?.logics?.[logicType as keyof typeof source.institutional_logics.logics];

                                                if (!logicData) {
                                                    return (
                                                        <td key={idx} className="p-3 align-top text-slate-400 italic text-xs">
                                                            Not detected
                                                        </td>
                                                    );
                                                }

                                                return (
                                                    <td key={idx} className="p-3 align-top space-y-4">
                                                        {/* Strength Bar */}
                                                        <div className="flex items-center gap-2 mb-2">
                                                            <div className="flex-1 h-1.5 bg-slate-100 rounded-full overflow-hidden">
                                                                <div
                                                                    className={cn("h-full rounded-full",
                                                                        logicType === 'market' ? "bg-purple-500" :
                                                                            logicType === 'state' ? "bg-blue-500" :
                                                                                logicType === 'community' ? "bg-emerald-500" :
                                                                                    "bg-amber-500" // professional
                                                                    )}
                                                                    style={{ width: `${(logicData.strength || 0) * 100}%` }}
                                                                />
                                                            </div>
                                                            <span className="text-xs font-medium text-slate-600 w-8 text-right">
                                                                {((logicData.strength || 0) * 100).toFixed(0)}%
                                                            </span>
                                                        </div>

                                                        {/* Manifestations */}
                                                        <div className="space-y-4">
                                                            {logicData.manifestation_material && (
                                                                <div>
                                                                    <span className="text-[10px] uppercase font-bold text-slate-400 tracking-wider">Material</span>
                                                                    {(() => {
                                                                        const summary = extractKeyTakeaway(logicData.manifestation_material);
                                                                        return summary ? (
                                                                            <div className="font-semibold text-slate-800 text-xs mt-1 mb-1 bg-slate-50 p-1.5 rounded border border-slate-100 leading-snug">
                                                                                {summary}
                                                                            </div>
                                                                        ) : null;
                                                                    })()}
                                                                    <div className="text-slate-700 text-xs mt-1 leading-relaxed pl-1">
                                                                        <TextParser text={logicData.manifestation_material} />
                                                                    </div>
                                                                </div>
                                                            )}
                                                            {logicData.manifestation_discursive && (
                                                                <div>
                                                                    <span className="text-[10px] uppercase font-bold text-slate-400 tracking-wider">Discursive</span>
                                                                    {(() => {
                                                                        const summary = extractKeyTakeaway(logicData.manifestation_discursive);
                                                                        return summary ? (
                                                                            <div className="font-semibold text-slate-800 text-xs mt-1 mb-1 bg-slate-50 p-1.5 rounded border border-slate-100 leading-snug">
                                                                                {summary}
                                                                            </div>
                                                                        ) : null;
                                                                    })()}
                                                                    <div className="text-slate-700 text-xs mt-1 leading-relaxed pl-1">
                                                                        <TextParser text={logicData.manifestation_discursive} />
                                                                    </div>
                                                                </div>
                                                            )}
                                                        </div>
                                                    </td>
                                                );
                                            })}
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </TabsContent>

                {/* --- CONFLICTS VIEW --- */}
                <TabsContent value="conflicts" className="mt-0">
                    <div className="border border-slate-200 rounded-lg overflow-hidden shadow-sm bg-white">
                        <div className="overflow-x-auto">
                            <table className="w-full text-left text-sm">
                                <thead>
                                    <tr className="bg-slate-50 border-b border-slate-200">
                                        <th className="p-3 font-semibold text-slate-500 w-40 min-w-[150px]">Conflict Pair</th>
                                        {sources.map((source, i) => (
                                            <th key={i} className="p-3 font-semibold text-slate-900 min-w-[280px]">
                                                <div className="flex items-center gap-2">
                                                    <div className={`w-2 h-2 rounded-full ${source.colorClass ? source.colorClass.replace('bg-', 'bg-').replace('border-', 'bg-') : 'bg-slate-400'}`} />
                                                    {source.title}
                                                </div>
                                            </th>
                                        ))}
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100">
                                    {sortedConflicts.length === 0 && (
                                        <tr>
                                            <td colSpan={sources.length + 1} className="p-8 text-center text-slate-400">
                                                No specific logic conflicts detected across these documents.
                                            </td>
                                        </tr>
                                    )}
                                    {sortedConflicts.map((pair) => (
                                        <tr key={pair} className="hover:bg-slate-50/50 transition-colors group">
                                            <td className="p-3 font-medium text-slate-700 align-top bg-slate-50/30 group-hover:bg-slate-50 border-r border-slate-100">
                                                <div className="capitalize">{pair}</div>
                                            </td>
                                            {sources.map((source, idx) => {
                                                // Find the conflict that matches this normalized pair
                                                const conflict = source.institutional_logics?.logic_conflicts?.find(c =>
                                                    c.between && normalizeConflictName(c.between) === pair
                                                );

                                                if (!conflict) {
                                                    return (
                                                        <td key={idx} className="p-3 align-top text-slate-300 text-xs">
                                                            -
                                                        </td>
                                                    );
                                                }

                                                return (
                                                    <td key={idx} className="p-3 align-top space-y-3">
                                                        <div>
                                                            <span className="text-[10px] uppercase font-bold text-slate-400 tracking-wider">Site of Conflict</span>
                                                            <div className="text-slate-700 text-xs mt-0.5 leading-relaxed">
                                                                <TextParser text={conflict.site_of_conflict || ""} />
                                                            </div>
                                                        </div>
                                                        {conflict.resolution_strategy && (
                                                            <div className="bg-amber-50 border border-amber-100 p-2 rounded">
                                                                <span className="text-[10px] uppercase font-bold text-amber-500 tracking-wider">Resolution</span>
                                                                <div className="text-amber-900 text-xs mt-0.5 leading-relaxed">
                                                                    {conflict.resolution_strategy}
                                                                </div>
                                                            </div>
                                                        )}
                                                    </td>
                                                );
                                            })}
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </TabsContent>
            </Tabs>
        </div>
    );
}

import { LegitimacyAnalysis } from "@/types";
import { Radar, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, ResponsiveContainer, Tooltip } from 'recharts';
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Scale } from "lucide-react";
import { MoralVocabularyMatrix } from "./MoralVocabularyMatrix";


interface LegitimacyAnalysisViewProps {
    analysis: LegitimacyAnalysis;
}

export function LegitimacyAnalysisView({ analysis }: LegitimacyAnalysisViewProps) {
    if (!analysis || !analysis.orders) return null;

    // Helper to safely render any weird hallucinated structure
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const renderSafe = (content: any): React.ReactNode => {
        if (typeof content === 'string' || typeof content === 'number') return content;

        if (Array.isArray(content)) {
            // Check if items are primitive strings/numbers to decide layout
            const isPrimitive = content.every(c => typeof c === 'string' || typeof c === 'number');

            if (isPrimitive) {
                return content.join(", ");
            }

            // For objects (like value-mechanism pairs), render as a vertical stack
            return (
                <div className="flex flex-col gap-2 mt-1">
                    {content.map((c, i) => (
                        <div key={i} className="pl-2 border-l-2 border-slate-200">
                            {renderSafe(c)}
                        </div>
                    ))}
                </div>
            );
        }

        if (typeof content === 'object' && content !== null) {
            // Check if it's a known conflict spot structure
            if (content.location && content.description) {
                return (
                    <div className="space-y-1">
                        <span className="font-semibold">{renderSafe(content.location)}: </span>
                        <span>{renderSafe(content.description)}</span>
                    </div>
                );
            }
            // Fallback for unknown objects
            return Object.entries(content).map(([k, v]) => (
                <div key={k} className="text-xs mb-1">
                    <span className="font-semibold capitalize text-slate-600">{k.replace(/_/g, ' ')}:</span><br />
                    <div className="ml-1">{renderSafe(v)}</div>
                </div>
            ));
        }
        return JSON.stringify(content);
    };

    // Helper to extract score from potentially complex object
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const getScore = (val: any): number => {
        if (typeof val === 'number') return val;
        if (typeof val === 'string') {
            const parsed = parseFloat(val);
            return isNaN(parsed) ? 0 : parsed;
        }
        if (typeof val === 'object' && val !== null) {
            // gpt-5.1 likes to return { score: 8, evidence: "..." }
            if (val.score) return getScore(val.score);
            if (val.value) return getScore(val.value);
            if (val.strength) return getScore(val.strength);
        }
        return 0;
    };

    const data = [
        { subject: 'Market', A: getScore(analysis.orders.market), fullMark: 10 },
        { subject: 'Industrial', A: getScore(analysis.orders.industrial), fullMark: 10 },
        { subject: 'Civic', A: getScore(analysis.orders.civic), fullMark: 10 },
        { subject: 'Domestic', A: getScore(analysis.orders.domestic), fullMark: 10 },
        { subject: 'Inspired', A: getScore(analysis.orders.inspired), fullMark: 10 },
        { subject: 'Fame', A: getScore(analysis.orders.fame), fullMark: 10 },
    ];

    return (
        <div className="space-y-6">
            <div className="flex flex-col md:flex-row gap-6">
                {/* Radar Chart */}
                <div className="w-full md:w-1/2 h-[300px]">
                    <ResponsiveContainer width="100%" height="100%">
                        <RadarChart cx="50%" cy="50%" outerRadius="80%" data={data}>
                            <PolarGrid stroke="#e2e8f0" />
                            <PolarAngleAxis dataKey="subject" tick={{ fill: '#64748b', fontSize: 12 }} />
                            <PolarRadiusAxis angle={30} domain={[0, 10]} tick={false} axisLine={false} />
                            <Radar
                                name="Legitimacy"
                                dataKey="A"
                                stroke="#4f46e5"
                                strokeWidth={2}
                                fill="#6366f1"
                                fillOpacity={0.4}
                            />
                            <Tooltip
                                contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                            />
                        </RadarChart>
                    </ResponsiveContainer>
                </div>

                {/* Analysis Details */}
                <div className="w-full md:w-1/2 space-y-4">
                    <div>
                        <h4 className="text-sm font-semibold text-slate-500 uppercase tracking-wider mb-2">Dominant Order</h4>
                        <div className="flex items-center gap-2">
                            <Scale className="h-5 w-5 text-indigo-600" />
                            <span className="text-lg font-bold text-slate-900">
                                {renderSafe(analysis.dominant_order)}
                            </span>
                        </div>
                    </div>

                    <div>
                        <h4 className="text-sm font-semibold text-slate-500 uppercase tracking-wider mb-2">Justification Logic</h4>
                        <div className="text-sm text-slate-700 leading-relaxed bg-slate-50 p-3 rounded-md border border-slate-100">
                            {renderSafe(analysis.justification_logic)}
                        </div>
                    </div>

                    <div>
                        <h4 className="text-sm font-semibold text-slate-500 uppercase tracking-wider mb-2">Moral Vocabulary</h4>
                        {analysis.moral_vocabulary ? (
                            <MoralVocabularyMatrix vocabulary={analysis.moral_vocabulary} />
                        ) : (
                            <div className="text-sm text-slate-400 italic">No moral vocabulary data available.</div>
                        )}
                    </div>
                </div>
            </div>

            {/* Conflict Spot */}
            {analysis.conflict_spot && (
                <Card className="bg-amber-50 border-amber-200">
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-bold text-amber-800 flex items-center gap-2">
                            ⚠️ Conflict Spot
                        </CardTitle>
                    </CardHeader>
                    <CardContent className="text-sm text-amber-900 space-y-2">
                        {renderSafe(analysis.conflict_spot)}
                    </CardContent>
                </Card>
            )}


        </div>
    );
}

import React from 'react';
import {
    Radar,
    RadarChart,
    PolarGrid,
    PolarAngleAxis,
    PolarRadiusAxis,
    ResponsiveContainer,
    Legend,
    Tooltip
} from 'recharts';
import { Source } from '@/types';

interface LogicsVisualizerProps {
    sources: Source[];
}

const LOGIC_TYPES = ["market", "state", "professional", "community"];

export function LogicsVisualizer({ sources }: LogicsVisualizerProps) {
    if (!sources || sources.length === 0) return null;

    // Transform data for Recharts Radar
    // Data format: [{ subject: 'Market', A: 120, B: 110, fullMark: 150 }, ...]
    const data = LOGIC_TYPES.map(logic => {
        const item: any = { subject: logic.charAt(0).toUpperCase() + logic.slice(1) };
        sources.forEach(source => {
            const logicData = source.institutional_logics?.logics?.[logic as keyof typeof source.institutional_logics.logics];
            // Normalize to 0-100 for chart
            item[source.id] = (logicData?.strength || 0) * 100;
        });
        return item;
    });

    return (
        <div className="w-full h-[350px] bg-white border border-slate-200 rounded-lg p-4 shadow-sm mb-6">
            <h3 className="text-sm font-semibold text-slate-500 mb-4 text-center uppercase tracking-wider">
                Comparative Logic Strength
            </h3>
            <div className="w-full h-[280px]">
                <ResponsiveContainer width="100%" height="100%">
                    <RadarChart cx="50%" cy="50%" outerRadius="80%" data={data}>
                        <PolarGrid stroke="#e2e8f0" />
                        <PolarAngleAxis
                            dataKey="subject"
                            tick={{ fill: '#64748b', fontSize: 12, fontWeight: 500 }}
                        />
                        <PolarRadiusAxis
                            angle={30}
                            domain={[0, 100]}
                            tick={false}
                            axisLine={false}
                        />
                        {sources.map((source, idx) => (
                            <Radar
                                key={source.id}
                                name={source.title}
                                dataKey={source.id}
                                stroke={source.colorClass ? getHexColor(source.colorClass) : '#94a3b8'}
                                fill={source.colorClass ? getHexColor(source.colorClass) : '#94a3b8'}
                                fillOpacity={0.3}
                            />
                        ))}
                        <Legend wrapperStyle={{ fontSize: '12px', paddingTop: '10px' }} />
                        <Tooltip
                            contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                            itemStyle={{ fontSize: '12px', padding: 0 }}
                        />
                    </RadarChart>
                </ResponsiveContainer>
            </div>
        </div>
    );
}

// Helper to map Tailwind classes to Hex for Recharts
// This is a simplified mapping, ideally we'd use computed styles or a robust map
function getHexColor(colorClass: string): string {
    if (colorClass.includes('purple')) return '#a855f7';
    if (colorClass.includes('blue')) return '#3b82f6';
    if (colorClass.includes('emerald')) return '#10b981';
    if (colorClass.includes('amber')) return '#f59e0b';
    if (colorClass.includes('red')) return '#ef4444';
    if (colorClass.includes('cyan')) return '#06b6d4';
    if (colorClass.includes('indigo')) return '#6366f1';
    if (colorClass.includes('rose')) return '#f43f5e';
    if (colorClass.includes('orange')) return '#f97316';

    // Default fallback
    return '#94a3b8'; // slate-400
}

import React, { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Textarea } from "@/components/ui/textarea";
import { EcosystemActor } from "@/types/ecosystem";
import { Loader2, Network } from "lucide-react";

interface MaterializeDialogProps {
    isOpen: boolean;
    onClose: () => void;
    initialName: string;
    initialDescription: string;
    sourceContext: {
        sourceId: string;
        type: "accountability" | "legitimacy" | "cultural_absence" | "trace";
        detail: string;
    };
    onConfirm: (actor: Omit<EcosystemActor, "id">) => Promise<void>;
}

export function MaterializeDialog({
    isOpen,
    onClose,
    initialName,
    initialDescription,
    sourceContext,
    onConfirm
}: MaterializeDialogProps) {
    const [name, setName] = useState(initialName);
    const [description, setDescription] = useState(initialDescription);
    const [type, setType] = useState<EcosystemActor["type"]>("Policymaker");
    const [roleType, setRoleType] = useState<EcosystemActor["role_type"]>("Mixed");
    const [mode, setMode] = useState<"actor" | "constraint">("actor");
    const [isSubmitting, setIsSubmitting] = useState(false);

    // Reset form when dialog opens with new data
    useEffect(() => {
        if (isOpen) {
            setName(initialName);
            setDescription(initialDescription);
            setIsSubmitting(false);

            // Heuristic for type
            if (sourceContext.type === "accountability") setType("Policymaker");
            if (sourceContext.type === "cultural_absence") setType("Civil Society");
        }
    }, [isOpen, initialName, initialDescription, sourceContext.type]);

    const handleConfirm = async () => {
        if (!name) return;
        setIsSubmitting(true);
        try {
            await onConfirm({
                sourceId: sourceContext.sourceId,
                name,
                description,
                type: mode === "constraint" ? "LegalObject" : type,
                role_type: mode === "constraint" ? "Expressive" : roleType,
                influence: "Medium", // Default
                source: "default",
                materialized_from: {
                    source_id: sourceContext.sourceId,
                    context_type: sourceContext.type,
                    context_detail: sourceContext.detail
                }
            });
            onClose();
        } catch (error) {
            console.error("Failed to materialize actor:", error);
            // Optionally show error state
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <Dialog open={isOpen} onOpenChange={(open) => !open && onClose()}>
            <DialogContent className="sm:max-w-[500px]">
                <DialogHeader>
                    <DialogTitle className="flex items-center gap-2">
                        <Network className="h-5 w-5 text-indigo-600" />
                        Materialize in Ecosystem
                    </DialogTitle>
                    <DialogDescription>
                        Convert this analysis insight into a persistent actor in the ecosystem graph.
                    </DialogDescription>
                </DialogHeader>

                <div className="grid gap-4 py-4">
                    <div className="grid grid-cols-4 items-center gap-4">
                        <Label htmlFor="name" className="text-right">
                            Name
                        </Label>
                        <Input
                            id="name"
                            value={name}
                            onChange={(e) => setName(e.target.value)}
                            className="col-span-3"
                        />
                    </div>

                    <div className="grid grid-cols-4 items-center gap-4">
                        <Label htmlFor="type" className="text-right">
                            Actor Type
                        </Label>
                        <Select
                            value={mode === "constraint" ? "LegalObject" : type}
                            onValueChange={(val: EcosystemActor["type"]) => setType(val)}
                            disabled={mode === "constraint"}
                        >
                            <SelectTrigger className="col-span-3">
                                <SelectValue placeholder="Select type" />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="Policymaker">Policymaker</SelectItem>
                                <SelectItem value="Civil Society">Civil Society</SelectItem>
                                <SelectItem value="Infrastructure">Infrastructure</SelectItem>
                                <SelectItem value="Algorithm">Algorithm</SelectItem>
                                <SelectItem value="PrivateTech">Private Tech / Startup</SelectItem>
                                <SelectItem value="Academic">Academic</SelectItem>
                                <SelectItem value="Dataset">Dataset</SelectItem>
                                <SelectItem value="AlgorithmicAgent">Algorithmic Agent (AI)</SelectItem>
                                <SelectItem value="LegalObject">Legal Object (Regulation)</SelectItem>
                            </SelectContent>
                        </Select>
                    </div>

                    <div className="grid grid-cols-4 items-center gap-4">
                        <Label htmlFor="role" className="text-right">
                            Ontology
                        </Label>
                        <Select
                            value={mode === "constraint" ? "Expressive" : roleType}
                            onValueChange={(val) => setRoleType(val as EcosystemActor["role_type"])}
                            disabled={mode === "constraint"}
                        >
                            <SelectTrigger className="col-span-3">
                                <SelectValue placeholder="Role Type" />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="Material">Material (Hardware/Bodies)</SelectItem>
                                <SelectItem value="Expressive">Expressive (Code/Law)</SelectItem>
                                <SelectItem value="Mixed">Mixed (Assemblage)</SelectItem>
                            </SelectContent>
                        </Select>
                    </div>

                    <div className="grid grid-cols-4 items-start gap-4">
                        <Label htmlFor="desc" className="text-right pt-2">
                            Context
                        </Label>
                        <Textarea
                            id="desc"
                            value={description}
                            onChange={(e) => setDescription(e.target.value)}
                            className="col-span-3 h-20 text-xs"
                            placeholder={mode === "constraint" ? "Paste the legal text or requirement here..." : "Describe the actor..."}
                        />
                    </div>

                    <div className="grid grid-cols-4 items-start gap-4">
                        <Label className="text-right pt-2">Mode</Label>
                        <Tabs value={mode} onValueChange={(v) => setMode(v as any)} className="col-span-3">
                            <TabsList className="grid w-full grid-cols-2">
                                <TabsTrigger value="actor">Actor / Assemblage</TabsTrigger>
                                <TabsTrigger value="constraint">Code / Law</TabsTrigger>
                            </TabsList>
                        </Tabs>
                    </div>

                    <div className="bg-slate-50 p-3 rounded text-xs text-slate-500 flex gap-2 border border-slate-100 italic">
                        <span className="font-bold not-italic">Source:</span>
                        {sourceContext.type.replace('_', ' ')} • {sourceContext.detail}
                    </div>
                </div>

                <DialogFooter>
                    <Button variant="outline" onClick={onClose} disabled={isSubmitting}>
                        Cancel
                    </Button>
                    <Button onClick={handleConfirm} disabled={!name || isSubmitting} className="bg-indigo-600 hover:bg-indigo-700">
                        {isSubmitting ? (
                            <>
                                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                Adding...
                            </>
                        ) : (
                            <>
                                <Network className="mr-2 h-4 w-4" />
                                Add to Ecosystem
                            </>
                        )}
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

import React, { useState } from 'react';
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Info } from "lucide-react";

interface VocabularyItem {
    term: string;
    order: string;
    level?: string;
}

interface MoralVocabularyMatrixProps {
    vocabulary: VocabularyItem[] | string[] | string;
}

export function MoralVocabularyMatrix({ vocabulary }: MoralVocabularyMatrixProps) {
    const [selectedCell, setSelectedCell] = useState<{ order: string; level: string; items: string[] } | null>(null);

    // 1. Normalize Data
    let items: VocabularyItem[] = [];
    if (Array.isArray(vocabulary)) {
        if (vocabulary.every(v => typeof v === 'string')) {
            // Legacy string array - mostly useless for matrix unless we AI-guess (too risky), 
            // so we'll dump them in a "Unclassified" bucket or handling them gracefully.
            // For now, let's treat them as "Unclassified / Meso" default
            items = (vocabulary as string[]).map(term => ({ term, order: "default", level: "meso" }));
        } else {
            items = vocabulary as VocabularyItem[];
        }
    } else if (typeof vocabulary === 'string') {
        items = vocabulary.split(',').map(s => ({ term: s.trim(), order: "default", level: "meso" }));
    }

    // 2. Aggregate Data for Heatmap
    const orders = ["market", "industrial", "civic", "domestic", "inspired", "fame"];
    const levels = ["micro", "meso", "macro"];

    const matrix: Record<string, Record<string, string[]>> = {};

    // Initialize
    orders.forEach(o => {
        matrix[o] = {};
        levels.forEach(l => matrix[o][l] = []);
    });

    // Populate
    let unclassifiedCount = 0;

    items.forEach(item => {
        const orderKey = item.order?.toLowerCase() || "default";
        const levelKey = item.level?.toLowerCase() || "meso";

        if (orders.includes(orderKey) && levels.includes(levelKey)) {
            matrix[orderKey][levelKey].push(item.term);
        } else if (orders.includes(orderKey)) {
            // Fallback level
            matrix[orderKey]["meso"].push(item.term);
        } else {
            unclassifiedCount++;
        }
    });

    // Color definitions (using Tailwind classes for base colors)
    const colorMap: Record<string, { bg: string, text: string, border: string, intense: string }> = {
        market: { bg: "bg-purple-100", text: "text-purple-900", border: "border-purple-200", intense: "bg-purple-500" },
        industrial: { bg: "bg-slate-100", text: "text-slate-900", border: "border-slate-200", intense: "bg-slate-500" },
        civic: { bg: "bg-emerald-100", text: "text-emerald-900", border: "border-emerald-200", intense: "bg-emerald-500" },
        domestic: { bg: "bg-amber-100", text: "text-amber-900", border: "border-amber-200", intense: "bg-amber-500" },
        inspired: { bg: "bg-rose-100", text: "text-rose-900", border: "border-rose-200", intense: "bg-rose-500" },
        fame: { bg: "bg-cyan-100", text: "text-cyan-900", border: "border-cyan-200", intense: "bg-cyan-500" },
    };

    // Calculate max count for scaling (simple relative intensity)
    let maxCount = 0;
    Object.values(matrix).forEach(row => {
        Object.values(row).forEach(cell => {
            if (cell.length > maxCount) maxCount = cell.length;
        });
    });

    return (
        <Card className="border-slate-200 shadow-sm overflow-hidden">
            <CardHeader className="bg-slate-50/50 pb-4 border-b border-slate-100">
                <div className="flex items-center justify-between">
                    <CardTitle className="text-sm font-semibold text-slate-700 flex items-center gap-2">
                        Moral Vocabulary Matrix
                        <Dialog>
                            <DialogTrigger>
                                <Info className="h-4 w-4 text-slate-400 cursor-help hover:text-slate-600" />
                            </DialogTrigger>
                            <DialogContent>
                                <DialogHeader>
                                    <DialogTitle>About the Moral Matrix</DialogTitle>
                                </DialogHeader>
                                <div className="text-sm text-slate-600 space-y-3">
                                    <p>This matrix visualizes the <strong>scale</strong> (Micro/Meso/Macro) relative to the <strong>Order of Worth</strong> (Moral Value System).</p>
                                    <ul className="list-disc pl-5 space-y-1">
                                        <li><strong>Macro</strong>: High-level values and ideals (e.g., "Liberty", "Efficiency").</li>
                                        <li><strong>Meso</strong>: Organizational structures and policies (e.g., "Protocols", "Audits").</li>
                                        <li><strong>Micro</strong>: Specific mechanisms and technical details (e.g., "Latency", "User Agent").</li>
                                    </ul>
                                    <p>A balanced justification typically spans all three levels. Gaps may indicate "High Rhetoric, Low Verification" (Macro-heavy) or "Technocratic Silence" (Micro-heavy).</p>
                                </div>
                            </DialogContent>
                        </Dialog>
                    </CardTitle>
                    <div className="text-xs text-slate-500">
                        {items.length} terms analyzed
                    </div>
                </div>
            </CardHeader>
            <CardContent className="p-0">
                <div className="grid grid-cols-[120px_1fr_1fr_1fr] divide-y divide-slate-100">
                    {/* Header Row */}
                    <div className="bg-slate-50 text-xs font-semibold text-slate-500 p-3 flex items-center">
                        Order of Worth
                    </div>
                    {levels.map(level => (
                        <div key={level} className="bg-slate-50 text-xs font-semibold text-slate-500 p-3 text-center capitalize border-l border-slate-100 hidden md:block">
                            {level}
                        </div>
                    ))}

                    {/* Data Rows */}
                    {orders.map(order => {
                        const style = colorMap[order];
                        const rowTotal = levels.reduce((sum, l) => sum + matrix[order][l].length, 0);
                        const isDominant = rowTotal > 0 && (rowTotal / items.length) > 0.3; // Highlight if > 30% of terms

                        return (
                            <React.Fragment key={order}>
                                <div className={`p-3 text-sm font-medium flex items-center justify-between group relative ${style.bg} ${style.border} border-l-4`}>
                                    <span className={style.text + " capitalize"}>{order}</span>
                                    {isDominant && <Badge variant="secondary" className="text-[10px] bg-white/50 ml-2">Dominant</Badge>}
                                </div>
                                {levels.map(level => {
                                    const cellItems = matrix[order][level];
                                    const count = cellItems.length;
                                    const intensity = maxCount > 0 ? count / maxCount : 0;

                                    // Visualizing "Empty" vs "Occupied"
                                    const isEmpty = count === 0;

                                    return (
                                        <div
                                            key={`${order}-${level}`}
                                            className={`
                                                relative p-2 border-l border-slate-100 transition-all cursor-pointer hover:bg-slate-50
                                                ${isEmpty ? 'bg-white' : ''}
                                            `}
                                            onClick={() => count > 0 && setSelectedCell({ order, level, items: cellItems })}
                                        >
                                            {/* Heatmap Bar / Background */}
                                            {!isEmpty && (
                                                <div
                                                    className={`absolute bottom-0 left-0 h-1 ${style.intense} transition-all`}
                                                    style={{ width: `${Math.min(100, (count / maxCount) * 100)}%`, opacity: 0.6 }}
                                                />
                                            )}

                                            <div className="flex flex-col items-center justify-center h-full min-h-[40px]">
                                                {count > 0 ? (
                                                    <div className="text-center">
                                                        <span className={`text-lg font-bold ${style.text}`}>{count}</span>
                                                        <span className="text-[10px] text-slate-400 block -mt-1">{count === 1 ? 'term' : 'terms'}</span>
                                                    </div>
                                                ) : (
                                                    <span className="text-slate-200 text-xl">·</span>
                                                )}
                                            </div>

                                            {/* Hover tooltip for quick preview */}
                                            {count > 0 && (
                                                <div className="absolute inset-0 opacity-0 hover:opacity-100 bg-white/95 flex items-center justify-center text-xs text-center p-1 pointer-events-none transition-opacity border border-slate-200 z-10 shadow-sm">
                                                    <span className="line-clamp-2">{cellItems.slice(0, 3).join(", ")}{cellItems.length > 3 && "..."}</span>
                                                </div>
                                            )}
                                        </div>
                                    );
                                })}
                            </React.Fragment>
                        );
                    })}
                </div>
            </CardContent>

            {/* Drill-down Dialog */}
            <Dialog open={!!selectedCell} onOpenChange={(open) => !open && setSelectedCell(null)}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle className="capitalize flex items-center gap-2">
                            {selectedCell?.order} Words
                            <Badge variant="outline" className="uppercase">{selectedCell?.level}</Badge>
                        </DialogTitle>
                    </DialogHeader>
                    <div className="grid gap-2 mt-4">
                        {selectedCell?.items.map((term, i) => (
                            <div key={i} className="p-2 bg-slate-50 border border-slate-100 rounded text-sm text-slate-700">
                                {term}
                            </div>
                        ))}
                    </div>
                </DialogContent>
            </Dialog>
        </Card>
    );
}

