interface MultiLensAnalysisProps {
    initialText?: string;
    sources?: Source[];
    onRefresh?: () => void;
}

type LensType = 'dsf' | 'cultural_framing' | 'institutional_logics' | 'legitimacy';

const LENSES: { id: LensType; name: string; description: string }[] = [
    { id: 'dsf', name: 'Decolonial Framework', description: 'Power, agency, and coloniality' },
    { id: 'cultural_framing', name: 'Cultural Framing', description: 'Values, narratives, and epistemic authority' },
    { id: 'institutional_logics', name: 'Institutional Logics', description: 'Conflicting institutional orders and practices' },
    { id: 'legitimacy', name: 'Legitimacy Orders', description: 'Justification regimes and moral vocabulary' }
];

export function MultiLensAnalysis({ initialText = '', sources = [], onRefresh }: MultiLensAnalysisProps) {
    const { isReadOnly } = useDemoMode(); // [NEW]

    // Helper function to determine actual document type from both type field and title
    const getDocumentType = (source: Source): "Policy" | "Web" | "Trace" => {
        // Check title prefix first (more reliable for user-added sources)
        if (source.title.startsWith('[Web]')) return "Web";
        if (source.title.startsWith('[Trace]')) return "Trace";

        // Fall back to type field
        if (source.type === 'Web') return "Web";
        if (source.type === 'Trace') return "Trace";

        // Default to Policy for PDF, Text, Word types
        return "Policy";
    };

    // Filter to only show Policy documents
    const policyDocuments = sources.filter(s => getDocumentType(s) === "Policy");

    // Persist text input
    const [text, setText] = useServerStorage("multi_lens_text", initialText);

    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [progress, setProgress] = useState<string>('');

    // [NEW] Granular Progress State for Graph
    const [analysisProgress, setAnalysisProgress] = useState<{
        decolonial: AnalysisStepStatus;
        cultural: AnalysisStepStatus;
        logics: AnalysisStepStatus;
        legitimacy: AnalysisStepStatus;
        message?: string;
    }>({
        decolonial: 'pending',
        cultural: 'pending',
        logics: 'pending',
        legitimacy: 'pending'
    });

    interface Evidence {
        title: string;
        type: "Order of Worth" | "Cultural Cluster" | "Trace";
        quotes: { text: string; source: string }[];
    }

    const [activeEvidence, setActiveEvidence] = useState<Evidence | null>(null);

    // Persist analysis results
    const [results, setResults] = useServerStorage<Record<LensType, AnalysisResult | null>>("multi_lens_results", {
        dsf: null,
        cultural_framing: null,
        institutional_logics: null,
        legitimacy: null
    });

    const [expandedLens, setExpandedLens] = useState<LensType | null>(null);

    const handleSourceSelect = (sourceId: string) => {
        const source = sources.find(s => s.id === sourceId);
        if (source && source.extractedText) {
            setText(source.extractedText.substring(0, 15000)); // Limit text length for analysis
        }
    };

    const [forceRefresh, setForceRefresh] = useState(false);

    const handleAnalyze = async () => {
        if (!text.trim()) return;
        if (isReadOnly) { // [NEW]
            alert("Analysis disabled in Demo Mode");
            return;
        }

        setIsAnalyzing(true);

        // [FIX] Clear previous results immediately
        const emptyResults: Record<LensType, AnalysisResult | null> = {
            dsf: null,
            cultural_framing: null,
            institutional_logics: null,
            legitimacy: null
        };
        setResults(emptyResults);

        const newResults = { ...emptyResults };

        // Reset Progress
        setAnalysisProgress({
            decolonial: 'pending',
            cultural: 'pending',
            logics: 'pending',
            legitimacy: 'pending',
            message: forceRefresh ? 'Forcing Re-Analysis...' : 'Initializing Entanglement...'
        });

        try {
            // Artificial delay to show start
            setAnalysisProgress(prev => ({ ...prev, decolonial: 'analyzing', message: 'Calibrating Decolonial Framework...' }));
            await new Promise(r => setTimeout(r, 800));

            for (const lens of LENSES) {
                const stepKey = lens.id === 'dsf' ? 'decolonial' :
                    lens.id === 'cultural_framing' ? 'cultural' :
                        lens.id === 'institutional_logics' ? 'logics' : 'legitimacy';

                setAnalysisProgress(prev => ({
                    ...prev,
                    [stepKey]: 'analyzing',
                    message: `Running ${lens.name}...`
                }));

                setProgress(`Running ${lens.name}...`);

                try {
                    const result = await analyzeDocument(
                        text,
                        lens.id as AnalysisMode,
                        'Policy Document', // Default source type
                        forceRefresh // Use the state variable
                    );
                    newResults[lens.id] = result;
                    setResults({ ...newResults });

                    setAnalysisProgress(prev => ({ ...prev, [stepKey]: 'done' }));

                } catch (error) {
                    console.error(`Error analyzing with ${lens.name}:`, error);
                    setAnalysisProgress(prev => ({ ...prev, [stepKey]: 'error' }));
                }
            }
        } catch (error) {
            console.error('Analysis failed:', error);
        } finally {
            setIsAnalyzing(false);
            setProgress('');
            // Keep the graph in "done" state for a moment or until reset?
            // For now, we leave it. The graph will be replaced by the result content or we can keep showing it.
            // Actually, usually we hide the graph when done or reset it.
            // Let's reset it after a delay so the user sees "Done".
            setTimeout(() => {
                setAnalysisProgress(prev => ({ ...prev, message: 'Analysis Complete' }));
            }, 1000);
        }
    };

    const getKeyInsight = (lens: LensType, result: AnalysisResult | null) => {
        if (!result) return 'No analysis yet.';

        switch (lens) {
            case 'dsf':
                return result.key_insight || result.reflexivity_situated_praxis || 'No insight generated.';
            case 'cultural_framing':
                // Handle both string and object types for dominant_cultural_logic
                const culturalLogic = result.plain_language_summary?.dominant_cultural_logic?.label || result.dominant_cultural_logic || 'Undetermined';
                return result.dominant_cultural_logic ? `Dominant Logic: ${culturalLogic}. ${result.state_market_society}` : result.key_insight || 'No cultural insight.';
            case 'institutional_logics':
                if (result.dominant_logic) {
                    return `Dominant Logic: ${result.dominant_logic}. ${result.overall_assessment || ''}`;
                }
                return result.overall_assessment || 'No institutional insight.';
            case 'legitimacy':
                const legitResult = result as unknown as LegitimacyAnalysis;
                // Temporarily treat as unknown to safely check for object structure
                const justificationRaw = legitResult.justification_logic as unknown;
                let justification = "";

                // Handle case where LLM returns object instead of string
                if (typeof justificationRaw === 'object' && justificationRaw !== null) {
                    const jObj = justificationRaw as { summary?: string; text?: string; description?: string;[key: string]: unknown };
                    justification = jObj.summary || jObj.text || jObj.description || JSON.stringify(jObj);
                } else {
                    justification = String(justificationRaw);
                }

                if (legitResult.dominant_order) {
                    return `Dominant Order: ${legitResult.dominant_order}. Justification: ${justification}`;
                }
                return justification || 'No legitimacy insight.';
            default:
                return 'N/A';
        }
    };

    return (
        <div className="space-y-6">
            <Card>
                <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                        <Wand2 className="h-5 w-5 text-indigo-600" />
                        Comparative Lens Analysis
                    </CardTitle>
                    <CardDescription>
                        Deploy multiple theoretical lenses simultaneously to observe how the assemblage refracts the artifact.
                    </CardDescription>
                </CardHeader>
                <CardContent className="space-y-4">
                    {policyDocuments.length > 0 && ( // Keep checks but improve UX below
                        <div className="space-y-2 mb-4">
                            <div className="flex items-center gap-2">
                                <FileText className="h-4 w-4 text-slate-500" />
                                <Select onValueChange={handleSourceSelect}>
                                    <SelectTrigger className="w-full md:w-[300px]">
                                        <SelectValue placeholder="Select artifact to assemble..." />
                                    </SelectTrigger>
                                    <SelectContent>
                                        {policyDocuments.map(source => (
                                            <SelectItem key={source.id} value={source.id}>
                                                {source.title}
                                            </SelectItem>
                                        ))}
                                    </SelectContent>
                                </Select>
                                {onRefresh && (
                                    <Button variant="ghost" size="sm" onClick={onRefresh} title="Refresh Source List">
                                        <Sparkles className="h-4 w-4" />
                                    </Button>
                                )}
                            </div>
                            <div className="text-xs text-slate-400 flex justify-between items-center px-1">
                                <span>or paste text below</span>
                                <span>
                                    {policyDocuments.length} Policy docs available
                                    {sources.length > policyDocuments.length && ` (${sources.length - policyDocuments.length} filtered)`}
                                </span>
                            </div>
                        </div>
                    )}
                    <Textarea
                        placeholder="Paste text for theoretical entanglement..."
                        value={text}
                        onChange={(e) => setText(e.target.value)}
                        className="min-h-[150px] font-mono text-sm"
                    />
                    {isAnalyzing ? (
                        <div className="min-h-[250px] flex items-center justify-center border border-slate-100 rounded-lg bg-slate-50/50">
                            <DeepAnalysisProgressGraph status={analysisProgress} currentStepMessage={analysisProgress.message} />
                        </div>
                    ) : (
                        <div className="relative min-h-[250px] bg-slate-50/30 rounded-lg border border-dashed border-slate-200 overflow-hidden group">
                            {/* Background Graph (Idle) */}
                            <div className="absolute inset-0 opacity-30 grayscale group-hover:grayscale-0 group-hover:opacity-50 transition-all duration-500 pointer-events-none">
                                <DeepAnalysisProgressGraph status={{ decolonial: 'pending', cultural: 'pending', logics: 'pending', legitimacy: 'pending' }} />
                            </div>

                            {/* Overlay Action */}
                            <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/40 backdrop-blur-[1px] group-hover:bg-white/20 transition-all z-10">
                                <div className="flex flex-col items-center gap-3">
                                    <Button
                                        onClick={handleAnalyze}
                                        disabled={!text.trim() || isReadOnly}
                                        className="bg-indigo-600 hover:bg-indigo-700 text-white shadow-lg animate-in zoom-in-95 duration-300 scale-110"
                                    >
                                        <Wand2 className="mr-2 h-4 w-4" />
                                        Initiate Entanglement
                                    </Button>

                                    <div className="flex items-center space-x-2 bg-white/80 px-3 py-1.5 rounded-full shadow-sm backdrop-blur-sm border border-indigo-100 animate-in fade-in zoom-in duration-500 delay-100">
                                        <input
                                            type="checkbox"
                                            id="force-refresh-chk"
                                            checked={forceRefresh}
                                            onChange={(e) => setForceRefresh(e.target.checked)}
                                            className="h-3.5 w-3.5 rounded border-indigo-300 text-indigo-600 focus:ring-indigo-500 cursor-pointer"
                                        />
                                        <label htmlFor="force-refresh-chk" className="text-xs font-medium text-indigo-600 cursor-pointer select-none">
                                            Force Re-Analysis
                                        </label>
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}
                    <p className="text-xs text-slate-500 text-center mt-2">
                        <span className="inline-flex items-center gap-1">
                            <Sparkles className="w-3 h-3 text-indigo-400" />
                            AI inputs processed by OpenAI (GPT-5.1) & Google (Gemini 3 Pro / Search).
                        </span>
                    </p>
                </CardContent>
            </Card>

            {Object.values(results).some(r => r !== null) && (
                <div className="space-y-6">
                    {/* Visualization of Entanglements */}
                    <SpectralRadar results={results} />

                    <div className="grid gap-6 md:grid-cols-2">
                        {LENSES.map((lens) => (
                            <Card key={lens.id} className={`flex flex-col transition-all duration-300 ${expandedLens === lens.id ? 'md:col-span-2 ring-2 ring-indigo-500 shadow-lg' : 'hover:shadow-md'}`}>
                                <CardHeader className="pb-3 bg-slate-50/50 border-b border-slate-100">
                                    <div className="flex items-center justify-between">
                                        <div className="space-y-1">
                                            <CardTitle className="text-base font-semibold text-slate-800 flex items-center gap-2">
                                                {lens.name}
                                                {results[lens.id] && (
                                                    <span className="text-[10px] px-2 py-0.5 rounded-full bg-green-100 text-green-700 font-medium">Ready</span>
                                                )}
                                            </CardTitle>
                                            <CardDescription className="text-xs">
                                                {lens.description}
                                            </CardDescription>
                                        </div>
                                        <Button
                                            variant="ghost"
                                            size="icon"
                                            className="h-7 w-7"
                                            onClick={() => setExpandedLens(expandedLens === lens.id ? null : lens.id)}
                                        >
                                            {expandedLens === lens.id ? <Minimize2 className="h-3.5 w-3.5" /> : <Maximize2 className="h-3.5 w-3.5" />}
                                        </Button>
                                    </div>
                                </CardHeader>
                                <CardContent className="flex-1 text-sm text-slate-600 pt-4">
                                    {results[lens.id] ? (
                                        <div className="space-y-4">

                                            {/* --- LEGITIMACY LENS --- */}
                                            {lens.id === 'legitimacy' && (
                                                <>
                                                    <div className="flex flex-col md:flex-row gap-4">
                                                        <div className="flex-1 space-y-2">
                                                            <div className="bg-indigo-50 border border-indigo-100 rounded-md p-3">
                                                                <span className="text-xs font-bold text-indigo-800 uppercase tracking-wide block mb-1">Dominant Order</span>
                                                                <p className="font-semibold text-indigo-900 leading-tight">
                                                                    {(results['legitimacy'] as any).dominant_order || 'Undetermined'}
                                                                </p>
                                                            </div>
                                                            <Accordion type="single" collapsible className="w-full">
                                                                <AccordionItem value="justification" className="border-none">
                                                                    <AccordionTrigger className="py-2 text-xs font-medium text-slate-500 hover:text-indigo-600 hover:no-underline">
                                                                        View Justification Logic
                                                                    </AccordionTrigger>
                                                                    <AccordionContent>
                                                                        <div className="text-xs leading-relaxed text-slate-600 bg-slate-50 p-3 rounded-md border border-slate-100">
                                                                            {(() => {
                                                                                const logic = (results['legitimacy'] as any).justification_logic;
                                                                                if (!logic) return 'No justification logic available.';
                                                                                if (typeof logic === 'string') return logic;
                                                                                if (typeof logic === 'object') {
                                                                                    // If it's the specific breakdown by order
                                                                                    if ('market' in logic || 'civic' in logic) {
                                                                                        return (
                                                                                            <div className="space-y-2">
                                                                                                {Object.entries(logic).map(([key, value]) => (
                                                                                                    <div key={key} className="flex flex-col gap-1 border-b border-slate-200 last:border-0 pb-2 last:pb-0">
                                                                                                        <span className="font-semibold capitalize text-indigo-700">{key}</span>
                                                                                                        <span className="text-slate-600">{String(value)}</span>
                                                                                                    </div>
                                                                                                ))}
                                                                                            </div>
                                                                                        );
                                                                                    }
                                                                                    // Fallback for other objects
                                                                                    return JSON.stringify(logic, null, 2);
                                                                                }
                                                                                return String(logic);
                                                                            })()}
                                                                        </div>
                                                                    </AccordionContent>
                                                                </AccordionItem>
                                                            </Accordion>
                                                        </div>
                                                        <div className="flex-1 min-h-[180px] -my-4">
                                                            <LegitimacyVisualizer analysis={results['legitimacy'] as unknown as LegitimacyAnalysis} />
                                                        </div>
                                                    </div>
                                                </>
                                            )}

                                            {/* --- INSTITUTIONAL LOGICS LENS --- */}
                                            {lens.id === 'institutional_logics' && (
                                                <>
                                                    <div className="flex flex-col md:flex-row gap-4">
                                                        <div className="flex-1 space-y-2">
                                                            <div className="bg-emerald-50 border border-emerald-100 rounded-md p-3">
                                                                <span className="text-xs font-bold text-emerald-800 uppercase tracking-wide block mb-1">Dominant Logic</span>
                                                                <p className="font-semibold text-emerald-900 leading-tight">
                                                                    {results['institutional_logics']?.dominant_logic || 'Undetermined'}
                                                                </p>
                                                            </div>
                                                            <Accordion type="single" collapsible className="w-full">
                                                                <AccordionItem value="assessment" className="border-none">
                                                                    <AccordionTrigger className="py-2 text-xs font-medium text-slate-500 hover:text-emerald-600 hover:no-underline">
                                                                        View Overall Assessment
                                                                    </AccordionTrigger>
                                                                    <AccordionContent>
                                                                        <p className="text-xs leading-relaxed text-slate-600 bg-slate-50 p-3 rounded-md border border-slate-100">
                                                                            {results['institutional_logics']?.overall_assessment || 'No assessment available.'}
                                                                        </p>
                                                                    </AccordionContent>
                                                                </AccordionItem>
                                                            </Accordion>
                                                        </div>
                                                        <div className="flex-1 min-h-[180px] -my-4">
                                                            <LogicsVisualizer analysis={results['institutional_logics']!} />
                                                        </div>
                                                    </div>
                                                </>
                                            )}

                                            {/* --- CULTURAL FRAMING --- */}
                                            {lens.id === 'cultural_framing' && results['cultural_framing'] && (
                                                <CulturalFramingCard result={results['cultural_framing']} />
                                            )}

                                            {/* --- DECOLONIAL FRAMEWORK --- */}
                                            {lens.id === 'dsf' && (
                                                <div className="space-y-3">
                                                    <div className="bg-rose-50 border border-rose-100 rounded-md p-3">
                                                        <span className="text-xs font-bold text-rose-800 uppercase tracking-wide block mb-1">Key Dynamic</span>
                                                        <p className="font-semibold text-rose-900 leading-tight">
                                                            {results['dsf']?.key_insight || 'Undetermined'}
                                                        </p>
                                                    </div>
                                                    <Accordion type="single" collapsible className="w-full">
                                                        <AccordionItem value="praxis" className="border-none">
                                                            <AccordionTrigger className="py-2 text-xs font-medium text-slate-500 hover:text-rose-600 hover:no-underline">
                                                                Detailed Situated Praxis
                                                            </AccordionTrigger>
                                                            <AccordionContent>
                                                                <p className="text-xs leading-relaxed text-slate-600 bg-slate-50 p-3 rounded-md border border-slate-100">
                                                                    {results['dsf']?.reflexivity_situated_praxis || 'No detail available.'}
                                                                </p>
                                                            </AccordionContent>
                                                        </AccordionItem>
                                                    </Accordion>
                                                </div>
                                            )}


                                            {/* Voices Silenced Section (Shared across all lenses) */}
                                            {results[lens.id]?.silenced_voices && results[lens.id]!.silenced_voices!.length > 0 && (
                                                <div className="mt-4 pt-3 border-t border-slate-100">
                                                    <span className="text-xs font-bold text-red-600 uppercase tracking-wider block mb-2 flex items-center gap-1">
                                                        <VolumeX className="h-3 w-3" /> Voices Silenced
                                                    </span>
                                                    <ul className="space-y-1">
                                                        {results[lens.id]!.silenced_voices!.slice(0, expandedLens === lens.id ? undefined : 2).map((voice, idx) => (
                                                            <li key={idx} className="text-xs text-red-800 font-medium flex items-start gap-2">
                                                                <span className="block w-1 h-1 rounded-full bg-red-400 mt-1.5 shrink-0" />
                                                                {voice}
                                                            </li>
                                                        ))}
                                                        {results[lens.id]!.silenced_voices!.length > 2 && expandedLens !== lens.id && (
                                                            <li className="text-xs text-red-500 italic pl-3 cursor-pointer hover:underline" onClick={() => setExpandedLens(lens.id)}>
                                                                + {results[lens.id]!.silenced_voices!.length - 2} more (click to expand)
                                                            </li>
                                                        )}
                                                    </ul>
                                                </div>
                                            )}

                                            {expandedLens === lens.id && (
                                                <div className="mt-4 space-y-2 animate-in fade-in duration-300 pt-4 border-t border-slate-100">
                                                    <h4 className="font-medium text-slate-900">Raw Analysis Data</h4>
                                                    <pre className="whitespace-pre-wrap bg-slate-900 text-slate-50 p-4 rounded-md text-xs overflow-x-auto max-h-[300px]">
                                                        {JSON.stringify(results[lens.id], null, 2)}
                                                    </pre>
                                                </div>
                                            )}
                                        </div>
                                    ) : (
                                        <div className="h-40 flex flex-col items-center justify-center text-slate-400 bg-slate-50/50 rounded-md border border-dashed border-slate-200">
                                            <div className="p-3 bg-white rounded-full mb-2 shadow-sm">
                                                <Sparkles className="h-4 w-4 text-slate-300" />
                                            </div>
                                            <span className="text-xs font-medium">Waiting for analysis...</span>
                                        </div>
                                    )}
                                </CardContent>
                            </Card>
                        ))}
                    </div>

                    {/* System Critique (Devil's Advocate) */}
                    {results['dsf'] && results['dsf'].system_critique && (
                        <SystemCritiqueSection critique={results['dsf'].system_critique} />
                    )}
                </div>
            )}

            <EvidenceLineageModal
                isOpen={!!activeEvidence}
                onClose={() => setActiveEvidence(null)}
                title={activeEvidence?.title || ""}
                description="Verbatim text segments that triggered this classification."
                quotes={activeEvidence?.quotes || []}
                sourceType={activeEvidence?.type || "Trace"}
            />
        </div>
    );
}

import { useState } from "react";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Checkbox } from "@/components/ui/checkbox";
import { Loader2, Settings2, Globe, BookOpen, AlertTriangle } from "lucide-react";
import { PositionalityData } from "@/types";

interface PositionalityDialogProps {
    isOpen: boolean;
    onClose: () => void;
    onConfirm: (data: PositionalityData) => void;
}

export function PositionalityDialog({ isOpen, onClose, onConfirm }: PositionalityDialogProps) {
    const [locus, setLocus] = useState("");
    const [discipline, setDiscipline] = useState("");
    const [reflexiveGap, setReflexiveGap] = useState("");
    const [enableCounterNarrative, setEnableCounterNarrative] = useState(false);
    const [isSaving, setIsSaving] = useState(false);

    const handleConfirm = async () => {
        if (!locus || !discipline || !reflexiveGap) return;

        setIsSaving(true);
        const data: PositionalityData = {
            locus,
            discipline,
            reflexiveGap,
            enableCounterNarrative
        };

        try {
            // Save to logs
            const headers: HeadersInit = { 'Content-Type': 'application/json' };
            if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true' && process.env.NEXT_PUBLIC_DEMO_USER_ID) {
                headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID;
            }

            await fetch('/api/logs', {
                method: 'POST',
                headers: headers,
                body: JSON.stringify({
                    action: "Positionality Calibration",
                    details: {
                        ...data,
                        context: "Pre-Analysis Calibration"
                    }
                })
            });

            onConfirm(data);
            // Reset for next time
            setLocus("");
            setDiscipline("");
            setReflexiveGap("");
            setEnableCounterNarrative(false);
        } catch (error) {
            console.error("Failed to save positionality statement", error);
            onConfirm(data);
        } finally {
            setIsSaving(false);
        }
    };

    return (
        <Dialog open={isOpen} onOpenChange={(open) => !open && onClose()}>
            <DialogContent className="sm:max-w-[600px] max-h-[90vh] overflow-y-auto">
                <DialogHeader>
                    <div className="flex items-center gap-2 text-indigo-600 mb-2">
                        <Settings2 className="h-5 w-5" />
                        <span className="text-xs font-bold uppercase tracking-wider">System Calibration</span>
                    </div>
                    <DialogTitle className="text-xl">Calibrate Interpretive Lenses</DialogTitle>
                    <DialogDescription>
                        Instant TEA uses your inputs to adjust its "Decolonial Prompts" and flag potential cultural misunderstandings.
                    </DialogDescription>
                </DialogHeader>

                <div className="space-y-6 py-4">
                    {/* Part 1: Locus of Enunciation */}
                    <div className="space-y-4 p-4 bg-slate-50 rounded-lg border border-slate-200">
                        <h5 className="text-sm font-bold text-slate-900 uppercase flex items-center gap-2">
                            <Globe className="h-4 w-4 text-slate-500" />
                            Part 1: Locus of Enunciation
                        </h5>
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <Label className="text-xs">Geographic Locus</Label>
                                <Select value={locus} onValueChange={setLocus}>
                                    <SelectTrigger>
                                        <SelectValue placeholder="Select Region" />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="Global North">Global North</SelectItem>
                                        <SelectItem value="Global South">Global South</SelectItem>
                                        <SelectItem value="Indigenous">Indigenous / First Nations</SelectItem>
                                        <SelectItem value="Diasporic">Diasporic</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>
                            <div className="space-y-2">
                                <Label className="text-xs">Disciplinary Lens</Label>
                                <Select value={discipline} onValueChange={setDiscipline}>
                                    <SelectTrigger>
                                        <SelectValue placeholder="Select Discipline" />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="Legal">Legal / Regulatory</SelectItem>
                                        <SelectItem value="Technical">Technical / Engineering</SelectItem>
                                        <SelectItem value="Sociological">Sociological / STS</SelectItem>
                                        <SelectItem value="Activist">Activist / Civil Society</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>
                        </div>
                    </div>

                    {/* Part 2: Epistemic Distance */}
                    <div className="space-y-4">
                        <h5 className="text-sm font-bold text-slate-900 uppercase flex items-center gap-2">
                            <BookOpen className="h-4 w-4 text-slate-500" />
                            Part 2: Epistemic Distance
                        </h5>
                        <div className="space-y-2">
                            <Label className="text-xs">Reflexive Gap Prediction</Label>
                            <p className="text-xs text-slate-500 mb-2">
                                Given your Locus ({locus || "..."}) and the Target Document, what specific concepts might you misinterpret?
                            </p>
                            <Textarea
                                placeholder="e.g., 'I might default to individual privacy definitions instead of communal data rights.'"
                                value={reflexiveGap}
                                onChange={(e) => setReflexiveGap(e.target.value)}
                                className="min-h-[80px]"
                            />
                        </div>
                    </div>

                    {/* Part 3: Active Calibration */}
                    <div className="space-y-4 p-4 bg-indigo-50 rounded-lg border border-indigo-100">
                        <h5 className="text-sm font-bold text-indigo-900 uppercase flex items-center gap-2">
                            <Settings2 className="h-4 w-4" />
                            Part 3: Active Calibration
                        </h5>
                        <div className="flex items-start gap-3">
                            <Checkbox
                                id="counter-narrative"
                                checked={enableCounterNarrative}
                                onCheckedChange={(checked: boolean | "indeterminate") => setEnableCounterNarrative(checked === true)}
                                className="mt-1"
                            />
                            <div className="space-y-1">
                                <Label htmlFor="counter-narrative" className="font-semibold text-indigo-900 cursor-pointer">
                                    Enable "Counter-Narrative" Prompts
                                </Label>
                                <p className="text-xs text-indigo-700 leading-relaxed">
                                    Force the AI to re-summarize key findings from the perspective of marginalized actors identified in the text.
                                </p>
                            </div>
                        </div>
                    </div>
                </div>

                <DialogFooter>
                    <Button variant="outline" onClick={onClose}>Cancel</Button>
                    <Button
                        onClick={handleConfirm}
                        disabled={!locus || !discipline || !reflexiveGap || isSaving}
                        className="bg-indigo-600 hover:bg-indigo-700 text-white"
                    >
                        {isSaving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : null}
                        Save & Calibrate Engine
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

"use client";

import React from 'react';
import { ResponsiveContainer, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar, Legend, Tooltip } from 'recharts';
import { AnalysisResult, LegitimacyAnalysis } from '@/types';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Activity } from 'lucide-react';

interface SpectralRadarProps {
    results: Record<string, AnalysisResult | null>;
}

export function SpectralRadar({ results }: SpectralRadarProps) {
    // 1. Extract Governance Scores (if available)
    const governanceResult = results['institutional_logics']; // Often holds gov scores in this app structure, or 'governance' if key exists.
    // Actually, based on types, governance scores might be in any result if the prompt extracted them.
    // But usually it's specifically the "Institutional Logics" or a specific "Governance" lens.
    // Let's iterate and find the first result with governance scores.
    const govScores = Object.values(results).find(r => r?.governance_scores)?.governance_scores;

    // 2. Extract Legitimacy Orders
    const legitimacyResult = results['legitimacy'] as unknown as LegitimacyAnalysis | undefined;
    // Note: cast as LegitimacyAnalysis because the generic AnalysisResult might not fully capture the specific shape if types aren't perfectly unified.
    // Looking at src/types/index.ts, `legitimacy_analysis` is a property on Source, but `AnalysisResult` has `legitimacy_claims`. 
    // However, the `MultiLensAnalysis` component casts the result to `LegitimacyAnalysis` in `getKeyInsight`, so the result object ITSELF mirrors that structure for that lens.
    const legOrders = legitimacyResult?.orders;


    if (!govScores && !legOrders) {
        return null;
    }

    // 3. Transform Data for Radar Chart
    // We want to normalize everything to 0-10 scale if possible.
    // Governance scores are usually 0-10 or 0-1. Let's assume 0-10 based on typical prompt.
    // Legitimacy orders are 0-10.

    const data = [
        { subject: 'Market', A: legOrders?.market || 0, B: govScores?.market_power || 0, fullMark: 10 },
        { subject: 'Civic/Rights', A: legOrders?.civic || 0, B: govScores?.rights_focus || 0, fullMark: 10 },
        { subject: 'Industrial/Proc', A: legOrders?.industrial || 0, B: govScores?.procedurality || 0, fullMark: 10 },
        { subject: 'Domestic/Flex', A: legOrders?.domestic || 0, B: govScores?.flexibility || 0, fullMark: 10 },
        { subject: 'Inspiration/Cent', A: legOrders?.inspired || 0, B: govScores?.centralization || 0, fullMark: 10 },
        // { subject: 'Fame', A: legOrders?.fame || 0, B: 0, fullMark: 10 },
    ];

    return (
        <Card className="col-span-1 md:col-span-2 border-indigo-100 bg-slate-50/50">
            <CardHeader className="pb-2">
                <CardTitle className="text-base font-semibold flex items-center gap-2">
                    <Activity className="h-4 w-4 text-indigo-600" />
                    Diffractive Spectral Radar
                </CardTitle>
                <CardDescription className="text-xs">
                    Visualizing the interference pattern between Legitimacy Orders (Justification) and Governance Mechanics (Power).
                </CardDescription>
            </CardHeader>
            <CardContent className="h-[300px]">
                <ResponsiveContainer width="100%" height="100%">
                    <RadarChart cx="50%" cy="50%" outerRadius="80%" data={data}>
                        <PolarGrid stroke="#e2e8f0" />
                        <PolarAngleAxis dataKey="subject" tick={{ fill: '#64748b', fontSize: 10 }} />
                        <PolarRadiusAxis angle={30} domain={[0, 10]} tick={false} axisLine={false} />

                        <Radar
                            name="Legitimacy (Justification)"
                            dataKey="A"
                            stroke="#8884d8"
                            strokeWidth={2}
                            fill="#8884d8"
                            fillOpacity={0.3}
                        />
                        <Radar
                            name="Governance (Mechanics)"
                            dataKey="B"
                            stroke="#82ca9d"
                            strokeWidth={2}
                            fill="#82ca9d"
                            fillOpacity={0.3}
                        />
                        <Legend wrapperStyle={{ fontSize: '12px', paddingTop: '10px' }} />
                        <Tooltip
                            contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#f8fafc' }}
                            itemStyle={{ color: '#f8fafc' }}
                        />
                    </RadarChart>
                </ResponsiveContainer>
            </CardContent>
        </Card>
    );
}

"use client"

import { useState } from "react";
import { ResistanceArtifact, ArtifactAnalysisResult } from "@/types/resistance";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Loader2, Sparkles, BookOpen, MessageCircle, Network } from "lucide-react";
import { useDemoMode } from "@/hooks/useDemoMode";

interface DiscourseAnalyzerProps {
    artifact: ResistanceArtifact;
    onAnalysisComplete?: (analysis: ArtifactAnalysisResult) => void;
}

export function DiscourseAnalyzer({ artifact, onAnalysisComplete }: DiscourseAnalyzerProps) {
    const { isReadOnly } = useDemoMode();
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [analysis, setAnalysis] = useState<ArtifactAnalysisResult | null>(
        artifact.frames ? {
            artifact_id: artifact.id,
            frames: artifact.frames,
            strategies: artifact.rhetorical_strategies || [],
            reconfiguration: artifact.reconfiguration_potential,
            generated_at: new Date().toISOString()
        } : null
    );

    const handleAnalyze = async () => {
        setIsAnalyzing(true);
        try {
            const headers: HeadersInit = { 'Content-Type': 'application/json' };
            if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true') {
                headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID || 'demo-user';
            }

            const response = await fetch('/api/resistance/analyze', {
                method: 'POST',
                headers: headers,
                body: JSON.stringify({
                    artifact_id: artifact.id,
                    artifact_text: artifact.text,
                    analysis_type: 'full'
                })
            });

            const data = await response.json();
            if (data.success) {
                setAnalysis(data.analysis);
                onAnalysisComplete?.(data.analysis);
            }
        } catch (error) {
            console.error('Analysis failed:', error);
        } finally {
            setIsAnalyzing(false);
        }
    };

    return (
        <div className="space-y-6">
            {/* Analysis Trigger */}
            {!analysis && (
                <Card>
                    <CardContent className="py-8 text-center">
                        <Sparkles className="h-12 w-12 text-purple-500 mx-auto mb-4" />
                        <h3 className="font-semibold text-lg mb-2">Discourse Analysis</h3>
                        <p className="text-sm text-slate-600 mb-4 max-w-md mx-auto">
                            Analyze this artifact to extract discourse frames, rhetorical strategies,
                            and assemblage reconfiguration potential.
                        </p>
                        <Button onClick={handleAnalyze} disabled={isAnalyzing || isReadOnly} title={isReadOnly ? "Analysis disabled in Demo Mode" : ""}>
                            {isAnalyzing ? (
                                <>
                                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                    Analyzing...
                                </>
                            ) : (
                                <>
                                    <Sparkles className="mr-2 h-4 w-4" />
                                    Run Discourse Analysis
                                </>
                            )}
                        </Button>
                        <p className="text-xs text-slate-500 text-center mt-2">
                            <span className="inline-flex items-center gap-1">
                                <Sparkles className="w-3 h-3 text-indigo-400" />
                                AI inputs processed by OpenAI (GPT-5.1) & Google (Gemini 3 Pro / Search).
                            </span>
                        </p>
                    </CardContent>
                </Card>
            )}

            {/* Analysis Results */}
            {analysis && (
                <>
                    {/* Discourse Frames */}
                    {analysis.frames && analysis.frames.length > 0 && (
                        <Card>
                            <CardHeader>
                                <div className="flex items-center gap-2">
                                    <BookOpen className="h-5 w-5 text-blue-600" />
                                    <CardTitle className="text-lg">Discourse Frames</CardTitle>
                                </div>
                            </CardHeader>
                            <CardContent className="space-y-4">
                                {analysis.frames.map((frame, idx) => (
                                    <div key={idx} className="border-l-4 border-blue-500 pl-4 py-2">
                                        <h4 className="font-bold text-slate-900">{frame.frame_name}</h4>
                                        <p className="text-sm text-slate-700 mt-1">{frame.description}</p>
                                        {frame.evidence_quotes && frame.evidence_quotes.length > 0 && (
                                            <div className="mt-3 space-y-2">
                                                {frame.evidence_quotes.map((quote, qIdx) => (
                                                    <blockquote key={qIdx} className="text-xs text-slate-600 italic pl-3 border-l-2 border-slate-200">
                                                        "{quote}"
                                                    </blockquote>
                                                ))}
                                            </div>
                                        )}
                                    </div>
                                ))}
                            </CardContent>
                        </Card>
                    )}

                    {/* Rhetorical Strategies */}
                    {analysis.strategies && analysis.strategies.length > 0 && (
                        <Card>
                            <CardHeader>
                                <div className="flex items-center gap-2">
                                    <MessageCircle className="h-5 w-5 text-green-600" />
                                    <CardTitle className="text-lg">Rhetorical Strategies</CardTitle>
                                </div>
                            </CardHeader>
                            <CardContent className="space-y-4">
                                {analysis.strategies.map((strategy, idx) => (
                                    <div key={idx} className="bg-green-50 p-4 rounded-lg">
                                        <div className="flex items-start justify-between">
                                            <Badge className="bg-green-200 text-green-800">
                                                {strategy.strategy.replace('_', ' ')}
                                            </Badge>
                                        </div>
                                        <p className="text-sm text-slate-700 mt-2">{strategy.description}</p>
                                        <p className="text-xs text-slate-600 mt-2 italic">
                                            Example: "{strategy.example}"
                                        </p>
                                    </div>
                                ))}
                            </CardContent>
                        </Card>
                    )}

                    {/* Assemblage Reconfiguration */}
                    {analysis.reconfiguration && (
                        <Card className="border-2 border-purple-200">
                            <CardHeader className="bg-purple-50">
                                <div className="flex items-center gap-2">
                                    <Network className="h-5 w-5 text-purple-600" />
                                    <CardTitle className="text-lg">Assemblage Reconfiguration Analysis</CardTitle>
                                </div>
                            </CardHeader>
                            <CardContent className="space-y-4 pt-6">
                                <div>
                                    <h4 className="font-semibold text-sm text-purple-900 mb-1">Deterritorializes:</h4>
                                    <p className="text-sm text-slate-700">{analysis.reconfiguration.deterritorializes}</p>
                                </div>

                                <div>
                                    <h4 className="font-semibold text-sm text-purple-900 mb-1">Recodes:</h4>
                                    <p className="text-sm text-slate-700">{analysis.reconfiguration.recodes}</p>
                                </div>

                                {analysis.reconfiguration.new_connections && (
                                    <div>
                                        <h4 className="font-semibold text-sm text-purple-900 mb-2">New Connections:</h4>
                                        <ul className="space-y-1">
                                            {analysis.reconfiguration.new_connections.map((conn, idx) => (
                                                <li key={idx} className="text-sm text-slate-700 flex items-start gap-2">
                                                    <span className="text-purple-500 mt-1">→</span>
                                                    <span>{conn}</span>
                                                </li>
                                            ))}
                                        </ul>
                                    </div>
                                )}

                                {analysis.reconfiguration.lines_of_flight && (
                                    <div>
                                        <h4 className="font-semibold text-sm text-purple-900 mb-2">Lines of Flight:</h4>
                                        <ul className="space-y-1">
                                            {analysis.reconfiguration.lines_of_flight.map((line, idx) => (
                                                <li key={idx} className="text-sm text-slate-700 flex items-start gap-2">
                                                    <span className="text-purple-500 mt-1">↗</span>
                                                    <span>{line}</span>
                                                </li>
                                            ))}
                                        </ul>
                                    </div>
                                )}

                                <div className="pt-4 border-t border-purple-100">
                                    <h4 className="font-semibold text-sm text-purple-900 mb-2">Theoretical Contribution:</h4>
                                    <p className="text-sm text-slate-800 leading-relaxed bg-white p-3 rounded border border-purple-100">
                                        {analysis.reconfiguration.theoretical_contribution}
                                    </p>
                                </div>

                                {analysis.reconfiguration.empirical_evidence && (
                                    <div>
                                        <h4 className="font-semibold text-sm text-purple-900 mb-2">Empirical Evidence:</h4>
                                        <blockquote className="text-xs text-slate-600 italic pl-3 border-l-2 border-purple-200">
                                            {analysis.reconfiguration.empirical_evidence}
                                        </blockquote>
                                    </div>
                                )}
                            </CardContent>
                        </Card>
                    )}

                    {/* Re-analyze button */}
                    <div className="flex justify-center">
                        <Button variant="outline" onClick={handleAnalyze} disabled={isAnalyzing || isReadOnly} title={isReadOnly ? "Analysis disabled in Demo Mode" : ""}>
                            {isAnalyzing ? (
                                <>
                                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                    Re-analyzing...
                                </>
                            ) : (
                                <>
                                    <Sparkles className="mr-2 h-4 w-4" />
                                    Re-run Analysis
                                </>
                            )}
                        </Button>
                    </div>
                </>
            )}
        </div>
    );
}

"use client"

import { ResistanceArtifact, ReconfigurationAnalysis } from "@/types/resistance";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { ArrowRight, Network } from "lucide-react";

interface ReconfigurationTrackerProps {
    artifact: ResistanceArtifact;
    targetPolicyTitle?: string;
}

export function ReconfigurationTracker({ artifact, targetPolicyTitle }: ReconfigurationTrackerProps) {
    const reconfig = artifact.reconfiguration_potential;

    if (!reconfig) {
        return null;
    }

    return (
        <Card className="border-2 border-purple-200 bg-gradient-to-br from-purple-50 to-white">
            <CardHeader className="bg-purple-100/50">
                <div className="flex items-center gap-2">
                    <Network className="h-5 w-5 text-purple-600" />
                    <CardTitle>Assemblage Reconfiguration Dynamics</CardTitle>
                </div>
                {targetPolicyTitle && (
                    <p className="text-sm text-slate-600 mt-2">
                        Target: <span className="font-semibold">{targetPolicyTitle}</span>
                    </p>
                )}
            </CardHeader>
            <CardContent className="pt-6">
                {/* Three-Stage Flow */}
                <div className="grid md:grid-cols-3 gap-4 mb-6">
                    {/* Before State */}
                    <div className="space-y-2">
                        <Badge className="bg-slate-200 text-slate-800">Before</Badge>
                        <div className="p-4 bg-slate-50 rounded-lg border border-slate-200 min-h-[120px]">
                            <p className="text-xs font-semibold text-slate-500 uppercase mb-2">
                                Original Configuration
                            </p>
                            <p className="text-sm text-slate-700">
                                {getBeforeState(reconfig)}
                            </p>
                        </div>
                    </div>

                    {/* Arrow */}
                    <div className="hidden md:flex items-center justify-center">
                        <ArrowRight className="h-8 w-8 text-purple-400" />
                    </div>

                    {/* After State */}
                    <div className="space-y-2">
                        <Badge className="bg-purple-200 text-purple-800">After</Badge>
                        <div className="p-4 bg-purple-50 rounded-lg border border-purple-200 min-h-[120px]">
                            <p className="text-xs font-semibold text-purple-600 uppercase mb-2">
                                Proposed Reconfiguration
                            </p>
                            <p className="text-sm text-slate-700">
                                {reconfig.recodes}
                            </p>
                        </div>
                    </div>
                </div>

                {/* Intervention */}
                <div className="mb-6 p-4 bg-yellow-50 border-l-4 border-yellow-400 rounded">
                    <p className="text-xs font-semibold text-yellow-800 uppercase mb-2">
                        Resistance Intervention
                    </p>
                    <p className="text-sm text-slate-700">
                        <strong>{artifact.title}</strong> deterritorializes: {reconfig.deterritorializes}
                    </p>
                </div>

                {/* Dynamics Grid */}
                <div className="grid md:grid-cols-2 gap-4 mb-6">
                    {/* New Connections */}
                    {reconfig.new_connections && reconfig.new_connections.length > 0 && (
                        <div className="p-4 bg-blue-50 rounded-lg border border-blue-200">
                            <h4 className="text-sm font-bold text-blue-900 mb-3 flex items-center gap-2">
                                <span className="text-blue-500">⚡</span>
                                New Connections Enabled
                            </h4>
                            <ul className="space-y-2">
                                {reconfig.new_connections.map((conn, idx) => (
                                    <li key={idx} className="text-xs text-slate-700 flex items-start gap-2">
                                        <span className="text-blue-500 mt-0.5">→</span>
                                        <span>{conn}</span>
                                    </li>
                                ))}
                            </ul>
                        </div>
                    )}

                    {/* Lines of Flight */}
                    {reconfig.lines_of_flight && reconfig.lines_of_flight.length > 0 && (
                        <div className="p-4 bg-green-50 rounded-lg border border-green-200">
                            <h4 className="text-sm font-bold text-green-900 mb-3 flex items-center gap-2">
                                <span className="text-green-500">↗</span>
                                Lines of Flight (Escape Routes)
                            </h4>
                            <ul className="space-y-2">
                                {reconfig.lines_of_flight.map((line, idx) => (
                                    <li key={idx} className="text-xs text-slate-700 flex items-start gap-2">
                                        <span className="text-green-500 mt-0.5">↗</span>
                                        <span>{line}</span>
                                    </li>
                                ))}
                            </ul>
                        </div>
                    )}
                </div>

                {/* Theoretical Insight */}
                <div className="p-5 bg-white rounded-lg border-2 border-purple-200 shadow-sm">
                    <h4 className="text-sm font-bold text-purple-900 mb-3 flex items-center gap-2">
                        💡 Theoretical Contribution
                    </h4>
                    <p className="text-sm text-slate-800 leading-relaxed">
                        {reconfig.theoretical_contribution}
                    </p>
                </div>

                {/* Empirical Grounding */}
                {reconfig.empirical_evidence && (
                    <div className="mt-4 p-4 bg-slate-50 rounded border border-slate-200">
                        <h4 className="text-xs font-semibold text-slate-600 uppercase mb-2">
                            Empirical Evidence
                        </h4>
                        <blockquote className="text-xs text-slate-700 italic border-l-2 border-slate-300 pl-3">
                            "{reconfig.empirical_evidence}"
                        </blockquote>
                    </div>
                )}
            </CardContent>
        </Card>
    );
}

// Helper to infer "before state" from deterritorialization
function getBeforeState(reconfig: ReconfigurationAnalysis): string {
    // Extract what was being deterritorialized as the "before" state
    return reconfig.deterritorializes;
}

"use client"

import { ResistanceArtifact } from "@/types/resistance";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { ArrowLeft, FileText, Calendar, User } from "lucide-react";
import { DiscourseAnalyzer } from "./DiscourseAnalyzer";
import { ReconfigurationTracker } from "./ReconfigurationTracker";
import { Badge } from "@/components/ui/badge";

interface ResistanceArtifactViewProps {
    artifact: ResistanceArtifact;
    onBack: () => void;
    onUpdate?: (updatedArtifact: ResistanceArtifact) => void;
}

export function ResistanceArtifactView({ artifact, onBack, onUpdate }: ResistanceArtifactViewProps) {
    const handleAnalysisComplete = (analysis: any) => {
        const updatedArtifact = {
            ...artifact,
            frames: analysis.frames,
            rhetorical_strategies: analysis.strategies,
            reconfiguration_potential: analysis.reconfiguration
        };
        onUpdate?.(updatedArtifact);
    };
    return (
        <div className="space-y-6">
            <Button variant="ghost" className="mb-2" onClick={onBack}>
                <ArrowLeft className="mr-2 h-4 w-4" />
