"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle, CardFooter } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { AlertTriangle, Trash2 } from "lucide-react";
import { useClerk } from "@clerk/nextjs";
import { useRouter } from "next/navigation";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
    AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { toast } from "sonner";

export function DeleteAccountSection() {
    const { signOut } = useClerk();
    const router = useRouter();
    const [isDeleting, setIsDeleting] = useState(false);
    const [confirmationText, setConfirmationText] = useState("");

    const handleDelete = async () => {
        if (confirmationText !== "DELETE") return;

        setIsDeleting(true);
        try {
            const res = await fetch("/api/user/delete", {
                method: "DELETE",
            });

            if (!res.ok) throw new Error("Failed to delete account");

            toast.success("Account deleted successfully");
            await signOut();
            router.push("/");
        } catch (error) {
            console.error(error);
            toast.error("Failed to delete account. Please try again.");
            setIsDeleting(false);
        }
    };

    return (
        <Card className="border-red-500/20 bg-red-950/10 mt-8">
            <CardHeader>
                <CardTitle className="text-red-600 flex items-center gap-2">
                    <AlertTriangle className="h-5 w-5" />
                    Danger Zone
                </CardTitle>
                <CardDescription>
                    Irreversible account actions.
                </CardDescription>
            </CardHeader>
            <CardContent>
                <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                    <div>
                        <h4 className="text-slate-900 dark:text-slate-200 font-medium">Delete Account</h4>
                        <p className="text-sm text-slate-500">
                            Permanently remove your account and all associated data. This action cannot be undone.
                        </p>
                    </div>

                    <AlertDialog>
                        <AlertDialogTrigger asChild>
                            <Button variant="destructive" className="bg-red-600 hover:bg-red-700">
                                <Trash2 className="mr-2 h-4 w-4" />
                                Delete Account
                            </Button>
                        </AlertDialogTrigger>
                        <AlertDialogContent className="bg-slate-950 text-slate-200 border-slate-800">
                            <AlertDialogHeader>
                                <AlertDialogTitle className="text-red-500">Are you absolutely sure?</AlertDialogTitle>
                                <AlertDialogDescription className="text-slate-400">
                                    This will permanently delete your account and remove your data from our servers.
                                    <br /><br />
                                    To confirm, type <strong>DELETE</strong> below:
                                </AlertDialogDescription>
                            </AlertDialogHeader>
                            <div className="py-4">
                                <Input
                                    value={confirmationText}
                                    onChange={(e) => setConfirmationText(e.target.value)}
                                    placeholder="Type DELETE to confirm"
                                    className="bg-slate-900 border-red-900/50 text-white placeholder:text-slate-600"
                                />
                            </div>
                            <AlertDialogFooter>
                                <AlertDialogCancel className="bg-slate-900 text-slate-300 hover:bg-slate-800 border-slate-700">Cancel</AlertDialogCancel>
                                <AlertDialogAction
                                    onClick={(e) => {
                                        e.preventDefault();
                                        handleDelete();
                                    }}
                                    disabled={confirmationText !== "DELETE" || isDeleting}
                                    className="bg-red-600 hover:bg-red-700 text-white"
                                >
                                    {isDeleting ? "Deleting..." : "Confirm Deletion"}
                                </AlertDialogAction>
                            </AlertDialogFooter>
                        </AlertDialogContent>
                    </AlertDialog>
                </div>
            </CardContent>
        </Card>
    );
}

"use client";

import { ProvenanceChain } from "@/types/provenance";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { ChevronDown, ChevronRight, Copy, FileText, Sparkles, Code, CheckCircle } from "lucide-react";
import { useState } from "react";

interface ProvenanceViewerProps {
    provenance?: ProvenanceChain;
}

/**
 * Visual flowchart showing the complete reasoning chain from source to insight
 * Each step is expandable to show full details including raw JSON
 */
export function ProvenanceViewer({ provenance }: ProvenanceViewerProps) {
    const [expandedSteps, setExpandedSteps] = useState<Set<number>>(new Set());

    if (!provenance) {
        return (
            <div className="text-sm text-slate-400 italic">
                Provenance chain not available for this analysis
            </div>
        );
    }

    const toggleStep = (index: number) => {
        const newExpanded = new Set(expandedSteps);
        if (newExpanded.has(index)) {
            newExpanded.delete(index);
        } else {
            newExpanded.add(index);
        }
        setExpandedSteps(newExpanded);
    };

    const getStepIcon = (type?: string) => {
        if (!type) return <Sparkles className="h-4 w-4" />;
        switch (type) {
            case 'source_extraction': return <FileText className="h-4 w-4" />;
            case 'prompt_generation': return <Code className="h-4 w-4" />;
            case 'ai_response': return <Sparkles className="h-4 w-4" />;
            case 'formatting': return <CheckCircle className="h-4 w-4" />;
            default: return <Sparkles className="h-4 w-4" />;
        }
    };

    const getStepLabel = (type: string) => {
        switch (type) {
            case 'source_extraction': return 'Source Text Extraction';
            case 'prompt_generation': return 'Prompt Generation';
            case 'ai_response': return 'AI Response';
            case 'formatting': return 'Formatting & Structuring';
            default: return type;
        }
    };

    const copyToClipboard = (text: string) => {
        navigator.clipboard.writeText(text);
    };

    return (
        <Card className="border-purple-200 bg-purple-50/30">
            <CardHeader>
                <CardTitle className="text-sm font-semibold text-purple-900 flex items-center gap-2">
                    <Sparkles className="h-4 w-4" />
                    Provenance Chain
                </CardTitle>
                <p className="text-xs text-slate-600">
                    Created: {new Date(provenance.created_at).toLocaleString()}
                </p>
            </CardHeader>
            <CardContent>
                <div className="space-y-3">
                    {provenance.steps.map((step, index) => {
                        const isExpanded = expandedSteps.has(index);
                        const isLast = index === provenance.steps.length - 1;

                        return (
                            <div key={index} className="relative">
                                {/* Step Card */}
                                <div className="bg-white border border-slate-200 rounded-lg overflow-hidden">
                                    {/* Step Header */}
                                    <button
                                        onClick={() => toggleStep(index)}
                                        className="w-full p-3 flex items-center justify-between hover:bg-slate-50 transition-colors"
                                    >
                                        <div className="flex items-center gap-2">
                                            <Badge variant="outline" className="text-xs">
                                                Step {index + 1}
                                            </Badge>
                                            {getStepIcon(step.type)}
                                            <span className="text-sm font-medium text-slate-700">
                                                {step.description}
                                            </span>
                                        </div>
                                        {isExpanded ? (
                                            <ChevronDown className="h-4 w-4 text-slate-400" />
                                        ) : (
                                            <ChevronRight className="h-4 w-4 text-slate-400" />
                                        )}
                                    </button>

                                    {/* Expanded Content */}
                                    {isExpanded && (
                                        <div className="p-3 pt-0 space-y-3 border-t border-slate-100">
                                            {/* Agent and Info */}
                                            <div className="flex justify-between items-center text-[10px] text-slate-400 uppercase tracking-wider">
                                                <span>Agent: {step.agent}</span>
                                                <span>ID: {step.step_id}</span>
                                            </div>

                                            {/* Inputs */}
                                            {Object.keys(step.inputs).length > 0 && (
                                                <div>
                                                    <p className="text-xs font-medium text-slate-600 mb-1">Inputs:</p>
                                                    <div className="space-y-2">
                                                        {Object.entries(step.inputs).map(([key, val]) => (
                                                            <div key={key}>
                                                                <div className="flex items-center justify-between mb-0.5">
                                                                    <span className="text-[10px] text-slate-400">{key}:</span>
                                                                    <Button
                                                                        variant="ghost"
                                                                        size="sm"
                                                                        onClick={() => copyToClipboard(typeof val === 'string' ? val : JSON.stringify(val, null, 2))}
                                                                        className="h-5 text-[10px]"
                                                                    >
                                                                        Copy
                                                                    </Button>
                                                                </div>
                                                                <pre className="text-[10px] bg-slate-50 p-2 rounded border border-slate-200 overflow-x-auto max-h-32">
                                                                    <code>{typeof val === 'string' ? val : JSON.stringify(val, null, 2)}</code>
                                                                </pre>
                                                            </div>
                                                        ))}
                                                    </div>
                                                </div>
                                            )}

                                            {/* Outputs */}
                                            {Object.keys(step.outputs).length > 0 && (
                                                <div>
                                                    <p className="text-xs font-medium text-slate-600 mb-1">Outputs:</p>
                                                    <div className="space-y-2">
                                                        {Object.entries(step.outputs).map(([key, val]) => (
                                                            <div key={key}>
                                                                <div className="flex items-center justify-between mb-0.5">
                                                                    <span className="text-[10px] text-slate-400">{key}:</span>
                                                                    <Button
                                                                        variant="ghost"
                                                                        size="sm"
                                                                        onClick={() => copyToClipboard(typeof val === 'string' ? val : JSON.stringify(val, null, 2))}
                                                                        className="h-5 text-[10px]"
                                                                    >
                                                                        Copy
                                                                    </Button>
                                                                </div>
                                                                <pre className="text-[10px] bg-green-50/50 p-2 rounded border border-green-100 overflow-x-auto max-h-32">
                                                                    <code>{typeof val === 'string' ? val : JSON.stringify(val, null, 2)}</code>
                                                                </pre>
                                                            </div>
                                                        ))}
                                                    </div>
                                                </div>
                                            )}

                                            {/* Timestamp */}
                                            <p className="text-[10px] text-slate-400 text-right">
                                                Executed: {new Date(step.timestamp).toLocaleString()}
                                            </p>
                                        </div>
                                    )}
                                </div>

                                {/* Arrow to next step */}
                                {!isLast && (
                                    <div className="flex justify-center my-2">
                                        <div className="w-0.5 h-4 bg-slate-300"></div>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            </CardContent>
        </Card>
    );
}

import React, { useState, useCallback, useRef } from 'react';
import { Upload, FileType } from 'lucide-react';
import { cn } from "@/lib/utils";

interface FileDropZoneProps {
    onFilesDropped: (files: File[]) => void;
    children?: React.ReactNode;
    className?: string;
    accept?: string[]; // e.g. ['.pdf', '.docx']
    isReadOnly?: boolean;
}

export function FileDropZone({
    onFilesDropped,
    children,
    className,
    accept = ['.pdf', '.docx', '.doc'],
    isReadOnly = false
}: FileDropZoneProps) {
    const [isDragging, setIsDragging] = useState(false);
    const overlayRef = useRef<HTMLDivElement>(null);

    const handleDragEnter = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        e.stopPropagation();
        if (isReadOnly) return;
        setIsDragging(true);
    }, [isReadOnly]);

    const handleDragLeave = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        e.stopPropagation();
        // Only set false if leaving the main container, not entering a child
        if (e.target === overlayRef.current) {
            setIsDragging(false);
        }
    }, []);

    const handleDragOver = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        e.stopPropagation();
        if (isReadOnly) {
            e.dataTransfer.dropEffect = 'none';
            return;
        }
        e.dataTransfer.dropEffect = 'copy';
    }, [isReadOnly]);

    const handleDrop = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        e.stopPropagation();
        setIsDragging(false);

        if (isReadOnly) return;

        const files = Array.from(e.dataTransfer.files);
        if (files.length === 0) return;

        // Filter by extensions if provided
        const validFiles = files.filter(file => {
            const ext = '.' + file.name.split('.').pop()?.toLowerCase();
            return accept.includes(ext);
        });

        if (validFiles.length > 0) {
            onFilesDropped(validFiles);
        } else {
            // Maybe alert or callback error? For now silent rejection of invalid types.
            // Or we pass all and let parent decide. But filtering here is good UX.
            // Let's fallback to passing them if extension check is loose.
            // Actually, simplest is to pass them and let parent validate.
            // But for now, let's filter.
        }
    }, [onFilesDropped, accept, isReadOnly]);

    return (
        <div
            className={cn("relative transition-all", className)}
            onDragEnter={handleDragEnter}
            onDragOver={handleDragOver}
            onDragLeave={handleDragLeave} // Captures bubbling leaves from children
            onDrop={handleDrop}
        >
            {children}

            {/* Drag Overlay */}
            {isDragging && !isReadOnly && (
                <div
                    ref={overlayRef}
                    className="absolute inset-0 z-50 rounded-xl bg-indigo-50/90 border-2 border-dashed border-indigo-400 flex flex-col items-center justify-center backdrop-blur-sm animate-in fade-in duration-200"
                    onDragLeave={() => setIsDragging(false)} // Double check leave on overlay
                    onDrop={handleDrop}
                >
                    <div className="bg-white p-4 rounded-full shadow-lg mb-4 pointer-events-none">
                        <Upload className="h-8 w-8 text-indigo-600 animate-bounce" />
                    </div>
                    <h3 className="text-xl font-bold text-indigo-900 pointer-events-none">Drop to Upload</h3>
                    <p className="text-indigo-600 font-medium pointer-events-none">PDF or Word Documents</p>
                </div>
            )}
        </div>
    );
}

