import { useState, useEffect } from 'react';
import { useDemoMode } from './useDemoMode';
import { useWorkspace } from '@/providers/WorkspaceProvider';

export function useCredits() {
    const { currentWorkspaceId } = useWorkspace();
    const [credits, setCredits] = useState<number | null>(null);
    const [loading, setLoading] = useState(true);
    const { isReadOnly } = useDemoMode();

    const fetchCredits = async () => {
        if (isReadOnly) {
            setCredits(0);
            setLoading(false);
            return;
        }

        try {
            const headers: HeadersInit = {};
            if (currentWorkspaceId) {
                headers['x-workspace-id'] = currentWorkspaceId;
            }

            const response = await fetch('/api/credits', { headers });
            if (response.ok) {
                const data = await response.json();
                setCredits(data.credits);
            }
        } catch (error) {
            console.error('Failed to fetch credits:', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchCredits();
    }, [isReadOnly, currentWorkspaceId]);

    return {
        credits,
        loading,
        refetch: fetchCredits,
        hasCredits: (credits !== null && credits > 0)
    };
}

import { useEffect, useRef, useState, useMemo } from 'react';
import * as d3 from 'd3';
import { EcosystemActor } from '@/types/ecosystem';

export interface SimulationNode extends d3.SimulationNodeDatum {
    id: string;
    name: string;
    type: string;
    radius: number;
    x?: number;
    y?: number;
    vx?: number;
    vy?: number;
    metrics?: any;
    // Radial Layout Props
    assemblageId?: string;
    startAngle?: number;
    endAngle?: number;
    // [NEW] Trace Mode Animation Support
    isHidden?: boolean;
}

export interface SimulationLink extends d3.SimulationLinkDatum<SimulationNode> {
    source: string | SimulationNode;
    target: string | SimulationNode;
    type: string;
}

// Helper to determine Ring Radius based on Actor Type
const getRadialRadius = (type: string, minDim: number) => {
    const t = type.toLowerCase();
    if (['legalobject', 'regulation', 'law'].some(k => t.includes(k))) return 0; // Center
    if (['policymaker', 'government'].some(k => t.includes(k))) return minDim * 0.15;
    if (['civilsociety', 'academic', 'ngo'].some(k => t.includes(k))) return minDim * 0.25;
    if (['market', 'private', 'startup'].some(k => t.includes(k))) return minDim * 0.35;
    return minDim * 0.45; // Outer
};

export function useForceGraph(
    actors: EcosystemActor[],
    width: number,
    height: number,
    configurations: { id: string; memberIds: string[] }[] = [],
    links: { source: string; target: string; type: string }[] = [],
    enableClustering: boolean = false, // Nested Mode (Static Radial)
    isPaused: boolean = false,
    configOffsets: Record<string, { x: number; y: number }> = {},
    enableMetricAlignment: boolean = false // Compass Mode (Physics)
) {
    const [nodes, setNodes] = useState<SimulationNode[]>([]);
    const simulationRef = useRef<d3.Simulation<SimulationNode, SimulationLink> | null>(null);
    const nodesRef = useRef<SimulationNode[]>([]);

    // 1. Initialize Nodes (Preserve State)
    useEffect(() => {
        const currentNodes = nodesRef.current;

        // Identify which config each actor belongs to (first match wins)
        const getAssemblageId = (actorId: string) => {
            const config = configurations.find(c => c.memberIds.includes(actorId));
            return config ? config.id : 'ungrouped';
        };

        const newNodes = actors.map(actor => {
            const existing = currentNodes.find(n => n.id === actor.id);
            const assemblageId = getAssemblageId(actor.id);

            if (existing) {
                existing.name = actor.name;
                existing.radius = actor.influence === 'High' ? 45 : actor.influence === 'Medium' ? 30 : 20;
                existing.metrics = actor.metrics;
                existing.assemblageId = assemblageId;
                return existing;
            }
            return {
                id: actor.id,
                name: actor.name,
                type: actor.type,
                radius: actor.influence === 'High' ? 45 : actor.influence === 'Medium' ? 30 : 20,
                x: width / 2 + (Math.random() - 0.5) * 50,
                y: height / 2 + (Math.random() - 0.5) * 50,
                metrics: actor.metrics,
                assemblageId: assemblageId,
                isHidden: (actor as any).isHidden || false
            } as SimulationNode;
        });

        // Loop through and update isHidden on existing nodes too to ensure real-time updates without remounting
        newNodes.forEach(n => {
            const actor = actors.find(a => a.id === n.id);
            if (actor) {
                n.isHidden = (actor as any).isHidden || false;
            }
        });

        nodesRef.current = newNodes;
        setNodes(newNodes);

        if (simulationRef.current) {
            simulationRef.current.nodes(newNodes);
            simulationRef.current.alpha(0.3).restart();
        }
    }, [actors, width, height, configurations]); // Re-run when configs change


    // 2. Main Layout Engine
    useEffect(() => {
        if (!nodes.length || isPaused) return;

        // Cleanup
        if (simulationRef.current) simulationRef.current.stop();

        const simulation = d3.forceSimulation(nodes)
            .alphaDecay(0.04)
            .velocityDecay(0.4);

        const isRadialMode = enableClustering && !enableMetricAlignment;

        if (isRadialMode) {
            // === STATIC RADIAL LAYOUT (Hybrid Pinning) ===
            const minDim = Math.min(width, height);

            // Group nodes by Assemblage to handle intra-wedge distribution
            const nodesByAssemblage: Record<string, SimulationNode[]> = {};
            // Initialize keys
            configurations.forEach(c => { nodesByAssemblage[c.id] = []; });
            nodesByAssemblage['ungrouped'] = [];

            nodes.forEach(n => {
                const key = n.assemblageId && nodesByAssemblage[n.assemblageId] ? n.assemblageId : 'ungrouped';
                nodesByAssemblage[key].push(n);
            });

            const totalConfigs = configurations.length;

            // If no configs, we treat everything as a single "ungrouped" spiral
            const safeTotalConfigs = totalConfigs || 1;
            const angleStep = (2 * Math.PI) / safeTotalConfigs;

            // 1. Process Configured Assemblages
            configurations.forEach((c, i) => {
                const members = nodesByAssemblage[c.id] || [];
                if (members.length === 0) return;

                // Sort members by Type (Radius) then Name
                members.sort((a, b) => {
                    const rA = getRadialRadius(a.type, minDim);
                    const rB = getRadialRadius(b.type, minDim);
                    return (rA - rB) || a.id.localeCompare(b.id);
                });

                const startAngle = i * angleStep - (Math.PI / 2); // Wedge start (Top aligned)
                const wedgeWidth = angleStep; // Full width

                members.forEach((node) => {
                    const r = getRadialRadius(node.type, minDim);

                    // Find count of nodes at this radius within this assemblage
                    const peers = members.filter(m => getRadialRadius(m.type, minDim) === r);
                    const peerIndex = peers.indexOf(node);
                    const peerCount = peers.length;

                    // Distribute angularly within wedge
                    // Avoid edges slightly for aesthetics
                    const effectiveWidth = wedgeWidth * 0.8;
                    const padding = wedgeWidth * 0.1;

                    let localAngle = startAngle + (wedgeWidth / 2); // Default center
                    if (peerCount > 1) {
                        const step = effectiveWidth / (peerCount - 1);
                        localAngle = startAngle + padding + (step * peerIndex);
                    }

                    const targetX = (width / 2) + Math.cos(localAngle) * r;
                    const targetY = (height / 2) + Math.sin(localAngle) * r;

                    if (!isNaN(targetX) && !isNaN(targetY)) {
                        node.fx = targetX;
                        node.fy = targetY;
                        node.x = targetX;
                        node.y = targetY;
                    }
                });
            });

            // 2. Process Ungrouped (if any)
            const ungrouped = nodesByAssemblage['ungrouped'];
            if (ungrouped.length > 0) {
                // If configs exist, ungrouped start after them. If 0 configs, start at top (-PI/2)
                const angleStart = configurations.length > 0
                    ? -Math.PI / 2 + (configurations.length * angleStep)
                    : -Math.PI / 2;

                ungrouped.forEach((node, idx) => {
                    const r = getRadialRadius(node.type, minDim);
                    // Spiral them
                    const angle = angleStart + (idx * 0.2);
                    const tx = (width / 2) + Math.cos(angle) * r;
                    const ty = (height / 2) + Math.sin(angle) * r;

                    if (!isNaN(tx) && !isNaN(ty)) {
                        node.fx = tx;
                        node.fy = ty;
                        node.x = tx;
                        node.y = ty;
                    }
                });
            }

            // Disable forces
            simulation.force("charge", null)
                .force("center", null)
                .force("collision", null);

        } else {
            // === COMPASS / PHYSICS MODE ===

            // Unpin everyone
            nodes.forEach(n => {
                n.fx = null;
                n.fy = null;
            });

            // 1. Collision
            simulation.force("collide", d3.forceCollide().radius((d: any) => d.isHidden ? 0 : (d.radius + 15)).iterations(2));

            // 2. Metric Forces (Compass)
            if (enableMetricAlignment) {
                const padding = 80;
                const safeW = width - (padding * 2);
                const safeH = height - (padding * 2);
                const getVal = (val: any) => {
                    if (typeof val === 'number') return val;
                    if (val === 'High' || val === 'Strong') return 8;
                    if (val === 'Medium' || val === 'Moderate') return 5;
                    return 2;
                };

                simulation.force("x", d3.forceX((d: SimulationNode) => {
                    const val = getVal(d.metrics?.territorialization || d.metrics?.territoriality);
                    return padding + (val / 10) * safeW;
                }).strength(0.3));

                simulation.force("y", d3.forceY((d: SimulationNode) => {
                    const val = getVal(d.metrics?.deterritorialization || d.metrics?.counter_conduct);
                    return (height - padding) - (val / 10) * safeH;
                }).strength(0.3));

                simulation.force("charge", d3.forceManyBody().strength(-100));
            } else {
                // Fallback
                simulation.force("charge", d3.forceManyBody().strength((d: any) => d.isHidden ? 0 : -300));
                simulation.force("center", d3.forceCenter(width / 2, height / 2));
            }
        }

        // Links
        if (links.length > 0) {
            const nodeIds = new Set(nodes.map(n => n.id));
            const validLinks = links.filter(l => {
                const sourceId = typeof l.source === 'object' ? (l.source as any).id : l.source;
                const targetId = typeof l.target === 'object' ? (l.target as any).id : l.target;
                return nodeIds.has(sourceId) && nodeIds.has(targetId);
            }).map(l => ({ ...l }));

            if (validLinks.length > 0) {
                simulation.force("link", d3.forceLink(validLinks)
                    .id((d: any) => d.id)
                    .strength((d: any) => {
                        // If either end is hidden, link strength is 0
                        if ((d.source as any).isHidden || (d.target as any).isHidden) return 0;
                        return isRadialMode ? 0 : 0.05;
                    })
                    .distance(100)
                );
            }
        }

        simulation.on("tick", () => setNodes([...nodes]));
        simulationRef.current = simulation;

        return () => {
            simulation.stop();
        };

        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [nodes.length, width, height, enableClustering, enableMetricAlignment, isPaused, configurations]);


    // Drag Interaction
    const drag = (node: SimulationNode) => {
        const dragStarted = (e: any) => {
            if (!e.active) simulationRef.current?.alphaTarget(0.3).restart();
            node.fx = node.x;
            node.fy = node.y;
        };
        const dragged = (e: any) => {
            node.fx = e.x;
            node.fy = e.y;
        };
        const dragEnded = (e: any) => {
            if (!e.active) simulationRef.current?.alphaTarget(0);
            if (!enableClustering) {
                node.fx = null;
                node.fy = null;
            }
        };
        return { dragStarted, dragged, dragEnded };
    }

    // eslint-disable-next-line react-hooks/refs
    return { nodes, simulation: simulationRef.current, drag };
}

import { useState, useCallback, useEffect } from 'react';
import { ResistanceArtifact } from '@/types/resistance';
import { useWorkspace } from '@/providers/WorkspaceProvider';

export function useResistanceArtifacts() {
    const { currentWorkspaceId } = useWorkspace();
    const [artifacts, setArtifacts] = useState<ResistanceArtifact[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    const getHeaders = (base: HeadersInit = {}) => {
        const headers = { ...base } as Record<string, string>;
        if (currentWorkspaceId) {
            headers['x-workspace-id'] = currentWorkspaceId;
        }
        if (process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true') {
            headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID || 'demo-user';
        }
        return headers;
    };

    const loadArtifacts = useCallback(async () => {
        if (!currentWorkspaceId) return;

        setIsLoading(true);
        setError(null);
        try {
            const response = await fetch('/api/resistance/artifacts', {
                headers: getHeaders()
            });
            const data = await response.json();
            if (data.success) {
                setArtifacts(data.artifacts);
            } else {
                setError(data.error || 'Failed to load artifacts');
            }
        } catch (err) {
            console.error('Failed to load artifacts:', err);
            setError('Failed to load artifacts');
        } finally {
            setIsLoading(false);
        }
    }, [currentWorkspaceId]);

    const addArtifact = useCallback(async (artifactData: Omit<ResistanceArtifact, 'id' | 'uploaded_at' | 'uploaded_by'>) => {
        try {
            const response = await fetch('/api/resistance/artifacts', {
                method: 'POST',
                headers: getHeaders({ 'Content-Type': 'application/json' }),
                body: JSON.stringify(artifactData)
            });

            const data = await response.json();
            if (data.success) {
                setArtifacts(prev => [...prev, data.artifact]);
                return data.artifact;
            } else {
                throw new Error(data.error || 'Failed to add artifact');
            }
        } catch (err) {
            console.error('Failed to add artifact:', err);
            throw err;
        }
    }, [currentWorkspaceId]);

    const deleteArtifact = useCallback(async (id: string) => {
        try {
            const response = await fetch(`/api/resistance/artifacts/${id}`, {
                method: 'DELETE',
                headers: getHeaders()
            });

            const data = await response.json();
            if (data.success) {
                setArtifacts(prev => prev.filter(a => a.id !== id));
            } else {
                throw new Error(data.error || 'Failed to delete artifact');
            }
        } catch (err) {
            console.error('Failed to delete artifact:', err);
            throw err;
        }
    }, [currentWorkspaceId]);

    // Initial load
    useEffect(() => {
        if (currentWorkspaceId) {
            loadArtifacts();
        }
    }, [loadArtifacts, currentWorkspaceId]);

    return {
        artifacts,
        isLoading,
        error,
        loadArtifacts,
        addArtifact,
        deleteArtifact
    };
}

import { useState, useEffect, useCallback } from "react";
import { useWorkspace } from '@/providers/WorkspaceProvider';
import { useDemoMode } from '@/hooks/useDemoMode'; // [Fix] Import hook

export function useServerStorage<T>(key: string, initialValue: T): [T, (value: T | ((val: T) => T)) => void, boolean] {
    const { currentWorkspaceId } = useWorkspace();
    const { isReadOnly, isDemoEnabled, isAuthLoaded } = useDemoMode(); // [Fix] Check read-only status
    const [storedValue, setStoredValue] = useState<T>(initialValue);
    const [isLoading, setIsLoading] = useState(true);

    const getHeaders = useCallback((base: HeadersInit = {}) => {
        const headers = { ...base } as Record<string, string>;
        if (currentWorkspaceId) {
            headers['x-workspace-id'] = currentWorkspaceId;
        }
        if (isDemoEnabled) {
            headers['x-demo-user-id'] = process.env.NEXT_PUBLIC_DEMO_USER_ID || 'demo-user';
        }
        return headers;
    }, [currentWorkspaceId, isDemoEnabled]);

    // Fetch initial value from server
    useEffect(() => {
        let isMounted = true;

        const fetchValue = async () => {
            // console.log(`[useServerStorage] Fetching key: "${key}" for workspace: ${currentWorkspaceId || 'default'}`);
            try {
                const response = await fetch(`/api/storage?key=${encodeURIComponent(key)}`, {
                    headers: getHeaders()
                });

                if (response.ok) {
                    const data = await response.json();
                    if (isMounted) {
                        setStoredValue(data.value ?? initialValue);
                    }
                } else {
                    // console.warn(`[useServerStorage] Failed to fetch ${key}: ${response.status}`);
                }
            } catch (error) {
                console.error(`Failed to fetch storage key "${key}":`, error);
            } finally {
                if (isMounted) {
                    setIsLoading(false);
                }
            }
        };

        if (currentWorkspaceId || isReadOnly) { // Allow fetch even if read-only (demo)
            fetchValue();
        } else {
            // If no workspace and not demo, we might be in weird state, but try anyway
            fetchValue();
        }

        return () => {
            isMounted = false;
        };
    }, [key, currentWorkspaceId, getHeaders, isReadOnly]);

    // Return a wrapped version of useState's setter function that ...
    // ... persists the new value to the server.
    const setValue = useCallback((value: T | ((val: T) => T)) => {
        try {
            // Allow value to be a function so we have same API as useState
            setStoredValue((prevValue) => {
                const valueToStore = value instanceof Function ? value(prevValue) : value;

                // [Fix] If Read-Only, skip server save to avoid 403
                // Or if we don't know yet because auth is loading and demo is enabled
                if (isReadOnly || (!isAuthLoaded && isDemoEnabled)) {
                    // console.log(`[useServerStorage] Read-Only Mode: Skipping save for "${key}"`);
                    return valueToStore;
                }

                // console.log(`[useServerStorage] Saving key: "${key}"...`);

                // Save to server
                fetch('/api/storage', {
                    method: 'POST',
                    headers: getHeaders({ 'Content-Type': 'application/json' }),
                    body: JSON.stringify({ key, value: valueToStore }),
                }).then(res => {
                    if (res.ok) {
                        // console.log(`[useServerStorage] Successfully saved "${key}"`);
                    } else {
                        if (res.status === 403) {
                            console.warn(`[useServerStorage] Skipped save for "${key}" (Read-Only/Demo)`);
                        } else {
                            console.error(`[useServerStorage] Failed to save "${key}": ${res.status}`);
                        }
                    }
                }).catch(err => console.error(`Failed to save storage key "${key}":`, err));

                return valueToStore;
            });
        } catch (error) {
            console.error(`Error setting value for key "${key}":`, error);
        }
    }, [key, currentWorkspaceId, getHeaders, isReadOnly, isDemoEnabled, isAuthLoaded]);


    return [storedValue, setValue, isLoading];
}

'use client';

import { useState, useEffect } from 'react';
import { useWorkspace } from '@/providers/WorkspaceProvider';
import { toast } from 'sonner';
import { useAuth } from '@clerk/nextjs';

export interface TeamMember {
    userId: string;
    email: string;
    role: 'OWNER' | 'EDITOR' | 'VOTER';
    joinedAt: number;
    name?: string;
}

export interface TeamDetails {
    id: string;
    name: string;
    createdBy: string;
    createdAt: number;
    members: TeamMember[];
}

export const useTeam = () => {
    const { userId } = useAuth();
    const { currentWorkspaceId, workspaceType } = useWorkspace();
    const [teamDetails, setTeamDetails] = useState<TeamDetails | null>(null);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const isTeamWorkspace = workspaceType === 'TEAM';

    // Derived Role
    const currentUserRole = teamDetails?.members.find(m => m.userId === userId)?.role;

    // Fetch team details and members
    const fetchTeamDetails = async () => {
        if (!isTeamWorkspace || !currentWorkspaceId) {
            setTeamDetails(null);
            return;
        }

        setIsLoading(true);
        setError(null);

        try {
            const res = await fetch(`/api/collaboration/teams/${currentWorkspaceId}`);

            if (!res.ok) {
                if (res.status === 404) {
                    throw new Error('Team not found');
                } else if (res.status === 403) {
                    throw new Error('You do not have access to this team');
                }
                throw new Error('Failed to fetch team details');
            }

            const data = await res.json();
            setTeamDetails(data);
        } catch (err) {
            const message = err instanceof Error ? err.message : 'Unknown error';
            setError(message);
            toast.error(message);
        } finally {
            setIsLoading(false);
        }
    };

    // Invite member
    const inviteMember = async (email: string, role: 'OWNER' | 'EDITOR' | 'VOTER' = 'EDITOR') => {
        if (!currentWorkspaceId) return { success: false, error: 'No team selected' };

        try {
            const res = await fetch('/api/collaboration/invites', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ teamId: currentWorkspaceId, email, role })
            });

            const data = await res.json();

            if (!res.ok) {
                return { success: false, error: data.error || 'Failed to create invitation' };
            }

            toast.success(`Invitation sent to ${email}`);
            return { success: true, token: data.token, expiresAt: data.expiresAt };
        } catch (err) {
            const message = err instanceof Error ? err.message : 'Network error';
            toast.error(message);
            return { success: false, error: message };
        }
    };

    // Remove member
    const removeMember = async (userId: string) => {
        if (!currentWorkspaceId) return { success: false, error: 'No team selected' };

        try {
            const res = await fetch(`/api/collaboration/teams/${currentWorkspaceId}/members/${userId}`, {
                method: 'DELETE'
            });

            const data = await res.json();

            if (!res.ok) {
                return { success: false, error: data.error || 'Failed to remove member' };
            }

            toast.success('Member removed from team');
            await fetchTeamDetails(); // Refresh
            return { success: true };
        } catch (err) {
            const message = err instanceof Error ? err.message : 'Network error';
            toast.error(message);
            return { success: false, error: message };
        }
    };

    // Auto-fetch when workspace changes
    useEffect(() => {
        fetchTeamDetails();
    }, [currentWorkspaceId, workspaceType]);

    return {
        teamDetails,
        currentUserRole,
        isLoading,
        error,
        isTeamWorkspace,
        inviteMember,
        removeMember,
        refreshTeam: fetchTeamDetails
    };
};

import { StorageService } from '@/lib/storage-service';

export interface AICallLog {
    id: string;
    timestamp: string;
    userId: string;
    analysisMode: string;

    // Request
    promptId: string;
    promptVersion: string;
    model: string;
    temperature: number;
    maxTokens: number;
    systemPromptHash?: string;
    systemPromptPreview: string;  // First 500 chars
    userContentPreview: string;   // First 500 chars

    // Response
    rawResponsePreview: string;   // First 1000 chars
    tokenUsage?: { prompt: number; completion: number; total: number };
    latencyMs: number;
    finishReason?: string;

    // Result
    parseSuccess: boolean;
    errorMessage?: string;
}

const STORAGE_KEY_PREFIX = 'ai_audit_log:';
const USER_LOGS_INDEX_PREFIX = 'user_audit_logs:';

export async function logAICall(log: AICallLog): Promise<void> {
    try {
        // 1. Store the individual log entry
        await StorageService.set(log.userId, `${STORAGE_KEY_PREFIX}${log.id}`, log);

        // 2. Add to user's index of logs (simplified for now, ideally this would be a list)
        // Since StorageService is key-value, we can't easily append to a list without reading it first.
        // For this implementation, we will mainly rely on the individual log storage.
        // A full implementation would use a proper DB or Redis list.

        console.log(`[AI-AUDIT] Logged call ${log.id} for user ${log.userId} (Prompt: ${log.promptId} v${log.promptVersion})`);

    } catch (error) {
        console.error('[AI-AUDIT] Failed to log AI call:', error);
        // Don't throw, we don't want to break the analysis flow if logging fails
    }
}

export async function getAICallLog(userId: string, logId: string): Promise<AICallLog | null> {
    return await StorageService.get<AICallLog>(userId, `${STORAGE_KEY_PREFIX}${logId}`);
}

