export async function runCritiqueLoop(openai: OpenAI, userId: string, verificationText: string, analysis: any) {
    try {
        console.log('[CRITIQUE] Starting Devil\'s Advocate loop...');
        let critiquePrompt = await PromptRegistry.getEffectivePrompt(userId, 'critique_panel');

        // [Fix] Hardcoded fallback if registry fails
        if (!critiquePrompt || critiquePrompt.length < 10) {
            console.warn('[CRITIQUE] System prompt missing from registry! Using hardcoded fallback.');
            critiquePrompt = "You are a 'Devil's Advocate' AI. Your goal is to critique the provided analysis. Identify blind spots, over-interpretations, and missing perspectives. Output your critique in plain text.";
        }

        // [Optimization] Aggressively simplify the analysis to avoid token limits
        // Only send the high-level insights and scores needed for a critique
        const critiquePayload = {
            key_insight: analysis.key_insight,
            governance_scores: analysis.governance_scores,
            dominant_logic: analysis.dominant_logic,
            overall_assessment: analysis.overall_assessment,
            // Include summary if short, otherwise truncate
            summary: (analysis.narrative || analysis.start_market_society || analysis.summary || "").substring(0, 500)
        };

        const critiqueUserContent = "ORIGINAL SOURCE TEXT(Excerpts): \n" + (verificationText || '').substring(0, 800) + "...\n\nGENERATED ANALYSIS(Summary): \n" + JSON.stringify(critiquePayload, null, 2) + " \n\nCritique this analysis.";

        console.log(`[CRITIQUE] Sending Request. Prompt Length: ${critiquePrompt.length}, Content Length: ${critiqueUserContent.length}`);

        const critiqueCompletion = await openai.chat.completions.create({
            model: process.env.OPENAI_MODEL || "gpt-4o",
            messages: [
                { role: 'system', content: critiquePrompt },
                { role: 'user', content: critiqueUserContent }
            ],
            max_completion_tokens: 4096
        });

        const choice = critiqueCompletion.choices[0];
        const critiqueText = choice?.message?.content || '';

        console.log(`[CRITIQUE] Valid Response? ${!!critiqueText}. Finish Reason: ${choice?.finish_reason}`);
        console.log(`[CRITIQUE] Raw Response: ${critiqueText.substring(0, 200)}`);

        if (!critiqueText) {
            return {
                critique: `Generation failed. OpenAI returned empty content. Reason: ${choice?.finish_reason || 'Unknown'}`,
                blind_spots: ["System Error"],
                implications: ["Check if the model filtered the response."]
            };
        }

        let critiqueJson;
        try {
            // robust clean
            const cleanedCritique = critiqueText
                .replace(/```json\s*/gi, '')
                .replace(/```/g, '')
                .replace(/^JSON:/i, '')
                .trim();

            if (cleanedCritique.startsWith('{')) {
                critiqueJson = JSON.parse(cleanedCritique);
            } else {
                // It's just text
                throw new Error("Not JSON");
            }

            // [Robustness] Validate schema. If empty or missing keys, force fallback.
            if (!critiqueJson.critique && !critiqueJson.blind_spots && !critiqueJson.over_interpretation) {
                console.warn('[CRITIQUE] Valid JSON but missing schema. Outputting raw text.');
                critiqueJson = {
                    critique: critiqueText,
                    blind_spots: critiqueJson.blind_spots || [],
                    over_interpretation: critiqueJson.over_interpretation,
                    ...critiqueJson
                };

                // If it's still barely populated, force a message
                if (!critiqueJson.critique || critiqueJson.critique === '{}') {
                    const foundKeys = Object.keys(critiqueJson).filter(k => k !== 'critique' && k !== 'blind_spots' && k !== 'over_interpretation');
                    critiqueJson.critique = `Critique generated but unstructured. Keys found: [${foundKeys.join(', ')}]. \nRaw: ${critiqueText.substring(0, 100)}`;
                }
            }

        } catch (e) {
            // Fallback for plain text response
            console.debug('JSON parse failed for critique, falling back to text', e);
            // Fallback for plain text response
            critiqueJson = {
                critique: critiqueText,
                blind_spots: ["(Unstructured Response)"],
                implications: ["Please review the raw critique text."]
            };
        }

        console.log('[CRITIQUE] Completed.');
        return critiqueJson;

    } catch (critiqueError) {
        console.warn('[CRITIQUE] Failed:', critiqueError);
        return {
            critique: "Automatic critique failed.",
            blind_spots: ["System Error"],
            implications: [critiqueError instanceof Error ? critiqueError.message : String(critiqueError)]
        };
    }
}

import OpenAI from 'openai';
import { PromptRegistry } from '@/lib/prompts/registry';
import { parseAnalysisResponse } from '@/lib/analysis-parser';

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export async function runStressTest(openai: OpenAI, userId: string, text: string, currentAnalysis: any, existingAnalysis: any = null) {
    console.log('[ANALYSIS] Running Stress Test sub-analyses...');
    const stressRes = currentAnalysis || {};
    const invertedText = stressRes.inverted_text_excerpt || stressRes.inverted_text;

    // 1. Analyze Inverted Text
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    let invAnalysis: any = {};
    if (invertedText) {
        const dsfPrompt = await PromptRegistry.getEffectivePrompt(userId, 'dsf_lens');
        const invCompletion = await openai.chat.completions.create({
            model: process.env.OPENAI_MODEL || "gpt-4o",
            messages: [
                { role: 'system', content: dsfPrompt },
                { role: 'user', content: `TEXT CONTENT: \n${invertedText} \n\nAnalyze this text using the Decolonial Situatedness Framework.` }
            ],
            response_format: { type: "json_object" }
        });
        invAnalysis = JSON.parse(invCompletion.choices[0]?.message?.content || '{}');
    } else {
        console.warn('[ANALYSIS WARNING] Stress test failed to generate inverted text.');
    }

    // 2. Analyze Original Text (Standard DSF)
    let origAnalysis = existingAnalysis;

    // [FIX] Check for verified quotes to ensure Audit functionality works
    const hasAuditData = origAnalysis && origAnalysis.verified_quotes && origAnalysis.verified_quotes.length > 0;

    if (origAnalysis && origAnalysis.governance_scores && hasAuditData) {
        console.log('[ANALYSIS] Utilizing EXISTING analysis (with Audit Data). Skipping re-run.');
    } else {
        if (!hasAuditData && origAnalysis) {
            console.log('[ANALYSIS] Existing analysis found but missing Audit Data (Verified Quotes). Forcing re-run to extract evidence.');
        } else {
            console.log('[ANALYSIS] No existing analysis provided. Re-running standard DSF...');
        }
        const dsfPrompt = await PromptRegistry.getEffectivePrompt(userId, 'dsf_lens');
        const origCompletion = await openai.chat.completions.create({
            model: process.env.OPENAI_MODEL || "gpt-4o",
            messages: [
                { role: 'system', content: dsfPrompt },
                { role: 'user', content: `TEXT CONTENT: \n${text} \n\nAnalyze this text using the Decolonial Situatedness Framework.` }
            ],
            response_format: { type: "json_object" }
        });

        const rawContent = origCompletion.choices[0]?.message?.content || '{}';
        origAnalysis = parseAnalysisResponse(rawContent, 'dsf');

        if (!origAnalysis.governance_scores) {
            console.warn('[ANALYSIS WARNING] Standard DSF re-run failed to produce governance scores. Parsing likely failed.');
            origAnalysis.governance_scores = {
                centralization: 50, rights_focus: 50, flexibility: 50, market_power: 50, procedurality: 50
            };
        }
    }

    // 3. Compute Deviation
    const scoreA = origAnalysis.governance_scores?.market_power || 50;
    const scoreB = invAnalysis.governance_scores?.market_power || 50;
    const diff = Math.abs(scoreA - scoreB);

    // 4. Construct Final Object
    return {
        ...origAnalysis,
        stress_test_report: {
            original_score: scoreA,
            perturbed_score: scoreB,
            framing_sensitivity: diff > 30 ? "High" : (diff > 15 ? "Medium" : "Low"),
            shift_explanation: stressRes.shift_explanation || "No explanation provided.",
            inverted_text_excerpt: invertedText ? (invertedText.substring(0, 300) + "...") : "Generation failed",
            rhetorical_shifts: stressRes.rhetorical_shifts || []
        }
    };
}

import OpenAI from 'openai';
import { executeGoogleSearch } from '@/lib/search-service';
/* eslint-disable @typescript-eslint/no-explicit-any */
import { EcosystemActor, EcosystemEdge } from '@/types/ecosystem';
import { v4 as uuidv4 } from 'uuid';

import { ANT_CORE_DEFINITIONS } from '@/lib/prompts';

export class AssemblageExtractionService {
    /**
     * Discovers actors by searching the web for a topic, aggregating results, 
     * and then performing extraction on the aggregated text.
     */
    static async discoverActorsFromTopic(
        query: string,
        openai: OpenAI
    ): Promise<{ actors: EcosystemActor[]; edges: EcosystemEdge[]; summary: string }> {
        console.log(`[DISCOVERY] Searching for: ${query}`);

        // 1. Execute Search
        const apiKey = process.env.GOOGLE_SEARCH_API_KEY || '';
        const cx = process.env.GOOGLE_SEARCH_CX || '';

        if (!apiKey || !cx) {
            throw new Error("Missing Google Search Configuration (API Key or CX)");
        }

        const searchResults = await executeGoogleSearch(query, apiKey, cx, 10);

        if (searchResults.length === 0) {
            console.warn("[DISCOVERY] No search results found.");
            return { actors: [], edges: [], summary: "No search results found for this topic." };
        }

        // 2. Aggregate Text from Snippets (and potentially fetch content if we had a scraper)
        // For now, we rely on rich snippets.
        const aggregatedText = searchResults
            .map(r => `Source: ${r.title}\nSnippet: ${r.snippet}`)
            .join("\n\n");

        console.log(`[DISCOVERY] Aggregated ${aggregatedText.length} chars of context.`);

        // 3. Extract Assembly
        return this.extractAssemblageFromText(aggregatedText, openai, `Search Results for "${query}"`);
    }

    /**
     * Extracts actors and relationships from raw text using ANT principles.
     */
    static async extractAssemblageFromText(
        text: string,
        openai: OpenAI,
        sourceLabel: string = "User Input"
    ): Promise<{ actors: EcosystemActor[]; edges: EcosystemEdge[]; summary: string }> {
        const prompt = `
        Analyze the following text from an Actor-Network Theory (ANT) perspective.
        
        Goal: Identify the "Assemblage" of actors (human, non-human, institutional, technological) and their relationships.
        
        Rules:
        1. Actors: Identify specific entities.
           - Type: PrivateTech, Policymaker, Civil Society, Academic, Infrastructure, Algorithm, Dataset, LegalObject, or Controversy.
           - Controversy: Mark "Hot Spots" or "Matters of Concern" where consensus is breaking down as type="Controversy".
           - Ontology: Is this actor an "individual", "collective" (group), or "punctualized" (complex network acting as one)?

        ${ANT_CORE_DEFINITIONS}

        3. Metrics (1-10):
           - Territorialization: Stability, authority.
           - Deterritorialization: Fluidity, resistance.
           - Coding: Rigidity of identity.

        Output structured JSON:
        {
            "summary": "Brief executive summary (max 2 sentences)",
            "actors": [
                {
                    "name": "Entity Name",
                    "type": "See list above",
                    "ontologicalStatus": "individual" | "collective" | "punctualized",
                    "description": "Role",
                    "evidence_quotes": ["Quote"],
                    "metrics": { "territorialization": 5, "deterritorialization": 5, "coding": 5 }
                }
            ],
            "relationships": [
                {
                    "source": "Actor A",
                    "target": "Actor B",
                    "type": "verb (e.g. regulates, distorts)",
                    "nature": "intermediary" | "mediator",
                    "transformationType": "amplify" | "translate" | "block" | "modify" | "create" | "dissolve",
                    "confidence": 0.9,
                    "evidence": ["Quote relating to the work of mediation"],
                    "description": "Context"
                }
            ]
        }

        Text Context: ${sourceLabel}
        Text Content:
        ${text.substring(0, 15000)}
        `;

        const response = await openai.chat.completions.create({
            model: process.env.OPENAI_API_MODEL || "gpt-4o",
            messages: [
                { role: "system", content: "You are an expert socio-technical analyst using Actor-Network Theory." },
                { role: "user", content: prompt }
            ],
            response_format: { type: "json_object" },
            temperature: 0.2 // Low temperature for factual extraction
        });

        const content = response.choices[0].message.content;
        if (!content) throw new Error("No extracted content from AI");


        const result = JSON.parse(content) as any;

        // Map to internal types
        const actors: EcosystemActor[] = (result.actors || []).map((a: any) => ({
            id: uuidv4(),
            name: a.name,
            type: this.validateType(a.type),
            description: a.description || "Extracted entity",
            influence: "Medium", // Inference placeholder
            source: "absence_fill", // Mark as AI generated/filled
            metrics: {
                territorialization: a.metrics?.territorialization || 5,
                deterritorialization: a.metrics?.deterritorialization || 5,
                coding: a.metrics?.coding || 5,
                territoriality: a.metrics?.territorialization || 5, // Backward compat
                counter_conduct: a.metrics?.deterritorialization || 5 // Backward compat
            },
            quotes: a.evidence_quotes || [],
            trace_metadata: {
                source: "ai_inference",
                evidence: (a.evidence_quotes && a.evidence_quotes[0]) || sourceLabel,
                provisional: true,
                confidence: 0.8
            },
            reflexive_log: [
                {
                    id: uuidv4(),
                    timestamp: Date.now(),
                    action_type: "Manual_Inscription",
                    rationale: `Actor extracted from source text (${sourceLabel})`,
                    user_id: "system"
                }
            ]
        }));

        const edges: EcosystemEdge[] = (result.relationships || []).map((r: any) => {
            // Find IDs for names with Fuzzy Matching
            const normalize = (s: string) => s.toLowerCase().trim();
            const findActor = (name: string) => {
                const n = normalize(name);
                return actors.find(a => normalize(a.name) === n) ||
                    actors.find(a => normalize(a.name).includes(n) || n.includes(normalize(a.name)));
            };


            const sourceActor = findActor(r.source);

            const targetActor = findActor(r.target);

            if (sourceActor && targetActor) {
                return {
                    source: sourceActor.id,
                    target: targetActor.id,
                    type: r.type || "relates_to",
                    description: r.description || "AI inferred connection",

                    // [NEW] ANT Properties
                    nature: r.nature || "intermediary",
                    transformationType: r.transformationType,
                    confidence: r.confidence || 0.8,
                    evidence: r.evidence ? (Array.isArray(r.evidence) ? r.evidence : [r.evidence]) : [],
                };
            }
            return null;
        }).filter((e: EcosystemEdge | null): e is EcosystemEdge => e !== null);

        return {
            actors,
            edges,
            summary: result.summary || "Extraction complete."
        };
    }


    private static validateType(type: string): any {
        const validTypes = ["PrivateTech", "Policymaker", "Civil Society", "Academic", "Infrastructure", "Algorithm", "Dataset", "AlgorithmicAgent", "LegalObject", "Controversy", "NonHuman"];
        const match = validTypes.find(t => t.toLowerCase() === type.toLowerCase());
        return match || "Infrastructure"; // Default fallback
    }
}

import { AssemblageMechanism, AssemblageCapacity, HullMetrics, MechanismType } from '@/types/assemblage-realist';
import { TracedActor, Association } from '@/types/ant';
import { EcosystemConfiguration } from '@/types/ecosystem';

/**
 * Assemblage Mechanism Service
 * Implements DeLanda's Assemblage Theory as ONTOLOGICAL layer
 * 
 * Key Principle: Provides explanatory mechanisms grounded in ANT traces
 */
export class AssemblageMechanismService {
    /**
     * Detect territorialization mechanisms from traced network
     */
    static detectTerritorialization(
        actors: TracedActor[],
        associations: Association[],
        configurations: EcosystemConfiguration[]
    ): AssemblageMechanism[] {
        const mechanisms: AssemblageMechanism[] = [];

        configurations.forEach(config => {
            const memberActors = actors.filter(a => config.memberIds.includes(a.id));
            const internalLinks = associations.filter(
                a => config.memberIds.includes(a.source) && config.memberIds.includes(a.target)
            );

            const intensity = config.properties.calculated_stability || 0.5;

            mechanisms.push({
                type: "territorialization",
                intensity,
                evidence: memberActors,
                explanation: `Configuration "${config.name}" exhibits ${this.intensityLabel(intensity)} territorialization through ${internalLinks.length} internal associations among ${memberActors.length} actors. This boundary-making process stabilizes the assemblage.`,
                confidence: 0.75
            });
        });

        return mechanisms;
    }

    /**
     * Detect deterritorialization mechanisms
     */
    static detectDeterritorialization(
        actors: TracedActor[],
        associations: Association[]
    ): AssemblageMechanism[] {
        const mechanisms: AssemblageMechanism[] = [];

        // Look for actors with high external connectivity (lines of flight)
        actors.forEach(actor => {
            const externalLinks = associations.filter(
                a => (a.source === actor.id || a.target === actor.id)
            );

            if (externalLinks.length > 5) { // Threshold for deterritorialization
                mechanisms.push({
                    type: "deterritorialization",
                    intensity: Math.min(externalLinks.length / 10, 1),
                    evidence: [actor],
                    explanation: `Actor "${actor.name}" shows deterritorialization through ${externalLinks.length} cross-boundary connections, creating lines of flight that destabilize territorial boundaries.`,
                    confidence: 0.7
                });
            }
        });

        return mechanisms;
    }

    /**
     * Identify assemblage capacities (what it can/cannot do)
     */
    static identifyCapacities(
        actors: TracedActor[],
        associations: Association[]
    ): AssemblageCapacity[] {
        const capacities: AssemblageCapacity[] = [];

        // Enforcement capacity
        const policymakers = actors.filter(a => a.type === "Policymaker");
        const regulatoryLinks = associations.filter(a => a.relation_type === "Regulates");

        if (policymakers.length > 0 && regulatoryLinks.length > 0) {
            capacities.push({
                name: "Enforcement Capacity",
                description: "Ability to enforce regulatory compliance through legal mechanisms",
                enabled_by: policymakers.map(p => p.id),
                blocked_by: [],
                actual: true,
                potential: true,
                evidence: `${policymakers.length} policymaker(s) with ${regulatoryLinks.length} regulatory link(s)`
            });
        }

        // Deliberation capacity
        const civilSociety = actors.filter(a => a.type === "Civil Society");
        const academics = actors.filter(a => a.type === "Academic");

        if (civilSociety.length > 0 || academics.length > 0) {
            capacities.push({
                name: "Deliberation Capacity",
                description: "Ability to engage in multi-stakeholder dialogue and knowledge production",
                enabled_by: [...civilSociety.map(c => c.id), ...academics.map(a => a.id)],
                blocked_by: [],
                actual: civilSociety.length + academics.length > 2,
                potential: true,
                evidence: `${civilSociety.length} civil society + ${academics.length} academic actor(s)`
            });
        }

        // Innovation capacity
        const privateTech = actors.filter(a => a.type === "PrivateTech");
        const infrastructure = actors.filter(a => a.type === "Infrastructure");

        if (privateTech.length > 0 && infrastructure.length > 0) {
            capacities.push({
                name: "Innovation Capacity",
                description: "Ability to develop and deploy new technological solutions",
                enabled_by: [...privateTech.map(s => s.id), ...infrastructure.map(i => i.id)],
                blocked_by: [],
                actual: true,
                potential: true,
                evidence: `${privateTech.length} private tech actor(s) with ${infrastructure.length} infrastructure actor(s)`
            });
        }

        return capacities;
    }

    /**
     * Calculate hull metrics (both ANT and Assemblage perspectives)
     */
    static calculateHullMetrics(
        config: EcosystemConfiguration,
        actors: TracedActor[],
        associations: Association[]
    ): HullMetrics {
        const memberIds = config.memberIds;
        const memberActors = actors.filter(a => memberIds.includes(a.id));

        const internalLinks = associations.filter(
            a => memberIds.includes(a.source) && memberIds.includes(a.target)
        );

        const externalLinks = associations.filter(
            a => (memberIds.includes(a.source) && !memberIds.includes(a.target)) ||
                (!memberIds.includes(a.source) && memberIds.includes(a.target))
        );

        const totalLinks = internalLinks.length + externalLinks.length;

        // ANT flow metrics (methodological)
        const porosity = totalLinks > 0 ? externalLinks.length / totalLinks : 0;
        const connectivity = memberActors.length > 1
            ? internalLinks.length / (memberActors.length * (memberActors.length - 1))
            : 0;

        // Assemblage realist metrics (ontological)
        const territorialization = config.properties.calculated_stability || 0.5;
        const coding_intensity = 1 - (config.properties.porosity_index || 0.5);
        const capacity_score = 0.7; // Would calculate from actual capacities

        return {
            flow_metrics: {
                porosity,
                connectivity,
                label: "ANT Flow Analysis"
            },
            realist_metrics: {
                territorialization,
                coding_intensity,
                capacity_score,
                label: "Assemblage Mechanism Analysis"
            }
        };
    }

    /**
     * Helper: Get intensity label
     */
    private static intensityLabel(intensity: number): string {
        if (intensity > 0.7) return "high";
        if (intensity > 0.4) return "medium";
        return "low";
    }
}

import { redis } from '@/lib/redis';
import { logger } from '@/lib/logger';

export type AuditEventType =
    | 'SECURITY_ACCESS_DENIED'
    | 'SECURITY_PREFIX_INJECTION'
    | 'TEAM_CREATED'
    | 'TEAM_DELETED'
    | 'MEMBER_INVITED'
    | 'MEMBER_ADDED'
    | 'MEMBER_REMOVED'
    | 'GOVERNANCE_OVERRIDE';

export interface AuditEvent {
    eventId: string;
    type: AuditEventType;
    actorId: string; // Real User ID
    targetId?: string; // Context/Team/Resource ID
    timestamp: number;
    metadata?: Record<string, any>;
    ipAddress?: string; // If available
}

export class AuditService {
    private static readonly STREAM_KEY = 'audit:events:stream';

    /**
     * Log a tamper-evident record of a system event.
     */
    static async log(
        type: AuditEventType,
        actorId: string,
        data: { targetId?: string, metadata?: Record<string, any>, ip?: string }
    ): Promise<string> {
        const eventId = crypto.randomUUID();
        const event: AuditEvent = {
            eventId,
            type,
            actorId,
            targetId: data.targetId,
            timestamp: Date.now(),
            metadata: data.metadata,
            ipAddress: data.ip
        };

        try {
            // Store simple JSON for MVP. 
            // In Phase 6 (SQL), this moves to a proper table.
            await redis.lpush('audit:events:log', JSON.stringify(event));

            // Console output for vercel logs
            logger.audit(`${type} | Actor: ${actorId} | Target: ${data.targetId || 'N/A'}`);

            return eventId;
        } catch (error) {
            logger.error('[AUDIT FAILED] Could not persist audit log:', error);
            // We do NOT throw here to prevent bringing down the main app flow,
            // but in high-security mode, we might want to fail-closed.
            return 'error-logging-event';
        }
    }

    static async getRecentLogs(limit = 50): Promise<AuditEvent[]> {
        const raws = await redis.lrange('audit:events:log', 0, limit - 1);
        return raws.map(s => JSON.parse(s));
    }
}

import crypto from 'crypto';

/**
 * Generate a deterministic hash from actor data for cache keys.
 * Uses canonical JSON representation to ensure consistent hashing.
 */
export function generateActorHash(actors: any[], context?: string): string {
    // Sort actors by ID to ensure consistent ordering
    const sortedActors = [...actors].sort((a, b) => {
        const idA = a.id || a.name || '';
        const idB = b.id || b.name || '';
        return idA.localeCompare(idB);
    });

    // Create canonical representation
    const canonical = {
        actors: sortedActors.map(a => ({
            id: a.id,
            name: a.name,
            type: a.type,
        })),
        context: context || '',
    };

    // Generate SHA-256 hash
    const jsonString = JSON.stringify(canonical);
    return crypto.createHash('sha256').update(jsonString).digest('hex');
}

/**
 * Generate cache key for deterritorialization simulation
 */
export function getDeterritorializationCacheKey(userId: string, actorHash: string): string {
    return `user:${userId}:cache:deterritorialization:v1:${actorHash}`;
}

/**
 * Cache TTL in seconds (24 hours)
 */
export const DETERRITORIALIZATION_CACHE_TTL = 86400;

import * as cheerio from 'cheerio';
// Removed top-level import to avoid build errors with CommonJS module
// import pdfParse from 'pdf-parse'; 

interface ExtractedContent {
    text: string;
    title: string;
    type: 'pdf' | 'html';
    contentLength: number;
}

export class ContentExtractor {
    /**
     * Extracts text content and title from a fetch Response object.
     * Automatically handles PDF extraction if Content-Type matches.
     */
    static async extract(response: Response, url: string): Promise<ExtractedContent> {
        const contentType = response.headers.get('content-type') || '';
        console.log(`[ContentExtractor] Extracting content from ${url}, Content-Type: ${contentType}`);

        let text = '';
        let title = '';
        let type: 'pdf' | 'html' = 'html';

        if (contentType.includes('application/pdf')) {
            console.log(`[ContentExtractor] Detected PDF`);
            type = 'pdf';
            const buffer = await response.arrayBuffer();

            // pdf-parse-fork is a maintained fork that works in Node.js
            const pdfParse = (await import('pdf-parse-fork')).default;
            const data = await pdfParse(Buffer.from(buffer));
            text = data.text;
            title = url.split('/').pop() || 'PDF Document'; // Fallback title
        } else {
            type = 'html';
            const html = await response.text();
            const $ = cheerio.load(html);

            // Remove scripts, styles, and other non-content elements
            $('script, style, noscript, iframe, svg, header, footer, nav').remove();

            // Extract title
            title = $('title').text().trim() || url;

            // Extract text content
            // We look for main content areas first, or fall back to body
            const contentSelector = 'main, article, #content, .content, body';
            text = $(contentSelector).first().text();
        }

        // Clean up whitespace
        text = text.replace(/\s+/g, ' ').trim();

        // Limit text length to avoid overwhelming the analysis
        const maxLength = 50000;
        if (text.length > maxLength) {
            text = text.substring(0, maxLength) + '... (truncated)';
        }

        console.log(`[ContentExtractor] Extracted ${text.length} chars. Title: ${title}`);

        return {
            text,
            title,
            type,
            contentLength: text.length
        };
    }
}

/**
 * Pre-LLM Compression Layer for Controversy Mapping
 * Objective: Radically reduce heterogeneous JSON structures from 7 different analytical strata
 * down to < 32k tokens, preserving only the highest signal structural features 
 * (names, themes, scores, friction points) while aggressively truncating quotes and arrays.
 */

export interface RawLensData {
    cultural?: any;
    institutional?: any;
    resistance?: any;
    abstractMachine?: any;
    actors?: any[];
    ghostNodes?: any[];
    configurations?: any[];
    crossCaseExport?: any;
}

export function compressLensesForControversyMapping(raw: RawLensData): string {
    // Helper to truncate strings 
    const truncate = (str: string, max = 250) =>
        str?.length > max ? str.substring(0, max) + '...' : str;

    // Helper to generic-filter arrays and strip heavy fields
    const stripNoise = (obj: any, depth = 0): any => {
        if (depth > 5) return "..."; // Prevent circular or massive nested objects
        if (obj === null || obj === undefined) return undefined;

        if (typeof obj === 'string') {
            // Strip UUIDs typically used for tracing (like q-ghost-xxxx)
            if (obj.match(/^[0-9a-fA-F-]{36}$/) || obj.match(/^q-/)) return undefined;
            return truncate(obj);
        }

        if (Array.isArray(obj)) {
            // Take at most top 7 items per array to avoid context blowout
            return obj.slice(0, 7).map(item => stripNoise(item, depth + 1)).filter(Boolean);
        }

        if (typeof obj === 'object') {
            const clean: any = {};
            for (const [key, value] of Object.entries(obj)) {
                // Aggressively drop heavy/noisy keys common in our schemas
                if ([
                    'evidenceQuotes', 'excerpts', 'supportedBy', 'rationale',
                    'sourceRef', 'id', 'color', 'createdAt', 'updatedAt',
                    'x', 'y', 'vx', 'vy', 'index'
                ].includes(key)) {
                    continue; // Skip entirely
                }

                const cleanedValue = stripNoise(value, depth + 1);
                // Drop empty objects/arrays to shrink JSON payload
                if (cleanedValue !== undefined &&
                    !(Array.isArray(cleanedValue) && cleanedValue.length === 0) &&
                    !(typeof cleanedValue === 'object' && Object.keys(cleanedValue).length === 0)) {
                    clean[key] = cleanedValue;
                }
            }
            return clean;
        }

        return obj; // Numbers, booleans pass through
    };

    // targeted aggressive mapping before the generic recursive strip
    const compressed = {
        cultural: raw.cultural ? {
            themes: raw.cultural.macro_themes?.map((t: any) => ({ name: t.name })),
            frames: raw.cultural.state_market_framing?.key_metaphors,
            justifications: raw.cultural.justification_regimes?.dominant_orders
        } : null,

        institutional: raw.institutional ? {
            clashes: raw.institutional.hybridity_friction_zones,
            dominance: raw.institutional.dominance_hierarchy
        } : null,

        resistance: raw.resistance ? {
            frictions: raw.resistance.friction_points_summary
        } : null,

        abstractMachine: raw.abstractMachine ? {
            diagram: raw.abstractMachine.diagram,
            articulations: raw.abstractMachine.double_articulation ? {
                clashes: raw.abstractMachine.double_articulation.clashes?.slice(0, 3),
                resonances: raw.abstractMachine.double_articulation.resonances?.slice(0, 3)
            } : null
        } : null,

        ontology: {
            // Only keep names and types for context
            actors: raw.actors?.slice(0, 15).map(a => ({ name: a.name, type: a.type })),
            ghosts: raw.ghostNodes?.slice(0, 10).map(g => ({ name: g.name, gap: truncate(g.ghostReason || g.description, 100) }))
        },

        compass: raw.configurations?.slice(0, 5).map(c => ({
            name: c.name,
            territorialization: c.properties?.territorialization_score,
            codingIntensity: c.properties?.coding_intensity_score
        })),

        crossCaseSynthesis: raw.crossCaseExport ? {
            impacts: raw.crossCaseExport.impactNarrative
        } : null
    };

    // Final recursive strip for any missed noise
    const finalClean = stripNoise(compressed);

    return JSON.stringify(finalClean, null, 2);
}

