const PARTICIPATORY_KEYWORDS = [
    'co-design', 'veto power', 'citizen jury', 'public consultation', 'multi-stakeholder', 'consensus',
    'oversight', 'accountability', 'transparency', 'explainability', 'audit', 'feedback', 'redress', 'appeal', 'collaboration', 'partnership', 'agency', 'choice', 'democratic'
];
const ASYMMETRICAL_KEYWORDS = [
    'unilateral', 'compliance requirement', 'terms of service', 'mandatory', 'enforcement', 'top-down',
    'centralized', 'control', 'authority', 'restricted', 'prohibited', 'disallowed', 'monitoring', 'rules', 'opaque', 'black box', 'limited access'
];

function calculateScore(text: string, positiveKeywords: string[], negativeKeywords: string[]): number {
    const lowerText = text.toLowerCase();
    let score = 0;
    let count = 0;

    positiveKeywords.forEach(keyword => {
        if (lowerText.includes(keyword)) {
            score += 1;
            count++;
        }
    });

    negativeKeywords.forEach(keyword => {
        if (lowerText.includes(keyword)) {
            score -= 1;
            count++;
        }
    });

    // Normalize to -1 to 1 range, avoiding division by zero
    // We use a sigmoid-like squash or simple clamping. Here, simple clamping with a scaling factor.
    // Assuming 5 keywords is a "strong" signal.
    return Math.max(-1, Math.min(1, score * 0.2));
}

export function calculateCompassScore(text: string, label: string): CompassPoint {
    const y = calculateScore(text, REGENERATIVE_KEYWORDS, EXTRACTIVE_KEYWORDS);
    const x = calculateScore(text, PARTICIPATORY_KEYWORDS, ASYMMETRICAL_KEYWORDS);
    return { x, y, label };
}

export function calculateDrift(policyText: string, techText: string): DriftVector {
    const rhetoric = calculateCompassScore(policyText, "Rhetoric");
    const reality = calculateCompassScore(techText, "Reality");

    const driftX = reality.x - rhetoric.x;
    const driftY = reality.y - rhetoric.y;
    const magnitude = Math.sqrt(driftX * driftX + driftY * driftY);

    return {
        rhetoric,
        reality,
        driftX,
        driftY,
        magnitude
    };
}

import OpenAI from 'openai';
import { AnalysisResult } from '@/types';
import { EscalationStatus, EscalationConfiguration, EscalationLevel, EscalationReasonCode } from '@/types/escalation';

// Define the structure for the AI's internal analysis response
interface AIPatternDetection {
    subtle_determinism: {
        detected: boolean;
        confidence: number;
        evidence: string[]; // Quotes
        mechanism?: string; // [NEW] Explanation of how language functions
    };
    hidden_normativity: {
        detected: boolean;
        confidence: number;
        evidence: string[];
        mechanism?: string;
    };
    scope_creep: {
        detected: boolean;
        confidence: number;
        evidence: string[];
        mechanism?: string;
    };
    overall_confidence: number;
    epistemic_uncertainty: boolean; // True if the model feels unqualified or context is missing
}

/**
 * The "Pattern Sentinel" - Epistemic Auditor.
 * Scans analysis results for specific discursive risks that deterministic rules miss.
 */
export async function runEscalationEvaluation(
    openai: OpenAI,
    analysis: AnalysisResult,
    config: EscalationConfiguration
): Promise<Partial<EscalationStatus>> {

    const context = `
    Analysis Summary: ${analysis.overall_assessment || analysis.key_insight || "N/A"}
    Key Insights: ${analysis.key_insight || "N/A"}
    Blindspots: ${analysis.system_critique?.blind_spots?.map((b: any) => typeof b === 'string' ? b : b.title).join('; ') || "None"}
    `;

    const prompt = (await import('@/prompts/escalation-sentinel')).PATTERN_SENTINEL_PROMPT;

    try {
        const response = await openai.chat.completions.create({
            model: "gpt-4o", // Use standard model for compatibility
            messages: [
                { role: "system", content: prompt },
                { role: "user", content: `CONTEXT TO AUDIT:\n${context}` }
            ],
            response_format: { type: "json_object" },
            temperature: 0.2 // Low temperature for consistent detection
        });

        const resultText = response.choices[0].message.content || "{}";
        const detection: AIPatternDetection = JSON.parse(resultText);

        // --- MAPPING LOGIC (The "Binding Policy") ---
        // The AI detects patterns; WE decide the consequences.

        const reasons: EscalationReasonCode[] = [];
        let level: EscalationLevel = 'NONE';
        const rationaleParts: string[] = [];

        // 1. Check for Epistemic Uncertainty (The "Uncertainty Principle")
        // If the auditor is unsure, we escalate to MEDIUM for human review.
        if (detection.epistemic_uncertainty || detection.overall_confidence < 0.6) {
            let explanation = "Pattern Sentinel reported high epistemic uncertainty. Human review required to verify analysis validity.";

            // Append any specific partial detections that contributed to confusion
            const fragments = [];
            if (detection.subtle_determinism?.evidence?.length) {
                const mech = detection.subtle_determinism.mechanism || "Phrasing that presents contingent outcomes as inevitable.";
                fragments.push(`Possible Determinism: ${mech}\nEvidence: "${detection.subtle_determinism.evidence.join('", "')}"`);
            }
            if (detection.hidden_normativity?.evidence?.length) {
                const mech = detection.hidden_normativity.mechanism || "Prescriptive statements disguised as descriptive facts.";
                fragments.push(`Possible Normativity: ${mech}\nEvidence: "${detection.hidden_normativity.evidence.join('", "')}"`);
            }
            if (detection.scope_creep?.evidence?.length) {
                const mech = detection.scope_creep.mechanism || "Claims of global validity based on local evidence.";
                fragments.push(`Possible Scope Creep: ${mech}\nEvidence: "${detection.scope_creep.evidence.join('", "')}"`);
            }

            if (fragments.length > 0) {
                explanation += `\n\nAmbiguity Context:\n${fragments.join('\n\n')}`;
            }

            return {
                level: 'MEDIUM',
                status: 'DETECTED',
                reasons: ['MANUAL_TRIGGER'], // Mapping uncertainty to manual trigger for review
                rationale: explanation
            };
        }

        // 2. Map Detections to Risks
        if (detection.subtle_determinism.detected && detection.subtle_determinism.confidence > 0.7) {
            reasons.push('RECURRENT_PATTERN'); // Using closest code, or we might need a new one like 'DISCURSIVE_RISK'
            const mech = detection.subtle_determinism.mechanism || "Phrasing that presents contingent outcomes as inevitable.";
            rationaleParts.push(`Subtle Determinism: ${mech} | Evidence: ${detection.subtle_determinism.evidence.join('; ')}`);
        }

        if (detection.hidden_normativity.detected && detection.hidden_normativity.confidence > 0.7) {
            reasons.push('HIGH_COLONIALITY'); // Conceptual mapping: Normativity often implies coloniality
            const mech = detection.hidden_normativity.mechanism || "Prescriptive statements disguised as descriptive facts.";
            rationaleParts.push(`Hidden Normativity: ${mech} | Evidence: ${detection.hidden_normativity.evidence.join('; ')}`);
        }

        if (detection.scope_creep.detected && detection.scope_creep.confidence > 0.7) {
            reasons.push('HIGH_ABSENCE'); // Conceptual mapping: Scope creep ignores absence of evidence
            const mech = detection.scope_creep.mechanism || "Claims of global validity based on local evidence.";
            rationaleParts.push(`Scope Creep: ${mech} | Evidence: ${detection.scope_creep.evidence.join('; ')}`);
        }

        // 3. Determine Level
        if (reasons.length > 0) {
            // "Grey Area" risks default to SOFT (Advisory) unless Recurrence or config says otherwise.
            // But per critique: "Uncertainty defaults to scrutiny".
            // Since we have specific detections here with high confidence, we set to SOFT to prompt reassembly,
            // but we can upgrade to MEDIUM if multiple risks are present.

            if (reasons.length >= 2) {
                level = 'MEDIUM'; // Multiple discursive risks -> Binding Reassembly
            } else {
                level = 'SOFT'; // Single discursive risk -> Advisory
            }
        }

        return {
            level,
            status: level === 'NONE' ? 'RESOLVED' : 'DETECTED',
            reasons,
            rationale: rationaleParts.join('\n') || "No discursive risks detected by Pattern Sentinel."
        };

    } catch (error) {
        console.error("Pattern Sentinel Failure:", error);
        // Fallback: If AI fails, we escalate to MEDIUM (Uncertainty Principle)
        return {
            level: 'MEDIUM',
            status: 'DETECTED',
            reasons: ['MANUAL_TRIGGER'],
            rationale: "Pattern Sentinel failed to execute. System defaulting to scrutiny (MEDIUM)."
        };
    }
}

import { AnalysisResult } from '../../types';
import { EscalationStatus, EscalationConfiguration, EscalationLevel } from '../../types/escalation';

// Mock context for Phase 1 - In Phase 2 this will be injected or fetched
export interface SystemContext {
    corpusSize?: number;
    recurrence_count?: number;
    recurrenceMap?: Record<string, number>;
}

/**
 * Computes configuration features for the escalation engine.
 * Specifically targets: Recurrence, Severity, and Variance.
 */
function computeConfigurationInference(analysis: AnalysisResult, context?: SystemContext): EscalationConfiguration {
    // 1. Risk Domain Severity (Heuristic based on keywords or tags)
    let severity: 'GENERAL' | 'MEDICAL' | 'LEGAL' | 'CRITICAL' = 'GENERAL';
    const text = (analysis.key_insight || analysis.raw_response || '').toLowerCase();

    if (text.includes('medical') || text.includes('patient') || text.includes('health')) severity = 'MEDICAL';
    if (text.includes('law') || text.includes('regulation') || text.includes('rights')) severity = 'LEGAL';

    // 2. Recurrence Count (Injected via SystemContext)
    const recurrence_count = context?.recurrence_count || 1;

    return {
        recurrence_count,
        risk_domain_severity: severity,
        evaluator_variance: 0,
        enforcement_signal_strength: 'LOW'
    };
}

// --------------------------------------------------------------------------
// RULE ENGINE IMPLEMENTATION
// --------------------------------------------------------------------------

/**
 * Interface definition for a Governance Rule.
 * This structure allows rules to be serialized/stored in DB in Phase 5.
 */
export interface GovernanceRule {
    id: string;
    description: string;
    evaluate: (analysis: AnalysisResult, config: EscalationConfiguration) => boolean;
    consequence: {
        level: EscalationLevel;
        reason: string;
    };
    meta?: {
        source: 'CONSTITUTION' | 'COMMUNITY_VOTE';
        version: number;
    };
}

/**
 * THE LIVE CONSTITUTION (Default Rules)
 * These are the current "If-Then" rules ratified by the system.
 */
export const GOVERNANCE_RULES: GovernanceRule[] = [
    {
        id: 'RULE_BLINDSPOT_INTENSITY',
        description: 'Flag High Blindspot Intensity as Advisory',
        evaluate: (a) => a.assemblage_analysis?.blindspot_intensity === 'High',
        consequence: {
            level: 'SOFT',
            reason: 'High Blindspot Intensity detected.'
        }
    },
    {
        id: 'RULE_HIGH_STAKES_DOMAIN',
        description: 'Bind Reassembly for High Stakes Domains with High Absence',
        evaluate: (a, c) => a.assemblage_analysis?.blindspot_intensity === 'High' &&
            (c.risk_domain_severity === 'MEDICAL' || c.risk_domain_severity === 'CRITICAL'),
        consequence: {
            level: 'MEDIUM',
            reason: 'High Absence in High-Stakes Domain.'
        }
    },
    {
        id: 'RULE_HIGH_RISK_TRAJECTORY',
        description: 'Bind Reassembly for High Risk Trajectories',
        evaluate: (a) => {
            const flights = a.assemblage_analysis?.trajectory_analysis?.lines_of_flight || [];
            return flights.some(l => l.risk_level === 'High');
        },
        consequence: {
            level: 'MEDIUM',
            reason: 'Detected High-Risk Line(s) of Flight.'
        }
    },
    {
        id: 'RULE_RECURRENT_PATTERN',
        description: 'Block Logic that makes frequent High-Risk appearances',
        evaluate: (a, c) => a.assemblage_analysis?.blindspot_intensity === 'High' &&
            (c.recurrence_count || 0) >= 3,
        consequence: {
            level: 'HARD',
            reason: 'Recurrent Pattern Logic detected across 3+ documents. Durability exceeds threshold.'
        }
    }
];

/**
 * Deterministic Rule Engine
 * Iterates through the active Ruleset and determines the highest signal.
 */
function evaluateDeterministicRules(analysis: AnalysisResult, config: EscalationConfiguration): { level: EscalationLevel, reasons: string[] } {
    const reasons: string[] = [];
    let maxLevelVal = 0;
    let maxLevel: EscalationLevel = 'NONE';

    for (const rule of GOVERNANCE_RULES) {
        try {
            if (rule.evaluate(analysis, config)) {
                reasons.push(rule.consequence.reason);
                const val = getLevelSeverity(rule.consequence.level);
                if (val > maxLevelVal) {
                    maxLevelVal = val;
                    maxLevel = rule.consequence.level;
                }
            }
        } catch (err) {
            console.error(`Rule ${rule.id} failed to evaluate:`, err);
        }
    }

    return { level: maxLevel, reasons };
}

// --------------------------------------------------------------------------
// SYSTEM HELPERS
// --------------------------------------------------------------------------

function getLevelSeverity(level: EscalationLevel): number {
    switch (level) {
        case 'HARD': return 3;
        case 'MEDIUM': return 2;
        case 'SOFT': return 1;
        case 'NONE': return 0;
        default: return 0;
    }
}

/**
 * Main Evaluation Function
 */
export async function evaluateEscalation(analysis: AnalysisResult, context?: SystemContext): Promise<EscalationStatus> {
    const config = computeConfigurationInference(analysis, context);

    // 1. Run Deterministic Rules
    const deterministic = evaluateDeterministicRules(analysis, config);
    let finalLevel = deterministic.level;
    const finalReasons = [...deterministic.reasons];
    let finalRationale = deterministic.reasons.join('\n'); // Default rationale from rules

    // 2. Hybrid Check
    if (finalLevel !== 'HARD') {
        try {
            const { evaluateEscalationWithAI } = await import('../../services/governance/escalationAi');
            const aiResult = await evaluateEscalationWithAI(analysis, config);

            if (aiResult) {
                if (getLevelSeverity(aiResult.level!) > getLevelSeverity(finalLevel)) {
                    finalLevel = aiResult.level!;
                    if (aiResult.reasons) finalReasons.push(...aiResult.reasons);
                    // Append AI rationale clearly
                    if (aiResult.rationale) finalRationale = finalRationale
                        ? `${finalRationale}\n\n[AI Signal]: ${aiResult.rationale}`
                        : aiResult.rationale;
                } else if (aiResult.level === finalLevel && aiResult.level !== 'NONE') {
                    if (aiResult.reasons) finalReasons.push(...aiResult.reasons);
                    if (aiResult.rationale) finalRationale += `\n\n[AI Signal]: ${aiResult.rationale}`;
                }
                config.evaluator_variance = Math.abs(getLevelSeverity(deterministic.level) - getLevelSeverity(aiResult.level!)) / 3;
            }
        } catch (e) {
            // console.warn("Pattern Sentinel skipped due to error:", e);
        }
    }

    return {
        level: finalLevel,
        status: finalLevel === 'NONE' ? 'RESOLVED' : 'DETECTED',
        reasons: finalReasons as any[],
        configuration: config,
        actions: [],
        printed_limitations: [],
        rationale: finalRationale
    };
}

import { EcosystemActor, EcosystemEdge } from '@/types/ecosystem';

interface Node {
    id: string;
    type: string;
}

interface Edge {
    source: string;
    target: string;
    weight: number;
}

interface CommunityResult {
    communityId: number;
    nodes: string[];
    diversityScore: number;
    metrics: {
        humanCount: number;
        nonHumanCount: number;
        size: number;
    };
}

/**
 * Calculates the Shannon Diversity Index for a set of actors based on their types.
 * Formula: H = -sum(pi * ln(pi))
 */
export function calculateDiversityIndex(actors: EcosystemActor[]): number {
    if (actors.length === 0) return 0;

    const typeCounts: Record<string, number> = {};
    actors.forEach(actor => {
        // Group broadly into Socio-Technical Categories for meaningful diversity
        let category = 'Other';
        const type = actor.type.toLowerCase();

        if (['policymaker', 'civil society', 'academic', 'activist'].some(t => type.includes(t))) {
            category = 'Human/Social';
        } else if (['algorithm', 'dataset', 'infrastructure', 'technology', 'code'].some(t => type.includes(t))) {
            category = 'Non-Human/Technical';
        } else if (['law', 'legalobject', 'regulation'].some(t => type.includes(t))) {
            category = 'Institutional/Legal';
        } else if (['startup', 'corporation', 'market'].some(t => type.includes(t))) {
            category = 'Market/Economic';
        }

        typeCounts[category] = (typeCounts[category] || 0) + 1;
    });

    const total = actors.length;
    let entropy = 0;

    Object.values(typeCounts).forEach(count => {
        const p = count / total;
        if (p > 0) {
            entropy -= p * Math.log(p);
        }
    });

    // Normalize (Index usually 0 to ~1.5 for 4 categories). 
    // We normalize to 0-1 range assuming max 4 categories: max entropy ~1.38
    const maxEntropy = Math.log(4);
    return Math.min(1, entropy / maxEntropy);
}

/**
 * Detects communities using a simplified Louvain Modularity Algorithm.
 * Adapted for client-side synchronous execution on small-to-medium graphs.
 */
export function detectCommunitiesLouvain(
    actors: EcosystemActor[],
    edges: { source: string; target: string }[]
): CommunityResult[] {
    // 1. Initialize each node in its own community
    const nodeCommunities = new Map<string, number>();
    const communities = new Map<number, Set<string>>();
    let nextCommunityId = 0;

    actors.forEach(actor => {
        nodeCommunities.set(actor.id, nextCommunityId);
        communities.set(nextCommunityId, new Set([actor.id]));
        nextCommunityId++;
    });

    // adjacency list
    const adj: Record<string, string[]> = {};
    actors.forEach(a => adj[a.id] = []);
    edges.forEach(e => {
        // Handle both object and string references from d3
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const s = typeof e.source === 'object' ? (e.source as any).id : e.source;
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const t = typeof e.target === 'object' ? (e.target as any).id : e.target;

        if (adj[s]) adj[s].push(t);
        if (adj[t]) adj[t].push(s);
    });

    // 2. Optimization Phase (Simplified: One pass Label Propagation with Modularity Heuristic)
    // Full Louvain is complex; a localized modularity greed is often sufficient for UI suggestions.
    // Iteratively move nodes to neighbor communities if it increases density.

    const m = edges.length; // Total edges (half-edges if undirected, but simplfied here)
    const twoM = m * 2;

    // Track total degree (sum of links) for each community
    const commTotDegree = new Map<number, number>();
    // Track degree of each node
    const nodeDegree: Record<string, number> = {};

    // Initialize degrees
    actors.forEach(a => {
        const d = adj[a.id]?.length || 0;
        nodeDegree[a.id] = d;
        commTotDegree.set(nodeCommunities.get(a.id)!, d);
    });

    let improvement = true;
    let iterations = 0;
    const MAX_ITERATIONS = 10;
    const RESOLUTION = 1.0; // Higher = smaller communities

    while (improvement && iterations < MAX_ITERATIONS) {
        improvement = false;
        iterations++;

        // Randomize order
        const shuffledActors = [...actors].sort(() => Math.random() - 0.5);

        for (const actor of shuffledActors) {
            const nodeId = actor.id;
            const currentComm = nodeCommunities.get(nodeId)!;
            const neighbors = adj[nodeId] || [];
            if (neighbors.length === 0) continue;

            const ki = nodeDegree[nodeId];

            // Remove from current community for calculation
            commTotDegree.set(currentComm, (commTotDegree.get(currentComm) || 0) - ki);
            // (Conceptually remove node, so we can see where it fits best as if it were free)

            // Calculate "best" community based on Modularity Gain
            // Gain = k_i_in - resolution * (Tot_c * k_i) / 2m

            const neighborCommWeights = new Map<number, number>();
            neighbors.forEach(nId => {
                const c = nodeCommunities.get(nId);
                // IF we allow self-loops, we'd handle it, but here simple graph
                if (c !== undefined) {
                    neighborCommWeights.set(c, (neighborCommWeights.get(c) || 0) + 1); // weight is 1
                }
            });

            // Consider staying in current (after conceptual removal, it is empty of this node,
            // but effectively we are comparing moving to C_current vs C_neighbor)
            // Actually simpler: Find max Delta Q for all neighbor communities + current (which has 0 gain if we don't move, but we calculated gain relative to being isolated)

            let bestComm = currentComm;
            // Best score starts with the score of returning to current community
            // k_in_current - res * (Tot_current * ki) / 2m
            const k_in_current = neighborCommWeights.get(currentComm) || 0;
            const tot_current = commTotDegree.get(currentComm) || 0;
            let maxGain = k_in_current - (RESOLUTION * tot_current * ki) / twoM;

            // Check all neighbor communities
            neighborCommWeights.forEach((k_in, commId) => {
                if (commId === currentComm) return;
                const tot_c = commTotDegree.get(commId) || 0;
                const gain = k_in - (RESOLUTION * tot_c * ki) / twoM;

                if (gain > maxGain) {
                    maxGain = gain;
                    bestComm = commId;
                }
            });

            // Apply move
            // Add back to (potentially new) community
            commTotDegree.set(bestComm, (commTotDegree.get(bestComm) || 0) + ki);

            if (bestComm !== currentComm) {
                // Update structure
                communities.get(currentComm)?.delete(nodeId);
                if (communities.get(currentComm)?.size === 0) communities.delete(currentComm);

                if (!communities.has(bestComm)) communities.set(bestComm, new Set());
                communities.get(bestComm)!.add(nodeId);
                nodeCommunities.set(nodeId, bestComm);

                improvement = true;
            }
        }
    }

    // 3. Format Results
    const results: CommunityResult[] = [];
    communities.forEach((members, commId) => {
        const memberIds = Array.from(members);
        // Filter tiny clusters (noise)
        if (memberIds.length < 3) return;

        const memberActors = actors.filter(a => memberIds.includes(a.id));
        const diversity = calculateDiversityIndex(memberActors);

        // Count rough types
        const humanCount = memberActors.filter(a =>
            ['policymaker', 'civil society', 'academic'].some(t => a.type.toLowerCase().includes(t))
        ).length;
        const nonHumanCount = memberActors.length - humanCount;

        results.push({
            communityId: commId,
            nodes: memberIds,
            diversityScore: diversity,
            metrics: {
                humanCount,
                nonHumanCount,
                size: memberActors.length
            }
        });
    });

    // Sort by Diversity (High to Low) then Size
    return results.sort((a, b) => (b.diversityScore * 2 + b.metrics.size) - (a.diversityScore * 2 + a.metrics.size));
}

import { EcosystemActor } from "@/types/ecosystem";

export function getLinkDetails(sourceType: string, targetType: string): { label: string, description: string, flow_type: 'power' | 'logic' } {
    if (sourceType === "Policymaker" && targetType === "PrivateTech") return { label: "Regulates", description: "Imposes legal boundaries.", flow_type: 'power' };
    if (sourceType === "Policymaker" && targetType === "Civil Society") return { label: "Excludes", description: "Social marginalization.", flow_type: 'power' };
    if (sourceType === "Information" && targetType === "Policymaker") return { label: "Informs", description: "Epistemic basis.", flow_type: 'logic' };

    if (sourceType === "PrivateTech" && targetType === "Academic") return { label: "Enables", description: "Tools for research.", flow_type: 'logic' };
    if (sourceType === "Infrastructure" && targetType === "PrivateTech") return { label: "Enables", description: "Computational substrate.", flow_type: 'power' };
    if (sourceType === "PrivateTech" && targetType === "Algorithm") return { label: "Delegates", description: "Authority to code.", flow_type: 'power' };

    if (sourceType === "Algorithm" && targetType === "Dataset") return { label: "Extracts", description: "Mines patterns.", flow_type: 'power' };
    if (sourceType === "Infrastructure" && targetType === "Dataset") return { label: "Extracts", description: "Accumulates data capital.", flow_type: 'power' };

    if (sourceType === "Academic" && targetType === "Algorithm") return { label: "Audits", description: "Critical examination.", flow_type: 'logic' };

    if (sourceType === "Civil Society" && targetType === "Academic") return { label: "Studies", description: "Community context.", flow_type: 'logic' };
    if (sourceType === "Policymaker" && targetType === "Algorithm") return { label: "Governs", description: "Regulates behavior.", flow_type: 'power' };

    if (sourceType.includes("AlgorithmicAgent") || targetType.includes("AlgorithmicAgent")) return { label: "Operates", description: "Autonomous action.", flow_type: 'power' };
    if (sourceType === "LegalObject" || targetType === "LegalObject") return { label: "Codifies", description: "Materializes law.", flow_type: 'logic' };
    if (sourceType === targetType) return { label: "Coordinates", description: "Internal loops.", flow_type: 'logic' };

    return { label: "Relates To", description: "Generic connection.", flow_type: 'logic' };
}

export function generateEdges(actors: EcosystemActor[]) {
    const edges: { source: EcosystemActor; target: EcosystemActor; label: string; description: string; flow_type: 'power' | 'logic' }[] = [];

    actors.forEach((source, i) => {
        actors.slice(i + 1).forEach((target) => {
            const sType = source.type;
            const tType = target.type;

            // Helper to check connection bidirectionally
            const isTypePair = (t1: string, t2: string) =>
                (sType === t1 && tType === t2) || (sType === t2 && tType === t1);

            const shouldConnect = (
                isTypePair("Policymaker", "Civil Society") ||
                isTypePair("PrivateTech", "Academic") ||
                isTypePair("Policymaker", "PrivateTech") ||
                isTypePair("Civil Society", "Academic") ||
                isTypePair("Infrastructure", "PrivateTech") ||
                isTypePair("Infrastructure", "Policymaker") ||
                isTypePair("Infrastructure", "Academic") ||
                isTypePair("PrivateTech", "Algorithm") ||
                isTypePair("Academic", "Algorithm") ||
                isTypePair("Algorithm", "Dataset") ||
                isTypePair("Policymaker", "Algorithm") ||
                isTypePair("Infrastructure", "Algorithm") ||
                isTypePair("Infrastructure", "Dataset") ||
                isTypePair("AlgorithmicAgent", "Dataset") ||
                isTypePair("AlgorithmicAgent", "Infrastructure") ||
                isTypePair("AlgorithmicAgent", "Policymaker") ||
                isTypePair("AlgorithmicAgent", "Civil Society") ||
                isTypePair("AlgorithmicAgent", "PrivateTech") ||
                isTypePair("AlgorithmicAgent", "Academic") ||

                isTypePair("LegalObject", "Policymaker") ||
                isTypePair("LegalObject", "Civil Society") ||

                // Broaden Policymaker connections
                (sType === "Policymaker" && tType === "Policymaker") || // Inter-agency
                (sType === "Civil Society" && tType === "Civil Society") || // Coalitions

                // [FIX] Explicit Ghost Node Connectivity Fallback
                // If either node is a ghost, explicitly ensure it connects to Policymakers (Exclusion) or other Civil Society (Solidarity)
                (('isGhost' in source && (source as any).isGhost) && (tType === "Policymaker" || tType === "PrivateTech" || tType === "Civil Society")) ||
                (('isGhost' in target && (target as any).isGhost) && (sType === "Policymaker" || sType === "PrivateTech" || sType === "Civil Society")) ||

                // Universal Catch-All for "Related" nodes if manually forced? No, stick to type logic for coherence.
                false
            );

            if (shouldConnect) {
                const details = getLinkDetails(sType, tType);
                edges.push({
                    source,
                    target,
                    label: details.label,
                    description: details.description,
                    flow_type: details.flow_type
                });
            }
        });
    });

    return edges;
}

// [NEW] Hull Calculation Logic
export function getHullPath(points: { x: number, y: number }[]) {
    if (points.length < 3) return "";
    points.sort((a, b) => a.x - b.x || a.y - b.y);

    // Cross product of vectors OA and OB
    const cross = (o: { x: number, y: number }, a: { x: number, y: number }, b: { x: number, y: number }) =>
        (a.x - o.x) * (b.y - o.y) - (a.y - o.y) * (b.x - o.x);

    const lower = [];
    for (let i = 0; i < points.length; i++) {
        while (lower.length >= 2 && cross(lower[lower.length - 2], lower[lower.length - 1], points[i]) <= 0) lower.pop();
        lower.push(points[i]);
    }

    const upper = [];
    for (let i = points.length - 1; i >= 0; i--) {
        while (upper.length >= 2 && cross(upper[upper.length - 2], upper[upper.length - 1], points[i]) <= 0) upper.pop();
        upper.push(points[i]);
    }

    upper.pop(); lower.pop();
    const hull = lower.concat(upper);
    return `M ${hull.map(p => `${p.x},${p.y}`).join(" L ")} Z`;
}

import { AnalysisResult } from "@/types";

export interface LiberatoryCapacity {
    score: number; // 0-8
    level: "Rhetorical/Fragile" | "Partial/Conditional" | "Structural/Robust";
    signals: {
        power_reversibility: boolean;
        agency_protection: boolean;
        epistemic_plurality: boolean;
        exit_rights: boolean;
        repair_recognition: boolean;
        temporal_openness: boolean;
        proportionality: boolean;
        contestable_safety: boolean;
    };
    explanations: {
        power: string;
        agency: string;
        epistemic: string;
        exit: string;
        repair: string;
        temporal: string;
        proportionality: string;
        safety: string;
    };
}

export function calculateLiberatoryCapacity(analysis: AnalysisResult): LiberatoryCapacity {
    const signals = {
        power_reversibility: false,
        agency_protection: false,
        epistemic_plurality: false,
        exit_rights: false,
        repair_recognition: false,
        temporal_openness: false,
        proportionality: false,
        contestable_safety: false
    };

    const explanations = {
        power: "",
        agency: "",
        epistemic: "",
        exit: "",
        repair: "",
        temporal: "",
        proportionality: "",
        safety: ""
    };

    const scores = analysis.governance_scores || { centralization: 50, rights_focus: 50, coloniality: 50, procedurality: 50 };

    // 1. Power Reversibility
    // Inverse of Centralization/Power Hardening
    if ((scores.centralization || 0) < 40 && (scores.procedurality || 0) < 70) {
        signals.power_reversibility = true;
        explanations.power = "Low centralization allows for decision reversal and contestability.";
    } else {
        explanations.power = "High centralization or rigid procedure limits reversibility.";
    }

    // 2. Situated Agency Protection
    // Agency Score check
    // Heuristic: Check if rights_focus is high or if agency text is positive
    const agencyText = analysis.agency_codesign_self_determination || "";
    if ((scores.rights_focus || 0) > 65 || agencyText.toLowerCase().includes("co-design")) {
        signals.agency_protection = true;
        explanations.agency = "Strong focus on rights or co-design protects human agency.";
    } else {
        explanations.agency = "Agency protections appear weak or undefined.";
    }

    // 3. Epistemic Plurality
    // Coloniality Score < 40 + Silence < 2
    const silenceCount = analysis.silenced_voices?.length || 0;
    if ((scores.coloniality || 0) < 45 && silenceCount < 2) {
        signals.epistemic_plurality = true;
        explanations.epistemic = "Low coloniality metric suggests openness to diverse knowledge systems.";
    } else {
        explanations.epistemic = "Epistemic closure detected (Coloniality > 45 or Silenced Voices).";
    }

    // 4. Exit, Pause, or Refusal Rights
    // Check rights pillar or keywords
    const rightsText = analysis.structural_pillars?.rights?.description || "";
    if (rightsText.toLowerCase().includes("refusal") || rightsText.toLowerCase().includes("opt-out") || (scores.rights_focus || 0) > 75) {
        signals.exit_rights = true;
        explanations.exit = "Explicit mention of refusal/opt-out or very high rights score.";
    } else {
        explanations.exit = "No structural guarantee of exit or refusal found.";
    }

    // 5. Recognition of Repair & Care Work
    // Keyword check in Temporal or Cultural analysis
    const temporal = analysis.temporal_orientation;
    const isTemporalObj = temporal && typeof temporal === 'object';
    const temporalEvidence = isTemporalObj ? (temporal as any).evidence : (typeof temporal === 'string' ? temporal : "");
    const framingText = analysis.technology_role || "";
    const hasCareKeywords = /repair|care|maintenance|stewardship|healing/i.test(temporalEvidence + framingText);

    if (hasCareKeywords || (isTemporalObj && (temporal as any).framing === "Care")) {
        signals.repair_recognition = true;
        explanations.repair = "Explicit recognition of maintenance, care, or stewardship.";
    } else {
        explanations.repair = "Focus is on innovation/deployment, obscuring maintenance labor.";
    }

    // 6. Temporal Openness
    if (isTemporalObj && (temporal as any).score > 60) {
        signals.temporal_openness = true;
        explanations.temporal = "Future framed as open/iterative, not determined/urgent.";
    } else {
        explanations.temporal = "Future framed as closed, urgent, or inevitable.";
    }

    // 7. Capacity-Sensitive Proportionality
    // Economic analysis check
    if (analysis.economic_burden?.burden_bearer === "Developer" || analysis.economic_burden?.burden_bearer === "State") {
        // If burden is on powerful actors, likely proportional
        signals.proportionality = true;
        explanations.proportionality = `Burden placed on ${analysis.economic_burden.burden_bearer}, protecting vulnerable capacity.`;
    } else if (analysis.economic_burden?.burden_bearer === "Individual") {
        explanations.proportionality = "Burden shifts to individuals, ignoring capacity constraints.";
    } else {
        explanations.proportionality = "Unclear distribution of burden relative to capacity.";
    }

    // 8. Contestable Safety Framing
    // Safety not used as "state of exception"
    // Heuristic: If legitimacy is NOT purely "Technocratic" AND Temporal is NOT "Urgency"
    const legitimacySource = analysis.legitimacy_claims?.source || "";
    const isUrgency = isTemporalObj && (temporal as any).framing === "Urgency";

    if (!legitimacySource.includes("Technocratic") && !isUrgency) {
        signals.contestable_safety = true;
        explanations.safety = "Safety framed within democratic/rights context, not existential emergency.";
    } else {
        explanations.safety = "Safety may be used to bypass contestability (Technocratic/Urgency).";
    }

    // Composite Score
    const score = Object.values(signals).filter(s => s).length;
    let level: LiberatoryCapacity["level"] = "Rhetorical/Fragile";
    if (score >= 6) level = "Structural/Robust";
    else if (score >= 3) level = "Partial/Conditional";

    return {
        score,
        level,
        signals,
        explanations
    };
}

