import { AnalysisResult } from "@/types";

export interface MicroFascismRisk {
    score: number; // 0-6
    level: "Interpretive" | "Directional Drift" | "Micro-Fascist Hardening";
    flags: {
        power_hardening: boolean;
        agency_collapse: boolean;
        epistemic_narrowing: boolean;
        structural_violence: boolean;
        temporal_closure: boolean;
        absence_as_control: boolean;
    };
    explanations: {
        power: string;
        agency: string;
        epistemic: string;
        structural: string;
        temporal: string;
        absence: string;
    };
}

export function calculateMicroFascismRisk(analysis: AnalysisResult): MicroFascismRisk {
    const flags = {
        power_hardening: false,
        agency_collapse: false,
        epistemic_narrowing: false,
        structural_violence: false,
        temporal_closure: false,
        absence_as_control: false
    };

    const explanations = {
        power: "",
        agency: "",
        epistemic: "",
        structural: "",
        temporal: "",
        absence: ""
    };

    const scores = analysis.governance_scores || { centralization: 50, procedurality: 50, market_power: 50, rights_focus: 50, flexibility: 50 };

    // 1. Power Hardening
    // Authority collapse into procedure or high centralization
    if ((scores.centralization || 0) > 75) {
        flags.power_hardening = true;
        explanations.power = `Centralization score (${scores.centralization}) exceeds critical threshold.`;
    } else if ((scores.procedurality || 0) > 85) {
        flags.power_hardening = true;
        explanations.power = `Procedurality score (${scores.procedurality}) indicates automated bureaucracy.`;
    }

    // 2. Agency Collapse
    // Agency reframed as liability
    const agencyScore = parseInt(analysis.agency_codesign_self_determination?.match(/(\d+)/)?.[1] || "50"); // Heuristic if not numeric field, but usually implicit
    // Actually we don't have a raw score for agency in governance_scores, so we infer from rights_focus or add it.
    // Let's use Rights Focus < 40 as proxy if explicit agency score missing, OR if we parse it from text.
    // Better: Use `rights_focus` context.
    if ((scores.rights_focus || 0) < 35) {
        flags.agency_collapse = true;
        explanations.agency = `Rights Focus (${scores.rights_focus}) is critically low, suggesting user liability.`;
    }

    // 3. Epistemic Narrowing
    // Knowledge standardization
    // Use Plurality/Inclusion text analysis or Coloniality Score
    if ((scores.coloniality || 0) > 60) {
        flags.epistemic_narrowing = true;
        explanations.epistemic = `Coloniality score (${scores.coloniality}) indicates domination of a single worldview.`;
    } else if (analysis.silenced_voices && analysis.silenced_voices.length > 3) {
        flags.epistemic_narrowing = true;
        explanations.epistemic = `High number of silenced voices (${analysis.silenced_voices.length}) detected.`;
    }

    // 4. Structural Violence
    // Material Consequences
    if (analysis.economic_burden) {
        if (analysis.economic_burden.market_consolidation_risk === "High") {
            flags.structural_violence = true;
            explanations.structural = "High risk of market consolidation detected.";
        } else if (analysis.economic_burden.burden_bearer === "Individual" || analysis.economic_burden.burden_bearer === "Society") {
            flags.structural_violence = true;
            explanations.structural = `Economic burden shifted to ${analysis.economic_burden.burden_bearer}.`;
        }
    }

    // 5. Temporal Closure
    // Teleology
    if (analysis.temporal_orientation && typeof analysis.temporal_orientation === 'object') {
        const temporal = analysis.temporal_orientation as any; // Fallback to any to avoid property access errors on complex unions
        if (temporal.score < 35) {
            flags.temporal_closure = true;
            explanations.temporal = `Temporal Openness score (${temporal.score}) indicates 'Desinty' or 'Urgency' framing.`;
        } else if (temporal.framing === "Urgency" || temporal.framing === "Destiny") {
            flags.temporal_closure = true;
            explanations.temporal = `Future framed as '${temporal.framing}', closing off alternatives.`;
        }
    }

    // 6. Absence as Control
    // No exit rights, invisible labor
    // We check system critique blind spots
    const blindSpots = analysis.system_critique?.blind_spots?.length || 0;
    if (blindSpots > 4) {
        flags.absence_as_control = true;
        explanations.absence = `Critical mass of blind spots (${blindSpots}) indicates governance by omission.`;
    }

    // Calculate Composite
    const score = Object.values(flags).filter(f => f).length;
    let level: MicroFascismRisk["level"] = "Interpretive";
    if (score >= 5) level = "Micro-Fascist Hardening";
    else if (score >= 3) level = "Directional Drift";

    return {
        score,
        level,
        flags,
        explanations
    };
}

import { GoogleGenerativeAI } from '@google/generative-ai';
import OpenAI from 'openai';
import { PromptRegistry, PROMPT_DEFINITIONS } from '@/lib/prompts/registry';
import { safeJSONParse } from '@/lib/analysis-utils';

export interface SearchResult {
    title: string;
    link: string;
    snippet: string;
    strategy?: string;
    explanation?: string;
}

/**
 * Executes a Google Custom Search for a given query.
 */
export async function executeGoogleSearch(query: string, apiKey: string, cx: string, maxResults: number = 10): Promise<SearchResult[]> {
    const url = `https://www.googleapis.com/customsearch/v1?key=${apiKey}&cx=${cx}&q=${encodeURIComponent(query)}&num=${Math.min(maxResults, 10)}`;
    try {
        console.log(`DEBUG: Executing Search: ${url}`);
        const res = await fetch(url);
        const d = await res.json();
        if (!res.ok) {
            console.error("Search API ERROR:", JSON.stringify(d, null, 2));
            return [];
        }
        if (!d.items) {
            console.warn("Search API returned OK but NO ITEMS:", JSON.stringify(d, null, 2));
        }
        return d.items?.map((item: { title: string; link: string; snippet: string }) => ({
            title: item.title,
            link: item.link,
            snippet: item.snippet,
        })) || [];
    } catch (e) {
        console.error("Fetch failed", e);
        return [];
    }
}

/**
 * Helper to process the raw JSON response from any AI model into curates results.
 */
function processCurationResponse(content: string, originalResults: SearchResult[]): SearchResult[] {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const parsed = safeJSONParse<any>(content, []);

    let itemsToProcess: any[] = [];

    // Robustly extract array
    if (Array.isArray(parsed)) {
        itemsToProcess = parsed;
    } else if (parsed && typeof parsed === 'object' && Array.isArray(parsed.items)) {
        itemsToProcess = parsed.items;
    }

    if (itemsToProcess.length > 0) {
        const curatedResults: SearchResult[] = [];

        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        itemsToProcess.forEach((item: any) => {
            let index = -1;
            let strategy = "Unclassified";
            let explanation = "";

            // Handle 'id' vs 'index' confusion
            const rawIndex = item.index !== undefined ? item.index : item.id;

            if (typeof item === 'number') {
                index = item;
            } else if (typeof item === 'object' && item !== null && (typeof rawIndex === 'number' || typeof rawIndex === 'string')) {
                index = parseInt(String(rawIndex));
                if (item.strategy) strategy = item.strategy;
                if (item.explanation) explanation = item.explanation;
                else if (item.context) explanation = item.context;
                else if (item.reason) explanation = item.reason;
            }

            if (index >= 0 && originalResults[index]) {
                // Fallback generation if AI failed
                if (!explanation || explanation === "Automated classification from Search") {
                    explanation = `AI identified this as ${strategy} based on keywords in the text.`;
                }

                curatedResults.push({
                    ...originalResults[index],
                    strategy: strategy,
                    explanation: explanation
                });
            }
        });

        if (curatedResults.length > 0) {
            return curatedResults;
        }
    }
    return [];
}

/**
 * Curates and classifies search results using Google Generative AI.
 * Enforces "Mandatory Explanation" validation.
 */
export async function curateResultsWithAI(
    results: SearchResult[],
    policyText: string,
    apiKey: string,
    modelName: string = "gemini-1.5-flash",
    userId?: string
): Promise<SearchResult[]> {
    if (results.length === 0) return [];

    try {
        const genAI = new GoogleGenerativeAI(apiKey);
        const model = genAI.getGenerativeModel({ model: modelName });

        // Fetch prompts
        let subjectPromptTemplate = PROMPT_DEFINITIONS['subject_identification'].defaultValue;
        let curationPromptTemplate = PROMPT_DEFINITIONS['resistance_curation'].defaultValue;

        if (userId) {
            subjectPromptTemplate = await PromptRegistry.getEffectivePrompt(userId, 'subject_identification');
            curationPromptTemplate = await PromptRegistry.getEffectivePrompt(userId, 'resistance_curation');
        }

        // EXTRACT SUBJECT ENTITY FIRST (Crucial for relevance)
        const subjectPrompt = subjectPromptTemplate.replace('${text}', policyText.substring(0, 1000));

        const subjectResult = await model.generateContent(subjectPrompt);
        const policySubject = subjectResult.response.text().trim().replace(/['"]/g, '');
        console.log("Extracted Policy Subject:", policySubject);

        const curationPrompt = curationPromptTemplate
            .replace('${policySubject}', policySubject)
            .replace('${items}', JSON.stringify(results.map((r, i) => ({ id: i, text: r.title + " " + r.snippet }))));

        const result = await model.generateContent(curationPrompt);
        const content = result.response.text().trim();

        const curatedResults = processCurationResponse(content, results);

        if (curatedResults.length > 0) {
            console.log(`AI Curation: Kept ${curatedResults.length} classified traces.`);
            return curatedResults;
        } else {
            console.log("AI Curation: Filtered all. Falling back to raw results.");
        }

    } catch (e) {
        console.warn("Google AI Curation failed (will attempt fallback):", (e as Error).message);
        // Return original results if curation fails or filters everything (safety net)
        return results;
    }

    return results;
}

