import { Source } from '@/types';
import { StorageService } from '@/lib/storage-service';
import { BASELINE_SOURCES } from '@/lib/data/baselines';

// Helper to managing explicitly deleted baselines
const getDeletedBaselines = async (userId: string): Promise<string[]> => {
    return (await StorageService.get<string[]>(userId, 'deleted_baselines')) || [];
};

const markBaselineAsDeleted = async (userId: string, id: string) => {
    const deleted = await getDeletedBaselines(userId);
    if (!deleted.includes(id)) {
        await StorageService.set(userId, 'deleted_baselines', [...deleted, id]);
    }
};

// Read sources from Redis (Atomic Hash Implementation)
export const getSources = async (userId: string): Promise<Source[]> => {
    // 1. Try to get from new Hash structure
    const sourceHash = await StorageService.getHash<Source>(userId, 'sources_v2');

    let sources: Source[] = [];

    if (sourceHash) {
        sources = Object.values(sourceHash);

        // [FIX] Ensure zombie baselines (stuck in storage but marked deleted) are filtered out
        if (sources.length > 0) {
            const deletedBaselines = await getDeletedBaselines(userId);
            if (deletedBaselines.length > 0) {
                sources = sources.filter(s => !deletedBaselines.includes(s.id));
            }
        }
    } else {
        // 2. Migration Path: Check for legacy array
        const legacySources = await StorageService.get<Source[]>(userId, 'sources');
        if (legacySources && legacySources.length > 0) {
            console.log(`[Migration] Migrating ${legacySources.length} sources to Hash for user ${userId}`);
            sources = legacySources;

            // Migrate to Hash
            for (const source of sources) {
                await StorageService.setHashField(userId, 'sources_v2', source.id, source);
            }

            // Cleanup legacy key to prevent zombie data if v2 becomes empty
            await StorageService.delete(userId, 'sources');
        } else {
            // New user or empty
            sources = [];
            // Seed if completely empty (and no legacy)
            // Note: Seeding intentionally skipped here to avoid logic duplication.
            // If seeding is needed, it should be done explicitly via addSource calls.
            // But for compatibility with old logic where we *returned empty array*, we start empty.
            // If the app relies on "if empty, add defaults", that logic belongs in the caller or here.
            // Re-adding simple seeding for empty state if needed, but Hash structure is cleaner empty.
        }
    }

    // Seeding: Ensure all BASELINE_SOURCES exist in the user's list
    // UNLESS they were explicitly deleted
    const deletedBaselines = await getDeletedBaselines(userId);

    for (const baseline of BASELINE_SOURCES) {
        if (deletedBaselines.includes(baseline.id)) {
            continue; // Skip if explicitly deleted
        }

        const exists = sources.some(s => s.id === baseline.id);
        if (!exists) {
            console.log(`[Seeding] Adding new baseline source: ${baseline.id}`);
            sources.push(baseline);
            // Persist immediately so it behaves like a normal source (editable etc)
            await StorageService.setHashField(userId, 'sources_v2', baseline.id, baseline);
        }
    }

    // Hot-patch loop: check for missing features in baselines (DR3/DR4 updates)
    // Optimization: Only patch if needed and save back to HASH specific fields
    const needsUpdate = false;
    const patchedSources = await Promise.all(sources.map(async (source) => {
        const baseline = BASELINE_SOURCES.find(b => b.id === source.id);
        let wasPatched = false;
        if (baseline) {
            const patched = { ...source };
            // Check for missing accountability_map (DR3)
            if (baseline.analysis?.accountability_map && !source.analysis?.accountability_map) {
                patched.analysis = {
                    ...patched.analysis,
                    accountability_map: baseline.analysis.accountability_map
                };
                wasPatched = true;
            }
            // Check for missing rebuttals (DR4)
            if (baseline.analysis?.rebuttals && !source.analysis?.rebuttals) {
                patched.analysis = {
                    ...patched.analysis,
                    rebuttals: baseline.analysis.rebuttals
                };
                wasPatched = true;
            }

            // Patch for missing Cultural/Logics/Legitimacy fields
            const cf = source.cultural_framing as Record<string, any> | undefined;
            if (baseline.cultural_framing && (!cf || !cf.technology_role)) {
                patched.cultural_framing = baseline.cultural_framing;
                wasPatched = true;
            }
            if (baseline.institutional_logics && !source.institutional_logics) {
                patched.institutional_logics = baseline.institutional_logics;
                wasPatched = true;
            }
            if (baseline.legitimacy_analysis && !source.legitimacy_analysis) {
                patched.legitimacy_analysis = baseline.legitimacy_analysis;
                wasPatched = true;
            }

            if (wasPatched) {
                // Atomic Patch: Save just this source back to Hash
                await StorageService.setHashField(userId, 'sources_v2', patched.id, patched);
                return patched;
            }
        }
        return source;
    }));

    return patchedSources;
};

// Save sources (Deprecated for arrays, kept for compatibility if needed elsewhere)
export const saveSources = async (userId: string, sources: Source[]): Promise<void> => {
    // Overwrite entire hash for consistency? 
    // Better to just loop and set. 
    // WARN: This is dangerous if strictly atomic is needed, but "saveSources" implies overwrite.
    for (const source of sources) {
        await StorageService.setHashField(userId, 'sources_v2', source.id, source);
    }
};

// Add a new source (Atomic)
export const addSource = async (userId: string, source: Source): Promise<Source> => {
    // Directly write to Hash. No read-modify-write race condition for the list!
    await StorageService.setHashField(userId, 'sources_v2', source.id, source);
    return source;
};

// Update a source (Atomic)
export const updateSource = async (userId: string, id: string, updates: Partial<Source>): Promise<Source | null> => {
    // 1. Get specific field (Optimized)
    // We don't have getHashField yet, but we can fetch all or just rely on the fact that we need the current state to merge.
    // Ideally we add getHashField to StorageService. 
    // For now, let's fetch all (safe enough) or use getSources().
    // Wait, getSources() does migration. We should use getSources() to be safe.

    // Better: Fetch specific source from Hash?
    // Let's rely on getSources() for now to handle migration implicitely.
    // But standard "getHash" returns a map.

    const sourceHash = await StorageService.getHash<Source>(userId, 'sources_v2');
    let currentSource = sourceHash ? sourceHash[id] : null;

    // Retry from legacy if not found (Double check migration)
    if (!currentSource) {
        const sources = await getSources(userId); // checks legacy and migrates
        currentSource = sources.find(s => s.id === id) || null;
    }

    if (!currentSource) return null;

    const updatedSource = { ...currentSource, ...updates };

    // Atomic Write
    await StorageService.setHashField(userId, 'sources_v2', id, updatedSource);

    return updatedSource;
};

// Delete a source (Atomic)
export const deleteSource = async (userId: string, id: string): Promise<boolean> => {
    // Ensure migration happened so we don't delete from empty hash while data sits in legacy
    const allSources = await getSources(userId);

    // [FIX] Check if it's a baseline source and mark as deleted
    const isBaseline = BASELINE_SOURCES.some(b => b.id === id);
    if (isBaseline) {
        await markBaselineAsDeleted(userId, id);
    }

    // [FIX] Cascade Delete: Remove any traces linked to this policy
    const childSources = allSources.filter(s => s.policyId === id);
    if (childSources.length > 0) {
        console.log(`[Cascade Delete] Removing ${childSources.length} traces associated with policy ${id}`);
        for (const child of childSources) {
            await StorageService.deleteHashField(userId, 'sources_v2', child.id);
        }
    }

    const count = await StorageService.deleteHashField(userId, 'sources_v2', id);
    return count > 0;
};

import { z } from 'zod';

import OpenAI from 'openai';
import { PromptRegistry } from '@/lib/prompts/registry';

// Define the structured output schema
// Define the structured output schema first as a base
export const BaseStructuralConcernSchema = z.object({
    insufficientEvidence: z.boolean().optional().default(false).describe("Set to true ONLY if you cannot even determine the evidence scope — i.e. the excerpts are too short, garbled, or off-topic to classify. Do NOT set true merely because governance standing is unproven."),
    evidenceScope: z.string().optional()
        .describe("Classify what the excerpts support. Use EXACTLY one of: 'impact_only' (actor mentioned as affected/rights-holder only, no governance roles), 'standing' (≥1 governance mechanism/OPP/participation rule present), 'exclusion' (bounded membership or closed language proves structural gap)"),
    missingSignals: z.array(z.string()).optional().default([])
        .describe("ALWAYS populate. Which structural signals are absent from excerpts. Use values like: noGovernanceMechanism, noParticipationRule, noBoundedForum, noOPPAccessInfo, noExclusionLanguage, noActorBoundaryLanguage"),
    signalsPresent: z.array(z.string()).optional().default([])
        .describe("ALWAYS populate. Which signals WERE found in excerpts. Use values like: impactMention, rightsHolder, governanceMechanism, participationRule, boundedForum, oppAccess, exclusionLanguage, actorBoundaryLanguage"),
    thesis: z.string().optional().describe("A 1-2 sentence overall conclusion of the structural exclusion or integration. E.g., 'Across these excerpts, the law completely domesticates authority, granting no formal standing to international organizations.'"),
    claims: z.array(z.object({
        sectionTitle: z.string().describe("Categorical boundary being analyzed (e.g., 'Authority', 'Coordination', 'Transnational Cooperation')."),
        claimText: z.string().describe("The hard analytical claim. e.g., 'Authority is fully domesticated (no shared or external governance seat).' Must be supported by excerpts."),
        supportedBy: z.array(z.string()).describe("Array of EXACT excerpt IDs from the input that prove this claim. YOU MUST ONLY USE IDs PROVIDED IN THE INPUT."),
        logicType: z.string().describe("The type of structural logic operating in these excerpts for this claim, e.g. role-allocation, categorical boundary, or silencing.")
    })).optional().default([]).describe("The detailed structural points. Max 6 points.")
});

// Since the service recursively attaches antiStructuralAnalysis, we need recursive types or manual extension
export type BaseStructuralConcernResult = z.infer<typeof BaseStructuralConcernSchema>;

export type StructuralConcernResult = BaseStructuralConcernResult & {
    antiStructuralAnalysis?: BaseStructuralConcernResult;
    escalation?: any;
};

// Replace old schema with base schema in runtime parser
export const StructuralConcernSchema = BaseStructuralConcernSchema;

export interface ExcerptInput {
    id: string;
    text: string;
    sourceRef?: any;
}

export class StructuralConcernService {

    /**
     * Executes the deep structural concern analysis on an actor using provided excerpts.
     */
    static async analyzeStructuralConcern(
        openai: OpenAI,
        userId: string,
        actorName: string,
        documentTitle: string,
        excerpts: ExcerptInput[],
        additionalContext?: string,
        promptId: 'structural_concern' | 'anti_structural_concern' = 'structural_concern'
    ): Promise<StructuralConcernResult> {

        if (!excerpts || excerpts.length === 0) {
            return {
                insufficientEvidence: true,
                thesis: "No excerpts provided for analysis.",
                claims: [],
                missingSignals: [],
                signalsPresent: []
            };
        }

        const formattedExcerpts = excerpts.map(e => `[ID: ${e.id}]\nQuote: "${e.text}"\n---`).join('\n\n');

        let systemPrompt = await PromptRegistry.getEffectivePrompt(userId, promptId);
        systemPrompt = systemPrompt
            .replace(/{{ACTOR_NAME}}/g, actorName)
            .replace(/{{DOCUMENT_TITLE}}/g, documentTitle);

        if (additionalContext) {
            systemPrompt += `\n\nContext: ${additionalContext}`;
        }

        const userPrompt = `Actor to analyze: ${actorName}
Document: ${documentTitle}

EXCERPTS TO ANALYZE:
${formattedExcerpts}

Generate a tight, structural concern analysis. Return the structured JSON.`;

        try {
            const completion = await openai.chat.completions.create({
                model: process.env.OPENAI_MODEL || 'gpt-4o-2024-08-06',
                messages: [
                    { role: 'system', content: systemPrompt },
                    { role: 'user', content: userPrompt }
                ],
                response_format: { type: 'json_object' }
            });

            const content = completion.choices[0].message.content || '{}';
            let result = StructuralConcernSchema.parse(JSON.parse(content));

            // STRICT GROUNDING VALIDATION: Reject hallucinated IDs
            result = this.enforceGrounding(result, excerpts);

            // [NEW] Automatic Pipeline: If standard mode finishes, run anti-structural mode immediately
            if (promptId === 'structural_concern' && !result.insufficientEvidence && excerpts.length > 0) {
                console.log(`[StructuralConcernService] Structural analysis successful, automatically triggering anti-structural concern...`);
                try {
                    const antiResult = await this.analyzeStructuralConcern(
                        openai,
                        userId,
                        actorName,
                        documentTitle,
                        excerpts,
                        additionalContext,
                        'anti_structural_concern'
                    );

                    let escalationResult = undefined;

                    // Run escalation evaluate regardless of whether the anti mode found sufficient evidence or not.
                    // If the anti side had no evidence to mount a challenge, the escalation prompt can still evaluate the pro side.
                    try {
                        escalationResult = await this.evaluateEscalation(
                            openai,
                            userId,
                            actorName,
                            documentTitle,
                            excerpts,
                            result,
                            antiResult
                        );
                    } catch (escalationError: any) {
                        console.warn(`[StructuralConcernService] Escalation evaluation failed for ${actorName}. Output might have failed schema validation. Error:`, escalationError?.message || escalationError);
                    }

                    // Return both formats. The API route currently unwraps `analysis.structural_concern`.
                    // We'll wrap it so both are sent down correctly to ConceptDetailsModal.
                    return {
                        ...result,
                        // Attach the secondary result as a nested property
                        antiStructuralAnalysis: antiResult,
                        escalation: escalationResult
                    } as any;
                } catch (antiError) {
                    console.warn(`[StructuralConcernService] Anti-structural concern failed, but returning main result. Error:`, antiError);
                }
            }

            return result;
        } catch (error) {
            console.error('[StructuralConcernService] Analysis failed:', error);
            throw error;
        }
    }

    /**
     * Validates that all output `supportedBy` IDs exist in the input set.
     * Strips hallucinated claims or flags insufficient evidence if everything is hallucinated.
     */
    static enforceGrounding(result: StructuralConcernResult, inputExcerpts: ExcerptInput[]): StructuralConcernResult {
        if (result.insufficientEvidence || !result.claims) {
            return result;
        }

        const validIds = new Set(inputExcerpts.map(e => e.id));
        const filteredClaims = [];

        for (const claim of result.claims) {
            // Filter the supportedBy array to only include valid IDs
            const validSupportedBy = claim.supportedBy.filter(id => validIds.has(id));

            // If checking strict grounding drops all evidence for a claim, the claim is hallucinated/invalid
            if (validSupportedBy.length > 0) {
                // Keep the claim but update it with the valid IDs
                filteredClaims.push({
                    ...claim,
                    supportedBy: validSupportedBy
                });
            } else {
                console.warn(`[StructuralConcernService] Dropped claim "${claim.sectionTitle}" due to hallucinated or missing excerpt IDs: ${claim.supportedBy.join(', ')}`);
            }
        }

        // If filtering removed all claims, retroactively flag as insufficient evidence
        if (filteredClaims.length === 0 && result.claims.length > 0) {
            return {
                insufficientEvidence: true,
                thesis: "Analysis generated claims that could not be grounded in the provided excerpt IDs. The text lacks the structure to support valid claims.",
                claims: [],
                missingSignals: result.missingSignals || [],
                signalsPresent: result.signalsPresent || []
            };
        }

        return {
            ...result,
            claims: filteredClaims
        };
    }

    /**
     * Evaluates the methodological strength of the pro vs anti structural arguments.
     */
    static async evaluateEscalation(
        openai: OpenAI,
        userId: string,
        actorName: string,
        documentTitle: string,
        excerpts: ExcerptInput[],
        proResult: StructuralConcernResult,
        antiResult: StructuralConcernResult
    ): Promise<any> {
        const { StructuralEscalationSchema } = await import('@/lib/prompts/structural-escalation');

        // Render the arguments for the prompt
        const proArgumentText = `Thesis: ${proResult.thesis || 'None'}\nClaims:\n` +
            (proResult.claims || []).map(c => `- [${c.sectionTitle}] ${c.claimText}`).join('\n');

        const antiArgumentText = `Thesis: ${antiResult.thesis || 'None'}\nClaims:\n` +
            (antiResult.claims || []).map(c => `- [${c.sectionTitle}] ${c.claimText}`).join('\n');

        const formattedExcerpts = excerpts.map(e => `[ID: ${e.id}]\nQuote: "${e.text}"\n---`).join('\n\n');

        let systemPrompt = await PromptRegistry.getEffectivePrompt(userId, 'structural_escalation');
        systemPrompt = systemPrompt
            .replace(/{{ACTOR_NAME}}/g, actorName)
            .replace(/{{DOCUMENT_TITLE}}/g, documentTitle);

        let userPrompt = (await PromptRegistry.getEffectivePrompt(userId, 'structural_escalation')) || '';
        // Because the user prompt is hardcoded in the file near the system prompt, we'll fetch it from the registry
        // Wait, the PromptRegistry only returns the default value (which is SYSTEM_PROMPT).
        // Let's just import the user prompt directly to ensure we have it.
        const { STRUCTURAL_ESCALATION_USER_PROMPT_TEMPLATE } = await import('@/lib/prompts/structural-escalation');

        userPrompt = STRUCTURAL_ESCALATION_USER_PROMPT_TEMPLATE
            .replace(/{{ACTOR_NAME}}/g, actorName)
            .replace(/{{DOCUMENT_TITLE}}/g, documentTitle)
            .replace(/{{EXCERPTS}}/g, formattedExcerpts)
            .replace(/{{PRO_ARGUMENT}}/g, proArgumentText)
            .replace(/{{ANTI_ARGUMENT}}/g, antiArgumentText);

        const completion = await openai.chat.completions.create({
            model: process.env.OPENAI_MODEL || 'gpt-4o-2024-08-06',
            messages: [
                { role: 'system', content: systemPrompt },
                { role: 'user', content: userPrompt }
            ],
            response_format: { type: 'json_object' }
        });

        const content = completion.choices[0].message.content || '{}';
        return StructuralEscalationSchema.parse(JSON.parse(content));
    }
}

