import { Source } from '@/types';
import { OntologyData } from '@/types/ontology';
import { StudyCase, StudyCaseConfig, STUDY_CASES } from './study-config';

/**
 * Generates a list of StudyCases based on the Ghost Nodes present in the provided ontology maps.
 * 
 * @param sources List of available sources (policies)
 * @param ontologyMaps Record of ontology data keyed by source ID
 * @returns Array of StudyCase objects for the research playlist
 */
export function generateCasesFromOntology(
    sources: Source[],
    ontologyMaps: Record<string, OntologyData>
): StudyCase[] {
    const casesBySource: Record<string, StudyCase[]> = {};
    const allCases: StudyCase[] = [];

    // Include the static cases defined in study-config.ts first
    const selectedCases: StudyCase[] = [...STUDY_CASES];

    // 1. Generate all potential cases grouped by source
    sources.forEach(source => {
        const data = ontologyMaps[source.id];
        if (!data || !data.nodes) return;

        const sourceCases: StudyCase[] = [];
        const ghostNodes = data.nodes.filter(n => n.isGhost);

        // Sort ghost nodes deterministically by ID to ensure consistency across evaluators
        ghostNodes.sort((a, b) => a.id.localeCompare(b.id));

        ghostNodes.forEach(node => {
            const caseId = `case_${source.id}_${node.id}`;
            const evidencePoints: string[] = [];

            if (node.potentialConnections && node.potentialConnections.length > 0) {
                node.potentialConnections.forEach(conn => {
                    evidencePoints.push(`Potential connection to ${conn.targetActor}: "${conn.evidence}"`);
                });
            } else if (node.quote) {
                evidencePoints.push(node.quote);
            } else {
                evidencePoints.push("No specific textual evidence provided, but structural analysis indicates absence.");
            }

            const hypothesis = node.exclusionType
                ? formatExclusionType(node.exclusionType)
                : "Constitutive Ghost Node";

            // Map the V2 AI output properties. 
            // Note: Our LLM outputs 'quote' and 'actors', but the UI expects 'text' and 'actorTags'.
            const mappedEvidenceQuotes = node.evidenceQuotes?.map((eq, index) => ({
                id: `q-${index}`,
                text: eq.quote, // Mapped
                sourceRef: { docId: source.id, section: eq.sourceRef }, // Mapped
                actorTags: eq.actors || [], // Mapped
                mechanismTags: []
            })) || [];

            const mappedRoster = node.roster ? {
                actorsInSection: node.roster.actors || [],
                mechanismsInSection: node.roster.mechanisms || []
            } : undefined;

            const mappedMissingSignals = node.missingSignals?.map((ms, index) => ({
                id: `ms-${index}`,
                label: ms.signal
            })) || [];

            sourceCases.push({
                id: caseId,
                sourceId: source.id,
                nodeId: node.id,
                title: `${source.title}: ${node.label}`,
                pane1: { evidencePoints },
                pane2: {
                    hypothesis,
                    reasoning: node.whyAbsent || "No reasoning provided for this ghost node."
                },
                config: { requireReflexivity: true },
                // V2 Overrides for mapping
                evidenceQuotes: mappedEvidenceQuotes.length > 0 ? mappedEvidenceQuotes : undefined,
                claim: node.claim,
                roster: mappedRoster,
                structuralAnalysis: node.structuralAnalysis,
                counterfactual: node.counterfactual,
                missingSignals: mappedMissingSignals.length > 0 ? mappedMissingSignals : undefined,
                evaluationConfig: {
                    presenceGateQuestion: `Based on the evidence, is the actor "${node.label}" materially excluded or marginalized in this document?`,
                    presenceGateOptions: [
                        "Yes - excluded/marginalized",
                        "No - adequately represented",
                        "Unsure/Depends"
                    ],
                    strengthAbsence: {
                        min: 0,
                        max: 100,
                        anchors: [
                            { value: 0, label: "Weak Absence" },
                            { value: 50, label: "Moderate" },
                            { value: 100, label: "Profound Absence" }
                        ]
                    },
                    confidenceOptions: ["High", "Medium", "Low"],
                    feasibility: {
                        min: 0,
                        max: 100,
                        anchors: [
                            { value: 0, label: "Highly Impractical" },
                            { value: 50, label: "Possible" },
                            { value: 100, label: "Highly Feasible" }
                        ],
                        mechanismGateThreshold: 60,
                        mechanismOptions: ["Policy Amendment", "Enforcement Guidelines", "Public Consultation", "Funding Allocation", "Other"]
                    }
                }
            });
        });

        if (sourceCases.length > 0) {
            casesBySource[source.id] = sourceCases;
        }
    });

    // 2. Select cases to meet requirements (At least 2 per source, Max 10 total)
    const sourceIds = Object.keys(casesBySource);
    const MIN_PER_SOURCE = 2;
    const MAX_TOTAL = 10;

    // Phase A: Take minimum from each source
    sourceIds.forEach(sourceId => {
        const cases = casesBySource[sourceId];
        const countToTake = Math.min(cases.length, MIN_PER_SOURCE);
        selectedCases.push(...cases.slice(0, countToTake));
        // Remove taken cases from the pool
        casesBySource[sourceId] = cases.slice(countToTake);
    });

    // Phase B: Fill remaining slots round-robin
    let slotsRemaining = MAX_TOTAL - selectedCases.length;
    let index = 0;

    while (slotsRemaining > 0 && sourceIds.some(id => casesBySource[id].length > 0)) {
        const sourceId = sourceIds[index % sourceIds.length];
        if (casesBySource[sourceId].length > 0) {
            selectedCases.push(casesBySource[sourceId].shift()!);
            slotsRemaining--;
        }
        index++;
    }

    return selectedCases;
}

function formatExclusionType(type: string): string {
    return type.split('-').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join(' ');
}

/**
 * Immutable object update by path.
 * Solves the React generic deep-merge clobbering problem (e.g. updating one cell in a table row wiping out another).
 * 
 * @param obj The root object to clone and mutate safely
 * @param path Dot-notation path (e.g. 'mechanismEval_evidence_collection.effectiveness')
 * @param value The value to set at the terminal path
 * @returns A strictly new object reference with the deep path updated
 */
export function setImmutablePath<T extends Record<string, any>>(obj: T, path: string, value: any): T {
    if (!path) return { ...obj };

    const parts = path.split('.');

    // Base case: shallow clone if no depth
    if (parts.length === 1) {
        return {
            ...obj,
            [parts[0]]: value
        };
    }

    const key = parts[0];
    const rest = parts.slice(1).join('.');

    // Recursive case: clone this level, delegate down
    return {
        ...obj,
        [key]: setImmutablePath(obj[key] || {}, rest, value)
    };
}

import { PromptMetadata, ProvenanceChain, ProvenanceStep, RejectionStep } from "@/types/provenance";
import crypto from 'crypto';

/**
 * Captures metadata about an LLM API call for transparency
 * This enables the "Show Prompt" feature
 */
export function capturePromptMetadata(
    prompt: string,
    modelVersion: string = "gpt-4-turbo-2024-04-09",
    temperature: number = 0.3,
    maxTokens?: number,
    promptId?: string,
    promptVersion?: string
): PromptMetadata {
    return {
        prompt_used: prompt,
        model_version: modelVersion,
        temperature,
        max_tokens: maxTokens,
        timestamp: new Date().toISOString(),
        prompt_id: promptId,
        prompt_version: promptVersion
    };
}

/**
 * Extracts confidence score and justification from LLM response
 * Expects the LLM to include a confidence field in its JSON response
 */
export function extractConfidenceScore(response: unknown): { score: number; justification: string } | null {
    // Type guard: ensure response is an object
    if (typeof response !== 'object' || response === null) {
        return null;
    }

    const resp = response as Record<string, unknown>;

    // Try to find confidence in various possible locations
    if (resp.confidence_score !== undefined) {
        return {
            score: typeof resp.confidence_score === 'number' ? resp.confidence_score : 0,
            justification: typeof resp.confidence_justification === 'string' ? resp.confidence_justification : "No justification provided"
        };
    }

    if (resp.confidence !== undefined) {
        if (typeof resp.confidence === 'object' && resp.confidence !== null) {
            const conf = resp.confidence as Record<string, unknown>;
            return {
                score: typeof conf.score === 'number' ? conf.score : 0,
                justification: typeof conf.justification === 'string' ? conf.justification : "No justification provided"
            };
        }
        return {
            score: typeof resp.confidence === 'number' ? resp.confidence : 0,
            justification: "No justification provided"
        };
    }

    return null;
}

/**
 * Requests a confidence score from the LLM using a second API call
 * This implements the multi-step confidence calculation strategy
 */
export async function calculateConfidenceScore(
    analysisResult: string,
    openaiApiKey: string
): Promise<{ score: number; justification: string }> {
    const confidencePrompt = `You are evaluating the confidence level of an analysis you just performed.

Analysis Result:
${analysisResult}

Rate your confidence in this analysis on a scale of 0-100, where:
- 90-100: Very high confidence, strong evidence, clear conclusions
- 70-89: High confidence, good evidence, minor ambiguities
- 50-69: Moderate confidence, some evidence, notable uncertainties
- 30-49: Low confidence, limited evidence, significant gaps
- 0-29: Very low confidence, weak evidence, highly speculative

Respond in JSON format:
{
  "score": <number 0-100>,
  "justification": "<brief explanation of why you assigned this score>"
}`;

    try {
        const response = await fetch('https://api.openai.com/v1/chat/completions', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${openaiApiKey}`
            },
            body: JSON.stringify({
                model: 'gpt-4-turbo-2024-04-09',
                messages: [
                    { role: 'system', content: 'You are a critical evaluator of AI analysis quality.' },
                    { role: 'user', content: confidencePrompt }
                ],
                temperature: 0.3,
                response_format: { type: 'json_object' }
            })
        });

        const data = await response.json();
        const content = data.choices[0]?.message?.content;

        if (content) {
            const parsed = JSON.parse(content);
            return {
                score: parsed.score || 0,
                justification: parsed.justification || "No justification provided"
            };
        }
    } catch (error) {
        console.error("Failed to calculate confidence score:", error);
    }

    // Fallback if confidence calculation fails
    return {
        score: 50,
        justification: "Confidence score could not be calculated"
    };
}

/**
 * Creates a new empty provenance chain
 */
export function createProvenanceChain(): ProvenanceChain {
    return {
        insight_id: crypto.randomUUID(),
        steps: [],
        created_at: new Date().toISOString()
    };
}

/**
 * Adds a step to the provenance chain
 */
export function addProvenanceStep(
    chain: ProvenanceChain,
    description: string,
    inputs: Record<string, any>,
    outputs: Record<string, any>,
    agent: string = "system"
): ProvenanceChain {
    const step: ProvenanceStep = {
        step_id: crypto.randomUUID(),
        description,
        inputs,
        outputs,
        agent,
        timestamp: new Date().toISOString()
    };

    return {
        ...chain,
        steps: [...chain.steps, step]
    };
}

/**
 * Adds a user rejection to the provenance chain (Sartrean Rupture)
 */
export function addRejectionStep(
    chain: ProvenanceChain,
    userId: string,
    justification: string,
    promptVersion: string
): ProvenanceChain {
    const rejection: RejectionStep = {
        step_id: crypto.randomUUID(),
        timestamp: new Date().toISOString(),
        user_id: userId,
        justification,
        prompt_version_rejected: promptVersion,
        signature_hash: crypto.createHash('sha256').update(userId + new Date().toISOString()).digest('hex')
    };

    return {
        ...chain,
        rejections: [...(chain.rejections || []), rejection]
    };
}

'use client';

import React, { createContext, useContext, useEffect, useState } from 'react';
import { useAuth } from '@clerk/nextjs';
import { toast } from 'sonner';

// ----------------------------------------------------------------------
// Types
// ----------------------------------------------------------------------

export type WorkspaceType = 'PERSONAL' | 'TEAM';

export interface Team {
    id: string;
    name: string;
    createdBy: string;
    createdAt: number;
    status: string;
}

interface WorkspaceContextProps {
    // State
    currentWorkspaceId: string | null;
    workspaceType: WorkspaceType;
    availableTeams: Team[];
    isLoading: boolean;

    // Actions
    switchWorkspace: (id: string) => void;
    refreshTeams: () => Promise<void>;
    createTeam: (name: string) => Promise<boolean>;
}

// ----------------------------------------------------------------------
// Context
// ----------------------------------------------------------------------

const WorkspaceContext = createContext<WorkspaceContextProps | undefined>(undefined);

export const useWorkspace = () => {
    const context = useContext(WorkspaceContext);
    if (!context) throw new Error('useWorkspace must be used within a WorkspaceProvider');
    return context;
};

// ----------------------------------------------------------------------
// Provider
// ----------------------------------------------------------------------

export const WorkspaceProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { userId, isLoaded } = useAuth();

    const [currentWorkspaceId, setCurrentWorkspaceId] = useState<string | null>(null);
    const [availableTeams, setAvailableTeams] = useState<Team[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    // 1. Initialize Workspace ID (Personal by default)
    useEffect(() => {
        if (isLoaded) {
            // 1. Authenticated User
            if (userId && !currentWorkspaceId) {
                // Restore from localStorage if possible
                const saved = localStorage.getItem('last_workspace_id');
                if (saved) {
                    setCurrentWorkspaceId(saved);
                } else {
                    setCurrentWorkspaceId(userId);
                }
            }
            // 2. Demo Mode Fallback (Signed Out)
            else if (!userId && !currentWorkspaceId && process.env.NEXT_PUBLIC_ENABLE_DEMO_MODE === 'true') {
                const demoId = process.env.NEXT_PUBLIC_DEMO_USER_ID;
                if (demoId) {
                    // console.log('[Workspace] Defaulting to Demo Workspace:', demoId);
                    setCurrentWorkspaceId(demoId);
                }
            }
        }
    }, [isLoaded, userId, currentWorkspaceId]);

    // 2. Fetch Teams
    const fetchTeams = async () => {
        if (!userId) return;
        setIsLoading(true);
        try {
            const res = await fetch('/api/collaboration/teams');
            if (res.ok) {
                const data = await res.json();
                setAvailableTeams(data.teams || []);

                // Re-hydrate selection from LocalStorage if valid
                const saved = localStorage.getItem('last_workspace_id');
                if (saved && saved !== userId) {
                    const exists = data.teams.some((t: Team) => t.id === saved);
                    if (exists) {
                        setCurrentWorkspaceId(saved);
                    }
                }
            } else {
                console.error('Failed to fetch teams');
                // Don't toast error on background fetch, distracts user
            }
        } catch (err) {
            console.error(err);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        if (userId) {
            fetchTeams();
        }
    }, [userId]);

    // 3. Actions
    const switchWorkspace = (id: string) => {
        setCurrentWorkspaceId(id);
        localStorage.setItem('last_workspace_id', id);

        // Safety: If switching to personal, force ID check
        if (id === userId) {
            toast.success('Switched to Personal Workspace');
        } else {
            const team = availableTeams.find(t => t.id === id);
            if (team) toast.success(`Switched to ${team.name}`);
        }

        // Logic: Trigger a "soft reload" or data re-fetch?
        // In simple React apps, context change triggers re-render of consumers.
        // If consumers use `currentWorkspaceId` as a query key for basic data, it handles itself.
        // We assume components like useAnalysis() will use this ID.
    };

    const createTeam = async (name: string): Promise<boolean> => {
        try {
            const res = await fetch('/api/collaboration/teams', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ name })
            });
            const data = await res.json();

            if (!res.ok) {
                toast.error(data.error || 'Failed to create team');
                return false;
            }

            toast.success('Team created successfully');
            await fetchTeams(); // Refresh list
            switchWorkspace(data.teamId); // Auto-switch
            return true;
        } catch (err) {
            console.error(err);
            toast.error('Network error creating team');
            return false;
        }
    };

    // Derived State
    const workspaceType = (currentWorkspaceId && currentWorkspaceId.startsWith('team_')) ? 'TEAM' : 'PERSONAL';

    return (
        <WorkspaceContext.Provider value={{
            currentWorkspaceId,
            workspaceType,
            availableTeams,
            isLoading,
            switchWorkspace,
            refreshTeams: fetchTeams,
            createTeam
        }}>
            {children}
        </WorkspaceContext.Provider>
    );
};

