import { redis } from '@/lib/redis';
import { AuditService } from '@/lib/audit';
import { nanoid } from 'nanoid';
import { TeamRole } from '@/lib/auth-middleware';
import crypto from 'crypto';

export class CollaborationService {
    // ----------------------------------------------------------------------
    // Constants & Quotas
    // ----------------------------------------------------------------------
    private static readonly MAX_TEAMS_PER_USER = 5;
    private static readonly MAX_INVITES_PER_DAY = 10;
    private static readonly INVITE_EXPIRY_SECONDS = 72 * 60 * 60; // 72 Hours

    // ----------------------------------------------------------------------
    // Team Management
    // ----------------------------------------------------------------------

    /**
     * Creates a new Team Workspace with the creator as OWNER.
     */
    static async createTeam(name: string, ownerId: string): Promise<{ success: boolean; teamId?: string; error?: string }> {
        // Don't lowercase user IDs - Clerk IDs are case-sensitive

        // 1. Check Quota
        const userTeams = await this.listMyTeams(ownerId);
        if (userTeams.length >= this.MAX_TEAMS_PER_USER) {
            return { success: false, error: 'Quota Exceeded: Max 5 Teams per User.' };
        }

        // 2. Generate ID (Safe, random, prefixed)
        // Using nanoid for URL-safe, short-ish IDs, prefixed to avoid collisions
        const teamId = `team_${nanoid(12).toLowerCase()}`;

        // 3. Persist Metadata & Roles (Atomic-ish)
        const timestamp = Date.now();
        const pipeline = redis.pipeline();

        // Metadata
        pipeline.hset(`${teamId}:metadata`, {
            name,
            createdBy: ownerId,
            createdAt: timestamp,
            status: 'active'
        });

        // Membership
        pipeline.sadd(`${teamId}:members`, ownerId);

        // Role
        pipeline.hset(`${teamId}:roles`, {
            [ownerId]: 'OWNER'
        });

        // Add to User's list (Index)
        pipeline.sadd(`user:${ownerId}:teams`, teamId);

        await pipeline.exec();

        // 4. Audit Log
        await AuditService.log('TEAM_CREATED', ownerId, {
            targetId: teamId,
            metadata: { name }
        });

        return { success: true, teamId };
    }

    static async listMyTeams(userId: string): Promise<string[]> {
        return await redis.smembers(`user:${userId}:teams`);
    }

    // ----------------------------------------------------------------------
    // Invitation System
    // ----------------------------------------------------------------------

    /**
     * Generates a secure invitation token for a new member.
     */
    static async createInvitation(
        teamId: string,
        inviterId: string,
        targetEmail: string,
        role: TeamRole = 'EDITOR'
    ): Promise<{ token: string; expiresAt: number }> {

        // 1. Generate Secure Token (32 bytes hex)
        const token = crypto.randomBytes(32).toString('hex');

        // 2. Hash Token for storage (Security Best Practice)
        // We only store the hash, user gets the raw token via email (simulated return here)
        const tokenHash = crypto.createHash('sha256').update(token).digest('hex');
        const inviteId = `invite_${nanoid(10)}`;

        const expiresAt = Date.now() + (this.INVITE_EXPIRY_SECONDS * 1000);

        // 3. Store Invitation
        await redis.setex(`invitation:${inviteId}`, this.INVITE_EXPIRY_SECONDS, JSON.stringify({
            teamId,
            inviterId,
            email: targetEmail.toLowerCase(),
            role,
            tokenHash, // Verify against this
            expiresAt
        }));

        // In a real system, we'd add this to a 'daily quota' counter here
        // await redis.incr(`quota:invites:${date}:${inviterId}`)

        await AuditService.log('MEMBER_INVITED', inviterId, {
            targetId: teamId,
            metadata: { email: targetEmail, role }
        });

        return { token: `${inviteId}:${token}`, expiresAt };
    }

    /**
     * Accepts an invitation using the composite token (id:secret).
     */
    static async acceptInvitation(userId: string, compositeToken: string): Promise<{ success: boolean; error?: string; teamId?: string }> {
        const [inviteId, secret] = compositeToken.split(':');
        if (!inviteId || !secret) return { success: false, error: 'Invalid Token Format' };

        // 1. Retrieve Invite
        const raw = await redis.get(`invitation:${inviteId}`);
        if (!raw) return { success: false, error: 'Invitation Expired or Invalid' };

        const invite = JSON.parse(raw);

        // 2. Verify Token Hash
        const providedHash = crypto.createHash('sha256').update(secret).digest('hex');
        if (providedHash !== invite.tokenHash) {
            await AuditService.log('SECURITY_ACCESS_DENIED', userId, { metadata: { reason: 'Invalid Invite Token' } });
            return { success: false, error: 'Invalid Token Secret' };
        }

        // 3. Execute Membership Add
        const pipeline = redis.pipeline();
        pipeline.sadd(`${invite.teamId}:members`, userId);
        pipeline.hset(`${invite.teamId}:roles`, { [userId]: invite.role });
        pipeline.sadd(`user:${userId}:teams`, invite.teamId);
        pipeline.del(`invitation:${inviteId}`); // Consume token (One-time use)

        await pipeline.exec();

        await AuditService.log('MEMBER_ADDED', userId, {
            targetId: invite.teamId,
            metadata: { role: invite.role, via: 'invite' }
        });


        return { success: true, teamId: invite.teamId };
    }

    /**
     * Retrieves basic Team Metadata.
     */
    static async getTeam(teamId: string): Promise<{ id: string; name: string; createdAt: number; status: string; createdBy: string; } | null> {
        const raw = await redis.hgetall(`${teamId}:metadata`);
        if (!raw || Object.keys(raw).length === 0) return null;

        return {
            id: teamId,
            name: raw.name,
            createdAt: parseInt(raw.createdAt || '0'),
            status: raw.status,
            createdBy: raw.createdBy
        };
    }

    /**
     * Alias for getTeam - used by API endpoints
     */
    static async getTeamInfo(teamId: string) {
        return this.getTeam(teamId);
    }

    /**
     * Get all team members with their roles and details
     */
    static async getTeamMembers(teamId: string): Promise<Array<{
        userId: string;
        email: string;
        role: TeamRole;
        joinedAt: number;
    }>> {
        const memberIds = await redis.smembers(`${teamId}:members`);
        const roles = await redis.hgetall(`${teamId}:roles`);

        const members = await Promise.all(
            memberIds.map(async (userId) => {
                // Fetch user details from Clerk
                let email = userId; // Fallback to userId if Clerk fetch fails

                console.log(`[getTeamMembers] Fetching user details for: ${userId}`);

                try {
                    const { clerkClient } = await import('@clerk/nextjs/server');
                    const client = await clerkClient();
                    const user = await client.users.getUser(userId);

                    console.log(`[getTeamMembers] Clerk user data:`, {
                        userId: user.id,
                        emailCount: user.emailAddresses.length,
                        primaryEmail: user.emailAddresses[0]?.emailAddress
                    });

                    email = user.emailAddresses[0]?.emailAddress || userId;
                    console.log(`[getTeamMembers] Using email: ${email}`);
                } catch (error) {
                    console.error(`[getTeamMembers] Failed to fetch user ${userId} from Clerk:`, error);
                    // Keep fallback email = userId
                }

                return {
                    userId,
                    email,
                    role: (roles[userId] || 'EDITOR') as TeamRole,
                    joinedAt: Date.now() // Placeholder - should track actual join time
                };
            })
        );

        console.log(`[getTeamMembers] Final members:`, members.map(m => ({ userId: m.userId, email: m.email })));
        return members;
    }

    /**
     * Check if user is a member of the team
     */
    static async isTeamMember(teamId: string, userId: string): Promise<boolean> {
        const members = await redis.smembers(`${teamId}:members`);
        return members.includes(userId);
    }

    /**
     * Remove a member from the team
     */
    static async removeMember(teamId: string, userId: string): Promise<void> {
        const pipeline = redis.pipeline();
        pipeline.srem(`${teamId}:members`, userId);
        pipeline.hdel(`${teamId}:roles`, userId);
        pipeline.srem(`user:${userId}:teams`, teamId);
        await pipeline.exec();

        await AuditService.log('MEMBER_REMOVED', userId, {
            targetId: teamId,
            metadata: { removedBy: 'owner' }
        });
    }

    /**
     * Get invitation details (for preview before accepting)
     */
    static async getInviteDetails(compositeToken: string): Promise<{
        teamName: string;
        inviterEmail: string;
        role: string;
    } | null> {
        const [inviteId] = compositeToken.split(':');
        if (!inviteId) return null;

        const raw = await redis.get(`invitation:${inviteId}`);
        if (!raw) return null;

        const invite = JSON.parse(raw);
        const team = await this.getTeam(invite.teamId);

        if (!team) return null;

        return {
            teamName: team.name,
            inviterEmail: invite.email,
            role: invite.role
        };
    }

    /**
     * Permanently deletes a team and all associated data.
     * Only callable by team OWNER.
     */
    static async deleteTeam(teamId: string, requesterId: string): Promise<{
        success: boolean;
        error?: string;
        members?: string[];
        teamName?: string;
    }> {
        // 1. Pre-deletion checks
        // Verify team exists and get metadata
        const metadataRaw = await redis.hgetall(`${teamId}:metadata`);
        if (!metadataRaw || Object.keys(metadataRaw).length === 0) {
            // Team already deleted - idempotent
            return { success: true, members: [] };
        }

        const teamName = metadataRaw.name;

        // Verify requester is OWNER
        const requesterRole = await redis.hget(`${teamId}:roles`, requesterId);
        if (requesterRole !== 'OWNER') {
            return { success: false, error: 'Only team owners can delete teams' };
        }

        // Get member list for notifications
        const members = await redis.smembers(`${teamId}:members`);

        // 2. Delete team-owned content using SCAN (safe for production)
        // Explicit patterns to avoid over-deletion
        const contentPatterns = [
            `${teamId}:sources`,
            `${teamId}:chunks`,
            `${teamId}:embeddings`,
            `${teamId}:analysis`,
            `${teamId}:*` // Catch-all for any other team-scoped keys
        ];

        const pipeline = redis.pipeline();

        // Use SCAN for safe iteration (non-blocking)
        for (const pattern of contentPatterns) {
            let cursor = '0';
            do {
                const [nextCursor, keys] = await redis.scan(cursor, 'MATCH', pattern, 'COUNT', 100);
                if (keys.length > 0) {
                    keys.forEach(key => pipeline.del(key));
                }
                cursor = nextCursor;
            } while (cursor !== '0');
        }

        // 3. Delete collaboration metadata
        pipeline.del(`${teamId}:metadata`);
        pipeline.del(`${teamId}:members`);
        pipeline.del(`${teamId}:roles`);

        // 4. Remove team from all members' team lists
        members.forEach(userId => {
            pipeline.srem(`user:${userId}:teams`, teamId);
        });

        // 5. Delete pending invitations for this team
        // Note: Current invitation storage doesn't prefix by team
        // This is a known limitation - we scan all invitations
        // Future: Store as `invitation:${teamId}:${inviteId}` for efficient cleanup
        let inviteCursor = '0';
        do {
            const [nextCursor, inviteKeys] = await redis.scan(inviteCursor, 'MATCH', 'invitation:*', 'COUNT', 100);
            for (const key of inviteKeys) {
                const inviteData = await redis.get(key);
                if (inviteData) {
                    const invite = JSON.parse(inviteData);
                    if (invite.teamId === teamId) {
                        pipeline.del(key);
                    }
                }
            }
            inviteCursor = nextCursor;
        } while (inviteCursor !== '0');

        // 6. Execute deletion pipeline
        const results = await pipeline.exec();

        // Check for pipeline failures
        const failures = results?.filter(([err]) => err !== null);
        if (failures && failures.length > 0) {
            console.error('[Delete Team] Pipeline failures:', failures);
            return { success: false, error: 'Partial deletion failure - please contact support' };
        }

        // 7. Audit log
        await AuditService.log('TEAM_DELETED', requesterId, {
            targetId: teamId,
            metadata: {
                teamName,
                memberCount: members.length,
                deletedBy: requesterId
            }
        });

        return {
            success: true,
            members,
            teamName
        };
    }
}

import { GENESIS_TIMESTAMP, PHASE_DURATIONS, VETO_CONFIG } from '@/config/governance-config';
import { GovernanceProfile, GenesisPhase, VerificationMethod, VerificationStatus } from '@/types/governance';
import { TenureMath } from '@/lib/governance/tenure-math';
import { logger } from '@/lib/logger';

/**
 * Sybil Resistance Adapter Interface
 * Allows swapping verification providers (Platform vs Decentralized)
 */
export interface IVerificationAdapter {
    verifyUser(userId: string): Promise<{ status: VerificationStatus, method: VerificationMethod, hash?: string }>;
}

/**
 * Default Platform Verifier (Email/Internal)
 */
class PlatformVerifier implements IVerificationAdapter {
    async verifyUser(userId: string) {
        // Mock implementation - in prod this checks DB or Auth Provider
        return {
            status: 'VERIFIED' as VerificationStatus,
            method: 'PLATFORM' as VerificationMethod,
            hash: `platform_hash_${userId}` // Placeholder hash
        };
    }
}

export class GovernanceService {
    private verifier: IVerificationAdapter;
    private developerVetoesUsed: number = 0;
    private readonly MAX_TRANSITION_VETOES = 3;

    constructor(verifier?: IVerificationAdapter) {
        this.verifier = verifier || new PlatformVerifier();
    }

    /**
     * Determines the current Constitutional Phase based on time elapsed since Genesis.
     */
    public getCurrentPhase(): GenesisPhase {
        const now = Date.now();
        const elapsed = now - GENESIS_TIMESTAMP;

        if (elapsed < PHASE_DURATIONS.FOUNDING) {
            return GenesisPhase.FOUNDING;
        } else if (elapsed < PHASE_DURATIONS.TRANSITION) {
            return GenesisPhase.TRANSITION;
        } else {
            return GenesisPhase.SOVEREIGNTY;
        }
    }

    /**
     * Checks if a user is eligible to vote based on Phase and Profile.
     */
    public async canVote(profile: GovernanceProfile): Promise<{ allowed: boolean; reason?: string }> {
        const phase = this.getCurrentPhase();

        // 1. Sybil Check: Must be Verified
        if (profile.verificationStatus !== 'VERIFIED') {
            return { allowed: false, reason: "User identification not verified (Sybil protection)." };
        }

        // 2. Phase-Specific Rules
        switch (phase) {
            case GenesisPhase.FOUNDING:
                // Only Core Team or Whitelisted users
                // Simplification for MVP: Founding phase allows voting but Dev Veto is absolute
                return { allowed: true };

            case GenesisPhase.TRANSITION:
                return { allowed: true };

            case GenesisPhase.SOVEREIGNTY:
                return { allowed: true };

            default:
                return { allowed: false, reason: "System Error: Unknown Phase" };
        }
    }

    /**
     * Calculates the effective voting power for a user.
     */
    public calculateVotingPower(profile: GovernanceProfile): number {
        return TenureMath.calculateWeight(profile.tenureDays);
    }

    /**
     * Applies a Developer Veto (Only valid in Transition Phase)
     */
    public applyDeveloperVeto(proposalId: string, rationale: string): boolean {
        const phase = this.getCurrentPhase();

        if (phase === GenesisPhase.FOUNDING) {
            logger.governance(`[VETO] Founding Phase Veto applied to ${proposalId}. Rationale: ${rationale}`);
            return true; // Absolute power
        }

        if (phase === GenesisPhase.TRANSITION) {
            if (this.developerVetoesUsed >= this.MAX_TRANSITION_VETOES) {
                logger.warn(`[VETO REJECTED] Max vetoes (${this.MAX_TRANSITION_VETOES}) exceeded.`);
                return false;
            }
            this.developerVetoesUsed++;
            logger.governance(`[VETO] Transition Veto used (${this.developerVetoesUsed}/${this.MAX_TRANSITION_VETOES}). Rationale: ${rationale}`);
            return true; // Limited power
        }

        if (phase === GenesisPhase.SOVEREIGNTY) {
            logger.error("[VETO ILLEGAL] Developer has no veto power in Sovereignty Phase.");
            return false; // No power
        }

        return false;
    }

    /**
     * Registration / Profile Creation Helper
     */
    public async registerUser(userId: string): Promise<GovernanceProfile> {
        const verification = await this.verifier.verifyUser(userId);

        return {
            userId,
            verificationStatus: verification.status,
            verificationMethod: verification.method,
            verificationDate: Date.now(),
            identityHash: verification.hash,
            firstActiveDate: Date.now(),
            tenureDays: 0,
            votingWeight: 1.0,
            proposalsCreated: 0,
            votesCast: 0,
            deliberationsJoined: 0
        };
    }

    /**
     * Governance Proposal Creation
     */
    public async createEpistemicNegationProposal(userId: string, analysisId: string, promptId: string, reason: string, sourceId?: string, sourceTitle?: string): Promise<import('@/types/governance').GovernanceProposal> {
        return this.createProposal(userId, {
            type: 'epistemic_negation',
            title: sourceTitle ? `Veto Analysis: ${sourceTitle}` : `Veto Analysis ${analysisId.substring(0, 8)}`,
            description: reason,
            targetAnalysisId: analysisId,
            targetPromptId: promptId,
            targetSourceId: sourceId,
            targetSourceTitle: sourceTitle,
            negationReason: reason
        });
    }

    /**
     * Governance Proposal Retrieval
     */
    public async getProposals(): Promise<import('@/types/governance').GovernanceProposal[]> {
        try {
            const response = await fetch('/api/governance/proposals');
            if (!response.ok) throw new Error('Failed to fetch proposals');
            return await response.json();
        } catch (error) {
            console.error('Failed to get proposals', error);
            return [];
        }
    }

    /**
     * Cast a vote on a proposal
     */
    public async castVote(proposalId: string, voteType: 'for' | 'against' | 'abstain', rationale?: string): Promise<import('@/types/governance').GovernanceProposal | null> {
        try {
            const response = await fetch('/api/governance/vote', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    proposalId,
                    voteType,
                    rationale,
                    userId: 'current_user' // In a real app this comes from session
                })
            });

            if (!response.ok) throw new Error('Failed to vote');
            const data = await response.json();
            return data.proposal;
        } catch (error) {
            console.error('Failed to cast vote', error);
            return null;
        }
    }

    /**
     * Delete a proposal (Owner Only)
     */
    public async deleteProposal(proposalId: string): Promise<boolean> {
        try {
            const response = await fetch(`/api/governance/proposals?id=${proposalId}`, {
                method: 'DELETE',
            });
            return response.ok;
        } catch (error) {
            console.error('Failed to delete proposal', error);
            return false;
        }
    }

    private async createProposal(userId: string, data: Partial<import('@/types/governance').GovernanceProposal>): Promise<import('@/types/governance').GovernanceProposal> {
        // Mock ID generation
        const id = `prop_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`;

        const proposal: import('@/types/governance').GovernanceProposal = {
            id,
            type: data.type || 'feature_request',
            title: data.title || 'Untitled Proposal',
            description: data.description || '',
            proposerId: userId,
            createdAt: Date.now(),
            expiresAt: Date.now() + (7 * 24 * 60 * 60 * 1000), // 7 Days
            status: 'active',
            votesFor: 0,
            votesAgainst: 0,
            votesAbstain: 0,
            ...data
        };

        try {
            await fetch('/api/governance/proposals', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(proposal)
            });
            logger.governance(`[PROPOSAL CREATED] ${proposal.type} by ${userId}: ${proposal.title}`);
        } catch (error) {
            console.error('Failed to persist proposal', error);
        }

        return proposal;
    }
}

import { AnalysisResult, Source } from '@/types';
import { EscalationConfiguration } from '@/types/escalation';

/**
 * Service to track the persistence/durability of logic patterns across the corpus.
 * This operationalizes the requirement that "Recurring High-Risk Patterns" trigger 
 * HARD escalation (Blocking), whereas isolated instances may be SOFT/MEDIUM.
 */

export interface RecurrenceContext {
    recurrence_count: number;
    similar_process_ids: string[]; // List of source IDs with similar patterns
    corpus_size: number;
}

export const RecurrenceService = {
    /**
     * Scans the corpus to find how many times the current analysis's "Dominant Logic"
     * has appeared in other documents with HIGH blindspot intensity.
     */
    calculateRecurrence: (
        currentAnalysis: AnalysisResult,
        allSources: Source[],
        currentSourceId?: string
    ): RecurrenceContext => {

        // 1. Identify the pattern to track
        // We track "High Blindspot" + "Dominant Logic"
        const currentIntensity = currentAnalysis.assemblage_analysis?.blindspot_intensity;
        const currentLogic = currentAnalysis.assemblage_analysis?.dominant_logic;

        if (currentIntensity !== 'High' || !currentLogic) {
            return { recurrence_count: 0, similar_process_ids: [], corpus_size: allSources.length };
        }

        // 2. Scan corpus
        const similarSources = allSources.filter(source => {
            // Exclude self
            if (source.id === currentSourceId) return false;

            const analysis = source.analysis;
            if (!analysis || !analysis.assemblage_analysis) return false;

            // Match criteria: High Intensity AND Same Dominant Logic (fuzzy match)
            const isHigh = analysis.assemblage_analysis.blindspot_intensity === 'High';
            const isSameLogic = analysis.assemblage_analysis.dominant_logic?.toLowerCase().includes(currentLogic.toLowerCase())
                || currentLogic.toLowerCase().includes(analysis.assemblage_analysis.dominant_logic?.toLowerCase() || '');

            return isHigh && isSameLogic;
        });

        // 3. Return context
        // Count includes self (so if found 2 others, count is 3)
        return {
            recurrence_count: similarSources.length + 1,
            similar_process_ids: similarSources.map(s => s.id),
            corpus_size: allSources.length
        };
    }
};

import { MEDIATOR_ANALYSIS_PROMPT, MEDIATOR_ANALYSIS_PROMPT_LITE } from '@/lib/prompts/ant-mediators';
// import { generateObject } from '@/lib/utils'; // Assuming utilize existing AI wrapper or similar

import { Relationship, MediatorDimensions } from '@/types/relationship';

interface AnalysisInput {
    sourceActor: string;
    targetActor: string;
    relationshipType: string;
    empiricalTraces: string[];
    documentContext: string;
}

interface AnalysisOutput {
    mediatorScore: number;
    dimensions: MediatorDimensions;
    interpretation: string;
}

export async function analyzeMediatorScore(
    input: AnalysisInput,
    apiKey?: string // Optional override
): Promise<AnalysisOutput> {

    // 1. Construct Prompt (Use Lite for Speed)
    const prompt = MEDIATOR_ANALYSIS_PROMPT_LITE
        .replace('{{source}}', input.sourceActor)
        .replace('{{type}}', input.relationshipType)
        .replace('{{target}}', input.targetActor)
        .replace('{{traces}}', input.empiricalTraces.map(t => `- "${t}"`).join('\n'))
        .replace('{{context}}', input.documentContext.substring(0, 1500)); // [SPEED] Reduced context slightly

    // 2. Call AI Service
    const response = await fetch('/api/relationships/analyze', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            prompt: prompt,
            mode: 'json',
            model: 'gpt-4o-mini' // [SPEED] Use lighter model for bulk links
        })
    });

    if (!response.ok) {
        throw new Error(`Analysis failed: ${response.statusText}`);
    }

    const result = await response.json();

    // [FIX] Robust response parsing
    // API returns { analysis: { ... } } where analysis might be the object OR a string
    // If it's the object, it has { mediatorScore, dimensions, ... }

    let aiData = result.analysis;

    // Debug logging
    // console.log("AI Data Received:", aiData);

    if (!aiData) {
        // Fallback if parsing failed but we got something
        throw new Error("No analysis data returned");
    }

    if (typeof aiData === 'string') {
        try {
            aiData = JSON.parse(aiData);
        } catch (e) {
            console.warn("Failed to parse AI string response", e);
            throw new Error("Invalid JSON from AI");
        }
    }

    // 3. Map Response to AnalysisOutput

    let dimensions: MediatorDimensions;
    let avgScore: number;

    if (aiData.scores) {
        // LITE PROTOCOL (Enriched)
        const scores = aiData.scores;

        const getScoreVal = (val: any) => (typeof val === 'object' && val !== null) ? val.score : val;
        const getJustification = (val: any) => (typeof val === 'object' && val !== null) ? val.justification : (aiData.interpretation || "Generated via fast analysis.");

        const sTrans = scores.transformation;
        const sStab = scores.stability;
        const sMult = scores.multiplicity;
        const sGen = scores.generativity;
        const sCont = scores.contestation;

        avgScore = (
            (getScoreVal(sTrans) || 0) +
            (getScoreVal(sStab) || 0) +
            (getScoreVal(sMult) || 0) +
            (getScoreVal(sGen) || 0) +
            (getScoreVal(sCont) || 0)
        ) / 5;

        const mapDim = (val: any) => ({
            score: getScoreVal(val) || 0,
            justification: getJustification(val),
            confidence: (aiData.confidence || 'medium') as 'high' | 'medium' | 'low'
        });

        dimensions = {
            transformation: mapDim(sTrans),
            stability: mapDim(sStab),
            multiplicity: mapDim(sMult),
            generativity: mapDim(sGen),
            contestation: mapDim(sCont)
        };
    } else if (aiData.dimensions) {
        // FULL PROTOCOL (Fallback)
        dimensions = aiData.dimensions;
        avgScore = aiData.mediatorScore || 0;

        // Recalculate average if simple property missing
        if (!aiData.mediatorScore) {
            const vals = Object.values(dimensions).map((d: any) => d.score || 0);
            if (vals.length) avgScore = vals.reduce((a: any, b: any) => a + b, 0) / vals.length;
        }
    } else {
        throw new Error("Invalid AI response: Missing scores or dimensions");
    }

    return {
        mediatorScore: avgScore,
        dimensions: dimensions,
        interpretation: aiData.interpretation || "Analysis complete."
    };
}

// Batch Analysis
export async function analyzeMediatorScoresBatch(
    inputs: AnalysisInput[]
): Promise<AnalysisOutput[]> {
    const BATCH_SIZE = 10; // [SPEED] Increased concurrency
    const results: AnalysisOutput[] = [];

    for (let i = 0; i < inputs.length; i += BATCH_SIZE) {
        const batch = inputs.slice(i, i + BATCH_SIZE);
        const batchPromises = batch.map(async (input) => {
            try {
                return await analyzeMediatorScore(input);
            } catch (error) {
                console.error(`Analysis failed for ${input.sourceActor} -> ${input.targetActor}:`, error);
                // Return a fallback "safe" result to keep the pipe moving
                // Return a fallback "safe" result to keep the pipe moving
                const fallbackDimension = (reason: string) => ({ score: 1, reasoning: reason, justification: reason, confidence: 'low' as const });
                return {
                    mediatorScore: 1, // Default to Intermediary (low score)
                    dimensions: {
                        transformation: fallbackDimension("Analysis failed, defaulting to intermediary."),
                        stability: fallbackDimension("Assumed stable due to missing analysis."),
                        multiplicity: fallbackDimension("N/A"),
                        generativity: fallbackDimension("N/A"),
                        contestation: fallbackDimension("N/A")
                    },
                    interpretation: "Analysis failed. Treated as a stable intermediary."
                } as AnalysisOutput;
            }
        });

        const batchResults = await Promise.all(batchPromises);
        results.push(...batchResults);
    }

    return results;
}

