import { BlindSpot, BlindSpotBasic, BlindSpotEnhanced, BlindSpotInteractive } from '@/types';

/**
 * Type Guards
 */

export function isBlindSpotString(spot: BlindSpot): spot is string {
    return typeof spot === 'string';
}

export function isBlindSpotBasic(spot: BlindSpot): spot is BlindSpotBasic {
    return typeof spot === 'object' && 'id' in spot && 'title' in spot && !('description' in spot);
}

export function isBlindSpotEnhanced(spot: BlindSpot): spot is BlindSpotEnhanced {
    return typeof spot === 'object' && 'description' in spot && !('status' in spot);
}

export function isBlindSpotInteractive(spot: BlindSpot): spot is BlindSpotInteractive {
    return typeof spot === 'object' && 'status' in spot;
}

/**
 * Tier Detection
 */

export function detectBlindSpotTier(spot: BlindSpot): 0 | 1 | 2 | 3 {
    if (isBlindSpotString(spot)) return 0;
    if (isBlindSpotInteractive(spot)) return 3;
    if (isBlindSpotEnhanced(spot)) return 2;
    if (isBlindSpotBasic(spot)) return 1;
    return 0;
}

export function detectOverallTier(spots: BlindSpot[]): 0 | 1 | 2 | 3 {
    if (spots.length === 0) return 0;
    const tiers = spots.map(detectBlindSpotTier);
    return Math.max(...tiers) as 0 | 1 | 2 | 3;
}

/**
 * Validation and Inference
 */

const HIGH_SEVERITY_KEYWORDS = [
    'excludes', 'ignores', 'colonial', 'reproduces', 'overlooks major',
    'silences', 'erases', 'marginalizes', 'extractive', 'asymmetric power'
];

const LOW_SEVERITY_KEYWORDS = [
    'minor', 'edge case', 'tangential', 'peripheral', 'secondary'
];

const CATEGORY_KEYWORDS: Record<string, string[]> = {
    epistemic: ['assumes', 'presumes', 'knowledge', 'literacy', 'expertise', 'understanding'],
    power: ['enforcement', 'authority', 'control', 'sovereignty', 'jurisdiction', 'capacity'],
    materiality: ['infrastructure', 'resources', 'material', 'physical', 'environmental'],
    temporality: ['urgency', 'timeline', 'future', 'legacy', 'maintenance'],
    coloniality: ['colonial', 'center', 'periphery', 'global south', 'extraction', 'imposition']
};

export function inferSeverity(spot: BlindSpot): 'low' | 'medium' | 'high' {
    const text = (typeof spot === 'string' ? spot : (spot.title + ' ' + (spot as any).description || '')).toLowerCase();

    if (HIGH_SEVERITY_KEYWORDS.some(kw => text.includes(kw))) return 'high';
    if (LOW_SEVERITY_KEYWORDS.some(kw => text.includes(kw))) return 'low';
    return 'medium';
}

export function inferCategory(spot: BlindSpot): BlindSpotBasic['category'] {
    const text = (typeof spot === 'string' ? spot : spot.title).toLowerCase();

    for (const [category, keywords] of Object.entries(CATEGORY_KEYWORDS)) {
        if (keywords.some(kw => text.includes(kw))) {
            return category as BlindSpotBasic['category'];
        }
    }

    return 'epistemic'; // Default fallback
}

/**
 * Validation
 */

export function validateBlindSpot(spot: any): BlindSpot {
    // If it's a string, return as-is (Tier 0)
    if (typeof spot === 'string') {
        return spot;
    }

    // Ensure required fields
    if (!spot.id) {
        spot.id = generateBlindSpotId();
    }

    if (!spot.title) {
        spot.title = 'Unnamed blind spot';
    }

    // Validate severity
    if (spot.severity && !['low', 'medium', 'high'].includes(spot.severity)) {
        spot.severity = inferSeverity(spot);
    }

    // Validate category
    if (spot.category && !['epistemic', 'power', 'materiality', 'temporality', 'coloniality'].includes(spot.category)) {
        spot.category = inferCategory(spot);
    }

    // Truncate long evidence quotes
    if (spot.evidence?.quote && spot.evidence.quote.length > 200) {
        spot.evidence.quote = spot.evidence.quote.slice(0, 197) + '...';
    }

    // Limit mitigations to 3
    if (spot.suggested_mitigations && spot.suggested_mitigations.length > 3) {
        spot.suggested_mitigations = spot.suggested_mitigations.slice(0, 3);
    }

    return spot as BlindSpot;
}

/**
 * Migration
 */

export function migrateBlindSpot(spot: string): BlindSpotBasic {
    return {
        id: generateBlindSpotId(),
        title: spot,
        severity: inferSeverity(spot),
        category: inferCategory(spot)
    };
}

export function migrateLegacyBlindSpots(spots: string[]): BlindSpotBasic[] {
    return spots.map(migrateBlindSpot);
}

/**
 * Coverage Score Calculation
 */

export function calculateEpistemicCoverageScore(spots: BlindSpot[]): number {
    if (spots.length === 0) return 100;

    const severityWeights = {
        high: 15,
        medium: 8,
        low: 3
    };

    let totalPenalty = 0;

    for (const spot of spots) {
        const severity = typeof spot === 'string'
            ? inferSeverity(spot)
            : spot.severity || inferSeverity(spot);

        totalPenalty += severityWeights[severity];
    }

    return Math.max(0, 100 - totalPenalty);
}

/**
 * Utilities
 */

export function generateBlindSpotId(): string {
    return `bs_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
}

export function getBlindSpotTitle(spot: BlindSpot): string {
    return typeof spot === 'string' ? spot : spot.title;
}

export function getBlindSpotSeverity(spot: BlindSpot): 'low' | 'medium' | 'high' {
    if (typeof spot === 'string') return inferSeverity(spot);
    return spot.severity || inferSeverity(spot);
}

export function getBlindSpotCategory(spot: BlindSpot): BlindSpotBasic['category'] {
    if (typeof spot === 'string') return inferCategory(spot);
    return spot.category || inferCategory(spot);
}

/**
 * Grouping and Filtering
 */

export function groupBlindSpotsByCategory(spots: BlindSpot[]): Record<string, BlindSpot[]> {
    const groups: Record<string, BlindSpot[]> = {
        epistemic: [],
        power: [],
        materiality: [],
        temporality: [],
        coloniality: [],
        uncategorized: []
    };

    for (const spot of spots) {
        const category = getBlindSpotCategory(spot) || 'uncategorized';
        groups[category].push(spot);
    }

    return groups;
}

export function groupBlindSpotsBySeverity(spots: BlindSpot[]): Record<string, BlindSpot[]> {
    const groups: Record<string, BlindSpot[]> = {
        high: [],
        medium: [],
        low: []
    };

    for (const spot of spots) {
        const severity = getBlindSpotSeverity(spot);
        groups[severity].push(spot);
    }

    return groups;
}

export function sortBlindSpotsBySeverity(spots: BlindSpot[]): BlindSpot[] {
    const severityOrder = { high: 0, medium: 1, low: 2 };

    return [...spots].sort((a, b) => {
        const severityA = getBlindSpotSeverity(a);
        const severityB = getBlindSpotSeverity(b);
        return severityOrder[severityA] - severityOrder[severityB];
    });
}

import { jsPDF } from "jspdf";
import { SynthesisComparisonResult } from "@/types/synthesis";

export function generateSynthesisPDF(data: SynthesisComparisonResult, sourceA: string, sourceB: string) {
    const doc = new jsPDF();
    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();
    const margin = 20;
    const contentWidth = pageWidth - 2 * margin;
    let y = margin;

    // Helper: Add Page Check
    const checkPageBreak = (heightNeeded: number) => {
        if (y + heightNeeded > pageHeight - margin) {
            doc.addPage();
            y = margin;
            return true;
        }
        return false;
    };

    // Helper: Add Title
    const addTitle = (text: string, size = 16) => {
        checkPageBreak(size);
        doc.setFontSize(size);
        doc.setFont("helvetica", "bold");
        doc.setTextColor(30, 41, 59); // Slate-900
        doc.text(text, margin, y + 6);
        y += size * 0.8 + 8;
    };

    // Helper: Add Section Header
    const addSection = (text: string) => {
        y += 5;
        checkPageBreak(20);
        doc.setFontSize(14);
        doc.setFont("helvetica", "bold");
        doc.setTextColor(71, 85, 105); // Slate-600
        doc.text(text, margin, y + 5);
        // Underline
        doc.setDrawColor(203, 213, 225); // Slate-300
        doc.line(margin, y + 8, pageWidth - margin, y + 8);
        y += 18;
    };

    // Helper: Add Paragraph
    const addParagraph = (text: string, size = 10, color: [number, number, number] = [0, 0, 0]) => {
        if (!text) return;
        doc.setFontSize(size);
        doc.setFont("helvetica", "normal");
        doc.setTextColor(...color);
        const lines = doc.splitTextToSize(text, contentWidth);
        const height = lines.length * size * 0.45; // Approx line height

        checkPageBreak(height + 5);
        doc.text(lines, margin, y);
        y += height + 4;
    };

    // Helper: Add Key-Value Box
    const addBox = (label: string, text: string, bgColor: [number, number, number]) => {
        if (!text || text === "...") return; // Skip empty

        doc.setFontSize(10);
        const lines = doc.splitTextToSize(text, contentWidth - 6); // Padding
        const height = lines.length * 5 + 12; // Text height + Padding

        checkPageBreak(height + 5);

        // Background
        doc.setFillColor(...bgColor);
        doc.setDrawColor(bgColor[0] - 20, bgColor[1] - 20, bgColor[2] - 20); // Darker border
        doc.roundedRect(margin, y, contentWidth, height, 2, 2, "FD");

        // Label
        doc.setFont("helvetica", "bold");
        doc.setFontSize(8);
        doc.setTextColor(50, 50, 50);
        doc.text(label.toUpperCase(), margin + 3, y + 6);

        // Content
        doc.setFont("helvetica", "normal");
        doc.setFontSize(10);
        doc.setTextColor(0, 0, 0);
        doc.text(lines, margin + 3, y + 14);

        y += height + 4;
    };

    // --- REPORT GENERATION ---

    // 1. Cover / Header
    addTitle("Decolonial Situatedness Analysis", 22);
    addParagraph(`Comparing: ${sourceA} vs ${sourceB}`, 12, [71, 85, 105]);
    addParagraph(`Generated: ${new Date().toLocaleDateString()}`, 10, [148, 163, 184]);
    y += 10;

    // 2. Executive Summary (if available)
    if (data.resonances?.narrative) {
        addSection("Executive Summary");
        addParagraph(data.resonances.narrative);
    }

    // 3. Matrix Analysis (Risk, Governance, Rights, Scope)
    const dimensions = [
        { key: 'risk', label: 'Risk Definition' },
        { key: 'governance', label: 'Governance Structure' },
        { key: 'rights', label: 'Rights Framework' },
        { key: 'scope', label: 'Territorial Scope' }
    ];

    dimensions.forEach(dim => {
        const item = data[dim.key as keyof SynthesisComparisonResult] as any;
        if (!item) return;

        addSection(dim.label);

        addBox("Convergence", item.convergence, [220, 252, 231]); // Green-100
        addBox("Divergence", item.divergence, [219, 234, 254]); // Blue-100
        addBox("Coloniality", item.coloniality, [254, 226, 226]); // Red-100
        addBox("Resistance", item.resistance, [243, 232, 255]); // Purple-100
    });

    // 4. Rhizomatic Resonances (Shared Strategies)
    if (data.resonances?.shared_strategies && data.resonances.shared_strategies.length > 0) {
        addSection("Rhizomatic Resonances");
        doc.setFont("helvetica", "bold");
        doc.text("Shared Strategies & Concepts:", margin, y);
        y += 6;

        data.resonances.shared_strategies.forEach(strat => {
            checkPageBreak(8);
            doc.setFont("helvetica", "normal");
            doc.text(`• ${strat}`, margin + 5, y);
            y += 6;
        });
    }

    // 5. Verified Quotes
    if (data.verified_quotes && data.verified_quotes.length > 0) {
        addSection("Verified Canonical Evidence");
        data.verified_quotes.forEach(quote => {
            const text = `"${quote.text}"`;
            const meta = `— ${quote.source} (${quote.relevance})`;

            checkPageBreak(30); // Approx
            addParagraph(text, 10, [51, 65, 85]); // Slate-700

            doc.setFont("helvetica", "italic");
            doc.setFontSize(9);
            doc.setTextColor(100, 116, 139);
            doc.text(meta, margin + 5, y - 2); // Tweak y back up slightly
            y += 6;
        });
    }

    // Footer Page Numbers
    const totalPages = doc.getNumberOfPages();
    for (let i = 1; i <= totalPages; i++) {
        doc.setPage(i);
        doc.setFontSize(8);
        doc.setTextColor(148, 163, 184); // Slate-400
        doc.text(
            `Page ${i} of ${totalPages}  |  Generated by Antigravity`,
            pageWidth / 2,
            pageHeight - 10,
            { align: "center" }
        );
    }

    // Save
    const filename = `analysis-${sourceA.substring(0, 10)}-vs-${sourceB.substring(0, 10)}.pdf`.replace(/[^a-z0-9]/gi, '_').toLowerCase();
    doc.save(filename);
}

import { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, BorderStyle, ImageRun } from "docx";
import { saveAs } from "file-saver";
import { STYLE } from "./styles";
import { sanitizeText } from "./helpers";

export class ReportGeneratorDOCX {
    public sections: any[] = [];

    constructor() { }

    public getDocument(): Document {
        return new Document({
            sections: [{
                properties: {},
                children: this.sections,
            }],
            styles: {
                paragraphStyles: [
                    {
                        id: "Normal",
                        name: "Normal",
                        run: {
                            font: "Helvetica",
                            size: 22, // 11pt
                            color: "000000",
                        },
                        paragraph: {
                            spacing: { line: 276, before: 0, after: 0 }, // 1.15 line height
                        },
                    },
                ],
            },
        });
    }

    public addTitlePage(title: string, subtitle: string) {
        this.sections.push(
            new Paragraph({
                text: title,
                heading: HeadingLevel.TITLE,
                alignment: AlignmentType.CENTER,
                spacing: { before: 4000, after: 300 },
                run: {
                    font: STYLE.fonts.header,
                    color: STYLE.colors.primary,
                    size: STYLE.sizes.title,
                    bold: true,
                }
            })
        );

        this.sections.push(
            new Paragraph({
                text: subtitle,
                alignment: AlignmentType.CENTER,
                spacing: { after: 300 },
                run: {
                    font: STYLE.fonts.normal,
                    color: STYLE.colors.meta,
                    size: STYLE.sizes.subHeader,
                }
            })
        );

        const dateStr = `Generated: ${new Date().toLocaleDateString("en-US", { year: "numeric", month: "long", day: "numeric" })}`;
        this.sections.push(
            new Paragraph({
                text: dateStr,
                alignment: AlignmentType.CENTER,
                run: {
                    font: STYLE.fonts.normal,
                    color: STYLE.colors.meta,
                    size: STYLE.sizes.body,
                }
            })
        );
    }

    public addPageBreak() {
        this.sections.push(new Paragraph({
            children: [new TextRun({ break: 1 })],
            pageBreakBefore: true
        }));
    }

    public addSectionHeader(title: string, pageBreak: boolean = false) {
        this.sections.push(
            new Paragraph({
                text: title.toUpperCase(),
                heading: HeadingLevel.HEADING_1,
                spacing: { before: 300, after: 150 },
                pageBreakBefore: pageBreak,
                run: {
                    font: STYLE.fonts.header,
                    color: STYLE.colors.primary,
                    size: STYLE.sizes.section,
                    bold: true,
                },
                border: {
                    bottom: { color: STYLE.colors.accent, space: 1, style: BorderStyle.SINGLE, size: 12 }
                }
            })
        );
    }

    public addSubHeader(title: string) {
        this.sections.push(
            new Paragraph({
                text: title,
                heading: HeadingLevel.HEADING_2,
                spacing: { before: 200, after: 100 },
                run: {
                    font: STYLE.fonts.header,
                    color: STYLE.colors.primary,
                    size: STYLE.sizes.subHeader,
                    bold: true,
                }
            })
        );
    }

    public addText(text: string | null | undefined, color: string = STYLE.colors.text, indent: number = 0, bold: boolean = false) {
        if (!text) return;

        const cleanContent = sanitizeText(text);
        const paragraphs = cleanContent.split('\n');

        paragraphs.forEach(p => {
            let content = p.trim();
            if (!content) return;

            const isBullet = content.startsWith("•");
            if (isBullet) {
                content = content.replace(/^[•\s]+/, "").trim();
            }

            this.sections.push(
                new Paragraph({
                    text: content,
                    bullet: isBullet ? { level: 0 } : undefined,
                    indent: isBullet ? undefined : { left: indent * 100 },
                    spacing: { after: 120 },
                    run: {
                        font: STYLE.fonts.normal,
                        color: color,
                        size: STYLE.sizes.body,
                        bold: bold,
                    }
                })
            );
        });
    }

    public addSpacer() {
        this.sections.push(new Paragraph({ text: "" }));
    }

    public addImage(base64Data: string, width: number = 600, height: number = 400, caption?: string) {
        if (!base64Data) return;

        // Strip prefix if present (e.g. "data:image/png;base64,")
        const data = base64Data.replace(/^data:image\/(png|jpg|jpeg);base64,/, "");

        try {
            const image = new ImageRun({
                data: data,
                transformation: {
                    width: width,
                    height: height,
                },
                type: "png", // docx seems to auto-detect or default to png/jpeg based on header usually, but explicit type helps
            });

            this.sections.push(
                new Paragraph({
                    children: [image],
                    alignment: AlignmentType.CENTER,
                    spacing: { before: 200, after: 100 },
                })
            );

            if (caption) {
                this.sections.push(
                    new Paragraph({
                        text: caption,
                        alignment: AlignmentType.CENTER,
                        spacing: { after: 300 },
                        run: {
                            font: STYLE.fonts.normal,
                            color: STYLE.colors.meta,
                            size: STYLE.sizes.meta, // 9pt
                            italics: true,
                        }
                    })
                );
            }

        } catch (e) {
            console.error("Failed to add image to report:", e);
            this.sections.push(
                new Paragraph({
                    text: "[Error: Could not render image]",
                    run: { color: STYLE.colors.danger, italics: true }
                })
            );
        }
    }

    public async generateAndDownload(filename: string) {
        const doc = new Document({
            sections: [{
                properties: {},
                children: this.sections,
            }],
        });

        const blob = await Packer.toBlob(doc);
        saveAs(blob, filename);
    }
}

import { ReportData } from "@/types/report";
import { Paragraph, Table, TableCell, TableRow, WidthType, BorderStyle } from "docx";
import { ReportGeneratorDOCX } from "../generator";
import { STYLE } from "../styles";
import { sanitizeText } from "../helpers";

export function renderEcosystemAnalysis(generator: ReportGeneratorDOCX, data: ReportData["ecosystem"]) {
    if (!data) return;
    generator.addSectionHeader("Ecosystem & Assemblage Analysis", true);

    if (data.actors) renderEcosystemActors(generator, data.actors);
    if (data.configurations) renderEcosystemConfigurations(generator, data.configurations);
    if (data.absenceAnalysis) renderAbsenceAnalysis(generator, data.absenceAnalysis);
    if (data.assemblage) renderAssemblageAnalysis(generator, data.assemblage);
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
function renderEcosystemActors(generator: ReportGeneratorDOCX, actors: any[]) {
    if (actors.length === 0) return;

    generator.addSubHeader("Key Ecosystem Actors");

    // Create Table Rows
    const headerRow = new TableRow({
        children: [
            new TableCell({ width: { size: 20, type: WidthType.PERCENTAGE }, children: [new Paragraph({ text: "Actor Name", run: { bold: true } })] }),
            new TableCell({ width: { size: 15, type: WidthType.PERCENTAGE }, children: [new Paragraph({ text: "Type", run: { bold: true } })] }),
            new TableCell({ width: { size: 10, type: WidthType.PERCENTAGE }, children: [new Paragraph({ text: "Infl.", run: { bold: true } })] }),
            new TableCell({ width: { size: 15, type: WidthType.PERCENTAGE }, children: [new Paragraph({ text: "Context", run: { bold: true } })] }),
            new TableCell({ width: { size: 40, type: WidthType.PERCENTAGE }, children: [new Paragraph({ text: "Description", run: { bold: true } })] }),
        ],
        tableHeader: true,
    });

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const rows = actors.map((actor: any) => new TableRow({
        children: [
            new TableCell({ children: [new Paragraph(actor.name)] }),
            new TableCell({ children: [new Paragraph(actor.type)] }),
            new TableCell({ children: [new Paragraph(actor.influence)] }),
            new TableCell({ children: [new Paragraph(actor.materialized_from?.context_type || "Direct")] }),
            new TableCell({ children: [new Paragraph(sanitizeText(actor.description || ""))] }),
        ]
    }));

    const table = new Table({
        rows: [headerRow, ...rows],
        width: { size: 100, type: WidthType.PERCENTAGE },
        borders: {
            top: { style: BorderStyle.SINGLE, size: 1, color: STYLE.colors.subtle },
            bottom: { style: BorderStyle.SINGLE, size: 1, color: STYLE.colors.subtle },
            left: { style: BorderStyle.SINGLE, size: 1, color: STYLE.colors.subtle },
            right: { style: BorderStyle.SINGLE, size: 1, color: STYLE.colors.subtle },
            insideHorizontal: { style: BorderStyle.SINGLE, size: 1, color: STYLE.colors.accent },
            insideVertical: { style: BorderStyle.SINGLE, size: 1, color: STYLE.colors.accent },
        }
    });

    generator.sections.push(table);
    generator.sections.push(new Paragraph({ text: "" })); // Spacing
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
function renderEcosystemConfigurations(generator: ReportGeneratorDOCX, configurations: any[]) {
    if (!configurations || configurations.length === 0) return;

    generator.addSubHeader("Ecosystem Configurations (Assemblages)");

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    configurations.forEach((config: any, index: number) => {
        generator.addText(`${index + 1}. ${config.name}`, STYLE.colors.primary, 0, true);
        if (config.description) {
            generator.addText(config.description, STYLE.colors.subtle, 1);
        }

        if (config.properties) {
            generator.addText(`Stability: ${config.properties.stability || 'N/A'}`, undefined, 1);
            generator.addText(`Generativity: ${config.properties.generativity || 'N/A'}`, undefined, 1);
            if (config.properties.territorialization_score !== undefined) {
                generator.addText(`Territorialization: ${config.properties.territorialization_score}/10`, undefined, 1);
            }
            if (config.properties.coding_intensity_score !== undefined) {
                generator.addText(`Coding Intensity: ${config.properties.coding_intensity_score}/10`, undefined, 1);
            }
        }

        if (config.memberIds && config.memberIds.length > 0) {
            generator.addText(`Member Actors: ${config.memberIds.length}`, STYLE.colors.secondary, 1);
        }

        generator.addSpacer();
    });
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
function renderAbsenceAnalysis(generator: ReportGeneratorDOCX, absenceAnalysis: any) {
    generator.addSubHeader("Critique: Absences & Blindspots");
    if (absenceAnalysis.narrative) {
        generator.addText(absenceAnalysis.narrative);
        generator.addSpacer();
    }

    if (absenceAnalysis.missing_voices && absenceAnalysis.missing_voices.length > 0) {
        generator.addText("Missing Voices:", STYLE.colors.secondary, 0, true);
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        absenceAnalysis.missing_voices.forEach((voice: any) => {
            // Check if voice is an object or string
            const text = typeof voice === 'string' ? voice : `${voice.name} (${voice.category}): ${voice.reason}`;
            generator.addText(`• ${text}`);
        });
        generator.addSpacer();
    }
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
function renderAssemblageAnalysis(generator: ReportGeneratorDOCX, assemblage: any) {
    generator.addSubHeader("Assemblage Analysis");

    // Parts (Socio-Technical Components)
    if (assemblage.socio_technical_components) {
        generator.addText("Parts (Socio-Technical Components)", STYLE.colors.secondary, 0, true);
        const { infra, discourse } = assemblage.socio_technical_components;
        if (infra && infra.length > 0) generator.addText(`Infrastructure: ${infra.join(", ")}`);
        if (discourse && discourse.length > 0) generator.addText(`Discourse: ${discourse.join(", ")}`);
        generator.addSpacer();
    }

    // Flow (Policy Mobilities)
    if (assemblage.policy_mobilities) {
        generator.addText("Flow (Policy Mobilities)", STYLE.colors.secondary, 0, true);
        const { origin_concepts, local_mutations } = assemblage.policy_mobilities;
        if (origin_concepts && origin_concepts.length > 0) generator.addText(`Origin Concepts: ${origin_concepts.join(", ")}`);
        if (local_mutations && local_mutations.length > 0) generator.addText(`Local Mutations: ${local_mutations.join(", ")}`);
        generator.addSpacer();
    }

    // Exterior (Relations of Exteriority)
    if (assemblage.relations_of_exteriority) {
        generator.addText("Exterior (Relations of Exteriority)", STYLE.colors.secondary, 0, true);
        const { detachable, embedded, mobility_score } = assemblage.relations_of_exteriority;
        // Check if mobility_score exists before printing
        if (mobility_score) generator.addText(`Mobility Score: ${mobility_score}`);
        if (detachable && detachable.length > 0) generator.addText(`Detachable Relations: ${detachable.join(", ")}`);
        if (embedded && embedded.length > 0) generator.addText(`Embedded Relations: ${embedded.join(", ")}`);
        generator.addSpacer();
    }

    // Stable (Stabilization Mechanisms)
    if (assemblage.stabilization_mechanisms && assemblage.stabilization_mechanisms.length > 0) {
        generator.addText("Stable (Stabilization Mechanisms)", STYLE.colors.secondary, 0, true);
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        assemblage.stabilization_mechanisms.forEach((mech: any) => generator.addText(`• ${mech}`));
        generator.addSpacer();
    }
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function renderScenarios(generator: ReportGeneratorDOCX, scenarios: any) {
    if (!scenarios || Object.keys(scenarios).length === 0) return;

    generator.addSectionHeader("Scenario Analysis", true);
    generator.addText("Hypothetical scenarios testing the resilience and adaptability of the governance assemblage.");
    generator.addSpacer();

    // Scenarios are typically stored as an object with scenario IDs as keys
    Object.entries(scenarios).forEach(([scenarioId, scenarioData]: [string, any]) => {
        if (scenarioData && scenarioData.name) {
            generator.addSubHeader(scenarioData.name);
            if (scenarioData.description) {
                generator.addText(scenarioData.description);
            }
            if (scenarioData.effects) {
                generator.addText("Effects:", STYLE.colors.secondary, 0, true);
                scenarioData.effects.forEach((effect: string) => {
                    generator.addText(`• ${effect}`, undefined, 1);
                });
            }
            generator.addSpacer();
        }
    });
}

import { Source } from "@/types";
import { Paragraph, Table, TableCell, TableRow, WidthType, BorderStyle } from "docx";
import { ReportGeneratorDOCX } from "../generator";
import { STYLE } from "../styles";
import { calculateMicroFascismRisk } from "@/lib/risk-calculator";
import { calculateLiberatoryCapacity } from "@/lib/liberatory-calculator";

export function renderComparisonMatrix(generator: ReportGeneratorDOCX, sources: Source[]) {
    if (!sources || sources.length < 2) return;

    // Filter for sources with analysis
    const validSources = sources.filter(s => s.analysis);
    if (validSources.length < 2) return;

    generator.addSectionHeader("Comparative Diagnostic Matrix", true);
    generator.addText("Flattened matrix view for rapid cross-policy signal analysis.", STYLE.colors.meta);

    // 1. Comparison Table
    renderComparisonTable(generator, validSources);

    // 2. Detailed Breakdown text (to avoid super wide tables)
    renderComparisonSignalBreakdown(generator, validSources);
}

function renderComparisonTable(generator: ReportGeneratorDOCX, validSources: Source[]) {
    // Calculate headers: Diagnostic Criteria + Source Names
    const tableHeaders = [
        new TableCell({
            width: { size: 25, type: WidthType.PERCENTAGE },
            children: [new Paragraph({ text: "Diagnostic Criteria", run: { bold: true, size: STYLE.sizes.small } })]
        }),
        ...validSources.map(s => new TableCell({
            width: { size: (75 / validSources.length), type: WidthType.PERCENTAGE },
            children: [new Paragraph({ text: s.title, run: { bold: true, size: STYLE.sizes.small } })]
        }))
    ];

    const rows: TableRow[] = [];

    // Header Row
    rows.push(new TableRow({ children: tableHeaders, tableHeader: true }));

    // A. Overall Risk Index Row
    const riskRowCells = [
        new TableCell({ children: [new Paragraph({ text: "Overall Risk Index", run: { bold: true, size: STYLE.sizes.small } })] }),
        ...validSources.map(s => {
            const risk = calculateMicroFascismRisk(s.analysis!);
            const color = risk && risk.score >= 4 ? STYLE.colors.danger : STYLE.colors.primary;
            return new TableCell({
                children: [new Paragraph({
                    text: risk ? `${risk.score}/6 (${risk.level})` : "-",
                    run: { color: color, bold: true, size: STYLE.sizes.small }
                })]
            });
        })
    ];
    rows.push(new TableRow({ children: riskRowCells }));

    // B. Liberatory Potential Row
    const capacityRowCells = [
        new TableCell({ children: [new Paragraph({ text: "Liberatory Potential", run: { bold: true, size: STYLE.sizes.small } })] }),
        ...validSources.map(s => {
            const cap = calculateLiberatoryCapacity(s.analysis!);
            const color = cap && cap.score >= 5 ? STYLE.colors.success : STYLE.colors.primary;
            return new TableCell({
                children: [new Paragraph({
                    text: cap ? `${cap.score}/8 (${cap.level})` : "-",
                    run: { color: color, bold: true, size: STYLE.sizes.small }
                })]
            });
        })
    ];
    rows.push(new TableRow({ children: capacityRowCells }));

    // Table Construction
    const matrixTable = new Table({
        rows: rows,
        width: { size: 100, type: WidthType.PERCENTAGE },
        borders: {
            top: { style: BorderStyle.SINGLE, size: 1, color: STYLE.colors.subtle },
            bottom: { style: BorderStyle.SINGLE, size: 1, color: STYLE.colors.subtle },
            left: { style: BorderStyle.SINGLE, size: 1, color: STYLE.colors.subtle },
            right: { style: BorderStyle.SINGLE, size: 1, color: STYLE.colors.subtle },
            insideHorizontal: { style: BorderStyle.SINGLE, size: 1, color: STYLE.colors.accent },
            insideVertical: { style: BorderStyle.SINGLE, size: 1, color: STYLE.colors.accent },
        }
    });

    generator.sections.push(matrixTable);
    generator.addSpacer();
    generator.addSpacer();
}

function renderComparisonSignalBreakdown(generator: ReportGeneratorDOCX, validSources: Source[]) {
    generator.addSubHeader("Detailed Signal Breakdown");

    validSources.forEach(s => {
        const risk = calculateMicroFascismRisk(s.analysis!);
        const cap = calculateLiberatoryCapacity(s.analysis!);

        generator.addText(`${s.title}:`, STYLE.colors.primary, 0, true);

        if (risk) {
            const riskFlags = Object.entries(risk.flags).filter(([k, v]) => v).map(([k]) => k.replace(/_/g, ' '));
            if (riskFlags.length > 0) {
                generator.addText(`• Risk Signals: ${riskFlags.join(", ")}`, STYLE.colors.danger);
            }
        }
        if (cap) {
            const capFlags = Object.entries(cap.signals).filter(([k, v]) => v).map(([k]) => k.replace(/_/g, ' '));
            if (capFlags.length > 0) {
                generator.addText(`• Liberatory Capacities: ${capFlags.join(", ")}`, STYLE.colors.success);
            }
        }
        generator.addText("");
    });
}

export function renderGovernanceMatrix(generator: ReportGeneratorDOCX, sources: Source[]) {
    if (!sources || sources.length < 2) return;

    // Filter for sources with governance scores
    const validSources = sources.filter(s => s.analysis && s.analysis.governance_scores);
    if (validSources.length < 2) return;

    generator.addSectionHeader("Governance Compass Matrix", true);
    generator.addText("Comparative analysis of governance mechanisms across frameworks.", STYLE.colors.meta);

    // Governance Dimensions
    const dimensions = [
        { id: "centralization", label: "Centralization" },
        { id: "rights_focus", label: "Rights Focus" },
        { id: "flexibility", label: "Flexibility" },
        { id: "market_power", label: "Market Power" },
        { id: "procedurality", label: "Procedurality" }
    ];

    // 1. Comparison Table
    const tableHeaders = [
        new TableCell({
            width: { size: 25, type: WidthType.PERCENTAGE },
            children: [new Paragraph({ text: "Governance Dimension", run: { bold: true, size: STYLE.sizes.small } })]
        }),
        ...validSources.map(s => new TableCell({
            width: { size: (75 / validSources.length), type: WidthType.PERCENTAGE },
            children: [new Paragraph({ text: s.title, run: { bold: true, size: STYLE.sizes.small } })]
        }))
    ];

    const rows: TableRow[] = [];
    rows.push(new TableRow({ children: tableHeaders, tableHeader: true }));

    dimensions.forEach(dim => {
        const rowCells = [
            new TableCell({ children: [new Paragraph({ text: dim.label, run: { bold: true, size: STYLE.sizes.small } })] }),
            ...validSources.map(s => {
                const score = s.analysis?.governance_scores?.[dim.id as keyof typeof s.analysis.governance_scores] ?? "-";
                return new TableCell({
                    children: [new Paragraph({
                        text: String(score),
                        run: { color: STYLE.colors.secondary, size: STYLE.sizes.small }
                    })]
                });
            })
        ];
        rows.push(new TableRow({ children: rowCells }));
    });

    // Table Construction
    const matrixTable = new Table({
        rows: rows,
        width: { size: 100, type: WidthType.PERCENTAGE },
        borders: {
            top: { style: BorderStyle.SINGLE, size: 1, color: STYLE.colors.subtle },
            bottom: { style: BorderStyle.SINGLE, size: 1, color: STYLE.colors.subtle },
            left: { style: BorderStyle.SINGLE, size: 1, color: STYLE.colors.subtle },
            right: { style: BorderStyle.SINGLE, size: 1, color: STYLE.colors.subtle },
            insideHorizontal: { style: BorderStyle.SINGLE, size: 1, color: STYLE.colors.accent },
            insideVertical: { style: BorderStyle.SINGLE, size: 1, color: STYLE.colors.accent },
        }
    });

    generator.sections.push(matrixTable);
    generator.addSpacer();
}

import { ResistanceAnalysis, Source } from "@/types";
import { ReportData } from "@/types/report";
import { ReportGeneratorDOCX } from "../generator";
import { STYLE } from "../styles";

export function renderResistanceTrace(generator: ReportGeneratorDOCX, source: Source) {
    if (!source.resistance_analysis) return;

    const r = source.resistance_analysis;
    generator.addSubHeader("Micro-Resistance Trace Analysis");

    generator.addText(`Strategy: ${r.strategy_detected}`, STYLE.colors.primary, 0, true);
    generator.addText(`Confidence: ${r.confidence}`, r.confidence === 'High' ? STYLE.colors.success : STYLE.colors.secondary, 0, true);

    if (r.evidence_quote) {
        generator.addText(`Evidence: "${r.evidence_quote}"`, STYLE.colors.subtle, 1);
    }

    if (r.interpretation) {
        generator.addText("Interpretation:", STYLE.colors.secondary, 0, true);
        generator.addText(r.interpretation);
    }
}

export function renderResistanceAnalysis(generator: ReportGeneratorDOCX, data: ReportData["resistance"]) {
    if (!data) return;
    generator.addSectionHeader("Micro-Resistance Analysis", true);

    if (data.executive_summary) {
        generator.addText(data.executive_summary);
    }

    if (data.dominant_strategies && data.dominant_strategies.length > 0) {
        generator.addSubHeader("Dominant Strategies");
        data.dominant_strategies.forEach((strat) => {
            generator.addText(strat.strategy, STYLE.colors.primary, 0, true);
            generator.addText(strat.description);
            generator.addText(`Frequency: ${strat.frequency}`, STYLE.colors.meta, 1);
            if (strat.minor_actor_verification) {
                generator.addText(`Minor Actor Signal: ${strat.minor_actor_verification}`, STYLE.colors.subtle, 1);
            }
            generator.addSpacer();
        });
    }

    if (data.lines_of_flight) {
        generator.addSubHeader("Lines of Flight (Deterritorialization)");
        generator.addText(data.lines_of_flight.narrative_aggregate);
        generator.addSpacer();

        if (data.lines_of_flight.vectors_of_deterritorialization) {
            generator.addText("Vectors of Deterritorialization:", STYLE.colors.secondary, 0, true);
            data.lines_of_flight.vectors_of_deterritorialization.forEach((vec) => {
                generator.addText(`• ${vec.name} (${vec.intensity}): ${vec.description}`, undefined, 1);
            });
            generator.addSpacer();
        }

        generator.addText(`Recapture Pressure: ${data.lines_of_flight.recapture_pressure}`, STYLE.colors.danger, 0, true);
    }

    if (data.implications_for_legitimacy) {
        generator.addSubHeader("Implications for Legitimacy");
        generator.addText(data.implications_for_legitimacy);
    }
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function renderResistanceArtifacts(generator: ReportGeneratorDOCX, artifacts: any[]) {
    if (!artifacts || artifacts.length === 0) return;

    generator.addSectionHeader("Resistance Artifacts (Primary Data)", true);

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    artifacts.forEach((artifact: any, index: number) => {
        const title = artifact.title || `Artifact #${index + 1}`;
        generator.addSubHeader(title);

        if (artifact.type) generator.addText(`Type: ${artifact.type}`, STYLE.colors.meta);
        if (artifact.date) generator.addText(`Date: ${artifact.date}`, STYLE.colors.meta);
        if (artifact.source) generator.addText(`Source/Platform: ${artifact.source}`, STYLE.colors.meta);

        generator.addSpacer();

        if (artifact.content) {
            generator.addText("Content / Excerpt:", STYLE.colors.secondary, 0, true);
            generator.addText(`"${artifact.content}"`, STYLE.colors.subtle, 1);
        }

        if (artifact.analysis) {
            generator.addText("Trace Analysis:", STYLE.colors.secondary, 0, true);
            if (artifact.analysis.tactic) generator.addText(`• Tactic: ${artifact.analysis.tactic}`, undefined, 1);
            if (artifact.analysis.target) generator.addText(`• Target: ${artifact.analysis.target}`, undefined, 1);
            if (artifact.analysis.effect) generator.addText(`• Effect: ${artifact.analysis.effect}`, undefined, 1);
        }
        generator.addSpacer();
    });
}

import { Source } from "@/types";
import { ReportGeneratorDOCX } from "../generator";
import { STYLE } from "../styles";
import { calculateMicroFascismRisk, MicroFascismRisk } from "@/lib/risk-calculator";
import { calculateLiberatoryCapacity, LiberatoryCapacity } from "@/lib/liberatory-calculator";

export function renderDataPageCalculations(generator: ReportGeneratorDOCX, source: Source) {
    if (!source.analysis) return;

    // 0. Decision Ownership & Accountability - Narrative First
    if (source.analysis.accountability_map) {
        generator.addSubHeader("Decision Ownership & Accountability");
        const acc = source.analysis.accountability_map;

        // Build interpretive narrative
        const hasFullAccountability = acc.signatory && acc.liability_holder && acc.appeals_mechanism;
        const narrative = hasFullAccountability
            ? `Accountability chains are formalized through explicit designation of ${acc.signatory} as signatory authority, with liability assigned to ${acc.liability_holder}. Appeals mechanisms (${acc.appeals_mechanism}) provide contestation pathways, suggesting robust procedural accountability architecture.`
            : `Accountability structures exhibit gaps or ambiguities. ${acc.signatory ? `While ${acc.signatory} serves as formal signatory, ` : 'Signatory authority remains unspecified, and '}${acc.liability_holder ? `liability rests with ${acc.liability_holder}, ` : 'liability assignment is unclear, '}creating potential enforcement weaknesses.`;

        generator.addText(narrative);
        generator.addSpacer();

        // Supporting details (subtle)
        if (acc.human_in_the_loop !== undefined) {
            generator.addText(`  → Human oversight: ${acc.human_in_the_loop ? 'Required' : 'Not mandated'}`, STYLE.colors.subtle, 1);
        }
    }

    // Calculate risk and capacity first as they are used in multiple sections
    const risk = calculateMicroFascismRisk(source.analysis);
    const capacity = calculateLiberatoryCapacity(source.analysis);

    // 1. Authoritarian Tendencies - Interpretive Narrative
    if (risk) {
        generator.addSubHeader("Authoritarian Tendencies Analysis");

        // Lead with rich interpretation
        const narrative = interpretRiskNarrative(risk);
        generator.addText(narrative);
        generator.addSpacer();

        // Evidence from observed indicators
        const triggeredFlags = Object.entries(risk.flags)
            .filter(([_, val]) => val)
            .map(([key]) => key.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase()));

        if (triggeredFlags.length > 0) {
            generator.addText("Observed Indicators:", STYLE.colors.secondary, 0, true);
            triggeredFlags.forEach(flag => {
                generator.addText(`  → ${flag}`, undefined, 1);
            });
            generator.addSpacer();
        }

        // Score goes to parenthetical reference
        generator.addText(`(Parametric summary: ${risk.score}/6 ${risk.level} - see methodological appendix)`, STYLE.colors.meta, 0, false);
        generator.addSpacer();
    }

    // 2. Liberatory Capacity - Interpretive Narrative
    if (capacity) {
        generator.addSubHeader("Liberatory Capacity Assessment");

        // Lead with interpretation
        const narrative = interpretCapacityNarrative(capacity);
        generator.addText(narrative);
        generator.addSpacer();

        // Evidence from active signals
        const triggeredSignals = Object.entries(capacity.signals)
            .filter(([_, val]) => val)
            .map(([key]) => key.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase()));

        if (triggeredSignals.length > 0) {
            generator.addText("Enabling Conditions:", STYLE.colors.secondary, 0, true);
            triggeredSignals.forEach(signal => {
                generator.addText(`  → ${signal}`, undefined, 1);
            });
            generator.addSpacer();
        }

        // Score parenthetical
        generator.addText(`(Parametric summary: ${capacity.score}/8 ${capacity.level})`, STYLE.colors.meta, 0, false);
        generator.addSpacer();
    }

    // 3. Verification Gap - Narrative First
    if (source.analysis.verification_gap) {
        generator.addSubHeader("Rhetorical-Empirical Alignment");
        const gap = source.analysis.verification_gap;

        // Interpretive narrative
        const narrative = gap.high_rhetoric_low_verification
            ? `A significant rhetorical-empirical gap emerges where aspirational language outpaces concrete enforcement mechanisms. ${gap.gap_explanation} This disconnect between text and practice creates space for symbolic compliance while substantive accountability remains elusive.`
            : `Claims are grounded in verifiable mechanisms, creating aligned rhetoric and enforcement. ${gap.gap_explanation} This coherence between stated intentions and operational capacity suggests the assemblage can deliver on its commitments.`;

        generator.addText(narrative);
        generator.addSpacer();
    }

    // 4. Counter-Narrative Stress Test - Narrative First
    if (source.analysis.stress_test_report) {
        generator.addSubHeader("Rhetorical Robustness Assessment");
        const stress = source.analysis.stress_test_report;

        // Lead with interpretive narrative
        const narrative = interpretStressTestNarrative(
            stress.framing_sensitivity,
            stress.original_score,
            stress.perturbed_score
        );
        generator.addText(narrative);
        generator.addSpacer();

        // Supporting evidence - rhetorical shifts
        if (stress.rhetorical_shifts && stress.rhetorical_shifts.length > 0) {
            generator.addText("Key Rhetorical Transformations:", STYLE.colors.secondary, 0, true);
            stress.rhetorical_shifts.forEach(shift => {
                generator.addText(`  → "${shift.original}" reframed as "${shift.new}"`, undefined, 1);
                if (shift.explanation) {
                    generator.addText(`    (${shift.explanation})`, STYLE.colors.subtle, 2);
                }
            });
            generator.addSpacer();
        }

        // Score as parenthetical
        generator.addText(`(Score shift: ${stress.original_score} → ${stress.perturbed_score}, Sensitivity: ${stress.framing_sensitivity})`, STYLE.colors.meta, 0, false);
        generator.addSpacer();
    }

    // 5. System Critique (Blind Spots) - Already narrative-heavy
    if (source.analysis.system_critique) {
        generator.addSubHeader("Reflexive Critique & Epistemological Limits");
        const critique = source.analysis.system_critique;

        if (critique.blind_spots && critique.blind_spots.length > 0) {
            generator.addText("Potential Blind Spots:", STYLE.colors.danger, 0, true);
            critique.blind_spots.forEach(spot => generator.addText(`  → ${spot}`, undefined, 1));
            generator.addSpacer();
        }

        if (critique.legitimacy_correction) {
            generator.addText("Legitimacy Correction:", STYLE.colors.secondary, 0, true);
            generator.addText(critique.legitimacy_correction);
            generator.addSpacer();
        }
    }

    // [NEW] Economic Burden
    if (source.analysis.economic_burden) {
        generator.addSubHeader("Economic Burden Analysis");
        const eb = source.analysis.economic_burden;
        generator.addText(`Burden Bearer: ${eb.burden_bearer}`, STYLE.colors.primary, 0, true);
        generator.addText(`Cost Visibility: ${eb.cost_visibility}`);
        generator.addText(`Market Consolidation Risk: ${eb.market_consolidation_risk}`);
        generator.addText("Explanation:", STYLE.colors.secondary, 0, true);
        generator.addText(eb.explanation);
        generator.addSpacer();
    }

    // [NEW] Verification Pathways
    if (source.analysis.verification_pathways) {
        generator.addSubHeader("Verification Pathways");
        const vp = source.analysis.verification_pathways;
        generator.addText(`Overall Score: ${vp.score}/10`, STYLE.colors.primary, 0, true);
        if (vp.visibility.length > 0) generator.addText(`• Visibility: ${vp.visibility.join(", ")}`);
        if (vp.enforcement.length > 0) generator.addText(`• Enforcement: ${vp.enforcement.join(", ")}`);
        if (vp.exemptions.length > 0) generator.addText(`• Exemptions: ${vp.exemptions.join(", ")}`);
        generator.addSpacer();
    }

    // 6. Canonical Evidence - Narrative context
    if (source.analysis.verified_quotes && source.analysis.verified_quotes.length > 0) {
        generator.addSubHeader("Canonical Evidence");
        generator.addText("The following textual anchors ground the above interpretations:");
        generator.addSpacer();

        source.analysis.verified_quotes.forEach((quote, idx) => {
            generator.addText(`[${idx + 1}] "${quote.text}"`, STYLE.colors.secondary, 0, false);
            generator.addText(`    Context: ${quote.context} (Confidence: ${quote.confidence})`, STYLE.colors.meta, 1);
        });
    }
}

// Helper methods for narrative interpretation
function interpretRiskNarrative(risk: MicroFascismRisk): string {
    if (risk.level === 'Micro-Fascist Hardening') {
        return "The assemblage exhibits pronounced authoritarian characteristics, manifested through exclusionary boundaries, opaque decision-making, and punitive enforcement mechanisms that concentrate power while marginalizing affected communities. These dynamics create conditions for micro-fascist organizing where bureaucratic authority supersedes democratic accountability.";
    } else if (risk.level === 'Directional Drift') {
        return "Moderate authoritarian tendencies emerge in bureaucratic rigidity and limited participatory channels, though countervailing democratic elements provide some accountability. The assemblage oscillates between technocratic efficiency and inclusive governance, creating friction points where power concentrates.";
    } else {
        return "The assemblage demonstrates democratic robustness with distributed authority, transparent procedures, and meaningful participation mechanisms. While not without hierarchies, power relations remain contestable and subject to procedural checks that prevent authoritarian drift.";
    }
}

function interpretCapacityNarrative(capacity: LiberatoryCapacity): string {
    if (capacity.level === 'Structural/Robust') {
        return "The assemblage creates substantive openings for emancipatory practice through collective rights frameworks, participatory governance structures, and explicit recognition of marginalized epistemologies. These enabling conditions support bottom-up organizing and resist neoliberal enclosure of political possibility.";
    } else if (capacity.level === 'Partial/Conditional') {
        return "Liberatory potential exists but remains constrained by institutional inertia and market logics. While formal rights and consultation mechanisms provide some agency, systemic barriers limit transformative capacity. The assemblage offers tactical openings rather than strategic reconfigurations of power.";
    } else {
        return "Limited liberatory capacity emerges within a predominantly technocratic framework that forecloses radical alternatives. Participation channels privilege expert knowledge over lived experience, and accountability mechanisms reinforce existing hierarchies rather than enabling collective self-determination.";
    }
}

function interpretStressTestNarrative(
    sensitivity: 'High' | 'Medium' | 'Low',
    originalScore: number,
    perturbedScore: number
): string {
    const shift = Math.abs(originalScore - perturbedScore);

    if (sensitivity === 'High') {
        return `Critical fragility detected: the assemblage's authority collapses under rhetorical inversion (${shift}-point degradation), revealing dependence on persuasive framing rather than robust structural mechanisms. This brittleness suggests the policy relies more on ideological legitimation than material accountability, making it vulnerable to hostile interpretation or bad-faith implementation.`;
    } else if (sensitivity === 'Medium') {
        return `Moderate rhetorical dependency emerges through adversarial reframing (${shift}-point shift). While the assemblage possesses some structural integrity, hostile actors could exploit framing ambiguities to weaken its authority. This suggests a need for more concrete enforcement mechanisms to insulate governance from interpretive manipulation.`;
    } else {
        return `Robust structural resilience withstands rhetorical inversion with minimal degradation (${shift}-point variance). The assemblage's authority derives from concrete mechanisms and specific mandates rather than aspirational language, enabling it to resist hostile spin and maintain operational coherence across varied interpretive contexts.`;
    }
}
